INSERT OR REPLACE INTO exercises (id, user_id, name, name_de, category, primary_muscle, equipment, instructions_en, instructions_de, muscle_group, secondary_muscles, instruction_steps_en, instruction_steps_de, thumbnail_url, gif_url, created_at, updated_at, deleted) VALUES
  ('1196e838-6c2f-55b3-aecc-c18d41fb23d2', NULL, '3/4 Sit-up', '3/4 Sit-up', 'waist', 'abs', 'body weight', 'Lie flat on your back with your knees bent and feet flat on the ground. Place your hands behind your head with your elbows pointing outwards. Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle. Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'hip flexors', '["hip flexors","lower back"]', '["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands behind your head with your elbows pointing outwards.","Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."]', '["Lege dich flach auf den Rücken, winkle die Knie an und stelle die Füsse flach auf den Boden.","Lege die Hände hinter den Kopf, die Ellbogen zeigen nach aussen.","Spanne die Bauchmuskeln an und hebe den Oberkörper langsam vom Boden ab, bis dein Rumpf einen Winkel von 45° zum Boden bildet.","Halte kurz oben inne und senke den Oberkörper anschliessend langsam zurück in die Ausgangsposition ab.","Wiederhole die Bewegung für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0001.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0001.gif', 1784612222128, 1784612222128, 0),
  ('bfaf7e3f-8f41-5886-9ca9-b30d4c054a2e', NULL, '45° Side Bend', '45°-Seitbeuge', 'waist', 'abs', 'body weight', 'Stand with your feet shoulder-width apart and your arms extended straight down by your sides. Keeping your back straight and your core engaged, slowly bend your torso to one side, lowering your hand towards your knee. Pause for a moment at the bottom, then slowly return to the starting position. Repeat on the other side. Continue alternating sides for the desired number of repetitions.', NULL, 'obliques', '["obliques"]', '["Stand with your feet shoulder-width apart and your arms extended straight down by your sides.","Keeping your back straight and your core engaged, slowly bend your torso to one side, lowering your hand towards your knee.","Pause for a moment at the bottom, then slowly return to the starting position.","Repeat on the other side.","Continue alternating sides for the desired number of repetitions."]', '["Stehe schulterbreit und lasse die Arme gestreckt seitlich am Körper herunterhängen.","Halte den Rücken gerade, spanne deine Körpermitte an und neige den Oberkörper langsam zur Seite, wobei die Hand Richtung Knie gleitet.","Halte unten kurz inne und kehre langsam in die Ausgangsposition zurück.","Wiederhole die Bewegung auf der anderen Seite.","Wechsle die Seiten fortlaufend für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0002.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0002.gif', 1784612222128, 1784612222128, 0),
  ('c81e517c-b223-5a34-8b7b-daef830608df', NULL, 'Air Bike', 'Air Bike', 'waist', 'abs', 'body weight', 'Lie flat on your back with your hands placed behind your head. Lift your legs off the ground and bend your knees at a 90-degree angle. Bring your right elbow towards your left knee while simultaneously straightening your right leg. Return to the starting position and repeat the movement on the opposite side, bringing your left elbow towards your right knee while straightening your left leg. Continue alternating sides in a pedaling motion for the desired number of repetitions.', NULL, 'hip flexors', '["hip flexors"]', '["Lie flat on your back with your hands placed behind your head.","Lift your legs off the ground and bend your knees at a 90-degree angle.","Bring your right elbow towards your left knee while simultaneously straightening your right leg.","Return to the starting position and repeat the movement on the opposite side, bringing your left elbow towards your right knee while straightening your left leg.","Continue alternating sides in a pedaling motion for the desired number of repetitions."]', '["Lege dich flach auf den Rücken und lege die Hände hinter den Kopf.","Hebe die Beine vom Boden ab und winkle die Knie im 90°-Winkel an.","Führe den rechten Ellbogen zum linken Knie, während du gleichzeitig das rechte Bein streckst.","Kehre in die Ausgangsposition zurück und wiederhole die Bewegung auf der anderen Seite: Führe den linken Ellbogen zum rechten Knie, während du das linke Bein streckst.","Wechsle die Seiten in dieser Tretbewegung fortlaufend für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0003.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0003.gif', 1784612222128, 1784612222128, 0),
  ('6af465a2-8e36-50ae-ad83-c5457dd6c638', NULL, 'All Fours Quad Stretch', 'Quadrizeps-Dehnung im Vierfüsslerstand', 'upper legs', 'quads', 'body weight', 'Start on all fours with your hands directly under your shoulders and your knees directly under your hips. Extend one leg straight back, keeping your knee bent and your foot flexed. Slowly lower your hips towards the ground, feeling a stretch in your quads. Hold this position for 20-30 seconds. Switch legs and repeat the stretch on the other side.', NULL, 'hamstrings', '["hamstrings","glutes"]', '["Start on all fours with your hands directly under your shoulders and your knees directly under your hips.","Extend one leg straight back, keeping your knee bent and your foot flexed.","Slowly lower your hips towards the ground, feeling a stretch in your quads.","Hold this position for 20-30 seconds.","Switch legs and repeat the stretch on the other side."]', '["Gehe in den Vierfüsslerstand, die Hände direkt unter den Schultern und die Knie direkt unter den Hüften.","Strecke ein Bein nach hinten aus, wobei das Knie leicht gebeugt und der Fuss angezogen bleibt.","Senke die Hüfte langsam Richtung Boden ab und spüre die Dehnung im Quadrizeps.","Halte diese Position 20-30 Sekunden.","Wechsle das Bein und wiederhole die Dehnung auf der anderen Seite."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1512.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1512.gif', 1784612222128, 1784612222128, 0),
  ('514f2ab2-d704-5b80-9007-3b11a0cb030a', NULL, 'Alternate Heel Touchers', 'Abwechselndes Fersentippen', 'waist', 'abs', 'body weight', 'Lie flat on your back with your knees bent and feet flat on the ground. Extend your arms straight out to the sides, parallel to the ground. Engaging your abs, lift your shoulders off the ground and reach your right hand towards your right heel. Return to the starting position and repeat on the left side, reaching your left hand towards your left heel. Continue alternating sides for the desired number of repetitions.', NULL, 'obliques', '["obliques"]', '["Lie flat on your back with your knees bent and feet flat on the ground.","Extend your arms straight out to the sides, parallel to the ground.","Engaging your abs, lift your shoulders off the ground and reach your right hand towards your right heel.","Return to the starting position and repeat on the left side, reaching your left hand towards your left heel.","Continue alternating sides for the desired number of repetitions."]', '["Lege dich flach auf den Rücken, winkle die Knie an und stelle die Füsse flach auf den Boden.","Strecke die Arme seitlich aus, parallel zum Boden.","Spanne die Bauchmuskeln an, hebe die Schultern vom Boden ab und strecke die rechte Hand Richtung rechter Ferse.","Kehre in die Ausgangsposition zurück und wiederhole auf der linken Seite, wobei die linke Hand Richtung linker Ferse greift.","Wechsle die Seiten fortlaufend für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0006.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0006.gif', 1784612222128, 1784612222128, 0),
  ('82b4576e-aaf2-53cf-87fd-e4b087f8e801', NULL, 'Alternate Lateral Pulldown', 'Abwechselnder seitlicher Latzug', 'back', 'lats', 'cable', 'Sit on the cable machine with your back straight and feet flat on the ground. Grasp the handles with an overhand grip, slightly wider than shoulder-width apart. Lean back slightly and pull the handles towards your chest, squeezing your shoulder blades together. Pause for a moment at the peak of the movement, then slowly release the handles back to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","rhomboids"]', '["Sit on the cable machine with your back straight and feet flat on the ground.","Grasp the handles with an overhand grip, slightly wider than shoulder-width apart.","Lean back slightly and pull the handles towards your chest, squeezing your shoulder blades together.","Pause for a moment at the peak of the movement, then slowly release the handles back to the starting position.","Repeat for the desired number of repetitions."]', '["Setze dich an den Kabelzug, halte den Rücken gerade und stelle die Füsse flach auf den Boden.","Greife die Griffe im Obergriff, etwas breiter als schulterbreit.","Lehne dich leicht zurück und ziehe die Griffe zur Brust, während du die Schulterblätter zusammenziehst.","Halte kurz in der Endposition inne und lasse die Griffe anschliessend langsam zurück in die Ausgangsposition gleiten.","Wiederhole die Bewegung für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0007.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0007.gif', 1784612222128, 1784612222128, 0),
  ('e9bb9fd6-66d8-596c-9cb8-dc6e18c93688', NULL, 'Ankle Circles', 'Fussgelenkkreisen', 'lower legs', 'calves', 'body weight', 'Sit on the ground with your legs extended in front of you. Lift one leg off the ground and rotate your ankle in a circular motion. Perform the desired number of circles in one direction, then switch to the other direction. Repeat with the other leg.', NULL, 'ankle stabilizers', '["ankle stabilizers"]', '["Sit on the ground with your legs extended in front of you.","Lift one leg off the ground and rotate your ankle in a circular motion.","Perform the desired number of circles in one direction, then switch to the other direction.","Repeat with the other leg."]', '["Setze dich auf den Boden und strecke die Beine vor dir aus.","Hebe ein Bein vom Boden ab und kreise mit dem Fussgelenk.","Führe die gewünschte Anzahl Kreise in eine Richtung aus und wechsle dann die Richtung.","Wiederhole mit dem anderen Bein."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1368.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1368.gif', 1784612222128, 1784612222128, 0),
  ('acd2bc5f-649b-5178-b3b0-150495146710', NULL, 'Archer Pull-up', 'Archer-Klimmzug', 'back', 'lats', 'body weight', 'Start by hanging from a pull-up bar with an overhand grip, slightly wider than shoulder-width apart. Engage your core and pull your shoulder blades down and back. As you pull yourself up, bend one arm and bring your elbow towards your side, while keeping the other arm straight. Continue pulling until your chin is above the bar and your bent arm is fully flexed. Lower yourself back down with control, straightening the bent arm and repeating the movement on the other side. Alternate sides with each repetition.', NULL, 'biceps', '["biceps","forearms"]', '["Start by hanging from a pull-up bar with an overhand grip, slightly wider than shoulder-width apart.","Engage your core and pull your shoulder blades down and back.","As you pull yourself up, bend one arm and bring your elbow towards your side, while keeping the other arm straight.","Continue pulling until your chin is above the bar and your bent arm is fully flexed.","Lower yourself back down with control, straightening the bent arm and repeating the movement on the other side.","Alternate sides with each repetition."]', '["Hänge dich mit Obergriff an eine Klimmzugstange, die Hände etwas breiter als schulterbreit.","Spanne deine Körpermitte an und ziehe die Schulterblätter nach unten und hinten.","Ziehe dich hoch, beuge dabei einen Arm und führe den Ellbogen zur Seite, während der andere Arm gestreckt bleibt.","Ziehe weiter, bis sich dein Kinn über der Stange befindet und der gebeugte Arm vollständig angewinkelt ist.","Senke dich kontrolliert ab, strecke den gebeugten Arm wieder und wiederhole die Bewegung auf der anderen Seite.","Wechsle die Seite bei jeder Wiederholung."]', 'https://ascent-api.sweber.workers.dev/media/exercises/3293.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/3293.gif', 1784612222128, 1784612222128, 0),
  ('7b34c6a9-7e3b-5fe3-8669-fd1ad3bf4a64', NULL, 'Archer Push-up', 'Archer-Liegestütz', 'chest', 'pectorals', 'body weight', 'Start in a push-up position with your hands slightly wider than shoulder-width apart. Extend one arm straight out to the side, parallel to the ground. Lower your body by bending your elbows, keeping your back straight and core engaged. Push back up to the starting position. Repeat on the other side, extending the opposite arm out to the side. Continue alternating sides for the desired number of repetitions.', NULL, 'triceps', '["triceps","shoulders","core"]', '["Start in a push-up position with your hands slightly wider than shoulder-width apart.","Extend one arm straight out to the side, parallel to the ground.","Lower your body by bending your elbows, keeping your back straight and core engaged.","Push back up to the starting position.","Repeat on the other side, extending the opposite arm out to the side.","Continue alternating sides for the desired number of repetitions."]', '["Gehe in die Liegestützposition, die Hände etwas breiter als schulterbreit.","Strecke einen Arm seitlich aus, parallel zum Boden.","Senke den Körper ab, indem du die Ellbogen beugst, während Rücken und Körpermitte stabil bleiben.","Drücke dich zurück in die Ausgangsposition.","Wiederhole auf der anderen Seite, indem du den anderen Arm seitlich ausstreckst.","Wechsle die Seiten fortlaufend für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/3294.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/3294.gif', 1784612222128, 1784612222128, 0),
  ('18b2c6a0-9e63-542d-a270-9dff147659a2', NULL, 'Arm Slingers Hanging Bent Knee Legs', 'Hängende Armschwünge mit angewinkelten Beinen', 'waist', 'abs', 'body weight', 'Hang from a pull-up bar with your arms fully extended and your knees bent at a 90-degree angle. Engage your core and lift your knees towards your chest, bringing them as close to your elbows as possible. Slowly lower your legs back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'shoulders', '["shoulders","back"]', '["Hang from a pull-up bar with your arms fully extended and your knees bent at a 90-degree angle.","Engage your core and lift your knees towards your chest, bringing them as close to your elbows as possible.","Slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."]', '["Hänge an einer Klimmzugstange mit gestreckten Armen und winkle die Knie im 90°-Winkel an.","Spanne deine Körpermitte an und ziehe die Knie Richtung Brust, so nah wie möglich an die Ellbogen heran.","Senke die Beine langsam zurück in die Ausgangsposition ab.","Wiederhole die Bewegung für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/2355.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/2355.gif', 1784612222128, 1784612222128, 0),
  ('25411492-8648-59fc-98b6-9c9b4db35571', NULL, 'Arm Slingers Hanging Straight Legs', 'Hängende Armschwünge mit gestreckten Beinen', 'waist', 'abs', 'body weight', 'Hang from a pull-up bar with your arms fully extended and your legs straight down. Engage your core and lift your legs up in front of you until they are parallel to the ground. Hold for a moment at the top, then slowly lower your legs back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'shoulders', '["shoulders","back"]', '["Hang from a pull-up bar with your arms fully extended and your legs straight down.","Engage your core and lift your legs up in front of you until they are parallel to the ground.","Hold for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."]', '["Hänge an einer Klimmzugstange mit gestreckten Armen, die Beine hängen gestreckt nach unten.","Spanne deine Körpermitte an und hebe die Beine vor dir an, bis sie parallel zum Boden sind.","Halte oben kurz inne und senke die Beine anschliessend langsam zurück in die Ausgangsposition ab.","Wiederhole die Bewegung für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/2333.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/2333.gif', 1784612222128, 1784612222128, 0),
  ('6dda3c42-96cd-5edd-996c-69f36b81b7d4', NULL, 'Arms Apart Circular Toe Touch (Male)', 'Kreisendes Zehentippen mit ausgestreckten Armen (männlich)', 'upper legs', 'glutes', 'body weight', 'Stand with your feet shoulder-width apart and arms extended to the sides. Keeping your legs straight, bend forward at the waist and reach down towards your toes with your right hand. As you reach down, simultaneously lift your left leg straight up behind you, maintaining balance. Return to the starting position and repeat the movement with your left hand reaching towards your toes and your right leg lifting up behind you. Continue alternating sides for the desired number of repetitions.', NULL, 'hamstrings', '["hamstrings","quadriceps","calves"]', '["Stand with your feet shoulder-width apart and arms extended to the sides.","Keeping your legs straight, bend forward at the waist and reach down towards your toes with your right hand.","As you reach down, simultaneously lift your left leg straight up behind you, maintaining balance.","Return to the starting position and repeat the movement with your left hand reaching towards your toes and your right leg lifting up behind you.","Continue alternating sides for the desired number of repetitions."]', '["Stehe schulterbreit und strecke die Arme seitlich aus.","Beuge dich mit gestreckten Beinen in der Hüfte nach vorne und greife mit der rechten Hand Richtung Zehen.","Hebe dabei gleichzeitig das linke Bein gestreckt hinter dir an und halte das Gleichgewicht.","Kehre in die Ausgangsposition zurück und wiederhole die Bewegung mit der linken Hand Richtung Zehen, während das rechte Bein hinter dir angehoben wird.","Wechsle die Seiten fortlaufend für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/3214.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/3214.gif', 1784612222128, 1784612222128, 0),
  ('377cd816-a707-56db-8e34-c39cceecaca0', NULL, 'Arms Overhead Full Sit-up (Male)', 'Vollständiger Sit-up mit Armen über dem Kopf (männlich)', 'waist', 'abs', 'body weight', 'Lie flat on your back with your knees bent and feet flat on the ground. Extend your arms overhead, keeping them straight. Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is upright. Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'hip flexors', '["hip flexors","lower back"]', '["Lie flat on your back with your knees bent and feet flat on the ground.","Extend your arms overhead, keeping them straight.","Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is upright.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."]', '["Lege dich flach auf den Rücken, winkle die Knie an und stelle die Füsse flach auf den Boden.","Strecke die Arme gestreckt über den Kopf.","Spanne die Bauchmuskeln an und hebe den Oberkörper langsam vom Boden ab, bis du aufrecht sitzt.","Halte kurz oben inne und senke den Oberkörper anschliessend langsam zurück in die Ausgangsposition ab.","Wiederhole die Bewegung für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/3204.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/3204.gif', 1784612222128, 1784612222128, 0),
  ('7f3b55ac-5d6f-53c9-99af-db9d82312a0a', NULL, 'Assisted Chest Dip (Kneeling)', 'Brust-Dip an der Maschine (kniend, unterstützt)', 'chest', 'pectorals', 'leverage machine', 'Adjust the machine to your desired height and secure your knees on the pad. Grasp the handles with your palms facing down and your arms fully extended. Lower your body by bending your elbows until your upper arms are parallel to the floor. Pause for a moment, then push yourself back up to the starting position. Repeat for the desired number of repetitions.', NULL, 'triceps', '["triceps","shoulders"]', '["Adjust the machine to your desired height and secure your knees on the pad.","Grasp the handles with your palms facing down and your arms fully extended.","Lower your body by bending your elbows until your upper arms are parallel to the floor.","Pause for a moment, then push yourself back up to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle das Gerät auf die gewünschte Höhe ein und platziere die Knie sicher auf dem Polster.","Greife die Griffe mit nach unten zeigenden Handflächen, die Arme gestreckt.","Senke den Körper ab, indem du die Ellbogen beugst, bis die Oberarme parallel zum Boden sind.","Halte kurz inne und drücke dich anschliessend zurück in die Ausgangsposition.","Wiederhole die Bewegung für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0009.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0009.gif', 1784612222128, 1784612222128, 0),
  ('bdac0b45-5f2b-5302-bda0-703678f63498', NULL, 'Assisted Hanging Knee Raise', 'Hängendes Knieheben (unterstützt)', 'waist', 'abs', 'assisted', 'Hang from a pull-up bar with your arms fully extended and your palms facing away from you. Engage your core muscles and lift your knees towards your chest, bending at the hips and knees. Pause for a moment at the top of the movement, squeezing your abs. Slowly lower your legs back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'hip flexors', '["hip flexors"]', '["Hang from a pull-up bar with your arms fully extended and your palms facing away from you.","Engage your core muscles and lift your knees towards your chest, bending at the hips and knees.","Pause for a moment at the top of the movement, squeezing your abs.","Slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."]', '["Hänge an einer Klimmzugstange mit gestreckten Armen, die Handflächen zeigen von dir weg.","Spanne deine Körpermitte an und ziehe die Knie Richtung Brust, indem du Hüfte und Knie beugst.","Halte kurz in der oberen Position inne und spanne die Bauchmuskeln an.","Senke die Beine langsam zurück in die Ausgangsposition ab.","Wiederhole die Bewegung für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0011.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0011.gif', 1784612222128, 1784612222128, 0),
  ('9a294e09-b63c-5340-916a-541485016343', NULL, 'Assisted Hanging Knee Raise with Throw Down', 'Hängendes Knieheben mit Ablassen (unterstützt)', 'waist', 'abs', 'assisted', 'Hang from a pull-up bar with your arms fully extended and your palms facing away from you. Engage your core and lift your knees towards your chest, keeping your legs together. Once your knees are at chest level, explosively throw your legs down towards the ground, extending them fully. Allow your legs to swing back up and repeat the movement for the desired number of repetitions.', NULL, 'hip flexors', '["hip flexors","lower back"]', '["Hang from a pull-up bar with your arms fully extended and your palms facing away from you.","Engage your core and lift your knees towards your chest, keeping your legs together.","Once your knees are at chest level, explosively throw your legs down towards the ground, extending them fully.","Allow your legs to swing back up and repeat the movement for the desired number of repetitions."]', '["Hänge an einer Klimmzugstange mit gestreckten Armen, die Handflächen zeigen von dir weg.","Spanne deine Körpermitte an und ziehe die Knie Richtung Brust, die Beine bleiben dabei zusammen.","Sobald die Knie auf Brusthöhe sind, schleudere die Beine explosiv nach unten und strecke sie dabei vollständig durch.","Lass die Beine wieder nach oben schwingen und wiederhole die Bewegung für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0010.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0010.gif', 1784612222128, 1784612222128, 0),
  ('bf7a6f28-c869-5a29-9205-2c898596ed84', NULL, 'Assisted Lying Calves Stretch', 'Wadendehnung im Liegen (unterstützt)', 'lower legs', 'calves', 'assisted', 'Lie on your back with your legs extended. Bend one knee and place your foot flat on the ground. Using your hands or a towel, gently pull your toes towards your body, feeling a stretch in your calf. Hold the stretch for 20-30 seconds. Release the stretch and repeat on the other leg.', NULL, 'hamstrings', '["hamstrings"]', '["Lie on your back with your legs extended.","Bend one knee and place your foot flat on the ground.","Using your hands or a towel, gently pull your toes towards your body, feeling a stretch in your calf.","Hold the stretch for 20-30 seconds.","Release the stretch and repeat on the other leg."]', '["Lege dich auf den Rücken und strecke die Beine aus.","Beuge ein Knie und stelle den Fuss flach auf den Boden.","Ziehe mit den Händen oder einem Handtuch die Zehen sanft Richtung Körper und spüre die Dehnung in der Wade.","Halte die Dehnung 20-30 Sekunden.","Löse die Dehnung und wiederhole mit dem anderen Bein."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1708.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1708.gif', 1784612222128, 1784612222128, 0),
  ('e870abf1-c2f1-5944-a9c7-2fbda96e77d9', NULL, 'Assisted Lying Glutes Stretch', 'Gesässdehnung im Liegen (unterstützt)', 'upper legs', 'glutes', 'assisted', 'Lie on your back with your legs extended. Bend your right knee and place your right ankle on your left thigh, just above the knee. Grasp your left thigh with both hands and gently pull it towards your chest. Hold the stretch for 20-30 seconds. Release and repeat on the other side.', NULL, 'hamstrings', '["hamstrings"]', '["Lie on your back with your legs extended.","Bend your right knee and place your right ankle on your left thigh, just above the knee.","Grasp your left thigh with both hands and gently pull it towards your chest.","Hold the stretch for 20-30 seconds.","Release and repeat on the other side."]', '["Lege dich auf den Rücken und strecke die Beine aus.","Beuge das rechte Knie und lege den rechten Knöchel knapp über dem Knie auf den linken Oberschenkel.","Umfasse den linken Oberschenkel mit beiden Händen und ziehe ihn sanft Richtung Brust.","Halte die Dehnung 20-30 Sekunden.","Löse die Dehnung und wiederhole auf der anderen Seite."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1709.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1709.gif', 1784612222128, 1784612222128, 0),
  ('047e35f3-c0c6-54d4-a6af-d736affa59a8', NULL, 'Assisted Lying Gluteus and Piriformis Stretch', 'Gesäss- und Piriformis-Dehnung im Liegen (unterstützt)', 'upper legs', 'glutes', 'assisted', 'Lie on your back with your legs extended. Bend your right knee and place your right ankle on your left thigh, just above the knee. Grasp your left thigh with both hands and gently pull it towards your chest. Hold the stretch for 20-30 seconds. Release the stretch and repeat on the other side.', NULL, 'hamstrings', '["hamstrings"]', '["Lie on your back with your legs extended.","Bend your right knee and place your right ankle on your left thigh, just above the knee.","Grasp your left thigh with both hands and gently pull it towards your chest.","Hold the stretch for 20-30 seconds.","Release the stretch and repeat on the other side."]', '["Lege dich auf den Rücken und strecke die Beine aus.","Beuge das rechte Knie und lege den rechten Knöchel knapp über dem Knie auf den linken Oberschenkel.","Umfasse den linken Oberschenkel mit beiden Händen und ziehe ihn sanft Richtung Brust.","Halte die Dehnung 20-30 Sekunden.","Löse die Dehnung und wiederhole auf der anderen Seite."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1710.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1710.gif', 1784612222128, 1784612222128, 0),
  ('2b1ee405-def7-5d41-a89e-b4650356c5d5', NULL, 'Assisted Lying Leg Raise with Lateral Throw Down', 'Beinheben im Liegen mit seitlichem Ablassen (unterstützt)', 'waist', 'abs', 'assisted', 'Lie flat on your back with your legs extended and your arms by your sides. Place your hands under your glutes for support. Engage your abs and lift your legs off the ground, keeping them straight. While keeping your legs together, lower them to one side until they are a few inches above the ground. Pause for a moment, then lift your legs back to the starting position. Repeat the movement to the other side. Continue alternating sides for the desired number of repetitions.', NULL, 'hip flexors', '["hip flexors","obliques"]', '["Lie flat on your back with your legs extended and your arms by your sides.","Place your hands under your glutes for support.","Engage your abs and lift your legs off the ground, keeping them straight.","While keeping your legs together, lower them to one side until they are a few inches above the ground.","Pause for a moment, then lift your legs back to the starting position.","Repeat the movement to the other side.","Continue alternating sides for the desired number of repetitions."]', '["Lege dich flach auf den Rücken, strecke die Beine aus und lege die Arme neben den Körper.","Lege die Hände zur Unterstützung unter das Gesäss.","Spanne die Bauchmuskeln an und hebe die gestreckten Beine vom Boden ab.","Senke die Beine, während sie zusammenbleiben, zur Seite ab, bis sie sich einige Zentimeter über dem Boden befinden.","Halte kurz inne und hebe die Beine anschliessend zurück in die Ausgangsposition.","Wiederhole die Bewegung zur anderen Seite.","Wechsle die Seiten fortlaufend für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0012.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0012.gif', 1784612222128, 1784612222128, 0),
  ('b7c2ed75-6ccb-54ea-8f41-41fa12e94cad', NULL, 'Assisted Lying Leg Raise with Throw Down', 'Beinheben im Liegen mit Ablassen (unterstützt)', 'waist', 'abs', 'assisted', 'Lie flat on your back with your legs extended and your arms by your sides. Place your hands under your glutes for support. Engage your core and lift your legs off the ground, keeping them straight. Raise your legs until they are perpendicular to the ground. Lower your legs back down to the starting position. Simultaneously, throw your legs down towards the ground, keeping them straight. Raise your legs back up to the starting position. Repeat for the desired number of repetitions.', NULL, 'hip flexors', '["hip flexors","quadriceps"]', '["Lie flat on your back with your legs extended and your arms by your sides.","Place your hands under your glutes for support.","Engage your core and lift your legs off the ground, keeping them straight.","Raise your legs until they are perpendicular to the ground.","Lower your legs back down to the starting position.","Simultaneously, throw your legs down towards the ground, keeping them straight.","Raise your legs back up to the starting position.","Repeat for the desired number of repetitions."]', '["Lege dich flach auf den Rücken, strecke die Beine aus und lege die Arme neben den Körper.","Lege die Hände zur Unterstützung unter das Gesäss.","Spanne deine Körpermitte an und hebe die gestreckten Beine vom Boden ab.","Hebe die Beine an, bis sie senkrecht zum Boden stehen.","Senke die Beine zurück in die Ausgangsposition ab.","Schleudere die Beine gleichzeitig Richtung Boden, wobei sie gestreckt bleiben.","Hebe die Beine wieder zurück in die Ausgangsposition an.","Wiederhole die Bewegung für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0013.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0013.gif', 1784612222128, 1784612222128, 0),
  ('b8ccba08-dcf0-5e12-93b3-05d1dabbd207', NULL, 'Assisted Motion Russian Twist', 'Russian Twist mit Medizinball (unterstützt)', 'waist', 'abs', 'medicine ball', 'Sit on the ground with your knees bent and feet flat on the floor. Hold the medicine ball with both hands in front of your chest. Lean back slightly, engaging your abs and keeping your back straight. Slowly twist your torso to the right, bringing the medicine ball towards the right side of your body. Pause for a moment, then twist your torso to the left, bringing the medicine ball towards the left side of your body. Continue alternating sides for the desired number of repetitions.', NULL, 'obliques', '["obliques","lower back"]', '["Sit on the ground with your knees bent and feet flat on the floor.","Hold the medicine ball with both hands in front of your chest.","Lean back slightly, engaging your abs and keeping your back straight.","Slowly twist your torso to the right, bringing the medicine ball towards the right side of your body.","Pause for a moment, then twist your torso to the left, bringing the medicine ball towards the left side of your body.","Continue alternating sides for the desired number of repetitions."]', '["Setze dich auf den Boden, winkle die Knie an und stelle die Füsse flach auf.","Halte den Medizinball mit beiden Händen vor der Brust.","Lehne dich leicht zurück, spanne die Bauchmuskeln an und halte den Rücken gerade.","Drehe den Oberkörper langsam nach rechts und führe den Medizinball zur rechten Körperseite.","Halte kurz inne und drehe den Oberkörper dann nach links, wobei der Medizinball zur linken Körperseite geführt wird.","Wechsle die Seiten fortlaufend für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0014.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0014.gif', 1784612222128, 1784612222128, 0),
  ('28596b28-f294-50b0-8c0f-a185651f8a9b', NULL, 'Assisted Parallel Close Grip Pull-up', 'Klimmzug eng im Parallelgriff an der Maschine (unterstützt)', 'back', 'lats', 'leverage machine', 'Adjust the machine to your desired weight and height. Place your hands on the parallel bars with a close grip, palms facing each other. Hang from the bars with your arms fully extended and your feet off the ground. Engage your back muscles and pull your body up towards the bars, keeping your elbows close to your body. Continue pulling until your chin is above the bars. Pause for a moment at the top, then slowly lower your body back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","forearms"]', '["Adjust the machine to your desired weight and height.","Place your hands on the parallel bars with a close grip, palms facing each other.","Hang from the bars with your arms fully extended and your feet off the ground.","Engage your back muscles and pull your body up towards the bars, keeping your elbows close to your body.","Continue pulling until your chin is above the bars.","Pause for a moment at the top, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle das Gerät auf das gewünschte Gewicht und die gewünschte Höhe ein.","Lege die Hände im engen Griff auf die parallelen Griffstangen, die Handflächen zeigen zueinander.","Hänge dich mit gestreckten Armen an die Griffe, die Füsse in der Luft.","Spanne die Rückenmuskulatur an und ziehe deinen Körper Richtung Griffe hoch, die Ellbogen bleiben nah am Körper.","Ziehe weiter, bis sich dein Kinn über den Griffen befindet.","Halte kurz oben inne und senke deinen Körper anschliessend langsam zurück in die Ausgangsposition ab.","Wiederhole die Bewegung für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0015.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0015.gif', 1784612222128, 1784612222128, 0),
  ('bfffcf69-f4af-507b-99b0-770adfa4d546', NULL, 'Assisted Prone Hamstring', 'Hamstring-Dehnung in Bauchlage (unterstützt)', 'upper legs', 'hamstrings', 'assisted', 'Lie face down on a mat or bench with your legs fully extended. Have a partner or use a resistance band to secure your ankles. Engage your hamstrings and lift your legs towards your glutes, keeping your knees straight. Pause for a moment at the top, then slowly lower your legs back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'glutes', '["glutes","lower back"]', '["Lie face down on a mat or bench with your legs fully extended.","Have a partner or use a resistance band to secure your ankles.","Engage your hamstrings and lift your legs towards your glutes, keeping your knees straight.","Pause for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."]', '["Lege dich mit dem Gesicht nach unten auf eine Matte oder Bank, die Beine vollständig gestreckt.","Lass die Knöchel von einem Partner fixieren oder sichere sie mit einem Widerstandsband.","Spanne die Beinbeuger an und hebe die Beine Richtung Gesäss, die Knie bleiben dabei gestreckt.","Halte kurz oben inne und senke die Beine anschliessend langsam zurück in die Ausgangsposition ab.","Wiederhole die Bewegung für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0016.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0016.gif', 1784612222128, 1784612222128, 0),
  ('1a749089-c5f0-5067-8a2b-9b559ffb29fc', NULL, 'Assisted Prone Lying Quads Stretch', 'Quadrizeps-Dehnung in Bauchlage (unterstützt)', 'upper legs', 'quads', 'assisted', 'Lie face down on the ground with your legs extended. Bend your left knee and reach back with your left hand to grab your left foot or ankle. Gently pull your left foot towards your glutes, feeling a stretch in your left quad. Hold the stretch for 20-30 seconds, then release. Repeat with your right leg.', NULL, 'hamstrings', '["hamstrings","glutes"]', '["Lie face down on the ground with your legs extended.","Bend your left knee and reach back with your left hand to grab your left foot or ankle.","Gently pull your left foot towards your glutes, feeling a stretch in your left quad.","Hold the stretch for 20-30 seconds, then release.","Repeat with your right leg."]', '["Lege dich mit dem Gesicht nach unten auf den Boden und strecke die Beine aus.","Beuge das linke Knie und greife mit der linken Hand nach hinten, um den linken Fuss oder Knöchel zu fassen.","Ziehe den linken Fuss sanft Richtung Gesäss und spüre die Dehnung im linken Quadrizeps.","Halte die Dehnung 20-30 Sekunden und löse sie anschliessend.","Wiederhole mit dem rechten Bein."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1713.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1713.gif', 1784612222128, 1784612222128, 0),
  ('acc713b1-ff40-53a9-8dde-fd8b8e1742c3', NULL, 'Assisted Prone Rectus Femoris Stretch', 'Rectus-femoris-Dehnung in Bauchlage (unterstützt)', 'waist', 'abs', 'assisted', 'Lie face down on the ground with your legs straight. Bend your right knee and reach back with your right hand to grab your right foot or ankle. Gently pull your right foot or ankle towards your glutes, feeling a stretch in the front of your right thigh. Hold the stretch for 20-30 seconds. Release and repeat on the other side.', NULL, 'quadriceps', '["quadriceps"]', '["Lie face down on the ground with your legs straight.","Bend your right knee and reach back with your right hand to grab your right foot or ankle.","Gently pull your right foot or ankle towards your glutes, feeling a stretch in the front of your right thigh.","Hold the stretch for 20-30 seconds.","Release and repeat on the other side."]', '["Lege dich mit dem Gesicht nach unten auf den Boden, die Beine gestreckt.","Beuge das rechte Knie und greife mit der rechten Hand nach hinten, um den rechten Fuss oder Knöchel zu fassen.","Ziehe Fuss oder Knöchel sanft Richtung Gesäss und spüre die Dehnung an der Vorderseite des rechten Oberschenkels.","Halte die Dehnung 20-30 Sekunden.","Löse die Dehnung und wiederhole auf der anderen Seite."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1714.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1714.gif', 1784612222128, 1784612222128, 0),
  ('a0867056-4ee3-5f78-b260-014b31e2f691', NULL, 'Assisted Pull-up', 'Klimmzug an der Maschine (unterstützt)', 'back', 'lats', 'leverage machine', 'Adjust the machine to your desired weight and height settings. Grasp the handles with an overhand grip, slightly wider than shoulder-width apart. Hang with your arms fully extended and your feet off the ground. Engage your back muscles and pull your body up towards the handles, keeping your elbows close to your body. Continue pulling until your chin is above the handles. Pause for a moment at the top, then slowly lower your body back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","forearms"]', '["Adjust the machine to your desired weight and height settings.","Grasp the handles with an overhand grip, slightly wider than shoulder-width apart.","Hang with your arms fully extended and your feet off the ground.","Engage your back muscles and pull your body up towards the handles, keeping your elbows close to your body.","Continue pulling until your chin is above the handles.","Pause for a moment at the top, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle das Gerät auf das gewünschte Gewicht und die gewünschte Höhe ein.","Greife die Griffe im Obergriff, etwas breiter als schulterbreit.","Hänge dich mit gestreckten Armen, die Füsse in der Luft.","Spanne die Rückenmuskulatur an und ziehe deinen Körper Richtung Griffe hoch, die Ellbogen bleiben nah am Körper.","Ziehe weiter, bis sich dein Kinn über den Griffen befindet.","Halte kurz oben inne und senke deinen Körper anschliessend langsam zurück in die Ausgangsposition ab.","Wiederhole die Bewegung für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0017.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0017.gif', 1784612222128, 1784612222128, 0),
  ('c9c30f3b-ca3e-50e8-b10a-11f519c4bfa7', NULL, 'Assisted Seated Pectoralis Major Stretch with Stability Ball', 'Dehnung des grossen Brustmuskels im Sitzen mit Gymnastikball (unterstützt)', 'chest', 'pectorals', 'assisted', 'Sit on a stability ball with your feet flat on the ground and your back straight. Hold a stability ball with both hands and extend your arms straight out in front of you. Slowly lower the stability ball towards your chest, feeling a stretch in your pectoral muscles. Hold the stretch for a few seconds, then slowly return to the starting position. Repeat for the desired number of repetitions.', NULL, 'shoulders', '["shoulders","triceps"]', '["Sit on a stability ball with your feet flat on the ground and your back straight.","Hold a stability ball with both hands and extend your arms straight out in front of you.","Slowly lower the stability ball towards your chest, feeling a stretch in your pectoral muscles.","Hold the stretch for a few seconds, then slowly return to the starting position.","Repeat for the desired number of repetitions."]', '["Setze dich auf einen Gymnastikball, stelle die Füsse flach auf den Boden und halte den Rücken gerade.","Halte einen Gymnastikball mit beiden Händen und strecke die Arme gerade nach vorne aus.","Senke den Gymnastikball langsam Richtung Brust ab und spüre die Dehnung in der Brustmuskulatur.","Halte die Dehnung einige Sekunden und kehre anschliessend langsam in die Ausgangsposition zurück.","Wiederhole die Bewegung für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1716.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1716.gif', 1784612222128, 1784612222128, 0),
  ('a9ee1dad-73fb-5782-a3e6-b62c404dad1c', NULL, 'Assisted Side Lying Adductor Stretch', 'Adduktorendehnung in Seitenlage (unterstützt)', 'upper legs', 'adductors', 'assisted', 'Lie on your side with your legs straight and stacked on top of each other. Bend your bottom leg slightly for stability. Place your top foot on a stable surface, such as a bench or step. Keeping your top leg straight, slowly lower it towards the ground, feeling a stretch in your inner thigh. Hold the stretch for 20-30 seconds. Return to the starting position and repeat on the other side.', NULL, 'hamstrings', '["hamstrings","glutes"]', '["Lie on your side with your legs straight and stacked on top of each other.","Bend your bottom leg slightly for stability.","Place your top foot on a stable surface, such as a bench or step.","Keeping your top leg straight, slowly lower it towards the ground, feeling a stretch in your inner thigh.","Hold the stretch for 20-30 seconds.","Return to the starting position and repeat on the other side."]', '["Lege dich auf die Seite, die Beine gestreckt und übereinander.","Beuge das untere Bein leicht, um Stabilität zu gewinnen.","Stelle den oberen Fuss auf eine stabile Unterlage, zum Beispiel eine Bank oder Stufe.","Senke das gestreckte obere Bein langsam Richtung Boden ab und spüre die Dehnung an der Innenseite des Oberschenkels.","Halte die Dehnung 20-30 Sekunden.","Kehre in die Ausgangsposition zurück und wiederhole auf der anderen Seite."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1712.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1712.gif', 1784612222128, 1784612222128, 0),
  ('dd60730e-ce48-5cc4-b262-71a27c817ba7', NULL, 'Assisted Sit-up', 'Sit-up (unterstützt)', 'waist', 'abs', 'assisted', 'Sit on the edge of a bench or have someone hold your feet down. Lie flat on your back with your knees bent and feet flat on the ground. Place your hands behind your head with your elbows pointing outwards. Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle. Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'hip flexors', '["hip flexors"]', '["Sit on the edge of a bench or have someone hold your feet down.","Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands behind your head with your elbows pointing outwards.","Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."]', '["Setze dich an den Rand einer Bank oder lass deine Füsse von jemandem festhalten.","Lege dich flach auf den Rücken, winkle die Knie an und stelle die Füsse flach auf den Boden.","Lege die Hände hinter den Kopf, die Ellbogen zeigen nach aussen.","Spanne die Bauchmuskeln an und hebe den Oberkörper langsam vom Boden ab, bis dein Rumpf einen Winkel von 45° zum Boden bildet.","Halte kurz oben inne und senke den Oberkörper anschliessend langsam zurück in die Ausgangsposition ab.","Wiederhole die Bewegung für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1758.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1758.gif', 1784612222128, 1784612222128, 0),
  ('c3fd9a5d-7262-5bba-a662-0ab25ac81bd1', NULL, 'Assisted Standing Chin-up', 'Klimmzug im Untergriff stehend an der Maschine (unterstützt)', 'back', 'lats', 'leverage machine', 'Adjust the machine to your desired assistance level. Stand on the foot platform and grip the handles with an overhand grip, slightly wider than shoulder-width apart. Keep your chest up and shoulders back, engage your core, and slightly bend your knees. Pull your body up by flexing your elbows and driving your elbows down towards your sides. Continue pulling until your chin is above the bar. Pause for a moment at the top, then slowly lower your body back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","forearms"]', '["Adjust the machine to your desired assistance level.","Stand on the foot platform and grip the handles with an overhand grip, slightly wider than shoulder-width apart.","Keep your chest up and shoulders back, engage your core, and slightly bend your knees.","Pull your body up by flexing your elbows and driving your elbows down towards your sides.","Continue pulling until your chin is above the bar.","Pause for a moment at the top, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle das Gerät auf die gewünschte Unterstützungsstufe ein.","Stelle dich auf die Fussplattform und greife die Griffe im Obergriff, etwas breiter als schulterbreit.","Halte die Brust aufrecht und die Schultern zurück, spanne deine Körpermitte an und beuge die Knie leicht.","Ziehe deinen Körper hoch, indem du die Ellbogen beugst und sie Richtung Körperseiten nach unten führst.","Ziehe weiter, bis sich dein Kinn über der Stange befindet.","Halte kurz oben inne und senke deinen Körper anschliessend langsam zurück in die Ausgangsposition ab.","Wiederhole die Bewegung für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1431.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1431.gif', 1784612222128, 1784612222128, 0),
  ('7c4d55fc-c324-5c25-9b54-54fe72db2bee', NULL, 'Assisted Standing Pull-up', 'Klimmzug stehend an der Maschine (unterstützt)', 'back', 'lats', 'leverage machine', 'Adjust the machine to your desired weight and height settings. Stand facing the machine with your feet shoulder-width apart. Grasp the handles with an overhand grip, slightly wider than shoulder-width apart. Engage your lats and biceps, and pull yourself up towards the handles. Pause for a moment at the top, squeezing your back muscles. Slowly lower yourself back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","forearms"]', '["Adjust the machine to your desired weight and height settings.","Stand facing the machine with your feet shoulder-width apart.","Grasp the handles with an overhand grip, slightly wider than shoulder-width apart.","Engage your lats and biceps, and pull yourself up towards the handles.","Pause for a moment at the top, squeezing your back muscles.","Slowly lower yourself back down to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle das Gerät auf das gewünschte Gewicht und die gewünschte Höhe ein.","Stelle dich mit schulterbreiten Füssen vor das Gerät.","Greife die Griffe im Obergriff, etwas breiter als schulterbreit.","Spanne Latissimus und Bizeps an und ziehe dich Richtung Griffe hoch.","Halte oben kurz inne und spanne die Rückenmuskulatur an.","Senke dich langsam zurück in die Ausgangsposition ab.","Wiederhole die Bewegung für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1432.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1432.gif', 1784612222128, 1784612222128, 0),
  ('bfcce4bb-ab6a-51fe-86ff-24a5b69c0ffb', NULL, 'Assisted Standing Triceps Extension (with Towel)', 'Trizepsstrecken im Stehen mit Handtuch (unterstützt)', 'upper arms', 'triceps', 'assisted', 'Stand with your feet shoulder-width apart and hold a towel with both hands behind your head. Keep your elbows close to your ears and your upper arms stationary. Slowly extend your forearms upward, squeezing your triceps at the top. Pause for a moment, then slowly lower the towel back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'shoulders', '["shoulders"]', '["Stand with your feet shoulder-width apart and hold a towel with both hands behind your head.","Keep your elbows close to your ears and your upper arms stationary.","Slowly extend your forearms upward, squeezing your triceps at the top.","Pause for a moment, then slowly lower the towel back down to the starting position.","Repeat for the desired number of repetitions."]', '["Stehe schulterbreit und halte ein Handtuch mit beiden Händen hinter dem Kopf.","Halte die Ellbogen nah an den Ohren und die Oberarme ruhig.","Strecke die Unterarme langsam nach oben und spanne den Trizeps in der Endposition an.","Halte kurz inne und senke das Handtuch anschliessend langsam zurück in die Ausgangsposition ab.","Wiederhole die Bewegung für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0018.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0018.gif', 1784612222128, 1784612222128, 0),
  ('362737d3-6caa-5e94-9a8f-69a3ce6d5b1d', NULL, 'Assisted Triceps Dip (Kneeling)', 'Trizeps-Dip an der Maschine (kniend, unterstützt)', 'upper arms', 'triceps', 'leverage machine', 'Adjust the machine to your desired weight and height. Kneel down on the pad facing the machine, with your hands gripping the handles. Lower your body by bending your elbows, keeping your back straight and close to the machine. Pause for a moment at the bottom, then push yourself back up to the starting position. Repeat for the desired number of repetitions.', NULL, 'chest', '["chest","shoulders"]', '["Adjust the machine to your desired weight and height.","Kneel down on the pad facing the machine, with your hands gripping the handles.","Lower your body by bending your elbows, keeping your back straight and close to the machine.","Pause for a moment at the bottom, then push yourself back up to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle das Gerät auf das gewünschte Gewicht und die gewünschte Höhe ein.","Knie dich auf das Polster vor dem Gerät und greife die Griffe.","Senke den Körper ab, indem du die Ellbogen beugst, der Rücken bleibt dabei gerade und nah am Gerät.","Halte unten kurz inne und drücke dich anschliessend zurück in die Ausgangsposition.","Wiederhole die Bewegung für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0019.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0019.gif', 1784612222128, 1784612222128, 0),
  ('b7f06feb-51a7-571f-bf5a-f21c032addfa', NULL, 'Assisted Wide-Grip Chest Dip (Kneeling)', 'Brust-Dip im weiten Griff an der Maschine (kniend, unterstützt)', 'chest', 'pectorals', 'leverage machine', 'Adjust the machine to your desired height and secure your knees on the pad. Grasp the handles with a wide grip and keep your elbows slightly bent. Lower your body by bending your elbows until your upper arms are parallel to the floor. Push yourself back up to the starting position by extending your arms. Repeat for the desired number of repetitions.', NULL, 'triceps', '["triceps","shoulders"]', '["Adjust the machine to your desired height and secure your knees on the pad.","Grasp the handles with a wide grip and keep your elbows slightly bent.","Lower your body by bending your elbows until your upper arms are parallel to the floor.","Push yourself back up to the starting position by extending your arms.","Repeat for the desired number of repetitions."]', '["Stelle das Gerät auf die gewünschte Höhe ein und platziere die Knie sicher auf dem Polster.","Greife die Griffe breit und halte die Ellbogen leicht gebeugt.","Senke den Körper ab, indem du die Ellbogen beugst, bis die Oberarme parallel zum Boden sind.","Drücke dich durch Strecken der Arme zurück in die Ausgangsposition.","Wiederhole die Bewegung für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/2364.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/2364.gif', 1784612222128, 1784612222128, 0),
  ('f141f12c-d869-5778-a289-e37c4d2e0b4d', NULL, 'Astride Jumps (Male)', 'Grätschsprünge (männlich)', 'cardio', 'cardiovascular system', 'body weight', 'Stand with your feet shoulder-width apart. Bend your knees and lower your body into a squat position. Jump explosively upwards, extending your legs and arms. While in the air, spread your legs apart and bring your arms out to the sides. Land softly with your feet shoulder-width apart, bending your knees to absorb the impact. Repeat for the desired number of repetitions.', NULL, 'quadriceps', '["quadriceps","hamstrings","calves"]', '["Stand with your feet shoulder-width apart.","Bend your knees and lower your body into a squat position.","Jump explosively upwards, extending your legs and arms.","While in the air, spread your legs apart and bring your arms out to the sides.","Land softly with your feet shoulder-width apart, bending your knees to absorb the impact.","Repeat for the desired number of repetitions."]', '["Stehe schulterbreit.","Beuge die Knie und senke den Körper in eine Kniebeugeposition ab.","Springe explosiv nach oben und strecke dabei Beine und Arme.","Spreize in der Luft die Beine und führe die Arme seitlich aus.","Lande weich mit schulterbreiten Füssen und beuge die Knie, um die Landung abzufedern.","Wiederhole die Bewegung für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/3220.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/3220.gif', 1784612222128, 1784612222128, 0),
  ('bd48b643-3a0f-5f07-a1ce-a77ab2a2d7ce', NULL, 'Back and Forth Step', 'Schritte vor und zurück', 'cardio', 'cardiovascular system', 'body weight', 'Stand with your feet shoulder-width apart. Step forward with your right foot, bending your knee and lowering your body into a lunge position. Push off with your right foot and step back to the starting position. Repeat the movement with your left foot, alternating legs with each step. Continue stepping back and forth, maintaining a steady pace. Repeat for the desired duration or number of repetitions.', NULL, 'quadriceps', '["quadriceps","hamstrings","glutes","calves"]', '["Stand with your feet shoulder-width apart.","Step forward with your right foot, bending your knee and lowering your body into a lunge position.","Push off with your right foot and step back to the starting position.","Repeat the movement with your left foot, alternating legs with each step.","Continue stepping back and forth, maintaining a steady pace.","Repeat for the desired duration or number of repetitions."]', '["Stehe schulterbreit.","Mache einen Schritt nach vorne mit dem rechten Fuss, beuge das Knie und senke den Körper in eine Ausfallschrittposition ab.","Stosse dich mit dem rechten Fuss ab und trete zurück in die Ausgangsposition.","Wiederhole die Bewegung mit dem linken Fuss und wechsle die Beine bei jedem Schritt.","Setze die Vor- und Rückwärtsschritte in gleichmässigem Tempo fort.","Wiederhole für die gewünschte Dauer oder Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/3672.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/3672.gif', 1784612222128, 1784612222128, 0),
  ('3bcf2ea8-f0d7-5bbc-b7c2-1fafb1272c7a', NULL, 'Back Extension on Exercise Ball', 'Rückenstrecker auf dem Gymnastikball', 'back', 'spine', 'stability ball', 'Place the stability ball on the ground and lie face down on top of it, with your hips resting on the ball and your feet against a wall or other stable surface. Position your hands behind your head or crossed over your chest. Engage your core and slowly lift your upper body off the ball, extending your back until your body forms a straight line from your head to your heels. Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'glutes', '["glutes","hamstrings"]', '["Place the stability ball on the ground and lie face down on top of it, with your hips resting on the ball and your feet against a wall or other stable surface.","Position your hands behind your head or crossed over your chest.","Engage your core and slowly lift your upper body off the ball, extending your back until your body forms a straight line from your head to your heels.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."]', '["Platziere den Gymnastikball auf dem Boden und lege dich mit dem Gesicht nach unten darauf, sodass die Hüfte auf dem Ball ruht und die Füsse an einer Wand oder anderen stabilen Fläche abgestützt sind.","Lege die Hände hinter den Kopf oder verschränke sie vor der Brust.","Spanne deine Körpermitte an und hebe den Oberkörper langsam vom Ball ab, indem du den Rücken streckst, bis dein Körper eine gerade Linie von Kopf bis Ferse bildet.","Halte kurz oben inne und senke den Oberkörper anschliessend langsam zurück in die Ausgangsposition ab.","Wiederhole die Bewegung für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1314.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1314.gif', 1784612222128, 1784612222128, 0),
  ('7527b80d-5482-5828-af1a-4f54252b0332', NULL, 'Back Lever', 'Back Lever', 'back', 'upper back', 'body weight', 'Start by hanging from a pull-up bar with an overhand grip, hands slightly wider than shoulder-width apart. Engage your core and pull your shoulder blades down and back. Bend your knees and tuck them towards your chest. Slowly lift your legs up, keeping them straight, until your body is parallel to the ground. Hold this position for a few seconds, then slowly lower your legs back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","forearms","core"]', '["Start by hanging from a pull-up bar with an overhand grip, hands slightly wider than shoulder-width apart.","Engage your core and pull your shoulder blades down and back.","Bend your knees and tuck them towards your chest.","Slowly lift your legs up, keeping them straight, until your body is parallel to the ground.","Hold this position for a few seconds, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."]', '["Hänge dich mit Obergriff an eine Klimmzugstange, die Hände etwas breiter als schulterbreit.","Spanne deine Körpermitte an und ziehe die Schulterblätter nach unten und hinten.","Beuge die Knie und ziehe sie Richtung Brust.","Hebe die Beine langsam gestreckt an, bis dein Körper parallel zum Boden ist.","Halte diese Position einige Sekunden und senke die Beine anschliessend langsam zurück in die Ausgangsposition ab.","Wiederhole die Bewegung für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/3297.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/3297.gif', 1784612222128, 1784612222128, 0),
  ('ab444738-749e-5b74-8484-8451fa17f89d', NULL, 'Back Pec Stretch', 'Rückendehnung', 'back', 'lats', 'body weight', 'Stand tall with your feet shoulder-width apart. Extend your arms straight out in front of you, parallel to the ground. Cross your arms in front of your body, with your right arm over your left arm. Interlock your fingers and rotate your palms away from your body. Slowly raise your arms up and away from your body, feeling a stretch in your back and chest. Hold the stretch for 15-30 seconds, then release. Repeat on the opposite side.', NULL, 'shoulders', '["shoulders","chest"]', '["Stand tall with your feet shoulder-width apart.","Extend your arms straight out in front of you, parallel to the ground.","Cross your arms in front of your body, with your right arm over your left arm.","Interlock your fingers and rotate your palms away from your body.","Slowly raise your arms up and away from your body, feeling a stretch in your back and chest.","Hold the stretch for 15-30 seconds, then release.","Repeat on the opposite side."]', '["Stehe aufrecht mit schulterbreiten Füssen.","Strecke die Arme gerade vor dir aus, parallel zum Boden.","Kreuze die Arme vor dem Körper, wobei der rechte Arm über dem linken liegt.","Verschränke die Finger und drehe die Handflächen vom Körper weg.","Hebe die Arme langsam vom Körper weg nach oben und spüre die Dehnung in Rücken und Brust.","Halte die Dehnung 15-30 Sekunden und löse sie anschliessend.","Wiederhole auf der anderen Seite."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1405.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1405.gif', 1784612222128, 1784612222128, 0),
  ('18f4214e-cbcf-5eae-94bf-ff28ddff1a9f', NULL, 'Backward Jump', 'Rückwärtssprung', 'upper legs', 'quads', 'body weight', 'Stand with your feet shoulder-width apart. Bend your knees slightly and jump backwards, pushing off with both feet. Land softly on the balls of your feet, bending your knees to absorb the impact. Repeat for the desired number of repetitions.', NULL, 'hamstrings', '["hamstrings","glutes","calves"]', '["Stand with your feet shoulder-width apart.","Bend your knees slightly and jump backwards, pushing off with both feet.","Land softly on the balls of your feet, bending your knees to absorb the impact.","Repeat for the desired number of repetitions."]', '["Stehe schulterbreit.","Beuge die Knie leicht und springe rückwärts, indem du dich mit beiden Füssen abstösst.","Lande weich auf den Fussballen und beuge die Knie, um die Landung abzufedern.","Wiederhole die Bewegung für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1473.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1473.gif', 1784612222128, 1784612222128, 0),
  ('51cce88d-81a9-5c9e-8de3-e5b8dda73b49', NULL, 'Balance Board', 'Balance Board', 'upper legs', 'quads', 'body weight', 'Place the balance board on a flat surface. Step onto the balance board with one foot, ensuring it is centered. Slowly shift your weight onto the foot on the balance board, keeping your core engaged. Maintain your balance and stability as you hold the position for a desired amount of time. Repeat the exercise with the other foot.', NULL, 'calves', '["calves","hamstrings","glutes"]', '["Place the balance board on a flat surface.","Step onto the balance board with one foot, ensuring it is centered.","Slowly shift your weight onto the foot on the balance board, keeping your core engaged.","Maintain your balance and stability as you hold the position for a desired amount of time.","Repeat the exercise with the other foot."]', '["Platziere das Balance-Board auf einer ebenen Fläche.","Stelle einen Fuss zentriert auf das Balance-Board.","Verlagere dein Gewicht langsam auf den Fuss auf dem Balance-Board und halte deine Körpermitte angespannt.","Halte das Gleichgewicht und die Stabilität, während du die Position für die gewünschte Zeit hältst.","Wiederhole die Übung mit dem anderen Fuss."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0020.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0020.gif', 1784612222128, 1784612222128, 0),
  ('b44508d6-e542-58ae-a714-5d071144ca12', NULL, 'Band Alternating Biceps Curl', 'Bizepscurl abwechselnd mit Band', 'upper arms', 'biceps', 'band', 'Stand with your feet shoulder-width apart and hold the band with an underhand grip, palms facing up. Keep your elbows close to your sides and slowly curl one arm up towards your shoulder, squeezing your biceps at the top. Lower the arm back down to the starting position and repeat with the other arm. Continue alternating arms for the desired number of repetitions.', NULL, 'forearms', '["forearms"]', '["Stand with your feet shoulder-width apart and hold the band with an underhand grip, palms facing up.","Keep your elbows close to your sides and slowly curl one arm up towards your shoulder, squeezing your biceps at the top.","Lower the arm back down to the starting position and repeat with the other arm.","Continue alternating arms for the desired number of repetitions."]', '["Stehe mit schulterbreit auseinander stehenden Füssen und halte das Band im Untergriff, Handflächen zeigen nach oben.","Halte deine Ellbogen nah am Körper und curle langsam einen Arm in Richtung Schulter, wobei du am oberen Punkt deinen Bizeps anspannst.","Senke den Arm zurück in die Ausgangsposition ab und wiederhole die Bewegung mit dem anderen Arm.","Wechsle die Arme fortlaufend für die gewünschte Anzahl Wiederholungen ab."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0968.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0968.gif', 1784612222128, 1784612222128, 0),
  ('0d41b2d7-5b2a-578e-b2bd-87daa22acc86', NULL, 'Band Alternating V-up', 'V-up abwechselnd mit Band', 'waist', 'abs', 'band', 'Lie flat on your back with your legs straight and your arms extended overhead, holding the band. Engage your abs and lift your legs and upper body off the ground simultaneously, reaching your hands towards your toes. As you lower your legs and upper body back down, switch the position of your legs, crossing one over the other. Repeat the movement, alternating the position of your legs with each repetition. Continue for the desired number of repetitions.', NULL, 'hip flexors', '["hip flexors"]', '["Lie flat on your back with your legs straight and your arms extended overhead, holding the band.","Engage your abs and lift your legs and upper body off the ground simultaneously, reaching your hands towards your toes.","As you lower your legs and upper body back down, switch the position of your legs, crossing one over the other.","Repeat the movement, alternating the position of your legs with each repetition.","Continue for the desired number of repetitions."]', '["Lege dich flach auf den Rücken, die Beine gestreckt und die Arme über dem Kopf ausgestreckt, während du das Band hältst.","Spanne deine Bauchmuskeln an und hebe gleichzeitig Beine und Oberkörper vom Boden ab, wobei du mit den Händen in Richtung Zehen greifst.","Während du Beine und Oberkörper wieder absenkst, wechsle die Position deiner Beine, indem du sie überkreuzt.","Wiederhole die Bewegung und wechsle bei jeder Wiederholung die Beinposition.","Fahre für die gewünschte Anzahl Wiederholungen fort."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0969.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0969.gif', 1784612222128, 1784612222128, 0),
  ('2d59ca1c-21a8-57df-8235-c54802d3c947', NULL, 'Band Assisted Pull-up', 'Klimmzug mit Band (unterstützt)', 'back', 'lats', 'band', 'Attach the band to a pull-up bar or sturdy anchor point. Step onto the band and grip the bar with your palms facing away from you, hands slightly wider than shoulder-width apart. Hang with your arms fully extended, keeping your core engaged and your shoulders down and back. Pull your body up towards the bar by squeezing your shoulder blades together and driving your elbows down towards your hips. Continue pulling until your chin is above the bar, then slowly lower yourself back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","forearms"]', '["Attach the band to a pull-up bar or sturdy anchor point.","Step onto the band and grip the bar with your palms facing away from you, hands slightly wider than shoulder-width apart.","Hang with your arms fully extended, keeping your core engaged and your shoulders down and back.","Pull your body up towards the bar by squeezing your shoulder blades together and driving your elbows down towards your hips.","Continue pulling until your chin is above the bar, then slowly lower yourself back down to the starting position.","Repeat for the desired number of repetitions."]', '["Befestige das Band an einer Klimmzugstange oder einem stabilen Fixpunkt.","Stelle dich auf das Band und greife die Stange mit den Handflächen von dir weg zeigend, die Hände etwas breiter als schulterbreit.","Hänge mit vollständig gestreckten Armen, spanne deine Körpermitte an und ziehe die Schultern nach unten und hinten.","Ziehe deinen Körper nach oben zur Stange, indem du die Schulterblätter zusammenziehst und die Ellbogen nach unten in Richtung Hüfte drückst.","Ziehe weiter, bis dein Kinn über der Stange ist, und senke dich dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0970.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0970.gif', 1784612222128, 1784612222128, 0),
  ('95ff9cbe-889d-5f58-9f7d-f18b0bb2c4da', NULL, 'Band Assisted Wheel Rollout', 'Ab-Rollout mit Band (unterstützt)', 'waist', 'abs', 'band', 'Kneel on the floor and hold the handles of the band with both hands, palms facing down. Place the band on the ground in front of you and position your hands shoulder-width apart. Engage your core and slowly roll the wheel forward, extending your body as far as you can while maintaining control. Pause for a moment at the furthest point, then slowly roll the wheel back towards your knees to return to the starting position. Repeat for the desired number of repetitions.', NULL, 'lower back', '["lower back"]', '["Kneel on the floor and hold the handles of the band with both hands, palms facing down.","Place the band on the ground in front of you and position your hands shoulder-width apart.","Engage your core and slowly roll the wheel forward, extending your body as far as you can while maintaining control.","Pause for a moment at the furthest point, then slowly roll the wheel back towards your knees to return to the starting position.","Repeat for the desired number of repetitions."]', '["Knie dich auf den Boden und halte die Griffe des Bandes mit beiden Händen, Handflächen zeigen nach unten.","Lege das Band vor dir auf den Boden und positioniere deine Hände schulterbreit.","Spanne deine Körpermitte an und rolle das Rad langsam nach vorne, wobei du deinen Körper so weit wie möglich streckst und dabei die Kontrolle behältst.","Halte am weitesten Punkt kurz inne und rolle das Rad dann langsam zurück in Richtung Knie, um in die Ausgangsposition zurückzukehren.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0971.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0971.gif', 1784612222128, 1784612222128, 0),
  ('5bc93214-69ff-5f60-8017-3dde94e62a4c', NULL, 'Band Bench Press', 'Bankdrücken mit Band', 'chest', 'pectorals', 'band', 'Lie flat on a bench with your feet flat on the ground and your back pressed against the bench. Grasp the band handles with an overhand grip, slightly wider than shoulder-width apart. Extend your arms fully, pushing the bands away from your chest. Slowly lower the bands back down to your chest, keeping your elbows at a 90-degree angle. Repeat for the desired number of repetitions.', NULL, 'triceps', '["triceps","shoulders"]', '["Lie flat on a bench with your feet flat on the ground and your back pressed against the bench.","Grasp the band handles with an overhand grip, slightly wider than shoulder-width apart.","Extend your arms fully, pushing the bands away from your chest.","Slowly lower the bands back down to your chest, keeping your elbows at a 90-degree angle.","Repeat for the desired number of repetitions."]', '["Lege dich flach auf eine Bank, die Füsse flach auf dem Boden und den Rücken gegen die Bank gedrückt.","Greife die Griffe des Bandes im Obergriff, etwas breiter als schulterbreit.","Strecke deine Arme vollständig durch und drücke die Bänder von deiner Brust weg.","Senke die Bänder langsam zurück zu deiner Brust ab, wobei deine Ellbogen einen 90-Grad-Winkel bilden.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1254.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1254.gif', 1784612222128, 1784612222128, 0),
  ('ab5bdba0-f2a6-521c-82db-01fca94c092e', NULL, 'Band Bent-Over Hip Extension', 'Hüftstrecken vorgebeugt mit Band', 'upper legs', 'glutes', 'band', 'Attach the band to a sturdy anchor point at ankle height. Stand facing away from the anchor point with your feet shoulder-width apart. Step back to create tension in the band, keeping your knees slightly bent. Hinge at the hips and lean forward, maintaining a neutral spine. Extend your right leg straight back, squeezing your glutes at the top. Lower your right leg back down and repeat with the left leg. Continue alternating legs for the desired number of repetitions.', NULL, 'hamstrings', '["hamstrings","lower back"]', '["Attach the band to a sturdy anchor point at ankle height.","Stand facing away from the anchor point with your feet shoulder-width apart.","Step back to create tension in the band, keeping your knees slightly bent.","Hinge at the hips and lean forward, maintaining a neutral spine.","Extend your right leg straight back, squeezing your glutes at the top.","Lower your right leg back down and repeat with the left leg.","Continue alternating legs for the desired number of repetitions."]', '["Befestige das Band an einem stabilen Fixpunkt auf Knöchelhöhe.","Stehe mit dem Rücken zum Fixpunkt, die Füsse schulterbreit auseinander.","Trete zurück, um Spannung im Band aufzubauen, und halte die Knie leicht gebeugt.","Beuge dich in der Hüfte nach vorne und behalte dabei eine neutrale Wirbelsäule bei.","Strecke dein rechtes Bein gerade nach hinten und spanne am oberen Punkt dein Gesäss an.","Senke dein rechtes Bein wieder ab und wiederhole die Bewegung mit dem linken Bein.","Wechsle die Beine fortlaufend für die gewünschte Anzahl Wiederholungen ab."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0980.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0980.gif', 1784612222128, 1784612222128, 0),
  ('873cbb94-1d9c-5d54-91dc-84c466dfd29f', NULL, 'Band Bicycle Crunch', 'Fahrrad-Crunch mit Band', 'waist', 'abs', 'band', 'Lie flat on your back with your hands behind your head and your knees bent. Lift your feet off the ground and bring your right knee towards your chest while simultaneously twisting your torso to bring your left elbow towards your right knee. Straighten your right leg while bringing your left knee towards your chest and twisting your torso to bring your right elbow towards your left knee. Continue alternating the twisting motion, as if you are pedaling a bicycle, while keeping your core engaged throughout the movement. Repeat for the desired number of repetitions.', NULL, 'hip flexors', '["hip flexors","obliques"]', '["Lie flat on your back with your hands behind your head and your knees bent.","Lift your feet off the ground and bring your right knee towards your chest while simultaneously twisting your torso to bring your left elbow towards your right knee.","Straighten your right leg while bringing your left knee towards your chest and twisting your torso to bring your right elbow towards your left knee.","Continue alternating the twisting motion, as if you are pedaling a bicycle, while keeping your core engaged throughout the movement.","Repeat for the desired number of repetitions."]', '["Lege dich flach auf den Rücken, die Hände hinter dem Kopf und die Knie gebeugt.","Hebe deine Füsse vom Boden ab und ziehe dein rechtes Knie zur Brust, während du gleichzeitig den Oberkörper drehst, um deinen linken Ellbogen zum rechten Knie zu bringen.","Strecke dein rechtes Bein, während du dein linkes Knie zur Brust ziehst und den Oberkörper drehst, um deinen rechten Ellbogen zum linken Knie zu bringen.","Wechsle die Drehbewegung fortlaufend ab, als würdest du Fahrrad fahren, und halte deine Körpermitte während der gesamten Bewegung angespannt.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0972.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0972.gif', 1784612222128, 1784612222128, 0),
  ('2072ee36-b7c7-5436-884e-06d02647082b', NULL, 'Band Close-Grip Pulldown', 'Latzug eng mit Band', 'back', 'lats', 'band', 'Attach the band to a high anchor point, such as a pull-up bar or sturdy beam. Stand facing the anchor point and grab the band with an underhand grip, hands shoulder-width apart. Step back to create tension in the band, keeping your feet hip-width apart. Engage your core and keep your back straight as you pull the band down towards your chest, squeezing your shoulder blades together. Pause for a moment at the bottom of the movement, then slowly release the band back to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","forearms"]', '["Attach the band to a high anchor point, such as a pull-up bar or sturdy beam.","Stand facing the anchor point and grab the band with an underhand grip, hands shoulder-width apart.","Step back to create tension in the band, keeping your feet hip-width apart.","Engage your core and keep your back straight as you pull the band down towards your chest, squeezing your shoulder blades together.","Pause for a moment at the bottom of the movement, then slowly release the band back to the starting position.","Repeat for the desired number of repetitions."]', '["Befestige das Band an einem hohen Fixpunkt, zum Beispiel einer Klimmzugstange oder einem stabilen Balken.","Stehe mit Blick zum Fixpunkt und greife das Band im Untergriff, die Hände schulterbreit auseinander.","Trete zurück, um Spannung im Band aufzubauen, die Füsse hüftbreit auseinander.","Spanne deine Körpermitte an und halte den Rücken gerade, während du das Band zur Brust ziehst und die Schulterblätter zusammenziehst.","Halte am unteren Punkt der Bewegung kurz inne und lasse das Band dann langsam zurück in die Ausgangsposition gleiten.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0974.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0974.gif', 1784612222128, 1784612222128, 0);

INSERT OR REPLACE INTO exercises (id, user_id, name, name_de, category, primary_muscle, equipment, instructions_en, instructions_de, muscle_group, secondary_muscles, instruction_steps_en, instruction_steps_de, thumbnail_url, gif_url, created_at, updated_at, deleted) VALUES
  ('e89989d2-747a-5a57-882a-83dccc060f5a', NULL, 'Band Close-Grip Push-up', 'Liegestütz eng mit Band', 'upper arms', 'triceps', 'band', 'Place a band around your upper arms, just above the elbows. Assume a push-up position with your hands directly under your shoulders and your body in a straight line from head to heels. Bend your elbows and lower your chest towards the ground, keeping your elbows close to your sides. Push through your palms to extend your arms and return to the starting position. Repeat for the desired number of repetitions.', NULL, 'chest', '["chest","shoulders"]', '["Place a band around your upper arms, just above the elbows.","Assume a push-up position with your hands directly under your shoulders and your body in a straight line from head to heels.","Bend your elbows and lower your chest towards the ground, keeping your elbows close to your sides.","Push through your palms to extend your arms and return to the starting position.","Repeat for the desired number of repetitions."]', '["Lege ein Band um deine Oberarme, direkt oberhalb der Ellbogen.","Nimm eine Liegestützposition ein, die Hände direkt unter den Schultern und der Körper in einer geraden Linie von Kopf bis Fersen.","Beuge deine Ellbogen und senke deine Brust in Richtung Boden ab, wobei du die Ellbogen nah am Körper hältst.","Drücke dich über die Handflächen ab, um die Arme zu strecken und in die Ausgangsposition zurückzukehren.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0975.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0975.gif', 1784612222128, 1784612222128, 0),
  ('66fab7aa-3cfc-5ccd-b0d0-0b27a25e52e7', NULL, 'Band Concentration Curl', 'Konzentrationscurl mit Band', 'upper arms', 'biceps', 'band', 'Sit on a bench or chair with your legs spread apart and your feet flat on the ground. Hold one end of the band in your hand and step on the other end with your foot on the same side. Lean forward slightly and rest your elbow on the inside of your thigh, just above the knee. With your palm facing up, slowly curl your hand towards your shoulder, keeping your upper arm stationary. Pause for a moment at the top, then slowly lower your hand back down to the starting position. Repeat for the desired number of repetitions, then switch sides.', NULL, 'forearms', '["forearms"]', '["Sit on a bench or chair with your legs spread apart and your feet flat on the ground.","Hold one end of the band in your hand and step on the other end with your foot on the same side.","Lean forward slightly and rest your elbow on the inside of your thigh, just above the knee.","With your palm facing up, slowly curl your hand towards your shoulder, keeping your upper arm stationary.","Pause for a moment at the top, then slowly lower your hand back down to the starting position.","Repeat for the desired number of repetitions, then switch sides."]', '["Setze dich auf eine Bank oder einen Stuhl, die Beine auseinander und die Füsse flach auf dem Boden.","Halte ein Ende des Bandes in der Hand und stelle dich mit dem Fuss auf derselben Seite auf das andere Ende.","Beuge dich leicht nach vorne und stütze deinen Ellbogen auf der Innenseite deines Oberschenkels, direkt oberhalb des Knies, ab.","Mit nach oben zeigender Handfläche curlst du deine Hand langsam in Richtung Schulter, während der Oberarm ruhig bleibt.","Halte am oberen Punkt kurz inne und senke deine Hand dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dann die Seite."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0976.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0976.gif', 1784612222128, 1784612222128, 0),
  ('2a384a8e-8708-574e-83ba-c264d88e2f85', NULL, 'Band Fixed Back Close Grip Pulldown', 'Latzug eng mit fixiertem Rücken mit Band', 'back', 'lats', 'band', 'Attach the band to a fixed point above you, such as a pull-up bar or sturdy beam. Sit down on a bench or chair facing the band, with your feet flat on the ground and your knees bent. Grasp the band with a close grip, palms facing towards you. Keep your back straight and engage your core. Pull the band down towards your chest, squeezing your shoulder blades together. Pause for a moment at the bottom of the movement, feeling the contraction in your lats. Slowly release the band back to the starting position, maintaining control throughout the movement. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","forearms"]', '["Attach the band to a fixed point above you, such as a pull-up bar or sturdy beam.","Sit down on a bench or chair facing the band, with your feet flat on the ground and your knees bent.","Grasp the band with a close grip, palms facing towards you.","Keep your back straight and engage your core.","Pull the band down towards your chest, squeezing your shoulder blades together.","Pause for a moment at the bottom of the movement, feeling the contraction in your lats.","Slowly release the band back to the starting position, maintaining control throughout the movement.","Repeat for the desired number of repetitions."]', '["Befestige das Band an einem festen Punkt über dir, zum Beispiel einer Klimmzugstange oder einem stabilen Balken.","Setze dich mit Blick zum Band auf eine Bank oder einen Stuhl, die Füsse flach auf dem Boden und die Knie gebeugt.","Greife das Band eng, die Handflächen zeigen zu dir.","Halte den Rücken gerade und spanne deine Körpermitte an.","Ziehe das Band zu deiner Brust und ziehe dabei die Schulterblätter zusammen.","Halte am unteren Punkt der Bewegung kurz inne und spüre die Anspannung im Latissimus.","Lasse das Band langsam zurück in die Ausgangsposition gleiten und behalte während der gesamten Bewegung die Kontrolle.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/3117.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/3117.gif', 1784612222128, 1784612222128, 0),
  ('7c705964-18b9-5b56-986b-5bbb6030a490', NULL, 'Band Fixed Back Underhand Pulldown', 'Latzug im Untergriff mit fixiertem Rücken mit Band', 'back', 'lats', 'band', 'Attach the band to a sturdy anchor point above your head. Stand facing the anchor point with your feet shoulder-width apart. Grasp the band with an underhand grip, hands slightly wider than shoulder-width apart. Step back to create tension in the band, keeping your arms fully extended. Engage your core and squeeze your shoulder blades together. Pull the band down towards your chest, leading with your elbows. Pause for a moment at the bottom of the movement, feeling the contraction in your lats. Slowly release the tension in the band and return to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","rhomboids","rear deltoids"]', '["Attach the band to a sturdy anchor point above your head.","Stand facing the anchor point with your feet shoulder-width apart.","Grasp the band with an underhand grip, hands slightly wider than shoulder-width apart.","Step back to create tension in the band, keeping your arms fully extended.","Engage your core and squeeze your shoulder blades together.","Pull the band down towards your chest, leading with your elbows.","Pause for a moment at the bottom of the movement, feeling the contraction in your lats.","Slowly release the tension in the band and return to the starting position.","Repeat for the desired number of repetitions."]', '["Befestige das Band an einem stabilen Fixpunkt über deinem Kopf.","Stehe mit Blick zum Fixpunkt, die Füsse schulterbreit auseinander.","Greife das Band im Untergriff, die Hände etwas breiter als schulterbreit.","Trete zurück, um Spannung im Band aufzubauen, und halte die Arme dabei vollständig gestreckt.","Spanne deine Körpermitte an und ziehe die Schulterblätter zusammen.","Ziehe das Band zu deiner Brust, die Ellbogen führen die Bewegung an.","Halte am unteren Punkt der Bewegung kurz inne und spüre die Anspannung im Latissimus.","Lasse die Spannung im Band langsam nach und kehre in die Ausgangsposition zurück.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/3116.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/3116.gif', 1784612222128, 1784612222128, 0),
  ('9e63c952-1637-5357-a92c-b954107137be', NULL, 'Band Front Lateral Raise', 'Frontales Seitheben mit Band', 'shoulders', 'delts', 'band', 'Stand with your feet shoulder-width apart and hold the band in front of your thighs with your palms facing down. Keep your arms straight and lift the band up in front of you until your arms are parallel to the ground. Pause for a moment at the top, then slowly lower the band back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'traps', '["traps","upper back"]', '["Stand with your feet shoulder-width apart and hold the band in front of your thighs with your palms facing down.","Keep your arms straight and lift the band up in front of you until your arms are parallel to the ground.","Pause for a moment at the top, then slowly lower the band back down to the starting position.","Repeat for the desired number of repetitions."]', '["Stehe mit schulterbreit auseinander stehenden Füssen und halte das Band vor deinen Oberschenkeln, Handflächen zeigen nach unten.","Halte die Arme gestreckt und hebe das Band vor dir an, bis deine Arme parallel zum Boden sind.","Halte am oberen Punkt kurz inne und senke das Band dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0977.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0977.gif', 1784612222128, 1784612222128, 0),
  ('f663e130-6fa6-501e-9535-725c9ef4e0c8', NULL, 'Band Front Raise', 'Frontheben mit Band', 'shoulders', 'delts', 'band', 'Stand with your feet shoulder-width apart and hold the band in front of your thighs with your palms facing down. Keep your arms straight and slowly raise them forward until they are parallel to the ground. Pause for a moment at the top, then slowly lower your arms back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'triceps', '["triceps","upper back"]', '["Stand with your feet shoulder-width apart and hold the band in front of your thighs with your palms facing down.","Keep your arms straight and slowly raise them forward until they are parallel to the ground.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."]', '["Stehe mit schulterbreit auseinander stehenden Füssen und halte das Band vor deinen Oberschenkeln, Handflächen zeigen nach unten.","Halte die Arme gestreckt und hebe sie langsam nach vorne an, bis sie parallel zum Boden sind.","Halte am oberen Punkt kurz inne und senke deine Arme dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0978.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0978.gif', 1784612222128, 1784612222128, 0),
  ('b1fb793a-7c11-5aa3-a8e4-20c064361fe2', NULL, 'Band Hip Lift', 'Hüftheben mit Band', 'upper legs', 'glutes', 'band', 'Lie on your back with your knees bent and feet flat on the ground. Place a resistance band just above your knees. Engage your glutes and core muscles. Press your heels into the ground and lift your hips off the floor, squeezing your glutes at the top. Pause for a moment at the top, then slowly lower your hips back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'hamstrings', '["hamstrings","quadriceps"]', '["Lie on your back with your knees bent and feet flat on the ground.","Place a resistance band just above your knees.","Engage your glutes and core muscles.","Press your heels into the ground and lift your hips off the floor, squeezing your glutes at the top.","Pause for a moment at the top, then slowly lower your hips back down to the starting position.","Repeat for the desired number of repetitions."]', '["Lege dich auf den Rücken, die Knie gebeugt und die Füsse flach auf dem Boden.","Platziere ein Widerstandsband direkt oberhalb deiner Knie.","Spanne dein Gesäss und deine Körpermitte an.","Drücke deine Fersen in den Boden und hebe deine Hüfte vom Boden ab, wobei du am oberen Punkt dein Gesäss anspannst.","Halte am oberen Punkt kurz inne und senke deine Hüfte dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1408.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1408.gif', 1784612222128, 1784612222128, 0),
  ('2d4c92b3-e3b0-5290-8c76-dd5591caeca0', NULL, 'Band Horizontal Pallof Press', 'Horizontaler Pallof-Press mit Band', 'waist', 'abs', 'band', 'Attach the band to a sturdy anchor point at waist height. Stand perpendicular to the anchor point with your feet shoulder-width apart. Grasp the band handle with both hands and step away from the anchor point to create tension in the band. Bring your hands to your chest, keeping your elbows bent and close to your body. Engage your core and maintain a stable stance. Extend your arms straight out in front of you, pushing the band away from your body. Hold the extended position for a few seconds, focusing on maintaining tension in your core. Slowly bring your hands back to your chest, resisting the pull of the band. Repeat for the desired number of repetitions.', NULL, 'obliques', '["obliques","glutes"]', '["Attach the band to a sturdy anchor point at waist height.","Stand perpendicular to the anchor point with your feet shoulder-width apart.","Grasp the band handle with both hands and step away from the anchor point to create tension in the band.","Bring your hands to your chest, keeping your elbows bent and close to your body.","Engage your core and maintain a stable stance.","Extend your arms straight out in front of you, pushing the band away from your body.","Hold the extended position for a few seconds, focusing on maintaining tension in your core.","Slowly bring your hands back to your chest, resisting the pull of the band.","Repeat for the desired number of repetitions."]', '["Befestige das Band an einem stabilen Fixpunkt auf Hüfthöhe.","Stehe seitlich zum Fixpunkt, die Füsse schulterbreit auseinander.","Greife den Griff des Bandes mit beiden Händen und trete vom Fixpunkt weg, um Spannung im Band aufzubauen.","Bringe deine Hände zur Brust, wobei die Ellbogen gebeugt und nah am Körper bleiben.","Spanne deine Körpermitte an und halte eine stabile Standposition.","Strecke deine Arme gerade vor dir aus und drücke das Band von deinem Körper weg.","Halte die gestreckte Position für einige Sekunden und achte darauf, die Spannung in deiner Körpermitte zu halten.","Bringe deine Hände langsam zurück zur Brust und widerstehe dabei dem Zug des Bandes.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0979.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0979.gif', 1784612222128, 1784612222128, 0),
  ('9fbb9eb3-2146-52f2-ad97-fa41eab00a07', NULL, 'Band Jack Knife Sit-up', 'Jackknife-Sit-up mit Band', 'waist', 'abs', 'band', 'Lie flat on your back with your legs straight and your arms extended overhead, holding the band. Engage your abs and lift your legs and upper body simultaneously, bringing your hands towards your feet. Pause for a moment at the top, then slowly lower your legs and upper body back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'hip flexors', '["hip flexors"]', '["Lie flat on your back with your legs straight and your arms extended overhead, holding the band.","Engage your abs and lift your legs and upper body simultaneously, bringing your hands towards your feet.","Pause for a moment at the top, then slowly lower your legs and upper body back down to the starting position.","Repeat for the desired number of repetitions."]', '["Lege dich flach auf den Rücken, die Beine gestreckt und die Arme über dem Kopf ausgestreckt, während du das Band hältst.","Spanne deine Bauchmuskeln an und hebe gleichzeitig Beine und Oberkörper an, wobei du mit den Händen in Richtung Füsse greifst.","Halte am oberen Punkt kurz inne und senke Beine und Oberkörper dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0981.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0981.gif', 1784612222128, 1784612222128, 0),
  ('0ce856d1-39c0-5b96-9c9c-38cf2022bbda', NULL, 'Band Kneeling One Arm Pulldown', 'Einarmiger Latzug kniend mit Band', 'back', 'lats', 'band', 'Attach the band to a sturdy anchor point above your head. Kneel down and hold the band with one hand, palm facing down. Extend your arm fully overhead, keeping your elbow slightly bent. Engage your lat muscles and pull the band down towards your side, bringing your elbow towards your ribcage. Pause for a moment at the bottom, then slowly release the tension and return to the starting position. Repeat for the desired number of repetitions, then switch sides.', NULL, 'biceps', '["biceps","rhomboids"]', '["Attach the band to a sturdy anchor point above your head.","Kneel down and hold the band with one hand, palm facing down.","Extend your arm fully overhead, keeping your elbow slightly bent.","Engage your lat muscles and pull the band down towards your side, bringing your elbow towards your ribcage.","Pause for a moment at the bottom, then slowly release the tension and return to the starting position.","Repeat for the desired number of repetitions, then switch sides."]', '["Befestige das Band an einem stabilen Fixpunkt über deinem Kopf.","Knie dich hin und halte das Band mit einer Hand, Handfläche zeigt nach unten.","Strecke deinen Arm vollständig über den Kopf, wobei der Ellbogen leicht gebeugt bleibt.","Spanne deinen Latissimus an und ziehe das Band nach unten zu deiner Seite, wobei der Ellbogen zum Brustkorb geführt wird.","Halte am unteren Punkt kurz inne, lasse die Spannung dann langsam nach und kehre in die Ausgangsposition zurück.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dann die Seite."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0983.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0983.gif', 1784612222128, 1784612222128, 0),
  ('987455ef-7bc7-59cf-92a6-a5e3a2cda6d1', NULL, 'Band Kneeling Twisting Crunch', 'Twist-Crunch kniend mit Band', 'waist', 'abs', 'band', 'Attach the band to a sturdy anchor point at waist height. Kneel down facing away from the anchor point and hold the band with both hands, keeping your elbows bent and close to your sides. Engage your abs and slowly twist your torso to one side, bringing your hands towards your opposite hip. Pause for a moment, then slowly return to the starting position. Repeat on the other side. Continue alternating sides for the desired number of repetitions.', NULL, 'obliques', '["obliques"]', '["Attach the band to a sturdy anchor point at waist height.","Kneel down facing away from the anchor point and hold the band with both hands, keeping your elbows bent and close to your sides.","Engage your abs and slowly twist your torso to one side, bringing your hands towards your opposite hip.","Pause for a moment, then slowly return to the starting position.","Repeat on the other side.","Continue alternating sides for the desired number of repetitions."]', '["Befestige das Band an einem stabilen Fixpunkt auf Hüfthöhe.","Knie dich mit dem Rücken zum Fixpunkt hin und halte das Band mit beiden Händen, die Ellbogen gebeugt und nah am Körper.","Spanne deine Bauchmuskeln an und drehe deinen Oberkörper langsam zur einen Seite, wobei du deine Hände in Richtung der gegenüberliegenden Hüfte bringst.","Halte kurz inne und kehre dann langsam in die Ausgangsposition zurück.","Wiederhole auf der anderen Seite.","Wechsle die Seiten fortlaufend für die gewünschte Anzahl Wiederholungen ab."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0985.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0985.gif', 1784612222128, 1784612222128, 0),
  ('d80554d8-d1ae-5de6-8ba2-4a3c1514d3b9', NULL, 'Band Lying Hip Internal Rotation', 'Hüftinnenrotation im Liegen mit Band', 'upper legs', 'glutes', 'band', 'Lie on your back with your legs straight and a resistance band looped around your feet. Bend your knees and bring them towards your chest, keeping your feet together. Slowly rotate your knees outwards, away from each other, while keeping your feet together. Pause for a moment at the end of the rotation, then slowly return to the starting position. Repeat for the desired number of repetitions.', NULL, 'hamstrings', '["hamstrings","quadriceps"]', '["Lie on your back with your legs straight and a resistance band looped around your feet.","Bend your knees and bring them towards your chest, keeping your feet together.","Slowly rotate your knees outwards, away from each other, while keeping your feet together.","Pause for a moment at the end of the rotation, then slowly return to the starting position.","Repeat for the desired number of repetitions."]', '["Lege dich auf den Rücken, die Beine gestreckt und ein Widerstandsband um deine Füsse geschlungen.","Beuge deine Knie und ziehe sie zur Brust, wobei die Füsse zusammenbleiben.","Drehe deine Knie langsam nach aussen, voneinander weg, während die Füsse zusammenbleiben.","Halte am Ende der Drehung kurz inne und kehre dann langsam in die Ausgangsposition zurück.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0984.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0984.gif', 1784612222128, 1784612222128, 0),
  ('291a4c02-8f4a-5cee-b0b4-5f77df21cb77', NULL, 'Band Lying Straight Leg Raise', 'Gestrecktes Beinheben im Liegen mit Band', 'waist', 'abs', 'band', 'Lie flat on your back with your legs straight and your feet together. Place the band around the arches of your feet and hold the ends of the band with your hands. Engaging your abs, lift both legs off the ground until they are perpendicular to the floor. Pause for a moment at the top, then slowly lower your legs back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'hip flexors', '["hip flexors"]', '["Lie flat on your back with your legs straight and your feet together.","Place the band around the arches of your feet and hold the ends of the band with your hands.","Engaging your abs, lift both legs off the ground until they are perpendicular to the floor.","Pause for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."]', '["Lege dich flach auf den Rücken, die Beine gestreckt und die Füsse zusammen.","Lege das Band um die Fussgewölbe und halte die Enden des Bandes mit den Händen.","Spanne deine Bauchmuskeln an und hebe beide Beine vom Boden ab, bis sie senkrecht zum Boden stehen.","Halte am oberen Punkt kurz inne und senke deine Beine dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1002.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1002.gif', 1784612222128, 1784612222128, 0),
  ('dde5754c-e001-5330-af10-39180a05008d', NULL, 'Band One Arm Overhead Biceps Curl', 'Einarmiger Bizepscurl über Kopf mit Band', 'upper arms', 'biceps', 'band', 'Stand with your feet shoulder-width apart and place one end of the band under your foot. Hold the other end of the band with your arm fully extended overhead, palm facing forward. Keeping your upper arm stationary, curl your forearm towards your shoulder, squeezing your biceps. Pause for a moment at the top, then slowly lower your forearm back to the starting position. Repeat for the desired number of repetitions, then switch arms.', NULL, 'forearms', '["forearms","shoulders"]', '["Stand with your feet shoulder-width apart and place one end of the band under your foot.","Hold the other end of the band with your arm fully extended overhead, palm facing forward.","Keeping your upper arm stationary, curl your forearm towards your shoulder, squeezing your biceps.","Pause for a moment at the top, then slowly lower your forearm back to the starting position.","Repeat for the desired number of repetitions, then switch arms."]', '["Stehe mit schulterbreit auseinander stehenden Füssen und platziere ein Ende des Bandes unter deinem Fuss.","Halte das andere Ende des Bandes mit vollständig über dem Kopf gestrecktem Arm, Handfläche zeigt nach vorne.","Halte den Oberarm ruhig und curle deinen Unterarm in Richtung Schulter, wobei du den Bizeps anspannst.","Halte am oberen Punkt kurz inne und senke deinen Unterarm dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dann den Arm."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0986.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0986.gif', 1784612222128, 1784612222128, 0),
  ('76b279fa-6a55-51a3-a218-912ef8b516b6', NULL, 'Band One Arm Single Leg Split Squat', 'Split Squat einarmig und einbeinig mit Band', 'upper legs', 'quads', 'band', 'Stand with your feet hip-width apart and place a resistance band around your ankles. Extend one leg forward and rest the top of your foot on a bench or step behind you. Hold onto a support with one hand for balance. Bend your standing leg and lower your body down into a squat position, keeping your knee in line with your toes. Push through your heel to return to the starting position. Repeat for the desired number of repetitions, then switch legs.', NULL, 'glutes', '["glutes","hamstrings"]', '["Stand with your feet hip-width apart and place a resistance band around your ankles.","Extend one leg forward and rest the top of your foot on a bench or step behind you.","Hold onto a support with one hand for balance.","Bend your standing leg and lower your body down into a squat position, keeping your knee in line with your toes.","Push through your heel to return to the starting position.","Repeat for the desired number of repetitions, then switch legs."]', '["Stehe mit hüftbreit auseinander stehenden Füssen und lege ein Widerstandsband um deine Knöchel.","Strecke ein Bein nach vorne aus und lege den Fussrücken auf eine Bank oder Stufe hinter dir ab.","Halte dich mit einer Hand an einer Stütze fest, um das Gleichgewicht zu halten.","Beuge dein Standbein und senke deinen Körper in eine Kniebeuge-Position ab, wobei dein Knie in einer Linie mit den Zehen bleibt.","Drücke dich über die Ferse ab, um in die Ausgangsposition zurückzukehren.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dann das Bein."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0987.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0987.gif', 1784612222128, 1784612222128, 0),
  ('4b04a4ac-01d5-53a3-952c-4a623c4ef444', NULL, 'Band One Arm Standing Low Row', 'Einarmiges Rudern tief im Stehen mit Band', 'back', 'upper back', 'band', 'Attach the band to a stable anchor point at waist height. Stand facing the anchor point with your feet shoulder-width apart. Hold the band with one hand, palm facing inward, and step back to create tension in the band. Bend your knees slightly and hinge forward at the hips, keeping your back straight. Pull the band towards your waist, squeezing your shoulder blades together. Pause for a moment at the top of the movement, then slowly release the band back to the starting position. Repeat for the desired number of repetitions, then switch sides.', NULL, 'biceps', '["biceps","shoulders"]', '["Attach the band to a stable anchor point at waist height.","Stand facing the anchor point with your feet shoulder-width apart.","Hold the band with one hand, palm facing inward, and step back to create tension in the band.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Pull the band towards your waist, squeezing your shoulder blades together.","Pause for a moment at the top of the movement, then slowly release the band back to the starting position.","Repeat for the desired number of repetitions, then switch sides."]', '["Befestige das Band an einem stabilen Fixpunkt auf Hüfthöhe.","Stehe mit Blick zum Fixpunkt, die Füsse schulterbreit auseinander.","Halte das Band mit einer Hand, Handfläche zeigt nach innen, und trete zurück, um Spannung im Band aufzubauen.","Beuge die Knie leicht und beuge dich in der Hüfte nach vorne, wobei der Rücken gerade bleibt.","Ziehe das Band zu deiner Hüfte und ziehe dabei die Schulterblätter zusammen.","Halte am oberen Punkt der Bewegung kurz inne und lasse das Band dann langsam zurück in die Ausgangsposition gleiten.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dann die Seite."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0988.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0988.gif', 1784612222128, 1784612222128, 0),
  ('c62df447-cd32-5929-a511-cbc668fb6feb', NULL, 'Band One Arm Twisting Chest Press', 'Einarmiges Brustdrücken mit Drehung mit Band', 'chest', 'pectorals', 'band', 'Attach the band to a sturdy anchor point at chest height. Stand with your side facing the anchor point and grab the band with one hand. Step away from the anchor point to create tension in the band. Position your feet shoulder-width apart and slightly bend your knees. Bring your hand holding the band across your body, towards the opposite shoulder. While maintaining tension in the band, push your hand forward and away from your body, extending your arm. Slowly return to the starting position and repeat for the desired number of repetitions. Switch sides and repeat the exercise with the other hand.', NULL, 'shoulders', '["shoulders","triceps"]', '["Attach the band to a sturdy anchor point at chest height.","Stand with your side facing the anchor point and grab the band with one hand.","Step away from the anchor point to create tension in the band.","Position your feet shoulder-width apart and slightly bend your knees.","Bring your hand holding the band across your body, towards the opposite shoulder.","While maintaining tension in the band, push your hand forward and away from your body, extending your arm.","Slowly return to the starting position and repeat for the desired number of repetitions.","Switch sides and repeat the exercise with the other hand."]', '["Befestige das Band an einem stabilen Fixpunkt auf Brusthöhe.","Stehe seitlich zum Fixpunkt und greife das Band mit einer Hand.","Trete vom Fixpunkt weg, um Spannung im Band aufzubauen.","Positioniere deine Füsse schulterbreit auseinander und beuge die Knie leicht.","Führe die Hand, die das Band hält, quer über deinen Körper zur gegenüberliegenden Schulter.","Während du die Spannung im Band hältst, drücke deine Hand nach vorne und von deinem Körper weg, wobei du den Arm streckst.","Kehre langsam in die Ausgangsposition zurück und wiederhole für die gewünschte Anzahl Wiederholungen.","Wechsle die Seite und wiederhole die Übung mit der anderen Hand."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0989.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0989.gif', 1784612222128, 1784612222128, 0),
  ('a611066b-2aee-586a-9aa2-8498c1add385', NULL, 'Band One Arm Twisting Seated Row', 'Einarmiges Rudern im Sitzen mit Drehung mit Band', 'back', 'upper back', 'band', 'Sit on a bench or chair with your feet flat on the ground and your back straight. Hold the band with one hand and extend your arm fully in front of you. Keeping your back straight, pull the band towards your body by bending your elbow and squeezing your shoulder blades together. At the same time, twist your torso towards the side of the pulling arm. Pause for a moment at the top, then slowly release the tension in the band and return to the starting position. Repeat for the desired number of repetitions, then switch to the other arm.', NULL, 'biceps', '["biceps","shoulders"]', '["Sit on a bench or chair with your feet flat on the ground and your back straight.","Hold the band with one hand and extend your arm fully in front of you.","Keeping your back straight, pull the band towards your body by bending your elbow and squeezing your shoulder blades together.","At the same time, twist your torso towards the side of the pulling arm.","Pause for a moment at the top, then slowly release the tension in the band and return to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."]', '["Setze dich auf eine Bank oder einen Stuhl, die Füsse flach auf dem Boden und der Rücken gerade.","Halte das Band mit einer Hand und strecke deinen Arm vollständig vor dir aus.","Halte den Rücken gerade und ziehe das Band zu deinem Körper, indem du den Ellbogen beugst und die Schulterblätter zusammenziehst.","Drehe gleichzeitig deinen Oberkörper zur Seite des ziehenden Arms.","Halte am oberen Punkt kurz inne, lasse die Spannung im Band dann langsam nach und kehre in die Ausgangsposition zurück.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dann zum anderen Arm."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0990.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0990.gif', 1784612222128, 1784612222128, 0),
  ('7c161565-1485-502b-9c2c-68b845d6a461', NULL, 'Band Pull Through', 'Pull-Through mit Band', 'upper legs', 'glutes', 'band', 'Attach a resistance band to a sturdy anchor point at ground level. Stand facing away from the anchor point with your feet shoulder-width apart. Step forward to create tension in the band, keeping your knees slightly bent. Hinge at the hips and push your glutes back, maintaining a slight bend in your knees. Lower your torso until it is parallel to the ground, feeling a stretch in your hamstrings. Drive your hips forward and squeeze your glutes to return to the starting position. Repeat for the desired number of repetitions.', NULL, 'hamstrings', '["hamstrings","lower back"]', '["Attach a resistance band to a sturdy anchor point at ground level.","Stand facing away from the anchor point with your feet shoulder-width apart.","Step forward to create tension in the band, keeping your knees slightly bent.","Hinge at the hips and push your glutes back, maintaining a slight bend in your knees.","Lower your torso until it is parallel to the ground, feeling a stretch in your hamstrings.","Drive your hips forward and squeeze your glutes to return to the starting position.","Repeat for the desired number of repetitions."]', '["Befestige ein Widerstandsband an einem stabilen Fixpunkt auf Bodenhöhe.","Stehe mit dem Rücken zum Fixpunkt, die Füsse schulterbreit auseinander.","Trete nach vorne, um Spannung im Band aufzubauen, und halte die Knie leicht gebeugt.","Beuge dich in der Hüfte und schiebe dein Gesäss nach hinten, wobei die Knie leicht gebeugt bleiben.","Senke deinen Oberkörper ab, bis er parallel zum Boden ist, und spüre eine Dehnung in den Beinbeugern.","Drücke deine Hüfte nach vorne und spanne dein Gesäss an, um in die Ausgangsposition zurückzukehren.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0991.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0991.gif', 1784612222128, 1784612222128, 0),
  ('06abbabd-3731-5b1d-b4c9-8556e9716ded', NULL, 'Band Push Sit-up', 'Druck-Sit-up mit Band', 'waist', 'abs', 'band', 'Attach the band securely to a stable anchor point. Lie flat on your back with your knees bent and feet flat on the ground. Hold the band with both hands and extend your arms straight up towards the ceiling. Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle. Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'shoulders', '["shoulders","chest"]', '["Attach the band securely to a stable anchor point.","Lie flat on your back with your knees bent and feet flat on the ground.","Hold the band with both hands and extend your arms straight up towards the ceiling.","Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."]', '["Befestige das Band sicher an einem stabilen Fixpunkt.","Lege dich flach auf den Rücken, die Knie gebeugt und die Füsse flach auf dem Boden.","Halte das Band mit beiden Händen und strecke die Arme gerade nach oben zur Decke.","Spanne deine Bauchmuskeln an und hebe deinen Oberkörper langsam vom Boden ab, wobei du dich nach vorne rollst, bis dein Oberkörper einen 45-Grad-Winkel bildet.","Halte am oberen Punkt kurz inne und senke deinen Oberkörper dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0992.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0992.gif', 1784612222128, 1784612222128, 0),
  ('7ff4ec21-71c4-5c89-b2a0-acf4cc542fff', NULL, 'Band Reverse Fly', 'Reverse Fliegende mit Band', 'shoulders', 'delts', 'band', 'Attach the band to a stationary object at chest height. Stand with your feet shoulder-width apart and hold the band with both hands in front of you. Keep your arms straight and lift them out to the sides until they are parallel to the ground. Squeeze your shoulder blades together at the top of the movement. Slowly lower your arms back to the starting position. Repeat for the desired number of repetitions.', NULL, 'upper back', '["upper back","trapezius"]', '["Attach the band to a stationary object at chest height.","Stand with your feet shoulder-width apart and hold the band with both hands in front of you.","Keep your arms straight and lift them out to the sides until they are parallel to the ground.","Squeeze your shoulder blades together at the top of the movement.","Slowly lower your arms back to the starting position.","Repeat for the desired number of repetitions."]', '["Befestige das Band an einem feststehenden Objekt auf Brusthöhe.","Stehe mit schulterbreit auseinander stehenden Füssen und halte das Band mit beiden Händen vor dir.","Halte die Arme gestreckt und hebe sie seitlich an, bis sie parallel zum Boden sind.","Ziehe am oberen Punkt der Bewegung die Schulterblätter zusammen.","Senke deine Arme langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0993.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0993.gif', 1784612222128, 1784612222128, 0),
  ('00661225-5c37-52e9-baa9-4fe25d2cf4c6', NULL, 'Band Reverse Wrist Curl', 'Handgelenk-Curl rückwärts mit Band', 'lower arms', 'forearms', 'band', 'Sit on a bench or chair with your feet flat on the ground. Hold the band with an overhand grip, palms facing down, and wrap it around your fingers. Rest your forearms on your thighs, with your wrists hanging off the edge. Slowly curl your wrists upward, squeezing your forearms. Pause for a moment at the top, then slowly lower your wrists back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'forearms', '["forearms"]', '["Sit on a bench or chair with your feet flat on the ground.","Hold the band with an overhand grip, palms facing down, and wrap it around your fingers.","Rest your forearms on your thighs, with your wrists hanging off the edge.","Slowly curl your wrists upward, squeezing your forearms.","Pause for a moment at the top, then slowly lower your wrists back down to the starting position.","Repeat for the desired number of repetitions."]', '["Setze dich auf eine Bank oder einen Stuhl, die Füsse flach auf dem Boden.","Halte das Band im Obergriff, Handflächen zeigen nach unten, und wickle es um deine Finger.","Lege deine Unterarme auf die Oberschenkel, die Handgelenke ragen über die Kante hinaus.","Curle deine Handgelenke langsam nach oben und spanne dabei die Unterarme an.","Halte am oberen Punkt kurz inne und senke deine Handgelenke dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0994.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0994.gif', 1784612222128, 1784612222128, 0),
  ('7a14696b-8f0a-539f-b88b-bbe251f350a0', NULL, 'Band Seated Hip Internal Rotation', 'Hüftinnenrotation im Sitzen mit Band', 'upper legs', 'glutes', 'band', 'Sit on a chair or bench with your back straight and feet flat on the ground. Place a resistance band around your thighs, just above your knees. Keep your knees bent at a 90-degree angle and your feet shoulder-width apart. Engage your glutes and slowly rotate your knees outward, pushing against the resistance of the band. Pause for a moment at the end of the movement, then slowly return to the starting position. Repeat for the desired number of repetitions.', NULL, 'hamstrings', '["hamstrings","quadriceps"]', '["Sit on a chair or bench with your back straight and feet flat on the ground.","Place a resistance band around your thighs, just above your knees.","Keep your knees bent at a 90-degree angle and your feet shoulder-width apart.","Engage your glutes and slowly rotate your knees outward, pushing against the resistance of the band.","Pause for a moment at the end of the movement, then slowly return to the starting position.","Repeat for the desired number of repetitions."]', '["Setze dich auf einen Stuhl oder eine Bank, der Rücken gerade und die Füsse flach auf dem Boden.","Lege ein Widerstandsband um deine Oberschenkel, direkt oberhalb der Knie.","Halte die Knie in einem 90-Grad-Winkel gebeugt und die Füsse schulterbreit auseinander.","Spanne dein Gesäss an und drehe deine Knie langsam nach aussen, gegen den Widerstand des Bandes.","Halte am Ende der Bewegung kurz inne und kehre dann langsam in die Ausgangsposition zurück.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0996.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0996.gif', 1784612222128, 1784612222128, 0),
  ('8cc33821-bc33-5dfe-aad5-ee99606ea7fa', NULL, 'Band Seated Twist', 'Rumpfdrehung im Sitzen mit Band', 'waist', 'abs', 'band', 'Sit on the ground with your legs extended in front of you and your back straight. Wrap the band around your waist and hold the ends with both hands. Engage your abs and slowly twist your torso to one side, keeping your back straight and your feet on the ground. Pause for a moment at the end of the twist, then slowly return to the starting position. Repeat the twist to the other side. Continue alternating sides for the desired number of repetitions.', NULL, 'obliques', '["obliques"]', '["Sit on the ground with your legs extended in front of you and your back straight.","Wrap the band around your waist and hold the ends with both hands.","Engage your abs and slowly twist your torso to one side, keeping your back straight and your feet on the ground.","Pause for a moment at the end of the twist, then slowly return to the starting position.","Repeat the twist to the other side.","Continue alternating sides for the desired number of repetitions."]', '["Setze dich auf den Boden, die Beine vor dir ausgestreckt und der Rücken gerade.","Wickle das Band um deine Taille und halte die Enden mit beiden Händen.","Spanne deine Bauchmuskeln an und drehe deinen Oberkörper langsam zur einen Seite, wobei der Rücken gerade bleibt und die Füsse am Boden bleiben.","Halte am Ende der Drehung kurz inne und kehre dann langsam in die Ausgangsposition zurück.","Wiederhole die Drehung zur anderen Seite.","Wechsle die Seiten fortlaufend für die gewünschte Anzahl Wiederholungen ab."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1011.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1011.gif', 1784612222128, 1784612222128, 0),
  ('e70b513f-67ec-5e09-87bd-f67aa30cced7', NULL, 'Band Shoulder Press', 'Schulterdrücken mit Band', 'shoulders', 'delts', 'band', 'Stand with your feet shoulder-width apart and place the band under your feet. Hold the band with your palms facing forward and raise your hands to shoulder height, elbows bent. Press the band overhead, fully extending your arms. Pause for a moment at the top, then slowly lower the band back to shoulder height. Repeat for the desired number of repetitions.', NULL, 'triceps', '["triceps","upper back"]', '["Stand with your feet shoulder-width apart and place the band under your feet.","Hold the band with your palms facing forward and raise your hands to shoulder height, elbows bent.","Press the band overhead, fully extending your arms.","Pause for a moment at the top, then slowly lower the band back to shoulder height.","Repeat for the desired number of repetitions."]', '["Stehe mit schulterbreit auseinander stehenden Füssen und platziere das Band unter deinen Füssen.","Halte das Band, die Handflächen zeigen nach vorne, und hebe die Hände auf Schulterhöhe, die Ellbogen gebeugt.","Drücke das Band über den Kopf und strecke dabei die Arme vollständig durch.","Halte am oberen Punkt kurz inne und senke das Band dann langsam zurück auf Schulterhöhe ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0997.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0997.gif', 1784612222128, 1784612222128, 0),
  ('4c212809-5d81-5ccb-8f24-80456144602a', NULL, 'Band Shrug', 'Schulterheben mit Band', 'back', 'traps', 'band', 'Stand with your feet shoulder-width apart and place the band under your feet, holding the ends with your hands. Keep your arms straight and relaxed, and let the band hang in front of your thighs. Engage your traps by shrugging your shoulders upward, lifting the band as high as possible. Hold the contraction for a moment, then slowly lower your shoulders back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'shoulders', '["shoulders"]', '["Stand with your feet shoulder-width apart and place the band under your feet, holding the ends with your hands.","Keep your arms straight and relaxed, and let the band hang in front of your thighs.","Engage your traps by shrugging your shoulders upward, lifting the band as high as possible.","Hold the contraction for a moment, then slowly lower your shoulders back down to the starting position.","Repeat for the desired number of repetitions."]', '["Stehe mit schulterbreit auseinander stehenden Füssen, platziere das Band unter deinen Füssen und halte die Enden mit den Händen.","Halte deine Arme gestreckt und entspannt, und lass das Band vor deinen Oberschenkeln hängen.","Spanne deinen Trapezmuskel an, indem du die Schultern nach oben ziehst und das Band so hoch wie möglich anhebst.","Halte die Anspannung kurz und senke deine Schultern dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1018.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1018.gif', 1784612222128, 1784612222128, 0),
  ('c1da3502-d8bd-535c-85a1-df83f9d8eb96', NULL, 'Band Side Triceps Extension', 'Seitliches Trizepsstrecken mit Band', 'upper arms', 'triceps', 'band', 'Stand with your feet shoulder-width apart and hold the band with both hands, palms facing down. Extend your arms straight out to the sides, keeping them parallel to the ground. Slowly bend your elbows and bring your hands towards your shoulders, keeping your upper arms still. Pause for a moment, then slowly extend your arms back out to the starting position. Repeat for the desired number of repetitions.', NULL, 'shoulders', '["shoulders"]', '["Stand with your feet shoulder-width apart and hold the band with both hands, palms facing down.","Extend your arms straight out to the sides, keeping them parallel to the ground.","Slowly bend your elbows and bring your hands towards your shoulders, keeping your upper arms still.","Pause for a moment, then slowly extend your arms back out to the starting position.","Repeat for the desired number of repetitions."]', '["Stehe mit schulterbreit auseinander stehenden Füssen und halte das Band mit beiden Händen, Handflächen zeigen nach unten.","Strecke deine Arme seitlich gerade aus, parallel zum Boden.","Beuge deine Ellbogen langsam und bringe die Hände in Richtung Schultern, wobei die Oberarme ruhig bleiben.","Halte kurz inne und strecke deine Arme dann langsam zurück in die Ausgangsposition aus.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0998.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0998.gif', 1784612222128, 1784612222128, 0),
  ('71617c22-9bde-5f94-be03-994859389746', NULL, 'Band Single Leg Calf Raise', 'Einbeiniges Wadenheben mit Band', 'lower legs', 'calves', 'band', 'Stand with your feet hip-width apart and place the band around the ball of your left foot. Hold onto a stable object for balance if needed. Slowly raise your left heel off the ground, lifting your body weight onto the ball of your foot. Pause for a moment at the top, then slowly lower your left heel back down to the starting position. Repeat for the desired number of repetitions, then switch to the right leg.', NULL, 'ankles', '["ankles","feet"]', '["Stand with your feet hip-width apart and place the band around the ball of your left foot.","Hold onto a stable object for balance if needed.","Slowly raise your left heel off the ground, lifting your body weight onto the ball of your foot.","Pause for a moment at the top, then slowly lower your left heel back down to the starting position.","Repeat for the desired number of repetitions, then switch to the right leg."]', '["Stehe mit hüftbreit auseinander stehenden Füssen und lege das Band um den Fussballen deines linken Fusses.","Halte dich bei Bedarf an einem stabilen Objekt fest, um das Gleichgewicht zu halten.","Hebe deine linke Ferse langsam vom Boden ab und verlagere dein Körpergewicht auf den Fussballen.","Halte am oberen Punkt kurz inne und senke deine linke Ferse dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dann zum rechten Bein."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0999.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0999.gif', 1784612222128, 1784612222128, 0),
  ('3f35abee-08e8-571c-9b97-8340ecee3af8', NULL, 'Band Single Leg Reverse Calf Raise', 'Einbeiniges umgekehrtes Wadenheben mit Band', 'lower legs', 'calves', 'band', 'Stand with your feet hip-width apart and place the band around the ball of your foot. Hold onto a stable object for balance. Slowly raise your heel off the ground, lifting your body weight onto the ball of your foot. Pause for a moment at the top, then slowly lower your heel back down to the starting position. Repeat for the desired number of repetitions, then switch to the other leg.', NULL, 'hamstrings', '["hamstrings","glutes"]', '["Stand with your feet hip-width apart and place the band around the ball of your foot.","Hold onto a stable object for balance.","Slowly raise your heel off the ground, lifting your body weight onto the ball of your foot.","Pause for a moment at the top, then slowly lower your heel back down to the starting position.","Repeat for the desired number of repetitions, then switch to the other leg."]', '["Stehe mit hüftbreit auseinander stehenden Füssen und lege das Band um den Fussballen.","Halte dich an einem stabilen Objekt fest, um das Gleichgewicht zu halten.","Hebe deine Ferse langsam vom Boden ab und verlagere dein Körpergewicht auf den Fussballen.","Halte am oberen Punkt kurz inne und senke deine Ferse dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dann zum anderen Bein."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1000.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1000.gif', 1784612222128, 1784612222128, 0),
  ('baff9d5c-dbc9-548c-b6c7-17e15fdc1c39', NULL, 'Band Single Leg Split Squat', 'Einbeiniger Split Squat mit Band', 'upper legs', 'quads', 'band', 'Stand with your feet hip-width apart and place a resistance band around your ankles. Take a big step forward with your right foot and a smaller step back with your left foot. Bend your knees and lower your body until your right thigh is parallel to the ground, keeping your left knee slightly above the ground. Push through your right heel to return to the starting position. Repeat on the other side.', NULL, 'glutes', '["glutes","hamstrings"]', '["Stand with your feet hip-width apart and place a resistance band around your ankles.","Take a big step forward with your right foot and a smaller step back with your left foot.","Bend your knees and lower your body until your right thigh is parallel to the ground, keeping your left knee slightly above the ground.","Push through your right heel to return to the starting position.","Repeat on the other side."]', '["Stehe mit hüftbreit auseinander stehenden Füssen und lege ein Widerstandsband um deine Knöchel.","Mache einen grossen Schritt nach vorne mit dem rechten Fuss und einen kleineren Schritt zurück mit dem linken Fuss.","Beuge deine Knie und senke deinen Körper ab, bis dein rechter Oberschenkel parallel zum Boden ist, wobei dein linkes Knie leicht über dem Boden bleibt.","Drücke dich über die rechte Ferse ab, um in die Ausgangsposition zurückzukehren.","Wiederhole auf der anderen Seite."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1001.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1001.gif', 1784612222128, 1784612222128, 0),
  ('76f6b346-2b8e-5be7-9078-c5169a7bdc0d', NULL, 'Band Squat', 'Kniebeuge mit Band', 'upper legs', 'glutes', 'band', 'Stand with your feet shoulder-width apart, with the band placed just above your knees. Keeping your chest up and core engaged, push your hips back and bend your knees to lower into a squat position. Make sure your knees are tracking over your toes and your weight is in your heels. Pause for a moment at the bottom, then push through your heels to return to the starting position. Repeat for the desired number of repetitions.', NULL, 'quadriceps', '["quadriceps","hamstrings","calves"]', '["Stand with your feet shoulder-width apart, with the band placed just above your knees.","Keeping your chest up and core engaged, push your hips back and bend your knees to lower into a squat position.","Make sure your knees are tracking over your toes and your weight is in your heels.","Pause for a moment at the bottom, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."]', '["Stehe mit schulterbreit auseinander stehenden Füssen, das Band direkt oberhalb deiner Knie platziert.","Halte die Brust aufrecht und die Körpermitte angespannt, schiebe die Hüfte nach hinten und beuge die Knie, um in eine Kniebeuge-Position abzusinken.","Achte darauf, dass deine Knie über den Zehen bleiben und dein Gewicht auf den Fersen liegt.","Halte am unteren Punkt kurz inne und drücke dich dann über die Fersen ab, um in die Ausgangsposition zurückzukehren.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1004.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1004.gif', 1784612222128, 1784612222128, 0),
  ('251c25da-3aaf-5150-8c5e-fed91b2300b3', NULL, 'Band Squat Row', 'Kniebeuge mit Rudern mit Band', 'upper legs', 'glutes', 'band', 'Attach the band to a sturdy anchor point at waist height. Stand facing the anchor point with your feet shoulder-width apart. Hold the band handles with your palms facing each other and your arms extended in front of you. Bend your knees and lower into a squat position, keeping your back straight and chest lifted. From the squat position, pull the band handles towards your body, squeezing your shoulder blades together. Pause for a moment at the top, then slowly release the tension and return to the starting position. Repeat for the desired number of repetitions.', NULL, 'hamstrings', '["hamstrings","quadriceps","back"]', '["Attach the band to a sturdy anchor point at waist height.","Stand facing the anchor point with your feet shoulder-width apart.","Hold the band handles with your palms facing each other and your arms extended in front of you.","Bend your knees and lower into a squat position, keeping your back straight and chest lifted.","From the squat position, pull the band handles towards your body, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly release the tension and return to the starting position.","Repeat for the desired number of repetitions."]', '["Befestige das Band an einem stabilen Fixpunkt auf Hüfthöhe.","Stehe mit Blick zum Fixpunkt, die Füsse schulterbreit auseinander.","Halte die Griffe des Bandes, die Handflächen zeigen zueinander, die Arme vor dir ausgestreckt.","Beuge deine Knie und senke dich in eine Kniebeuge-Position ab, wobei der Rücken gerade und die Brust aufgerichtet bleibt.","Ziehe aus der Kniebeuge-Position die Griffe des Bandes zu deinem Körper und ziehe dabei die Schulterblätter zusammen.","Halte am oberen Punkt kurz inne, lasse die Spannung dann langsam nach und kehre in die Ausgangsposition zurück.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1003.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1003.gif', 1784612222128, 1784612222128, 0),
  ('5303a661-6d52-5c46-b517-786de08d3bd7', NULL, 'Band Standing Crunch', 'Crunch im Stehen mit Band', 'waist', 'abs', 'band', 'Attach the band to a sturdy anchor point at waist height. Stand facing away from the anchor point with your feet shoulder-width apart. Hold the band with both hands and bring it up to your chest, keeping your elbows bent and close to your body. Engage your abs and slowly crunch forward, bringing your chest towards your knees. Pause for a moment at the top of the crunch, then slowly return to the starting position. Repeat for the desired number of repetitions.', NULL, 'obliques', '["obliques"]', '["Attach the band to a sturdy anchor point at waist height.","Stand facing away from the anchor point with your feet shoulder-width apart.","Hold the band with both hands and bring it up to your chest, keeping your elbows bent and close to your body.","Engage your abs and slowly crunch forward, bringing your chest towards your knees.","Pause for a moment at the top of the crunch, then slowly return to the starting position.","Repeat for the desired number of repetitions."]', '["Befestige das Band an einem stabilen Fixpunkt auf Hüfthöhe.","Stehe mit dem Rücken zum Fixpunkt, die Füsse schulterbreit auseinander.","Halte das Band mit beiden Händen und bringe es zu deiner Brust, wobei die Ellbogen gebeugt und nah am Körper bleiben.","Spanne deine Bauchmuskeln an und beuge dich langsam nach vorne, wobei du deine Brust in Richtung Knie bringst.","Halte am oberen Punkt der Bewegung kurz inne und kehre dann langsam in die Ausgangsposition zurück.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1005.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1005.gif', 1784612222128, 1784612222128, 0),
  ('9293901c-0c25-50c7-a49c-ea8022328e62', NULL, 'Band Standing Rear Delt Row', 'Rudern für die hintere Schulter im Stehen mit Band', 'shoulders', 'delts', 'band', 'Stand with your feet shoulder-width apart and place the band under your feet. Hold the band handles with your palms facing each other and your arms extended in front of you. Bend your knees slightly and hinge forward at the hips, keeping your back straight. Pull the band towards your chest, squeezing your shoulder blades together. Pause for a moment at the top, then slowly release the tension and return to the starting position. Repeat for the desired number of repetitions.', NULL, 'trapezius', '["trapezius","rhomboids","biceps"]', '["Stand with your feet shoulder-width apart and place the band under your feet.","Hold the band handles with your palms facing each other and your arms extended in front of you.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Pull the band towards your chest, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly release the tension and return to the starting position.","Repeat for the desired number of repetitions."]', '["Stehe mit schulterbreit auseinander stehenden Füssen und platziere das Band unter deinen Füssen.","Halte die Griffe des Bandes, die Handflächen zeigen zueinander, die Arme vor dir ausgestreckt.","Beuge die Knie leicht und beuge dich in der Hüfte nach vorne, wobei der Rücken gerade bleibt.","Ziehe das Band zu deiner Brust und ziehe dabei die Schulterblätter zusammen.","Halte am oberen Punkt kurz inne, lasse die Spannung dann langsam nach und kehre in die Ausgangsposition zurück.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1022.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1022.gif', 1784612222128, 1784612222128, 0),
  ('f61ee1d2-e630-588c-91de-50834e94c47d', NULL, 'Band Standing Twisting Crunch', 'Twist-Crunch im Stehen mit Band', 'waist', 'abs', 'band', 'Stand with your feet shoulder-width apart and place the band around your upper back, crossing it in front of your chest. Hold the ends of the band with your hands, keeping your elbows bent and close to your sides. Engage your abs and twist your torso to one side, bringing your elbow towards the opposite knee. Pause for a moment, then return to the starting position. Repeat on the other side. Continue alternating sides for the desired number of repetitions.', NULL, 'obliques', '["obliques"]', '["Stand with your feet shoulder-width apart and place the band around your upper back, crossing it in front of your chest.","Hold the ends of the band with your hands, keeping your elbows bent and close to your sides.","Engage your abs and twist your torso to one side, bringing your elbow towards the opposite knee.","Pause for a moment, then return to the starting position.","Repeat on the other side.","Continue alternating sides for the desired number of repetitions."]', '["Stelle dich mit schulterbreitem Stand hin und lege das Band um deinen oberen Rücken, wobei es sich vor deiner Brust kreuzt.","Halte die Enden des Bands mit den Händen, die Ellbogen gebeugt und nah am Körper.","Spanne deine Körpermitte an und drehe deinen Oberkörper zu einer Seite, wobei du den Ellbogen zum gegenüberliegenden Knie führst.","Halte kurz inne und kehre dann in die Ausgangsposition zurück.","Wiederhole auf der anderen Seite.","Wechsle die Seiten fortlaufend für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1007.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1007.gif', 1784612222128, 1784612222128, 0),
  ('f4e8ef0e-01ad-59a9-9358-62ebe356b7b0', NULL, 'Band Step-up', 'Step-up mit Band', 'upper legs', 'glutes', 'band', 'Place a band around your thighs, just above your knees. Stand facing a step or platform with your feet hip-width apart. Step up onto the platform with your right foot, pushing through your heel. Extend your left leg behind you, keeping it straight. Lower your left foot back down to the ground. Repeat with your left foot stepping up onto the platform. Continue alternating legs for the desired number of repetitions.', NULL, 'quadriceps', '["quadriceps","hamstrings","calves"]', '["Place a band around your thighs, just above your knees.","Stand facing a step or platform with your feet hip-width apart.","Step up onto the platform with your right foot, pushing through your heel.","Extend your left leg behind you, keeping it straight.","Lower your left foot back down to the ground.","Repeat with your left foot stepping up onto the platform.","Continue alternating legs for the desired number of repetitions."]', '["Lege ein Band um deine Oberschenkel, knapp über den Knien.","Stelle dich mit hüftbreitem Stand vor eine Stufe oder Plattform.","Steige mit dem rechten Fuss auf die Plattform und drücke dich über die Ferse ab.","Strecke dein linkes Bein gerade nach hinten aus.","Senke deinen linken Fuss zurück zum Boden.","Wiederhole, indem du mit dem linken Fuss auf die Plattform steigst.","Wechsle die Beine fortlaufend für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1008.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1008.gif', 1784612222128, 1784612222128, 0),
  ('e3910bbd-7017-518c-a10a-82291beefa68', NULL, 'Band Stiff Leg Deadlift', 'Kreuzheben mit steifen Beinen mit Band', 'upper legs', 'glutes', 'band', 'Stand with your feet shoulder-width apart and place the band around your ankles. Hold the band with both hands in front of your thighs, palms facing your body. Keeping your back straight and your core engaged, hinge at the hips and slowly lower your upper body towards the ground. As you lower, push your hips back and allow your knees to bend slightly. Lower the band towards the ground, feeling a stretch in your hamstrings. Pause for a moment at the bottom, then engage your glutes and hamstrings to lift your upper body back up to the starting position. Repeat for the desired number of repetitions.', NULL, 'hamstrings', '["hamstrings","lower back"]', '["Stand with your feet shoulder-width apart and place the band around your ankles.","Hold the band with both hands in front of your thighs, palms facing your body.","Keeping your back straight and your core engaged, hinge at the hips and slowly lower your upper body towards the ground.","As you lower, push your hips back and allow your knees to bend slightly.","Lower the band towards the ground, feeling a stretch in your hamstrings.","Pause for a moment at the bottom, then engage your glutes and hamstrings to lift your upper body back up to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle dich mit schulterbreitem Stand hin und lege das Band um deine Knöchel.","Halte das Band mit beiden Händen vor deinen Oberschenkeln, Handflächen zu deinem Körper zeigend.","Halte den Rücken gerade und spanne deine Körpermitte an, beuge dich in der Hüfte und senke deinen Oberkörper langsam Richtung Boden.","Schiebe dabei deine Hüfte nach hinten und lasse die Knie leicht beugen.","Senke das Band Richtung Boden ab, du spürst eine Dehnung in den Beinbeugern.","Halte unten kurz inne und richte deinen Oberkörper dann mit Gesäss und Beinbeugern wieder in die Ausgangsposition auf.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1009.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1009.gif', 1784612222128, 1784612222128, 0),
  ('1c3f7657-9723-55a9-8c28-7728f8aac9c3', NULL, 'Band Straight Back Stiff Leg Deadlift', 'Kreuzheben mit geradem Rücken und steifen Beinen mit Band', 'upper legs', 'glutes', 'band', 'Stand with your feet shoulder-width apart and place the band around your upper legs. Hold the band with both hands in front of your thighs, palms facing your body. Keeping your back straight and your knees slightly bent, hinge at the hips and lower the band towards the ground. Feel the stretch in your hamstrings as you lower the band. Engage your glutes and hamstrings to lift your body back up to the starting position. Repeat for the desired number of repetitions.', NULL, 'hamstrings', '["hamstrings","lower back"]', '["Stand with your feet shoulder-width apart and place the band around your upper legs.","Hold the band with both hands in front of your thighs, palms facing your body.","Keeping your back straight and your knees slightly bent, hinge at the hips and lower the band towards the ground.","Feel the stretch in your hamstrings as you lower the band.","Engage your glutes and hamstrings to lift your body back up to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle dich mit schulterbreitem Stand hin und lege das Band um deine Oberschenkel.","Halte das Band mit beiden Händen vor deinen Oberschenkeln, Handflächen zu deinem Körper zeigend.","Halte den Rücken gerade und die Knie leicht gebeugt, beuge dich in der Hüfte und senke das Band Richtung Boden ab.","Spüre dabei die Dehnung in den Beinbeugern.","Spanne Gesäss und Beinbeuger an, um deinen Körper zurück in die Ausgangsposition zu heben.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1023.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1023.gif', 1784612222128, 1784612222128, 0),
  ('5a61eda5-542a-5644-9120-3232eb3a9510', NULL, 'Band Straight Leg Deadlift', 'Kreuzheben mit gestreckten Beinen mit Band', 'back', 'spine', 'band', 'Stand with your feet shoulder-width apart and place the band around your feet. Hold the band with both hands, palms facing your body, and keep your arms straight. Engage your core and maintain a slight bend in your knees. Slowly hinge forward at your hips, keeping your back straight and chest lifted. Lower the band towards the ground while keeping your legs straight. Pause for a moment at the bottom, then squeeze your glutes and hamstrings to return to the starting position. Repeat for the desired number of repetitions.', NULL, 'hamstrings', '["hamstrings","glutes"]', '["Stand with your feet shoulder-width apart and place the band around your feet.","Hold the band with both hands, palms facing your body, and keep your arms straight.","Engage your core and maintain a slight bend in your knees.","Slowly hinge forward at your hips, keeping your back straight and chest lifted.","Lower the band towards the ground while keeping your legs straight.","Pause for a moment at the bottom, then squeeze your glutes and hamstrings to return to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle dich mit schulterbreitem Stand hin und lege das Band um deine Füsse.","Halte das Band mit beiden Händen, Handflächen zu deinem Körper zeigend, und halte die Arme gestreckt.","Spanne deine Körpermitte an und behalte eine leichte Beugung in den Knien bei.","Beuge dich langsam in der Hüfte nach vorne, halte den Rücken gerade und die Brust aufgerichtet.","Senke das Band Richtung Boden ab, während du die Beine gestreckt hältst.","Halte unten kurz inne und kehre dann durch Anspannen von Gesäss und Beinbeugern in die Ausgangsposition zurück.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1010.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1010.gif', 1784612222128, 1784612222128, 0),
  ('7158fdfa-c19d-5215-b063-540d4d97f436', NULL, 'Band Twisting Overhead Press', 'Überkopfdrücken mit Drehung mit Band', 'shoulders', 'delts', 'band', 'Stand with your feet shoulder-width apart and place the band under your feet. Hold the band handles at shoulder height with your palms facing forward. Engage your core and press the band overhead, fully extending your arms. As you press, twist your torso to one side, keeping your hips stable. Pause for a moment at the top, then return to the starting position. Repeat the press and twist on the opposite side. Continue alternating sides for the desired number of repetitions.', NULL, 'triceps', '["triceps","upper back"]', '["Stand with your feet shoulder-width apart and place the band under your feet.","Hold the band handles at shoulder height with your palms facing forward.","Engage your core and press the band overhead, fully extending your arms.","As you press, twist your torso to one side, keeping your hips stable.","Pause for a moment at the top, then return to the starting position.","Repeat the press and twist on the opposite side.","Continue alternating sides for the desired number of repetitions."]', '["Stelle dich mit schulterbreitem Stand hin und lege das Band unter deine Füsse.","Halte die Griffe des Bands auf Schulterhöhe, Handflächen nach vorne zeigend.","Spanne deine Körpermitte an und drücke das Band über den Kopf, bis die Arme vollständig gestreckt sind.","Drehe dabei deinen Oberkörper zu einer Seite, während deine Hüfte stabil bleibt.","Halte oben kurz inne und kehre dann in die Ausgangsposition zurück.","Wiederhole das Drücken und Drehen auf der Gegenseite.","Wechsle die Seiten fortlaufend für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1012.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1012.gif', 1784612222128, 1784612222128, 0),
  ('d7ea9b2b-516e-5517-969f-8496246d9931', NULL, 'Band Two Legs Calf Raise (Band Under Both Legs) V. 2', 'Wadenheben beidbeinig mit Band (Band unter beiden Beinen) V. 2', 'lower legs', 'calves', 'band', 'Stand with your feet shoulder-width apart and place a resistance band under both feet. Hold the ends of the band with your hands for stability. Raise your heels off the ground as high as possible, using your calves. Pause for a moment at the top, then slowly lower your heels back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'ankles', '["ankles","feet"]', '["Stand with your feet shoulder-width apart and place a resistance band under both feet.","Hold the ends of the band with your hands for stability.","Raise your heels off the ground as high as possible, using your calves.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle dich mit schulterbreitem Stand hin und lege ein Widerstandsband unter beide Füsse.","Halte die Enden des Bands mit den Händen zur Stabilisierung.","Hebe deine Fersen so weit wie möglich vom Boden ab, angetrieben durch deine Waden.","Halte oben kurz inne und senke deine Fersen dann langsam zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1369.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1369.gif', 1784612222128, 1784612222128, 0),
  ('6b69f6cb-f2c4-591b-a6b1-09d090c51bf1', NULL, 'Band Underhand Pulldown', 'Latzug im Untergriff mit Band', 'back', 'lats', 'band', 'Attach the band to a high anchor point, such as a pull-up bar or sturdy beam. Stand facing the anchor point with your feet shoulder-width apart. Grasp the band with an underhand grip, hands slightly wider than shoulder-width apart. Extend your arms fully overhead, keeping your elbows slightly bent. Engage your lats and pull the band down towards your chest, squeezing your shoulder blades together. Pause for a moment at the bottom of the movement, then slowly release the tension and return to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","forearms"]', '["Attach the band to a high anchor point, such as a pull-up bar or sturdy beam.","Stand facing the anchor point with your feet shoulder-width apart.","Grasp the band with an underhand grip, hands slightly wider than shoulder-width apart.","Extend your arms fully overhead, keeping your elbows slightly bent.","Engage your lats and pull the band down towards your chest, squeezing your shoulder blades together.","Pause for a moment at the bottom of the movement, then slowly release the tension and return to the starting position.","Repeat for the desired number of repetitions."]', '["Befestige das Band an einem hohen Fixpunkt, zum Beispiel einer Klimmzugstange oder einem stabilen Balken.","Stelle dich mit schulterbreitem Stand dem Fixpunkt zugewandt hin.","Fasse das Band im Untergriff, die Hände etwas breiter als schulterbreit.","Strecke deine Arme vollständig über den Kopf, die Ellbogen leicht gebeugt.","Spanne deinen Latissimus an und ziehe das Band Richtung Brust, während du die Schulterblätter zusammenziehst.","Halte unten kurz inne, löse die Spannung dann langsam und kehre in die Ausgangsposition zurück.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1013.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1013.gif', 1784612222128, 1784612222128, 0),
  ('b8e3dd07-a07a-5a0f-a479-02ffd3618b50', NULL, 'Band V-up', 'V-up mit Band', 'waist', 'abs', 'band', 'Lie flat on your back with your legs straight and your arms extended overhead, holding the band. Engaging your abs, lift your legs and upper body off the ground simultaneously, reaching your hands towards your toes. Pause for a moment at the top, then slowly lower your legs and upper body back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'hip flexors', '["hip flexors"]', '["Lie flat on your back with your legs straight and your arms extended overhead, holding the band.","Engaging your abs, lift your legs and upper body off the ground simultaneously, reaching your hands towards your toes.","Pause for a moment at the top, then slowly lower your legs and upper body back down to the starting position.","Repeat for the desired number of repetitions."]', '["Lege dich flach auf den Rücken, die Beine gestreckt und die Arme über dem Kopf ausgestreckt, das Band haltend.","Spanne deine Bauchmuskeln an und hebe Beine und Oberkörper gleichzeitig vom Boden ab, wobei du mit den Händen zu deinen Zehen greifst.","Halte oben kurz inne und senke Beine und Oberkörper dann langsam zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1014.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1014.gif', 1784612222128, 1784612222128, 0),
  ('1f681a8c-1ed0-56d5-9a0f-03e8cca21ad7', NULL, 'Band Vertical Pallof Press', 'Vertikaler Pallof-Press mit Band', 'waist', 'abs', 'band', 'Stand with your feet shoulder-width apart and wrap the band around a sturdy object at chest height. Hold the band with both hands and step away from the anchor point, creating tension in the band. Position yourself perpendicular to the anchor point, with your side facing the band. Extend your arms straight out in front of you, keeping your hands at chest height. Engage your core and press the band away from your chest, fully extending your arms. Hold the position for a few seconds, then slowly bring the band back towards your chest. Repeat for the desired number of repetitions, then switch sides.', NULL, 'obliques', '["obliques","glutes"]', '["Stand with your feet shoulder-width apart and wrap the band around a sturdy object at chest height.","Hold the band with both hands and step away from the anchor point, creating tension in the band.","Position yourself perpendicular to the anchor point, with your side facing the band.","Extend your arms straight out in front of you, keeping your hands at chest height.","Engage your core and press the band away from your chest, fully extending your arms.","Hold the position for a few seconds, then slowly bring the band back towards your chest.","Repeat for the desired number of repetitions, then switch sides."]', '["Stelle dich mit schulterbreitem Stand hin und wickle das Band auf Brusthöhe um ein stabiles Objekt.","Halte das Band mit beiden Händen und trete vom Fixpunkt weg, um Spannung im Band aufzubauen.","Stelle dich seitlich zum Fixpunkt, sodass deine Seite dem Band zugewandt ist.","Strecke deine Arme gerade vor dir aus, die Hände auf Brusthöhe.","Spanne deine Körpermitte an und drücke das Band von deiner Brust weg, bis die Arme vollständig gestreckt sind.","Halte die Position einige Sekunden, bevor du das Band langsam zurück zur Brust führst.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dann die Seite."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1015.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1015.gif', 1784612222128, 1784612222128, 0),
  ('73609389-900e-506e-87cc-5515ca2f844b', NULL, 'Band Wrist Curl', 'Handgelenk-Curl mit Band', 'lower arms', 'forearms', 'band', 'Sit on a bench or chair with your feet flat on the ground. Hold the band with both hands, palms facing up, and rest your forearms on your thighs. Slowly curl your wrists upward, squeezing your forearms. Pause for a moment at the top, then slowly lower your wrists back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","triceps"]', '["Sit on a bench or chair with your feet flat on the ground.","Hold the band with both hands, palms facing up, and rest your forearms on your thighs.","Slowly curl your wrists upward, squeezing your forearms.","Pause for a moment at the top, then slowly lower your wrists back down to the starting position.","Repeat for the desired number of repetitions."]', '["Setze dich auf eine Bank oder einen Stuhl, die Füsse flach auf dem Boden.","Halte das Band mit beiden Händen, Handflächen nach oben, und lege deine Unterarme auf die Oberschenkel.","Rolle deine Handgelenke langsam nach oben und spanne dabei die Unterarme an.","Halte oben kurz inne und senke deine Handgelenke dann langsam zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1016.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1016.gif', 1784612222128, 1784612222128, 0),
  ('d5251f22-6072-5ef0-a9a3-8653aa1329a9', NULL, 'Band Y-Raise', 'Y-Raise mit Band', 'shoulders', 'delts', 'band', 'Stand with your feet shoulder-width apart and hold the band in front of your thighs with your palms facing inwards. Keep your arms straight and lift them up and out to the sides, forming a ''Y'' shape with your body. Squeeze your shoulder blades together at the top of the movement. Slowly lower your arms back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'traps', '["traps","rhomboids"]', '["Stand with your feet shoulder-width apart and hold the band in front of your thighs with your palms facing inwards.","Keep your arms straight and lift them up and out to the sides, forming a ''Y'' shape with your body.","Squeeze your shoulder blades together at the top of the movement.","Slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle dich mit schulterbreitem Stand hin und halte das Band vor deinen Oberschenkeln, Handflächen nach innen zeigend.","Halte die Arme gestreckt und hebe sie seitlich nach oben aussen an, sodass dein Körper ein ''Y'' bildet.","Ziehe die Schulterblätter am oberen Punkt der Bewegung zusammen.","Senke deine Arme langsam zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1017.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1017.gif', 1784612222128, 1784612222128, 0),
  ('c5a28ce0-bb5e-5870-87d7-6eafcf11d262', NULL, 'Barbell Alternate Biceps Curl', 'Abwechselnder Langhantel-Bizepscurl', 'upper arms', 'biceps', 'barbell', 'Stand up straight with your feet shoulder-width apart and hold a barbell in each hand, palms facing forward. Keep your upper arms stationary and exhale as you curl the weights while contracting your biceps. Continue to raise the barbells until your biceps are fully contracted and the barbells are at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale as you slowly begin to lower the barbells back to the starting position. Repeat for the desired number of repetitions, alternating arms.', NULL, 'forearms', '["forearms"]', '["Stand up straight with your feet shoulder-width apart and hold a barbell in each hand, palms facing forward.","Keep your upper arms stationary and exhale as you curl the weights while contracting your biceps.","Continue to raise the barbells until your biceps are fully contracted and the barbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale as you slowly begin to lower the barbells back to the starting position.","Repeat for the desired number of repetitions, alternating arms."]', '["Stehe aufrecht mit schulterbreitem Stand und halte in jeder Hand eine Langhantel, Handflächen nach vorne zeigend.","Halte deine Oberarme ruhig und atme aus, während du die Gewichte hochziehst und dabei deinen Bizeps anspannst.","Hebe die Langhanteln weiter an, bis dein Bizeps vollständig angespannt ist und sich die Langhanteln auf Schulterhöhe befinden.","Halte die angespannte Position für einen kurzen Moment und spanne dabei deinen Bizeps an.","Atme ein, während du die Langhanteln langsam zurück in die Ausgangsposition senkst.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dabei die Arme ab."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0023.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0023.gif', 1784612222128, 1784612222128, 0),
  ('ba19641b-3cf2-50ae-8d7a-30decb97adc3', NULL, 'Barbell Bench Front Squat', 'Langhantel-Frontkniebeuge zur Bank', 'upper legs', 'quads', 'barbell', 'Start by standing with your feet shoulder-width apart and the barbell resting on your upper chest, just below your collarbone. Hold the barbell with an overhand grip, keeping your elbows up and your upper arms parallel to the ground. Lower your body down into a squat position by bending at the knees and hips, keeping your back straight and your chest up. Pause for a moment at the bottom of the squat, then push through your heels to return to the starting position. Repeat for the desired number of repetitions.', NULL, 'hamstrings', '["hamstrings","glutes","calves"]', '["Start by standing with your feet shoulder-width apart and the barbell resting on your upper chest, just below your collarbone.","Hold the barbell with an overhand grip, keeping your elbows up and your upper arms parallel to the ground.","Lower your body down into a squat position by bending at the knees and hips, keeping your back straight and your chest up.","Pause for a moment at the bottom of the squat, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle dich mit schulterbreitem Stand hin, die Langhantel liegt auf deiner oberen Brust, knapp unterhalb des Schlüsselbeins.","Halte die Langhantel im Obergriff, die Ellbogen nach oben gerichtet und die Oberarme parallel zum Boden.","Senke deinen Körper in die Hocke ab, indem du Knie und Hüfte beugst, den Rücken gerade und die Brust aufgerichtet haltend.","Halte am unteren Punkt der Kniebeuge kurz inne und drücke dich dann über die Fersen zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0024.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0024.gif', 1784612222128, 1784612222128, 0),
  ('52b93346-35c6-5d9f-98c9-aee8761fa247', NULL, 'Barbell Bench Press', 'Langhantel-Bankdrücken', 'chest', 'pectorals', 'barbell', 'Lie flat on a bench with your feet flat on the ground and your back pressed against the bench. Grasp the barbell with an overhand grip slightly wider than shoulder-width apart. Lift the barbell off the rack and hold it directly above your chest with your arms fully extended. Lower the barbell slowly towards your chest, keeping your elbows tucked in. Pause for a moment when the barbell touches your chest. Push the barbell back up to the starting position by extending your arms. Repeat for the desired number of repetitions.', NULL, 'triceps', '["triceps","shoulders"]', '["Lie flat on a bench with your feet flat on the ground and your back pressed against the bench.","Grasp the barbell with an overhand grip slightly wider than shoulder-width apart.","Lift the barbell off the rack and hold it directly above your chest with your arms fully extended.","Lower the barbell slowly towards your chest, keeping your elbows tucked in.","Pause for a moment when the barbell touches your chest.","Push the barbell back up to the starting position by extending your arms.","Repeat for the desired number of repetitions."]', '["Lege dich flach auf eine Bank, die Füsse flach auf dem Boden und der Rücken an die Bank gepresst.","Fasse die Langhantel im Obergriff, etwas breiter als schulterbreit.","Hebe die Langhantel aus der Ablage und halte sie mit vollständig gestreckten Armen direkt über deiner Brust.","Senke die Langhantel langsam Richtung Brust ab, die Ellbogen dabei nah am Körper haltend.","Halte kurz inne, sobald die Langhantel deine Brust berührt.","Drücke die Langhantel durch Strecken der Arme zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0025.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0025.gif', 1784612222128, 1784612222128, 0),
  ('9c9c6c71-0714-5141-99e0-e235e9949e2b', NULL, 'Barbell Bench Squat', 'Langhantel-Kniebeuge zur Bank', 'upper legs', 'quads', 'barbell', 'Set up a barbell on a squat rack at chest height. Stand facing away from the rack, with your feet shoulder-width apart. Bend your knees and lower your body down into a squat position, keeping your back straight and chest up. Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart. Lift the barbell off the rack and step back, ensuring your feet are still shoulder-width apart. Lower your body down into a squat, keeping your knees in line with your toes. Pause for a moment at the bottom, then push through your heels to return to the starting position. Repeat for the desired number of repetitions.', NULL, 'glutes', '["glutes","hamstrings","calves"]', '["Set up a barbell on a squat rack at chest height.","Stand facing away from the rack, with your feet shoulder-width apart.","Bend your knees and lower your body down into a squat position, keeping your back straight and chest up.","Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart.","Lift the barbell off the rack and step back, ensuring your feet are still shoulder-width apart.","Lower your body down into a squat, keeping your knees in line with your toes.","Pause for a moment at the bottom, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."]', '["Baue eine Langhantel auf einem Squat-Rack auf Brusthöhe auf.","Stelle dich mit dem Rücken zum Rack, die Füsse schulterbreit auseinander.","Beuge die Knie und senke deinen Körper in die Hocke ab, den Rücken gerade und die Brust aufgerichtet haltend.","Fasse die Langhantel im Obergriff, etwas breiter als schulterbreit.","Hebe die Langhantel aus der Ablage und trete zurück, wobei deine Füsse weiterhin schulterbreit stehen.","Senke deinen Körper in die Hocke ab, die Knie dabei in Linie mit den Zehen haltend.","Halte am unteren Punkt kurz inne und drücke dich dann über die Fersen zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0026.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0026.gif', 1784612222128, 1784612222128, 0);

INSERT OR REPLACE INTO exercises (id, user_id, name, name_de, category, primary_muscle, equipment, instructions_en, instructions_de, muscle_group, secondary_muscles, instruction_steps_en, instruction_steps_de, thumbnail_url, gif_url, created_at, updated_at, deleted) VALUES
  ('e8af057d-8f70-5b59-973b-331e1784d7d8', NULL, 'Barbell Bent Arm Pullover', 'Langhantel-Überzug mit gebeugten Armen', 'back', 'lats', 'barbell', 'Lie flat on a bench with your head at one end and your feet on the floor. Hold a barbell with a shoulder-width grip and extend your arms straight above your chest. Lower the barbell behind your head while keeping your arms slightly bent. Pause for a moment, then raise the barbell back to the starting position. Repeat for the desired number of repetitions.', NULL, 'triceps', '["triceps","chest"]', '["Lie flat on a bench with your head at one end and your feet on the floor.","Hold a barbell with a shoulder-width grip and extend your arms straight above your chest.","Lower the barbell behind your head while keeping your arms slightly bent.","Pause for a moment, then raise the barbell back to the starting position.","Repeat for the desired number of repetitions."]', '["Lege dich flach auf eine Bank, den Kopf an einem Ende und die Füsse auf dem Boden.","Halte eine Langhantel im schulterbreiten Griff und strecke die Arme gerade über deine Brust.","Senke die Langhantel hinter deinen Kopf ab, die Arme dabei leicht gebeugt haltend.","Halte kurz inne und hebe die Langhantel dann zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1316.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1316.gif', 1784612222128, 1784612222128, 0),
  ('834aea33-7376-5eee-b0e7-cbd68e078f46', NULL, 'Barbell Bent Over Row', 'Langhantel-Rudern vorgebeugt', 'back', 'upper back', 'barbell', 'Stand with your feet shoulder-width apart and knees slightly bent. Bend forward at the hips while keeping your back straight and chest up. Grasp the barbell with an overhand grip, hands slightly wider than shoulder-width apart. Pull the barbell towards your lower chest by retracting your shoulder blades and squeezing your back muscles. Pause for a moment at the top, then slowly lower the barbell back to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","forearms"]', '["Stand with your feet shoulder-width apart and knees slightly bent.","Bend forward at the hips while keeping your back straight and chest up.","Grasp the barbell with an overhand grip, hands slightly wider than shoulder-width apart.","Pull the barbell towards your lower chest by retracting your shoulder blades and squeezing your back muscles.","Pause for a moment at the top, then slowly lower the barbell back to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle dich mit schulterbreitem Stand hin, die Knie leicht gebeugt.","Beuge dich in der Hüfte nach vorne, halte dabei den Rücken gerade und die Brust aufgerichtet.","Fasse die Langhantel im Obergriff, die Hände etwas breiter als schulterbreit.","Ziehe die Langhantel zu deinem unteren Brustbereich, indem du die Schulterblätter zurückziehst und die Rückenmuskulatur anspannst.","Halte oben kurz inne und senke die Langhantel dann langsam zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0027.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0027.gif', 1784612222128, 1784612222128, 0),
  ('5bbd9c6d-0b65-52c6-b32b-12cb80134910', NULL, 'Barbell Biceps Curl (with Arm Blaster)', 'Langhantel-Bizepscurl (mit Arm Blaster)', 'upper arms', 'biceps', 'barbell', 'Stand up straight with your feet shoulder-width apart and hold a barbell with an underhand grip, palms facing up. Place your upper arms against the arm blaster, keeping your elbows close to your torso. Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Continue to raise the barbell until your biceps are fully contracted and the bar is at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly begin to lower the barbell back to the starting position. Repeat for the desired number of repetitions.', NULL, 'forearms', '["forearms"]', '["Stand up straight with your feet shoulder-width apart and hold a barbell with an underhand grip, palms facing up.","Place your upper arms against the arm blaster, keeping your elbows close to your torso.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the barbell until your biceps are fully contracted and the bar is at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the barbell back to the starting position.","Repeat for the desired number of repetitions."]', '["Stehe aufrecht mit schulterbreitem Stand und halte eine Langhantel im Untergriff, Handflächen nach oben zeigend.","Lege deine Oberarme an den Arm-Blaster an, die Ellbogen nah am Rumpf haltend.","Halte deine Oberarme ruhig, atme aus und ziehe die Gewichte hoch, während du deinen Bizeps anspannst.","Hebe die Langhantel weiter an, bis dein Bizeps vollständig angespannt ist und sich die Stange auf Schulterhöhe befindet.","Halte die angespannte Position für einen kurzen Moment und spanne dabei deinen Bizeps an.","Atme ein und senke die Langhantel langsam zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/2407.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/2407.gif', 1784612222128, 1784612222128, 0),
  ('91d292f7-a834-505a-9287-3888217fcf5e', NULL, 'Barbell Clean and Press', 'Clean and Press mit der Langhantel', 'upper legs', 'quads', 'barbell', 'Stand with your feet shoulder-width apart and the barbell on the floor in front of you. Bend your knees and hinge at the hips to lower down and grip the barbell with an overhand grip, hands slightly wider than shoulder-width apart. Drive through your heels and extend your hips and knees to lift the barbell off the floor, keeping it close to your body. As the barbell reaches your thighs, explosively extend your hips, shrug your shoulders, and pull the barbell up towards your chest. As the barbell reaches chest height, quickly drop under it and catch it at shoulder level, with your elbows pointing forward and your palms facing up. From the catch position, press the barbell overhead by extending your arms and pushing the barbell straight up. Lower the barbell back down to the starting position and repeat for the desired number of repetitions.', NULL, 'hamstrings', '["hamstrings","glutes","shoulders","triceps"]', '["Stand with your feet shoulder-width apart and the barbell on the floor in front of you.","Bend your knees and hinge at the hips to lower down and grip the barbell with an overhand grip, hands slightly wider than shoulder-width apart.","Drive through your heels and extend your hips and knees to lift the barbell off the floor, keeping it close to your body.","As the barbell reaches your thighs, explosively extend your hips, shrug your shoulders, and pull the barbell up towards your chest.","As the barbell reaches chest height, quickly drop under it and catch it at shoulder level, with your elbows pointing forward and your palms facing up.","From the catch position, press the barbell overhead by extending your arms and pushing the barbell straight up.","Lower the barbell back down to the starting position and repeat for the desired number of repetitions."]', '["Stelle dich mit schulterbreitem Stand hin, die Langhantel liegt vor dir auf dem Boden.","Beuge die Knie und die Hüfte, um dich abzusenken, und fasse die Langhantel im Obergriff, die Hände etwas breiter als schulterbreit.","Drücke dich über die Fersen ab und strecke Hüfte und Knie, um die Langhantel vom Boden zu heben, nah am Körper haltend.","Sobald die Langhantel deine Oberschenkel erreicht, strecke explosiv die Hüfte, ziehe die Schultern hoch und ziehe die Langhantel Richtung Brust.","Sobald die Langhantel Brusthöhe erreicht, tauche schnell darunter und fange sie auf Schulterhöhe auf, die Ellbogen nach vorne gerichtet und die Handflächen nach oben zeigend.","Drücke aus der Fangposition die Langhantel über den Kopf, indem du die Arme streckst und die Langhantel gerade nach oben schiebst.","Senke die Langhantel zurück in die Ausgangsposition und wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0028.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0028.gif', 1784612222128, 1784612222128, 0),
  ('2221401c-4dbc-5f57-8796-c5cb73e1e7e5', NULL, 'Barbell Clean-Grip Front Squat', 'Langhantel-Frontkniebeuge im Umsetzgriff', 'upper legs', 'glutes', 'barbell', 'Start by standing with your feet shoulder-width apart and the barbell resting on your upper chest, with your elbows pointing forward. Lower your body by bending your knees and pushing your hips back, as if you are sitting back into a chair. Keep your chest up and your back straight as you lower down, making sure your knees do not go past your toes. Continue lowering until your thighs are parallel to the ground, or as low as you can comfortably go. Pause for a moment at the bottom, then push through your heels to stand back up, extending your hips and knees. Repeat for the desired number of repetitions.', NULL, 'quadriceps', '["quadriceps","hamstrings","calves","core"]', '["Start by standing with your feet shoulder-width apart and the barbell resting on your upper chest, with your elbows pointing forward.","Lower your body by bending your knees and pushing your hips back, as if you are sitting back into a chair.","Keep your chest up and your back straight as you lower down, making sure your knees do not go past your toes.","Continue lowering until your thighs are parallel to the ground, or as low as you can comfortably go.","Pause for a moment at the bottom, then push through your heels to stand back up, extending your hips and knees.","Repeat for the desired number of repetitions."]', '["Stelle dich mit schulterbreitem Stand hin, die Langhantel liegt auf deiner oberen Brust, die Ellbogen nach vorne gerichtet.","Senke deinen Körper ab, indem du die Knie beugst und die Hüfte nach hinten schiebst, als würdest du dich in einen Stuhl setzen.","Halte die Brust aufgerichtet und den Rücken gerade beim Absenken, achte darauf, dass deine Knie nicht über die Zehen hinausragen.","Senke dich weiter ab, bis deine Oberschenkel parallel zum Boden sind, oder so tief, wie es dir angenehm möglich ist.","Halte am unteren Punkt kurz inne und drücke dich dann über die Fersen nach oben, indem du Hüfte und Knie streckst.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0029.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0029.gif', 1784612222128, 1784612222128, 0),
  ('016392e8-5c7d-5685-bdf2-df4f1c72f389', NULL, 'Barbell Close-Grip Bench Press', 'Langhantel-Bankdrücken eng', 'upper arms', 'triceps', 'barbell', 'Lie flat on a bench with your feet flat on the ground and your back pressed against the bench. Grasp the barbell with a close grip, slightly narrower than shoulder-width apart. Unrack the barbell and lower it slowly towards your chest, keeping your elbows close to your body. Pause for a moment when the barbell touches your chest. Push the barbell back up to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', NULL, 'chest', '["chest","shoulders"]', '["Lie flat on a bench with your feet flat on the ground and your back pressed against the bench.","Grasp the barbell with a close grip, slightly narrower than shoulder-width apart.","Unrack the barbell and lower it slowly towards your chest, keeping your elbows close to your body.","Pause for a moment when the barbell touches your chest.","Push the barbell back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."]', '["Lege dich flach auf eine Bank, die Füsse flach auf dem Boden und der Rücken an die Bank gepresst.","Fasse die Langhantel im engen Griff, etwas schmaler als schulterbreit.","Hebe die Langhantel aus der Ablage und senke sie langsam Richtung Brust ab, die Ellbogen dabei nah am Körper haltend.","Halte kurz inne, sobald die Langhantel deine Brust berührt.","Drücke die Langhantel zurück in die Ausgangsposition, die Arme dabei vollständig streckend.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0030.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0030.gif', 1784612222128, 1784612222128, 0),
  ('71ee078e-c339-53da-9422-cb18875e39fe', NULL, 'Barbell Curl', 'Langhantel-Curl', 'upper arms', 'biceps', 'barbell', 'Stand up straight with your feet shoulder-width apart and hold a barbell with an underhand grip, palms facing forward. Keep your elbows close to your torso and exhale as you curl the weights while contracting your biceps. Continue to raise the bar until your biceps are fully contracted and the bar is at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale as you slowly begin to lower the bar back to the starting position. Repeat for the desired number of repetitions.', NULL, 'forearms', '["forearms"]', '["Stand up straight with your feet shoulder-width apart and hold a barbell with an underhand grip, palms facing forward.","Keep your elbows close to your torso and exhale as you curl the weights while contracting your biceps.","Continue to raise the bar until your biceps are fully contracted and the bar is at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale as you slowly begin to lower the bar back to the starting position.","Repeat for the desired number of repetitions."]', '["Stehe aufrecht mit schulterbreitem Stand und halte eine Langhantel im Untergriff, Handflächen nach vorne zeigend.","Halte die Ellbogen nah am Rumpf und atme aus, während du die Gewichte hochziehst und dabei deinen Bizeps anspannst.","Hebe die Stange weiter an, bis dein Bizeps vollständig angespannt ist und sich die Stange auf Schulterhöhe befindet.","Halte die angespannte Position für einen kurzen Moment und spanne dabei deinen Bizeps an.","Atme ein, während du die Stange langsam zurück in die Ausgangsposition senkst.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0031.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0031.gif', 1784612222128, 1784612222128, 0),
  ('82f0a75a-d8cc-5bd4-adf1-f05964bfcb68', NULL, 'Barbell Deadlift', 'Langhantel-Kreuzheben', 'upper legs', 'glutes', 'barbell', 'Stand with your feet shoulder-width apart and the barbell on the ground in front of you. Bend your knees and hinge at the hips to lower your torso and grip the barbell with an overhand grip, hands slightly wider than shoulder-width apart. Keep your back straight and chest lifted as you drive through your heels to lift the barbell off the ground, extending your hips and knees. As you stand up straight, squeeze your glutes and keep your core engaged. Lower the barbell back down to the ground by bending at the hips and knees, keeping your back straight. Repeat for the desired number of repetitions.', NULL, 'hamstrings', '["hamstrings","lower back"]', '["Stand with your feet shoulder-width apart and the barbell on the ground in front of you.","Bend your knees and hinge at the hips to lower your torso and grip the barbell with an overhand grip, hands slightly wider than shoulder-width apart.","Keep your back straight and chest lifted as you drive through your heels to lift the barbell off the ground, extending your hips and knees.","As you stand up straight, squeeze your glutes and keep your core engaged.","Lower the barbell back down to the ground by bending at the hips and knees, keeping your back straight.","Repeat for the desired number of repetitions."]', '["Stelle dich mit schulterbreitem Stand hin, die Langhantel liegt vor dir auf dem Boden.","Beuge die Knie und die Hüfte, um deinen Oberkörper abzusenken, und fasse die Langhantel im Obergriff, die Hände etwas breiter als schulterbreit.","Halte den Rücken gerade und die Brust aufgerichtet, während du dich über die Fersen abdrückst, um die Langhantel vom Boden zu heben, Hüfte und Knie dabei streckend.","Spanne beim Aufrichten dein Gesäss an und halte deine Körpermitte angespannt.","Senke die Langhantel zurück zum Boden, indem du Hüfte und Knie beugst und den Rücken gerade hältst.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0032.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0032.gif', 1784612222128, 1784612222128, 0),
  ('6a408698-26c4-546f-a5bd-13741a06474a', NULL, 'Barbell Decline Bench Press', 'Langhantel-Negativbankdrücken', 'chest', 'pectorals', 'barbell', 'Lie on a decline bench with your feet secured and your head lower than your hips. Grasp the barbell with an overhand grip slightly wider than shoulder-width apart. Unrack the barbell and lower it slowly towards your chest, keeping your elbows tucked in. Pause for a moment at the bottom, then push the barbell back up to the starting position. Repeat for the desired number of repetitions.', NULL, 'triceps', '["triceps","shoulders"]', '["Lie on a decline bench with your feet secured and your head lower than your hips.","Grasp the barbell with an overhand grip slightly wider than shoulder-width apart.","Unrack the barbell and lower it slowly towards your chest, keeping your elbows tucked in.","Pause for a moment at the bottom, then push the barbell back up to the starting position.","Repeat for the desired number of repetitions."]', '["Lege dich auf eine Negativbank, die Füsse gesichert und der Kopf tiefer als die Hüfte.","Fasse die Langhantel im Obergriff, etwas breiter als schulterbreit.","Hebe die Langhantel aus der Ablage und senke sie langsam Richtung Brust ab, die Ellbogen dabei nah am Körper haltend.","Halte am unteren Punkt kurz inne und drücke die Langhantel dann zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0033.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0033.gif', 1784612222128, 1784612222128, 0),
  ('a0597e60-256b-504f-b150-3d2bfe608e46', NULL, 'Barbell Decline Bent Arm Pullover', 'Langhantel-Überzug mit gebeugten Armen auf der Negativbank', 'back', 'lats', 'barbell', 'Lie down on a decline bench with your head lower than your hips and your feet secured. Hold a barbell with a pronated grip (palms facing away from you) and extend your arms straight above your chest. Lower the barbell behind your head in a controlled manner, keeping your arms slightly bent. Pause for a moment, then raise the barbell back to the starting position by contracting your lats. Repeat for the desired number of repetitions.', NULL, 'triceps', '["triceps","chest"]', '["Lie down on a decline bench with your head lower than your hips and your feet secured.","Hold a barbell with a pronated grip (palms facing away from you) and extend your arms straight above your chest.","Lower the barbell behind your head in a controlled manner, keeping your arms slightly bent.","Pause for a moment, then raise the barbell back to the starting position by contracting your lats.","Repeat for the desired number of repetitions."]', '["Lege dich auf eine Negativbank, der Kopf tiefer als die Hüfte und die Füsse gesichert.","Halte eine Langhantel im Pronationsgriff (Handflächen von dir weg zeigend) und strecke die Arme gerade über deine Brust.","Senke die Langhantel kontrolliert hinter deinen Kopf ab, die Arme dabei leicht gebeugt haltend.","Halte kurz inne und hebe die Langhantel dann durch Anspannen des Latissimus zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0034.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0034.gif', 1784612222128, 1784612222128, 0),
  ('98a0a21b-987f-50ca-b667-eea74fd5157e', NULL, 'Barbell Decline Close Grip to Skull Press', 'Langhantel-Skullcrusher eng auf der Negativbank', 'upper arms', 'triceps', 'barbell', 'Lie on a decline bench with your head lower than your feet and hold a barbell with a close grip. Lower the barbell towards your forehead by bending your elbows, keeping your upper arms stationary. Pause for a moment, then extend your arms to press the barbell back up to the starting position. Repeat for the desired number of repetitions.', NULL, 'chest', '["chest","shoulders"]', '["Lie on a decline bench with your head lower than your feet and hold a barbell with a close grip.","Lower the barbell towards your forehead by bending your elbows, keeping your upper arms stationary.","Pause for a moment, then extend your arms to press the barbell back up to the starting position.","Repeat for the desired number of repetitions."]', '["Lege dich auf eine Negativbank, der Kopf tiefer als die Füsse, und halte eine Langhantel im engen Griff.","Senke die Langhantel Richtung Stirn ab, indem du die Ellbogen beugst und die Oberarme ruhig hältst.","Halte kurz inne und strecke die Arme dann, um die Langhantel zurück in die Ausgangsposition zu drücken.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0035.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0035.gif', 1784612222128, 1784612222128, 0),
  ('8109e257-34ef-57a1-ba44-3392907582be', NULL, 'Barbell Decline Pullover', 'Langhantel-Überzug auf der Negativbank', 'chest', 'pectorals', 'barbell', 'Lie down on a decline bench with your head lower than your hips and your feet secured. Hold the barbell with a pronated grip (palms facing away from you) and your hands slightly wider than shoulder-width apart. Extend your arms above your chest, keeping a slight bend in your elbows. Lower the barbell in an arc motion behind your head, feeling a stretch in your chest and shoulders. Pause for a moment, then return the barbell to the starting position by reversing the motion. Repeat for the desired number of repetitions.', NULL, 'triceps', '["triceps","shoulders"]', '["Lie down on a decline bench with your head lower than your hips and your feet secured.","Hold the barbell with a pronated grip (palms facing away from you) and your hands slightly wider than shoulder-width apart.","Extend your arms above your chest, keeping a slight bend in your elbows.","Lower the barbell in an arc motion behind your head, feeling a stretch in your chest and shoulders.","Pause for a moment, then return the barbell to the starting position by reversing the motion.","Repeat for the desired number of repetitions."]', '["Lege dich auf eine Negativbank, der Kopf tiefer als die Hüfte und die Füsse gesichert.","Halte die Langhantel im Pronationsgriff (Handflächen von dir weg zeigend), die Hände etwas breiter als schulterbreit.","Strecke die Arme über deine Brust, die Ellbogen dabei leicht gebeugt haltend.","Senke die Langhantel in einer Bogenbewegung hinter deinen Kopf ab, du spürst eine Dehnung in Brust und Schultern.","Halte kurz inne und führe die Langhantel dann durch die umgekehrte Bewegung zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1255.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1255.gif', 1784612222128, 1784612222128, 0),
  ('d19e833c-ac63-58e5-bbdf-fd0eef5ff8b7', NULL, 'Barbell Decline Wide-Grip Press', 'Langhantel-Negativbankdrücken weit', 'chest', 'pectorals', 'barbell', 'Lie on a decline bench with your feet secured and your head lower than your hips. Grasp the barbell with a wide grip, slightly wider than shoulder-width apart. Lower the barbell to your chest, keeping your elbows out to the sides. Push the barbell back up to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', NULL, 'triceps', '["triceps","shoulders"]', '["Lie on a decline bench with your feet secured and your head lower than your hips.","Grasp the barbell with a wide grip, slightly wider than shoulder-width apart.","Lower the barbell to your chest, keeping your elbows out to the sides.","Push the barbell back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."]', '["Lege dich auf eine Negativbank, die Füsse gesichert und der Kopf tiefer als die Hüfte.","Fasse die Langhantel im breiten Griff, etwas breiter als schulterbreit.","Senke die Langhantel Richtung Brust ab, die Ellbogen dabei seitlich auswärts haltend.","Drücke die Langhantel zurück in die Ausgangsposition, die Arme dabei vollständig streckend.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0036.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0036.gif', 1784612222128, 1784612222128, 0),
  ('e57c1f8f-178c-50fb-95b4-f17889006937', NULL, 'Barbell Decline Wide-Grip Pullover', 'Langhantel-Überzug weit auf der Negativbank', 'back', 'lats', 'barbell', 'Lie on a decline bench with your head lower than your hips and your feet secured. Hold a barbell with a wide grip and extend your arms straight above your chest. Lower the barbell behind your head in a controlled manner, keeping your arms straight. Pause for a moment, then raise the barbell back to the starting position. Repeat for the desired number of repetitions.', NULL, 'triceps', '["triceps","chest"]', '["Lie on a decline bench with your head lower than your hips and your feet secured.","Hold a barbell with a wide grip and extend your arms straight above your chest.","Lower the barbell behind your head in a controlled manner, keeping your arms straight.","Pause for a moment, then raise the barbell back to the starting position.","Repeat for the desired number of repetitions."]', '["Lege dich auf eine Negativbank, der Kopf tiefer als die Hüfte und die Füsse gesichert.","Halte eine Langhantel im breiten Griff und strecke die Arme gerade über deine Brust.","Senke die Langhantel kontrolliert hinter deinen Kopf ab, die Arme dabei gestreckt haltend.","Halte kurz inne und hebe die Langhantel dann zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0037.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0037.gif', 1784612222128, 1784612222128, 0),
  ('abd3a25a-283d-5404-8cc2-a8ef6e456d3d', NULL, 'Barbell Drag Curl', 'Langhantel-Drag-Curl', 'upper arms', 'biceps', 'barbell', 'Stand with your feet shoulder-width apart and hold a barbell with an underhand grip, palms facing up. Let the barbell hang at arm''s length in front of your thighs. Keeping your upper arms stationary, curl the barbell up towards your chest by contracting your biceps. Pause for a moment at the top, then slowly lower the barbell back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'forearms', '["forearms"]', '["Stand with your feet shoulder-width apart and hold a barbell with an underhand grip, palms facing up.","Let the barbell hang at arm''s length in front of your thighs.","Keeping your upper arms stationary, curl the barbell up towards your chest by contracting your biceps.","Pause for a moment at the top, then slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle dich mit schulterbreitem Stand hin und halte eine Langhantel im Untergriff, Handflächen nach oben zeigend.","Lasse die Langhantel mit gestreckten Armen vor deinen Oberschenkeln hängen.","Halte die Oberarme ruhig und ziehe die Langhantel durch Anspannen des Bizeps Richtung Brust hoch.","Halte oben kurz inne und senke die Langhantel dann langsam zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0038.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0038.gif', 1784612222128, 1784612222128, 0),
  ('f310d5b0-6f2d-5a45-84a8-118d616a9c61', NULL, 'Barbell Floor Calf Raise', 'Langhantel-Wadenheben am Boden', 'lower legs', 'calves', 'barbell', 'Place a barbell on the floor in front of you. Stand with the balls of your feet on the edge of the barbell, with your heels hanging off. Hold onto a stable object for balance if needed. Raise your heels as high as possible, using your calves to lift your body. Pause for a moment at the top, then slowly lower your heels back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'hamstrings', '["hamstrings"]', '["Place a barbell on the floor in front of you.","Stand with the balls of your feet on the edge of the barbell, with your heels hanging off.","Hold onto a stable object for balance if needed.","Raise your heels as high as possible, using your calves to lift your body.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."]', '["Lege eine Langhantel vor dir auf den Boden.","Stelle dich mit den Fussballen auf den Rand der Langhantel, die Fersen dabei in der Luft.","Halte dich bei Bedarf an einem stabilen Objekt fest, um das Gleichgewicht zu halten.","Hebe deine Fersen so weit wie möglich an, angetrieben durch deine Waden, um deinen Körper zu heben.","Halte oben kurz inne und senke deine Fersen dann langsam zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1370.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1370.gif', 1784612222128, 1784612222128, 0),
  ('5d4db464-b51e-5e75-bc88-40704c344ed6', NULL, 'Barbell Front Chest Squat', 'Langhantel-Frontkniebeuge an der Brust', 'upper legs', 'glutes', 'barbell', 'Start by standing with your feet shoulder-width apart, toes slightly turned out. Hold the barbell in front of your chest with your hands shoulder-width apart, elbows pointing forward. Engage your core and keep your chest up as you lower your body down into a squat position, pushing your hips back and bending your knees. Lower until your thighs are parallel to the ground, or as low as you can comfortably go. Pause for a moment at the bottom, then push through your heels to return to the starting position. Repeat for the desired number of repetitions.', NULL, 'quadriceps', '["quadriceps","hamstrings","calves","core"]', '["Start by standing with your feet shoulder-width apart, toes slightly turned out.","Hold the barbell in front of your chest with your hands shoulder-width apart, elbows pointing forward.","Engage your core and keep your chest up as you lower your body down into a squat position, pushing your hips back and bending your knees.","Lower until your thighs are parallel to the ground, or as low as you can comfortably go.","Pause for a moment at the bottom, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle dich mit schulterbreitem Stand hin, die Zehen leicht nach aussen gedreht.","Halte die Langhantel vor deiner Brust, die Hände schulterbreit auseinander und die Ellbogen nach vorne gerichtet.","Spanne deine Körpermitte an und halte die Brust aufgerichtet, während du deinen Körper in die Hocke absenkst, die Hüfte nach hinten schiebend und die Knie beugend.","Senke dich ab, bis deine Oberschenkel parallel zum Boden sind, oder so tief, wie es dir angenehm möglich ist.","Halte am unteren Punkt kurz inne und drücke dich dann über die Fersen zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0039.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0039.gif', 1784612222128, 1784612222128, 0),
  ('be0b152f-32fb-5e6e-925a-9b1d76924cd2', NULL, 'Barbell Front Raise', 'Langhantel-Frontheben', 'shoulders', 'delts', 'barbell', 'Stand with your feet shoulder-width apart and hold a barbell in front of your thighs with an overhand grip. Keep your arms straight and lift the barbell forward and upward until it reaches shoulder level. Pause for a moment at the top, then slowly lower the barbell back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","triceps"]', '["Stand with your feet shoulder-width apart and hold a barbell in front of your thighs with an overhand grip.","Keep your arms straight and lift the barbell forward and upward until it reaches shoulder level.","Pause for a moment at the top, then slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle dich mit schulterbreitem Stand hin und halte eine Langhantel im Obergriff vor deinen Oberschenkeln.","Halte die Arme gestreckt und hebe die Langhantel nach vorne oben an, bis sie Schulterhöhe erreicht.","Halte oben kurz inne und senke die Langhantel dann langsam zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0041.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0041.gif', 1784612222128, 1784612222128, 0),
  ('00a7e537-01a5-5751-9db4-ba6dd208ad96', NULL, 'Barbell Front Raise and Pullover', 'Langhantel-Frontheben und Überzug', 'chest', 'pectorals', 'barbell', 'Stand with your feet shoulder-width apart and hold a barbell with an overhand grip, palms facing down. Keep your arms straight and raise the barbell in front of you until it reaches shoulder height. Pause for a moment at the top, then slowly lower the barbell back down to the starting position. Next, lower the barbell behind your head, keeping your arms straight. Pause for a moment at the bottom, then raise the barbell back up to the starting position. Repeat for the desired number of repetitions.', NULL, 'deltoids', '["deltoids","triceps"]', '["Stand with your feet shoulder-width apart and hold a barbell with an overhand grip, palms facing down.","Keep your arms straight and raise the barbell in front of you until it reaches shoulder height.","Pause for a moment at the top, then slowly lower the barbell back down to the starting position.","Next, lower the barbell behind your head, keeping your arms straight.","Pause for a moment at the bottom, then raise the barbell back up to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle dich mit schulterbreitem Stand hin und halte eine Langhantel im Obergriff, Handflächen nach unten zeigend.","Halte die Arme gestreckt und hebe die Langhantel vor dir an, bis sie Schulterhöhe erreicht.","Halte oben kurz inne und senke die Langhantel dann langsam zurück in die Ausgangsposition.","Senke die Langhantel als Nächstes hinter deinen Kopf ab, die Arme dabei gestreckt haltend.","Halte unten kurz inne und hebe die Langhantel dann zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0040.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0040.gif', 1784612222128, 1784612222128, 0),
  ('b8f0b81a-1412-5005-9cb9-5efb50ad9834', NULL, 'Barbell Front Squat', 'Langhantel-Frontkniebeuge', 'upper legs', 'glutes', 'barbell', 'Start by standing with your feet shoulder-width apart, toes slightly turned out. Hold the barbell in front of your shoulders, resting it on your collarbone and shoulders. Engage your core and keep your chest up as you lower your body down into a squat position, pushing your hips back and bending your knees. Lower until your thighs are parallel to the ground, or as low as you can comfortably go. Pause for a moment at the bottom, then push through your heels to return to the starting position. Repeat for the desired number of repetitions.', NULL, 'quadriceps', '["quadriceps","hamstrings","calves","core"]', '["Start by standing with your feet shoulder-width apart, toes slightly turned out.","Hold the barbell in front of your shoulders, resting it on your collarbone and shoulders.","Engage your core and keep your chest up as you lower your body down into a squat position, pushing your hips back and bending your knees.","Lower until your thighs are parallel to the ground, or as low as you can comfortably go.","Pause for a moment at the bottom, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle dich mit schulterbreitem Stand hin, die Zehen leicht nach aussen gedreht.","Halte die Langhantel vor deinen Schultern, auf Schlüsselbein und Schultern aufliegend.","Spanne deine Körpermitte an und halte die Brust aufgerichtet, während du deinen Körper in die Hocke absenkst, die Hüfte nach hinten schiebend und die Knie beugend.","Senke dich ab, bis deine Oberschenkel parallel zum Boden sind, oder so tief, wie es dir angenehm möglich ist.","Halte am unteren Punkt kurz inne und drücke dich dann über die Fersen zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0042.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0042.gif', 1784612222128, 1784612222128, 0),
  ('37609db7-83e0-54f4-b006-eae02dcbb958', NULL, 'Barbell Full Squat', 'Langhantel-Tiefkniebeuge', 'upper legs', 'glutes', 'barbell', 'Stand with your feet shoulder-width apart, toes slightly turned out. Hold the barbell across your upper back, resting it on your traps or rear delts. Engage your core and keep your chest up as you begin to lower your body down. Bend at the knees and hips, pushing your hips back and down as if sitting into a chair. Lower yourself until your thighs are parallel to the ground or slightly below. Keep your knees in line with your toes and your weight in your heels. Drive through your heels to stand back up, extending your hips and knees. Repeat for the desired number of repetitions.', NULL, 'quadriceps', '["quadriceps","hamstrings","calves","core"]', '["Stand with your feet shoulder-width apart, toes slightly turned out.","Hold the barbell across your upper back, resting it on your traps or rear delts.","Engage your core and keep your chest up as you begin to lower your body down.","Bend at the knees and hips, pushing your hips back and down as if sitting into a chair.","Lower yourself until your thighs are parallel to the ground or slightly below.","Keep your knees in line with your toes and your weight in your heels.","Drive through your heels to stand back up, extending your hips and knees.","Repeat for the desired number of repetitions."]', '["Stelle dich mit schulterbreitem Stand hin, die Zehen leicht nach aussen gedreht.","Halte die Langhantel auf deinem oberen Rücken, auf Trapez oder hinterer Schulter aufliegend.","Spanne deine Körpermitte an und halte die Brust aufgerichtet, während du beginnst, deinen Körper abzusenken.","Beuge Knie und Hüfte und schiebe die Hüfte nach hinten unten, als würdest du dich in einen Stuhl setzen.","Senke dich ab, bis deine Oberschenkel parallel zum Boden sind oder leicht darunter.","Halte die Knie in Linie mit den Zehen und dein Gewicht auf den Fersen.","Drücke dich über die Fersen nach oben, indem du Hüfte und Knie streckst.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0043.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0043.gif', 1784612222128, 1784612222128, 0),
  ('d680242b-1c71-5314-85f1-555477651ca1', NULL, 'Barbell Full Squat (Back POV)', 'Langhantel-Tiefkniebeuge (Rückenansicht)', 'upper legs', 'glutes', 'barbell', 'Stand with your feet shoulder-width apart, toes slightly turned out. Hold the barbell across your upper back, resting it on your traps or rear delts. Engage your core and keep your chest up as you begin to lower your body down. Bend at the knees and hips, pushing your hips back and down as if sitting into a chair. Lower your body until your thighs are parallel to the ground or slightly below. Keep your knees in line with your toes and your weight in your heels. Drive through your heels to stand back up, extending your hips and knees. Repeat for the desired number of repetitions.', NULL, 'quadriceps', '["quadriceps","hamstrings","calves","core"]', '["Stand with your feet shoulder-width apart, toes slightly turned out.","Hold the barbell across your upper back, resting it on your traps or rear delts.","Engage your core and keep your chest up as you begin to lower your body down.","Bend at the knees and hips, pushing your hips back and down as if sitting into a chair.","Lower your body until your thighs are parallel to the ground or slightly below.","Keep your knees in line with your toes and your weight in your heels.","Drive through your heels to stand back up, extending your hips and knees.","Repeat for the desired number of repetitions."]', '["Stelle dich mit schulterbreitem Stand hin, die Zehen leicht nach aussen gedreht.","Halte die Langhantel auf deinem oberen Rücken, auf Trapez oder hinterer Schulter aufliegend.","Spanne deine Körpermitte an und halte die Brust aufgerichtet, während du beginnst, deinen Körper abzusenken.","Beuge Knie und Hüfte und schiebe die Hüfte nach hinten unten, als würdest du dich in einen Stuhl setzen.","Senke deinen Körper ab, bis deine Oberschenkel parallel zum Boden sind oder leicht darunter.","Halte die Knie in Linie mit den Zehen und dein Gewicht auf den Fersen.","Drücke dich über die Fersen nach oben, indem du Hüfte und Knie streckst.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1461.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1461.gif', 1784612222128, 1784612222128, 0),
  ('2096f749-38f8-5f1c-8ebb-43ac19cabe0c', NULL, 'Barbell Full Squat (Side POV)', 'Langhantel-Tiefkniebeuge (Seitenansicht)', 'upper legs', 'glutes', 'barbell', 'Stand with your feet shoulder-width apart, toes slightly turned out. Hold the barbell across your upper back, resting it on your traps or rear delts. Engage your core and keep your chest up as you begin to lower your body down. Bend at the knees and hips, pushing your hips back and down as if sitting into a chair. Lower your body until your thighs are parallel to the ground or slightly below. Keep your knees in line with your toes and your weight in your heels. Drive through your heels to stand back up, extending your hips and knees. Repeat for the desired number of repetitions.', NULL, 'quadriceps', '["quadriceps","hamstrings","calves","core"]', '["Stand with your feet shoulder-width apart, toes slightly turned out.","Hold the barbell across your upper back, resting it on your traps or rear delts.","Engage your core and keep your chest up as you begin to lower your body down.","Bend at the knees and hips, pushing your hips back and down as if sitting into a chair.","Lower your body until your thighs are parallel to the ground or slightly below.","Keep your knees in line with your toes and your weight in your heels.","Drive through your heels to stand back up, extending your hips and knees.","Repeat for the desired number of repetitions."]', '["Stelle dich mit schulterbreitem Stand hin, die Zehen leicht nach aussen gedreht.","Halte die Langhantel auf deinem oberen Rücken, auf Trapez oder hinterer Schulter aufliegend.","Spanne deine Körpermitte an und halte die Brust aufgerichtet, während du beginnst, deinen Körper abzusenken.","Beuge Knie und Hüfte und schiebe die Hüfte nach hinten unten, als würdest du dich in einen Stuhl setzen.","Senke deinen Körper ab, bis deine Oberschenkel parallel zum Boden sind oder leicht darunter.","Halte die Knie in Linie mit den Zehen und dein Gewicht auf den Fersen.","Drücke dich über die Fersen nach oben, indem du Hüfte und Knie streckst.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1462.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1462.gif', 1784612222128, 1784612222128, 0),
  ('0d64241d-4c33-5f35-8e55-7499b57ac5d1', NULL, 'Barbell Full Zercher Squat', 'Langhantel-Zercher-Tiefkniebeuge', 'upper legs', 'glutes', 'barbell', 'Stand with your feet shoulder-width apart and toes slightly turned out. Hold the barbell in the crooks of your elbows, with your hands gripping the barbell for stability. Engage your core and keep your chest lifted as you lower your hips back and down into a squat position. Keep your knees in line with your toes and your weight in your heels. Lower until your thighs are parallel to the ground, or as low as you can comfortably go. Drive through your heels to stand back up, squeezing your glutes at the top of the movement. Repeat for the desired number of repetitions.', NULL, 'quadriceps', '["quadriceps","hamstrings","calves","core"]', '["Stand with your feet shoulder-width apart and toes slightly turned out.","Hold the barbell in the crooks of your elbows, with your hands gripping the barbell for stability.","Engage your core and keep your chest lifted as you lower your hips back and down into a squat position.","Keep your knees in line with your toes and your weight in your heels.","Lower until your thighs are parallel to the ground, or as low as you can comfortably go.","Drive through your heels to stand back up, squeezing your glutes at the top of the movement.","Repeat for the desired number of repetitions."]', '["Stelle dich mit schulterbreitem Stand hin, die Zehen leicht nach aussen gedreht.","Halte die Langhantel in den Ellbogenbeugen, die Hände greifen die Stange zur Stabilisierung.","Spanne deine Körpermitte an und halte die Brust aufgerichtet, während du deine Hüfte nach hinten unten in die Hocke absenkst.","Halte die Knie in Linie mit den Zehen und dein Gewicht auf den Fersen.","Senke dich ab, bis deine Oberschenkel parallel zum Boden sind, oder so tief, wie es dir angenehm möglich ist.","Drücke dich über die Fersen nach oben und spanne am oberen Punkt der Bewegung dein Gesäss an.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1545.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1545.gif', 1784612222128, 1784612222128, 0),
  ('dad2d7e4-dafb-5c6c-b721-d878aaeadc2c', NULL, 'Barbell Glute Bridge', 'Langhantel-Gesässbrücke', 'upper legs', 'glutes', 'barbell', 'Start by lying flat on your back on the ground with your knees bent and feet flat on the floor. Place a barbell across your hips, holding it securely with both hands. Engage your glutes and core muscles, then lift your hips off the ground until your body forms a straight line from your knees to your shoulders. Pause for a moment at the top, squeezing your glutes. Slowly lower your hips back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'hamstrings', '["hamstrings","lower back"]', '["Start by lying flat on your back on the ground with your knees bent and feet flat on the floor.","Place a barbell across your hips, holding it securely with both hands.","Engage your glutes and core muscles, then lift your hips off the ground until your body forms a straight line from your knees to your shoulders.","Pause for a moment at the top, squeezing your glutes.","Slowly lower your hips back down to the starting position.","Repeat for the desired number of repetitions."]', '["Lege dich flach auf den Rücken auf den Boden, die Knie gebeugt und die Füsse flach aufgestellt.","Lege eine Langhantel über deine Hüfte und halte sie mit beiden Händen sicher fest.","Spanne Gesäss und Körpermitte an und hebe dann deine Hüfte vom Boden ab, bis dein Körper eine gerade Linie von den Knien zu den Schultern bildet.","Halte oben kurz inne und spanne dabei dein Gesäss an.","Senke deine Hüfte langsam zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1409.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1409.gif', 1784612222128, 1784612222128, 0),
  ('b505d6ca-d708-5886-8e77-33fdf0058234', NULL, 'Barbell Glute Bridge Two Legs on Bench (Male)', 'Langhantel-Gesässbrücke mit beiden Beinen auf der Bank (männlich)', 'upper legs', 'glutes', 'barbell', 'Start by sitting on the edge of a bench with your upper back resting against it and your feet flat on the ground, hip-width apart. Place a barbell across your hips, holding it securely with both hands. Engage your glutes and core muscles, then press through your heels to lift your hips off the bench, creating a straight line from your knees to your shoulders. Pause for a moment at the top, squeezing your glutes. Slowly lower your hips back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'hamstrings', '["hamstrings","core"]', '["Start by sitting on the edge of a bench with your upper back resting against it and your feet flat on the ground, hip-width apart.","Place a barbell across your hips, holding it securely with both hands.","Engage your glutes and core muscles, then press through your heels to lift your hips off the bench, creating a straight line from your knees to your shoulders.","Pause for a moment at the top, squeezing your glutes.","Slowly lower your hips back down to the starting position.","Repeat for the desired number of repetitions."]', '["Setze dich an den Rand einer Bank, den oberen Rücken daran angelehnt und die Füsse hüftbreit flach auf dem Boden.","Lege eine Langhantel über deine Hüfte und halte sie mit beiden Händen sicher fest.","Spanne Gesäss und Körpermitte an und drücke dich dann über die Fersen ab, um deine Hüfte von der Bank abzuheben, sodass eine gerade Linie von den Knien zu den Schultern entsteht.","Halte oben kurz inne und spanne dabei dein Gesäss an.","Senke deine Hüfte langsam zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/3562.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/3562.gif', 1784612222128, 1784612222128, 0),
  ('36f95420-c6df-5be3-beda-2899ca282d8f', NULL, 'Barbell Good Morning', 'Good Morning mit der Langhantel', 'upper legs', 'hamstrings', 'barbell', 'Start by standing with your feet shoulder-width apart and the barbell resting on your upper back. Keeping your back straight and your core engaged, hinge forward at the hips, pushing your buttocks back as if you were trying to touch the wall behind you with your glutes. Lower your torso until it is parallel to the ground, feeling a stretch in your hamstrings. Pause for a moment, then return to the starting position by squeezing your glutes and pushing your hips forward. Repeat for the desired number of repetitions.', NULL, 'lower back', '["lower back"]', '["Start by standing with your feet shoulder-width apart and the barbell resting on your upper back.","Keeping your back straight and your core engaged, hinge forward at the hips, pushing your buttocks back as if you were trying to touch the wall behind you with your glutes.","Lower your torso until it is parallel to the ground, feeling a stretch in your hamstrings.","Pause for a moment, then return to the starting position by squeezing your glutes and pushing your hips forward.","Repeat for the desired number of repetitions."]', '["Stell dich mit schulterbreiten Füssen hin und lege die Langhantel auf deinen oberen Rücken.","Halte den Rücken gerade und spanne deine Körpermitte an, beuge dich in der Hüfte nach vorne und schiebe dein Gesäss nach hinten, als würdest du versuchen, mit dem Po eine Wand hinter dir zu berühren.","Senke deinen Oberkörper ab, bis er parallel zum Boden ist, und spüre die Dehnung in den Beinbeugern.","Halte kurz inne, kehre dann in die Ausgangsposition zurück, indem du dein Gesäss anspannst und die Hüfte nach vorne schiebst.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0044.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0044.gif', 1784612222128, 1784612222128, 0),
  ('46671020-465d-56d0-a737-9fe575adf4fd', NULL, 'Barbell Guillotine Bench Press', 'Langhantel-Guillotine-Bankdrücken', 'chest', 'pectorals', 'barbell', 'Lie flat on a bench with your feet flat on the ground and your back pressed against the bench. Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart. Lower the barbell slowly towards your neck, keeping your elbows pointed outwards. Pause for a moment when the barbell is just above your neck. Push the barbell back up to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', NULL, 'shoulders', '["shoulders","triceps"]', '["Lie flat on a bench with your feet flat on the ground and your back pressed against the bench.","Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart.","Lower the barbell slowly towards your neck, keeping your elbows pointed outwards.","Pause for a moment when the barbell is just above your neck.","Push the barbell back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."]', '["Lege dich flach auf eine Bank, die Füsse fest auf dem Boden und den Rücken gegen die Bank gedrückt.","Greife die Langhantel im Obergriff, etwas breiter als schulterbreit.","Senke die Langhantel langsam in Richtung deines Halses ab und halte die Ellbogen dabei nach aussen zeigend.","Halte kurz inne, wenn die Langhantel knapp über deinem Hals ist.","Drücke die Langhantel zurück in die Ausgangsposition, indem du die Arme vollständig streckst.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0045.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0045.gif', 1784612222128, 1784612222128, 0),
  ('f9cf4877-bceb-5a4c-ba77-bffed0e9fc35', NULL, 'Barbell Hack Squat', 'Langhantel-Hack-Squat', 'upper legs', 'glutes', 'barbell', 'Start by standing with your feet shoulder-width apart and your toes slightly turned out. Hold the barbell behind your legs, resting it on your upper thighs. Lower your body by bending at the knees and hips, keeping your back straight and your chest up. Continue lowering until your thighs are parallel to the ground, or as low as you can comfortably go. Pause for a moment, then push through your heels to return to the starting position. Repeat for the desired number of repetitions.', NULL, 'quadriceps', '["quadriceps","hamstrings","calves"]', '["Start by standing with your feet shoulder-width apart and your toes slightly turned out.","Hold the barbell behind your legs, resting it on your upper thighs.","Lower your body by bending at the knees and hips, keeping your back straight and your chest up.","Continue lowering until your thighs are parallel to the ground, or as low as you can comfortably go.","Pause for a moment, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."]', '["Stell dich mit schulterbreiten Füssen hin, die Zehen leicht nach aussen gedreht.","Halte die Langhantel hinter deinen Beinen und lasse sie auf deinen Oberschenkeln aufliegen.","Senke deinen Körper ab, indem du Knie und Hüfte beugst, dabei bleibt der Rücken gerade und die Brust aufgerichtet.","Senke dich weiter ab, bis deine Oberschenkel parallel zum Boden sind, oder so tief, wie es dir bequem möglich ist.","Halte kurz inne und drücke dich dann über die Fersen zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0046.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0046.gif', 1784612222128, 1784612222128, 0),
  ('a6ddcbfe-0ecb-5f3e-a64e-7dc5849053b3', NULL, 'Barbell High Bar Squat', 'Langhantel-High-Bar-Kniebeuge', 'upper legs', 'glutes', 'barbell', 'Stand with your feet shoulder-width apart, toes slightly turned out. Place the barbell on your upper back, resting it on your traps. Engage your core and keep your chest up as you begin to squat down, pushing your hips back and bending your knees. Lower yourself until your thighs are parallel to the ground, or as low as you can comfortably go. Drive through your heels to stand back up, extending your hips and knees. Repeat for the desired number of repetitions.', NULL, 'quadriceps', '["quadriceps","hamstrings","calves","core"]', '["Stand with your feet shoulder-width apart, toes slightly turned out.","Place the barbell on your upper back, resting it on your traps.","Engage your core and keep your chest up as you begin to squat down, pushing your hips back and bending your knees.","Lower yourself until your thighs are parallel to the ground, or as low as you can comfortably go.","Drive through your heels to stand back up, extending your hips and knees.","Repeat for the desired number of repetitions."]', '["Stell dich mit schulterbreiten Füssen hin, die Zehen leicht nach aussen gedreht.","Lege die Langhantel auf deinen oberen Rücken, sodass sie auf dem Trapezmuskel aufliegt.","Spanne deine Körpermitte an und halte die Brust aufgerichtet, während du dich in die Hocke begibst, die Hüfte nach hinten schiebst und die Knie beugst.","Senke dich ab, bis deine Oberschenkel parallel zum Boden sind, oder so tief, wie es dir bequem möglich ist.","Drücke dich über die Fersen nach oben, indem du Hüfte und Knie streckst.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1436.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1436.gif', 1784612222128, 1784612222128, 0),
  ('52e90514-ef77-51bc-9132-9fe76d719292', NULL, 'Barbell Incline Bench Press', 'Langhantel-Schrägbankdrücken', 'chest', 'pectorals', 'barbell', 'Set up an incline bench at a 45-degree angle. Lie down on the bench with your feet flat on the ground. Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart. Unrack the barbell and lower it slowly towards your chest, keeping your elbows at a 45-degree angle. Pause for a moment at the bottom, then push the barbell back up to the starting position. Repeat for the desired number of repetitions.', NULL, 'shoulders', '["shoulders","triceps"]', '["Set up an incline bench at a 45-degree angle.","Lie down on the bench with your feet flat on the ground.","Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart.","Unrack the barbell and lower it slowly towards your chest, keeping your elbows at a 45-degree angle.","Pause for a moment at the bottom, then push the barbell back up to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle eine Schrägbank auf einen 45-Grad-Winkel ein.","Lege dich auf die Bank, die Füsse fest auf dem Boden.","Greife die Langhantel im Obergriff, etwas breiter als schulterbreit.","Hebe die Langhantel aus der Ablage und senke sie langsam in Richtung deiner Brust ab, die Ellbogen dabei im 45-Grad-Winkel haltend.","Halte kurz unten inne und drücke die Langhantel dann zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0047.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0047.gif', 1784612222128, 1784612222128, 0),
  ('9968565a-2778-535e-a32c-ae3c8cbaa4a0', NULL, 'Barbell Incline Close Grip Bench Press', 'Langhantel-Schrägbankdrücken eng', 'upper arms', 'triceps', 'barbell', 'Set up an incline bench at a 45-degree angle. Lie down on the bench with your feet flat on the ground. Grasp the barbell with a close grip, slightly narrower than shoulder-width apart. Unrack the barbell and lower it slowly towards your chest, keeping your elbows close to your body. Pause for a moment when the barbell touches your chest. Push the barbell back up to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', NULL, 'chest', '["chest","shoulders"]', '["Set up an incline bench at a 45-degree angle.","Lie down on the bench with your feet flat on the ground.","Grasp the barbell with a close grip, slightly narrower than shoulder-width apart.","Unrack the barbell and lower it slowly towards your chest, keeping your elbows close to your body.","Pause for a moment when the barbell touches your chest.","Push the barbell back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."]', '["Stelle eine Schrägbank auf einen 45-Grad-Winkel ein.","Lege dich auf die Bank, die Füsse fest auf dem Boden.","Greife die Langhantel im engen Griff, etwas schmaler als schulterbreit.","Hebe die Langhantel aus der Ablage und senke sie langsam in Richtung deiner Brust ab, die Ellbogen dabei nah am Körper haltend.","Halte kurz inne, wenn die Langhantel deine Brust berührt.","Drücke die Langhantel zurück in die Ausgangsposition, indem du die Arme vollständig streckst.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1719.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1719.gif', 1784612222128, 1784612222128, 0),
  ('e006b94e-eb1f-573d-b8f2-ab5a7c9af32d', NULL, 'Barbell Incline Reverse-Grip Press', 'Langhantel-Schrägbankdrücken im Untergriff', 'upper arms', 'triceps', 'barbell', 'Set up an incline bench at a 45-degree angle. Lie back on the bench and grasp the barbell with a reverse grip, hands slightly wider than shoulder-width apart. Unrack the barbell and lower it towards your upper chest, keeping your elbows tucked in. Pause for a moment at the bottom, then push the barbell back up to the starting position. Repeat for the desired number of repetitions.', NULL, 'chest', '["chest","shoulders"]', '["Set up an incline bench at a 45-degree angle.","Lie back on the bench and grasp the barbell with a reverse grip, hands slightly wider than shoulder-width apart.","Unrack the barbell and lower it towards your upper chest, keeping your elbows tucked in.","Pause for a moment at the bottom, then push the barbell back up to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle eine Schrägbank auf einen 45-Grad-Winkel ein.","Lege dich auf die Bank und greife die Langhantel im umgekehrten Griff, die Hände etwas breiter als schulterbreit.","Hebe die Langhantel aus der Ablage und senke sie in Richtung deiner oberen Brust ab, die Ellbogen dabei nah am Körper haltend.","Halte kurz unten inne und drücke die Langhantel dann zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0048.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0048.gif', 1784612222128, 1784612222128, 0),
  ('6f2e602f-1b04-56ef-8520-22ed50f1f005', NULL, 'Barbell Incline Row', 'Langhantel-Rudern auf der Schrägbank', 'back', 'upper back', 'barbell', 'Set up an incline bench at a 45-degree angle. Lie face down on the bench with your chest against the pad and your feet flat on the ground. Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart. Keep your back straight and your core engaged. Pull the barbell towards your chest, squeezing your shoulder blades together. Pause for a moment at the top, then slowly lower the barbell back to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","forearms"]', '["Set up an incline bench at a 45-degree angle.","Lie face down on the bench with your chest against the pad and your feet flat on the ground.","Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart.","Keep your back straight and your core engaged.","Pull the barbell towards your chest, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower the barbell back to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle eine Schrägbank auf einen 45-Grad-Winkel ein.","Lege dich mit der Brust auf das Polster der Bank, die Füsse fest auf dem Boden.","Greife die Langhantel im Obergriff, etwas breiter als schulterbreit.","Halte den Rücken gerade und spanne deine Körpermitte an.","Ziehe die Langhantel in Richtung deiner Brust und drücke dabei die Schulterblätter zusammen.","Halte kurz oben inne und senke die Langhantel dann langsam zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0049.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0049.gif', 1784612222128, 1784612222128, 0),
  ('610a0b05-0cef-544a-946e-292eb0cd93e0', NULL, 'Barbell Incline Shoulder Raise', 'Langhantel-Schulterheben auf der Schrägbank', 'chest', 'serratus anterior', 'barbell', 'Set up an incline bench at a 45-degree angle. Sit on the bench with your back against the pad and feet flat on the ground. Hold a barbell with an overhand grip, slightly wider than shoulder-width apart. Lift the barbell up to shoulder height, keeping your elbows slightly bent. Slowly raise the barbell overhead, extending your arms fully. Pause for a moment at the top, then slowly lower the barbell back to shoulder height. Repeat for the desired number of repetitions.', NULL, 'deltoids', '["deltoids","trapezius"]', '["Set up an incline bench at a 45-degree angle.","Sit on the bench with your back against the pad and feet flat on the ground.","Hold a barbell with an overhand grip, slightly wider than shoulder-width apart.","Lift the barbell up to shoulder height, keeping your elbows slightly bent.","Slowly raise the barbell overhead, extending your arms fully.","Pause for a moment at the top, then slowly lower the barbell back to shoulder height.","Repeat for the desired number of repetitions."]', '["Stelle eine Schrägbank auf einen 45-Grad-Winkel ein.","Setze dich auf die Bank, den Rücken gegen das Polster und die Füsse fest auf dem Boden.","Halte eine Langhantel im Obergriff, etwas breiter als schulterbreit.","Hebe die Langhantel bis auf Schulterhöhe, die Ellbogen dabei leicht gebeugt haltend.","Hebe die Langhantel langsam über den Kopf, indem du die Arme vollständig streckst.","Halte kurz oben inne und senke die Langhantel dann langsam zurück auf Schulterhöhe.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0050.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0050.gif', 1784612222128, 1784612222128, 0),
  ('6614f8c0-98cf-59e1-9dad-78b09081dad2', NULL, 'Barbell Jefferson Squat', 'Langhantel-Jefferson-Kniebeuge', 'upper legs', 'glutes', 'barbell', 'Stand with your feet shoulder-width apart and toes slightly turned out. Hold the barbell with an overhand grip, resting it on the front of your body, just below your waist. Step your left foot forward and your right foot back, keeping your feet shoulder-width apart. Bend your knees and lower your body down into a squat position, keeping your back straight and chest up. Push through your heels to stand back up to the starting position. Repeat the movement, alternating your forward and back foot with each repetition.', NULL, 'quadriceps', '["quadriceps","hamstrings","calves"]', '["Stand with your feet shoulder-width apart and toes slightly turned out.","Hold the barbell with an overhand grip, resting it on the front of your body, just below your waist.","Step your left foot forward and your right foot back, keeping your feet shoulder-width apart.","Bend your knees and lower your body down into a squat position, keeping your back straight and chest up.","Push through your heels to stand back up to the starting position.","Repeat the movement, alternating your forward and back foot with each repetition."]', '["Stell dich mit schulterbreiten Füssen hin, die Zehen leicht nach aussen gedreht.","Halte die Langhantel im Obergriff vor deinem Körper, knapp unterhalb der Taille.","Setze deinen linken Fuss nach vorne und den rechten nach hinten, die Füsse bleiben dabei schulterbreit auseinander.","Beuge die Knie und senke deinen Körper in die Hocke ab, dabei bleibt der Rücken gerade und die Brust aufgerichtet.","Drücke dich über die Fersen zurück in die Ausgangsposition.","Wiederhole die Bewegung und wechsle dabei bei jeder Wiederholung den vorderen und hinteren Fuss."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0051.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0051.gif', 1784612222128, 1784612222128, 0),
  ('b92854b0-9e9b-5481-b0f8-fc1b34f65bb3', NULL, 'Barbell JM Bench Press', 'Langhantel-JM-Press', 'upper arms', 'triceps', 'barbell', 'Lie flat on a bench with your feet flat on the ground and your back pressed against the bench. Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart. Lower the barbell to your chest, keeping your elbows tucked in close to your body. Push the barbell back up to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', NULL, 'chest', '["chest","shoulders"]', '["Lie flat on a bench with your feet flat on the ground and your back pressed against the bench.","Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart.","Lower the barbell to your chest, keeping your elbows tucked in close to your body.","Push the barbell back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."]', '["Lege dich flach auf eine Bank, die Füsse fest auf dem Boden und den Rücken gegen die Bank gedrückt.","Greife die Langhantel im Obergriff, etwas breiter als schulterbreit.","Senke die Langhantel in Richtung deiner Brust ab, die Ellbogen dabei nah am Körper haltend.","Drücke die Langhantel zurück in die Ausgangsposition, indem du die Arme vollständig streckst.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0052.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0052.gif', 1784612222128, 1784612222128, 0),
  ('28ed5719-6f74-58b1-bb63-24953a1da2fb', NULL, 'Barbell Jump Squat', 'Langhantel-Sprungkniebeuge', 'upper legs', 'glutes', 'barbell', 'Start by standing with your feet shoulder-width apart, holding a barbell across your upper back. Lower your body into a squat position by bending your knees and pushing your hips back. Once you reach the bottom of the squat, explode upwards by jumping off the ground. As you jump, extend your hips, knees, and ankles, pushing through your toes. Land softly back into the squat position and immediately repeat the movement for the desired number of repetitions.', NULL, 'quadriceps', '["quadriceps","hamstrings","calves"]', '["Start by standing with your feet shoulder-width apart, holding a barbell across your upper back.","Lower your body into a squat position by bending your knees and pushing your hips back.","Once you reach the bottom of the squat, explode upwards by jumping off the ground.","As you jump, extend your hips, knees, and ankles, pushing through your toes.","Land softly back into the squat position and immediately repeat the movement for the desired number of repetitions."]', '["Stell dich mit schulterbreiten Füssen hin und lege eine Langhantel auf deinen oberen Rücken.","Senke deinen Körper in die Hocke ab, indem du die Knie beugst und die Hüfte nach hinten schiebst.","Sobald du den tiefsten Punkt der Hocke erreichst, springe explosiv nach oben ab.","Strecke während des Sprungs Hüfte, Knie und Sprunggelenke und drücke dich über die Zehen ab.","Lande weich zurück in der Hockposition und wiederhole die Bewegung sofort für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0053.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0053.gif', 1784612222128, 1784612222128, 0),
  ('1c643ac8-edb9-5169-89b8-d68db98f6e11', NULL, 'Barbell Lateral Lunge', 'Langhantel-Seitausfallschritt', 'upper legs', 'glutes', 'barbell', 'Stand with your feet shoulder-width apart, holding a barbell across your upper back. Take a big step to the side with your right foot, keeping your left foot planted. Bend your right knee and lower your body down into a lunge position, keeping your left leg straight. Push off with your right foot and return to the starting position. Repeat on the other side, stepping with your left foot.', NULL, 'quadriceps', '["quadriceps","hamstrings","calves"]', '["Stand with your feet shoulder-width apart, holding a barbell across your upper back.","Take a big step to the side with your right foot, keeping your left foot planted.","Bend your right knee and lower your body down into a lunge position, keeping your left leg straight.","Push off with your right foot and return to the starting position.","Repeat on the other side, stepping with your left foot."]', '["Stell dich mit schulterbreiten Füssen hin und lege eine Langhantel auf deinen oberen Rücken.","Mache mit dem rechten Fuss einen grossen Schritt zur Seite, während dein linker Fuss fest am Boden bleibt.","Beuge dein rechtes Knie und senke deinen Körper in eine Ausfallschritt-Position ab, das linke Bein bleibt dabei gestreckt.","Drücke dich mit dem rechten Fuss ab und kehre in die Ausgangsposition zurück.","Wiederhole auf der anderen Seite, indem du mit dem linken Fuss zur Seite trittst."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1410.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1410.gif', 1784612222128, 1784612222128, 0),
  ('e2ab7845-3eb1-5c11-84e0-ea824626e609', NULL, 'Barbell Low Bar Squat', 'Langhantel-Low-Bar-Kniebeuge', 'upper legs', 'glutes', 'barbell', 'Stand with your feet shoulder-width apart and the barbell resting on your upper back. Keeping your chest up and core engaged, slowly lower your body by bending your knees and pushing your hips back. Continue lowering until your thighs are parallel to the ground or slightly below. Pause for a moment, then push through your heels to return to the starting position. Repeat for the desired number of repetitions.', NULL, 'quadriceps', '["quadriceps","hamstrings","calves"]', '["Stand with your feet shoulder-width apart and the barbell resting on your upper back.","Keeping your chest up and core engaged, slowly lower your body by bending your knees and pushing your hips back.","Continue lowering until your thighs are parallel to the ground or slightly below.","Pause for a moment, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."]', '["Stell dich mit schulterbreiten Füssen hin und lege die Langhantel auf deinen oberen Rücken.","Halte die Brust aufgerichtet und die Körpermitte angespannt, während du deinen Körper langsam absenkst, indem du die Knie beugst und die Hüfte nach hinten schiebst.","Senke dich weiter ab, bis deine Oberschenkel parallel zum Boden sind oder leicht darunter.","Halte kurz inne und drücke dich dann über die Fersen zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1435.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1435.gif', 1784612222128, 1784612222128, 0),
  ('fa1d3a76-4d6b-5849-81b1-cecbd5a57825', NULL, 'Barbell Lunge', 'Langhantel-Ausfallschritt', 'upper legs', 'glutes', 'barbell', 'Start by standing with your feet shoulder-width apart and a barbell resting on your upper back. Take a step forward with your right foot, keeping your torso upright. Lower your body by bending your right knee until your thigh is parallel to the ground. Push through your right heel to return to the starting position. Repeat with your left leg, alternating legs for the desired number of repetitions.', NULL, 'quadriceps', '["quadriceps","hamstrings","calves"]', '["Start by standing with your feet shoulder-width apart and a barbell resting on your upper back.","Take a step forward with your right foot, keeping your torso upright.","Lower your body by bending your right knee until your thigh is parallel to the ground.","Push through your right heel to return to the starting position.","Repeat with your left leg, alternating legs for the desired number of repetitions."]', '["Stell dich mit schulterbreiten Füssen hin und lege eine Langhantel auf deinen oberen Rücken.","Mache mit dem rechten Fuss einen Schritt nach vorne und halte den Oberkörper dabei aufrecht.","Senke deinen Körper ab, indem du das rechte Knie beugst, bis dein Oberschenkel parallel zum Boden ist.","Drücke dich über die rechte Ferse zurück in die Ausgangsposition.","Wiederhole mit dem linken Bein und wechsle die Beine für die gewünschte Anzahl Wiederholungen ab."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0054.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0054.gif', 1784612222128, 1784612222128, 0),
  ('17aba6b8-0a77-520f-9651-8a157adb7ffa', NULL, 'Barbell Lying Back of the Head Triceps Extension', 'Langhantel-Trizepsstrecken hinter dem Kopf im Liegen', 'upper arms', 'triceps', 'barbell', 'Lie flat on a bench with your feet flat on the ground and your head at the end of the bench. Hold a barbell with an overhand grip, hands shoulder-width apart, and extend your arms straight up over your chest. Keeping your upper arms stationary, slowly lower the barbell behind your head by bending your elbows. Pause for a moment, then extend your arms back up to the starting position. Repeat for the desired number of repetitions.', NULL, 'shoulders', '["shoulders"]', '["Lie flat on a bench with your feet flat on the ground and your head at the end of the bench.","Hold a barbell with an overhand grip, hands shoulder-width apart, and extend your arms straight up over your chest.","Keeping your upper arms stationary, slowly lower the barbell behind your head by bending your elbows.","Pause for a moment, then extend your arms back up to the starting position.","Repeat for the desired number of repetitions."]', '["Lege dich flach auf eine Bank, die Füsse fest auf dem Boden und den Kopf am Ende der Bank.","Halte eine Langhantel im Obergriff, die Hände schulterbreit auseinander, und strecke die Arme gerade über deine Brust nach oben.","Senke die Langhantel langsam hinter deinen Kopf ab, indem du die Ellbogen beugst, während die Oberarme unbewegt bleiben.","Halte kurz inne und strecke die Arme dann zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1720.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1720.gif', 1784612222128, 1784612222128, 0),
  ('e0aafa6a-c5cf-5e9a-9b8a-23a01542da58', NULL, 'Barbell Lying Close-Grip Press', 'Langhantel-Drücken eng im Liegen', 'upper arms', 'triceps', 'barbell', 'Lie flat on a bench with your feet flat on the ground and your back pressed against the bench. Grasp the barbell with a close grip, hands shoulder-width apart, palms facing towards your feet. Lift the barbell off the rack and hold it directly above your chest with your arms fully extended. Slowly lower the barbell towards your chest, keeping your elbows close to your body. Pause for a moment when the barbell touches your chest, then push it back up to the starting position. Repeat for the desired number of repetitions.', NULL, 'chest', '["chest","shoulders"]', '["Lie flat on a bench with your feet flat on the ground and your back pressed against the bench.","Grasp the barbell with a close grip, hands shoulder-width apart, palms facing towards your feet.","Lift the barbell off the rack and hold it directly above your chest with your arms fully extended.","Slowly lower the barbell towards your chest, keeping your elbows close to your body.","Pause for a moment when the barbell touches your chest, then push it back up to the starting position.","Repeat for the desired number of repetitions."]', '["Lege dich flach auf eine Bank, die Füsse fest auf dem Boden und den Rücken gegen die Bank gedrückt.","Greife die Langhantel im engen Griff, die Hände schulterbreit auseinander, die Handflächen zeigen zu deinen Füssen.","Hebe die Langhantel aus der Ablage und halte sie mit gestreckten Armen direkt über deiner Brust.","Senke die Langhantel langsam in Richtung deiner Brust ab, die Ellbogen dabei nah am Körper haltend.","Halte kurz inne, wenn die Langhantel deine Brust berührt, und drücke sie dann zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0055.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0055.gif', 1784612222128, 1784612222128, 0),
  ('b0cbb9c2-29d2-5095-9d73-0bd8336454a2', NULL, 'Barbell Lying Close-Grip Triceps Extension', 'Langhantel-Trizepsstrecken eng im Liegen', 'upper arms', 'triceps', 'barbell', 'Lie flat on a bench with your feet flat on the ground and your head at the end of the bench. Grasp the barbell with a close grip, hands shoulder-width apart, palms facing up. Extend your arms fully, lifting the barbell above your chest. Keeping your upper arms stationary, slowly lower the barbell towards your forehead by bending your elbows. Pause for a moment at the bottom, then extend your arms back to the starting position. Repeat for the desired number of repetitions.', NULL, 'shoulders', '["shoulders"]', '["Lie flat on a bench with your feet flat on the ground and your head at the end of the bench.","Grasp the barbell with a close grip, hands shoulder-width apart, palms facing up.","Extend your arms fully, lifting the barbell above your chest.","Keeping your upper arms stationary, slowly lower the barbell towards your forehead by bending your elbows.","Pause for a moment at the bottom, then extend your arms back to the starting position.","Repeat for the desired number of repetitions."]', '["Lege dich flach auf eine Bank, die Füsse fest auf dem Boden und den Kopf am Ende der Bank.","Greife die Langhantel im engen Griff, die Hände schulterbreit auseinander, die Handflächen zeigen nach oben.","Strecke die Arme vollständig und hebe die Langhantel über deine Brust.","Senke die Langhantel langsam in Richtung deiner Stirn ab, indem du die Ellbogen beugst, während die Oberarme unbewegt bleiben.","Halte kurz unten inne und strecke die Arme dann zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0056.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0056.gif', 1784612222128, 1784612222128, 0),
  ('efce2a05-c898-5116-9e0b-67f2d031a0a9', NULL, 'Barbell Lying Extension', 'Langhantel-Streckung im Liegen (Trizeps)', 'upper arms', 'triceps', 'barbell', 'Lie flat on a bench with your feet flat on the ground and your head at the end of the bench. Hold the barbell with an overhand grip, hands shoulder-width apart, and extend your arms straight up over your chest. Keeping your upper arms stationary, slowly lower the barbell towards your forehead by bending your elbows. Pause for a moment, then extend your arms back up to the starting position. Repeat for the desired number of repetitions.', NULL, 'shoulders', '["shoulders"]', '["Lie flat on a bench with your feet flat on the ground and your head at the end of the bench.","Hold the barbell with an overhand grip, hands shoulder-width apart, and extend your arms straight up over your chest.","Keeping your upper arms stationary, slowly lower the barbell towards your forehead by bending your elbows.","Pause for a moment, then extend your arms back up to the starting position.","Repeat for the desired number of repetitions."]', '["Lege dich flach auf eine Bank, die Füsse fest auf dem Boden und den Kopf am Ende der Bank.","Halte die Langhantel im Obergriff, die Hände schulterbreit auseinander, und strecke die Arme gerade über deine Brust nach oben.","Senke die Langhantel langsam in Richtung deiner Stirn ab, indem du die Ellbogen beugst, während die Oberarme unbewegt bleiben.","Halte kurz inne und strecke die Arme dann zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0057.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0057.gif', 1784612222128, 1784612222128, 0),
  ('eea398bd-2be6-5935-9546-d65b1c5e9b32', NULL, 'Barbell Lying Lifting (on Hip)', 'Langhantel-Hüftheben im Liegen', 'upper legs', 'glutes', 'barbell', 'Lie flat on your back on a bench with your feet flat on the ground and your knees bent. Hold the barbell with an overhand grip and position it on your hips. Engaging your glutes, lift your hips off the bench until your body forms a straight line from your knees to your shoulders. Pause for a moment at the top, then slowly lower your hips back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'hamstrings', '["hamstrings","quadriceps"]', '["Lie flat on your back on a bench with your feet flat on the ground and your knees bent.","Hold the barbell with an overhand grip and position it on your hips.","Engaging your glutes, lift your hips off the bench until your body forms a straight line from your knees to your shoulders.","Pause for a moment at the top, then slowly lower your hips back down to the starting position.","Repeat for the desired number of repetitions."]', '["Lege dich mit dem Rücken flach auf eine Bank, die Füsse fest auf dem Boden und die Knie gebeugt.","Halte die Langhantel im Obergriff und positioniere sie auf deiner Hüfte.","Spanne dein Gesäss an und hebe die Hüfte von der Bank ab, bis dein Körper eine gerade Linie von den Knien bis zu den Schultern bildet.","Halte kurz oben inne und senke die Hüfte dann langsam zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0058.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0058.gif', 1784612222128, 1784612222128, 0),
  ('b30f77e9-2496-5774-b08d-f0567c3a2a9a', NULL, 'Barbell Lying Preacher Curl', 'Langhantel-Preacher-Curl im Liegen', 'upper arms', 'biceps', 'barbell', 'Sit on a preacher bench with your chest against the pad and your arms extended over the edge, holding a barbell with an underhand grip. Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Continue to raise the bar until your biceps are fully contracted and the bar is at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly begin to lower the barbell back to the starting position. Repeat for the desired number of repetitions.', NULL, 'forearms', '["forearms"]', '["Sit on a preacher bench with your chest against the pad and your arms extended over the edge, holding a barbell with an underhand grip.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the bar until your biceps are fully contracted and the bar is at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the barbell back to the starting position.","Repeat for the desired number of repetitions."]', '["Setze dich auf eine Scott-Bank, die Brust gegen das Polster gelehnt, die Arme über die Kante gestreckt, und halte eine Langhantel im Untergriff.","Atme aus und beuge die Arme, um die Hantel anzuheben, während du die Bizeps anspannst; die Oberarme bleiben dabei unbewegt.","Hebe die Hantel weiter an, bis der Bizeps vollständig angespannt ist und sich die Stange auf Schulterhöhe befindet.","Halte die angespannte Position kurz und drücke dabei den Bizeps zusammen.","Atme ein und senke die Langhantel langsam zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0059.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0059.gif', 1784612222128, 1784612222128, 0),
  ('eb219ab8-13f6-57eb-b9d9-e5f1cd7e8c30', NULL, 'Barbell Lying Triceps Extension', 'Langhantel-Trizepsstrecken im Liegen', 'upper arms', 'triceps', 'barbell', 'Lie flat on a bench with your feet flat on the ground and your head at the end of the bench. Hold the barbell with an overhand grip, hands shoulder-width apart, and extend your arms straight up over your chest. Keeping your upper arms stationary, slowly lower the barbell towards your forehead by bending your elbows. Pause for a moment at the bottom, then extend your arms back up to the starting position. Repeat for the desired number of repetitions.', NULL, 'shoulders', '["shoulders"]', '["Lie flat on a bench with your feet flat on the ground and your head at the end of the bench.","Hold the barbell with an overhand grip, hands shoulder-width apart, and extend your arms straight up over your chest.","Keeping your upper arms stationary, slowly lower the barbell towards your forehead by bending your elbows.","Pause for a moment at the bottom, then extend your arms back up to the starting position.","Repeat for the desired number of repetitions."]', '["Lege dich flach auf eine Bank, die Füsse fest auf dem Boden und den Kopf am Ende der Bank.","Halte die Langhantel im Obergriff, die Hände schulterbreit auseinander, und strecke die Arme gerade über deine Brust nach oben.","Senke die Langhantel langsam in Richtung deiner Stirn ab, indem du die Ellbogen beugst, während die Oberarme unbewegt bleiben.","Halte kurz unten inne und strecke die Arme dann zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0061.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0061.gif', 1784612222128, 1784612222128, 0),
  ('3781746e-2da5-5118-80b3-d4dfacd6f1dd', NULL, 'Barbell Lying Triceps Extension Skull Crusher', 'Langhantel-Skullcrusher im Liegen', 'upper arms', 'triceps', 'barbell', 'Lie flat on a bench with your feet flat on the ground and your head at the end of the bench. Hold the barbell with an overhand grip, hands shoulder-width apart, and extend your arms straight up over your chest. Keeping your upper arms stationary, slowly lower the barbell towards your forehead by bending your elbows. Pause for a moment when the barbell is just above your forehead, then extend your arms back up to the starting position. Repeat for the desired number of repetitions.', NULL, 'shoulders', '["shoulders"]', '["Lie flat on a bench with your feet flat on the ground and your head at the end of the bench.","Hold the barbell with an overhand grip, hands shoulder-width apart, and extend your arms straight up over your chest.","Keeping your upper arms stationary, slowly lower the barbell towards your forehead by bending your elbows.","Pause for a moment when the barbell is just above your forehead, then extend your arms back up to the starting position.","Repeat for the desired number of repetitions."]', '["Lege dich flach auf eine Bank, die Füsse fest auf dem Boden und den Kopf am Ende der Bank.","Halte die Langhantel im Obergriff, die Hände schulterbreit auseinander, und strecke die Arme gerade über deine Brust nach oben.","Senke die Langhantel langsam in Richtung deiner Stirn ab, indem du die Ellbogen beugst, während die Oberarme unbewegt bleiben.","Halte kurz inne, wenn die Langhantel knapp über deiner Stirn ist, und strecke die Arme dann zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0060.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0060.gif', 1784612222128, 1784612222128, 0),
  ('ac92b728-7835-5658-8d73-03ab4bdea6c7', NULL, 'Barbell Narrow Stance Squat', 'Langhantel-Kniebeuge im engen Stand', 'upper legs', 'glutes', 'barbell', 'Stand with your feet shoulder-width apart and toes pointing slightly outward. Hold the barbell across your upper back, resting it on your traps or rear delts. Engage your core and keep your chest up as you slowly lower your body by bending your knees and pushing your hips back. Continue lowering until your thighs are parallel to the ground or slightly below. Pause for a moment, then push through your heels to return to the starting position. Repeat for the desired number of repetitions.', NULL, 'quadriceps', '["quadriceps","hamstrings","calves"]', '["Stand with your feet shoulder-width apart and toes pointing slightly outward.","Hold the barbell across your upper back, resting it on your traps or rear delts.","Engage your core and keep your chest up as you slowly lower your body by bending your knees and pushing your hips back.","Continue lowering until your thighs are parallel to the ground or slightly below.","Pause for a moment, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."]', '["Stell dich mit schulterbreiten Füssen hin, die Zehen leicht nach aussen zeigend.","Lege die Langhantel auf deinen oberen Rücken, sodass sie auf dem Trapezmuskel oder den hinteren Schultern aufliegt.","Spanne deine Körpermitte an und halte die Brust aufgerichtet, während du deinen Körper langsam absenkst, indem du die Knie beugst und die Hüfte nach hinten schiebst.","Senke dich weiter ab, bis deine Oberschenkel parallel zum Boden sind oder leicht darunter.","Halte kurz inne und drücke dich dann über die Fersen zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0063.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0063.gif', 1784612222128, 1784612222128, 0);

INSERT OR REPLACE INTO exercises (id, user_id, name, name_de, category, primary_muscle, equipment, instructions_en, instructions_de, muscle_group, secondary_muscles, instruction_steps_en, instruction_steps_de, thumbnail_url, gif_url, created_at, updated_at, deleted) VALUES
  ('7840f4e8-d096-546f-a586-71bb01a12bf3', NULL, 'Barbell One Arm Bent Over Row', 'Einarmiges Langhantel-Rudern vorgebeugt', 'back', 'upper back', 'barbell', 'Stand with your feet shoulder-width apart, knees slightly bent, and hold a barbell with one hand using an overhand grip. Bend forward at the hips, keeping your back straight and your head in a neutral position. Pull the barbell up towards your chest, keeping your elbow close to your body and squeezing your shoulder blades together. Lower the barbell back down to the starting position in a controlled manner. Repeat for the desired number of repetitions, then switch to the other arm.', NULL, 'biceps', '["biceps","forearms"]', '["Stand with your feet shoulder-width apart, knees slightly bent, and hold a barbell with one hand using an overhand grip.","Bend forward at the hips, keeping your back straight and your head in a neutral position.","Pull the barbell up towards your chest, keeping your elbow close to your body and squeezing your shoulder blades together.","Lower the barbell back down to the starting position in a controlled manner.","Repeat for the desired number of repetitions, then switch to the other arm."]', '["Stell dich mit schulterbreiten Füssen hin, die Knie leicht gebeugt, und halte eine Langhantel mit einer Hand im Obergriff.","Beuge dich in der Hüfte nach vorne, dabei bleibt der Rücken gerade und der Kopf in neutraler Position.","Ziehe die Langhantel in Richtung deiner Brust, halte den Ellbogen dabei nah am Körper und drücke die Schulterblätter zusammen.","Senke die Langhantel kontrolliert zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dann den Arm."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0064.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0064.gif', 1784612222128, 1784612222128, 0),
  ('694c1dfd-b714-5f41-9332-56d2bdd1e51e', NULL, 'Barbell One Arm Floor Press', 'Einarmiges Langhantel-Bankdrücken am Boden', 'upper arms', 'triceps', 'barbell', 'Lie flat on your back on the floor with your knees bent and feet flat on the ground. Hold the barbell with one hand, palm facing up, and extend your arm straight up over your chest. Slowly lower the barbell towards your chest, keeping your elbow close to your body. Pause for a moment at the bottom, then push the barbell back up to the starting position. Repeat for the desired number of repetitions, then switch arms.', NULL, 'chest', '["chest","shoulders"]', '["Lie flat on your back on the floor with your knees bent and feet flat on the ground.","Hold the barbell with one hand, palm facing up, and extend your arm straight up over your chest.","Slowly lower the barbell towards your chest, keeping your elbow close to your body.","Pause for a moment at the bottom, then push the barbell back up to the starting position.","Repeat for the desired number of repetitions, then switch arms."]', '["Lege dich mit dem Rücken flach auf den Boden, die Knie gebeugt und die Füsse fest auf dem Boden.","Halte die Langhantel mit einer Hand, die Handfläche zeigt nach oben, und strecke den Arm gerade über deine Brust nach oben.","Senke die Langhantel langsam in Richtung deiner Brust ab, den Ellbogen dabei nah am Körper haltend.","Halte kurz unten inne und drücke die Langhantel dann zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dann den Arm."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0065.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0065.gif', 1784612222128, 1784612222128, 0),
  ('ffa86444-c5e7-52ca-9534-1670a11d0a6f', NULL, 'Barbell One Arm Side Deadlift', 'Einarmiges Langhantel-Kreuzheben seitlich', 'upper legs', 'glutes', 'barbell', 'Stand with your feet shoulder-width apart, holding a barbell in one hand with an overhand grip. Keep your back straight and your core engaged. Bend at the hips and lower the barbell towards the outside of your leg, keeping your arm straight and your chest up. Lower the barbell as far as you can while maintaining good form. Pause for a moment, then slowly return to the starting position. Repeat for the desired number of repetitions, then switch sides.', NULL, 'hamstrings', '["hamstrings","quadriceps","lower back"]', '["Stand with your feet shoulder-width apart, holding a barbell in one hand with an overhand grip.","Keep your back straight and your core engaged.","Bend at the hips and lower the barbell towards the outside of your leg, keeping your arm straight and your chest up.","Lower the barbell as far as you can while maintaining good form.","Pause for a moment, then slowly return to the starting position.","Repeat for the desired number of repetitions, then switch sides."]', '["Stell dich mit schulterbreiten Füssen hin und halte eine Langhantel mit einer Hand im Obergriff.","Halte den Rücken gerade und spanne deine Körpermitte an.","Beuge dich in der Hüfte und senke die Langhantel seitlich neben deinem Bein ab, der Arm bleibt dabei gestreckt und die Brust aufgerichtet.","Senke die Langhantel so weit ab, wie es dir mit sauberer Technik möglich ist.","Halte kurz inne und kehre dann langsam in die Ausgangsposition zurück.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dann die Seite."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0066.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0066.gif', 1784612222128, 1784612222128, 0),
  ('3b0da3ea-7a8c-5c16-80cf-3b1b41588d98', NULL, 'Barbell One Arm Snatch', 'Einarmiges Langhantel-Reissen', 'shoulders', 'delts', 'barbell', 'Stand with your feet shoulder-width apart, toes pointing slightly outwards. Hold the barbell with an overhand grip, hands slightly wider than shoulder-width apart. Bend your knees and lower your hips into a squat position, keeping your back straight and chest up. Explosively extend your hips, knees, and ankles, driving the barbell upwards. As the barbell reaches chest level, pull it upwards with your arm, keeping it close to your body. Rotate your elbow under the barbell and extend your arm fully overhead, locking out your elbow. Lower the barbell back down to the starting position in a controlled manner. Repeat for the desired number of repetitions, then switch arms.', NULL, 'traps', '["traps","forearms","core"]', '["Stand with your feet shoulder-width apart, toes pointing slightly outwards.","Hold the barbell with an overhand grip, hands slightly wider than shoulder-width apart.","Bend your knees and lower your hips into a squat position, keeping your back straight and chest up.","Explosively extend your hips, knees, and ankles, driving the barbell upwards.","As the barbell reaches chest level, pull it upwards with your arm, keeping it close to your body.","Rotate your elbow under the barbell and extend your arm fully overhead, locking out your elbow.","Lower the barbell back down to the starting position in a controlled manner.","Repeat for the desired number of repetitions, then switch arms."]', '["Stell dich mit schulterbreiten Füssen hin, die Zehen leicht nach aussen zeigend.","Greife die Langhantel im Obergriff, die Hände etwas breiter als schulterbreit.","Beuge die Knie und senke die Hüfte in eine Hockposition ab, dabei bleibt der Rücken gerade und die Brust aufgerichtet.","Strecke Hüfte, Knie und Sprunggelenke explosiv, um die Langhantel nach oben zu treiben.","Sobald die Langhantel Brusthöhe erreicht, ziehe sie mit deinem Arm weiter nach oben, nah am Körper.","Drehe deinen Ellbogen unter die Langhantel und strecke den Arm vollständig über den Kopf, bis der Ellbogen blockiert ist.","Senke die Langhantel kontrolliert zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dann den Arm."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0067.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0067.gif', 1784612222128, 1784612222128, 0),
  ('1d48354a-9c79-5755-bef0-2aec92388339', NULL, 'Barbell One Leg Squat', 'Einbeinige Langhantel-Kniebeuge', 'upper legs', 'quads', 'barbell', 'Stand with your feet shoulder-width apart and hold a barbell across your upper back. Lift one foot off the ground and extend it forward, keeping it parallel to the ground. Bend your standing leg and lower your body down as if sitting back into a chair, keeping your chest up and your back straight. Lower yourself until your thigh is parallel to the ground, then push through your heel to return to the starting position. Repeat for the desired number of repetitions, then switch legs and repeat.', NULL, 'glutes', '["glutes","hamstrings","calves"]', '["Stand with your feet shoulder-width apart and hold a barbell across your upper back.","Lift one foot off the ground and extend it forward, keeping it parallel to the ground.","Bend your standing leg and lower your body down as if sitting back into a chair, keeping your chest up and your back straight.","Lower yourself until your thigh is parallel to the ground, then push through your heel to return to the starting position.","Repeat for the desired number of repetitions, then switch legs and repeat."]', '["Stell dich mit schulterbreiten Füssen hin und lege eine Langhantel auf deinen oberen Rücken.","Hebe einen Fuss vom Boden ab und strecke ihn nach vorne, parallel zum Boden.","Beuge dein Standbein und senke deinen Körper ab, als würdest du dich in einen Stuhl zurücksetzen, die Brust bleibt dabei aufgerichtet und der Rücken gerade.","Senke dich ab, bis dein Oberschenkel parallel zum Boden ist, und drücke dich dann über die Ferse zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dann das Bein."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0068.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0068.gif', 1784612222128, 1784612222128, 0),
  ('2093779b-14a6-5734-bcbe-f6b77a9853aa', NULL, 'Barbell Overhead Squat', 'Langhantel-Überkopfkniebeuge', 'upper legs', 'quads', 'barbell', 'Stand with your feet shoulder-width apart and toes slightly turned out. Hold the barbell with a wide grip, positioning it overhead with your arms fully extended. Engage your core and lower your body down into a squat position, keeping your chest up and knees tracking over your toes. Pause for a moment at the bottom, then push through your heels to return to the starting position. Repeat for the desired number of repetitions.', NULL, 'glutes', '["glutes","hamstrings","calves","core"]', '["Stand with your feet shoulder-width apart and toes slightly turned out.","Hold the barbell with a wide grip, positioning it overhead with your arms fully extended.","Engage your core and lower your body down into a squat position, keeping your chest up and knees tracking over your toes.","Pause for a moment at the bottom, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."]', '["Stell dich mit schulterbreiten Füssen hin, die Zehen leicht nach aussen gedreht.","Halte die Langhantel im weiten Griff über deinem Kopf, die Arme dabei vollständig gestreckt.","Spanne deine Körpermitte an und senke deinen Körper in die Hocke ab, die Brust bleibt aufgerichtet und die Knie folgen der Richtung der Zehen.","Halte kurz unten inne und drücke dich dann über die Fersen zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0069.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0069.gif', 1784612222128, 1784612222128, 0),
  ('f360c8e5-b383-58f1-acd7-0d7be38e36fb', NULL, 'Barbell Palms Down Wrist Curl over a Bench', 'Langhantel-Handgelenkcurl im Obergriff über der Bank', 'lower arms', 'forearms', 'barbell', 'Sit on a bench with your feet flat on the ground and your forearms resting on your thighs, palms facing down. Hold a barbell with an overhand grip, hands shoulder-width apart. Lower the barbell towards the ground by flexing your wrists, keeping your forearms stationary. Pause for a moment at the bottom, then slowly raise the barbell back up by extending your wrists. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","brachialis"]', '["Sit on a bench with your feet flat on the ground and your forearms resting on your thighs, palms facing down.","Hold a barbell with an overhand grip, hands shoulder-width apart.","Lower the barbell towards the ground by flexing your wrists, keeping your forearms stationary.","Pause for a moment at the bottom, then slowly raise the barbell back up by extending your wrists.","Repeat for the desired number of repetitions."]', '["Setze dich auf eine Bank, die Füsse fest auf dem Boden, die Unterarme auf den Oberschenkeln abgelegt, die Handflächen zeigen nach unten.","Halte eine Langhantel im Obergriff, die Hände schulterbreit auseinander.","Senke die Langhantel in Richtung Boden ab, indem du die Handgelenke beugst, während die Unterarme unbewegt bleiben.","Halte kurz unten inne und hebe die Langhantel dann langsam wieder an, indem du die Handgelenke streckst.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1411.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1411.gif', 1784612222128, 1784612222128, 0),
  ('77b31f67-9998-5e37-a931-ea99612ca4b5', NULL, 'Barbell Palms Up Wrist Curl over a Bench', 'Langhantel-Handgelenkcurl im Untergriff über der Bank', 'lower arms', 'forearms', 'barbell', 'Sit on a bench with your feet flat on the ground and hold a barbell with an underhand grip, palms facing up. Rest your forearms on the bench, allowing your wrists to hang off the edge. Keeping your forearms stationary, exhale and curl your wrists upwards as far as possible. Hold the contracted position for a brief pause, then inhale and slowly lower the barbell back to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","shoulders"]', '["Sit on a bench with your feet flat on the ground and hold a barbell with an underhand grip, palms facing up.","Rest your forearms on the bench, allowing your wrists to hang off the edge.","Keeping your forearms stationary, exhale and curl your wrists upwards as far as possible.","Hold the contracted position for a brief pause, then inhale and slowly lower the barbell back to the starting position.","Repeat for the desired number of repetitions."]', '["Setze dich auf eine Bank, die Füsse fest auf dem Boden, und halte eine Langhantel im Untergriff, die Handflächen zeigen nach oben.","Lege deine Unterarme auf der Bank ab, sodass die Handgelenke über die Kante hängen.","Atme aus und beuge die Handgelenke so weit wie möglich nach oben, während die Unterarme unbewegt bleiben.","Halte die angespannte Position kurz, atme dann ein und senke die Langhantel langsam zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1412.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1412.gif', 1784612222128, 1784612222128, 0),
  ('9adcdd0b-417f-53fe-9169-d00ebb4f0286', NULL, 'Barbell Pendlay Row', 'Langhantel-Pendlay-Rudern', 'back', 'upper back', 'barbell', 'Stand with your feet shoulder-width apart and your knees slightly bent. Bend forward at the hips, keeping your back straight and your chest up. Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart. Pull the barbell towards your upper abdomen, squeezing your shoulder blades together. Lower the barbell back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","forearms"]', '["Stand with your feet shoulder-width apart and your knees slightly bent.","Bend forward at the hips, keeping your back straight and your chest up.","Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart.","Pull the barbell towards your upper abdomen, squeezing your shoulder blades together.","Lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."]', '["Stell dich mit schulterbreiten Füssen hin und beuge die Knie leicht.","Beuge dich in der Hüfte nach vorne, dabei bleibt der Rücken gerade und die Brust aufgerichtet.","Greife die Langhantel im Obergriff, etwas breiter als schulterbreit.","Ziehe die Langhantel in Richtung deines oberen Bauchs und drücke dabei die Schulterblätter zusammen.","Senke die Langhantel zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/3017.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/3017.gif', 1784612222128, 1784612222128, 0),
  ('f706b36b-83f9-526d-9dc8-1e2ac5c2766e', NULL, 'Barbell Pin Presses', 'Langhantel-Pin-Press', 'upper arms', 'triceps', 'barbell', 'Set up a barbell on a power rack at chest height. Stand facing the barbell and position yourself underneath it, with your feet shoulder-width apart. Grip the barbell with an overhand grip, slightly wider than shoulder-width apart. Lift the barbell off the rack and hold it directly above your chest, with your arms fully extended. Lower the barbell down towards your chest, keeping your elbows tucked in close to your body. Pause for a moment when the barbell touches your chest. Push the barbell back up to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', NULL, 'shoulders', '["shoulders"]', '["Set up a barbell on a power rack at chest height.","Stand facing the barbell and position yourself underneath it, with your feet shoulder-width apart.","Grip the barbell with an overhand grip, slightly wider than shoulder-width apart.","Lift the barbell off the rack and hold it directly above your chest, with your arms fully extended.","Lower the barbell down towards your chest, keeping your elbows tucked in close to your body.","Pause for a moment when the barbell touches your chest.","Push the barbell back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."]', '["Lege eine Langhantel in einem Kraftrack auf Brusthöhe ab.","Stell dich mit dem Gesicht zur Langhantel darunter, die Füsse schulterbreit auseinander.","Greife die Langhantel im Obergriff, etwas breiter als schulterbreit.","Hebe die Langhantel aus der Ablage und halte sie mit vollständig gestreckten Armen direkt über deiner Brust.","Senke die Langhantel in Richtung deiner Brust ab, die Ellbogen dabei nah am Körper haltend.","Halte kurz inne, wenn die Langhantel deine Brust berührt.","Drücke die Langhantel zurück in die Ausgangsposition, indem du die Arme vollständig streckst.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1751.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1751.gif', 1784612222128, 1784612222128, 0),
  ('2ac41956-05a5-5bbd-8ade-635521589492', NULL, 'Barbell Preacher Curl', 'Langhantel-Preacher-Curl', 'upper arms', 'biceps', 'barbell', 'Sit on a preacher bench with your upper arms resting on the pad and your chest against the support. Grasp the barbell with an underhand grip, slightly wider than shoulder-width apart. Keeping your upper arms stationary, exhale and curl the barbell up towards your shoulders. Pause for a moment at the top, squeezing your biceps. Inhale and slowly lower the barbell back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'forearms', '["forearms"]', '["Sit on a preacher bench with your upper arms resting on the pad and your chest against the support.","Grasp the barbell with an underhand grip, slightly wider than shoulder-width apart.","Keeping your upper arms stationary, exhale and curl the barbell up towards your shoulders.","Pause for a moment at the top, squeezing your biceps.","Inhale and slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."]', '["Setze dich auf eine Scott-Bank, die Oberarme auf dem Polster abgelegt und die Brust gegen die Stütze gelehnt.","Greife die Langhantel im Untergriff, etwas breiter als schulterbreit.","Atme aus und beuge die Arme, um die Langhantel in Richtung deiner Schultern anzuheben, während die Oberarme unbewegt bleiben.","Halte oben kurz inne und drücke dabei den Bizeps zusammen.","Atme ein und senke die Langhantel langsam zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0070.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0070.gif', 1784612222128, 1784612222128, 0),
  ('f98a2a2c-2684-5538-9a55-ffd7faa8e1e8', NULL, 'Barbell Press Sit-up', 'Sit-up mit Langhantel-Überkopfdrücken', 'waist', 'abs', 'barbell', 'Lie flat on your back on a mat with your knees bent and feet flat on the ground. Hold the barbell with an overhand grip, resting it on your chest. Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle. Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'shoulders', '["shoulders","chest"]', '["Lie flat on your back on a mat with your knees bent and feet flat on the ground.","Hold the barbell with an overhand grip, resting it on your chest.","Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."]', '["Lege dich mit dem Rücken flach auf eine Matte, die Knie gebeugt und die Füsse fest auf dem Boden.","Halte die Langhantel im Obergriff und lege sie auf deiner Brust ab.","Spanne deine Bauchmuskeln an und hebe deinen Oberkörper langsam vom Boden ab, bis dein Rumpf im 45-Grad-Winkel steht.","Halte oben kurz inne und senke deinen Oberkörper dann langsam zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0071.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0071.gif', 1784612222128, 1784612222128, 0),
  ('4ba0b73d-dbbc-5121-9bb2-31df344c8ded', NULL, 'Barbell Prone Incline Curl', 'Langhantel-Curl in Bauchlage auf der Schrägbank', 'upper arms', 'biceps', 'barbell', 'Set up an incline bench at a 45-degree angle. Lie face down on the bench with your chest and stomach resting against it. Hold a barbell with an underhand grip, shoulder-width apart. Extend your arms fully, allowing the barbell to hang down towards the floor. Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Continue to raise the barbell until your biceps are fully contracted and the bar is at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly begin to lower the barbell back to the starting position. Repeat for the desired number of repetitions.', NULL, 'forearms', '["forearms"]', '["Set up an incline bench at a 45-degree angle.","Lie face down on the bench with your chest and stomach resting against it.","Hold a barbell with an underhand grip, shoulder-width apart.","Extend your arms fully, allowing the barbell to hang down towards the floor.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the barbell until your biceps are fully contracted and the bar is at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the barbell back to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle eine Schrägbank auf einen 45-Grad-Winkel ein.","Lege dich mit Brust und Bauch auf die Bank.","Halte eine Langhantel im Untergriff, schulterbreit auseinander.","Strecke die Arme vollständig, sodass die Langhantel Richtung Boden hängt.","Atme aus und beuge die Arme, um die Hantel anzuheben, während du die Bizeps anspannst; die Oberarme bleiben dabei unbewegt.","Hebe die Langhantel weiter an, bis der Bizeps vollständig angespannt ist und sich die Stange auf Schulterhöhe befindet.","Halte die angespannte Position kurz und drücke dabei den Bizeps zusammen.","Atme ein und beginne, die Langhantel langsam zurück in die Ausgangsposition zu senken.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0072.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0072.gif', 1784612222128, 1784612222128, 0),
  ('d14ce8c9-34b4-5bcf-b66e-5c1112bfc81c', NULL, 'Barbell Pullover', 'Langhantel-Überzug', 'back', 'lats', 'barbell', 'Lie flat on a bench with your head at one end and your feet on the floor. Hold a barbell with a shoulder-width grip and extend your arms straight above your chest. Keeping your arms straight, lower the barbell behind your head in a controlled manner until you feel a stretch in your lats. Pause for a moment, then raise the barbell back to the starting position. Repeat for the desired number of repetitions.', NULL, 'chest', '["chest","triceps"]', '["Lie flat on a bench with your head at one end and your feet on the floor.","Hold a barbell with a shoulder-width grip and extend your arms straight above your chest.","Keeping your arms straight, lower the barbell behind your head in a controlled manner until you feel a stretch in your lats.","Pause for a moment, then raise the barbell back to the starting position.","Repeat for the desired number of repetitions."]', '["Lege dich flach auf eine Bank, den Kopf an einem Ende und die Füsse auf dem Boden.","Halte eine Langhantel im schulterbreiten Griff und strecke die Arme gerade über deine Brust.","Senke die Langhantel kontrolliert hinter deinen Kopf ab, die Arme bleiben dabei gestreckt, bis du eine Dehnung im Latissimus spürst.","Halte kurz inne und hebe die Langhantel dann zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0073.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0073.gif', 1784612222128, 1784612222128, 0),
  ('8bf5d654-1ba0-5c7a-8311-118bbc71b0b6', NULL, 'Barbell Pullover to Press', 'Langhantel-Überzug zum Drücken', 'back', 'lats', 'barbell', 'Lie flat on a bench with your head at one end and your feet on the ground. Hold the barbell with a pronated grip (palms facing away from you) and extend your arms straight above your chest. Keeping your arms straight, lower the barbell behind your head in an arc-like motion until you feel a stretch in your lats. Pause for a moment, then reverse the motion and press the barbell back to the starting position above your chest. Repeat for the desired number of repetitions.', NULL, 'triceps', '["triceps","chest","shoulders"]', '["Lie flat on a bench with your head at one end and your feet on the ground.","Hold the barbell with a pronated grip (palms facing away from you) and extend your arms straight above your chest.","Keeping your arms straight, lower the barbell behind your head in an arc-like motion until you feel a stretch in your lats.","Pause for a moment, then reverse the motion and press the barbell back to the starting position above your chest.","Repeat for the desired number of repetitions."]', '["Lege dich flach auf eine Bank, den Kopf an einem Ende und die Füsse auf dem Boden.","Halte die Langhantel im Pronationsgriff (Handflächen zeigen von dir weg) und strecke die Arme gerade über deine Brust.","Senke die Langhantel in einer bogenförmigen Bewegung hinter deinen Kopf ab, die Arme bleiben dabei gestreckt, bis du eine Dehnung im Latissimus spürst.","Halte kurz inne, kehre die Bewegung dann um und drücke die Langhantel zurück in die Ausgangsposition über deiner Brust.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0022.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0022.gif', 1784612222128, 1784612222128, 0),
  ('30c5480a-f7cd-59c0-b5c9-58df453ded61', NULL, 'Barbell Rack Pull', 'Langhantel-Rack-Pull', 'upper legs', 'glutes', 'barbell', 'Set up a barbell on a rack at knee height. Stand with your feet shoulder-width apart, toes pointing slightly outwards. Bend at the hips and knees to lower yourself down and grip the barbell with an overhand grip, hands shoulder-width apart. Engage your core and lift the barbell by extending your hips and knees, pulling your shoulders back and squeezing your glutes at the top. Lower the barbell back down to the starting position by bending at the hips and knees. Repeat for the desired number of repetitions.', NULL, 'hamstrings', '["hamstrings","lower back"]', '["Set up a barbell on a rack at knee height.","Stand with your feet shoulder-width apart, toes pointing slightly outwards.","Bend at the hips and knees to lower yourself down and grip the barbell with an overhand grip, hands shoulder-width apart.","Engage your core and lift the barbell by extending your hips and knees, pulling your shoulders back and squeezing your glutes at the top.","Lower the barbell back down to the starting position by bending at the hips and knees.","Repeat for the desired number of repetitions."]', '["Lege eine Langhantel auf einer Ablage in Kniehöhe ab.","Stell dich mit schulterbreiten Füssen hin, die Zehen leicht nach aussen zeigend.","Beuge Hüfte und Knie, um dich abzusenken, und greife die Langhantel im Obergriff, die Hände schulterbreit auseinander.","Spanne deine Körpermitte an und hebe die Langhantel, indem du Hüfte und Knie streckst, die Schultern zurückziehst und das Gesäss oben anspannst.","Senke die Langhantel zurück in die Ausgangsposition ab, indem du Hüfte und Knie beugst.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0074.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0074.gif', 1784612222128, 1784612222128, 0),
  ('aa6c4634-49d5-58ff-9882-615035181c03', NULL, 'Barbell Rear Delt Raise', 'Langhantel-Vorgebeugtes Seitheben (hintere Schulter)', 'shoulders', 'delts', 'barbell', 'Stand with your feet shoulder-width apart and hold a barbell with an overhand grip, palms facing down. Bend your knees slightly and hinge forward at the hips, keeping your back straight. Raise the barbell out to the sides, keeping your arms straight, until they are parallel to the ground. Pause for a moment at the top, then slowly lower the barbell back to the starting position. Repeat for the desired number of repetitions.', NULL, 'traps', '["traps","rhomboids"]', '["Stand with your feet shoulder-width apart and hold a barbell with an overhand grip, palms facing down.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Raise the barbell out to the sides, keeping your arms straight, until they are parallel to the ground.","Pause for a moment at the top, then slowly lower the barbell back to the starting position.","Repeat for the desired number of repetitions."]', '["Stehe mit schulterbreit auseinanderstehenden Füssen und halte eine Langhantel im Obergriff, Handflächen zeigen nach unten.","Beuge die Knie leicht und beuge dich mit geradem Rücken in der Hüfte nach vorne.","Hebe die Langhantel mit gestreckten Armen seitlich an, bis sie parallel zum Boden ist.","Halte oben kurz inne, senke die Langhantel dann langsam zurück in die Ausgangsposition ab.","Wiederhole die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0075.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0075.gif', 1784612222128, 1784612222128, 0),
  ('5586bc7d-5032-5670-8fc3-277bfa501ec7', NULL, 'Barbell Rear Delt Row', 'Langhantel-Vorgebeugtes Rudern (hintere Schulter)', 'shoulders', 'delts', 'barbell', 'Stand with your feet shoulder-width apart and knees slightly bent. Hold a barbell with an overhand grip, hands slightly wider than shoulder-width apart. Bend forward at the hips, keeping your back straight and chest up. Pull the barbell towards your chest, squeezing your shoulder blades together. Pause for a moment at the top, then slowly lower the barbell back to the starting position. Repeat for the desired number of repetitions.', NULL, 'trapezius', '["trapezius","rhomboids","biceps"]', '["Stand with your feet shoulder-width apart and knees slightly bent.","Hold a barbell with an overhand grip, hands slightly wider than shoulder-width apart.","Bend forward at the hips, keeping your back straight and chest up.","Pull the barbell towards your chest, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower the barbell back to the starting position.","Repeat for the desired number of repetitions."]', '["Stehe mit schulterbreit auseinanderstehenden Füssen und leicht gebeugten Knien.","Halte eine Langhantel im Obergriff, die Hände etwas breiter als schulterbreit.","Beuge dich mit geradem Rücken und aufrechter Brust in der Hüfte nach vorne.","Ziehe die Langhantel zu deiner Brust, indem du die Schulterblätter zusammenziehst.","Halte oben kurz inne, senke die Langhantel dann langsam zurück in die Ausgangsposition ab.","Wiederhole die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0076.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0076.gif', 1784612222128, 1784612222128, 0),
  ('ddaa91b0-abfc-54eb-9527-669a39e8a799', NULL, 'Barbell Rear Lunge', 'Langhantel-Ausfallschritt rückwärts', 'upper legs', 'glutes', 'barbell', 'Start by standing with your feet shoulder-width apart and a barbell resting on your upper back. Take a step backward with your right foot, landing on the ball of your foot. Bend both knees to lower your body until your left thigh is parallel to the ground. Push through your left heel to return to the starting position. Repeat with the other leg.', NULL, 'quadriceps', '["quadriceps","hamstrings","calves"]', '["Start by standing with your feet shoulder-width apart and a barbell resting on your upper back.","Take a step backward with your right foot, landing on the ball of your foot.","Bend both knees to lower your body until your left thigh is parallel to the ground.","Push through your left heel to return to the starting position.","Repeat with the other leg."]', '["Beginne im Stand mit schulterbreit auseinanderstehenden Füssen, die Langhantel liegt auf deinem oberen Rücken.","Mache mit dem rechten Fuss einen Schritt nach hinten und lande auf dem Fussballen.","Beuge beide Knie, um deinen Körper abzusenken, bis dein linker Oberschenkel parallel zum Boden ist.","Drücke dich über die linke Ferse zurück in die Ausgangsposition.","Wiederhole mit dem anderen Bein."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0078.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0078.gif', 1784612222128, 1784612222128, 0),
  ('460f72d0-4daa-5409-bc63-df161026db6b', NULL, 'Barbell Rear Lunge V. 2', 'Langhantel-Ausfallschritt rückwärts (Variante 2)', 'upper legs', 'glutes', 'barbell', 'Stand with your feet shoulder-width apart and hold a barbell across your upper back. Take a step backward with your right foot, landing on the ball of your foot. Bend both knees to lower your body until your left thigh is parallel to the ground. Push through your left heel to return to the starting position. Repeat with the other leg.', NULL, 'quadriceps', '["quadriceps","hamstrings","calves"]', '["Stand with your feet shoulder-width apart and hold a barbell across your upper back.","Take a step backward with your right foot, landing on the ball of your foot.","Bend both knees to lower your body until your left thigh is parallel to the ground.","Push through your left heel to return to the starting position.","Repeat with the other leg."]', '["Stehe mit schulterbreit auseinanderstehenden Füssen und halte eine Langhantel auf deinem oberen Rücken.","Mache mit dem rechten Fuss einen Schritt nach hinten und lande auf dem Fussballen.","Beuge beide Knie, um deinen Körper abzusenken, bis dein linker Oberschenkel parallel zum Boden ist.","Drücke dich über die linke Ferse zurück in die Ausgangsposition.","Wiederhole mit dem anderen Bein."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0077.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0077.gif', 1784612222128, 1784612222128, 0),
  ('d14e85f9-88e7-5aea-9489-3604f3b313fd', NULL, 'Barbell Reverse Wrist Curl V. 2', 'Langhantel-Reverse-Handgelenkscurl (Variante 2)', 'lower arms', 'forearms', 'barbell', 'Sit on a bench with your feet flat on the ground and your knees bent. Hold a barbell with an overhand grip, palms facing down, and your hands shoulder-width apart. Rest your forearms on your thighs, allowing your wrists to hang off the edge. Keeping your forearms stationary, exhale and curl your wrists upward as far as possible. Hold the contracted position for a brief pause, then inhale and slowly lower the barbell back to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","brachialis"]', '["Sit on a bench with your feet flat on the ground and your knees bent.","Hold a barbell with an overhand grip, palms facing down, and your hands shoulder-width apart.","Rest your forearms on your thighs, allowing your wrists to hang off the edge.","Keeping your forearms stationary, exhale and curl your wrists upward as far as possible.","Hold the contracted position for a brief pause, then inhale and slowly lower the barbell back to the starting position.","Repeat for the desired number of repetitions."]', '["Setze dich auf eine Bank, die Füsse flach auf dem Boden und die Knie gebeugt.","Halte eine Langhantel im Obergriff, Handflächen zeigen nach unten, die Hände schulterbreit auseinander.","Lege deine Unterarme auf die Oberschenkel, sodass die Handgelenke über die Kante hinausragen.","Halte die Unterarme ruhig, atme aus und rolle die Handgelenke so weit wie möglich nach oben.","Halte die angespannte Position kurz, atme dann ein und senke die Langhantel langsam zurück in die Ausgangsposition.","Wiederhole die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0079.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0079.gif', 1784612222128, 1784612222128, 0),
  ('3bac8c64-f77e-50b2-8292-3e1920b96db3', NULL, 'Barbell Reverse Close-Grip Bench Press', 'Langhantel-Bankdrücken eng im Untergriff', 'upper arms', 'triceps', 'barbell', 'Lie flat on a bench with your feet flat on the ground and your back pressed against the bench. Grasp the barbell with a reverse grip, hands shoulder-width apart. Lift the barbell off the rack and hold it directly above your chest with your arms fully extended. Slowly lower the barbell down towards your chest, keeping your elbows close to your body. Pause for a moment when the barbell is just above your chest. Push the barbell back up to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', NULL, 'chest', '["chest","shoulders"]', '["Lie flat on a bench with your feet flat on the ground and your back pressed against the bench.","Grasp the barbell with a reverse grip, hands shoulder-width apart.","Lift the barbell off the rack and hold it directly above your chest with your arms fully extended.","Slowly lower the barbell down towards your chest, keeping your elbows close to your body.","Pause for a moment when the barbell is just above your chest.","Push the barbell back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."]', '["Lege dich flach auf eine Bank, die Füsse flach auf dem Boden und der Rücken fest gegen die Bank gedrückt.","Greife die Langhantel im Reversgriff, die Hände schulterbreit auseinander.","Hebe die Langhantel aus der Ablage und halte sie mit gestreckten Armen direkt über deiner Brust.","Senke die Langhantel langsam zu deiner Brust ab und halte die Ellbogen nah am Körper.","Halte kurz inne, wenn die Langhantel knapp über deiner Brust ist.","Drücke die Langhantel mit vollständig gestreckten Armen zurück in die Ausgangsposition.","Wiederhole die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/2187.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/2187.gif', 1784612222128, 1784612222128, 0),
  ('b47bb030-15a2-593d-8d3b-4c0f1d25617a', NULL, 'Barbell Reverse Curl', 'Langhantel-Reverse-Curl', 'upper arms', 'biceps', 'barbell', 'Stand up straight with your feet shoulder-width apart and hold a barbell with an overhand grip, palms facing down. Keep your upper arms stationary and exhale as you curl the barbell upward, contracting your biceps. Continue to raise the barbell until your biceps are fully contracted and the barbell is at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale as you slowly lower the barbell back to the starting position, keeping your upper arms stationary. Repeat for the desired number of repetitions.', NULL, 'forearms', '["forearms"]', '["Stand up straight with your feet shoulder-width apart and hold a barbell with an overhand grip, palms facing down.","Keep your upper arms stationary and exhale as you curl the barbell upward, contracting your biceps.","Continue to raise the barbell until your biceps are fully contracted and the barbell is at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale as you slowly lower the barbell back to the starting position, keeping your upper arms stationary.","Repeat for the desired number of repetitions."]', '["Stehe aufrecht mit schulterbreit auseinanderstehenden Füssen und halte eine Langhantel im Obergriff, Handflächen zeigen nach unten.","Halte die Oberarme ruhig und atme aus, während du die Langhantel nach oben curlst und deinen Bizeps anspannst.","Hebe die Langhantel weiter an, bis dein Bizeps vollständig angespannt ist und sich die Langhantel auf Schulterhöhe befindet.","Halte die angespannte Position kurz und drücke deinen Bizeps zusammen.","Atme ein und senke die Langhantel langsam zurück in die Ausgangsposition ab, während die Oberarme ruhig bleiben.","Wiederhole die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0080.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0080.gif', 1784612222128, 1784612222128, 0),
  ('acf0e037-437a-5e29-9454-0b8cf9f6ab01', NULL, 'Barbell Reverse Grip Bent Over Row', 'Langhantel-Vorgebeugtes Rudern im Untergriff', 'back', 'upper back', 'barbell', 'Stand with your feet shoulder-width apart and knees slightly bent. Hold a barbell with an overhand grip, palms facing down, and hands slightly wider than shoulder-width apart. Bend forward at the hips, keeping your back straight and chest up, until your torso is almost parallel to the floor. Pull the barbell towards your lower chest, squeezing your shoulder blades together. Pause for a moment at the top, then slowly lower the barbell back to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","forearms"]', '["Stand with your feet shoulder-width apart and knees slightly bent.","Hold a barbell with an overhand grip, palms facing down, and hands slightly wider than shoulder-width apart.","Bend forward at the hips, keeping your back straight and chest up, until your torso is almost parallel to the floor.","Pull the barbell towards your lower chest, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower the barbell back to the starting position.","Repeat for the desired number of repetitions."]', '["Stehe mit schulterbreit auseinanderstehenden Füssen und leicht gebeugten Knien.","Halte eine Langhantel im Obergriff, Handflächen zeigen nach unten, die Hände etwas breiter als schulterbreit.","Beuge dich mit geradem Rücken und aufrechter Brust in der Hüfte nach vorne, bis dein Oberkörper fast parallel zum Boden ist.","Ziehe die Langhantel zu deinem unteren Brustbereich, indem du die Schulterblätter zusammenziehst.","Halte oben kurz inne, senke die Langhantel dann langsam zurück in die Ausgangsposition ab.","Wiederhole die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0118.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0118.gif', 1784612222128, 1784612222128, 0),
  ('1496f2a9-4727-53fb-a38a-78822060c200', NULL, 'Barbell Reverse Grip Decline Bench Press', 'Langhantel-Negativbankdrücken im Untergriff', 'chest', 'pectorals', 'barbell', 'Lie on a decline bench with your feet secured and your head lower than your hips. Grasp the barbell with a reverse grip, slightly wider than shoulder-width apart. Unrack the barbell and lower it slowly towards your chest, keeping your elbows tucked in. Pause for a moment at the bottom, then push the barbell back up to the starting position. Repeat for the desired number of repetitions.', NULL, 'triceps', '["triceps","shoulders"]', '["Lie on a decline bench with your feet secured and your head lower than your hips.","Grasp the barbell with a reverse grip, slightly wider than shoulder-width apart.","Unrack the barbell and lower it slowly towards your chest, keeping your elbows tucked in.","Pause for a moment at the bottom, then push the barbell back up to the starting position.","Repeat for the desired number of repetitions."]', '["Lege dich auf eine Negativbank, die Füsse fixiert und der Kopf tiefer als die Hüfte.","Greife die Langhantel im Reversgriff, etwas breiter als schulterbreit.","Hebe die Langhantel aus der Ablage und senke sie langsam zu deiner Brust ab, die Ellbogen bleiben eng am Körper.","Halte unten kurz inne, drücke die Langhantel dann zurück in die Ausgangsposition.","Wiederhole die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1256.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1256.gif', 1784612222128, 1784612222128, 0),
  ('fa384a4f-03a8-5853-a857-4910e2992802', NULL, 'Barbell Reverse Grip Incline Bench Press', 'Langhantel-Schrägbankdrücken im Untergriff', 'chest', 'pectorals', 'barbell', 'Set up an incline bench at a 45-degree angle. Lie down on the bench with your feet flat on the ground. Grasp the barbell with a reverse grip, hands slightly wider than shoulder-width apart. Unrack the barbell and lower it slowly towards your chest, keeping your elbows tucked in. Pause for a moment when the barbell touches your chest. Push the barbell back up to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', NULL, 'triceps', '["triceps","shoulders"]', '["Set up an incline bench at a 45-degree angle.","Lie down on the bench with your feet flat on the ground.","Grasp the barbell with a reverse grip, hands slightly wider than shoulder-width apart.","Unrack the barbell and lower it slowly towards your chest, keeping your elbows tucked in.","Pause for a moment when the barbell touches your chest.","Push the barbell back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."]', '["Stelle eine Schrägbank auf einen Winkel von 45° ein.","Lege dich auf die Bank, die Füsse flach auf dem Boden.","Greife die Langhantel im Reversgriff, die Hände etwas breiter als schulterbreit.","Hebe die Langhantel aus der Ablage und senke sie langsam zu deiner Brust ab, die Ellbogen bleiben eng am Körper.","Halte kurz inne, wenn die Langhantel deine Brust berührt.","Drücke die Langhantel mit vollständig gestreckten Armen zurück in die Ausgangsposition.","Wiederhole die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1257.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1257.gif', 1784612222128, 1784612222128, 0),
  ('96c7ae4e-5595-5521-908f-e38cb89f09c9', NULL, 'Barbell Reverse Grip Incline Bench Row', 'Langhantel-Rudern auf der Schrägbank im Untergriff', 'back', 'upper back', 'barbell', 'Set up an incline bench at a 45-degree angle. Sit on the bench facing the backrest with your chest against it. Grab the barbell with a reverse grip (palms facing down) and hands slightly wider than shoulder-width apart. Keep your back straight and core engaged. Pull the barbell towards your upper abdomen, squeezing your shoulder blades together. Pause for a moment at the top of the movement. Slowly lower the barbell back to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","forearms"]', '["Set up an incline bench at a 45-degree angle.","Sit on the bench facing the backrest with your chest against it.","Grab the barbell with a reverse grip (palms facing down) and hands slightly wider than shoulder-width apart.","Keep your back straight and core engaged.","Pull the barbell towards your upper abdomen, squeezing your shoulder blades together.","Pause for a moment at the top of the movement.","Slowly lower the barbell back to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle eine Schrägbank auf einen Winkel von 45° ein.","Setze dich mit der Brust gegen die Rückenlehne auf die Bank.","Greife die Langhantel im Reversgriff (Handflächen zeigen nach unten), die Hände etwas breiter als schulterbreit.","Halte den Rücken gerade und spanne deine Körpermitte an.","Ziehe die Langhantel zu deinem oberen Bauchbereich, indem du die Schulterblätter zusammenziehst.","Halte am oberen Punkt der Bewegung kurz inne.","Senke die Langhantel langsam zurück in die Ausgangsposition.","Wiederhole die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1317.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1317.gif', 1784612222128, 1784612222128, 0),
  ('6506f143-46fd-5e30-a0b0-6b1f4c1f173a', NULL, 'Barbell Reverse Grip Skullcrusher', 'Langhantel-Skullcrusher im Untergriff', 'upper arms', 'triceps', 'barbell', 'Lie flat on a bench with your feet flat on the ground and your head at the end of the bench. Hold the barbell with a reverse grip, palms facing towards your face, and your hands shoulder-width apart. Extend your arms straight up over your chest, keeping your elbows in and your wrists straight. Slowly lower the barbell towards your forehead by bending your elbows, keeping your upper arms stationary. Pause for a moment at the bottom, then extend your arms back up to the starting position. Repeat for the desired number of repetitions.', NULL, 'forearms', '["forearms"]', '["Lie flat on a bench with your feet flat on the ground and your head at the end of the bench.","Hold the barbell with a reverse grip, palms facing towards your face, and your hands shoulder-width apart.","Extend your arms straight up over your chest, keeping your elbows in and your wrists straight.","Slowly lower the barbell towards your forehead by bending your elbows, keeping your upper arms stationary.","Pause for a moment at the bottom, then extend your arms back up to the starting position.","Repeat for the desired number of repetitions."]', '["Lege dich flach auf eine Bank, die Füsse flach auf dem Boden und dein Kopf am Ende der Bank.","Halte die Langhantel im Reversgriff, Handflächen zeigen zu deinem Gesicht, die Hände schulterbreit auseinander.","Strecke deine Arme gerade über deiner Brust nach oben, die Ellbogen bleiben eng und die Handgelenke gerade.","Senke die Langhantel langsam zu deiner Stirn ab, indem du die Ellbogen beugst, die Oberarme bleiben dabei ruhig.","Halte unten kurz inne, strecke die Arme dann zurück in die Ausgangsposition.","Wiederhole die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1721.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1721.gif', 1784612222128, 1784612222128, 0),
  ('03a61d4b-6b3d-51fb-ae2f-231611abb0d5', NULL, 'Barbell Reverse Preacher Curl', 'Langhantel-Preacher Curl im Untergriff', 'upper arms', 'biceps', 'barbell', 'Sit on a preacher bench with your chest against the pad and your arms extended straight down, holding a barbell with an overhand grip. Keeping your upper arms stationary, exhale and curl the barbell upward while contracting your biceps. Continue to raise the barbell until your biceps are fully contracted and the barbell is at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly lower the barbell back to the starting position. Repeat for the desired number of repetitions.', NULL, 'forearms', '["forearms"]', '["Sit on a preacher bench with your chest against the pad and your arms extended straight down, holding a barbell with an overhand grip.","Keeping your upper arms stationary, exhale and curl the barbell upward while contracting your biceps.","Continue to raise the barbell until your biceps are fully contracted and the barbell is at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly lower the barbell back to the starting position.","Repeat for the desired number of repetitions."]', '["Setze dich an eine Scottbank, die Brust gegen die Polsterung gedrückt und die Arme gerade nach unten gestreckt, halte dabei eine Langhantel im Obergriff.","Halte die Oberarme ruhig, atme aus und curl die Langhantel nach oben, während du deinen Bizeps anspannst.","Hebe die Langhantel weiter an, bis dein Bizeps vollständig angespannt ist und sich die Langhantel auf Schulterhöhe befindet.","Halte die angespannte Position kurz und drücke deinen Bizeps zusammen.","Atme ein und senke die Langhantel langsam zurück in die Ausgangsposition.","Wiederhole die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0081.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0081.gif', 1784612222128, 1784612222128, 0),
  ('11724e5f-ff4c-514e-b39b-493ada9ecc4f', NULL, 'Barbell Reverse Wrist Curl', 'Langhantel-Reverse-Handgelenkscurl', 'lower arms', 'forearms', 'barbell', 'Sit on a bench with your feet flat on the ground and hold a barbell with an overhand grip, palms facing down. Rest your forearms on your thighs, allowing your wrists to hang off the edge. Slowly curl your wrists upward, bringing the barbell towards your body. Pause for a moment at the top, then slowly lower the barbell back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","brachialis"]', '["Sit on a bench with your feet flat on the ground and hold a barbell with an overhand grip, palms facing down.","Rest your forearms on your thighs, allowing your wrists to hang off the edge.","Slowly curl your wrists upward, bringing the barbell towards your body.","Pause for a moment at the top, then slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."]', '["Setze dich auf eine Bank, die Füsse flach auf dem Boden, und halte eine Langhantel im Obergriff, Handflächen zeigen nach unten.","Lege deine Unterarme auf die Oberschenkel, sodass die Handgelenke über die Kante hinausragen.","Rolle deine Handgelenke langsam nach oben und ziehe die Langhantel zu deinem Körper.","Halte oben kurz inne, senke die Langhantel dann langsam zurück in die Ausgangsposition ab.","Wiederhole die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0082.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0082.gif', 1784612222128, 1784612222128, 0),
  ('976bfefe-8758-5cac-9430-cda8429eed1f', NULL, 'Barbell Rollout', 'Langhantel-Rollout', 'waist', 'abs', 'barbell', 'Kneel on the floor and hold a barbell with both hands, shoulder-width apart. Roll the barbell forward, extending your arms and keeping your core engaged. Continue rolling forward until your body is fully extended and your arms are overhead. Pause for a moment, then slowly roll the barbell back towards your knees, maintaining control. Repeat for the desired number of repetitions.', NULL, 'lower back', '["lower back"]', '["Kneel on the floor and hold a barbell with both hands, shoulder-width apart.","Roll the barbell forward, extending your arms and keeping your core engaged.","Continue rolling forward until your body is fully extended and your arms are overhead.","Pause for a moment, then slowly roll the barbell back towards your knees, maintaining control.","Repeat for the desired number of repetitions."]', '["Knie dich auf den Boden und halte eine Langhantel mit beiden Händen schulterbreit auseinander.","Rolle die Langhantel nach vorne, strecke dabei die Arme und spanne deine Körpermitte an.","Rolle weiter nach vorne, bis dein Körper vollständig gestreckt ist und deine Arme über dem Kopf sind.","Halte kurz inne und rolle die Langhantel dann kontrolliert zurück zu deinen Knien.","Wiederhole die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0084.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0084.gif', 1784612222128, 1784612222128, 0),
  ('6034b651-7f03-5750-8ea7-244f4628689f', NULL, 'Barbell Rollout from Bench', 'Langhantel-Rollout von der Bank aus', 'waist', 'abs', 'barbell', 'Start by kneeling on the floor with a barbell placed on a bench in front of you. Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart. Keeping your core engaged and your back straight, slowly roll the barbell forward, extending your arms in front of you. Continue rolling the barbell forward until your body is fully extended and your arms are overhead. Pause for a moment at the fully extended position, then slowly roll the barbell back towards your body, returning to the starting position. Repeat for the desired number of repetitions.', NULL, 'shoulders', '["shoulders","triceps"]', '["Start by kneeling on the floor with a barbell placed on a bench in front of you.","Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart.","Keeping your core engaged and your back straight, slowly roll the barbell forward, extending your arms in front of you.","Continue rolling the barbell forward until your body is fully extended and your arms are overhead.","Pause for a moment at the fully extended position, then slowly roll the barbell back towards your body, returning to the starting position.","Repeat for the desired number of repetitions."]', '["Beginne kniend auf dem Boden, wobei eine Langhantel auf einer Bank vor dir liegt.","Greife die Langhantel im Obergriff, etwas breiter als schulterbreit.","Spanne deine Körpermitte an, halte den Rücken gerade und rolle die Langhantel langsam nach vorne, wobei du die Arme vor dir streckst.","Rolle die Langhantel weiter nach vorne, bis dein Körper vollständig gestreckt ist und deine Arme über dem Kopf sind.","Halte in der vollständig gestreckten Position kurz inne und rolle die Langhantel dann langsam zurück zu deinem Körper in die Ausgangsposition.","Wiederhole die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0083.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0083.gif', 1784612222128, 1784612222128, 0),
  ('f7e646dc-93e7-5251-8fc5-901959e91126', NULL, 'Barbell Romanian Deadlift', 'Langhantel-Rumänisches Kreuzheben', 'upper legs', 'glutes', 'barbell', 'Stand with your feet shoulder-width apart and your toes pointing forward. Hold the barbell with an overhand grip, hands slightly wider than shoulder-width apart. Bend at the hips, keeping your back straight and your knees slightly bent. Lower the barbell towards the ground, keeping it close to your body. Feel the stretch in your hamstrings as you lower the barbell. Once you feel a stretch in your hamstrings, push your hips forward and stand up straight. Squeeze your glutes at the top of the movement. Lower the barbell back down to the starting position and repeat for the desired number of repetitions.', NULL, 'hamstrings', '["hamstrings","lower back"]', '["Stand with your feet shoulder-width apart and your toes pointing forward.","Hold the barbell with an overhand grip, hands slightly wider than shoulder-width apart.","Bend at the hips, keeping your back straight and your knees slightly bent.","Lower the barbell towards the ground, keeping it close to your body.","Feel the stretch in your hamstrings as you lower the barbell.","Once you feel a stretch in your hamstrings, push your hips forward and stand up straight.","Squeeze your glutes at the top of the movement.","Lower the barbell back down to the starting position and repeat for the desired number of repetitions."]', '["Stehe mit schulterbreit auseinanderstehenden Füssen, die Zehen zeigen nach vorne.","Halte die Langhantel im Obergriff, die Hände etwas breiter als schulterbreit.","Beuge dich mit geradem Rücken und leicht gebeugten Knien in der Hüfte.","Senke die Langhantel Richtung Boden ab und halte sie dabei nah am Körper.","Spüre beim Absenken die Dehnung in deinen Beinbeugern.","Sobald du eine Dehnung in den Beinbeugern spürst, schiebe deine Hüfte nach vorne und richte dich auf.","Spanne am oberen Punkt der Bewegung dein Gesäss an.","Senke die Langhantel zurück in die Ausgangsposition ab und wiederhole die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0085.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0085.gif', 1784612222128, 1784612222128, 0),
  ('a3e7e233-9ac0-518b-bcc1-ec9a49240b5a', NULL, 'Barbell Seated Behind Head Military Press', 'Langhantel-Nackendrücken im Sitzen', 'shoulders', 'delts', 'barbell', 'Sit on a bench with your back straight and feet flat on the ground. Hold the barbell with an overhand grip, slightly wider than shoulder-width apart. Lift the barbell off the rack and bring it down to shoulder level, behind your head. Press the barbell upward until your arms are fully extended. Lower the barbell back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'triceps', '["triceps","upper back"]', '["Sit on a bench with your back straight and feet flat on the ground.","Hold the barbell with an overhand grip, slightly wider than shoulder-width apart.","Lift the barbell off the rack and bring it down to shoulder level, behind your head.","Press the barbell upward until your arms are fully extended.","Lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."]', '["Setze dich mit geradem Rücken und flach aufgestellten Füssen auf eine Bank.","Halte die Langhantel im Obergriff, etwas breiter als schulterbreit.","Hebe die Langhantel aus der Ablage und senke sie hinter deinem Kopf auf Schulterhöhe ab.","Drücke die Langhantel nach oben, bis deine Arme vollständig gestreckt sind.","Senke die Langhantel zurück in die Ausgangsposition ab.","Wiederhole die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0086.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0086.gif', 1784612222128, 1784612222128, 0),
  ('bbb97f20-144c-513d-addc-b5e167c2ff0c', NULL, 'Barbell Seated Bradford Rocky Press', 'Langhantel-Bradford-Press wippend im Sitzen', 'shoulders', 'delts', 'barbell', 'Sit on a bench with your back straight and feet flat on the ground. Hold the barbell with an overhand grip, slightly wider than shoulder-width apart. Lift the barbell to shoulder height, keeping your elbows slightly bent and pointing forward. Press the barbell overhead, fully extending your arms. Lower the barbell back to shoulder height and repeat for the desired number of repetitions.', NULL, 'triceps', '["triceps","upper back"]', '["Sit on a bench with your back straight and feet flat on the ground.","Hold the barbell with an overhand grip, slightly wider than shoulder-width apart.","Lift the barbell to shoulder height, keeping your elbows slightly bent and pointing forward.","Press the barbell overhead, fully extending your arms.","Lower the barbell back to shoulder height and repeat for the desired number of repetitions."]', '["Setze dich mit geradem Rücken und flach aufgestellten Füssen auf eine Bank.","Halte die Langhantel im Obergriff, etwas breiter als schulterbreit.","Hebe die Langhantel auf Schulterhöhe, die Ellbogen bleiben leicht gebeugt und zeigen nach vorne.","Drücke die Langhantel mit vollständig gestreckten Armen über den Kopf.","Senke die Langhantel zurück auf Schulterhöhe ab und wiederhole die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0087.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0087.gif', 1784612222128, 1784612222128, 0),
  ('c1da7199-dc9a-50b8-8ac9-0705c4568e7c', NULL, 'Barbell Seated Calf Raise', 'Langhantel-Wadenheben im Sitzen', 'lower legs', 'calves', 'barbell', 'Sit on a bench with your feet flat on the floor and a barbell resting on your thighs. Place the balls of your feet on a raised platform, such as a block or step. Position the barbell across your thighs and hold it securely with your hands. Keeping your back straight and your core engaged, lift your heels off the ground by extending your ankles. Pause for a moment at the top, then slowly lower your heels back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'hamstrings', '["hamstrings","quadriceps"]', '["Sit on a bench with your feet flat on the floor and a barbell resting on your thighs.","Place the balls of your feet on a raised platform, such as a block or step.","Position the barbell across your thighs and hold it securely with your hands.","Keeping your back straight and your core engaged, lift your heels off the ground by extending your ankles.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."]', '["Setze dich auf eine Bank, die Füsse flach auf dem Boden, eine Langhantel liegt auf deinen Oberschenkeln.","Stelle die Fussballen auf eine erhöhte Fläche, zum Beispiel einen Block oder eine Stufe.","Positioniere die Langhantel quer über deinen Oberschenkeln und halte sie mit den Händen sicher fest.","Halte den Rücken gerade und spanne deine Körpermitte an, hebe die Fersen vom Boden ab, indem du die Fussgelenke streckst.","Halte oben kurz inne, senke die Fersen dann langsam zurück in die Ausgangsposition ab.","Wiederhole die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0088.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0088.gif', 1784612222128, 1784612222128, 0),
  ('be38eeae-4a5a-5b01-8827-639daee9b4b1', NULL, 'Barbell Seated Calf Raise', 'Langhantel-Wadenheben im Sitzen', 'lower legs', 'calves', 'barbell', 'Sit on a bench with your feet flat on the floor and a barbell resting on your thighs. Place the balls of your feet on a raised platform, such as a block or step. Lower your heels as far as possible, feeling a stretch in your calves. Raise your heels as high as possible, contracting your calves. Repeat for the desired number of repetitions.', NULL, 'hamstrings', '["hamstrings"]', '["Sit on a bench with your feet flat on the floor and a barbell resting on your thighs.","Place the balls of your feet on a raised platform, such as a block or step.","Lower your heels as far as possible, feeling a stretch in your calves.","Raise your heels as high as possible, contracting your calves.","Repeat for the desired number of repetitions."]', '["Setze dich auf eine Bank, die Füsse flach auf dem Boden, eine Langhantel liegt auf deinen Oberschenkeln.","Stelle die Fussballen auf eine erhöhte Fläche, zum Beispiel einen Block oder eine Stufe.","Senke deine Fersen so weit wie möglich ab und spüre die Dehnung in den Waden.","Hebe deine Fersen so hoch wie möglich an und spanne die Waden an.","Wiederhole die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1371.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1371.gif', 1784612222128, 1784612222128, 0),
  ('1277cd90-7166-5aa1-99de-63946bb624b2', NULL, 'Barbell Seated Close Grip Behind Neck Triceps Extension', 'Langhantel-Trizepsstrecken hinter dem Nacken eng im Sitzen', 'upper arms', 'triceps', 'barbell', 'Sit on a bench with your back straight and feet flat on the ground. Hold the barbell with a close grip behind your neck, palms facing forward. Keep your elbows close to your head and slowly lower the barbell towards the back of your head. Pause for a moment, then extend your arms back up to the starting position. Repeat for the desired number of repetitions.', NULL, 'shoulders', '["shoulders"]', '["Sit on a bench with your back straight and feet flat on the ground.","Hold the barbell with a close grip behind your neck, palms facing forward.","Keep your elbows close to your head and slowly lower the barbell towards the back of your head.","Pause for a moment, then extend your arms back up to the starting position.","Repeat for the desired number of repetitions."]', '["Setze dich mit geradem Rücken und flach aufgestellten Füssen auf eine Bank.","Halte die Langhantel im engen Griff hinter deinem Nacken, Handflächen zeigen nach vorne.","Halte die Ellbogen nah am Kopf und senke die Langhantel langsam Richtung Hinterkopf ab.","Halte kurz inne und strecke die Arme dann zurück in die Ausgangsposition.","Wiederhole die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1718.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1718.gif', 1784612222128, 1784612222128, 0),
  ('99689841-9371-50b4-8ddf-14504315e0f5', NULL, 'Barbell Seated Close-Grip Concentration Curl', 'Langhantel-Konzentrationscurl eng im Sitzen', 'upper arms', 'biceps', 'barbell', 'Sit on a bench with your feet flat on the floor and hold a barbell with an underhand grip, hands shoulder-width apart. Rest your upper arms against your inner thighs, just above your knees, and let the barbell hang down in front of you. Keeping your upper arms stationary, exhale and curl the barbell up towards your shoulders, contracting your biceps. Hold the contracted position for a brief pause, then inhale and slowly lower the barbell back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'forearms', '["forearms"]', '["Sit on a bench with your feet flat on the floor and hold a barbell with an underhand grip, hands shoulder-width apart.","Rest your upper arms against your inner thighs, just above your knees, and let the barbell hang down in front of you.","Keeping your upper arms stationary, exhale and curl the barbell up towards your shoulders, contracting your biceps.","Hold the contracted position for a brief pause, then inhale and slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."]', '["Setze dich auf eine Bank, die Füsse flach auf dem Boden, und halte eine Langhantel im Untergriff, die Hände schulterbreit auseinander.","Lege deine Oberarme an die Innenseite der Oberschenkel, knapp über den Knien, und lass die Langhantel vor dir hängen.","Halte die Oberarme ruhig, atme aus und curl die Langhantel zu deinen Schultern hoch, während du deinen Bizeps anspannst.","Halte die angespannte Position kurz, atme dann ein und senke die Langhantel langsam zurück in die Ausgangsposition.","Wiederhole die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0089.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0089.gif', 1784612222128, 1784612222128, 0),
  ('6afea5cd-8b74-50e3-bd77-3a9c28d72f71', NULL, 'Barbell Seated Good Morning', 'Langhantel-Good Morning im Sitzen', 'upper legs', 'glutes', 'barbell', 'Sit on a bench with your feet flat on the ground and a barbell resting on your upper back. Keep your back straight and your chest up. Slowly hinge forward at the hips, lowering your torso towards the ground. Pause for a moment at the bottom, then push through your heels to return to the starting position. Repeat for the desired number of repetitions.', NULL, 'hamstrings', '["hamstrings","lower back"]', '["Sit on a bench with your feet flat on the ground and a barbell resting on your upper back.","Keep your back straight and your chest up.","Slowly hinge forward at the hips, lowering your torso towards the ground.","Pause for a moment at the bottom, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."]', '["Setze dich auf eine Bank, die Füsse flach auf dem Boden, eine Langhantel liegt auf deinem oberen Rücken.","Halte den Rücken gerade und die Brust aufrecht.","Beuge dich langsam in der Hüfte nach vorne und senke deinen Oberkörper Richtung Boden.","Halte unten kurz inne und drücke dich dann über die Fersen zurück in die Ausgangsposition.","Wiederhole die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0090.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0090.gif', 1784612222128, 1784612222128, 0),
  ('16d68739-9f92-5af9-968a-cc3b0a5843eb', NULL, 'Barbell Seated Overhead Press', 'Langhantel-Überkopfdrücken im Sitzen', 'shoulders', 'delts', 'barbell', 'Sit on a bench with your back straight and feet flat on the ground. Hold the barbell with an overhand grip, slightly wider than shoulder-width apart. Lift the barbell off the rack and bring it to shoulder level, with your elbows bent and palms facing forward. Press the barbell overhead by extending your arms fully. Pause for a moment at the top, then slowly lower the barbell back to shoulder level. Repeat for the desired number of repetitions.', NULL, 'triceps', '["triceps","upper back"]', '["Sit on a bench with your back straight and feet flat on the ground.","Hold the barbell with an overhand grip, slightly wider than shoulder-width apart.","Lift the barbell off the rack and bring it to shoulder level, with your elbows bent and palms facing forward.","Press the barbell overhead by extending your arms fully.","Pause for a moment at the top, then slowly lower the barbell back to shoulder level.","Repeat for the desired number of repetitions."]', '["Setze dich mit geradem Rücken und flach aufgestellten Füssen auf eine Bank.","Halte die Langhantel im Obergriff, etwas breiter als schulterbreit.","Hebe die Langhantel aus der Ablage und bringe sie auf Schulterhöhe, die Ellbogen gebeugt und die Handflächen zeigen nach vorne.","Drücke die Langhantel über den Kopf, indem du die Arme vollständig streckst.","Halte oben kurz inne, senke die Langhantel dann langsam zurück auf Schulterhöhe ab.","Wiederhole die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0091.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0091.gif', 1784612222128, 1784612222128, 0),
  ('af2a24ef-5af3-5178-9efa-c64e2f9b20fb', NULL, 'Barbell Seated Overhead Triceps Extension', 'Langhantel-Trizepsstrecken über Kopf im Sitzen', 'upper arms', 'triceps', 'barbell', 'Sit on a bench with your back straight and feet flat on the ground. Hold a barbell with an overhand grip, hands shoulder-width apart, and raise it overhead. Lower the barbell behind your head by bending your elbows, keeping your upper arms close to your head. Pause for a moment, then extend your arms to raise the barbell back to the starting position. Repeat for the desired number of repetitions.', NULL, 'shoulders', '["shoulders"]', '["Sit on a bench with your back straight and feet flat on the ground.","Hold a barbell with an overhand grip, hands shoulder-width apart, and raise it overhead.","Lower the barbell behind your head by bending your elbows, keeping your upper arms close to your head.","Pause for a moment, then extend your arms to raise the barbell back to the starting position.","Repeat for the desired number of repetitions."]', '["Setze dich mit geradem Rücken und flach aufgestellten Füssen auf eine Bank.","Halte eine Langhantel im Obergriff, die Hände schulterbreit auseinander, und hebe sie über den Kopf.","Senke die Langhantel hinter deinen Kopf ab, indem du die Ellbogen beugst, die Oberarme bleiben dabei nah am Kopf.","Halte kurz inne und strecke die Arme dann, um die Langhantel zurück in die Ausgangsposition zu heben.","Wiederhole die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0092.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0092.gif', 1784612222128, 1784612222128, 0),
  ('272ef4a8-8ca8-5b9a-b55e-16a91e6873cc', NULL, 'Barbell Seated Twist', 'Langhantel-Rumpfdrehen im Sitzen', 'waist', 'abs', 'barbell', 'Sit on a flat bench with your feet flat on the ground and your knees bent. Hold a barbell with both hands in front of your chest, keeping your elbows slightly bent. Engage your core and slowly twist your torso to one side, keeping your back straight. Pause for a moment at the end of the twist, then slowly rotate back to the starting position. Repeat the twist to the other side. Continue alternating sides for the desired number of repetitions.', NULL, 'obliques', '["obliques","lower back"]', '["Sit on a flat bench with your feet flat on the ground and your knees bent.","Hold a barbell with both hands in front of your chest, keeping your elbows slightly bent.","Engage your core and slowly twist your torso to one side, keeping your back straight.","Pause for a moment at the end of the twist, then slowly rotate back to the starting position.","Repeat the twist to the other side.","Continue alternating sides for the desired number of repetitions."]', '["Setze dich auf eine flache Bank, die Füsse flach auf dem Boden und die Knie gebeugt.","Halte eine Langhantel mit beiden Händen vor deiner Brust, die Ellbogen leicht gebeugt.","Spanne deine Körpermitte an und drehe deinen Oberkörper langsam mit geradem Rücken zu einer Seite.","Halte am Ende der Drehung kurz inne und drehe dich dann langsam zurück in die Ausgangsposition.","Wiederhole die Drehung zur anderen Seite.","Wechsle die Seiten fortlaufend für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0094.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0094.gif', 1784612222128, 1784612222128, 0),
  ('1d9208fa-63c2-5277-810f-32b86c90f613', NULL, 'Barbell Shrug', 'Langhantel-Schulterheben', 'back', 'traps', 'barbell', 'Stand with your feet shoulder-width apart and hold a barbell in front of you with an overhand grip. Keep your arms straight and your back straight throughout the exercise. Lift your shoulders up towards your ears as high as possible, squeezing your traps at the top. Hold for a moment, then slowly lower your shoulders back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'shoulders', '["shoulders"]', '["Stand with your feet shoulder-width apart and hold a barbell in front of you with an overhand grip.","Keep your arms straight and your back straight throughout the exercise.","Lift your shoulders up towards your ears as high as possible, squeezing your traps at the top.","Hold for a moment, then slowly lower your shoulders back down to the starting position.","Repeat for the desired number of repetitions."]', '["Stehe mit schulterbreit auseinanderstehenden Füssen und halte eine Langhantel im Obergriff vor dir.","Halte die Arme und den Rücken während der gesamten Übung gerade.","Ziehe deine Schultern so hoch wie möglich zu den Ohren und spanne oben deinen Trapezmuskel an.","Halte kurz inne und senke die Schultern dann langsam zurück in die Ausgangsposition ab.","Wiederhole die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0095.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0095.gif', 1784612222128, 1784612222128, 0),
  ('529ab7ea-8e44-5927-aa80-a2f98f691ed3', NULL, 'Barbell Side Bend V. 2', 'Langhantel-Seitbeuge (Variante 2)', 'waist', 'abs', 'barbell', 'Stand with your feet shoulder-width apart and hold a barbell with both hands, palms facing down. Keep your back straight and core engaged throughout the exercise. Slowly bend your torso to the right side, lowering the barbell towards your right knee. Pause for a moment, then return to the starting position. Repeat the movement on the left side. Continue alternating sides for the desired number of repetitions.', NULL, 'obliques', '["obliques","lower back"]', '["Stand with your feet shoulder-width apart and hold a barbell with both hands, palms facing down.","Keep your back straight and core engaged throughout the exercise.","Slowly bend your torso to the right side, lowering the barbell towards your right knee.","Pause for a moment, then return to the starting position.","Repeat the movement on the left side.","Continue alternating sides for the desired number of repetitions."]', '["Stehe mit schulterbreit auseinanderstehenden Füssen und halte eine Langhantel mit beiden Händen, Handflächen zeigen nach unten.","Halte den Rücken gerade und die Körpermitte während der gesamten Übung angespannt.","Beuge deinen Oberkörper langsam zur rechten Seite und senke die Langhantel Richtung rechtes Knie ab.","Halte kurz inne und kehre dann zurück in die Ausgangsposition.","Wiederhole die Bewegung zur linken Seite.","Wechsle die Seiten fortlaufend für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0096.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0096.gif', 1784612222128, 1784612222128, 0),
  ('34d8296b-8a8d-5d9f-9a5f-3bdf3f1be709', NULL, 'Barbell Side Split Squat', 'Langhantel-Split Squat seitlich', 'upper legs', 'quads', 'barbell', 'Stand with your feet wider than shoulder-width apart, toes pointing slightly outward. Hold a barbell across your upper back, resting it on your traps. Engage your core and keep your chest up as you lower your body down into a squat position, bending at the knees and hips. As you lower, push your knees out to the sides and keep your weight on your heels. Lower until your thighs are parallel to the ground, then push through your heels to return to the starting position. Repeat for the desired number of repetitions.', NULL, 'glutes', '["glutes","hamstrings","calves"]', '["Stand with your feet wider than shoulder-width apart, toes pointing slightly outward.","Hold a barbell across your upper back, resting it on your traps.","Engage your core and keep your chest up as you lower your body down into a squat position, bending at the knees and hips.","As you lower, push your knees out to the sides and keep your weight on your heels.","Lower until your thighs are parallel to the ground, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."]', '["Stehe mit den Füssen breiter als schulterbreit auseinander, die Zehen zeigen leicht nach aussen.","Halte eine Langhantel quer über deinem oberen Rücken, sie liegt auf deinem Trapezmuskel.","Spanne deine Körpermitte an und halte die Brust aufrecht, während du deinen Körper in die Hocke absenkst, indem du Knie und Hüfte beugst.","Drücke beim Absenken deine Knie nach aussen und halte dein Gewicht auf den Fersen.","Senke dich ab, bis deine Oberschenkel parallel zum Boden sind, und drücke dich dann über die Fersen zurück in die Ausgangsposition.","Wiederhole die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0098.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0098.gif', 1784612222128, 1784612222128, 0),
  ('53a38bb1-54f0-5fb5-871c-96087872a703', NULL, 'Barbell Side Split Squat V. 2', 'Langhantel-Split Squat seitlich (Variante 2)', 'upper legs', 'quads', 'barbell', 'Stand with your feet wider than shoulder-width apart, toes pointing slightly outwards. Hold a barbell across your upper back, resting it on your shoulders. Take a big step to the side with your right foot, keeping your left foot planted. Bend your right knee and lower your body down into a squat position, keeping your chest up and your back straight. Push through your right heel to return to the starting position. Repeat on the other side, stepping out with your left foot. Continue alternating sides for the desired number of repetitions.', NULL, 'glutes', '["glutes","hamstrings","calves"]', '["Stand with your feet wider than shoulder-width apart, toes pointing slightly outwards.","Hold a barbell across your upper back, resting it on your shoulders.","Take a big step to the side with your right foot, keeping your left foot planted.","Bend your right knee and lower your body down into a squat position, keeping your chest up and your back straight.","Push through your right heel to return to the starting position.","Repeat on the other side, stepping out with your left foot.","Continue alternating sides for the desired number of repetitions."]', '["Stehe mit den Füssen breiter als schulterbreit auseinander, die Zehen zeigen leicht nach aussen.","Halte eine Langhantel quer über deinem oberen Rücken, sie liegt auf deinen Schultern.","Mache mit dem rechten Fuss einen grossen Schritt zur Seite, der linke Fuss bleibt fest am Boden.","Beuge dein rechtes Knie und senke deinen Körper in die Hocke ab, halte dabei die Brust aufrecht und den Rücken gerade.","Drücke dich über die rechte Ferse zurück in die Ausgangsposition.","Wiederhole auf der anderen Seite, indem du mit dem linken Fuss zur Seite trittst.","Wechsle die Seiten fortlaufend für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0097.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0097.gif', 1784612222128, 1784612222128, 0),
  ('ce1e35e1-c56f-5027-81ab-2e1c595d05dd', NULL, 'Barbell Single Leg Deadlift', 'Langhantel-Kreuzheben einbeinig', 'upper legs', 'glutes', 'barbell', 'Stand with your feet hip-width apart, holding a barbell in front of your thighs with an overhand grip. Shift your weight onto your left foot and lift your right foot slightly off the ground. Hinge forward at the hips, keeping your back straight and your right leg extended behind you for balance. Lower the barbell towards the ground, keeping it close to your body and your left leg slightly bent. Pause for a moment at the bottom, then engage your glutes and hamstrings to lift your torso back up to the starting position. Repeat for the desired number of repetitions, then switch sides.', NULL, 'hamstrings', '["hamstrings","lower back"]', '["Stand with your feet hip-width apart, holding a barbell in front of your thighs with an overhand grip.","Shift your weight onto your left foot and lift your right foot slightly off the ground.","Hinge forward at the hips, keeping your back straight and your right leg extended behind you for balance.","Lower the barbell towards the ground, keeping it close to your body and your left leg slightly bent.","Pause for a moment at the bottom, then engage your glutes and hamstrings to lift your torso back up to the starting position.","Repeat for the desired number of repetitions, then switch sides."]', '["Stehe mit hüftbreit auseinanderstehenden Füssen und halte eine Langhantel im Obergriff vor deinen Oberschenkeln.","Verlagere dein Gewicht auf den linken Fuss und hebe den rechten Fuss leicht vom Boden ab.","Beuge dich mit geradem Rücken in der Hüfte nach vorne und strecke dein rechtes Bein zur Balance nach hinten aus.","Senke die Langhantel Richtung Boden ab, halte sie nah am Körper und das linke Bein leicht gebeugt.","Halte unten kurz inne und spanne dann Gesäss und Beinbeuger an, um deinen Oberkörper zurück in die Ausgangsposition zu heben.","Wiederhole die gewünschte Anzahl Wiederholungen und wechsle dann die Seite."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1756.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1756.gif', 1784612222128, 1784612222128, 0),
  ('55576247-3f34-58ec-81c2-5e772a6b6317', NULL, 'Barbell Single Leg Split Squat', 'Langhantel-Split Squat einbeinig', 'upper legs', 'quads', 'barbell', 'Stand with your feet shoulder-width apart, holding a barbell across your upper back. Take a large step forward with one leg, keeping your torso upright. Lower your body by bending your front knee and hip, while keeping your back leg straight. Continue lowering until your front thigh is parallel to the ground. Pause for a moment, then push through your front heel to return to the starting position. Repeat for the desired number of repetitions, then switch legs.', NULL, 'glutes', '["glutes","hamstrings","calves"]', '["Stand with your feet shoulder-width apart, holding a barbell across your upper back.","Take a large step forward with one leg, keeping your torso upright.","Lower your body by bending your front knee and hip, while keeping your back leg straight.","Continue lowering until your front thigh is parallel to the ground.","Pause for a moment, then push through your front heel to return to the starting position.","Repeat for the desired number of repetitions, then switch legs."]', '["Stehe mit schulterbreit auseinanderstehenden Füssen und halte eine Langhantel quer über deinem oberen Rücken.","Mache mit einem Bein einen grossen Schritt nach vorne und halte den Oberkörper aufrecht.","Senke deinen Körper ab, indem du das vordere Knie und die Hüfte beugst, während das hintere Bein gestreckt bleibt.","Senke dich weiter ab, bis dein vorderer Oberschenkel parallel zum Boden ist.","Halte kurz inne und drücke dich dann über die vordere Ferse zurück in die Ausgangsposition.","Wiederhole die gewünschte Anzahl Wiederholungen und wechsle dann das Bein."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0099.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0099.gif', 1784612222128, 1784612222128, 0),
  ('2976f3e1-7b88-5758-877a-1bbaf8d1af4f', NULL, 'Barbell Seated Alternate Leg Raise', 'Langhantel-Wechselseitiges Beinheben im Sitzen', 'waist', 'abs', 'barbell', 'Sit on a bench with your back straight and hold a barbell across your thighs. Keeping your legs straight, lift one leg up as high as possible while keeping the other leg on the ground. Lower the raised leg back down and repeat with the other leg. Continue alternating legs for the desired number of repetitions.', NULL, 'hip flexors', '["hip flexors"]', '["Sit on a bench with your back straight and hold a barbell across your thighs.","Keeping your legs straight, lift one leg up as high as possible while keeping the other leg on the ground.","Lower the raised leg back down and repeat with the other leg.","Continue alternating legs for the desired number of repetitions."]', '["Setze dich mit geradem Rücken auf eine Bank und halte eine Langhantel quer über deinen Oberschenkeln.","Hebe ein Bein mit gestrecktem Knie so hoch wie möglich an, während das andere Bein am Boden bleibt.","Senke das angehobene Bein wieder ab und wiederhole mit dem anderen Bein.","Wechsle die Beine fortlaufend für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/2799.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/2799.gif', 1784612222128, 1784612222128, 0);

INSERT OR REPLACE INTO exercises (id, user_id, name, name_de, category, primary_muscle, equipment, instructions_en, instructions_de, muscle_group, secondary_muscles, instruction_steps_en, instruction_steps_de, thumbnail_url, gif_url, created_at, updated_at, deleted) VALUES
  ('0ca89eec-c032-56ee-9ff5-1b77e3dd67e8', NULL, 'Barbell Seated Alternate Leg Raise (Female)', 'Langhantel-Wechselseitiges Beinheben im Sitzen (weiblich)', 'waist', 'abs', 'barbell', 'Sit on a bench with your back straight and hold a barbell across your thighs. Place your hands on the sides of the bench for support. Keeping your legs straight, lift one leg up as high as possible while keeping it parallel to the ground. Lower the leg back down and repeat with the other leg. Continue alternating legs for the desired number of repetitions.', NULL, 'hip flexors', '["hip flexors","quadriceps"]', '["Sit on a bench with your back straight and hold a barbell across your thighs.","Place your hands on the sides of the bench for support.","Keeping your legs straight, lift one leg up as high as possible while keeping it parallel to the ground.","Lower the leg back down and repeat with the other leg.","Continue alternating legs for the desired number of repetitions."]', '["Setze dich mit geradem Rücken auf eine Bank und halte eine Langhantel quer über deinen Oberschenkeln.","Stütze dich mit den Händen seitlich an der Bank ab.","Hebe ein Bein mit gestrecktem Knie so hoch an, dass es parallel zum Boden ist.","Senke das Bein wieder ab und wiederhole mit dem anderen Bein.","Wechsle die Beine fortlaufend für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/2800.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/2800.gif', 1784612222128, 1784612222128, 0),
  ('1827d562-fec3-5f9c-a302-bc983055f5c3', NULL, 'Barbell Skier', 'Langhantel-Skibewegung', 'shoulders', 'delts', 'barbell', 'Stand with your feet shoulder-width apart and hold a barbell in front of your thighs with an overhand grip. Bend your knees slightly and hinge forward at the hips, keeping your back straight and chest up. Simultaneously lift the barbell up towards your shoulders while jumping slightly off the ground. As you reach the top of the movement, quickly reverse the motion and lower the barbell back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'triceps', '["triceps","core"]', '["Stand with your feet shoulder-width apart and hold a barbell in front of your thighs with an overhand grip.","Bend your knees slightly and hinge forward at the hips, keeping your back straight and chest up.","Simultaneously lift the barbell up towards your shoulders while jumping slightly off the ground.","As you reach the top of the movement, quickly reverse the motion and lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."]', '["Stehe mit schulterbreit auseinanderstehenden Füssen und halte eine Langhantel im Obergriff vor deinen Oberschenkeln.","Beuge die Knie leicht und beuge dich mit geradem Rücken und aufrechter Brust in der Hüfte nach vorne.","Hebe die Langhantel gleichzeitig zu deinen Schultern hoch, während du leicht vom Boden abspringst.","Kehre die Bewegung am oberen Punkt schnell um und senke die Langhantel zurück in die Ausgangsposition ab.","Wiederhole die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0100.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0100.gif', 1784612222128, 1784612222128, 0),
  ('f7971eb3-a30e-5559-b5db-0cdcc1e70c5e', NULL, 'Barbell Speed Squat', 'Langhantel-Speed-Kniebeuge', 'upper legs', 'glutes', 'barbell', 'Stand with your feet shoulder-width apart, toes slightly turned out. Hold the barbell across your upper back, resting it on your traps or rear delts. Engage your core and keep your chest up as you lower your hips back and down, as if sitting into a chair. Lower until your thighs are parallel to the ground, or as low as you can comfortably go. Drive through your heels to stand back up, squeezing your glutes at the top. Repeat for the desired number of repetitions.', NULL, 'quadriceps', '["quadriceps","hamstrings","calves"]', '["Stand with your feet shoulder-width apart, toes slightly turned out.","Hold the barbell across your upper back, resting it on your traps or rear delts.","Engage your core and keep your chest up as you lower your hips back and down, as if sitting into a chair.","Lower until your thighs are parallel to the ground, or as low as you can comfortably go.","Drive through your heels to stand back up, squeezing your glutes at the top.","Repeat for the desired number of repetitions."]', '["Stehe mit schulterbreit auseinanderstehenden Füssen, die Zehen leicht nach aussen gedreht.","Halte die Langhantel quer über deinem oberen Rücken, sie liegt auf deinem Trapezmuskel oder deiner hinteren Schulter.","Spanne deine Körpermitte an und halte die Brust aufrecht, während du deine Hüfte nach hinten und unten absenkst, als würdest du dich auf einen Stuhl setzen.","Senke dich ab, bis deine Oberschenkel parallel zum Boden sind, oder so tief, wie es für dich angenehm ist.","Drücke dich über die Fersen nach oben und spanne oben dein Gesäss an.","Wiederhole die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0101.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0101.gif', 1784612222128, 1784612222128, 0),
  ('4d17dbdc-f09b-5282-a0e5-24c8efbb879b', NULL, 'Barbell Split Squat V. 2', 'Langhantel-Split Squat (Variante 2)', 'upper legs', 'quads', 'barbell', 'Start by standing with your feet shoulder-width apart, holding a barbell across your upper back. Take a large step forward with your right foot, keeping your torso upright. Lower your body by bending your knees and hips until your right thigh is parallel to the ground. Pause for a moment, then push through your right heel to return to the starting position. Repeat with your left leg forward for the desired number of repetitions.', NULL, 'glutes', '["glutes","hamstrings","calves"]', '["Start by standing with your feet shoulder-width apart, holding a barbell across your upper back.","Take a large step forward with your right foot, keeping your torso upright.","Lower your body by bending your knees and hips until your right thigh is parallel to the ground.","Pause for a moment, then push through your right heel to return to the starting position.","Repeat with your left leg forward for the desired number of repetitions."]', '["Beginne im Stand mit schulterbreit auseinanderstehenden Füssen und halte eine Langhantel quer über deinem oberen Rücken.","Mache mit dem rechten Fuss einen grossen Schritt nach vorne und halte den Oberkörper aufrecht.","Senke deinen Körper ab, indem du Knie und Hüfte beugst, bis dein rechter Oberschenkel parallel zum Boden ist.","Halte kurz inne und drücke dich dann über die rechte Ferse zurück in die Ausgangsposition.","Wiederhole mit dem linken Bein vorne für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/2810.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/2810.gif', 1784612222128, 1784612222128, 0),
  ('09ef6846-adde-5e25-b40f-6f87549e9ebe', NULL, 'Barbell Squat (on Knees)', 'Langhantel-Kniebeuge (kniend)', 'upper legs', 'quads', 'barbell', 'Start by kneeling on the ground with your knees hip-width apart and your toes pointing forward. Place a barbell across your shoulders, gripping it with an overhand grip and your hands slightly wider than shoulder-width apart. Engage your core and keep your chest lifted as you slowly lower your body down by bending your knees, keeping your back straight. Continue lowering until your thighs are parallel to the ground, or as low as you can comfortably go. Pause for a moment at the bottom, then push through your heels to return to the starting position. Repeat for the desired number of repetitions.', NULL, 'glutes', '["glutes","hamstrings","calves"]', '["Start by kneeling on the ground with your knees hip-width apart and your toes pointing forward.","Place a barbell across your shoulders, gripping it with an overhand grip and your hands slightly wider than shoulder-width apart.","Engage your core and keep your chest lifted as you slowly lower your body down by bending your knees, keeping your back straight.","Continue lowering until your thighs are parallel to the ground, or as low as you can comfortably go.","Pause for a moment at the bottom, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."]', '["Beginne kniend auf dem Boden, die Knie hüftbreit auseinander und die Zehen zeigen nach vorne.","Lege eine Langhantel quer über deine Schultern und greife sie im Obergriff, die Hände etwas breiter als schulterbreit.","Spanne deine Körpermitte an und halte die Brust aufrecht, während du deinen Körper langsam absenkst, indem du die Knie beugst und den Rücken gerade hältst.","Senke dich weiter ab, bis deine Oberschenkel parallel zum Boden sind, oder so tief, wie es für dich angenehm ist.","Halte unten kurz inne und drücke dich dann über die Fersen zurück in die Ausgangsposition.","Wiederhole die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0102.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0102.gif', 1784612222128, 1784612222128, 0),
  ('d658cdf7-5536-5a5a-afb2-144ac0f16f94', NULL, 'Barbell Squat Jump Step Rear Lunge', 'Langhantel-Kniebeuge-Sprung mit Ausfallschritt rückwärts', 'upper legs', 'quads', 'barbell', 'Start by standing with your feet shoulder-width apart, holding a barbell across your upper back. Lower your body into a squat position by bending your knees and pushing your hips back. Explode upwards, jumping off the ground as high as you can. Land softly on your feet and immediately step back with one leg into a reverse lunge. Lower your body down until your front thigh is parallel to the ground, keeping your back straight. Push through your front heel to return to the starting position. Repeat the jump and lunge sequence on the other leg. Continue alternating legs for the desired number of repetitions.', NULL, 'glutes', '["glutes","hamstrings","calves"]', '["Start by standing with your feet shoulder-width apart, holding a barbell across your upper back.","Lower your body into a squat position by bending your knees and pushing your hips back.","Explode upwards, jumping off the ground as high as you can.","Land softly on your feet and immediately step back with one leg into a reverse lunge.","Lower your body down until your front thigh is parallel to the ground, keeping your back straight.","Push through your front heel to return to the starting position.","Repeat the jump and lunge sequence on the other leg.","Continue alternating legs for the desired number of repetitions."]', '["Beginne im Stand mit schulterbreit auseinanderstehenden Füssen und halte eine Langhantel quer über deinem oberen Rücken.","Senke deinen Körper in die Hocke ab, indem du die Knie beugst und die Hüfte nach hinten schiebst.","Springe explosiv nach oben und hebe so hoch wie möglich vom Boden ab.","Lande weich auf den Füssen und trete sofort mit einem Bein in einen Ausfallschritt nach hinten.","Senke deinen Körper ab, bis dein vorderer Oberschenkel parallel zum Boden ist, halte dabei den Rücken gerade.","Drücke dich über die vordere Ferse zurück in die Ausgangsposition.","Wiederhole die Sprung-Ausfallschritt-Sequenz mit dem anderen Bein.","Wechsle die Beine fortlaufend für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/2798.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/2798.gif', 1784612222128, 1784612222128, 0),
  ('3dc2905e-d9a6-5a8e-bec3-fb872da729a9', NULL, 'Barbell Standing Ab Rollout', 'Langhantel-Rollout im Stehen', 'waist', 'abs', 'barbell', 'Stand upright with your feet shoulder-width apart and hold the barbell with both hands in front of your thighs. Engage your core and slowly roll the barbell down towards the ground, keeping your back straight and your arms extended. Continue rolling the barbell forward until your body is fully extended and your hands are directly above your head. Pause for a moment, then slowly roll the barbell back towards your thighs, maintaining control and keeping your core engaged. Repeat for the desired number of repetitions.', NULL, 'shoulders', '["shoulders","lower back"]', '["Stand upright with your feet shoulder-width apart and hold the barbell with both hands in front of your thighs.","Engage your core and slowly roll the barbell down towards the ground, keeping your back straight and your arms extended.","Continue rolling the barbell forward until your body is fully extended and your hands are directly above your head.","Pause for a moment, then slowly roll the barbell back towards your thighs, maintaining control and keeping your core engaged.","Repeat for the desired number of repetitions."]', '["Stehe aufrecht mit schulterbreit auseinanderstehenden Füssen und halte die Langhantel mit beiden Händen vor deinen Oberschenkeln.","Spanne deine Körpermitte an und rolle die Langhantel langsam Richtung Boden, halte dabei den Rücken gerade und die Arme gestreckt.","Rolle die Langhantel weiter nach vorne, bis dein Körper vollständig gestreckt ist und deine Hände direkt über deinem Kopf sind.","Halte kurz inne und rolle die Langhantel dann kontrolliert zurück zu deinen Oberschenkeln, die Körpermitte bleibt dabei angespannt.","Wiederhole die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0103.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0103.gif', 1784612222128, 1784612222128, 0),
  ('e4e0dc73-2a58-53a9-bc95-95a21695fbef', NULL, 'Barbell Standing Back Wrist Curl', 'Langhantel-Reverse-Handgelenkscurl im Stehen', 'lower arms', 'forearms', 'barbell', 'Stand up straight with your feet shoulder-width apart and hold a barbell with an overhand grip. Rest the barbell on the back of your hands with your palms facing down and your fingers pointing towards your body. Keeping your upper arms stationary, exhale and curl your wrists upwards as far as possible. Hold the contracted position for a brief pause, then inhale and slowly lower the barbell back to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","shoulders"]', '["Stand up straight with your feet shoulder-width apart and hold a barbell with an overhand grip.","Rest the barbell on the back of your hands with your palms facing down and your fingers pointing towards your body.","Keeping your upper arms stationary, exhale and curl your wrists upwards as far as possible.","Hold the contracted position for a brief pause, then inhale and slowly lower the barbell back to the starting position.","Repeat for the desired number of repetitions."]', '["Stehe aufrecht mit schulterbreit auseinanderstehenden Füssen und halte eine Langhantel im Obergriff.","Lass die Langhantel auf dem Handrücken ruhen, die Handflächen zeigen nach unten und die Finger zu deinem Körper.","Halte die Oberarme ruhig, atme aus und rolle die Handgelenke so weit wie möglich nach oben.","Halte die angespannte Position kurz, atme dann ein und senke die Langhantel langsam zurück in die Ausgangsposition.","Wiederhole die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0104.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0104.gif', 1784612222128, 1784612222128, 0),
  ('ad4c1bf9-4b7c-5423-b2aa-c1bb5da7ca27', NULL, 'Barbell Standing Bradford Press', 'Langhantel-Bradford-Press im Stehen', 'shoulders', 'delts', 'barbell', 'Stand with your feet shoulder-width apart and hold the barbell in front of your shoulders with an overhand grip. Press the barbell overhead, fully extending your arms. Lower the barbell back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'triceps', '["triceps","upper back"]', '["Stand with your feet shoulder-width apart and hold the barbell in front of your shoulders with an overhand grip.","Press the barbell overhead, fully extending your arms.","Lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle dich schulterbreit hin und halte die Langhantel im Obergriff vor deinen Schultern.","Drücke die Langhantel nach oben, bis deine Arme vollständig gestreckt sind.","Senke die Langhantel zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0105.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0105.gif', 1784612222128, 1784612222128, 0),
  ('a8fb5710-6bcc-5cab-96e2-141b06cb9cac', NULL, 'Barbell Standing Calf Raise', 'Langhantel-Wadenheben im Stehen', 'lower legs', 'calves', 'barbell', 'Stand with your feet shoulder-width apart and place a barbell across your upper back. Raise your heels off the ground as high as possible, using only your toes. Pause for a moment at the top, then slowly lower your heels back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'hamstrings', '["hamstrings","glutes"]', '["Stand with your feet shoulder-width apart and place a barbell across your upper back.","Raise your heels off the ground as high as possible, using only your toes.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle dich schulterbreit hin und lege die Langhantel auf deinen oberen Rücken.","Hebe deine Fersen so hoch wie möglich vom Boden ab und stütze dich nur auf die Zehenballen.","Halte oben kurz inne und senke deine Fersen dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1372.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1372.gif', 1784612222128, 1784612222128, 0),
  ('687457fd-028d-5733-a049-4f6fe370d68a', NULL, 'Barbell Standing Close Grip Curl', 'Langhantel-Curl eng im Stehen', 'upper arms', 'biceps', 'barbell', 'Stand up straight with your feet shoulder-width apart and hold a barbell with an underhand grip, hands close together. Keep your elbows close to your torso and your upper arms stationary throughout the movement. Exhale as you curl the weights while contracting your biceps. Continue to raise the bar until your biceps are fully contracted and the bar is at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale as you slowly begin to bring the barbell back to the starting position. Repeat for the desired number of repetitions.', NULL, 'forearms', '["forearms"]', '["Stand up straight with your feet shoulder-width apart and hold a barbell with an underhand grip, hands close together.","Keep your elbows close to your torso and your upper arms stationary throughout the movement.","Exhale as you curl the weights while contracting your biceps. Continue to raise the bar until your biceps are fully contracted and the bar is at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale as you slowly begin to bring the barbell back to the starting position.","Repeat for the desired number of repetitions."]', '["Stehe aufrecht mit schulterbreitem Stand und halte die Langhantel im Untergriff mit eng beieinanderliegenden Händen.","Halte deine Ellbogen nah am Oberkörper und deine Oberarme während der gesamten Bewegung ruhig.","Atme aus, während du die Langhantel hochziehst und deinen Bizeps anspannst. Hebe die Stange weiter an, bis dein Bizeps vollständig angespannt ist und sich die Stange auf Schulterhöhe befindet.","Halte die angespannte Position kurz und drücke deinen Bizeps dabei zusammen.","Atme ein und bringe die Langhantel langsam zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0106.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0106.gif', 1784612222128, 1784612222128, 0),
  ('58357e9d-37d2-5646-9a6e-5ca6aad4d830', NULL, 'Barbell Standing Close Grip Military Press', 'Langhantel-Schulterdrücken eng im Stehen', 'shoulders', 'delts', 'barbell', 'Stand with your feet shoulder-width apart and hold the barbell with an overhand grip, hands slightly closer than shoulder-width apart. Lift the barbell to shoulder height, keeping your elbows close to your body. Press the barbell overhead, extending your arms fully. Lower the barbell back to shoulder height. Repeat for the desired number of repetitions.', NULL, 'triceps', '["triceps","upper back"]', '["Stand with your feet shoulder-width apart and hold the barbell with an overhand grip, hands slightly closer than shoulder-width apart.","Lift the barbell to shoulder height, keeping your elbows close to your body.","Press the barbell overhead, extending your arms fully.","Lower the barbell back to shoulder height.","Repeat for the desired number of repetitions."]', '["Stelle dich schulterbreit hin und halte die Langhantel im Obergriff mit einem Handabstand etwas enger als schulterbreit.","Hebe die Langhantel auf Schulterhöhe und halte deine Ellbogen nah am Körper.","Drücke die Langhantel über Kopf, bis deine Arme vollständig gestreckt sind.","Senke die Langhantel zurück auf Schulterhöhe ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1456.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1456.gif', 1784612222128, 1784612222128, 0),
  ('11d0873a-a55a-5126-8d97-8dc46f6ef143', NULL, 'Barbell Standing Concentration Curl', 'Langhantel-Konzentrationscurl im Stehen', 'upper arms', 'biceps', 'barbell', 'Stand with your feet shoulder-width apart and hold a barbell in one hand, palm facing up. Rest your opposite hand on your thigh for support. Keeping your upper arm stationary, exhale and curl the weight up towards your shoulder. Pause for a moment at the top, squeezing your biceps. Inhale and slowly lower the weight back down to the starting position. Repeat for the desired number of repetitions, then switch arms.', NULL, 'forearms', '["forearms"]', '["Stand with your feet shoulder-width apart and hold a barbell in one hand, palm facing up.","Rest your opposite hand on your thigh for support.","Keeping your upper arm stationary, exhale and curl the weight up towards your shoulder.","Pause for a moment at the top, squeezing your biceps.","Inhale and slowly lower the weight back down to the starting position.","Repeat for the desired number of repetitions, then switch arms."]', '["Stelle dich schulterbreit hin und halte die Langhantel mit einer Hand, Handfläche nach oben.","Stütze deine andere Hand zur Unterstützung auf deinem Oberschenkel ab.","Halte deinen Oberarm ruhig, atme aus und ziehe das Gewicht in Richtung deiner Schulter hoch.","Halte oben kurz inne und spanne deinen Bizeps an.","Atme ein und senke das Gewicht langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dann die Seite."]', 'https://ascent-api.sweber.workers.dev/media/exercises/2414.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/2414.gif', 1784612222128, 1784612222128, 0),
  ('92990872-f230-556f-b773-5ac04ab90b8c', NULL, 'Barbell Standing Front Raise Over Head', 'Langhantel-Frontheben über Kopf im Stehen', 'shoulders', 'delts', 'barbell', 'Stand with your feet shoulder-width apart, holding a barbell in front of your thighs with an overhand grip. Keep your back straight and engage your core. Slowly raise the barbell in front of you, keeping your arms straight and your palms facing down. Continue lifting until the barbell is slightly above shoulder level. Pause for a moment at the top, then slowly lower the barbell back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'triceps', '["triceps","upper back"]', '["Stand with your feet shoulder-width apart, holding a barbell in front of your thighs with an overhand grip.","Keep your back straight and engage your core.","Slowly raise the barbell in front of you, keeping your arms straight and your palms facing down.","Continue lifting until the barbell is slightly above shoulder level.","Pause for a moment at the top, then slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle dich schulterbreit hin und halte die Langhantel im Obergriff vor deinen Oberschenkeln.","Halte deinen Rücken gerade und spanne deine Körpermitte an.","Hebe die Langhantel langsam vor deinem Körper an, die Arme dabei gestreckt und die Handflächen nach unten gerichtet.","Hebe weiter an, bis die Langhantel leicht über Schulterhöhe ist.","Halte oben kurz inne und senke die Langhantel dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0107.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0107.gif', 1784612222128, 1784612222128, 0),
  ('82a85fb1-9ea3-5b4e-99e5-3b83b97e47c7', NULL, 'Barbell Standing Leg Calf Raise', 'Langhantel-Wadenheben im Stehen', 'lower legs', 'calves', 'barbell', 'Stand with your feet shoulder-width apart and place a barbell across your upper back. Raise your heels off the ground as high as possible, using your calves. Pause for a moment at the top, then slowly lower your heels back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'hamstrings', '["hamstrings","glutes"]', '["Stand with your feet shoulder-width apart and place a barbell across your upper back.","Raise your heels off the ground as high as possible, using your calves.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle dich schulterbreit hin und lege die Langhantel auf deinen oberen Rücken.","Hebe deine Fersen mithilfe deiner Waden so hoch wie möglich vom Boden ab.","Halte oben kurz inne und senke deine Fersen dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0108.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0108.gif', 1784612222128, 1784612222128, 0),
  ('e3954548-98c2-5c71-bf65-b0c96bf0c89d', NULL, 'Barbell Standing Overhead Triceps Extension', 'Langhantel-Trizepsstrecken über Kopf im Stehen', 'upper arms', 'triceps', 'barbell', 'Stand with your feet shoulder-width apart and hold a barbell with an overhand grip. Raise the barbell overhead, fully extending your arms. Keeping your upper arms close to your head, slowly lower the barbell behind your head by bending your elbows. Pause for a moment, then raise the barbell back to the starting position by extending your arms. Repeat for the desired number of repetitions.', NULL, 'shoulders', '["shoulders"]', '["Stand with your feet shoulder-width apart and hold a barbell with an overhand grip.","Raise the barbell overhead, fully extending your arms.","Keeping your upper arms close to your head, slowly lower the barbell behind your head by bending your elbows.","Pause for a moment, then raise the barbell back to the starting position by extending your arms.","Repeat for the desired number of repetitions."]', '["Stelle dich schulterbreit hin und halte die Langhantel im Obergriff.","Hebe die Langhantel über Kopf, bis deine Arme vollständig gestreckt sind.","Halte deine Oberarme nah am Kopf und senke die Langhantel langsam hinter deinen Kopf ab, indem du deine Ellbogen beugst.","Halte kurz inne, dann strecke deine Arme, um die Langhantel zurück in die Ausgangsposition zu heben.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0109.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0109.gif', 1784612222128, 1784612222128, 0),
  ('3f0b6d89-6f57-5ae9-b867-b674c9d29413', NULL, 'Barbell Standing Reverse Grip Curl', 'Langhantel-Curl im Untergriff im Stehen', 'upper arms', 'biceps', 'barbell', 'Stand up straight with your feet shoulder-width apart and hold a barbell with an underhand grip, palms facing up. Keep your elbows close to your torso and your upper arms stationary. Exhale and curl the weights while contracting your biceps, bringing the barbell as close to your shoulders as possible. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly lower the barbell back to the starting position. Repeat for the desired number of repetitions.', NULL, 'forearms', '["forearms"]', '["Stand up straight with your feet shoulder-width apart and hold a barbell with an underhand grip, palms facing up.","Keep your elbows close to your torso and your upper arms stationary.","Exhale and curl the weights while contracting your biceps, bringing the barbell as close to your shoulders as possible.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly lower the barbell back to the starting position.","Repeat for the desired number of repetitions."]', '["Stehe aufrecht mit schulterbreitem Stand und halte die Langhantel im Untergriff, Handflächen nach oben.","Halte deine Ellbogen nah am Oberkörper und deine Oberarme ruhig.","Atme aus und ziehe die Langhantel hoch, während du deinen Bizeps anspannst, bis sie so nah wie möglich an deinen Schultern ist.","Halte die angespannte Position kurz und drücke deinen Bizeps dabei zusammen.","Atme ein und senke die Langhantel langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0110.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0110.gif', 1784612222128, 1784612222128, 0),
  ('81a21a77-f11e-5f00-b45f-d45d00d25d01', NULL, 'Barbell Standing Rocking Leg Calf Raise', 'Langhantel-Wadenheben im Stehen (wippend)', 'lower legs', 'calves', 'barbell', 'Stand with your feet shoulder-width apart and hold a barbell across your upper back. Raise your heels off the ground as high as possible, balancing on the balls of your feet. Slowly lower your heels back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'hamstrings', '["hamstrings","quadriceps"]', '["Stand with your feet shoulder-width apart and hold a barbell across your upper back.","Raise your heels off the ground as high as possible, balancing on the balls of your feet.","Slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle dich schulterbreit hin und halte die Langhantel auf deinem oberen Rücken.","Hebe deine Fersen so hoch wie möglich vom Boden ab und balanciere auf den Zehenballen.","Senke deine Fersen langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0111.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0111.gif', 1784612222128, 1784612222128, 0),
  ('b4b147ff-bb8b-5a43-b12e-c125687014d1', NULL, 'Barbell Standing Twist', 'Langhantel-Rumpfdrehen im Stehen', 'waist', 'abs', 'barbell', 'Stand with your feet shoulder-width apart and hold a barbell in front of your chest with both hands, palms facing down. Engage your core and keep your back straight throughout the exercise. Slowly twist your torso to the right, pivoting on your feet and hips, while keeping your lower body stable. Pause for a moment at the end of the twist, then slowly return to the starting position. Repeat the twist to the left side. Continue alternating twists for the desired number of repetitions.', NULL, 'obliques', '["obliques","lower back"]', '["Stand with your feet shoulder-width apart and hold a barbell in front of your chest with both hands, palms facing down.","Engage your core and keep your back straight throughout the exercise.","Slowly twist your torso to the right, pivoting on your feet and hips, while keeping your lower body stable.","Pause for a moment at the end of the twist, then slowly return to the starting position.","Repeat the twist to the left side.","Continue alternating twists for the desired number of repetitions."]', '["Stelle dich schulterbreit hin und halte die Langhantel mit beiden Händen vor deiner Brust, Handflächen nach unten.","Spanne deine Körpermitte an und halte deinen Rücken während der gesamten Übung gerade.","Drehe deinen Oberkörper langsam nach rechts, drehe dabei über Füsse und Hüfte, während dein Unterkörper stabil bleibt.","Halte am Ende der Drehung kurz inne und kehre dann langsam in die Ausgangsposition zurück.","Wiederhole die Drehung zur linken Seite.","Wechsle die Seiten weiter ab, für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0112.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0112.gif', 1784612222128, 1784612222128, 0),
  ('d7488f08-d8e6-5c1b-9765-a6b48ef0c78a', NULL, 'Barbell Standing Wide Grip Biceps Curl', 'Langhantel-Bizepscurl weit im Stehen', 'upper arms', 'biceps', 'barbell', 'Stand with your feet shoulder-width apart and hold a barbell with an underhand grip, hands wider than shoulder-width apart. Keep your back straight and your elbows close to your torso. Exhale and curl the barbell up towards your shoulders, keeping your upper arms stationary. Pause for a moment at the top, squeezing your biceps. Inhale and slowly lower the barbell back to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', NULL, 'forearms', '["forearms"]', '["Stand with your feet shoulder-width apart and hold a barbell with an underhand grip, hands wider than shoulder-width apart.","Keep your back straight and your elbows close to your torso.","Exhale and curl the barbell up towards your shoulders, keeping your upper arms stationary.","Pause for a moment at the top, squeezing your biceps.","Inhale and slowly lower the barbell back to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."]', '["Stelle dich schulterbreit hin und halte die Langhantel im Untergriff mit einem Handabstand breiter als schulterbreit.","Halte deinen Rücken gerade und deine Ellbogen nah am Oberkörper.","Atme aus und ziehe die Langhantel in Richtung deiner Schultern hoch, während deine Oberarme ruhig bleiben.","Halte oben kurz inne und spanne deinen Bizeps an.","Atme ein und senke die Langhantel langsam zurück in die Ausgangsposition ab, bis deine Arme vollständig gestreckt sind.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1629.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1629.gif', 1784612222128, 1784612222128, 0),
  ('f3b95151-36f1-5d48-a609-7ca00b470250', NULL, 'Barbell Standing Wide Military Press', 'Langhantel-Schulterdrücken weit im Stehen', 'shoulders', 'delts', 'barbell', 'Stand with your feet shoulder-width apart and hold the barbell with an overhand grip, slightly wider than shoulder-width. Lift the barbell to shoulder height, keeping your elbows slightly in front of the bar. Press the barbell overhead, extending your arms fully. Lower the barbell back to shoulder height and repeat for the desired number of repetitions.', NULL, 'triceps', '["triceps","upper back"]', '["Stand with your feet shoulder-width apart and hold the barbell with an overhand grip, slightly wider than shoulder-width.","Lift the barbell to shoulder height, keeping your elbows slightly in front of the bar.","Press the barbell overhead, extending your arms fully.","Lower the barbell back to shoulder height and repeat for the desired number of repetitions."]', '["Stelle dich schulterbreit hin und halte die Langhantel im Obergriff, etwas breiter als schulterbreit.","Hebe die Langhantel auf Schulterhöhe und halte deine Ellbogen leicht vor der Stange.","Drücke die Langhantel über Kopf, bis deine Arme vollständig gestreckt sind.","Senke die Langhantel zurück auf Schulterhöhe ab und wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1457.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1457.gif', 1784612222128, 1784612222128, 0),
  ('01caaee1-a3cb-5d05-8413-8bda2e42c1dc', NULL, 'Barbell Standing Wide-Grip Curl', 'Langhantel-Curl weit im Stehen', 'upper arms', 'biceps', 'barbell', 'Stand up straight with your feet shoulder-width apart and hold a barbell with an overhand grip, hands wider than shoulder-width apart. Let the barbell hang at arm''s length in front of your thighs, with your palms facing away from your body. Keeping your upper arms stationary, exhale and curl the barbell upward by contracting your biceps. Continue to raise the barbell until your biceps are fully contracted and the barbell is at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly begin to lower the barbell back to the starting position. Repeat for the desired number of repetitions.', NULL, 'forearms', '["forearms","shoulders"]', '["Stand up straight with your feet shoulder-width apart and hold a barbell with an overhand grip, hands wider than shoulder-width apart.","Let the barbell hang at arm''s length in front of your thighs, with your palms facing away from your body.","Keeping your upper arms stationary, exhale and curl the barbell upward by contracting your biceps.","Continue to raise the barbell until your biceps are fully contracted and the barbell is at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the barbell back to the starting position.","Repeat for the desired number of repetitions."]', '["Stehe aufrecht mit schulterbreitem Stand und halte die Langhantel im Obergriff mit einem Handabstand breiter als schulterbreit.","Lasse die Langhantel mit gestreckten Armen vor deinen Oberschenkeln hängen, Handflächen vom Körper weg gerichtet.","Halte deine Oberarme ruhig, atme aus und ziehe die Langhantel hoch, während du deinen Bizeps anspannst.","Hebe weiter an, bis dein Bizeps vollständig angespannt ist und sich die Langhantel auf Schulterhöhe befindet.","Halte die angespannte Position kurz und drücke deinen Bizeps dabei zusammen.","Atme ein und beginne, die Langhantel langsam zurück in die Ausgangsposition zu senken.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0113.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0113.gif', 1784612222128, 1784612222128, 0),
  ('2812c5e2-0f4f-5afa-94d4-43f71fe4f78c', NULL, 'Barbell Step-up', 'Langhantel-Step-up', 'upper legs', 'glutes', 'barbell', 'Stand in front of a bench or step with a barbell resting on your upper back. Place one foot on the bench or step, ensuring your entire foot is in contact with the surface. Push through your heel and step up onto the bench or step, fully extending your hip and knee. Pause briefly at the top, then lower yourself back down to the starting position. Repeat with the opposite leg. Continue alternating legs for the desired number of repetitions.', NULL, 'quadriceps', '["quadriceps","hamstrings","calves"]', '["Stand in front of a bench or step with a barbell resting on your upper back.","Place one foot on the bench or step, ensuring your entire foot is in contact with the surface.","Push through your heel and step up onto the bench or step, fully extending your hip and knee.","Pause briefly at the top, then lower yourself back down to the starting position.","Repeat with the opposite leg.","Continue alternating legs for the desired number of repetitions."]', '["Stelle dich vor eine Bank oder Stufe, die Langhantel auf deinem oberen Rücken.","Stelle einen Fuss vollständig auf die Bank oder Stufe.","Drücke dich über die Ferse ab und steige auf die Bank oder Stufe, bis Hüfte und Knie vollständig gestreckt sind.","Halte oben kurz inne und senke dich dann zurück in die Ausgangsposition ab.","Wiederhole mit dem anderen Bein.","Wechsle die Beine weiter ab, für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0114.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0114.gif', 1784612222128, 1784612222128, 0),
  ('b39c6904-b4eb-5e59-831d-47f1784fc474', NULL, 'Barbell Stiff Leg Good Morning', 'Langhantel-Good Morning mit gestreckten Beinen', 'upper legs', 'glutes', 'barbell', 'Stand with your feet shoulder-width apart and your knees slightly bent. Hold the barbell across your upper back, resting it on your traps. Keeping your back straight, hinge forward at the hips, pushing your glutes back. Lower your torso until it is parallel to the ground, feeling a stretch in your hamstrings. Engage your glutes and hamstrings to return to the starting position. Repeat for the desired number of repetitions.', NULL, 'hamstrings', '["hamstrings","lower back"]', '["Stand with your feet shoulder-width apart and your knees slightly bent.","Hold the barbell across your upper back, resting it on your traps.","Keeping your back straight, hinge forward at the hips, pushing your glutes back.","Lower your torso until it is parallel to the ground, feeling a stretch in your hamstrings.","Engage your glutes and hamstrings to return to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle dich schulterbreit hin, die Knie leicht gebeugt.","Halte die Langhantel auf deinem oberen Rücken, aufliegend auf deinem Trapezmuskel.","Halte deinen Rücken gerade und beuge dich in der Hüfte nach vorne, während du dein Gesäss nach hinten schiebst.","Senke deinen Oberkörper ab, bis er parallel zum Boden ist, und spüre die Dehnung in deinen Beinbeugern.","Spanne Gesäss und Beinbeuger an, um in die Ausgangsposition zurückzukehren.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0115.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0115.gif', 1784612222128, 1784612222128, 0),
  ('7dd0e04a-5cd6-568c-a055-fb82f8f23e4e', NULL, 'Barbell Straight Leg Deadlift', 'Langhantel-Kreuzheben mit gestreckten Beinen', 'upper legs', 'hamstrings', 'barbell', 'Stand with your feet shoulder-width apart and your toes pointing forward. Hold the barbell with an overhand grip, hands slightly wider than shoulder-width apart. Bend at your hips and lower the barbell towards the ground, keeping your back straight and your knees slightly bent. Lower the barbell until you feel a stretch in your hamstrings. Engage your hamstrings and glutes to lift the barbell back up to the starting position. Repeat for the desired number of repetitions.', NULL, 'glutes', '["glutes","lower back"]', '["Stand with your feet shoulder-width apart and your toes pointing forward.","Hold the barbell with an overhand grip, hands slightly wider than shoulder-width apart.","Bend at your hips and lower the barbell towards the ground, keeping your back straight and your knees slightly bent.","Lower the barbell until you feel a stretch in your hamstrings.","Engage your hamstrings and glutes to lift the barbell back up to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle dich schulterbreit hin, die Zehen zeigen nach vorne.","Halte die Langhantel im Obergriff mit einem Handabstand etwas breiter als schulterbreit.","Beuge dich in der Hüfte und senke die Langhantel Richtung Boden ab, halte dabei den Rücken gerade und die Knie leicht gebeugt.","Senke die Langhantel ab, bis du eine Dehnung in deinen Beinbeugern spürst.","Spanne Beinbeuger und Gesäss an, um die Langhantel zurück in die Ausgangsposition zu heben.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0116.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0116.gif', 1784612222128, 1784612222128, 0),
  ('708df6db-a616-5ae0-b5ce-a2a55dbf9021', NULL, 'Barbell Sumo Deadlift', 'Langhantel-Sumo-Kreuzheben', 'upper legs', 'glutes', 'barbell', 'Stand with your feet wider than shoulder-width apart, toes pointing outwards. Place a barbell on the ground in front of you, centered between your feet. Bend your knees and lower your hips, keeping your back straight and chest up, to grip the barbell with an overhand grip. Engage your core and drive through your heels to lift the barbell off the ground, extending your hips and knees simultaneously. As you lift, keep your chest up and back straight, and push your hips forward to fully engage your glutes. Pause for a moment at the top, then slowly lower the barbell back down to the starting position, maintaining control throughout the movement. Repeat for the desired number of repetitions.', NULL, 'hamstrings', '["hamstrings","quadriceps","lower back"]', '["Stand with your feet wider than shoulder-width apart, toes pointing outwards.","Place a barbell on the ground in front of you, centered between your feet.","Bend your knees and lower your hips, keeping your back straight and chest up, to grip the barbell with an overhand grip.","Engage your core and drive through your heels to lift the barbell off the ground, extending your hips and knees simultaneously.","As you lift, keep your chest up and back straight, and push your hips forward to fully engage your glutes.","Pause for a moment at the top, then slowly lower the barbell back down to the starting position, maintaining control throughout the movement.","Repeat for the desired number of repetitions."]', '["Stelle dich breiter als schulterbreit hin, die Zehen zeigen nach aussen.","Platziere eine Langhantel auf dem Boden vor dir, mittig zwischen deinen Füssen.","Beuge deine Knie und senke deine Hüfte ab, halte dabei Rücken und Brust aufrecht, und greife die Langhantel im Obergriff.","Spanne deine Körpermitte an und drücke dich über die Fersen ab, um die Langhantel vom Boden zu heben, während du Hüfte und Knie gleichzeitig streckst.","Halte beim Heben Brust und Rücken aufrecht und schiebe deine Hüfte nach vorne, um dein Gesäss vollständig anzuspannen.","Halte oben kurz inne und senke die Langhantel dann langsam und kontrolliert zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0117.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0117.gif', 1784612222128, 1784612222128, 0),
  ('32304266-0aba-5242-bcde-d21f16679616', NULL, 'Barbell Thruster', 'Langhantel-Thruster', 'shoulders', 'delts', 'barbell', 'Start by standing with your feet shoulder-width apart, holding a barbell at shoulder height with an overhand grip. Lower into a squat position by bending your knees and pushing your hips back. As you reach the bottom of the squat, explosively drive through your heels to stand up, simultaneously pressing the barbell overhead. Lower the barbell back to shoulder height as you lower back into the squat position. Repeat for the desired number of repetitions.', NULL, 'quadriceps', '["quadriceps","glutes","hamstrings","core"]', '["Start by standing with your feet shoulder-width apart, holding a barbell at shoulder height with an overhand grip.","Lower into a squat position by bending your knees and pushing your hips back.","As you reach the bottom of the squat, explosively drive through your heels to stand up, simultaneously pressing the barbell overhead.","Lower the barbell back to shoulder height as you lower back into the squat position.","Repeat for the desired number of repetitions."]', '["Stelle dich schulterbreit hin und halte die Langhantel im Obergriff auf Schulterhöhe.","Senke dich in eine Kniebeuge ab, indem du deine Knie beugst und deine Hüfte nach hinten schiebst.","Drücke dich am unteren Punkt der Kniebeuge explosiv über die Fersen nach oben und drücke die Langhantel gleichzeitig über Kopf.","Senke die Langhantel zurück auf Schulterhöhe ab, während du wieder in die Kniebeuge sinkst.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/3305.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/3305.gif', 1784612222128, 1784612222128, 0),
  ('902899d2-3d5e-5b36-9dce-cf8d9ea52635', NULL, 'Barbell Upright Row', 'Langhantel-Aufrechtes Rudern', 'shoulders', 'delts', 'barbell', 'Stand with your feet shoulder-width apart and hold a barbell with an overhand grip, hands slightly wider than shoulder-width apart. Let the barbell hang in front of your thighs, arms fully extended. Keeping your back straight and core engaged, exhale and lift the barbell straight up towards your chin, leading with your elbows. Pause for a moment at the top, then inhale and slowly lower the barbell back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'traps', '["traps","biceps"]', '["Stand with your feet shoulder-width apart and hold a barbell with an overhand grip, hands slightly wider than shoulder-width apart.","Let the barbell hang in front of your thighs, arms fully extended.","Keeping your back straight and core engaged, exhale and lift the barbell straight up towards your chin, leading with your elbows.","Pause for a moment at the top, then inhale and slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle dich schulterbreit hin und halte die Langhantel im Obergriff mit einem Handabstand etwas breiter als schulterbreit.","Lasse die Langhantel mit gestreckten Armen vor deinen Oberschenkeln hängen.","Halte den Rücken gerade und spanne deine Körpermitte an, atme aus und ziehe die Langhantel gerade nach oben in Richtung Kinn, die Ellbogen führen die Bewegung.","Halte oben kurz inne, atme ein und senke die Langhantel dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0120.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0120.gif', 1784612222128, 1784612222128, 0),
  ('270b23ab-310b-5573-a39f-e3ea4ac5db4b', NULL, 'Barbell Upright Row V. 2', 'Langhantel-Aufrechtes Rudern (Variante 2)', 'shoulders', 'delts', 'barbell', 'Stand with your feet shoulder-width apart and hold a barbell with an overhand grip, hands slightly wider than shoulder-width apart. Let the barbell hang in front of your thighs, arms fully extended. Keeping your back straight, exhale and lift the barbell straight up towards your chin, leading with your elbows. Pause for a moment at the top, then inhale and slowly lower the barbell back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'traps', '["traps","biceps"]', '["Stand with your feet shoulder-width apart and hold a barbell with an overhand grip, hands slightly wider than shoulder-width apart.","Let the barbell hang in front of your thighs, arms fully extended.","Keeping your back straight, exhale and lift the barbell straight up towards your chin, leading with your elbows.","Pause for a moment at the top, then inhale and slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle dich schulterbreit hin und halte die Langhantel im Obergriff mit einem Handabstand etwas breiter als schulterbreit.","Lasse die Langhantel mit gestreckten Armen vor deinen Oberschenkeln hängen.","Halte den Rücken gerade, atme aus und ziehe die Langhantel gerade nach oben in Richtung Kinn, die Ellbogen führen die Bewegung.","Halte oben kurz inne, atme ein und senke die Langhantel dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0119.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0119.gif', 1784612222128, 1784612222128, 0),
  ('19a321fd-9363-5fc3-abed-e0c51b3eb96f', NULL, 'Barbell Upright Row V. 3', 'Langhantel-Aufrechtes Rudern (Variante 3)', 'shoulders', 'delts', 'barbell', 'Stand with your feet shoulder-width apart and hold a barbell with an overhand grip, hands slightly wider than shoulder-width apart. Let the barbell hang in front of your thighs, arms fully extended. Keeping your core engaged and back straight, exhale as you lift the barbell straight up towards your chin, leading with your elbows. Pause for a moment at the top, then inhale as you slowly lower the barbell back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'traps', '["traps","biceps"]', '["Stand with your feet shoulder-width apart and hold a barbell with an overhand grip, hands slightly wider than shoulder-width apart.","Let the barbell hang in front of your thighs, arms fully extended.","Keeping your core engaged and back straight, exhale as you lift the barbell straight up towards your chin, leading with your elbows.","Pause for a moment at the top, then inhale as you slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle dich schulterbreit hin und halte die Langhantel im Obergriff mit einem Handabstand etwas breiter als schulterbreit.","Lasse die Langhantel mit gestreckten Armen vor deinen Oberschenkeln hängen.","Spanne deine Körpermitte an, halte den Rücken gerade, atme aus und ziehe die Langhantel gerade nach oben in Richtung Kinn, die Ellbogen führen die Bewegung.","Halte oben kurz inne, atme ein und senke die Langhantel dabei langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0121.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0121.gif', 1784612222128, 1784612222128, 0),
  ('2d91baef-0bb8-544f-aca7-10cb2059fc21', NULL, 'Barbell Wide Bench Press', 'Langhantel-Bankdrücken weit', 'chest', 'pectorals', 'barbell', 'Lie flat on a bench with your feet flat on the ground and your back pressed against the bench. Grasp the barbell with a wide grip, slightly wider than shoulder-width apart. Lift the barbell off the rack and hold it directly above your chest with your arms fully extended. Lower the barbell slowly towards your chest, keeping your elbows slightly flared out. Pause for a moment when the barbell touches your chest, then push it back up to the starting position. Repeat for the desired number of repetitions.', NULL, 'shoulders', '["shoulders","triceps"]', '["Lie flat on a bench with your feet flat on the ground and your back pressed against the bench.","Grasp the barbell with a wide grip, slightly wider than shoulder-width apart.","Lift the barbell off the rack and hold it directly above your chest with your arms fully extended.","Lower the barbell slowly towards your chest, keeping your elbows slightly flared out.","Pause for a moment when the barbell touches your chest, then push it back up to the starting position.","Repeat for the desired number of repetitions."]', '["Lege dich flach auf eine Bank, die Füsse flach auf dem Boden und den Rücken an die Bank gedrückt.","Greife die Langhantel mit einem weiten Griff, etwas breiter als schulterbreit.","Hebe die Langhantel aus der Ablage und halte sie mit gestreckten Armen direkt über deiner Brust.","Senke die Langhantel langsam in Richtung deiner Brust ab, die Ellbogen dabei leicht nach aussen gerichtet.","Halte kurz inne, sobald die Langhantel deine Brust berührt, und drücke sie dann zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0122.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0122.gif', 1784612222128, 1784612222128, 0),
  ('06850e36-c5ce-5e29-b48d-f074f491d2a4', NULL, 'Barbell Wide Reverse Grip Bench Press', 'Langhantel-Bankdrücken weit im Untergriff', 'chest', 'pectorals', 'barbell', 'Lie flat on a bench with your feet flat on the ground and your back pressed against the bench. Grasp the barbell with a wide reverse grip, slightly wider than shoulder-width apart. Lift the barbell off the rack and hold it directly above your chest with your arms fully extended. Lower the barbell slowly towards your chest, keeping your elbows tucked in and your wrists straight. Pause for a moment when the barbell touches your chest, then push it back up to the starting position. Repeat for the desired number of repetitions.', NULL, 'triceps', '["triceps","shoulders"]', '["Lie flat on a bench with your feet flat on the ground and your back pressed against the bench.","Grasp the barbell with a wide reverse grip, slightly wider than shoulder-width apart.","Lift the barbell off the rack and hold it directly above your chest with your arms fully extended.","Lower the barbell slowly towards your chest, keeping your elbows tucked in and your wrists straight.","Pause for a moment when the barbell touches your chest, then push it back up to the starting position.","Repeat for the desired number of repetitions."]', '["Lege dich flach auf eine Bank, die Füsse flach auf dem Boden und den Rücken an die Bank gedrückt.","Greife die Langhantel im weiten Untergriff, etwas breiter als schulterbreit.","Hebe die Langhantel aus der Ablage und halte sie mit gestreckten Armen direkt über deiner Brust.","Senke die Langhantel langsam in Richtung deiner Brust ab, die Ellbogen dabei eng am Körper und die Handgelenke gerade.","Halte kurz inne, sobald die Langhantel deine Brust berührt, und drücke sie dann zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1258.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1258.gif', 1784612222128, 1784612222128, 0),
  ('3eaa03ec-9599-50b2-8208-dc9601cc5526', NULL, 'Barbell Wide Squat', 'Langhantel-Kniebeuge weit', 'upper legs', 'quads', 'barbell', 'Stand with your feet wider than shoulder-width apart, toes pointing slightly outward. Hold the barbell across your upper back, resting it on your traps or rear delts. Engage your core and keep your chest up as you lower your body down into a squat, pushing your hips back and bending your knees. Lower until your thighs are parallel to the ground, or as low as you can comfortably go. Pause for a moment at the bottom, then push through your heels to return to the starting position. Repeat for the desired number of repetitions.', NULL, 'glutes', '["glutes","hamstrings","calves"]', '["Stand with your feet wider than shoulder-width apart, toes pointing slightly outward.","Hold the barbell across your upper back, resting it on your traps or rear delts.","Engage your core and keep your chest up as you lower your body down into a squat, pushing your hips back and bending your knees.","Lower until your thighs are parallel to the ground, or as low as you can comfortably go.","Pause for a moment at the bottom, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle dich breiter als schulterbreit hin, die Zehen leicht nach aussen gerichtet.","Halte die Langhantel auf deinem oberen Rücken, aufliegend auf Trapezmuskel oder hinterer Schulter.","Spanne deine Körpermitte an und halte die Brust aufrecht, während du dich in die Kniebeuge absenkst, die Hüfte nach hinten schiebst und die Knie beugst.","Senke dich ab, bis deine Oberschenkel parallel zum Boden sind, oder so tief, wie es für dich angenehm ist.","Halte unten kurz inne und drücke dich dann über die Fersen zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0124.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0124.gif', 1784612222128, 1784612222128, 0),
  ('30728d7f-ac68-553f-b700-413f14526e04', NULL, 'Barbell Wide-Grip Upright Row', 'Langhantel-Aufrechtes Rudern weit', 'shoulders', 'delts', 'barbell', 'Stand with your feet shoulder-width apart and hold a barbell with an overhand grip, hands wider than shoulder-width apart. Let the barbell hang in front of your thighs, arms fully extended. Keeping your back straight, exhale and lift the barbell straight up towards your chin, leading with your elbows. Pause for a moment at the top, then inhale and slowly lower the barbell back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'traps', '["traps","biceps"]', '["Stand with your feet shoulder-width apart and hold a barbell with an overhand grip, hands wider than shoulder-width apart.","Let the barbell hang in front of your thighs, arms fully extended.","Keeping your back straight, exhale and lift the barbell straight up towards your chin, leading with your elbows.","Pause for a moment at the top, then inhale and slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle dich schulterbreit hin und halte die Langhantel im Obergriff mit einem Handabstand breiter als schulterbreit.","Lasse die Langhantel mit gestreckten Armen vor deinen Oberschenkeln hängen.","Halte den Rücken gerade, atme aus und ziehe die Langhantel gerade nach oben in Richtung Kinn, die Ellbogen führen die Bewegung.","Halte oben kurz inne, atme ein und senke die Langhantel dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0123.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0123.gif', 1784612222128, 1784612222128, 0),
  ('7ccfb65e-3475-550b-b236-8a23d972e840', NULL, 'Barbell Wrist Curl', 'Langhantel-Handgelenkscurl', 'lower arms', 'forearms', 'barbell', 'Sit on a bench with your feet flat on the ground and your forearms resting on your thighs, holding a barbell with an underhand grip. Allow the barbell to roll down to your fingertips, keeping your wrists straight. Slowly curl the barbell up towards your forearms by flexing your wrists. Pause for a moment at the top, then slowly lower the barbell back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","brachialis"]', '["Sit on a bench with your feet flat on the ground and your forearms resting on your thighs, holding a barbell with an underhand grip.","Allow the barbell to roll down to your fingertips, keeping your wrists straight.","Slowly curl the barbell up towards your forearms by flexing your wrists.","Pause for a moment at the top, then slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."]', '["Setze dich auf eine Bank, die Füsse flach auf dem Boden, die Unterarme auf den Oberschenkeln abgestützt, und halte die Langhantel im Untergriff.","Lasse die Langhantel bis zu deinen Fingerspitzen abrollen, die Handgelenke dabei gerade halten.","Rolle die Langhantel langsam in Richtung deiner Unterarme, indem du deine Handgelenke beugst.","Halte oben kurz inne und senke die Langhantel dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0126.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0126.gif', 1784612222128, 1784612222128, 0),
  ('3892a8c2-a345-5372-8f20-a0ae28073c67', NULL, 'Barbell Wrist Curl V. 2', 'Langhantel-Handgelenkscurl (Variante 2)', 'lower arms', 'forearms', 'barbell', 'Sit on a bench with your feet flat on the ground and your knees bent. Hold a barbell with an underhand grip, palms facing up, and your hands shoulder-width apart. Rest your forearms on your thighs, allowing your wrists to hang off the edge. Slowly curl your wrists upward, bringing the barbell towards your forearms. Pause for a moment at the top, then slowly lower the barbell back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","brachialis"]', '["Sit on a bench with your feet flat on the ground and your knees bent.","Hold a barbell with an underhand grip, palms facing up, and your hands shoulder-width apart.","Rest your forearms on your thighs, allowing your wrists to hang off the edge.","Slowly curl your wrists upward, bringing the barbell towards your forearms.","Pause for a moment at the top, then slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."]', '["Setze dich auf eine Bank, die Füsse flach auf dem Boden und die Knie gebeugt.","Halte die Langhantel im Untergriff, Handflächen nach oben, mit schulterbreitem Handabstand.","Stütze deine Unterarme auf deinen Oberschenkeln ab und lasse deine Handgelenke über die Kante hängen.","Beuge deine Handgelenke langsam nach oben und ziehe die Langhantel in Richtung deiner Unterarme.","Halte oben kurz inne und senke die Langhantel dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0125.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0125.gif', 1784612222128, 1784612222128, 0),
  ('2d3742d3-3360-55a7-9696-ec7a2c845afa', NULL, 'Barbell Zercher Squat', 'Langhantel-Zercher-Kniebeuge', 'upper legs', 'glutes', 'barbell', 'Stand with your feet shoulder-width apart and toes slightly turned out. Hold the barbell in the crooks of your elbows, with your hands gripping the bar for stability. Engage your core and keep your chest lifted as you lower your hips back and down into a squat position. Keep your knees in line with your toes and your weight in your heels. Pause for a moment at the bottom of the squat, then push through your heels to return to the starting position. Repeat for the desired number of repetitions.', NULL, 'quadriceps', '["quadriceps","hamstrings","calves","core"]', '["Stand with your feet shoulder-width apart and toes slightly turned out.","Hold the barbell in the crooks of your elbows, with your hands gripping the bar for stability.","Engage your core and keep your chest lifted as you lower your hips back and down into a squat position.","Keep your knees in line with your toes and your weight in your heels.","Pause for a moment at the bottom of the squat, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle dich schulterbreit hin, die Zehen leicht nach aussen gedreht.","Halte die Langhantel in den Ellbogenbeugen und umgreife die Stange mit den Händen für zusätzliche Stabilität.","Spanne deine Körpermitte an und halte die Brust hoch, während du deine Hüfte nach hinten und unten in eine Kniebeuge absenkst.","Halte deine Knie in Linie mit den Zehen und dein Gewicht auf den Fersen.","Halte am unteren Punkt der Kniebeuge kurz inne und drücke dich dann über die Fersen zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0127.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0127.gif', 1784612222128, 1784612222128, 0),
  ('f15dc389-05c1-59c0-8410-0bf3bc5e58e7', NULL, 'Basic Toe Touch (Male)', 'Einfaches Zehenberühren im Stehen (männlich)', 'upper legs', 'glutes', 'body weight', 'Stand with your feet shoulder-width apart and your arms by your sides. Bend forward at the waist, keeping your back straight and your knees slightly bent. Reach down towards your toes with your hands, keeping your legs as straight as possible. Pause for a moment at the bottom, then slowly return to the starting position. Repeat for the desired number of repetitions.', NULL, 'hamstrings', '["hamstrings","calves"]', '["Stand with your feet shoulder-width apart and your arms by your sides.","Bend forward at the waist, keeping your back straight and your knees slightly bent.","Reach down towards your toes with your hands, keeping your legs as straight as possible.","Pause for a moment at the bottom, then slowly return to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle dich schulterbreit hin, die Arme seitlich am Körper.","Beuge dich in der Hüfte nach vorne, halte dabei den Rücken gerade und die Knie leicht gebeugt.","Strecke deine Hände in Richtung deiner Zehen, die Beine dabei so gerade wie möglich halten.","Halte unten kurz inne und kehre dann langsam in die Ausgangsposition zurück.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/3212.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/3212.gif', 1784612222128, 1784612222128, 0),
  ('b0541c15-b856-55a7-80c4-01f9c31ef18f', NULL, 'Battling Ropes', 'Battle Ropes', 'shoulders', 'delts', 'rope', 'Stand with your feet shoulder-width apart and knees slightly bent. Hold one end of the rope in each hand, with your palms facing each other. Raise your arms to shoulder height, keeping your elbows slightly bent. Begin making alternating waves with the ropes by rapidly raising and lowering each arm. Continue for the desired duration or number of repetitions.', NULL, 'forearms', '["forearms","core"]', '["Stand with your feet shoulder-width apart and knees slightly bent.","Hold one end of the rope in each hand, with your palms facing each other.","Raise your arms to shoulder height, keeping your elbows slightly bent.","Begin making alternating waves with the ropes by rapidly raising and lowering each arm.","Continue for the desired duration or number of repetitions."]', '["Stelle dich schulterbreit hin, die Knie leicht gebeugt.","Halte je ein Seilende in einer Hand, die Handflächen zueinander gerichtet.","Hebe deine Arme auf Schulterhöhe an, die Ellbogen dabei leicht gebeugt.","Erzeuge abwechselnde Wellen mit den Seilen, indem du jeden Arm schnell anhebst und senkst.","Setze für die gewünschte Dauer oder Anzahl Wiederholungen fort."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0128.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0128.gif', 1784612222128, 1784612222128, 0),
  ('5a263aa5-8dbe-5854-ae15-35493f7b62d7', NULL, 'Bear Crawl', 'Bärengang', 'cardio', 'cardiovascular system', 'body weight', 'Start on all fours with your hands directly under your shoulders and your knees directly under your hips. Lift your knees slightly off the ground, keeping your back flat and your core engaged. Move your right hand and left foot forward simultaneously, followed by your left hand and right foot. Continue crawling forward, alternating your hand and foot movements. Maintain a steady pace and keep your core tight throughout the exercise. Continue for the desired distance or time.', NULL, 'core', '["core","shoulders","triceps"]', '["Start on all fours with your hands directly under your shoulders and your knees directly under your hips.","Lift your knees slightly off the ground, keeping your back flat and your core engaged.","Move your right hand and left foot forward simultaneously, followed by your left hand and right foot.","Continue crawling forward, alternating your hand and foot movements.","Maintain a steady pace and keep your core tight throughout the exercise.","Continue for the desired distance or time."]', '["Gehe in den Vierfüsslerstand, die Hände direkt unter den Schultern und die Knie direkt unter der Hüfte.","Hebe deine Knie leicht vom Boden ab, halte den Rücken flach und die Körpermitte angespannt.","Bewege gleichzeitig die rechte Hand und den linken Fuss nach vorne, gefolgt von der linken Hand und dem rechten Fuss.","Krieche weiter vorwärts und wechsle dabei Hände und Füsse ab.","Halte ein gleichmässiges Tempo und spanne deine Körpermitte während der gesamten Übung an.","Setze für die gewünschte Distanz oder Zeit fort."]', 'https://ascent-api.sweber.workers.dev/media/exercises/3360.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/3360.gif', 1784612222128, 1784612222128, 0),
  ('f1004ec8-a316-5612-80b0-60baee99c9ff', NULL, 'Behind Head Chest Stretch', 'Brustdehnung hinter dem Kopf', 'chest', 'pectorals', 'assisted', 'Stand tall with your feet shoulder-width apart. Interlace your fingers behind your head with your elbows pointing outwards. Slowly squeeze your shoulder blades together and push your chest forward. Hold the stretch for 15-30 seconds. Release the stretch and repeat as desired.', NULL, 'shoulders', '["shoulders","triceps"]', '["Stand tall with your feet shoulder-width apart.","Interlace your fingers behind your head with your elbows pointing outwards.","Slowly squeeze your shoulder blades together and push your chest forward.","Hold the stretch for 15-30 seconds.","Release the stretch and repeat as desired."]', '["Stelle dich aufrecht und schulterbreit hin.","Verschränke deine Finger hinter deinem Kopf, die Ellbogen zeigen nach aussen.","Ziehe deine Schulterblätter langsam zusammen und schiebe deine Brust nach vorne.","Halte die Dehnung für 15-30 Sekunden.","Löse die Dehnung und wiederhole nach Bedarf."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1259.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1259.gif', 1784612222128, 1784612222128, 0),
  ('21ca27c3-90e3-57af-acc1-f7ea863e6ad4', NULL, 'Bench Dip (Knees Bent)', 'Bankdip mit gebeugten Knien', 'upper arms', 'triceps', 'body weight', 'Sit on the edge of a bench or chair with your hands gripping the edge next to your hips. Slide your butt off the bench and straighten your legs in front of you, keeping your heels on the ground. Bend your elbows and lower your body towards the ground, keeping your back close to the bench. Pause for a moment at the bottom, then push yourself back up to the starting position. Repeat for the desired number of repetitions.', NULL, 'chest', '["chest","shoulders"]', '["Sit on the edge of a bench or chair with your hands gripping the edge next to your hips.","Slide your butt off the bench and straighten your legs in front of you, keeping your heels on the ground.","Bend your elbows and lower your body towards the ground, keeping your back close to the bench.","Pause for a moment at the bottom, then push yourself back up to the starting position.","Repeat for the desired number of repetitions."]', '["Setze dich auf die Kante einer Bank oder eines Stuhls, die Hände greifen die Kante neben deiner Hüfte.","Schiebe dein Gesäss von der Bank und strecke deine Beine vor dir aus, die Fersen bleiben dabei am Boden.","Beuge deine Ellbogen und senke deinen Körper Richtung Boden ab, halte dabei deinen Rücken nah an der Bank.","Halte unten kurz inne und drücke dich dann zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0129.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0129.gif', 1784612222128, 1784612222128, 0),
  ('bdd5b215-64ea-5a5d-ada8-0af6914d6708', NULL, 'Bench Dip on Floor', 'Bankdip auf dem Boden', 'upper arms', 'triceps', 'body weight', 'Sit on the edge of a bench or chair with your hands gripping the edge, fingers pointing forward. Slide your butt off the bench, supporting your weight with your hands. Lower your body by bending your elbows until your upper arms are parallel to the floor. Push yourself back up to the starting position by straightening your arms. Repeat for the desired number of repetitions.', NULL, 'chest', '["chest","shoulders"]', '["Sit on the edge of a bench or chair with your hands gripping the edge, fingers pointing forward.","Slide your butt off the bench, supporting your weight with your hands.","Lower your body by bending your elbows until your upper arms are parallel to the floor.","Push yourself back up to the starting position by straightening your arms.","Repeat for the desired number of repetitions."]', '["Setze dich auf die Kante einer Bank oder eines Stuhls, die Hände greifen die Kante, Finger zeigen nach vorne.","Schiebe dein Gesäss von der Bank und stütze dein Gewicht mit den Händen ab.","Senke deinen Körper ab, indem du deine Ellbogen beugst, bis deine Oberarme parallel zum Boden sind.","Drücke dich zurück in die Ausgangsposition, indem du deine Arme streckst.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1399.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1399.gif', 1784612222128, 1784612222128, 0),
  ('cfb0de39-366f-56f1-ac45-30fa074e2089', NULL, 'Bench Hip Extension', 'Hüftstreckung auf der Bank', 'upper legs', 'glutes', 'body weight', 'Sit on a bench with your back against the bench and your feet flat on the ground. Place your hands on the bench for support. Engage your glutes and hamstrings, then lift your hips off the bench until your body forms a straight line from your knees to your shoulders. Pause for a moment at the top, then slowly lower your hips back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'hamstrings', '["hamstrings"]', '["Sit on a bench with your back against the bench and your feet flat on the ground.","Place your hands on the bench for support.","Engage your glutes and hamstrings, then lift your hips off the bench until your body forms a straight line from your knees to your shoulders.","Pause for a moment at the top, then slowly lower your hips back down to the starting position.","Repeat for the desired number of repetitions."]', '["Setze dich mit dem Rücken an eine Bank gelehnt, die Füsse flach auf dem Boden.","Stütze deine Hände zur Unterstützung auf der Bank ab.","Spanne Gesäss und Beinbeuger an und hebe deine Hüfte von der Bank ab, bis dein Körper eine gerade Linie von den Knien bis zu den Schultern bildet.","Halte oben kurz inne und senke deine Hüfte dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0130.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0130.gif', 1784612222128, 1784612222128, 0),
  ('8685de43-1578-5a88-9363-3da36205c6c6', NULL, 'Bench Pull-ups', 'Invertiertes Rudern an der Bank', 'back', 'lats', 'body weight', 'Position yourself under a bar or a sturdy horizontal surface that is at chest height. Grab the bar or surface with an overhand grip, slightly wider than shoulder-width apart. Hang with your arms fully extended and your body straight. Pull your chest towards the bar or surface by squeezing your shoulder blades together and bending your elbows. Continue pulling until your chin is above the bar or surface. Lower yourself back down to the starting position with control. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","forearms"]', '["Position yourself under a bar or a sturdy horizontal surface that is at chest height.","Grab the bar or surface with an overhand grip, slightly wider than shoulder-width apart.","Hang with your arms fully extended and your body straight.","Pull your chest towards the bar or surface by squeezing your shoulder blades together and bending your elbows.","Continue pulling until your chin is above the bar or surface.","Lower yourself back down to the starting position with control.","Repeat for the desired number of repetitions."]', '["Positioniere dich unter einer Stange oder einer stabilen horizontalen Fläche auf Brusthöhe.","Greife die Stange oder Fläche im Obergriff mit einem Handabstand etwas breiter als schulterbreit.","Hänge mit vollständig gestreckten Armen und geradem Körper.","Ziehe deine Brust in Richtung der Stange oder Fläche, indem du deine Schulterblätter zusammenziehst und die Ellbogen beugst.","Ziehe weiter, bis dein Kinn über der Stange oder Fläche ist.","Senke dich kontrolliert zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/3019.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/3019.gif', 1784612222128, 1784612222128, 0),
  ('9d37d646-8c06-5e8c-949c-ea0205d0c13a', NULL, 'Bent Knee Lying Twist (Male)', 'Rumpfdrehen im Liegen mit gebeugten Knien (männlich)', 'upper legs', 'glutes', 'body weight', 'Lie flat on your back with your knees bent and feet flat on the ground. Extend your arms out to the sides, perpendicular to your body. Keeping your knees together, slowly lower them to one side, aiming to touch the ground with your knees. Pause for a moment, then engage your core and slowly lift your knees back to the starting position. Repeat the movement to the other side. Continue alternating sides for the desired number of repetitions.', NULL, 'obliques', '["obliques","hip flexors"]', '["Lie flat on your back with your knees bent and feet flat on the ground.","Extend your arms out to the sides, perpendicular to your body.","Keeping your knees together, slowly lower them to one side, aiming to touch the ground with your knees.","Pause for a moment, then engage your core and slowly lift your knees back to the starting position.","Repeat the movement to the other side.","Continue alternating sides for the desired number of repetitions."]', '["Lege dich flach auf den Rücken, die Knie gebeugt und die Füsse flach auf dem Boden.","Strecke deine Arme seitlich aus, im rechten Winkel zu deinem Körper.","Halte deine Knie zusammen und senke sie langsam zu einer Seite ab, bis sie den Boden berühren.","Halte kurz inne, spanne dann deine Körpermitte an und hebe deine Knie langsam zurück in die Ausgangsposition.","Wiederhole die Bewegung zur anderen Seite.","Wechsle die Seiten weiter ab, für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/3639.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/3639.gif', 1784612222128, 1784612222128, 0),
  ('afc31291-83a7-5543-81fe-1947a8251fdc', NULL, 'Biceps Leg Concentration Curl', 'Bizeps-Konzentrationscurl', 'upper arms', 'biceps', 'body weight', 'Sit on a bench with your legs spread apart and your feet flat on the ground. Hold a dumbbell in one hand and place your elbow on the inside of your thigh, just above the knee. With your palm facing up, curl the dumbbell towards your shoulder while keeping your upper arm stationary. Squeeze your biceps at the top of the movement, then slowly lower the dumbbell back to the starting position. Repeat for the desired number of repetitions, then switch arms.', NULL, 'forearms', '["forearms"]', '["Sit on a bench with your legs spread apart and your feet flat on the ground.","Hold a dumbbell in one hand and place your elbow on the inside of your thigh, just above the knee.","With your palm facing up, curl the dumbbell towards your shoulder while keeping your upper arm stationary.","Squeeze your biceps at the top of the movement, then slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."]', '["Setze dich auf eine Bank, die Beine gespreizt und die Füsse flach auf dem Boden.","Halte eine Kurzhantel in einer Hand und stütze deinen Ellbogen an der Innenseite deines Oberschenkels, knapp über dem Knie, ab.","Mit nach oben zeigender Handfläche ziehst du die Kurzhantel in Richtung Schulter, während dein Oberarm ruhig bleibt.","Spanne deinen Bizeps am oberen Punkt der Bewegung an und senke die Kurzhantel dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dann die Seite."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1770.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1770.gif', 1784612222128, 1784612222128, 0),
  ('0712f89f-adb3-568f-9095-c2c7263b2d93', NULL, 'Biceps Narrow Pull-ups', 'Klimmzüge eng (Bizeps)', 'upper arms', 'biceps', 'body weight', 'Hang from a pull-up bar with your palms facing towards you and your hands shoulder-width apart. Engage your core and pull yourself up towards the bar, focusing on using your biceps to lift your body. Pause for a moment at the top, then slowly lower yourself back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'forearms', '["forearms","shoulders"]', '["Hang from a pull-up bar with your palms facing towards you and your hands shoulder-width apart.","Engage your core and pull yourself up towards the bar, focusing on using your biceps to lift your body.","Pause for a moment at the top, then slowly lower yourself back down to the starting position.","Repeat for the desired number of repetitions."]', '["Hänge dich an eine Klimmzugstange, die Handflächen zeigen zu dir, die Hände schulterbreit.","Spanne deine Körpermitte an und ziehe dich zur Stange hoch, konzentriere dich darauf, deinen Körper mit dem Bizeps zu heben.","Halte oben kurz inne und senke dich dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0139.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0139.gif', 1784612222128, 1784612222128, 0),
  ('8c1591b4-d0fb-586b-b56d-49ce9a4029a0', NULL, 'Biceps Pull-up', 'Klimmzug (Bizeps)', 'upper arms', 'biceps', 'body weight', 'Hang from a pull-up bar with your palms facing away from you and your hands shoulder-width apart. Engage your core and pull yourself up by bending your elbows, bringing your chest towards the bar. Pause at the top of the movement, then slowly lower yourself back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'forearms', '["forearms","shoulders"]', '["Hang from a pull-up bar with your palms facing away from you and your hands shoulder-width apart.","Engage your core and pull yourself up by bending your elbows, bringing your chest towards the bar.","Pause at the top of the movement, then slowly lower yourself back down to the starting position.","Repeat for the desired number of repetitions."]', '["Hänge dich an eine Klimmzugstange, die Handflächen zeigen von dir weg, die Hände schulterbreit.","Spanne deine Körpermitte an und ziehe dich hoch, indem du deine Ellbogen beugst und deine Brust zur Stange bringst.","Halte am oberen Punkt der Bewegung kurz inne und senke dich dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0140.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0140.gif', 1784612222128, 1784612222128, 0),
  ('39cd0c3a-8a28-54e6-a316-bc8344d9d4b8', NULL, 'Body-up', 'Body-up (Trizeps-Bodendip)', 'upper arms', 'triceps', 'body weight', 'Start by placing your hands on a raised surface, such as a bench or parallel bars, with your palms facing down and fingers pointing forward. Extend your legs out in front of you, keeping your heels on the ground and your body straight. Lower your body by bending your elbows, keeping them close to your sides, until your upper arms are parallel to the ground. Pause for a moment, then push through your palms to straighten your arms and lift your body back up to the starting position. Repeat for the desired number of repetitions.', NULL, 'chest', '["chest","shoulders"]', '["Start by placing your hands on a raised surface, such as a bench or parallel bars, with your palms facing down and fingers pointing forward.","Extend your legs out in front of you, keeping your heels on the ground and your body straight.","Lower your body by bending your elbows, keeping them close to your sides, until your upper arms are parallel to the ground.","Pause for a moment, then push through your palms to straighten your arms and lift your body back up to the starting position.","Repeat for the desired number of repetitions."]', '["Platziere deine Hände auf einer erhöhten Fläche, etwa einer Bank oder Barren, die Handflächen nach unten und die Finger nach vorne zeigend.","Strecke deine Beine vor dir aus, die Fersen bleiben am Boden und dein Körper bleibt gerade.","Senke deinen Körper ab, indem du deine Ellbogen beugst und eng am Körper hältst, bis deine Oberarme parallel zum Boden sind.","Halte kurz inne, drücke dich dann über die Handflächen ab, um deine Arme zu strecken und deinen Körper zurück in die Ausgangsposition zu heben.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0137.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0137.gif', 1784612222128, 1784612222128, 0);

INSERT OR REPLACE INTO exercises (id, user_id, name, name_de, category, primary_muscle, equipment, instructions_en, instructions_de, muscle_group, secondary_muscles, instruction_steps_en, instruction_steps_de, thumbnail_url, gif_url, created_at, updated_at, deleted) VALUES
  ('b7e26766-e6bb-515e-b9e8-3f696522afee', NULL, 'Bodyweight Drop Jump Squat', 'Drop-Jump-Kniebeuge', 'upper legs', 'glutes', 'body weight', 'Stand with your feet shoulder-width apart. Lower your body into a squat position by bending your knees and pushing your hips back. Jump up explosively, extending your hips, knees, and ankles. While in mid-air, quickly bring your feet together. Land softly on the balls of your feet and immediately drop back into a squat position. Repeat for the desired number of repetitions.', NULL, 'quadriceps', '["quadriceps","hamstrings","calves"]', '["Stand with your feet shoulder-width apart.","Lower your body into a squat position by bending your knees and pushing your hips back.","Jump up explosively, extending your hips, knees, and ankles.","While in mid-air, quickly bring your feet together.","Land softly on the balls of your feet and immediately drop back into a squat position.","Repeat for the desired number of repetitions."]', '["Stehe mit schulterbreit auseinander stehenden Füssen.","Senke deinen Körper in die Hocke ab, indem du die Knie beugst und die Hüfte nach hinten schiebst.","Springe explosiv nach oben und strecke dabei Hüfte, Knie und Knöchel durch.","Bringe deine Füsse in der Luft schnell zusammen.","Lande weich auf den Fussballen und gehe sofort wieder in die Hocke.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/3543.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/3543.gif', 1784612222128, 1784612222128, 0),
  ('7cbb66a9-6ea9-520e-9df3-5eca48db51ce', NULL, 'Bodyweight Incline Side Plank', 'Seitplank erhöht', 'waist', 'abs', 'body weight', 'Start by lying on your side with your legs extended and stacked on top of each other. Place your forearm on the ground directly below your shoulder, with your elbow bent at a 90-degree angle. Engage your core and lift your hips off the ground, creating a straight line from your head to your feet. Hold this position for the desired amount of time. Lower your hips back down to the ground and repeat on the other side.', NULL, 'obliques', '["obliques","shoulders"]', '["Start by lying on your side with your legs extended and stacked on top of each other.","Place your forearm on the ground directly below your shoulder, with your elbow bent at a 90-degree angle.","Engage your core and lift your hips off the ground, creating a straight line from your head to your feet.","Hold this position for the desired amount of time.","Lower your hips back down to the ground and repeat on the other side."]', '["Lege dich auf die Seite, die Beine gestreckt und übereinander liegend.","Platziere deinen Unterarm direkt unter der Schulter auf dem Boden, der Ellbogen im 90°-Winkel gebeugt.","Spanne deine Körpermitte an und hebe die Hüfte vom Boden ab, sodass eine gerade Linie von Kopf bis Fuss entsteht.","Halte diese Position für die gewünschte Dauer.","Senke die Hüfte zurück zum Boden ab und wiederhole auf der anderen Seite."]', 'https://ascent-api.sweber.workers.dev/media/exercises/3544.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/3544.gif', 1784612222128, 1784612222128, 0),
  ('1d2fba09-b9aa-5c8e-9e1f-1d4912c7972e', NULL, 'Bodyweight Kneeling Triceps Extension', 'Trizepsstrecken kniend', 'upper arms', 'triceps', 'body weight', 'Kneel down on the ground with your knees hip-width apart. Place your hands on the ground in front of you, shoulder-width apart, fingers pointing forward. Extend your legs straight behind you, balancing on your toes and hands, forming a straight line from head to heels. Bend your elbows and lower your upper body towards the ground, keeping your elbows close to your sides. Pause for a moment at the bottom, then push through your hands to straighten your arms and return to the starting position. Repeat for the desired number of repetitions.', NULL, 'shoulders', '["shoulders","chest"]', '["Kneel down on the ground with your knees hip-width apart.","Place your hands on the ground in front of you, shoulder-width apart, fingers pointing forward.","Extend your legs straight behind you, balancing on your toes and hands, forming a straight line from head to heels.","Bend your elbows and lower your upper body towards the ground, keeping your elbows close to your sides.","Pause for a moment at the bottom, then push through your hands to straighten your arms and return to the starting position.","Repeat for the desired number of repetitions."]', '["Knie dich mit hüftbreit auseinanderstehenden Knien auf den Boden.","Platziere deine Hände schulterbreit auseinander vor dir auf dem Boden, die Finger zeigen nach vorne.","Strecke deine Beine gerade nach hinten aus und stütze dich auf Zehen und Händen ab, sodass eine gerade Linie vom Kopf bis zu den Fersen entsteht.","Beuge die Ellbogen und senke deinen Oberkörper Richtung Boden ab, die Ellbogen bleiben nah am Körper.","Halte kurz inne, wenn du unten angekommen bist, und drücke dich dann über die Hände wieder in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1771.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1771.gif', 1784612222128, 1784612222128, 0),
  ('57da9858-0166-525b-8af2-f049d73c3a74', NULL, 'Bodyweight Side Lying Biceps Curl', 'Bizepscurl in Seitlage', 'upper arms', 'biceps', 'body weight', 'Lie on your side with your legs extended and your head supported by your arm. Hold your upper arm against your side and bend your elbow to curl your forearm towards your shoulder. Pause for a moment at the top, then slowly lower your forearm back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'forearms', '["forearms"]', '["Lie on your side with your legs extended and your head supported by your arm.","Hold your upper arm against your side and bend your elbow to curl your forearm towards your shoulder.","Pause for a moment at the top, then slowly lower your forearm back down to the starting position.","Repeat for the desired number of repetitions."]', '["Lege dich auf die Seite, die Beine gestreckt, den Kopf auf deinem Arm abgestützt.","Halte deinen Oberarm eng am Körper und beuge den Ellbogen, um den Unterarm Richtung Schulter anzuheben.","Halte oben kurz inne und senke den Unterarm dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1769.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1769.gif', 1784612222128, 1784612222128, 0),
  ('1973f816-ae53-5127-ba7b-84f418184d71', NULL, 'Bodyweight Squatting Row', 'Rudern in der Hocke', 'back', 'upper back', 'body weight', 'Stand with your feet shoulder-width apart, holding onto a sturdy object or suspension trainer with your arms extended. Lower your body into a squat position, keeping your back straight and your knees behind your toes. From the squat position, pull your body up towards the object or suspension trainer, squeezing your shoulder blades together. Pause for a moment at the top, then slowly lower your body back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","shoulders"]', '["Stand with your feet shoulder-width apart, holding onto a sturdy object or suspension trainer with your arms extended.","Lower your body into a squat position, keeping your back straight and your knees behind your toes.","From the squat position, pull your body up towards the object or suspension trainer, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."]', '["Stehe schulterbreit und halte dich mit gestreckten Armen an einem stabilen Objekt oder Schlingentrainer fest.","Senke deinen Körper in die Hocke ab, halte dabei den Rücken gerade und die Knie hinter den Zehenspitzen.","Ziehe dich aus der Hocke heraus Richtung Objekt oder Schlingentrainer nach oben und ziehe dabei die Schulterblätter zusammen.","Halte oben kurz inne und senke deinen Körper dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/3168.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/3168.gif', 1784612222128, 1784612222128, 0),
  ('a68d45c5-535d-5f87-8f01-86698bca34e3', NULL, 'Bodyweight Squatting Row (with Towel)', 'Rudern in der Hocke mit Handtuch', 'back', 'upper back', 'body weight', 'Stand with your feet shoulder-width apart, holding a towel in front of you with your palms facing down. Bend your knees and lower your body into a squat position, keeping your back straight and your chest up. As you lower into the squat, simultaneously pull the towel towards your chest, squeezing your shoulder blades together. Pause for a moment at the bottom of the squat, then slowly return to the starting position while extending your arms. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","shoulders"]', '["Stand with your feet shoulder-width apart, holding a towel in front of you with your palms facing down.","Bend your knees and lower your body into a squat position, keeping your back straight and your chest up.","As you lower into the squat, simultaneously pull the towel towards your chest, squeezing your shoulder blades together.","Pause for a moment at the bottom of the squat, then slowly return to the starting position while extending your arms.","Repeat for the desired number of repetitions."]', '["Stehe schulterbreit und halte ein Handtuch mit nach unten zeigenden Handflächen vor dir.","Beuge die Knie und senke deinen Körper in die Hocke ab, halte dabei den Rücken gerade und die Brust aufgerichtet.","Ziehe während des Absenkens gleichzeitig das Handtuch Richtung Brust und ziehe die Schulterblätter zusammen.","Halte unten in der Hocke kurz inne und kehre dann langsam in die Ausgangsposition zurück, während du die Arme streckst.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/3167.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/3167.gif', 1784612222128, 1784612222128, 0),
  ('0afcd05c-87a5-5a6d-9aef-3745b9ea20f4', NULL, 'Bodyweight Standing Calf Raise', 'Wadenheben im Stehen', 'lower legs', 'calves', 'body weight', 'Stand with your feet shoulder-width apart, toes pointing forward. Place your hands on a wall or stable surface for balance. Slowly raise your heels off the ground, lifting your body weight onto the balls of your feet. Pause for a moment at the top, then slowly lower your heels back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'ankles', '["ankles","feet"]', '["Stand with your feet shoulder-width apart, toes pointing forward.","Place your hands on a wall or stable surface for balance.","Slowly raise your heels off the ground, lifting your body weight onto the balls of your feet.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."]', '["Stehe mit schulterbreit auseinander stehenden Füssen, die Zehen zeigen nach vorne.","Platziere deine Hände zum Gleichgewicht an einer Wand oder stabilen Fläche.","Hebe deine Fersen langsam vom Boden ab und verlagere dein Körpergewicht auf die Fussballen.","Halte oben kurz inne und senke die Fersen dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1373.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1373.gif', 1784612222128, 1784612222128, 0),
  ('e503d854-34cb-5a29-ab54-b60b647dc871', NULL, 'Bodyweight Standing Close-Grip One Arm Row', 'Einarmiges Rudern eng im Stehen', 'back', 'upper back', 'body weight', 'Stand with your feet shoulder-width apart, knees slightly bent, and hold a dumbbell in one hand with a neutral grip. Bend forward at the hips, keeping your back straight and your core engaged. Pull the dumbbell up towards your chest, keeping your elbow close to your body and squeezing your shoulder blades together. Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position. Repeat for the desired number of repetitions, then switch sides.', NULL, 'biceps', '["biceps","forearms"]', '["Stand with your feet shoulder-width apart, knees slightly bent, and hold a dumbbell in one hand with a neutral grip.","Bend forward at the hips, keeping your back straight and your core engaged.","Pull the dumbbell up towards your chest, keeping your elbow close to your body and squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position.","Repeat for the desired number of repetitions, then switch sides."]', '["Stehe schulterbreit, die Knie leicht gebeugt, und halte eine Kurzhantel mit neutralem Griff in einer Hand.","Beuge dich in der Hüfte nach vorne, halte dabei den Rücken gerade und die Körpermitte angespannt.","Ziehe die Kurzhantel Richtung Brust nach oben, halte den Ellbogen nah am Körper und ziehe die Schulterblätter zusammen.","Halte oben kurz inne und senke die Kurzhantel dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dann die Seite."]', 'https://ascent-api.sweber.workers.dev/media/exercises/3156.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/3156.gif', 1784612222128, 1784612222128, 0),
  ('12d805d5-28c6-567a-bf59-544c28fbe7f7', NULL, 'Bodyweight Standing Close-Grip Row', 'Rudern eng im Stehen', 'back', 'upper back', 'body weight', 'Stand with your feet shoulder-width apart and knees slightly bent. Bend forward at the waist, keeping your back straight and your core engaged. Extend your arms straight in front of you, gripping the bar or handles with a close grip. Pull the bar or handles towards your body, squeezing your shoulder blades together. Pause for a moment at the top of the movement, then slowly release and return to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","forearms"]', '["Stand with your feet shoulder-width apart and knees slightly bent.","Bend forward at the waist, keeping your back straight and your core engaged.","Extend your arms straight in front of you, gripping the bar or handles with a close grip.","Pull the bar or handles towards your body, squeezing your shoulder blades together.","Pause for a moment at the top of the movement, then slowly release and return to the starting position.","Repeat for the desired number of repetitions."]', '["Stehe schulterbreit, die Knie leicht gebeugt.","Beuge dich in der Hüfte nach vorne, halte dabei den Rücken gerade und die Körpermitte angespannt.","Strecke deine Arme gerade vor dir aus und greife die Stange oder die Griffe eng.","Ziehe die Stange oder die Griffe Richtung Körper und ziehe dabei die Schulterblätter zusammen.","Halte am oberen Ende der Bewegung kurz inne und löse die Spannung dann langsam, um in die Ausgangsposition zurückzukehren.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/3158.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/3158.gif', 1784612222128, 1784612222128, 0),
  ('e33018eb-959e-50be-ae2c-7e2e008b2917', NULL, 'Bodyweight Standing One Arm Row', 'Einarmiges Rudern im Stehen', 'back', 'upper back', 'body weight', 'Stand with your feet shoulder-width apart, knees slightly bent, and hold a dumbbell in one hand. Bend forward at the hips, keeping your back straight and your core engaged. Let the dumbbell hang straight down in front of you, with your arm fully extended. Pull the dumbbell up towards your chest, keeping your elbow close to your body. Squeeze your shoulder blades together at the top of the movement. Lower the dumbbell back down to the starting position. Repeat for the desired number of repetitions, then switch sides.', NULL, 'biceps', '["biceps","forearms"]', '["Stand with your feet shoulder-width apart, knees slightly bent, and hold a dumbbell in one hand.","Bend forward at the hips, keeping your back straight and your core engaged.","Let the dumbbell hang straight down in front of you, with your arm fully extended.","Pull the dumbbell up towards your chest, keeping your elbow close to your body.","Squeeze your shoulder blades together at the top of the movement.","Lower the dumbbell back down to the starting position.","Repeat for the desired number of repetitions, then switch sides."]', '["Stehe schulterbreit, die Knie leicht gebeugt, und halte eine Kurzhantel in einer Hand.","Beuge dich in der Hüfte nach vorne, halte dabei den Rücken gerade und die Körpermitte angespannt.","Lass die Kurzhantel mit gestrecktem Arm gerade vor dir herunterhängen.","Ziehe die Kurzhantel Richtung Brust nach oben, halte den Ellbogen nah am Körper.","Ziehe am oberen Ende der Bewegung die Schulterblätter zusammen.","Senke die Kurzhantel zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dann die Seite."]', 'https://ascent-api.sweber.workers.dev/media/exercises/3162.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/3162.gif', 1784612222128, 1784612222128, 0),
  ('6bacc613-df37-521b-8cff-5f40a087a4f9', NULL, 'Bodyweight Standing One Arm Row (with Towel)', 'Einarmiges Rudern im Stehen mit Handtuch', 'back', 'upper back', 'body weight', 'Stand with your feet shoulder-width apart, knees slightly bent, and hold a towel with one hand. Bend forward at the hips, keeping your back straight and your core engaged. Pull the towel towards your chest, squeezing your shoulder blades together. Pause for a moment at the top, then slowly lower the towel back to the starting position. Repeat for the desired number of repetitions, then switch to the other arm.', NULL, 'biceps', '["biceps","forearms"]', '["Stand with your feet shoulder-width apart, knees slightly bent, and hold a towel with one hand.","Bend forward at the hips, keeping your back straight and your core engaged.","Pull the towel towards your chest, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower the towel back to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."]', '["Stehe schulterbreit, die Knie leicht gebeugt, und halte ein Handtuch in einer Hand.","Beuge dich in der Hüfte nach vorne, halte dabei den Rücken gerade und die Körpermitte angespannt.","Ziehe das Handtuch Richtung Brust und ziehe dabei die Schulterblätter zusammen.","Halte oben kurz inne und senke das Handtuch dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dann den Arm."]', 'https://ascent-api.sweber.workers.dev/media/exercises/3161.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/3161.gif', 1784612222128, 1784612222128, 0),
  ('67300da7-6137-5136-8a58-5d857731b755', NULL, 'Bodyweight Standing Row', 'Rudern im Stehen', 'back', 'upper back', 'body weight', 'Stand with your feet shoulder-width apart and knees slightly bent. Grasp a bar or handles with an overhand grip, palms facing down. Keep your back straight and core engaged. Pull the bar or handles towards your body, squeezing your shoulder blades together. Pause for a moment at the top of the movement. Slowly release and extend your arms back to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","shoulders"]', '["Stand with your feet shoulder-width apart and knees slightly bent.","Grasp a bar or handles with an overhand grip, palms facing down.","Keep your back straight and core engaged.","Pull the bar or handles towards your body, squeezing your shoulder blades together.","Pause for a moment at the top of the movement.","Slowly release and extend your arms back to the starting position.","Repeat for the desired number of repetitions."]', '["Stehe schulterbreit, die Knie leicht gebeugt.","Greife eine Stange oder Griffe im Obergriff, die Handflächen zeigen nach unten.","Halte den Rücken gerade und die Körpermitte angespannt.","Ziehe die Stange oder die Griffe Richtung Körper und ziehe dabei die Schulterblätter zusammen.","Halte am oberen Ende der Bewegung kurz inne.","Löse die Spannung langsam und strecke die Arme zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/3166.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/3166.gif', 1784612222128, 1784612222128, 0),
  ('6cc4c064-1d37-5e88-bda1-9b6240368fa8', NULL, 'Bodyweight Standing Row (with Towel)', 'Rudern im Stehen mit Handtuch', 'back', 'upper back', 'body weight', 'Stand with your feet shoulder-width apart and hold a towel in front of you with both hands. Bend your knees slightly and hinge forward at the hips, keeping your back straight. Pull the towel towards your chest, squeezing your shoulder blades together. Pause for a moment at the top, then slowly release the tension and return to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","shoulders"]', '["Stand with your feet shoulder-width apart and hold a towel in front of you with both hands.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Pull the towel towards your chest, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly release the tension and return to the starting position.","Repeat for the desired number of repetitions."]', '["Stehe schulterbreit und halte ein Handtuch mit beiden Händen vor dir.","Beuge die Knie leicht und beuge dich in der Hüfte nach vorne, der Rücken bleibt gerade.","Ziehe das Handtuch Richtung Brust und ziehe dabei die Schulterblätter zusammen.","Halte oben kurz inne und löse die Spannung dann langsam, um in die Ausgangsposition zurückzukehren.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/3165.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/3165.gif', 1784612222128, 1784612222128, 0),
  ('83c8cc8f-d6dd-53ee-b41c-09647aa01dc7', NULL, 'Bottoms-up', 'Beckenheben (Bottoms-up)', 'waist', 'abs', 'body weight', 'Lie flat on your back with your legs extended and your arms by your sides. Bend your knees and bring them towards your chest, keeping your feet off the ground. Engaging your abs, lift your hips off the ground, bringing your knees towards your head. Pause for a moment at the top, then slowly lower your hips back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'obliques', '["obliques","hip flexors"]', '["Lie flat on your back with your legs extended and your arms by your sides.","Bend your knees and bring them towards your chest, keeping your feet off the ground.","Engaging your abs, lift your hips off the ground, bringing your knees towards your head.","Pause for a moment at the top, then slowly lower your hips back down to the starting position.","Repeat for the desired number of repetitions."]', '["Lege dich flach auf den Rücken, die Beine gestreckt und die Arme neben dem Körper.","Beuge die Knie und ziehe sie Richtung Brust, die Füsse bleiben dabei in der Luft.","Spanne die Bauchmuskeln an und hebe die Hüfte vom Boden ab, sodass die Knie Richtung Kopf wandern.","Halte oben kurz inne und senke die Hüfte dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0138.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0138.gif', 1784612222128, 1784612222128, 0),
  ('388bcb62-90d5-5ffa-b0d3-f70d8e7558ee', NULL, 'Box Jump Down with One Leg Stabilization', 'Box Jump Down mit einbeiniger Stabilisation', 'lower legs', 'calves', 'body weight', 'Stand in front of a box or platform with your feet shoulder-width apart. Bend your knees and jump onto the box, landing softly with one foot on the box and the other foot hanging off the edge. Stabilize yourself on the box with the foot that is on it, while keeping the other foot off the ground. Hold this position for a few seconds, engaging your calf muscles to maintain balance. Slowly step down with the foot that is on the box, returning to the starting position. Repeat the exercise with the other leg.', NULL, 'quadriceps', '["quadriceps","hamstrings","glutes"]', '["Stand in front of a box or platform with your feet shoulder-width apart.","Bend your knees and jump onto the box, landing softly with one foot on the box and the other foot hanging off the edge.","Stabilize yourself on the box with the foot that is on it, while keeping the other foot off the ground.","Hold this position for a few seconds, engaging your calf muscles to maintain balance.","Slowly step down with the foot that is on the box, returning to the starting position.","Repeat the exercise with the other leg."]', '["Stehe schulterbreit vor einer Box oder Plattform.","Beuge die Knie und springe auf die Box, lande weich mit einem Fuss auf der Box und dem anderen Fuss über der Kante hängend.","Stabilisiere dich mit dem Fuss auf der Box, während der andere Fuss den Boden nicht berührt.","Halte diese Position einige Sekunden und spanne dabei die Wadenmuskulatur an, um das Gleichgewicht zu halten.","Steige langsam mit dem Fuss auf der Box ab und kehre in die Ausgangsposition zurück.","Wiederhole die Übung mit dem anderen Bein."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1374.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1374.gif', 1784612222128, 1784612222128, 0),
  ('bfa54ce3-799a-53bf-9a6e-bf8f558c6554', NULL, 'Bridge - Mountain Climber (Cross Body)', 'Bridge mit Mountain Climber (überkreuz)', 'waist', 'abs', 'body weight', 'Start in a high plank position with your hands directly under your shoulders and your body in a straight line. Engage your core and lift your right foot off the ground, bringing your right knee towards your left elbow. Return your right foot to the starting position and repeat the movement with your left foot towards your right elbow. Continue alternating sides, moving at a controlled pace. Keep your hips level and avoid lifting your hips too high or sagging them too low. Maintain a steady breathing pattern throughout the exercise. Repeat for the desired number of repetitions.', NULL, 'glutes', '["glutes","quadriceps","hamstrings","shoulders","triceps"]', '["Start in a high plank position with your hands directly under your shoulders and your body in a straight line.","Engage your core and lift your right foot off the ground, bringing your right knee towards your left elbow.","Return your right foot to the starting position and repeat the movement with your left foot towards your right elbow.","Continue alternating sides, moving at a controlled pace.","Keep your hips level and avoid lifting your hips too high or sagging them too low.","Maintain a steady breathing pattern throughout the exercise.","Repeat for the desired number of repetitions."]', '["Starte im hohen Liegestütz mit den Händen direkt unter den Schultern und dem Körper in einer geraden Linie.","Spanne deine Körpermitte an und hebe den rechten Fuss vom Boden ab, führe das rechte Knie Richtung linken Ellbogen.","Bringe den rechten Fuss zurück in die Ausgangsposition und wiederhole die Bewegung mit dem linken Fuss Richtung rechten Ellbogen.","Wechsle kontrolliert die Seiten in gleichmässigem Tempo.","Halte die Hüfte auf gleicher Höhe und vermeide es, sie zu hoch anzuheben oder durchhängen zu lassen.","Atme während der gesamten Übung gleichmässig.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/2466.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/2466.gif', 1784612222128, 1784612222128, 0),
  ('f955bfa1-a841-57d3-87dc-2334a0985758', NULL, 'Burpee', 'Burpee', 'cardio', 'cardiovascular system', 'body weight', 'Start in a standing position with your feet shoulder-width apart. Lower your body into a squat position by bending your knees and placing your hands on the floor in front of you. Kick your feet back into a push-up position. Perform a push-up, keeping your body in a straight line. Jump your feet back into the squat position. Jump up explosively, reaching your arms overhead. Land softly and immediately lower back into a squat position to begin the next repetition.', NULL, 'quadriceps', '["quadriceps","hamstrings","calves","shoulders","chest"]', '["Start in a standing position with your feet shoulder-width apart.","Lower your body into a squat position by bending your knees and placing your hands on the floor in front of you.","Kick your feet back into a push-up position.","Perform a push-up, keeping your body in a straight line.","Jump your feet back into the squat position.","Jump up explosively, reaching your arms overhead.","Land softly and immediately lower back into a squat position to begin the next repetition."]', '["Starte im Stand mit schulterbreit auseinander stehenden Füssen.","Senke deinen Körper in die Hocke ab, indem du die Knie beugst und die Hände vor dir auf den Boden stellst.","Springe mit den Füssen nach hinten in die Liegestützposition.","Führe einen Liegestütz aus, halte dabei den Körper in einer geraden Linie.","Springe mit den Füssen zurück in die Hocke.","Springe explosiv nach oben und strecke dabei die Arme über den Kopf.","Lande weich und gehe sofort wieder in die Hocke, um die nächste Wiederholung zu beginnen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1160.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1160.gif', 1784612222128, 1784612222128, 0),
  ('495b61e0-d615-5784-9151-c808a53658a6', NULL, 'Butt-ups', 'Gesässheben (Butt-ups)', 'waist', 'abs', 'body weight', 'Lie flat on your back with your knees bent and feet flat on the ground. Place your hands by your sides, palms facing down. Engaging your abs, lift your legs off the ground, bringing your knees towards your chest. At the top of the movement, squeeze your abs and pause for a moment. Slowly lower your legs back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'hip flexors', '["hip flexors","lower back"]', '["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands by your sides, palms facing down.","Engaging your abs, lift your legs off the ground, bringing your knees towards your chest.","At the top of the movement, squeeze your abs and pause for a moment.","Slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."]', '["Lege dich flach auf den Rücken, die Knie gebeugt und die Füsse flach auf dem Boden.","Platziere deine Hände neben dem Körper, die Handflächen zeigen nach unten.","Spanne die Bauchmuskeln an und hebe die Beine vom Boden ab, sodass die Knie Richtung Brust wandern.","Spanne am oberen Ende der Bewegung die Bauchmuskeln an und halte kurz inne.","Senke die Beine langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0870.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0870.gif', 1784612222128, 1784612222128, 0),
  ('ddb15a57-e960-5943-838f-4b60cd69d4b0', NULL, 'Butterfly Yoga Pose', 'Schmetterlingssitz (Yoga)', 'upper legs', 'adductors', 'body weight', 'Sit on the floor with your legs extended in front of you. Bend your knees and bring the soles of your feet together, allowing your knees to fall out to the sides. Hold onto your ankles or feet with your hands. Sit up tall and lengthen your spine. Gently press your knees down towards the floor, feeling a stretch in your inner thighs. Hold this position for a few breaths. To release, slowly bring your knees back up and extend your legs.', NULL, 'hamstrings', '["hamstrings","groin"]', '["Sit on the floor with your legs extended in front of you.","Bend your knees and bring the soles of your feet together, allowing your knees to fall out to the sides.","Hold onto your ankles or feet with your hands.","Sit up tall and lengthen your spine.","Gently press your knees down towards the floor, feeling a stretch in your inner thighs.","Hold this position for a few breaths.","To release, slowly bring your knees back up and extend your legs."]', '["Setze dich auf den Boden, die Beine vor dir ausgestreckt.","Beuge die Knie und bringe die Fusssohlen zusammen, lass die Knie dabei zur Seite absinken.","Halte deine Knöchel oder Füsse mit den Händen fest.","Sitze aufrecht und strecke deine Wirbelsäule lang.","Drücke die Knie sanft Richtung Boden und spüre die Dehnung in den Innenseiten der Oberschenkel.","Halte diese Position für einige Atemzüge.","Um zu lösen, bringe die Knie langsam wieder nach oben und strecke die Beine aus."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1494.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1494.gif', 1784612222128, 1784612222128, 0),
  ('d7482cd5-c9ec-500e-866f-b09ea6ef27b9', NULL, 'Cable Alternate Shoulder Press', 'Kabelzug-Schulterdrücken wechselseitig', 'shoulders', 'delts', 'cable', 'Stand with your feet shoulder-width apart and grasp the handles of the cable machine with an overhand grip. Position your hands at shoulder height, with your palms facing forward. Keep your core engaged and your back straight. Press one handle up and forward until your arm is fully extended. Pause for a moment at the top, then slowly lower the handle back to the starting position. Repeat with the other arm. Alternate between arms for the desired number of repetitions.', NULL, 'triceps', '["triceps","upper back"]', '["Stand with your feet shoulder-width apart and grasp the handles of the cable machine with an overhand grip.","Position your hands at shoulder height, with your palms facing forward.","Keep your core engaged and your back straight.","Press one handle up and forward until your arm is fully extended.","Pause for a moment at the top, then slowly lower the handle back to the starting position.","Repeat with the other arm.","Alternate between arms for the desired number of repetitions."]', '["Stehe schulterbreit und greife die Griffe des Kabelzugs im Obergriff.","Positioniere deine Hände auf Schulterhöhe, die Handflächen zeigen nach vorne.","Halte deine Körpermitte angespannt und den Rücken gerade.","Drücke einen Griff nach oben und vorne, bis der Arm vollständig gestreckt ist.","Halte oben kurz inne und senke den Griff dann langsam zurück in die Ausgangsposition ab.","Wiederhole mit dem anderen Arm.","Wechsle die Arme für die gewünschte Anzahl Wiederholungen ab."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0148.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0148.gif', 1784612222128, 1784612222128, 0),
  ('648a2ef3-f471-5d83-b458-1d16c8701fa0', NULL, 'Cable Alternate Triceps Extension', 'Kabelzug-Trizepsstrecken wechselseitig', 'upper arms', 'triceps', 'cable', 'Stand facing the cable machine with your feet shoulder-width apart. Hold the cable handle with your right hand and bring your arm up so that your upper arm is parallel to the ground and your elbow is bent at a 90-degree angle. Keep your upper arm stationary and extend your forearm backward, fully straightening your arm. Pause for a moment, then slowly return to the starting position. Repeat with your left arm. Continue alternating arms for the desired number of repetitions.', NULL, 'shoulders', '["shoulders"]', '["Stand facing the cable machine with your feet shoulder-width apart.","Hold the cable handle with your right hand and bring your arm up so that your upper arm is parallel to the ground and your elbow is bent at a 90-degree angle.","Keep your upper arm stationary and extend your forearm backward, fully straightening your arm.","Pause for a moment, then slowly return to the starting position.","Repeat with your left arm.","Continue alternating arms for the desired number of repetitions."]', '["Stehe schulterbreit vor dem Kabelzug.","Halte den Griff des Kabelzugs mit der rechten Hand und bringe den Arm so nach oben, dass der Oberarm parallel zum Boden ist und der Ellbogen im 90°-Winkel gebeugt ist.","Halte den Oberarm ruhig und strecke den Unterarm nach hinten, bis der Arm vollständig gestreckt ist.","Halte kurz inne und kehre dann langsam in die Ausgangsposition zurück.","Wiederhole mit dem linken Arm.","Wechsle die Arme für die gewünschte Anzahl Wiederholungen ab."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0149.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0149.gif', 1784612222128, 1784612222128, 0),
  ('1c23c15c-9f46-55a9-96e2-c6cb3a8ad1ef', NULL, 'Cable Assisted Inverse Leg Curl', 'Kabelzug-unterstützter Nordic-Hamstring-Curl', 'upper legs', 'hamstrings', 'cable', 'Adjust the cable machine so that the ankle attachment is at the lowest setting. Lie face down on the bench with your legs straight and the ankle attachment secured to your ankles. Hold onto the handles of the bench for stability. Keeping your upper body stationary, exhale and curl your legs up towards your glutes by flexing your knees. Pause for a moment at the top of the movement, squeezing your hamstrings. Inhale and slowly lower your legs back to the starting position. Repeat for the desired number of repetitions.', NULL, 'glutes', '["glutes","calves"]', '["Adjust the cable machine so that the ankle attachment is at the lowest setting.","Lie face down on the bench with your legs straight and the ankle attachment secured to your ankles.","Hold onto the handles of the bench for stability.","Keeping your upper body stationary, exhale and curl your legs up towards your glutes by flexing your knees.","Pause for a moment at the top of the movement, squeezing your hamstrings.","Inhale and slowly lower your legs back to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle den Kabelzug so ein, dass die Knöchelmanschette auf der niedrigsten Position ist.","Lege dich mit dem Gesicht nach unten auf die Bank, die Beine gestreckt und die Knöchelmanschette an deinen Knöcheln befestigt.","Halte dich zur Stabilität an den Griffen der Bank fest.","Halte den Oberkörper ruhig, atme aus und beuge die Beine Richtung Gesäss, indem du die Knie beugst.","Halte am oberen Ende der Bewegung kurz inne und spanne dabei die Beinbeuger an.","Atme ein und senke die Beine langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/3235.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/3235.gif', 1784612222128, 1784612222128, 0),
  ('9c4d165e-5db8-59fd-8367-f985ec4bf502', NULL, 'Cable Bar Lateral Pulldown', 'Kabelzug-Latzug mit Stange', 'back', 'lats', 'cable', 'Adjust the cable pulley to a high position and attach a straight bar. Sit facing the cable machine with your feet flat on the ground and your knees slightly bent. Grasp the bar with an overhand grip, slightly wider than shoulder-width apart. Lean back slightly and keep your chest up, maintaining a slight arch in your lower back. Pull the bar down towards your chest, leading with your elbows and squeezing your shoulder blades together. Pause for a moment at the bottom of the movement, then slowly return the bar to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","rhomboids","rear deltoids"]', '["Adjust the cable pulley to a high position and attach a straight bar.","Sit facing the cable machine with your feet flat on the ground and your knees slightly bent.","Grasp the bar with an overhand grip, slightly wider than shoulder-width apart.","Lean back slightly and keep your chest up, maintaining a slight arch in your lower back.","Pull the bar down towards your chest, leading with your elbows and squeezing your shoulder blades together.","Pause for a moment at the bottom of the movement, then slowly return the bar to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle die Kabelzugrolle auf eine hohe Position und befestige eine gerade Stange.","Setze dich vor den Kabelzug, die Füsse flach auf dem Boden und die Knie leicht gebeugt.","Greife die Stange im Obergriff, etwas breiter als schulterbreit.","Lehne dich leicht zurück und halte die Brust aufgerichtet, mit einer leichten Krümmung im unteren Rücken.","Ziehe die Stange Richtung Brust, führe die Bewegung mit den Ellbogen an und ziehe die Schulterblätter zusammen.","Halte unten kurz inne und führe die Stange dann langsam zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0150.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0150.gif', 1784612222128, 1784612222128, 0),
  ('186429c6-0aaa-523f-bdbd-902a1d007613', NULL, 'Cable Bench Press', 'Kabelzug-Bankdrücken', 'chest', 'pectorals', 'cable', 'Adjust the cable machine to chest height and attach the handles. Stand facing away from the machine with your feet shoulder-width apart. Grasp the handles with an overhand grip and step forward to create tension in the cables. Position your feet firmly on the ground and engage your core. Bend your elbows and bring your hands to shoulder level, keeping your elbows at a 90-degree angle. Push the handles forward, extending your arms fully in front of you. Pause for a moment, then slowly reverse the movement, bringing your hands back to shoulder level. Repeat for the desired number of repetitions.', NULL, 'triceps', '["triceps","shoulders"]', '["Adjust the cable machine to chest height and attach the handles.","Stand facing away from the machine with your feet shoulder-width apart.","Grasp the handles with an overhand grip and step forward to create tension in the cables.","Position your feet firmly on the ground and engage your core.","Bend your elbows and bring your hands to shoulder level, keeping your elbows at a 90-degree angle.","Push the handles forward, extending your arms fully in front of you.","Pause for a moment, then slowly reverse the movement, bringing your hands back to shoulder level.","Repeat for the desired number of repetitions."]', '["Stelle den Kabelzug auf Brusthöhe ein und befestige die Griffe.","Stehe mit dem Rücken zum Gerät, die Füsse schulterbreit auseinander.","Greife die Griffe im Obergriff und mache einen Schritt nach vorne, um Spannung auf die Kabel zu bringen.","Stelle deine Füsse fest auf den Boden und spanne deine Körpermitte an.","Beuge die Ellbogen und bringe die Hände auf Schulterhöhe, die Ellbogen im 90°-Winkel.","Drücke die Griffe nach vorne und strecke die Arme vollständig vor dir aus.","Halte kurz inne und führe die Bewegung dann langsam umgekehrt aus, bis die Hände wieder auf Schulterhöhe sind.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0151.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0151.gif', 1784612222128, 1784612222128, 0),
  ('d0eee880-d699-540b-ad1f-0f512940fc7b', NULL, 'Cable Close Grip Curl', 'Kabelzug-Curl eng', 'upper arms', 'biceps', 'cable', 'Attach a straight bar to a low pulley cable machine. Stand facing the machine with your feet shoulder-width apart and your knees slightly bent. Grasp the bar with an underhand grip, hands shoulder-width apart. Keep your elbows close to your sides and your upper arms stationary throughout the exercise. Exhale and curl the bar up towards your shoulders, contracting your biceps. Pause for a moment at the top of the movement, squeezing your biceps. Inhale and slowly lower the bar back to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', NULL, 'forearms', '["forearms"]', '["Attach a straight bar to a low pulley cable machine.","Stand facing the machine with your feet shoulder-width apart and your knees slightly bent.","Grasp the bar with an underhand grip, hands shoulder-width apart.","Keep your elbows close to your sides and your upper arms stationary throughout the exercise.","Exhale and curl the bar up towards your shoulders, contracting your biceps.","Pause for a moment at the top of the movement, squeezing your biceps.","Inhale and slowly lower the bar back to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."]', '["Befestige eine gerade Stange an einem unteren Kabelzug.","Stehe vor dem Gerät, die Füsse schulterbreit auseinander und die Knie leicht gebeugt.","Greife die Stange im Untergriff, die Hände schulterbreit auseinander.","Halte die Ellbogen nah am Körper und die Oberarme während der gesamten Übung ruhig.","Atme aus und ziehe die Stange Richtung Schultern nach oben, spanne dabei den Bizeps an.","Halte am oberen Ende der Bewegung kurz inne und spanne den Bizeps an.","Atme ein und senke die Stange langsam zurück in die Ausgangsposition ab, strecke dabei die Arme vollständig.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1630.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1630.gif', 1784612222128, 1784612222128, 0),
  ('4b68e98a-99ea-52b4-88a6-43ac6fc42993', NULL, 'Cable Concentration Curl', 'Kabelzug-Konzentrationscurl', 'upper arms', 'biceps', 'cable', 'Sit on a bench or chair with your feet flat on the floor and your knees slightly bent. Hold the cable handle with an underhand grip and rest your elbow against the inside of your thigh. Keeping your upper arm stationary, exhale and curl the cable handle towards your shoulder while contracting your biceps. Pause for a moment at the top of the movement, then inhale and slowly lower the cable handle back to the starting position. Repeat for the desired number of repetitions, then switch arms.', NULL, 'forearms', '["forearms"]', '["Sit on a bench or chair with your feet flat on the floor and your knees slightly bent.","Hold the cable handle with an underhand grip and rest your elbow against the inside of your thigh.","Keeping your upper arm stationary, exhale and curl the cable handle towards your shoulder while contracting your biceps.","Pause for a moment at the top of the movement, then inhale and slowly lower the cable handle back to the starting position.","Repeat for the desired number of repetitions, then switch arms."]', '["Setze dich auf eine Bank oder einen Stuhl, die Füsse flach auf dem Boden und die Knie leicht gebeugt.","Halte den Griff des Kabelzugs im Untergriff und stütze den Ellbogen an der Innenseite deines Oberschenkels ab.","Halte den Oberarm ruhig, atme aus und ziehe den Griff Richtung Schulter, während du den Bizeps anspannst.","Halte am oberen Ende der Bewegung kurz inne, atme ein und senke den Griff dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dann den Arm."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1631.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1631.gif', 1784612222128, 1784612222128, 0),
  ('105534cd-f569-538a-98f5-e3e52c0abd54', NULL, 'Cable Concentration Extension (on Knee)', 'Kabelzug-Trizepsstrecken abgestützt (auf dem Knie)', 'upper arms', 'triceps', 'cable', 'Sit on a bench or chair with your knees bent and feet flat on the ground. Hold the cable handle with your right hand and place your elbow on the inside of your right knee. Extend your arm fully, keeping your elbow stationary and close to your knee. Pause for a moment at the top, then slowly lower your arm back to the starting position. Repeat for the desired number of repetitions, then switch sides.', NULL, 'forearms', '["forearms"]', '["Sit on a bench or chair with your knees bent and feet flat on the ground.","Hold the cable handle with your right hand and place your elbow on the inside of your right knee.","Extend your arm fully, keeping your elbow stationary and close to your knee.","Pause for a moment at the top, then slowly lower your arm back to the starting position.","Repeat for the desired number of repetitions, then switch sides."]', '["Setze dich auf eine Bank oder einen Stuhl, die Knie gebeugt und die Füsse flach auf dem Boden.","Halte den Griff des Kabelzugs mit der rechten Hand und platziere den Ellbogen an der Innenseite deines rechten Knies.","Strecke deinen Arm vollständig durch, der Ellbogen bleibt dabei ruhig und nah am Knie.","Halte oben kurz inne und senke den Arm dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dann die Seite."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0152.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0152.gif', 1784612222128, 1784612222128, 0),
  ('12fa380f-9a91-5696-9c56-cdbe611077ca', NULL, 'Cable Cross-Over Lateral Pulldown', 'Kabelzug-Latzug über Kreuz', 'back', 'lats', 'cable', 'Attach a cable handle to each side of a cable machine at shoulder height. Stand in the middle of the machine with your feet shoulder-width apart. Grasp the handles with an overhand grip and step back to create tension in the cables. Lean forward slightly from the hips, keeping your back straight and your chest up. Pull the handles down and across your body, squeezing your shoulder blades together. Pause for a moment at the bottom of the movement, then slowly return to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","rhomboids","rear deltoids"]', '["Attach a cable handle to each side of a cable machine at shoulder height.","Stand in the middle of the machine with your feet shoulder-width apart.","Grasp the handles with an overhand grip and step back to create tension in the cables.","Lean forward slightly from the hips, keeping your back straight and your chest up.","Pull the handles down and across your body, squeezing your shoulder blades together.","Pause for a moment at the bottom of the movement, then slowly return to the starting position.","Repeat for the desired number of repetitions."]', '["Befestige an beiden Seiten des Kabelzugs auf Schulterhöhe je einen Griff.","Stehe mittig zwischen den Geräten, die Füsse schulterbreit auseinander.","Greife die Griffe im Obergriff und mache einen Schritt zurück, um Spannung auf die Kabel zu bringen.","Beuge dich leicht aus der Hüfte nach vorne, halte dabei den Rücken gerade und die Brust aufgerichtet.","Ziehe die Griffe nach unten und über den Körper, ziehe dabei die Schulterblätter zusammen.","Halte unten kurz inne und kehre dann langsam in die Ausgangsposition zurück.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0153.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0153.gif', 1784612222128, 1784612222128, 0),
  ('dd8a057b-c555-50e0-868d-b5ec34a256db', NULL, 'Cable Cross-Over Reverse Fly', 'Kabelzug-Reverse Fliegende über Kreuz', 'shoulders', 'delts', 'cable', 'Attach a D-handle to each low pulley cable and stand in the middle of the cable crossover machine. Grasp the handles with a pronated grip (palms facing down) and take a step forward, positioning your feet shoulder-width apart. Bend your knees slightly and lean forward at the waist, keeping your back straight and your abs engaged. With your arms extended out to the sides and slightly bent at the elbows, exhale and squeeze your shoulder blades together as you pull the cables back and upward in a reverse fly motion. Pause for a moment at the peak contraction, then inhale and slowly return to the starting position. Repeat for the desired number of repetitions.', NULL, 'rhomboids', '["rhomboids","trapezius"]', '["Attach a D-handle to each low pulley cable and stand in the middle of the cable crossover machine.","Grasp the handles with a pronated grip (palms facing down) and take a step forward, positioning your feet shoulder-width apart.","Bend your knees slightly and lean forward at the waist, keeping your back straight and your abs engaged.","With your arms extended out to the sides and slightly bent at the elbows, exhale and squeeze your shoulder blades together as you pull the cables back and upward in a reverse fly motion.","Pause for a moment at the peak contraction, then inhale and slowly return to the starting position.","Repeat for the desired number of repetitions."]', '["Befestige an jedem unteren Kabelzug einen D-Griff und stelle dich mittig zwischen die Kabelzugtürme.","Greife die Griffe im Pronationsgriff (Handflächen zeigen nach unten) und mache einen Schritt nach vorne, die Füsse schulterbreit auseinander.","Beuge die Knie leicht und beuge dich in der Hüfte nach vorne, halte dabei den Rücken gerade und die Bauchmuskeln angespannt.","Strecke die Arme seitlich aus, die Ellbogen leicht gebeugt, atme aus und ziehe die Kabel in einer Reverse-Fly-Bewegung nach hinten oben, während du die Schulterblätter zusammenziehst.","Halte an der stärksten Anspannung kurz inne, atme ein und kehre langsam in die Ausgangsposition zurück.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0154.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0154.gif', 1784612222128, 1784612222128, 0),
  ('ea43b451-9e2e-5c2a-85ba-a23e734f3b76', NULL, 'Cable Cross-Over Variation', 'Kabelzug-Cross-Over (Variante)', 'chest', 'pectorals', 'cable', 'Adjust the cable pulleys to chest height. Stand in the center of the cable machine with one foot in front of the other. Grasp the handles with your palms facing down and your arms extended out to the sides. Take a step forward, keeping your arms slightly bent. With a slight bend in your elbows, bring your hands together in front of your chest. Pause for a moment, then slowly return your arms back to the starting position. Repeat for the desired number of repetitions.', NULL, 'deltoids', '["deltoids","triceps"]', '["Adjust the cable pulleys to chest height.","Stand in the center of the cable machine with one foot in front of the other.","Grasp the handles with your palms facing down and your arms extended out to the sides.","Take a step forward, keeping your arms slightly bent.","With a slight bend in your elbows, bring your hands together in front of your chest.","Pause for a moment, then slowly return your arms back to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle die Kabelzugrollen auf Brusthöhe ein.","Stehe mittig zwischen den Geräten, ein Fuss vor dem anderen.","Greife die Griffe mit nach unten zeigenden Handflächen und strecke die Arme seitlich aus.","Mache einen Schritt nach vorne, die Arme dabei leicht gebeugt.","Führe die Hände mit leicht gebeugten Ellbogen vor deiner Brust zusammen.","Halte kurz inne und führe die Arme dann langsam zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0155.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0155.gif', 1784612222128, 1784612222128, 0),
  ('a3e3534b-3d4a-5cd5-a3ba-a5b139c8e447', NULL, 'Cable Curl', 'Kabelzug-Curl', 'upper arms', 'biceps', 'cable', 'Stand facing the cable machine with your feet shoulder-width apart. Grasp the cable attachment with an underhand grip, palms facing up. Keep your elbows close to your sides and your upper arms stationary. Exhale and curl the cable attachment towards your shoulders, contracting your biceps. Pause for a moment at the top of the movement, squeezing your biceps. Inhale and slowly lower the cable attachment back to the starting position. Repeat for the desired number of repetitions.', NULL, 'forearms', '["forearms"]', '["Stand facing the cable machine with your feet shoulder-width apart.","Grasp the cable attachment with an underhand grip, palms facing up.","Keep your elbows close to your sides and your upper arms stationary.","Exhale and curl the cable attachment towards your shoulders, contracting your biceps.","Pause for a moment at the top of the movement, squeezing your biceps.","Inhale and slowly lower the cable attachment back to the starting position.","Repeat for the desired number of repetitions."]', '["Stehe schulterbreit vor dem Kabelzug.","Greife den Griff im Untergriff, die Handflächen zeigen nach oben.","Halte die Ellbogen nah am Körper und die Oberarme ruhig.","Atme aus und ziehe den Griff Richtung Schultern, spanne dabei den Bizeps an.","Halte am oberen Ende der Bewegung kurz inne und spanne den Bizeps an.","Atme ein und senke den Griff langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0868.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0868.gif', 1784612222128, 1784612222128, 0),
  ('3756b85c-21fc-58b0-9026-3dfd07e67ee6', NULL, 'Cable Deadlift', 'Kabelzug-Kreuzheben', 'upper legs', 'glutes', 'cable', 'Stand facing the cable machine with your feet shoulder-width apart. Bend at the hips and knees, lowering your torso until your back is parallel to the ground. Grasp the cable handles with an overhand grip, keeping your arms straight and your shoulders back. Engage your glutes and hamstrings to lift the cable handles, extending your hips and standing up straight. Pause for a moment at the top, then slowly lower the cable handles back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'hamstrings', '["hamstrings","quadriceps","lower back"]', '["Stand facing the cable machine with your feet shoulder-width apart.","Bend at the hips and knees, lowering your torso until your back is parallel to the ground.","Grasp the cable handles with an overhand grip, keeping your arms straight and your shoulders back.","Engage your glutes and hamstrings to lift the cable handles, extending your hips and standing up straight.","Pause for a moment at the top, then slowly lower the cable handles back down to the starting position.","Repeat for the desired number of repetitions."]', '["Stehe schulterbreit vor dem Kabelzug.","Beuge dich in Hüfte und Knie, bis dein Oberkörper parallel zum Boden ist.","Greife die Griffe des Kabelzugs im Obergriff, halte die Arme gestreckt und die Schultern zurück.","Spanne Gesäss und Beinbeuger an, um die Griffe hochzuziehen, strecke dabei die Hüfte und richte dich auf.","Halte oben kurz inne und senke die Griffe dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0157.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0157.gif', 1784612222128, 1784612222128, 0),
  ('3c67d783-53c3-5f57-8123-1310fc07c24b', NULL, 'Cable Decline Fly', 'Kabelzug-Fliegende auf der Negativbank', 'chest', 'pectorals', 'cable', 'Adjust the cable machine to a decline position. Stand facing away from the machine with your feet shoulder-width apart. Hold the handles with your palms facing forward and your arms extended straight out in front of you. Keeping a slight bend in your elbows, open your arms out to the sides in a controlled motion. Pause for a moment at the fully extended position, then slowly return to the starting position. Repeat for the desired number of repetitions.', NULL, 'shoulders', '["shoulders","triceps"]', '["Adjust the cable machine to a decline position.","Stand facing away from the machine with your feet shoulder-width apart.","Hold the handles with your palms facing forward and your arms extended straight out in front of you.","Keeping a slight bend in your elbows, open your arms out to the sides in a controlled motion.","Pause for a moment at the fully extended position, then slowly return to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle den Kabelzug auf eine Negativposition ein.","Stehe mit dem Rücken zum Gerät, die Füsse schulterbreit auseinander.","Halte die Griffe mit nach vorne zeigenden Handflächen, die Arme gerade vor dir ausgestreckt.","Öffne die Arme mit leicht gebeugten Ellbogen kontrolliert zur Seite.","Halte in der vollständig geöffneten Position kurz inne und kehre dann langsam in die Ausgangsposition zurück.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0158.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0158.gif', 1784612222128, 1784612222128, 0),
  ('7d46f972-57f7-526d-8b04-e7cc8265db52', NULL, 'Cable Decline One Arm Press', 'Kabelzug-Drücken einarmig auf der Negativbank', 'chest', 'pectorals', 'cable', 'Adjust the cable machine to a decline position. Stand facing away from the machine and grab the handle with one hand. Position yourself with your back against the decline bench and your arm extended straight in front of you. Bend your elbow and lower the handle towards your chest while keeping your upper arm stationary. Pause for a moment at the bottom, then push the handle back up to the starting position. Repeat for the desired number of repetitions, then switch arms.', NULL, 'triceps', '["triceps","shoulders"]', '["Adjust the cable machine to a decline position.","Stand facing away from the machine and grab the handle with one hand.","Position yourself with your back against the decline bench and your arm extended straight in front of you.","Bend your elbow and lower the handle towards your chest while keeping your upper arm stationary.","Pause for a moment at the bottom, then push the handle back up to the starting position.","Repeat for the desired number of repetitions, then switch arms."]', '["Stelle den Kabelzug auf eine Negativposition ein.","Stehe mit dem Rücken zum Gerät und greife den Griff mit einer Hand.","Positioniere dich mit dem Rücken an der Negativbank, den Arm gerade vor dir ausgestreckt.","Beuge den Ellbogen und senke den Griff Richtung Brust ab, der Oberarm bleibt dabei ruhig.","Halte unten kurz inne und drücke den Griff dann zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dann den Arm."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1260.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1260.gif', 1784612222128, 1784612222128, 0),
  ('30238bbc-8a8e-5ed7-b98f-17f11b702ea8', NULL, 'Cable Decline Press', 'Kabelzug-Drücken auf der Negativbank', 'chest', 'pectorals', 'cable', 'Adjust the cable machine to a decline position. Sit on the decline bench facing the cable machine. Grasp the handles with an overhand grip and position them at chest level. Keep your feet flat on the ground and your back firmly against the bench. Exhale and push the handles away from your body, extending your arms fully. Pause for a moment at the end of the movement, squeezing your chest muscles. Inhale and slowly return the handles back to the starting position. Repeat for the desired number of repetitions.', NULL, 'triceps', '["triceps","shoulders"]', '["Adjust the cable machine to a decline position.","Sit on the decline bench facing the cable machine.","Grasp the handles with an overhand grip and position them at chest level.","Keep your feet flat on the ground and your back firmly against the bench.","Exhale and push the handles away from your body, extending your arms fully.","Pause for a moment at the end of the movement, squeezing your chest muscles.","Inhale and slowly return the handles back to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle den Kabelzug auf eine Negativposition ein.","Setze dich auf die Negativbank mit Blick zum Kabelzug.","Greife die Griffe im Obergriff und positioniere sie auf Brusthöhe.","Halte die Füsse flach auf dem Boden und den Rücken fest an der Bank.","Atme aus und drücke die Griffe vom Körper weg, strecke dabei die Arme vollständig durch.","Halte am Ende der Bewegung kurz inne und spanne die Brustmuskulatur an.","Atme ein und führe die Griffe langsam zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1261.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1261.gif', 1784612222128, 1784612222128, 0),
  ('61126fe4-69f4-5026-a757-bc4007b03204', NULL, 'Cable Decline Seated Wide-Grip Row', 'Kabelzug-Rudern weit im Sitzen auf der Negativbank', 'back', 'upper back', 'cable', 'Sit on the decline bench facing the cable machine with your feet securely placed on the footrests. Grasp the cable attachment with a wide overhand grip, palms facing down. Lean back slightly, keeping your back straight and your core engaged. Pull the cable towards your lower chest, squeezing your shoulder blades together. Pause for a moment at the peak of the contraction, then slowly release the cable back to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","forearms"]', '["Sit on the decline bench facing the cable machine with your feet securely placed on the footrests.","Grasp the cable attachment with a wide overhand grip, palms facing down.","Lean back slightly, keeping your back straight and your core engaged.","Pull the cable towards your lower chest, squeezing your shoulder blades together.","Pause for a moment at the peak of the contraction, then slowly release the cable back to the starting position.","Repeat for the desired number of repetitions."]', '["Setze dich auf die Negativbank mit Blick zum Kabelzug, die Füsse fest auf den Fussstützen.","Greife den Griff im breiten Obergriff, die Handflächen zeigen nach unten.","Lehne dich leicht zurück, halte dabei den Rücken gerade und die Körpermitte angespannt.","Ziehe das Kabel Richtung unterer Brust und ziehe dabei die Schulterblätter zusammen.","Halte an der stärksten Anspannung kurz inne und lass das Kabel dann langsam zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0159.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0159.gif', 1784612222128, 1784612222128, 0),
  ('40c7027a-119f-5b70-b489-0a5b3d04c410', NULL, 'Cable Drag Curl', 'Kabelzug-Drag Curl', 'upper arms', 'biceps', 'cable', 'Stand facing a cable machine with your feet shoulder-width apart. Grasp the cable attachment with an underhand grip, palms facing up, and arms fully extended. Keeping your upper arms stationary, exhale and curl the cable attachment towards your shoulders by contracting your biceps. Pause for a moment at the top of the movement, squeezing your biceps. Inhale and slowly lower the cable attachment back to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', NULL, 'forearms', '["forearms"]', '["Stand facing a cable machine with your feet shoulder-width apart.","Grasp the cable attachment with an underhand grip, palms facing up, and arms fully extended.","Keeping your upper arms stationary, exhale and curl the cable attachment towards your shoulders by contracting your biceps.","Pause for a moment at the top of the movement, squeezing your biceps.","Inhale and slowly lower the cable attachment back to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."]', '["Stehe schulterbreit vor dem Kabelzug.","Greife den Griff im Untergriff, die Handflächen zeigen nach oben, die Arme vollständig gestreckt.","Halte die Oberarme ruhig, atme aus und ziehe den Griff Richtung Schultern, indem du den Bizeps anspannst.","Halte am oberen Ende der Bewegung kurz inne und spanne den Bizeps an.","Atme ein und senke den Griff langsam zurück in die Ausgangsposition ab, strecke dabei die Arme vollständig.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1632.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1632.gif', 1784612222128, 1784612222128, 0),
  ('59340b27-4145-5101-997f-21073ebf9c02', NULL, 'Cable Floor Seated Wide-Grip Row', 'Kabelzug-Rudern weit im Sitzen am Boden', 'back', 'upper back', 'cable', 'Sit on the floor with your legs extended and your back straight. Attach a cable handle to a low pulley and position the cable machine behind you. Grasp the handle with a wide overhand grip, palms facing down. Lean back slightly, keeping your back straight and your chest lifted. Pull the handle towards your waist, squeezing your shoulder blades together. Pause for a moment at the top of the movement, then slowly release the handle back to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","forearms"]', '["Sit on the floor with your legs extended and your back straight.","Attach a cable handle to a low pulley and position the cable machine behind you.","Grasp the handle with a wide overhand grip, palms facing down.","Lean back slightly, keeping your back straight and your chest lifted.","Pull the handle towards your waist, squeezing your shoulder blades together.","Pause for a moment at the top of the movement, then slowly release the handle back to the starting position.","Repeat for the desired number of repetitions."]', '["Setze dich auf den Boden, die Beine gestreckt und der Rücken gerade.","Befestige einen Griff an einem unteren Kabelzug und positioniere das Gerät hinter dir.","Greife den Griff im breiten Obergriff, die Handflächen zeigen nach unten.","Lehne dich leicht zurück, halte dabei den Rücken gerade und die Brust aufgerichtet.","Ziehe den Griff Richtung Taille und ziehe dabei die Schulterblätter zusammen.","Halte am oberen Ende der Bewegung kurz inne und lass den Griff dann langsam zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0160.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0160.gif', 1784612222128, 1784612222128, 0),
  ('e4f31c81-8a89-55a3-aa77-7058a6263bf9', NULL, 'Cable Forward Raise', 'Kabelzug-Frontheben', 'shoulders', 'delts', 'cable', 'Stand with your feet shoulder-width apart and your knees slightly bent. Hold the cable handle with an overhand grip, palms facing down, and your arms fully extended in front of you. Keeping your arms straight, raise the cable handle up to shoulder level. Pause for a moment at the top, then slowly lower the cable handle back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'triceps', '["triceps","forearms"]', '["Stand with your feet shoulder-width apart and your knees slightly bent.","Hold the cable handle with an overhand grip, palms facing down, and your arms fully extended in front of you.","Keeping your arms straight, raise the cable handle up to shoulder level.","Pause for a moment at the top, then slowly lower the cable handle back down to the starting position.","Repeat for the desired number of repetitions."]', '["Stehe schulterbreit, die Knie leicht gebeugt.","Halte den Griff des Kabelzugs im Obergriff, die Handflächen zeigen nach unten, die Arme vollständig vor dir gestreckt.","Hebe den Griff mit gestreckten Armen bis auf Schulterhöhe an.","Halte oben kurz inne und senke den Griff dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0161.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0161.gif', 1784612222128, 1784612222128, 0),
  ('693f9b25-0bde-5e64-aadc-936891896559', NULL, 'Cable Front Raise', 'Kabelzug-Frontheben', 'shoulders', 'delts', 'cable', 'Stand with your feet shoulder-width apart and grasp the cable handle with an overhand grip. Keep your back straight and your core engaged. Raise the cable handle in front of you, keeping your arms straight and your palms facing down. Continue lifting until your arms are parallel to the floor. Pause for a moment at the top, then slowly lower the cable handle back to the starting position. Repeat for the desired number of repetitions.', NULL, 'triceps', '["triceps","forearms"]', '["Stand with your feet shoulder-width apart and grasp the cable handle with an overhand grip.","Keep your back straight and your core engaged.","Raise the cable handle in front of you, keeping your arms straight and your palms facing down.","Continue lifting until your arms are parallel to the floor.","Pause for a moment at the top, then slowly lower the cable handle back to the starting position.","Repeat for the desired number of repetitions."]', '["Stehe schulterbreit und greife den Griff des Kabelzugs im Obergriff.","Halte den Rücken gerade und die Körpermitte angespannt.","Hebe den Griff vor dir an, die Arme bleiben gestreckt und die Handflächen zeigen nach unten.","Hebe weiter an, bis die Arme parallel zum Boden sind.","Halte oben kurz inne und senke den Griff dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0162.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0162.gif', 1784612222128, 1784612222128, 0),
  ('ab197ca4-5af5-5948-9264-ccf4e784f52a', NULL, 'Cable Front Shoulder Raise', 'Kabelzug-Frontheben (Schulter)', 'shoulders', 'delts', 'cable', 'Stand with your feet shoulder-width apart and grasp the cable handle with an overhand grip. Keep your back straight and your core engaged. Raise the cable handle in front of you, keeping your arms straight and your palms facing down. Continue lifting until your arms are parallel to the floor. Pause for a moment at the top, then slowly lower the cable handle back to the starting position. Repeat for the desired number of repetitions.', NULL, 'trapezius', '["trapezius","biceps"]', '["Stand with your feet shoulder-width apart and grasp the cable handle with an overhand grip.","Keep your back straight and your core engaged.","Raise the cable handle in front of you, keeping your arms straight and your palms facing down.","Continue lifting until your arms are parallel to the floor.","Pause for a moment at the top, then slowly lower the cable handle back to the starting position.","Repeat for the desired number of repetitions."]', '["Stehe schulterbreit und greife den Griff des Kabelzugs im Obergriff.","Halte den Rücken gerade und die Körpermitte angespannt.","Hebe den Griff vor dir an, die Arme bleiben gestreckt und die Handflächen zeigen nach unten.","Hebe weiter an, bis die Arme parallel zum Boden sind.","Halte oben kurz inne und senke den Griff dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0164.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0164.gif', 1784612222128, 1784612222128, 0),
  ('9fc27034-3416-555f-9729-f2ceae234a16', NULL, 'Cable Hammer Curl (with Rope)', 'Kabelzug-Hammercurl mit Seil', 'upper arms', 'biceps', 'cable', 'Stand upright with your feet shoulder-width apart and a slight bend in your knees. Hold the cable rope attachment with an underhand grip, palms facing each other, and your arms fully extended. Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Continue to raise the cable rope attachment until your biceps are fully contracted and the rope is at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly begin to lower the cable rope attachment back to the starting position. Repeat for the desired number of repetitions.', NULL, 'forearms', '["forearms"]', '["Stand upright with your feet shoulder-width apart and a slight bend in your knees.","Hold the cable rope attachment with an underhand grip, palms facing each other, and your arms fully extended.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the cable rope attachment until your biceps are fully contracted and the rope is at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the cable rope attachment back to the starting position.","Repeat for the desired number of repetitions."]', '["Stehe aufrecht, die Füsse schulterbreit auseinander und die Knie leicht gebeugt.","Halte das Seil des Kabelzugs im Untergriff, die Handflächen zeigen zueinander, die Arme vollständig gestreckt.","Halte die Oberarme ruhig, atme aus und ziehe das Gewicht hoch, während du den Bizeps anspannst.","Hebe das Seil weiter an, bis der Bizeps vollständig angespannt ist und sich das Seil auf Schulterhöhe befindet.","Halte die angespannte Position kurz und spanne dabei den Bizeps an.","Atme ein und senke das Seil langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0165.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0165.gif', 1784612222128, 1784612222128, 0),
  ('04dc4d52-8a7b-590c-a726-73d84f8c07bf', NULL, 'Cable High Pulley Overhead Triceps Extension', 'Kabelzug-Trizepsstrecken über Kopf am oberen Zug', 'upper arms', 'triceps', 'cable', 'Attach a rope to a high pulley and stand facing away from the machine. Grasp the rope with both hands and extend your arms overhead. Keep your elbows close to your head and your upper arms stationary. Slowly lower the rope behind your head by bending your elbows. Pause for a moment, then extend your arms back to the starting position. Repeat for the desired number of repetitions.', NULL, 'shoulders', '["shoulders"]', '["Attach a rope to a high pulley and stand facing away from the machine.","Grasp the rope with both hands and extend your arms overhead.","Keep your elbows close to your head and your upper arms stationary.","Slowly lower the rope behind your head by bending your elbows.","Pause for a moment, then extend your arms back to the starting position.","Repeat for the desired number of repetitions."]', '["Befestige ein Seil an einem hohen Kabelzug und stelle dich mit dem Rücken zur Maschine.","Greife das Seil mit beiden Händen und strecke die Arme über den Kopf.","Halte die Ellbogen nah am Kopf und die Oberarme ruhig.","Senke das Seil langsam hinter den Kopf ab, indem du die Ellbogen beugst.","Halte kurz inne und strecke die Arme dann zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1722.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1722.gif', 1784612222128, 1784612222128, 0),
  ('bf476b0b-6c1b-530b-887a-ee4b75c8f4d9', NULL, 'Cable High Row (Kneeling)', 'Kabelzug-Rudern hoch kniend', 'back', 'upper back', 'cable', 'Attach a straight bar to a cable machine at chest height. Kneel down in front of the cable machine and grab the bar with an overhand grip, hands shoulder-width apart. Sit back on your heels, keeping your back straight and your core engaged. Pull the bar towards your upper abdomen, squeezing your shoulder blades together. Pause for a moment at the top of the movement, then slowly release the bar back to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","shoulders"]', '["Attach a straight bar to a cable machine at chest height.","Kneel down in front of the cable machine and grab the bar with an overhand grip, hands shoulder-width apart.","Sit back on your heels, keeping your back straight and your core engaged.","Pull the bar towards your upper abdomen, squeezing your shoulder blades together.","Pause for a moment at the top of the movement, then slowly release the bar back to the starting position.","Repeat for the desired number of repetitions."]', '["Befestige eine gerade Stange an einem Kabelzug auf Brusthöhe.","Knie dich vor den Kabelzug und greife die Stange im Obergriff, Hände schulterbreit auseinander.","Setze dich auf deine Fersen zurück, halte den Rücken gerade und spanne deine Körpermitte an.","Ziehe die Stange zu deinem oberen Bauch, indem du die Schulterblätter zusammenziehst.","Halte kurz inne am oberen Punkt der Bewegung und führe die Stange dann langsam zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0167.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0167.gif', 1784612222128, 1784612222128, 0),
  ('54c6d6e0-11df-544b-a370-83c488c7ee61', NULL, 'Cable Hip Adduction', 'Kabelzug-Hüftadduktion', 'upper legs', 'adductors', 'cable', 'Attach the ankle cuff to your ankle and stand facing the cable machine. Position yourself far enough away from the machine so that there is tension on the cable. Place your hands on the machine for support. Keeping your leg straight, slowly move your leg across your body towards the midline. Pause for a moment at the end of the movement, then slowly return to the starting position. Repeat for the desired number of repetitions.', NULL, 'glutes', '["glutes","quadriceps"]', '["Attach the ankle cuff to your ankle and stand facing the cable machine.","Position yourself far enough away from the machine so that there is tension on the cable.","Place your hands on the machine for support.","Keeping your leg straight, slowly move your leg across your body towards the midline.","Pause for a moment at the end of the movement, then slowly return to the starting position.","Repeat for the desired number of repetitions."]', '["Befestige die Fussmanschette an deinem Knöchel und stelle dich mit dem Gesicht zum Kabelzug.","Positioniere dich weit genug von der Maschine entfernt, sodass Spannung auf dem Kabel liegt.","Stütze deine Hände zur Unterstützung an der Maschine ab.","Halte das Bein gestreckt und bewege es langsam über deinen Körper zur Körpermitte.","Halte kurz inne am Ende der Bewegung und kehre dann langsam in die Ausgangsposition zurück.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0168.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0168.gif', 1784612222128, 1784612222128, 0),
  ('4ba64e7c-ec5f-5f1f-ae96-9364e71c3c9c', NULL, 'Cable Incline Bench Press', 'Kabelzug-Schrägbankdrücken', 'chest', 'pectorals', 'cable', 'Adjust the bench to a 45-degree incline. Attach the cable handles to the high pulleys. Sit on the bench facing the cable machine with your feet flat on the ground. Grasp the handles with an overhand grip and bring them to shoulder height. Push the handles forward and upward until your arms are fully extended. Pause for a moment, then slowly lower the handles back to the starting position. Repeat for the desired number of repetitions.', NULL, 'deltoids', '["deltoids","triceps"]', '["Adjust the bench to a 45-degree incline.","Attach the cable handles to the high pulleys.","Sit on the bench facing the cable machine with your feet flat on the ground.","Grasp the handles with an overhand grip and bring them to shoulder height.","Push the handles forward and upward until your arms are fully extended.","Pause for a moment, then slowly lower the handles back to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle die Bank auf eine 45-Grad-Schräge ein.","Befestige die Kabelgriffe an den oberen Umlenkrollen.","Setze dich mit dem Gesicht zum Kabelzug auf die Bank, die Füsse flach auf dem Boden.","Greife die Griffe im Obergriff und bringe sie auf Schulterhöhe.","Drücke die Griffe nach vorne oben, bis deine Arme vollständig gestreckt sind.","Halte kurz inne und senke die Griffe dann langsam zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0169.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0169.gif', 1784612222128, 1784612222128, 0),
  ('649ea285-d0f9-5fbb-9719-b6c4ff900abc', NULL, 'Cable Incline Bench Row', 'Kabelzug-Rudern auf der Schrägbank', 'back', 'upper back', 'cable', 'Set up an incline bench at a 45-degree angle and attach a cable handle to the low pulley. Sit on the bench facing the cable machine with your feet flat on the floor and your knees slightly bent. Grasp the cable handle with an overhand grip and extend your arms fully in front of you. Lean forward from your hips while keeping your back straight and your core engaged. Pull the cable handle towards your chest by retracting your shoulder blades and bending your elbows. Squeeze your back muscles at the top of the movement, then slowly extend your arms back to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","rear deltoids"]', '["Set up an incline bench at a 45-degree angle and attach a cable handle to the low pulley.","Sit on the bench facing the cable machine with your feet flat on the floor and your knees slightly bent.","Grasp the cable handle with an overhand grip and extend your arms fully in front of you.","Lean forward from your hips while keeping your back straight and your core engaged.","Pull the cable handle towards your chest by retracting your shoulder blades and bending your elbows.","Squeeze your back muscles at the top of the movement, then slowly extend your arms back to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle eine Schrägbank auf 45 Grad ein und befestige einen Kabelgriff an der unteren Umlenkrolle.","Setze dich mit dem Gesicht zum Kabelzug auf die Bank, die Füsse flach auf dem Boden und die Knie leicht gebeugt.","Greife den Kabelgriff im Obergriff und strecke die Arme vollständig vor dir aus.","Beuge dich aus der Hüfte nach vorne und halte dabei den Rücken gerade und die Körpermitte angespannt.","Ziehe den Kabelgriff zu deiner Brust, indem du die Schulterblätter zusammenziehst und die Ellbogen beugst.","Spanne deine Rückenmuskulatur am oberen Punkt der Bewegung an und strecke die Arme dann langsam zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1318.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1318.gif', 1784612222128, 1784612222128, 0),
  ('55ec71e2-d159-59bd-af17-119d0b30f2eb', NULL, 'Cable Incline Fly', 'Kabelzug-Fliegende auf der Schrägbank', 'chest', 'pectorals', 'cable', 'Adjust the cable machine to a low position and attach the handles. Sit on an incline bench with your back against the pad and feet flat on the floor. Grasp the handles with an overhand grip and extend your arms straight out in front of you. Keeping a slight bend in your elbows, open your arms out to the sides in a controlled motion. Pause for a moment at the fully extended position, then slowly return to the starting position. Repeat for the desired number of repetitions.', NULL, 'deltoids', '["deltoids","triceps"]', '["Adjust the cable machine to a low position and attach the handles.","Sit on an incline bench with your back against the pad and feet flat on the floor.","Grasp the handles with an overhand grip and extend your arms straight out in front of you.","Keeping a slight bend in your elbows, open your arms out to the sides in a controlled motion.","Pause for a moment at the fully extended position, then slowly return to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle den Kabelzug auf eine niedrige Position ein und befestige die Griffe.","Setze dich auf eine Schrägbank, den Rücken an der Polsterung, die Füsse flach auf dem Boden.","Greife die Griffe im Obergriff und strecke die Arme gerade vor dir aus.","Öffne die Arme mit leicht gebeugten Ellbogen kontrolliert zur Seite.","Halte kurz inne in der vollständig gedehnten Position und kehre dann langsam in die Ausgangsposition zurück.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0171.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0171.gif', 1784612222128, 1784612222128, 0),
  ('fb71ea34-c0c8-54b1-af18-eb928bd679aa', NULL, 'Cable Incline Fly (on Stability Ball)', 'Kabelzug-Fliegende schräg auf dem Gymnastikball', 'chest', 'pectorals', 'cable', 'Set up a stability ball at an incline angle. Attach the cable handles to the high pulleys of a cable machine. Sit on the stability ball facing away from the machine, with your feet firmly planted on the ground. Grasp the cable handles with an overhand grip, palms facing forward. Lean forward slightly, keeping your back straight and core engaged. With a controlled motion, bring your arms out to the sides, keeping a slight bend in your elbows. Continue the motion until your arms are parallel to the ground. Pause for a moment, then slowly return to the starting position. Repeat for the desired number of repetitions.', NULL, 'deltoids', '["deltoids","triceps"]', '["Set up a stability ball at an incline angle.","Attach the cable handles to the high pulleys of a cable machine.","Sit on the stability ball facing away from the machine, with your feet firmly planted on the ground.","Grasp the cable handles with an overhand grip, palms facing forward.","Lean forward slightly, keeping your back straight and core engaged.","With a controlled motion, bring your arms out to the sides, keeping a slight bend in your elbows.","Continue the motion until your arms are parallel to the ground.","Pause for a moment, then slowly return to the starting position.","Repeat for the desired number of repetitions."]', '["Positioniere einen Gymnastikball in einer geneigten Ausrichtung.","Befestige die Kabelgriffe an den oberen Umlenkrollen eines Kabelzugs.","Setze dich mit dem Rücken zur Maschine auf den Gymnastikball, die Füsse fest auf dem Boden.","Greife die Kabelgriffe im Obergriff, die Handflächen zeigen nach vorne.","Lehne dich leicht nach vorne, halte den Rücken gerade und spanne deine Körpermitte an.","Führe die Arme mit einer kontrollierten Bewegung und leicht gebeugten Ellbogen zur Seite.","Führe die Bewegung fort, bis deine Arme parallel zum Boden sind.","Halte kurz inne und kehre dann langsam in die Ausgangsposition zurück.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0170.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0170.gif', 1784612222128, 1784612222128, 0),
  ('6cc085cf-266a-5d5f-9f3a-a683bd41b852', NULL, 'Cable Incline Pushdown', 'Kabelzug-Pushdown schräg', 'back', 'lats', 'cable', 'Attach a straight bar to a high pulley cable machine. Stand facing away from the machine with your feet shoulder-width apart. Grasp the bar with an overhand grip, hands slightly wider than shoulder-width apart. Lean forward slightly and keep your back straight. Pull the bar down towards your thighs by extending your elbows. Pause for a moment at the bottom, then slowly return the bar to the starting position. Repeat for the desired number of repetitions.', NULL, 'triceps', '["triceps","shoulders"]', '["Attach a straight bar to a high pulley cable machine.","Stand facing away from the machine with your feet shoulder-width apart.","Grasp the bar with an overhand grip, hands slightly wider than shoulder-width apart.","Lean forward slightly and keep your back straight.","Pull the bar down towards your thighs by extending your elbows.","Pause for a moment at the bottom, then slowly return the bar to the starting position.","Repeat for the desired number of repetitions."]', '["Befestige eine gerade Stange an einem hohen Kabelzug.","Stelle dich mit dem Rücken zur Maschine, die Füsse schulterbreit auseinander.","Greife die Stange im Obergriff, die Hände etwas breiter als schulterbreit.","Lehne dich leicht nach vorne und halte den Rücken gerade.","Ziehe die Stange zu deinen Oberschenkeln, indem du die Ellbogen streckst.","Halte kurz inne am unteren Punkt und führe die Stange dann langsam zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0172.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0172.gif', 1784612222128, 1784612222128, 0);

INSERT OR REPLACE INTO exercises (id, user_id, name, name_de, category, primary_muscle, equipment, instructions_en, instructions_de, muscle_group, secondary_muscles, instruction_steps_en, instruction_steps_de, thumbnail_url, gif_url, created_at, updated_at, deleted) VALUES
  ('ff3e73c2-c8f0-5b94-9a29-928c8aee112a', NULL, 'Cable Incline Triceps Extension', 'Kabelzug-Trizepsstrecken auf der Schrägbank', 'upper arms', 'triceps', 'cable', 'Adjust the cable machine to a low pulley position. Attach a straight bar to the cable. Stand facing away from the machine with your feet shoulder-width apart. Grasp the bar with an overhand grip and extend your arms straight overhead. Lean forward slightly, keeping your back straight and core engaged. Bend your elbows and lower the bar behind your head, keeping your upper arms close to your ears. Pause for a moment, then extend your arms back to the starting position. Repeat for the desired number of repetitions.', NULL, 'shoulders', '["shoulders"]', '["Adjust the cable machine to a low pulley position.","Attach a straight bar to the cable.","Stand facing away from the machine with your feet shoulder-width apart.","Grasp the bar with an overhand grip and extend your arms straight overhead.","Lean forward slightly, keeping your back straight and core engaged.","Bend your elbows and lower the bar behind your head, keeping your upper arms close to your ears.","Pause for a moment, then extend your arms back to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle den Kabelzug auf eine niedrige Umlenkrolle ein.","Befestige eine gerade Stange am Kabel.","Stelle dich mit dem Rücken zur Maschine, die Füsse schulterbreit auseinander.","Greife die Stange im Obergriff und strecke die Arme gerade über den Kopf.","Lehne dich leicht nach vorne, halte den Rücken gerade und spanne deine Körpermitte an.","Beuge die Ellbogen und senke die Stange hinter den Kopf ab, wobei die Oberarme nah an den Ohren bleiben.","Halte kurz inne und strecke die Arme dann zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0173.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0173.gif', 1784612222128, 1784612222128, 0),
  ('f99e1d90-461c-54ee-9ef4-b42a55dd9866', NULL, 'Cable Judo Flip', 'Kabelzug-Judo-Flip (Rumpfrotation)', 'waist', 'abs', 'cable', 'Stand facing the cable machine with your feet shoulder-width apart. Hold the cable handle with both hands at chest level, palms facing down. Engage your core and rotate your torso to the right, pulling the cable across your body. As you rotate, pivot your back foot and allow your hips to rotate naturally. Extend your arms fully and finish the movement by flipping the cable handle over your shoulder. Return to the starting position by reversing the movement, rotating your torso back to the center. Repeat the movement on the opposite side. Continue alternating sides for the desired number of repetitions.', NULL, 'obliques', '["obliques","shoulders"]', '["Stand facing the cable machine with your feet shoulder-width apart.","Hold the cable handle with both hands at chest level, palms facing down.","Engage your core and rotate your torso to the right, pulling the cable across your body.","As you rotate, pivot your back foot and allow your hips to rotate naturally.","Extend your arms fully and finish the movement by flipping the cable handle over your shoulder.","Return to the starting position by reversing the movement, rotating your torso back to the center.","Repeat the movement on the opposite side.","Continue alternating sides for the desired number of repetitions."]', '["Stelle dich mit dem Gesicht zum Kabelzug, die Füsse schulterbreit auseinander.","Halte den Kabelgriff mit beiden Händen auf Brusthöhe, die Handflächen zeigen nach unten.","Spanne deine Körpermitte an und drehe deinen Oberkörper nach rechts, wobei du das Kabel über deinen Körper ziehst.","Drehe dabei deinen hinteren Fuss mit und lass deine Hüfte natürlich mitdrehen.","Strecke die Arme vollständig und beende die Bewegung, indem du den Kabelgriff über deine Schulter führst.","Kehre in die Ausgangsposition zurück, indem du die Bewegung umkehrst und deinen Oberkörper zurück zur Mitte drehst.","Wiederhole die Bewegung auf der Gegenseite.","Wechsle die Seiten fortlaufend für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0174.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0174.gif', 1784612222128, 1784612222128, 0),
  ('3195c59d-2657-5ca2-b9ff-47fe91368670', NULL, 'Cable Kickback', 'Kabelzug-Trizeps-Kickback', 'upper arms', 'triceps', 'cable', 'Stand facing a cable machine with your feet shoulder-width apart. Hold the cable handle with your right hand and step back to create tension in the cable. Bend your knees slightly and hinge forward at the hips, keeping your back straight. Keep your upper arm close to your body and your elbow bent at a 90-degree angle. Extend your forearm backward, straightening your arm fully. Pause for a moment, then slowly return to the starting position. Repeat for the desired number of repetitions, then switch sides.', NULL, 'shoulders', '["shoulders"]', '["Stand facing a cable machine with your feet shoulder-width apart.","Hold the cable handle with your right hand and step back to create tension in the cable.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Keep your upper arm close to your body and your elbow bent at a 90-degree angle.","Extend your forearm backward, straightening your arm fully.","Pause for a moment, then slowly return to the starting position.","Repeat for the desired number of repetitions, then switch sides."]', '["Stelle dich mit dem Gesicht zum Kabelzug, die Füsse schulterbreit auseinander.","Halte den Kabelgriff mit der rechten Hand und trete einen Schritt zurück, um Spannung auf das Kabel zu bringen.","Beuge die Knie leicht und beuge dich aus der Hüfte nach vorne, während du den Rücken gerade hältst.","Halte den Oberarm nah am Körper und den Ellbogen im 90-Grad-Winkel gebeugt.","Strecke den Unterarm nach hinten und strecke den Arm vollständig aus.","Halte kurz inne und kehre dann langsam in die Ausgangsposition zurück.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dann die Seite."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0860.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0860.gif', 1784612222128, 1784612222128, 0),
  ('310e863f-3fdc-57d9-8e65-0e9c946a82f7', NULL, 'Cable Kneeling Crunch', 'Kabelzug-Crunch kniend', 'waist', 'abs', 'cable', 'Attach a rope handle to a high pulley and kneel down facing away from the machine. Hold the rope handle with both hands and place it behind your head, keeping your elbows out to the sides. Keeping your hips stationary, flex your waist and crunch your torso down towards your thighs. Pause for a moment at the bottom, then slowly return to the starting position. Repeat for the desired number of repetitions.', NULL, 'obliques', '["obliques"]', '["Attach a rope handle to a high pulley and kneel down facing away from the machine.","Hold the rope handle with both hands and place it behind your head, keeping your elbows out to the sides.","Keeping your hips stationary, flex your waist and crunch your torso down towards your thighs.","Pause for a moment at the bottom, then slowly return to the starting position.","Repeat for the desired number of repetitions."]', '["Befestige einen Seilgriff an einem hohen Kabelzug und knie dich mit dem Rücken zur Maschine hin.","Halte den Seilgriff mit beiden Händen und platziere ihn hinter deinem Kopf, die Ellbogen zeigen zur Seite.","Halte die Hüfte ruhig, beuge dich in der Taille und rolle deinen Oberkörper nach unten zu den Oberschenkeln.","Halte kurz inne am unteren Punkt und kehre dann langsam in die Ausgangsposition zurück.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0175.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0175.gif', 1784612222128, 1784612222128, 0),
  ('d2e126c1-ec70-5486-bf21-abf217d2d716', NULL, 'Cable Kneeling Rear Delt Row (with Rope) (Male)', 'Kabelzug-Rudern kniend für die hintere Schulter mit Seil (männlich)', 'shoulders', 'delts', 'cable', 'Attach a rope handle to a low cable pulley and kneel down facing the machine. Grasp the rope with a neutral grip (palms facing each other) and extend your arms fully in front of you. Keeping your back straight and core engaged, pull the rope towards your body by retracting your shoulder blades. Squeeze your shoulder blades together at the end of the movement and hold for a brief pause. Slowly release the tension and return to the starting position. Repeat for the desired number of repetitions.', NULL, 'trapezius', '["trapezius","rhomboids","biceps"]', '["Attach a rope handle to a low cable pulley and kneel down facing the machine.","Grasp the rope with a neutral grip (palms facing each other) and extend your arms fully in front of you.","Keeping your back straight and core engaged, pull the rope towards your body by retracting your shoulder blades.","Squeeze your shoulder blades together at the end of the movement and hold for a brief pause.","Slowly release the tension and return to the starting position.","Repeat for the desired number of repetitions."]', '["Befestige einen Seilgriff an einer niedrigen Kabel-Umlenkrolle und knie dich mit dem Gesicht zur Maschine hin.","Greife das Seil im neutralen Griff (Handflächen zueinander) und strecke die Arme vollständig vor dir aus.","Halte den Rücken gerade und die Körpermitte angespannt und ziehe das Seil zu deinem Körper, indem du die Schulterblätter zusammenziehst.","Ziehe die Schulterblätter am Ende der Bewegung zusammen und halte kurz inne.","Löse die Spannung langsam und kehre in die Ausgangsposition zurück.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/3697.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/3697.gif', 1784612222128, 1784612222128, 0),
  ('e5a8c60b-ff48-5d95-b129-871ad25aa5a1', NULL, 'Cable Kneeling Triceps Extension', 'Kabelzug-Trizepsstrecken kniend', 'upper arms', 'triceps', 'cable', 'Attach a rope handle to a high pulley and kneel down facing the cable machine. Grasp the rope with a neutral grip (palms facing each other) and bring your hands to the sides of your head. Keep your elbows close to your head and your upper arms stationary throughout the exercise. Extend your forearms by contracting your triceps until your arms are fully extended. Pause for a moment, then slowly return to the starting position by bending your elbows. Repeat for the desired number of repetitions.', NULL, 'shoulders', '["shoulders"]', '["Attach a rope handle to a high pulley and kneel down facing the cable machine.","Grasp the rope with a neutral grip (palms facing each other) and bring your hands to the sides of your head.","Keep your elbows close to your head and your upper arms stationary throughout the exercise.","Extend your forearms by contracting your triceps until your arms are fully extended.","Pause for a moment, then slowly return to the starting position by bending your elbows.","Repeat for the desired number of repetitions."]', '["Befestige einen Seilgriff an einem hohen Kabelzug und knie dich mit dem Gesicht zur Maschine hin.","Greife das Seil im neutralen Griff (Handflächen zueinander) und bringe die Hände neben deinen Kopf.","Halte die Ellbogen während der gesamten Übung nah am Kopf und die Oberarme ruhig.","Strecke die Unterarme, indem du den Trizeps anspannst, bis die Arme vollständig gestreckt sind.","Halte kurz inne und kehre dann durch Beugen der Ellbogen langsam in die Ausgangsposition zurück.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0176.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0176.gif', 1784612222128, 1784612222128, 0),
  ('104e690b-63bb-5cb1-b2f8-8b7bc5b1374b', NULL, 'Cable Lat Pulldown Full Range of Motion', 'Kabelzug-Latzug voller Bewegungsumfang', 'back', 'lats', 'cable', 'Sit on the lat pulldown machine with your knees positioned under the pads. Grasp the cable bar with an overhand grip, slightly wider than shoulder-width apart. Lean back slightly and keep your chest up, maintaining a slight arch in your lower back. Pull the bar down towards your upper chest, squeezing your shoulder blades together. Pause for a moment at the bottom of the movement, then slowly release the bar back to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","rhomboids","rear deltoids"]', '["Sit on the lat pulldown machine with your knees positioned under the pads.","Grasp the cable bar with an overhand grip, slightly wider than shoulder-width apart.","Lean back slightly and keep your chest up, maintaining a slight arch in your lower back.","Pull the bar down towards your upper chest, squeezing your shoulder blades together.","Pause for a moment at the bottom of the movement, then slowly release the bar back to the starting position.","Repeat for the desired number of repetitions."]', '["Setze dich an die Latzugmaschine, die Knie unter den Polstern fixiert.","Greife die Kabelstange im Obergriff, etwas breiter als schulterbreit.","Lehne dich leicht zurück und halte die Brust hoch, mit einem leichten Hohlkreuz im unteren Rücken.","Ziehe die Stange zu deiner oberen Brust, indem du die Schulterblätter zusammenziehst.","Halte kurz inne am unteren Punkt der Bewegung und führe die Stange dann langsam zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/2330.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/2330.gif', 1784612222128, 1784612222128, 0),
  ('1fef756c-2769-5086-b9b1-4a71d83d0b3d', NULL, 'Cable Lateral Pulldown (with Rope Attachment)', 'Kabelzug-Latzug mit Seil', 'back', 'lats', 'cable', 'Attach a rope attachment to the cable machine at a high position. Stand facing the machine with your feet shoulder-width apart. Grasp the rope with an overhand grip, palms facing each other. Keep your back straight and lean slightly back. Pull the rope down towards your sides, squeezing your shoulder blades together. Pause for a moment at the bottom of the movement. Slowly release the tension and allow the rope to return to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","forearms"]', '["Attach a rope attachment to the cable machine at a high position.","Stand facing the machine with your feet shoulder-width apart.","Grasp the rope with an overhand grip, palms facing each other.","Keep your back straight and lean slightly back.","Pull the rope down towards your sides, squeezing your shoulder blades together.","Pause for a moment at the bottom of the movement.","Slowly release the tension and allow the rope to return to the starting position.","Repeat for the desired number of repetitions."]', '["Befestige einen Seilaufsatz auf einer hohen Position am Kabelzug.","Stelle dich mit dem Gesicht zur Maschine, die Füsse schulterbreit auseinander.","Greife das Seil im Obergriff, die Handflächen zeigen zueinander.","Halte den Rücken gerade und lehne dich leicht zurück.","Ziehe das Seil nach unten zu deinen Seiten, indem du die Schulterblätter zusammenziehst.","Halte kurz inne am unteren Punkt der Bewegung.","Löse die Spannung langsam und lasse das Seil zurück in die Ausgangsposition kehren.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0177.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0177.gif', 1784612222128, 1784612222128, 0),
  ('ee32bbea-746e-59bb-a7d7-388016f4f4ea', NULL, 'Cable Lateral Pulldown with V-Bar', 'Kabelzug-Latzug mit V-Griff', 'back', 'lats', 'cable', 'Sit down on the cable pulldown machine and grab the v-bar attachment with an overhand grip. Adjust the knee pad so that your thighs are secured under it. Keep your back straight and lean back slightly. Pull the v-bar down towards your upper chest while keeping your elbows close to your body. Squeeze your back muscles at the bottom of the movement. Slowly return the v-bar to the starting position and repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","forearms"]', '["Sit down on the cable pulldown machine and grab the v-bar attachment with an overhand grip.","Adjust the knee pad so that your thighs are secured under it.","Keep your back straight and lean back slightly.","Pull the v-bar down towards your upper chest while keeping your elbows close to your body.","Squeeze your back muscles at the bottom of the movement.","Slowly return the v-bar to the starting position and repeat for the desired number of repetitions."]', '["Setze dich an die Latzugmaschine und greife den V-Griff im Obergriff.","Stelle das Beinpolster so ein, dass deine Oberschenkel darunter fixiert sind.","Halte den Rücken gerade und lehne dich leicht zurück.","Ziehe den V-Griff zu deiner oberen Brust, während du die Ellbogen nah am Körper hältst.","Spanne deine Rückenmuskulatur am unteren Punkt der Bewegung an.","Führe den V-Griff langsam zurück in die Ausgangsposition und wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/2616.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/2616.gif', 1784612222128, 1784612222128, 0),
  ('476c3a08-f7e9-56b8-b252-d2bca84aef18', NULL, 'Cable Lateral Raise', 'Kabelzug-Seitheben', 'shoulders', 'delts', 'cable', 'Stand with your feet shoulder-width apart and grasp the cable handles with an overhand grip. Keep your arms straight and your core engaged. Raise your arms out to the sides until they are parallel to the floor. Pause for a moment at the top, then slowly lower your arms back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'traps', '["traps","triceps"]', '["Stand with your feet shoulder-width apart and grasp the cable handles with an overhand grip.","Keep your arms straight and your core engaged.","Raise your arms out to the sides until they are parallel to the floor.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle dich mit schulterbreiten Füssen hin und greife die Kabelgriffe im Obergriff.","Halte die Arme gestreckt und die Körpermitte angespannt.","Hebe die Arme zur Seite an, bis sie parallel zum Boden sind.","Halte kurz inne am oberen Punkt und senke die Arme dann langsam zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0178.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0178.gif', 1784612222128, 1784612222128, 0),
  ('faa46814-6ceb-5874-a2bb-67a637c12faf', NULL, 'Cable Low Fly', 'Kabelzug-Fliegende von unten', 'chest', 'pectorals', 'cable', 'Attach the handles to the low pulleys of a cable machine and select an appropriate weight. Stand in the middle of the machine with your feet shoulder-width apart and a slight bend in your knees. Grasp the handles with an overhand grip and extend your arms out to the sides, keeping a slight bend in your elbows. Maintaining control, slowly bring your arms forward in a sweeping motion, crossing them in front of your body. Pause for a moment at the peak of the movement, feeling the stretch in your chest muscles. Reverse the motion and slowly return your arms to the starting position, keeping tension on your chest muscles throughout. Repeat for the desired number of repetitions.', NULL, 'deltoids', '["deltoids","triceps"]', '["Attach the handles to the low pulleys of a cable machine and select an appropriate weight.","Stand in the middle of the machine with your feet shoulder-width apart and a slight bend in your knees.","Grasp the handles with an overhand grip and extend your arms out to the sides, keeping a slight bend in your elbows.","Maintaining control, slowly bring your arms forward in a sweeping motion, crossing them in front of your body.","Pause for a moment at the peak of the movement, feeling the stretch in your chest muscles.","Reverse the motion and slowly return your arms to the starting position, keeping tension on your chest muscles throughout.","Repeat for the desired number of repetitions."]', '["Befestige die Griffe an den unteren Umlenkrollen eines Kabelzugs und wähle ein passendes Gewicht.","Stelle dich in die Mitte der Maschine, die Füsse schulterbreit auseinander und die Knie leicht gebeugt.","Greife die Griffe im Obergriff und strecke die Arme mit leicht gebeugten Ellbogen zur Seite.","Führe die Arme kontrolliert in einer schwingenden Bewegung nach vorne und kreuze sie vor deinem Körper.","Halte kurz inne am höchsten Punkt der Bewegung und spüre die Dehnung in deiner Brustmuskulatur.","Kehre die Bewegung um und führe die Arme langsam zurück in die Ausgangsposition, wobei die Spannung durchgehend auf der Brustmuskulatur bleibt.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0179.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0179.gif', 1784612222128, 1784612222128, 0),
  ('c118e57a-43d2-5656-b22d-241f1394c44e', NULL, 'Cable Low Seated Row', 'Kabelzug-Rudern im Sitzen tief', 'back', 'upper back', 'cable', 'Sit on the machine with your feet flat on the footrests and your knees slightly bent. Grasp the handles with an overhand grip, palms facing down. Keep your back straight and lean slightly forward, maintaining a slight bend in your elbows. Pull the handles towards your body, squeezing your shoulder blades together. Pause for a moment at the peak of the movement, then slowly release the handles back to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","forearms"]', '["Sit on the machine with your feet flat on the footrests and your knees slightly bent.","Grasp the handles with an overhand grip, palms facing down.","Keep your back straight and lean slightly forward, maintaining a slight bend in your elbows.","Pull the handles towards your body, squeezing your shoulder blades together.","Pause for a moment at the peak of the movement, then slowly release the handles back to the starting position.","Repeat for the desired number of repetitions."]', '["Setze dich an die Maschine, die Füsse flach auf den Fussstützen und die Knie leicht gebeugt.","Greife die Griffe im Obergriff, die Handflächen zeigen nach unten.","Halte den Rücken gerade und lehne dich leicht nach vorne, mit leicht gebeugten Ellbogen.","Ziehe die Griffe zu deinem Körper, indem du die Schulterblätter zusammenziehst.","Halte kurz inne am höchsten Punkt der Bewegung und führe die Griffe dann langsam zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0180.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0180.gif', 1784612222128, 1784612222128, 0),
  ('2c7197d0-5d77-58af-ae03-fe27c4adb92b', NULL, 'Cable Lying Biceps Curl', 'Kabelzug-Bizepscurl im Liegen', 'upper arms', 'biceps', 'cable', 'Attach a straight bar to a low pulley cable machine. Lie face up on a flat bench with your feet flat on the ground. Grasp the bar with an underhand grip, hands shoulder-width apart. Extend your arms fully, keeping your elbows close to your sides. Keeping your upper arms stationary, exhale and curl the bar up towards your shoulders. Pause for a moment at the top, squeezing your biceps. Inhale and slowly lower the bar back to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', NULL, 'forearms', '["forearms"]', '["Attach a straight bar to a low pulley cable machine.","Lie face up on a flat bench with your feet flat on the ground.","Grasp the bar with an underhand grip, hands shoulder-width apart.","Extend your arms fully, keeping your elbows close to your sides.","Keeping your upper arms stationary, exhale and curl the bar up towards your shoulders.","Pause for a moment at the top, squeezing your biceps.","Inhale and slowly lower the bar back to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."]', '["Befestige eine gerade Stange an einem niedrigen Kabelzug.","Lege dich mit dem Rücken auf eine flache Bank, die Füsse flach auf dem Boden.","Greife die Stange im Untergriff, die Hände schulterbreit auseinander.","Strecke die Arme vollständig aus und halte die Ellbogen nah am Körper.","Halte die Oberarme ruhig, atme aus und ziehe die Stange zu deinen Schultern hoch.","Halte kurz inne am oberen Punkt und spanne deinen Bizeps an.","Atme ein und senke die Stange langsam zurück in die Ausgangsposition, die Arme dabei vollständig streckend.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1634.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1634.gif', 1784612222128, 1784612222128, 0),
  ('b08a69e8-61dc-59b5-b745-9c38cb028901', NULL, 'Cable Lying Close-Grip Curl', 'Kabelzug-Curl eng im Liegen', 'upper arms', 'biceps', 'cable', 'Attach a straight bar to a low pulley cable machine. Lie face up on a flat bench with your feet flat on the ground. Grasp the bar with an underhand grip, hands shoulder-width apart. Extend your arms fully, keeping your elbows close to your sides. Keeping your upper arms stationary, curl the bar towards your chest by contracting your biceps. Pause for a moment at the top, squeezing your biceps. Slowly lower the bar back to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', NULL, 'forearms', '["forearms"]', '["Attach a straight bar to a low pulley cable machine.","Lie face up on a flat bench with your feet flat on the ground.","Grasp the bar with an underhand grip, hands shoulder-width apart.","Extend your arms fully, keeping your elbows close to your sides.","Keeping your upper arms stationary, curl the bar towards your chest by contracting your biceps.","Pause for a moment at the top, squeezing your biceps.","Slowly lower the bar back to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."]', '["Befestige eine gerade Stange an einem niedrigen Kabelzug.","Lege dich mit dem Rücken auf eine flache Bank, die Füsse flach auf dem Boden.","Greife die Stange im Untergriff, die Hände schulterbreit auseinander.","Strecke die Arme vollständig aus und halte die Ellbogen nah am Körper.","Halte die Oberarme ruhig und ziehe die Stange durch Anspannen des Bizeps zu deiner Brust hoch.","Halte kurz inne am oberen Punkt und spanne deinen Bizeps an.","Senke die Stange langsam zurück in die Ausgangsposition und strecke die Arme dabei vollständig.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0182.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0182.gif', 1784612222128, 1784612222128, 0),
  ('c4b094ce-91be-5853-8bce-719c4a4531ae', NULL, 'Cable Lying Extension Pullover (with Rope Attachment)', 'Kabelzug-Überzug mit Streckung im Liegen (mit Seil)', 'back', 'lats', 'cable', 'Attach a rope to a cable machine and set the pulley at the highest position. Lie down on a bench with your head towards the cable machine. Hold the rope with both hands and extend your arms straight up above your chest. Keeping your arms straight, slowly lower the rope behind your head while maintaining control. Pause for a moment at the bottom, then slowly raise the rope back to the starting position. Repeat for the desired number of repetitions.', NULL, 'triceps', '["triceps","shoulders"]', '["Attach a rope to a cable machine and set the pulley at the highest position.","Lie down on a bench with your head towards the cable machine.","Hold the rope with both hands and extend your arms straight up above your chest.","Keeping your arms straight, slowly lower the rope behind your head while maintaining control.","Pause for a moment at the bottom, then slowly raise the rope back to the starting position.","Repeat for the desired number of repetitions."]', '["Befestige ein Seil an einem Kabelzug und stelle die Umlenkrolle auf die höchste Position ein.","Lege dich mit dem Kopf zum Kabelzug auf eine Bank.","Halte das Seil mit beiden Händen und strecke die Arme gerade über deine Brust nach oben.","Senke das Seil mit gestreckten Armen kontrolliert hinter deinen Kopf ab.","Halte kurz inne am unteren Punkt und hebe das Seil dann langsam zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0184.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0184.gif', 1784612222128, 1784612222128, 0),
  ('9861032c-b66b-5015-b112-2fa8f12fa2c4', NULL, 'Cable Lying Fly', 'Kabelzug-Fliegende im Liegen', 'chest', 'pectorals', 'cable', 'Attach the handles to the cables and lie flat on a bench with your feet flat on the ground. Hold the handles with your palms facing each other and your arms extended straight above your chest. Keeping a slight bend in your elbows, lower your arms out to the sides in a wide arc until you feel a stretch in your chest. Pause for a moment, then squeeze your chest muscles to bring your arms back to the starting position. Repeat for the desired number of repetitions.', NULL, 'deltoids', '["deltoids","triceps"]', '["Attach the handles to the cables and lie flat on a bench with your feet flat on the ground.","Hold the handles with your palms facing each other and your arms extended straight above your chest.","Keeping a slight bend in your elbows, lower your arms out to the sides in a wide arc until you feel a stretch in your chest.","Pause for a moment, then squeeze your chest muscles to bring your arms back to the starting position.","Repeat for the desired number of repetitions."]', '["Befestige die Griffe an den Kabeln und lege dich flach auf eine Bank, die Füsse flach auf dem Boden.","Halte die Griffe mit zueinander zeigenden Handflächen und strecke die Arme gerade über deiner Brust.","Senke die Arme mit leicht gebeugten Ellbogen in einem weiten Bogen zur Seite ab, bis du eine Dehnung in der Brust spürst.","Halte kurz inne und spanne die Brustmuskulatur an, um die Arme zurück in die Ausgangsposition zu bringen.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0185.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0185.gif', 1784612222128, 1784612222128, 0),
  ('1c28176e-ff26-5a75-b64e-c50fa706c863', NULL, 'Cable Lying Triceps Extension V. 2', 'Kabelzug-Trizepsstrecken im Liegen (Variante 2)', 'upper arms', 'triceps', 'cable', 'Attach a rope handle to a low pulley cable machine. Lie down on a flat bench facing up, with your head towards the cable machine. Grasp the rope handle with both hands, palms facing each other, and extend your arms straight up over your chest. Keeping your upper arms stationary, slowly lower the rope handle towards your forehead by bending your elbows. Pause for a moment at the bottom, then extend your arms back up to the starting position. Repeat for the desired number of repetitions.', NULL, 'shoulders', '["shoulders"]', '["Attach a rope handle to a low pulley cable machine.","Lie down on a flat bench facing up, with your head towards the cable machine.","Grasp the rope handle with both hands, palms facing each other, and extend your arms straight up over your chest.","Keeping your upper arms stationary, slowly lower the rope handle towards your forehead by bending your elbows.","Pause for a moment at the bottom, then extend your arms back up to the starting position.","Repeat for the desired number of repetitions."]', '["Befestige einen Seilgriff an einem niedrigen Kabelzug.","Lege dich mit dem Rücken auf eine flache Bank, den Kopf zum Kabelzug gerichtet.","Greife den Seilgriff mit beiden Händen, die Handflächen zeigen zueinander, und strecke die Arme gerade über deiner Brust nach oben.","Halte die Oberarme ruhig und senke den Seilgriff langsam durch Beugen der Ellbogen zu deiner Stirn ab.","Halte kurz inne am unteren Punkt und strecke die Arme dann zurück nach oben in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0186.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0186.gif', 1784612222128, 1784612222128, 0),
  ('eab9cc77-b98d-5819-9714-acfe47033838', NULL, 'Cable Middle Fly', 'Kabelzug-Fliegende mittig', 'chest', 'pectorals', 'cable', 'Attach cables to both sides of a cable machine at chest height. Stand in the center of the machine with one foot slightly in front of the other. Grasp the handles with an overhand grip and extend your arms out to the sides. Keep a slight bend in your elbows and maintain a slight forward lean. Engage your chest muscles and bring your arms forward in a sweeping motion. Pause for a moment at the center, then slowly return your arms back to the starting position. Repeat for the desired number of repetitions.', NULL, 'deltoids', '["deltoids","triceps"]', '["Attach cables to both sides of a cable machine at chest height.","Stand in the center of the machine with one foot slightly in front of the other.","Grasp the handles with an overhand grip and extend your arms out to the sides.","Keep a slight bend in your elbows and maintain a slight forward lean.","Engage your chest muscles and bring your arms forward in a sweeping motion.","Pause for a moment at the center, then slowly return your arms back to the starting position.","Repeat for the desired number of repetitions."]', '["Befestige an beiden Seiten eines Kabelzugs auf Brusthöhe je ein Kabel.","Stelle dich in die Mitte der Maschine, ein Fuss leicht vor dem anderen.","Greife die Griffe im Obergriff und strecke die Arme zur Seite aus.","Halte die Ellbogen leicht gebeugt und lehne dich leicht nach vorne.","Spanne deine Brustmuskulatur an und führe die Arme in einer schwingenden Bewegung nach vorne.","Halte kurz inne in der Mitte und führe die Arme dann langsam zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0188.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0188.gif', 1784612222128, 1784612222128, 0),
  ('efadc388-2507-595c-9c60-446900616f01', NULL, 'Cable One Arm Bent Over Row', 'Kabelzug-Vorgebeugtes Rudern einarmig', 'back', 'upper back', 'cable', 'Stand facing a cable machine with your feet shoulder-width apart. Bend your knees slightly and hinge forward at the hips, keeping your back straight. Grasp the cable handle with one hand, palm facing inward, and extend your arm fully. Pull the cable handle towards your body, keeping your elbow close to your side, until your hand reaches your lower chest. Pause for a moment, then slowly extend your arm back to the starting position. Repeat for the desired number of repetitions, then switch sides.', NULL, 'biceps', '["biceps","forearms"]', '["Stand facing a cable machine with your feet shoulder-width apart.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Grasp the cable handle with one hand, palm facing inward, and extend your arm fully.","Pull the cable handle towards your body, keeping your elbow close to your side, until your hand reaches your lower chest.","Pause for a moment, then slowly extend your arm back to the starting position.","Repeat for the desired number of repetitions, then switch sides."]', '["Stelle dich mit dem Gesicht zum Kabelzug, die Füsse schulterbreit auseinander.","Beuge die Knie leicht und beuge dich aus der Hüfte nach vorne, während du den Rücken gerade hältst.","Greife den Kabelgriff mit einer Hand, die Handfläche zeigt nach innen, und strecke den Arm vollständig aus.","Ziehe den Kabelgriff zu deinem Körper, den Ellbogen nah am Körper haltend, bis deine Hand deine untere Brust erreicht.","Halte kurz inne und strecke den Arm dann langsam zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dann die Seite."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0189.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0189.gif', 1784612222128, 1784612222128, 0),
  ('5907e457-6cb3-5f90-8da7-c07c8f2024e4', NULL, 'Cable One Arm Curl', 'Kabelzug-Curl einarmig', 'upper arms', 'biceps', 'cable', 'Stand facing the cable machine with your feet shoulder-width apart. Grasp the cable handle with an underhand grip, palm facing up. Keep your elbow close to your side and slowly curl your forearm up towards your shoulder. Pause for a moment at the top, then slowly lower your forearm back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'forearms', '["forearms"]', '["Stand facing the cable machine with your feet shoulder-width apart.","Grasp the cable handle with an underhand grip, palm facing up.","Keep your elbow close to your side and slowly curl your forearm up towards your shoulder.","Pause for a moment at the top, then slowly lower your forearm back down to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle dich mit dem Gesicht zum Kabelzug, die Füsse schulterbreit auseinander.","Greife den Kabelgriff im Untergriff, die Handfläche zeigt nach oben.","Halte den Ellbogen nah am Körper und ziehe deinen Unterarm langsam zur Schulter hoch.","Halte kurz inne am oberen Punkt und senke den Unterarm dann langsam zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0190.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0190.gif', 1784612222128, 1784612222128, 0),
  ('06bc5f32-bc20-51a9-afb1-4bb4b7bc65f8', NULL, 'Cable One Arm Decline Chest Fly', 'Kabelzug-Fliegende einarmig auf der Negativbank', 'chest', 'pectorals', 'cable', 'Attach a D-handle to a low pulley cable machine and set the bench to a decline angle. Lie down on the bench with your head towards the machine and grab the handle with your right hand. Extend your arm straight up above your chest, keeping a slight bend in your elbow. With a controlled motion, lower your arm out to the side until your hand is in line with your shoulder. Pause for a moment, then reverse the motion and bring your arm back to the starting position. Repeat for the desired number of repetitions, then switch to your left arm and repeat the exercise.', NULL, 'shoulders', '["shoulders","triceps"]', '["Attach a D-handle to a low pulley cable machine and set the bench to a decline angle.","Lie down on the bench with your head towards the machine and grab the handle with your right hand.","Extend your arm straight up above your chest, keeping a slight bend in your elbow.","With a controlled motion, lower your arm out to the side until your hand is in line with your shoulder.","Pause for a moment, then reverse the motion and bring your arm back to the starting position.","Repeat for the desired number of repetitions, then switch to your left arm and repeat the exercise."]', '["Befestige einen D-Griff an einem niedrigen Kabelzug und stelle die Bank auf eine Negativ-Neigung ein.","Lege dich mit dem Kopf zur Maschine auf die Bank und greife den Griff mit deiner rechten Hand.","Strecke den Arm gerade über deiner Brust nach oben, mit leicht gebeugtem Ellbogen.","Senke den Arm mit einer kontrollierten Bewegung zur Seite ab, bis deine Hand auf einer Linie mit deiner Schulter ist.","Halte kurz inne, kehre die Bewegung dann um und bringe den Arm zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen, wechsle dann zum linken Arm und wiederhole die Übung."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1262.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1262.gif', 1784612222128, 1784612222128, 0),
  ('81156c1c-bd34-57f7-8d92-852fdf26d2ae', NULL, 'Cable One Arm Fly on Exercise Ball', 'Kabelzug-Fliegende einarmig auf dem Gymnastikball', 'chest', 'pectorals', 'cable', 'Sit on an exercise ball with your feet flat on the ground and your back straight. Hold a cable handle in one hand and extend your arm out to the side, parallel to the ground. Keep your elbow slightly bent and your palm facing forward. Slowly bring your arm across your body, squeezing your chest muscles. Pause for a moment at the end of the movement, then slowly return to the starting position. Repeat for the desired number of repetitions, then switch sides.', NULL, 'deltoids', '["deltoids","triceps"]', '["Sit on an exercise ball with your feet flat on the ground and your back straight.","Hold a cable handle in one hand and extend your arm out to the side, parallel to the ground.","Keep your elbow slightly bent and your palm facing forward.","Slowly bring your arm across your body, squeezing your chest muscles.","Pause for a moment at the end of the movement, then slowly return to the starting position.","Repeat for the desired number of repetitions, then switch sides."]', '["Setze dich auf einen Gymnastikball, die Füsse flach auf dem Boden und der Rücken gerade.","Halte einen Kabelgriff in einer Hand und strecke den Arm parallel zum Boden zur Seite aus.","Halte den Ellbogen leicht gebeugt und die Handfläche nach vorne gerichtet.","Führe den Arm langsam über deinen Körper und spanne dabei die Brustmuskulatur an.","Halte kurz inne am Ende der Bewegung und kehre dann langsam in die Ausgangsposition zurück.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dann die Seite."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1263.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1263.gif', 1784612222128, 1784612222128, 0),
  ('bbdad43f-0800-58b9-b1ce-0bb9f5f85a0c', NULL, 'Cable One Arm Incline Fly on Exercise Ball', 'Kabelzug-Fliegende einarmig schräg auf dem Gymnastikball', 'chest', 'pectorals', 'cable', 'Sit on an exercise ball with your feet flat on the ground and your back against an incline bench. Hold a cable handle in one hand with your arm extended and palm facing inward. Keeping a slight bend in your elbow, slowly lower your arm out to the side until your hand is in line with your shoulder. Pause for a moment, then squeeze your chest muscles to bring your arm back to the starting position. Repeat for the desired number of repetitions, then switch arms.', NULL, 'deltoids', '["deltoids","triceps"]', '["Sit on an exercise ball with your feet flat on the ground and your back against an incline bench.","Hold a cable handle in one hand with your arm extended and palm facing inward.","Keeping a slight bend in your elbow, slowly lower your arm out to the side until your hand is in line with your shoulder.","Pause for a moment, then squeeze your chest muscles to bring your arm back to the starting position.","Repeat for the desired number of repetitions, then switch arms."]', '["Setze dich auf einen Gymnastikball, die Füsse flach auf dem Boden und den Rücken an eine Schrägbank gelehnt.","Halte einen Kabelgriff in einer Hand mit gestrecktem Arm, die Handfläche zeigt nach innen.","Senke den Arm mit leicht gebeugtem Ellbogen langsam zur Seite ab, bis deine Hand auf einer Linie mit deiner Schulter ist.","Halte kurz inne und spanne die Brustmuskulatur an, um den Arm zurück in die Ausgangsposition zu bringen.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dann den Arm."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1264.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1264.gif', 1784612222128, 1784612222128, 0),
  ('202566aa-faf2-5f96-9805-cb37cb4b7145', NULL, 'Cable One Arm Incline Press', 'Kabelzug-Drücken einarmig auf der Schrägbank', 'chest', 'pectorals', 'cable', 'Adjust the cable machine to a low pulley position. Sit on an incline bench facing away from the cable machine. Grasp the handle with one hand and bring it up to shoulder height. Position your feet firmly on the ground and maintain a stable position. Press the handle forward and upward, extending your arm fully. Pause for a moment at the top, then slowly lower the handle back to the starting position. Repeat for the desired number of repetitions, then switch sides.', NULL, 'deltoids', '["deltoids","triceps"]', '["Adjust the cable machine to a low pulley position.","Sit on an incline bench facing away from the cable machine.","Grasp the handle with one hand and bring it up to shoulder height.","Position your feet firmly on the ground and maintain a stable position.","Press the handle forward and upward, extending your arm fully.","Pause for a moment at the top, then slowly lower the handle back to the starting position.","Repeat for the desired number of repetitions, then switch sides."]', '["Stelle den Kabelzug auf eine niedrige Umlenkrolle ein.","Setze dich mit dem Rücken zum Kabelzug auf eine Schrägbank.","Greife den Griff mit einer Hand und bringe ihn auf Schulterhöhe.","Stelle die Füsse fest auf den Boden und halte eine stabile Position.","Drücke den Griff nach vorne oben und strecke dabei den Arm vollständig aus.","Halte kurz inne am oberen Punkt und senke den Griff dann langsam zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dann die Seite."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1265.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1265.gif', 1784612222128, 1784612222128, 0),
  ('ab1ef430-57cb-5d98-b7bd-2b10748d51a0', NULL, 'Cable One Arm Incline Press on Exercise Ball', 'Kabelzug-Drücken einarmig schräg auf dem Gymnastikball', 'chest', 'pectorals', 'cable', 'Sit on an exercise ball with your feet flat on the ground and your back resting against an incline bench. Hold a cable handle in one hand and position your arm at a 90-degree angle with your elbow bent. Press the cable handle forward and upward, extending your arm fully. Pause for a moment at the top, then slowly lower the cable handle back to the starting position. Repeat for the desired number of repetitions, then switch to the other arm.', NULL, 'shoulders', '["shoulders","triceps"]', '["Sit on an exercise ball with your feet flat on the ground and your back resting against an incline bench.","Hold a cable handle in one hand and position your arm at a 90-degree angle with your elbow bent.","Press the cable handle forward and upward, extending your arm fully.","Pause for a moment at the top, then slowly lower the cable handle back to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."]', '["Setze dich auf einen Gymnastikball, die Füsse flach auf dem Boden und den Rücken an eine Schrägbank gelehnt.","Halte einen Kabelgriff in einer Hand und positioniere den Arm im 90-Grad-Winkel mit gebeugtem Ellbogen.","Drücke den Kabelgriff nach vorne oben und strecke dabei den Arm vollständig aus.","Halte kurz inne am oberen Punkt und senke den Kabelgriff dann langsam zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dann zum anderen Arm."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1266.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1266.gif', 1784612222128, 1784612222128, 0),
  ('87ccca02-ef79-52d5-abaa-3b9c43fd3d76', NULL, 'Cable One Arm Lateral Bent-Over', 'Kabelzug-Seitheben einarmig vorgebeugt', 'chest', 'pectorals', 'cable', 'Stand with your feet shoulder-width apart, facing a cable machine. Grasp the handle with one hand and step back to create tension on the cable. Bend forward at the waist, keeping your back straight and your core engaged. Extend your arm out to the side, parallel to the ground, with a slight bend in your elbow. Slowly bring your arm back to the starting position, maintaining control throughout the movement. Repeat for the desired number of repetitions, then switch sides.', NULL, 'deltoids', '["deltoids","trapezius"]', '["Stand with your feet shoulder-width apart, facing a cable machine.","Grasp the handle with one hand and step back to create tension on the cable.","Bend forward at the waist, keeping your back straight and your core engaged.","Extend your arm out to the side, parallel to the ground, with a slight bend in your elbow.","Slowly bring your arm back to the starting position, maintaining control throughout the movement.","Repeat for the desired number of repetitions, then switch sides."]', '["Stelle dich mit schulterbreiten Füssen vor einen Kabelzug.","Greife den Griff mit einer Hand und trete einen Schritt zurück, um Spannung auf das Kabel zu bringen.","Beuge dich in der Taille nach vorne, während du den Rücken gerade hältst und die Körpermitte anspannst.","Strecke den Arm mit leicht gebeugtem Ellbogen parallel zum Boden zur Seite aus.","Führe den Arm langsam zurück in die Ausgangsposition und behalte die Kontrolle während der gesamten Bewegung.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dann die Seite."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0191.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0191.gif', 1784612222128, 1784612222128, 0),
  ('16a64253-82c5-5cfa-8d9f-47b0cabca22c', NULL, 'Cable One Arm Lateral Raise', 'Kabelzug-Seitheben einarmig', 'shoulders', 'delts', 'cable', 'Stand with your feet shoulder-width apart, facing the cable machine. Hold the cable handle with one hand, palm facing down, and stand far enough away from the machine so that there is tension on the cable. Keep your arm straight and slowly raise it out to the side until it is parallel to the ground. Pause for a moment at the top, then slowly lower your arm back down to the starting position. Repeat for the desired number of repetitions, then switch sides.', NULL, 'traps', '["traps","triceps"]', '["Stand with your feet shoulder-width apart, facing the cable machine.","Hold the cable handle with one hand, palm facing down, and stand far enough away from the machine so that there is tension on the cable.","Keep your arm straight and slowly raise it out to the side until it is parallel to the ground.","Pause for a moment at the top, then slowly lower your arm back down to the starting position.","Repeat for the desired number of repetitions, then switch sides."]', '["Stelle dich mit dem Gesicht zum Kabelzug, die Füsse schulterbreit auseinander.","Halte den Kabelgriff mit einer Hand, die Handfläche zeigt nach unten, und stelle dich weit genug von der Maschine entfernt, sodass Spannung auf dem Kabel liegt.","Halte den Arm gestreckt und hebe ihn langsam zur Seite an, bis er parallel zum Boden ist.","Halte kurz inne am oberen Punkt und senke den Arm dann langsam zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dann die Seite."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0192.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0192.gif', 1784612222128, 1784612222128, 0),
  ('6875c0b3-e3c4-5683-80bc-a3f85346ba3f', NULL, 'Cable One Arm Preacher Curl', 'Kabelzug-Preacher Curl einarmig', 'upper arms', 'biceps', 'cable', 'Adjust the cable machine so that the preacher curl pad is at chest height. Stand facing the cable machine with your feet shoulder-width apart. Grasp the cable handle with an underhand grip and position your upper arm against the preacher curl pad. Keep your back straight and your core engaged. Slowly curl the cable handle towards your shoulder, keeping your upper arm against the pad. Pause for a moment at the top of the movement, squeezing your biceps. Slowly lower the cable handle back to the starting position. Repeat for the desired number of repetitions. Switch arms and repeat the exercise.', NULL, 'forearms', '["forearms"]', '["Adjust the cable machine so that the preacher curl pad is at chest height.","Stand facing the cable machine with your feet shoulder-width apart.","Grasp the cable handle with an underhand grip and position your upper arm against the preacher curl pad.","Keep your back straight and your core engaged.","Slowly curl the cable handle towards your shoulder, keeping your upper arm against the pad.","Pause for a moment at the top of the movement, squeezing your biceps.","Slowly lower the cable handle back to the starting position.","Repeat for the desired number of repetitions.","Switch arms and repeat the exercise."]', '["Stelle den Kabelzug so ein, dass das Scott-Pult auf Brusthöhe ist.","Stelle dich mit dem Gesicht zum Kabelzug, die Füsse schulterbreit auseinander.","Greife den Kabelgriff im Untergriff und lege den Oberarm auf das Scott-Pult.","Halte den Rücken gerade und die Körpermitte angespannt.","Ziehe den Kabelgriff langsam zu deiner Schulter, während der Oberarm auf dem Pult bleibt.","Halte kurz inne am oberen Punkt der Bewegung und spanne deinen Bizeps an.","Senke den Kabelgriff langsam zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen.","Wechsle den Arm und wiederhole die Übung."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1633.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1633.gif', 1784612222128, 1784612222128, 0),
  ('e2b9a0ff-7e4b-5ab8-ac3b-72e142239cef', NULL, 'Cable One Arm Press on Exercise Ball', 'Kabelzug-Drücken einarmig auf dem Gymnastikball', 'chest', 'pectorals', 'cable', 'Sit on an exercise ball with your feet flat on the ground and your back straight. Hold a cable handle in one hand and position your arm at chest height, elbow bent. Place your other hand on your hip for stability. Press the cable handle forward, extending your arm fully. Pause for a moment, then slowly return to the starting position. Repeat for the desired number of repetitions, then switch arms.', NULL, 'shoulders', '["shoulders","triceps"]', '["Sit on an exercise ball with your feet flat on the ground and your back straight.","Hold a cable handle in one hand and position your arm at chest height, elbow bent.","Place your other hand on your hip for stability.","Press the cable handle forward, extending your arm fully.","Pause for a moment, then slowly return to the starting position.","Repeat for the desired number of repetitions, then switch arms."]', '["Setze dich auf einen Gymnastikball, die Füsse flach auf dem Boden und der Rücken gerade.","Halte einen Kabelgriff in einer Hand und positioniere den Arm auf Brusthöhe mit gebeugtem Ellbogen.","Stütze die andere Hand zur Stabilisierung auf deiner Hüfte ab.","Drücke den Kabelgriff nach vorne und strecke dabei den Arm vollständig aus.","Halte kurz inne und kehre dann langsam in die Ausgangsposition zurück.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dann den Arm."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1267.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1267.gif', 1784612222128, 1784612222128, 0),
  ('f79a13a5-a449-5353-914e-51921e01a864', NULL, 'Cable One Arm Pulldown', 'Kabelzug-Latzug einarmig', 'back', 'lats', 'cable', 'Attach a single handle to a high pulley cable machine. Stand facing the machine with your feet shoulder-width apart. Grasp the handle with an overhand grip and extend your arm fully. Keep your back straight and your core engaged. Pull the handle down towards your side while keeping your elbow close to your body. Pause for a moment at the bottom of the movement, squeezing your lat muscle. Slowly release the handle back to the starting position. Repeat for the desired number of repetitions. Switch sides and repeat the exercise with the other arm.', NULL, 'biceps', '["biceps","forearms"]', '["Attach a single handle to a high pulley cable machine.","Stand facing the machine with your feet shoulder-width apart.","Grasp the handle with an overhand grip and extend your arm fully.","Keep your back straight and your core engaged.","Pull the handle down towards your side while keeping your elbow close to your body.","Pause for a moment at the bottom of the movement, squeezing your lat muscle.","Slowly release the handle back to the starting position.","Repeat for the desired number of repetitions.","Switch sides and repeat the exercise with the other arm."]', '["Befestige einen einzelnen Griff an einem hohen Kabelzug.","Stelle dich mit dem Gesicht zur Maschine, die Füsse schulterbreit auseinander.","Greife den Griff im Obergriff und strecke den Arm vollständig aus.","Halte den Rücken gerade und die Körpermitte angespannt.","Ziehe den Griff nach unten zu deiner Seite, während du den Ellbogen nah am Körper hältst.","Halte kurz inne am unteren Punkt der Bewegung und spanne deinen Latissimus an.","Löse den Griff langsam zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen.","Wechsle die Seite und wiederhole die Übung mit dem anderen Arm."]', 'https://ascent-api.sweber.workers.dev/media/exercises/3563.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/3563.gif', 1784612222128, 1784612222128, 0),
  ('5b741784-bb78-531a-9928-1a9ec1dca969', NULL, 'Cable One Arm Reverse Preacher Curl', 'Kabelzug-Preacher Curl einarmig im Untergriff', 'upper arms', 'biceps', 'cable', 'Adjust the cable machine so that the pulley is at the lowest position. Stand facing the cable machine with your feet shoulder-width apart. Grasp the cable handle with an underhand grip and position your upper arm against the preacher bench pad. Keep your back straight and your core engaged throughout the exercise. Slowly curl your forearm towards your bicep, keeping your upper arm stationary against the pad. Pause for a moment at the top of the movement, squeezing your bicep. Slowly lower the cable handle back to the starting position. Repeat for the desired number of repetitions. Switch arms and repeat the exercise.', NULL, 'forearms', '["forearms"]', '["Adjust the cable machine so that the pulley is at the lowest position.","Stand facing the cable machine with your feet shoulder-width apart.","Grasp the cable handle with an underhand grip and position your upper arm against the preacher bench pad.","Keep your back straight and your core engaged throughout the exercise.","Slowly curl your forearm towards your bicep, keeping your upper arm stationary against the pad.","Pause for a moment at the top of the movement, squeezing your bicep.","Slowly lower the cable handle back to the starting position.","Repeat for the desired number of repetitions.","Switch arms and repeat the exercise."]', '["Stelle den Kabelzug so ein, dass sich die Umlenkrolle in der niedrigsten Position befindet.","Stelle dich mit dem Gesicht zum Kabelzug, die Füsse schulterbreit auseinander.","Greife den Kabelgriff im Untergriff und lege den Oberarm auf das Polster des Scott-Pults.","Halte den Rücken gerade und die Körpermitte während der gesamten Übung angespannt.","Ziehe deinen Unterarm langsam zum Bizeps hoch, während der Oberarm ruhig auf dem Pult bleibt.","Halte kurz inne am oberen Punkt der Bewegung und spanne deinen Bizeps an.","Senke den Kabelgriff langsam zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen.","Wechsle den Arm und wiederhole die Übung."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1635.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1635.gif', 1784612222128, 1784612222128, 0),
  ('97dde5b9-c157-5ab2-9e87-1bcc29cdb178', NULL, 'Cable One Arm Straight Back High Row (Kneeling)', 'Kabelzug-Rudern hoch einarmig mit geradem Rücken kniend', 'back', 'upper back', 'cable', 'Attach a handle to a cable machine at waist height. Kneel down facing the cable machine and grab the handle with one hand. Keep your back straight and your core engaged. Pull the handle towards your chest, squeezing your shoulder blades together. Pause for a moment at the top of the movement. Slowly release the handle back to the starting position. Repeat for the desired number of repetitions. Switch sides and repeat the exercise with the other arm.', NULL, 'biceps', '["biceps","shoulders"]', '["Attach a handle to a cable machine at waist height.","Kneel down facing the cable machine and grab the handle with one hand.","Keep your back straight and your core engaged.","Pull the handle towards your chest, squeezing your shoulder blades together.","Pause for a moment at the top of the movement.","Slowly release the handle back to the starting position.","Repeat for the desired number of repetitions.","Switch sides and repeat the exercise with the other arm."]', '["Befestige einen Griff an einem Kabelzug auf Hüfthöhe.","Knie dich mit dem Gesicht zum Kabelzug hin und greife den Griff mit einer Hand.","Halte den Rücken gerade und die Körpermitte angespannt.","Ziehe den Griff zu deiner Brust, indem du die Schulterblätter zusammenziehst.","Halte kurz inne am oberen Punkt der Bewegung.","Löse den Griff langsam zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen.","Wechsle die Seite und wiederhole die Übung mit dem anderen Arm."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0193.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0193.gif', 1784612222128, 1784612222128, 0),
  ('111148cc-45b1-5932-9f58-afedaa9ab67b', NULL, 'Cable One Arm Tricep Pushdown', 'Kabelzug-Trizeps-Pushdown einarmig', 'upper arms', 'triceps', 'cable', 'Stand facing a cable machine with a straight bar attachment at chest height. Grasp the bar with an overhand grip and step back to create tension in the cable. Position your feet shoulder-width apart and slightly bend your knees. Keep your back straight and core engaged throughout the exercise. Start with your arm fully extended and perpendicular to the floor. Keeping your upper arm stationary, exhale and push the bar down until your arm is fully extended. Pause for a moment, then inhale and slowly return to the starting position. Repeat for the desired number of repetitions, then switch arms.', NULL, 'forearms', '["forearms"]', '["Stand facing a cable machine with a straight bar attachment at chest height.","Grasp the bar with an overhand grip and step back to create tension in the cable.","Position your feet shoulder-width apart and slightly bend your knees.","Keep your back straight and core engaged throughout the exercise.","Start with your arm fully extended and perpendicular to the floor.","Keeping your upper arm stationary, exhale and push the bar down until your arm is fully extended.","Pause for a moment, then inhale and slowly return to the starting position.","Repeat for the desired number of repetitions, then switch arms."]', '["Stehe vor einem Kabelzug mit einer Stange auf Brusthöhe.","Greife die Stange im Obergriff und trete einen Schritt zurück, um Zug auf das Kabel zu bringen.","Stelle deine Füsse schulterbreit auseinander und beuge die Knie leicht.","Halte den Rücken gerade und die Körpermitte während der ganzen Übung angespannt.","Beginne mit vollständig gestrecktem Arm, senkrecht zum Boden.","Halte den Oberarm ruhig, atme aus und drücke die Stange nach unten, bis dein Arm vollständig gestreckt ist.","Halte kurz inne, atme dann ein und kehre langsam in die Ausgangsposition zurück.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dann die Seite."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1723.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1723.gif', 1784612222128, 1784612222128, 0),
  ('e03aeb8a-e10b-5ecf-b17b-d39de41042e3', NULL, 'Cable Overhead Curl', 'Kabelzug-Curl über Kopf', 'upper arms', 'biceps', 'cable', 'Attach a straight bar to a high pulley cable machine. Stand facing the machine with your feet shoulder-width apart. Grasp the bar with an underhand grip, hands shoulder-width apart. Keep your elbows close to your sides and your upper arms stationary. Exhale and curl the bar down towards your forehead, keeping your upper arms stationary. Pause for a moment at the bottom of the movement, squeezing your biceps. Inhale and slowly return the bar to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', NULL, 'forearms', '["forearms","shoulders"]', '["Attach a straight bar to a high pulley cable machine.","Stand facing the machine with your feet shoulder-width apart.","Grasp the bar with an underhand grip, hands shoulder-width apart.","Keep your elbows close to your sides and your upper arms stationary.","Exhale and curl the bar down towards your forehead, keeping your upper arms stationary.","Pause for a moment at the bottom of the movement, squeezing your biceps.","Inhale and slowly return the bar to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."]', '["Befestige eine Stange an der oberen Umlenkrolle des Kabelzugs.","Stehe mit schulterbreiten Füssen vor dem Gerät.","Greife die Stange im Untergriff, Hände schulterbreit auseinander.","Halte die Ellbogen nah am Körper und die Oberarme ruhig.","Atme aus und ziehe die Stange in Richtung Stirn, während die Oberarme ruhig bleiben.","Halte am unteren Punkt kurz inne und spanne den Bizeps an.","Atme ein und führe die Stange langsam zurück in die Ausgangsposition, bis die Arme vollständig gestreckt sind.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1636.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1636.gif', 1784612222128, 1784612222128, 0),
  ('abcfa637-dac4-5334-a7bd-d4005ec245c3', NULL, 'Cable Overhead Curl on Exercise Ball', 'Kabelzug-Curl über Kopf auf dem Gymnastikball', 'upper arms', 'biceps', 'cable', 'Sit on an exercise ball and hold the cable handle with an underhand grip. Extend your arms fully overhead, keeping your elbows close to your ears. Slowly curl the cable down towards your forehead, keeping your upper arms stationary. Pause for a moment at the bottom of the movement, then slowly return to the starting position. Repeat for the desired number of repetitions.', NULL, 'forearms', '["forearms","shoulders"]', '["Sit on an exercise ball and hold the cable handle with an underhand grip.","Extend your arms fully overhead, keeping your elbows close to your ears.","Slowly curl the cable down towards your forehead, keeping your upper arms stationary.","Pause for a moment at the bottom of the movement, then slowly return to the starting position.","Repeat for the desired number of repetitions."]', '["Setze dich auf einen Gymnastikball und halte den Kabelgriff im Untergriff.","Strecke die Arme vollständig über den Kopf, die Ellbogen nah an den Ohren.","Ziehe das Kabel langsam in Richtung Stirn, während die Oberarme ruhig bleiben.","Halte am unteren Punkt kurz inne und kehre danach langsam in die Ausgangsposition zurück.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1637.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1637.gif', 1784612222128, 1784612222128, 0),
  ('746a1e0f-e26c-5d5b-b28b-fc0d7f020b29', NULL, 'Cable Overhead Triceps Extension (Rope Attachment)', 'Kabelzug-Trizepsstrecken über Kopf (Seilgriff)', 'upper arms', 'triceps', 'cable', 'Attach a rope to a cable machine at a high position. Stand facing away from the machine with your feet shoulder-width apart. Grasp the rope with both hands, palms facing each other, and bring your hands above your head. Keep your upper arms close to your head and your elbows pointing forward. Slowly lower the rope behind your head by bending your elbows. Pause for a moment, then extend your arms back up to the starting position. Repeat for the desired number of repetitions.', NULL, 'shoulders', '["shoulders"]', '["Attach a rope to a cable machine at a high position.","Stand facing away from the machine with your feet shoulder-width apart.","Grasp the rope with both hands, palms facing each other, and bring your hands above your head.","Keep your upper arms close to your head and your elbows pointing forward.","Slowly lower the rope behind your head by bending your elbows.","Pause for a moment, then extend your arms back up to the starting position.","Repeat for the desired number of repetitions."]', '["Befestige ein Seil in hoher Position am Kabelzug.","Stehe mit dem Rücken zum Gerät, Füsse schulterbreit auseinander.","Greife das Seil mit beiden Händen, Handflächen zueinander, und führe die Hände über den Kopf.","Halte die Oberarme nah am Kopf, die Ellbogen zeigen nach vorne.","Senke das Seil langsam hinter den Kopf ab, indem du die Ellbogen beugst.","Halte kurz inne und strecke die Arme zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0194.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0194.gif', 1784612222128, 1784612222128, 0),
  ('3326fe44-0ae1-5120-bb86-2c1c544a35b8', NULL, 'Cable Palm Rotational Row', 'Kabelzug-Rudern mit Handrotation', 'back', 'upper back', 'cable', 'Attach a handle to a cable machine at waist height. Stand facing the machine with your feet shoulder-width apart. Grasp the handle with an overhand grip, palms facing down. Step back to create tension on the cable, keeping your back straight and knees slightly bent. Pull the handle towards your body, rotating your palms to face upwards as you do so. Squeeze your shoulder blades together at the end of the movement. Slowly release the handle back to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","forearms"]', '["Attach a handle to a cable machine at waist height.","Stand facing the machine with your feet shoulder-width apart.","Grasp the handle with an overhand grip, palms facing down.","Step back to create tension on the cable, keeping your back straight and knees slightly bent.","Pull the handle towards your body, rotating your palms to face upwards as you do so.","Squeeze your shoulder blades together at the end of the movement.","Slowly release the handle back to the starting position.","Repeat for the desired number of repetitions."]', '["Befestige einen Griff auf Hüfthöhe am Kabelzug.","Stehe mit schulterbreiten Füssen vor dem Gerät.","Greife den Griff im Obergriff, Handflächen nach unten.","Trete zurück, um Zug auf das Kabel zu bringen, halte dabei den Rücken gerade und die Knie leicht gebeugt.","Ziehe den Griff zum Körper und drehe dabei die Handflächen nach oben.","Ziehe die Schulterblätter am Ende der Bewegung zusammen.","Lass den Griff langsam zurück in die Ausgangsposition gleiten.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1319.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1319.gif', 1784612222128, 1784612222128, 0),
  ('fb4c64a3-33b3-5802-871c-c9a6bcb91690', NULL, 'Cable Preacher Curl', 'Kabelzug-Preacher Curl', 'upper arms', 'biceps', 'cable', 'Adjust the cable machine so that the preacher curl pad is at chest height. Sit on the preacher curl bench and place your upper arms on the pad, gripping the cable attachment with an underhand grip. Keep your back straight and your elbows tucked in at your sides. Slowly curl the cable attachment up towards your shoulders, squeezing your biceps at the top of the movement. Pause for a moment, then slowly lower the cable attachment back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'forearms', '["forearms"]', '["Adjust the cable machine so that the preacher curl pad is at chest height.","Sit on the preacher curl bench and place your upper arms on the pad, gripping the cable attachment with an underhand grip.","Keep your back straight and your elbows tucked in at your sides.","Slowly curl the cable attachment up towards your shoulders, squeezing your biceps at the top of the movement.","Pause for a moment, then slowly lower the cable attachment back down to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle den Kabelzug so ein, dass die Scott-Curl-Polsterung auf Brusthöhe ist.","Setze dich auf die Scott-Bank, lege die Oberarme auf das Polster und greife den Griff im Untergriff.","Halte den Rücken gerade und die Ellbogen nah am Körper.","Ziehe den Griff langsam in Richtung Schultern und spanne den Bizeps am oberen Punkt an.","Halte kurz inne und senke den Griff dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0195.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0195.gif', 1784612222128, 1784612222128, 0),
  ('d85ce38c-8556-5978-ab53-4514c87b2b88', NULL, 'Cable Press on Exercise Ball', 'Kabelzug-Drücken auf dem Gymnastikball', 'chest', 'pectorals', 'cable', 'Sit on an exercise ball with your feet flat on the ground and your knees at a 90-degree angle. Hold the cable handles at chest height with your palms facing down and your elbows bent. Engage your core and press the cable handles forward until your arms are fully extended. Pause for a moment, then slowly release the tension and bring the cable handles back to the starting position. Repeat for the desired number of repetitions.', NULL, 'shoulders', '["shoulders","triceps"]', '["Sit on an exercise ball with your feet flat on the ground and your knees at a 90-degree angle.","Hold the cable handles at chest height with your palms facing down and your elbows bent.","Engage your core and press the cable handles forward until your arms are fully extended.","Pause for a moment, then slowly release the tension and bring the cable handles back to the starting position.","Repeat for the desired number of repetitions."]', '["Setze dich auf einen Gymnastikball, die Füsse flach am Boden, Knie im 90-Grad-Winkel.","Halte die Kabelgriffe auf Brusthöhe, Handflächen nach unten, Ellbogen gebeugt.","Spanne die Körpermitte an und drücke die Griffe nach vorne, bis die Arme vollständig gestreckt sind.","Halte kurz inne, lass die Spannung dann langsam nach und führe die Griffe zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1268.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1268.gif', 1784612222128, 1784612222128, 0),
  ('c6f78e04-273c-5267-ba1d-bb04eb01dc46', NULL, 'Cable Pull-Through (with Rope)', 'Kabelzug-Pull-Through (mit Seil)', 'upper legs', 'glutes', 'cable', 'Stand facing away from the cable machine with your feet shoulder-width apart. Grab the rope attachment with both hands and step forward, creating tension in the cable. Bend at the hips and lower your upper body until it is parallel to the ground, keeping your back straight. Engage your glutes and hamstrings to pull your body back up to the starting position. Repeat for the desired number of repetitions.', NULL, 'hamstrings', '["hamstrings","lower back"]', '["Stand facing away from the cable machine with your feet shoulder-width apart.","Grab the rope attachment with both hands and step forward, creating tension in the cable.","Bend at the hips and lower your upper body until it is parallel to the ground, keeping your back straight.","Engage your glutes and hamstrings to pull your body back up to the starting position.","Repeat for the desired number of repetitions."]', '["Stehe mit dem Rücken zum Kabelzug, Füsse schulterbreit auseinander.","Greife den Seilgriff mit beiden Händen und trete nach vorne, um Zug auf das Kabel zu bringen.","Beuge dich in der Hüfte und senke den Oberkörper ab, bis er parallel zum Boden ist, der Rücken bleibt gerade.","Spanne Gesäss und Beinbeuger an, um deinen Körper zurück in die Ausgangsposition zu ziehen.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0196.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0196.gif', 1784612222128, 1784612222128, 0),
  ('91f84555-62af-509e-ba6c-321a290717d9', NULL, 'Cable Pulldown', 'Kabelzug-Latzug', 'back', 'lats', 'cable', 'Adjust the cable pulldown machine so that the seat is at a comfortable height and the knee pad is secured. Sit on the seat with your back straight and your feet flat on the ground. Grasp the cable bar with an overhand grip, slightly wider than shoulder-width apart. Lean back slightly and engage your core. Pull the cable bar down towards your chest, squeezing your shoulder blades together. Pause for a moment at the bottom of the movement, then slowly release the bar back to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","forearms"]', '["Adjust the cable pulldown machine so that the seat is at a comfortable height and the knee pad is secured.","Sit on the seat with your back straight and your feet flat on the ground.","Grasp the cable bar with an overhand grip, slightly wider than shoulder-width apart.","Lean back slightly and engage your core.","Pull the cable bar down towards your chest, squeezing your shoulder blades together.","Pause for a moment at the bottom of the movement, then slowly release the bar back to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle den Kabelzug so ein, dass der Sitz auf angenehmer Höhe ist und die Knierolle gesichert ist.","Setze dich mit geradem Rücken und flach am Boden stehenden Füssen auf den Sitz.","Greife die Stange im Obergriff, etwas breiter als schulterbreit.","Lehne dich leicht zurück und spanne die Körpermitte an.","Ziehe die Stange in Richtung Brust und ziehe dabei die Schulterblätter zusammen.","Halte am unteren Punkt kurz inne und lass die Stange dann langsam zurück in die Ausgangsposition gleiten.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0198.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0198.gif', 1784612222128, 1784612222128, 0),
  ('f79e5cdb-6921-5c58-8967-9066fad1fa8c', NULL, 'Cable Pulldown (Pro Lat Bar)', 'Kabelzug-Latzug (Lat-Stange)', 'back', 'lats', 'cable', 'Adjust the seat height so that your thighs are parallel to the ground and your feet are flat on the floor. Grasp the lat bar with an overhand grip, slightly wider than shoulder-width apart. Sit down and lean back slightly, keeping your chest up and your back straight. Pull the bar down towards your chest, squeezing your shoulder blades together. Pause for a moment at the bottom of the movement, then slowly release the bar back up to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","forearms"]', '["Adjust the seat height so that your thighs are parallel to the ground and your feet are flat on the floor.","Grasp the lat bar with an overhand grip, slightly wider than shoulder-width apart.","Sit down and lean back slightly, keeping your chest up and your back straight.","Pull the bar down towards your chest, squeezing your shoulder blades together.","Pause for a moment at the bottom of the movement, then slowly release the bar back up to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle die Sitzhöhe so ein, dass deine Oberschenkel parallel zum Boden sind und die Füsse flach auf dem Boden stehen.","Greife die Latzugstange im Obergriff, etwas breiter als schulterbreit.","Setze dich hin und lehne dich leicht zurück, Brust raus, Rücken gerade.","Ziehe die Stange in Richtung Brust und ziehe dabei die Schulterblätter zusammen.","Halte am unteren Punkt kurz inne und lass die Stange dann langsam zurück nach oben gleiten.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0197.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0197.gif', 1784612222128, 1784612222128, 0),
  ('c483d7cc-2508-5760-87db-4581830dc9e4', NULL, 'Cable Pulldown Bicep Curl', 'Kabelzug-Latzug-Bizepscurl', 'upper arms', 'biceps', 'cable', 'Attach a straight bar to the cable machine at the highest setting. Stand facing the machine with your feet shoulder-width apart. Grasp the bar with an underhand grip, hands shoulder-width apart. Keep your elbows close to your sides and your upper arms stationary. Exhale and slowly curl the bar down towards your thighs, keeping your wrists straight. Pause for a moment at the bottom of the movement, squeezing your biceps. Inhale and slowly return the bar to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', NULL, 'forearms', '["forearms"]', '["Attach a straight bar to the cable machine at the highest setting.","Stand facing the machine with your feet shoulder-width apart.","Grasp the bar with an underhand grip, hands shoulder-width apart.","Keep your elbows close to your sides and your upper arms stationary.","Exhale and slowly curl the bar down towards your thighs, keeping your wrists straight.","Pause for a moment at the bottom of the movement, squeezing your biceps.","Inhale and slowly return the bar to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."]', '["Befestige eine Stange auf höchster Stufe am Kabelzug.","Stehe mit schulterbreiten Füssen vor dem Gerät.","Greife die Stange im Untergriff, Hände schulterbreit auseinander.","Halte die Ellbogen nah am Körper und die Oberarme ruhig.","Atme aus und ziehe die Stange langsam in Richtung Oberschenkel, die Handgelenke bleiben gerade.","Halte am unteren Punkt kurz inne und spanne den Bizeps an.","Atme ein und führe die Stange langsam zurück in die Ausgangsposition, bis die Arme vollständig gestreckt sind.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1638.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1638.gif', 1784612222128, 1784612222128, 0),
  ('423dc489-791c-50af-bde3-6b6a1d107b30', NULL, 'Cable Pushdown', 'Kabelzug-Pushdown', 'upper arms', 'triceps', 'cable', 'Attach a straight bar to a high pulley cable machine. Stand facing the machine with your feet shoulder-width apart and a slight bend in your knees. Grasp the bar with an overhand grip, hands shoulder-width apart. Keep your elbows close to your sides and your upper arms stationary. Exhale and push the bar down until your elbows are fully extended. Pause for a moment, then inhale and slowly return the bar to the starting position. Repeat for the desired number of repetitions.', NULL, 'forearms', '["forearms"]', '["Attach a straight bar to a high pulley cable machine.","Stand facing the machine with your feet shoulder-width apart and a slight bend in your knees.","Grasp the bar with an overhand grip, hands shoulder-width apart.","Keep your elbows close to your sides and your upper arms stationary.","Exhale and push the bar down until your elbows are fully extended.","Pause for a moment, then inhale and slowly return the bar to the starting position.","Repeat for the desired number of repetitions."]', '["Befestige eine Stange an der oberen Umlenkrolle des Kabelzugs.","Stehe mit schulterbreiten Füssen und leicht gebeugten Knien vor dem Gerät.","Greife die Stange im Obergriff, Hände schulterbreit auseinander.","Halte die Ellbogen nah am Körper und die Oberarme ruhig.","Atme aus und drücke die Stange nach unten, bis die Ellbogen vollständig gestreckt sind.","Halte kurz inne, atme dann ein und führe die Stange langsam zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0201.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0201.gif', 1784612222128, 1784612222128, 0),
  ('cd16800d-96cc-59c2-8e16-6d59827aef40', NULL, 'Cable Pushdown (Straight Arm) V. 2', 'Kabelzug-Pushdown gestreckter Arm V. 2', 'back', 'lats', 'cable', 'Attach a straight bar to a high pulley cable machine. Stand facing the machine with your feet shoulder-width apart and a slight bend in your knees. Grasp the bar with an overhand grip, keeping your arms straight and your palms facing down. Engage your core and keep your back straight as you exhale and push the bar down towards your thighs. Pause for a moment at the bottom, then slowly return the bar to the starting position while inhaling. Repeat for the desired number of repetitions.', NULL, 'triceps', '["triceps","shoulders"]', '["Attach a straight bar to a high pulley cable machine.","Stand facing the machine with your feet shoulder-width apart and a slight bend in your knees.","Grasp the bar with an overhand grip, keeping your arms straight and your palms facing down.","Engage your core and keep your back straight as you exhale and push the bar down towards your thighs.","Pause for a moment at the bottom, then slowly return the bar to the starting position while inhaling.","Repeat for the desired number of repetitions."]', '["Befestige eine Stange an der oberen Umlenkrolle des Kabelzugs.","Stehe mit schulterbreiten Füssen und leicht gebeugten Knien vor dem Gerät.","Greife die Stange im Obergriff, die Arme bleiben gestreckt, Handflächen nach unten.","Spanne die Körpermitte an, halte den Rücken gerade, atme aus und drücke die Stange in Richtung Oberschenkel.","Halte am unteren Punkt kurz inne und führe die Stange dann während des Einatmens langsam zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0199.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0199.gif', 1784612222128, 1784612222128, 0),
  ('61b80b0f-6103-50f4-9729-b104f96dbfc5', NULL, 'Cable Pushdown (with Rope Attachment)', 'Kabelzug-Pushdown (Seilgriff)', 'upper arms', 'triceps', 'cable', 'Attach a rope attachment to a high pulley on a cable machine. Stand facing the machine with your feet shoulder-width apart and a slight bend in your knees. Grasp the rope with an overhand grip, palms facing each other. Keep your elbows close to your sides and your upper arms stationary throughout the exercise. Exhale and push the rope downward by extending your elbows until your arms are fully extended. Pause for a moment, then inhale and slowly return to the starting position by allowing your elbows to flex. Repeat for the desired number of repetitions.', NULL, 'forearms', '["forearms"]', '["Attach a rope attachment to a high pulley on a cable machine.","Stand facing the machine with your feet shoulder-width apart and a slight bend in your knees.","Grasp the rope with an overhand grip, palms facing each other.","Keep your elbows close to your sides and your upper arms stationary throughout the exercise.","Exhale and push the rope downward by extending your elbows until your arms are fully extended.","Pause for a moment, then inhale and slowly return to the starting position by allowing your elbows to flex.","Repeat for the desired number of repetitions."]', '["Befestige einen Seilgriff an der oberen Umlenkrolle des Kabelzugs.","Stehe mit schulterbreiten Füssen und leicht gebeugten Knien vor dem Gerät.","Greife das Seil im Obergriff, Handflächen zueinander.","Halte die Ellbogen während der ganzen Übung nah am Körper und die Oberarme ruhig.","Atme aus und drücke das Seil nach unten, indem du die Ellbogen streckst, bis die Arme vollständig gestreckt sind.","Halte kurz inne, atme dann ein und kehre langsam in die Ausgangsposition zurück, indem du die Ellbogen wieder beugst.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0200.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0200.gif', 1784612222128, 1784612222128, 0),
  ('e64a2241-8d40-57ba-a5d3-646e1486bdd5', NULL, 'Cable Rear Delt Row (Stirrups)', 'Kabelzug-Rudern hintere Schulter (Griffe)', 'shoulders', 'delts', 'cable', 'Attach a stirrup handle to a low cable pulley and stand facing the machine. Grasp the handle with your left hand and take a step back with your right foot, positioning your body at a slight angle. Bend your knees slightly and hinge forward at the hips, keeping your back straight and your core engaged. With your left arm extended and your palm facing down, pull the handle towards your chest by retracting your shoulder blade. Pause for a moment at the top of the movement, squeezing your shoulder blade. Slowly release the handle back to the starting position and repeat for the desired number of repetitions. Switch sides and repeat the exercise with your right arm.', NULL, 'trapezius', '["trapezius","rhomboids","biceps"]', '["Attach a stirrup handle to a low cable pulley and stand facing the machine.","Grasp the handle with your left hand and take a step back with your right foot, positioning your body at a slight angle.","Bend your knees slightly and hinge forward at the hips, keeping your back straight and your core engaged.","With your left arm extended and your palm facing down, pull the handle towards your chest by retracting your shoulder blade.","Pause for a moment at the top of the movement, squeezing your shoulder blade.","Slowly release the handle back to the starting position and repeat for the desired number of repetitions.","Switch sides and repeat the exercise with your right arm."]', '["Befestige einen Steigbügelgriff an der unteren Umlenkrolle und stehe vor dem Gerät.","Greife den Griff mit der linken Hand und trete mit dem rechten Fuss einen Schritt zurück, sodass dein Körper leicht schräg steht.","Beuge die Knie leicht und beuge dich in der Hüfte nach vorne, Rücken gerade, Körpermitte angespannt.","Mit gestrecktem linken Arm und nach unten zeigender Handfläche ziehst du den Griff zur Brust, indem du das Schulterblatt zurückziehst.","Halte am oberen Punkt kurz inne und spanne das Schulterblatt an.","Lass den Griff langsam zurück in die Ausgangsposition gleiten und wiederhole für die gewünschte Anzahl Wiederholungen.","Wechsle die Seite und wiederhole die Übung mit dem rechten Arm."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0202.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0202.gif', 1784612222128, 1784612222128, 0),
  ('dc75b5ad-e861-59ba-bcf5-5c9a4c4c2df7', NULL, 'Cable Rear Delt Row (with Rope)', 'Kabelzug-Rudern hintere Schulter (Seil)', 'shoulders', 'delts', 'cable', 'Attach a rope handle to a low pulley cable machine. Stand facing the machine with your feet shoulder-width apart. Grasp the rope handle with an overhand grip, palms facing each other. Bend your knees slightly and hinge forward at the hips, keeping your back straight. Keep your elbows slightly bent and pull the rope towards your chest, squeezing your shoulder blades together. Pause for a moment at the top of the movement, then slowly release the tension and return to the starting position. Repeat for the desired number of repetitions.', NULL, 'trapezius', '["trapezius","rhomboids","biceps"]', '["Attach a rope handle to a low pulley cable machine.","Stand facing the machine with your feet shoulder-width apart.","Grasp the rope handle with an overhand grip, palms facing each other.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Keep your elbows slightly bent and pull the rope towards your chest, squeezing your shoulder blades together.","Pause for a moment at the top of the movement, then slowly release the tension and return to the starting position.","Repeat for the desired number of repetitions."]', '["Befestige einen Seilgriff an der unteren Umlenkrolle des Kabelzugs.","Stehe mit schulterbreiten Füssen vor dem Gerät.","Greife den Seilgriff im Obergriff, Handflächen zueinander.","Beuge die Knie leicht und beuge dich in der Hüfte nach vorne, der Rücken bleibt gerade.","Halte die Ellbogen leicht gebeugt und ziehe das Seil zur Brust, während du die Schulterblätter zusammenziehst.","Halte am oberen Punkt kurz inne, lass die Spannung dann langsam nach und kehre in die Ausgangsposition zurück.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0203.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0203.gif', 1784612222128, 1784612222128, 0),
  ('dda76722-0475-5959-9690-096bec8b6707', NULL, 'Cable Rear Drive', 'Kabelzug-Rückwärtsdrücken', 'upper arms', 'triceps', 'cable', 'Attach a handle to a low pulley cable machine and stand facing away from the machine. Grasp the handle with an overhand grip and extend your arms straight out in front of you. Keeping your elbows stationary, pull the handle back towards your body, squeezing your triceps at the end of the movement. Slowly return the handle to the starting position and repeat for the desired number of repetitions.', NULL, 'shoulders', '["shoulders","back"]', '["Attach a handle to a low pulley cable machine and stand facing away from the machine.","Grasp the handle with an overhand grip and extend your arms straight out in front of you.","Keeping your elbows stationary, pull the handle back towards your body, squeezing your triceps at the end of the movement.","Slowly return the handle to the starting position and repeat for the desired number of repetitions."]', '["Befestige einen Griff an der unteren Umlenkrolle des Kabelzugs und stehe mit dem Rücken zum Gerät.","Greife den Griff im Obergriff und strecke die Arme gerade nach vorne aus.","Halte die Ellbogen ruhig und ziehe den Griff zum Körper zurück, spanne dabei am Ende der Bewegung den Trizeps an.","Führe den Griff langsam zurück in die Ausgangsposition und wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0204.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0204.gif', 1784612222128, 1784612222128, 0),
  ('df2b84e6-c755-54e7-b1bc-1751c891008a', NULL, 'Cable Rear Pulldown', 'Kabelzug-Nackenzug', 'back', 'lats', 'cable', 'Adjust the cable machine so that the pulley is at the highest position. Sit facing the machine with your feet flat on the ground and your knees slightly bent. Grasp the cable attachment with an overhand grip, hands slightly wider than shoulder-width apart. Lean back slightly, keeping your back straight and your chest up. Pull the cable attachment down towards your chest, squeezing your shoulder blades together. Pause for a moment at the bottom of the movement, then slowly release the cable back up to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","rhomboids","rear deltoids"]', '["Adjust the cable machine so that the pulley is at the highest position.","Sit facing the machine with your feet flat on the ground and your knees slightly bent.","Grasp the cable attachment with an overhand grip, hands slightly wider than shoulder-width apart.","Lean back slightly, keeping your back straight and your chest up.","Pull the cable attachment down towards your chest, squeezing your shoulder blades together.","Pause for a moment at the bottom of the movement, then slowly release the cable back up to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle den Kabelzug so ein, dass die Umlenkrolle in der höchsten Position ist.","Setze dich mit dem Gesicht zum Gerät, Füsse flach am Boden, Knie leicht gebeugt.","Greife den Griff im Obergriff, Hände etwas breiter als schulterbreit.","Lehne dich leicht zurück, Rücken gerade, Brust raus.","Ziehe den Griff in Richtung Brust und ziehe dabei die Schulterblätter zusammen.","Halte am unteren Punkt kurz inne und lass das Kabel dann langsam zurück nach oben gleiten.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0205.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0205.gif', 1784612222128, 1784612222128, 0);

INSERT OR REPLACE INTO exercises (id, user_id, name, name_de, category, primary_muscle, equipment, instructions_en, instructions_de, muscle_group, secondary_muscles, instruction_steps_en, instruction_steps_de, thumbnail_url, gif_url, created_at, updated_at, deleted) VALUES
  ('708c9f64-69b9-5d64-b272-bf8cbcd8acf5', NULL, 'Cable Reverse Crunch', 'Kabelzug-Reverse Crunch', 'waist', 'abs', 'cable', 'Attach a cable to a low pulley and lie down facing up on a mat. Hold the cable with both hands and extend your arms straight up towards the ceiling. Bend your knees and lift your legs up, bringing your thighs towards your chest. While keeping your upper body stable, curl your pelvis up towards your chest, lifting your hips off the mat. Pause for a moment at the top, then slowly lower your hips back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'hip flexors', '["hip flexors"]', '["Attach a cable to a low pulley and lie down facing up on a mat.","Hold the cable with both hands and extend your arms straight up towards the ceiling.","Bend your knees and lift your legs up, bringing your thighs towards your chest.","While keeping your upper body stable, curl your pelvis up towards your chest, lifting your hips off the mat.","Pause for a moment at the top, then slowly lower your hips back down to the starting position.","Repeat for the desired number of repetitions."]', '["Befestige ein Kabel an der unteren Umlenkrolle und lege dich rücklings auf eine Matte.","Halte das Kabel mit beiden Händen und strecke die Arme gerade Richtung Decke.","Beuge die Knie und hebe die Beine an, sodass die Oberschenkel Richtung Brust kommen.","Halte den Oberkörper stabil und rolle das Becken Richtung Brust, sodass die Hüfte von der Matte abhebt.","Halte am oberen Punkt kurz inne und senke die Hüfte dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0873.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0873.gif', 1784612222128, 1784612222128, 0),
  ('519217f1-ff74-5f5c-b79a-940b2ee20ba9', NULL, 'Cable Reverse Curl', 'Kabelzug-Reverse Curl', 'upper arms', 'biceps', 'cable', 'Attach a straight bar to a low pulley cable machine. Stand facing the machine with your feet shoulder-width apart and your knees slightly bent. Grasp the bar with an underhand grip, hands shoulder-width apart. Keep your elbows close to your sides and your upper arms stationary throughout the exercise. Exhale and curl the bar up towards your shoulders, contracting your biceps. Pause for a moment at the top, squeezing your biceps. Inhale and slowly lower the bar back to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', NULL, 'forearms', '["forearms"]', '["Attach a straight bar to a low pulley cable machine.","Stand facing the machine with your feet shoulder-width apart and your knees slightly bent.","Grasp the bar with an underhand grip, hands shoulder-width apart.","Keep your elbows close to your sides and your upper arms stationary throughout the exercise.","Exhale and curl the bar up towards your shoulders, contracting your biceps.","Pause for a moment at the top, squeezing your biceps.","Inhale and slowly lower the bar back to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."]', '["Befestige eine Stange an der unteren Umlenkrolle des Kabelzugs.","Stehe mit schulterbreiten Füssen und leicht gebeugten Knien vor dem Gerät.","Greife die Stange im Untergriff, Hände schulterbreit auseinander.","Halte die Ellbogen während der ganzen Übung nah am Körper und die Oberarme ruhig.","Atme aus und ziehe die Stange in Richtung Schultern hoch, spanne dabei den Bizeps an.","Halte am oberen Punkt kurz inne und spanne den Bizeps an.","Atme ein und senke die Stange langsam zurück in die Ausgangsposition, bis die Arme vollständig gestreckt sind.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0206.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0206.gif', 1784612222128, 1784612222128, 0),
  ('9c4ad3f9-2718-55eb-890a-9da30067bb71', NULL, 'Cable Reverse Grip Triceps Pushdown (SZ-Bar) (with Arm Blaster)', 'Kabelzug-Trizeps-Pushdown Untergriff (SZ-Stange, mit Arm Blaster)', 'upper arms', 'triceps', 'cable', 'Attach a straight bar to the cable machine at the highest setting. Stand facing the cable machine with your feet shoulder-width apart. Grasp the bar with an underhand grip, palms facing up, and your hands shoulder-width apart. Keep your elbows close to your sides and your upper arms stationary throughout the exercise. Engage your triceps and slowly push the bar down until your arms are fully extended. Pause for a moment at the bottom, then slowly return the bar to the starting position. Repeat for the desired number of repetitions.', NULL, 'forearms', '["forearms"]', '["Attach a straight bar to the cable machine at the highest setting.","Stand facing the cable machine with your feet shoulder-width apart.","Grasp the bar with an underhand grip, palms facing up, and your hands shoulder-width apart.","Keep your elbows close to your sides and your upper arms stationary throughout the exercise.","Engage your triceps and slowly push the bar down until your arms are fully extended.","Pause for a moment at the bottom, then slowly return the bar to the starting position.","Repeat for the desired number of repetitions."]', '["Befestige eine Stange auf höchster Stufe am Kabelzug.","Stehe mit schulterbreiten Füssen vor dem Kabelzug.","Greife die Stange im Untergriff, Handflächen nach oben, Hände schulterbreit auseinander.","Halte die Ellbogen während der ganzen Übung nah am Körper und die Oberarme ruhig.","Spanne den Trizeps an und drücke die Stange langsam nach unten, bis die Arme vollständig gestreckt sind.","Halte am unteren Punkt kurz inne und führe die Stange dann langsam zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/2406.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/2406.gif', 1784612222128, 1784612222128, 0),
  ('b1447979-fb66-5064-9987-0174dc50d8fb', NULL, 'Cable Reverse One Arm Curl', 'Kabelzug-Reverse Curl einarmig', 'upper arms', 'biceps', 'cable', 'Stand facing a cable machine with your feet shoulder-width apart. Grasp the cable handle with an underhand grip, palm facing down. Keep your elbow close to your side and slowly curl your forearm up towards your shoulder. Pause for a moment at the top, then slowly lower your forearm back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'forearms', '["forearms"]', '["Stand facing a cable machine with your feet shoulder-width apart.","Grasp the cable handle with an underhand grip, palm facing down.","Keep your elbow close to your side and slowly curl your forearm up towards your shoulder.","Pause for a moment at the top, then slowly lower your forearm back down to the starting position.","Repeat for the desired number of repetitions."]', '["Stehe mit schulterbreiten Füssen vor einem Kabelzug.","Greife den Kabelgriff im Untergriff, Handfläche nach unten.","Halte den Ellbogen nah am Körper und ziehe den Unterarm langsam Richtung Schulter hoch.","Halte am oberen Punkt kurz inne und senke den Unterarm dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1413.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1413.gif', 1784612222128, 1784612222128, 0),
  ('6db04e14-1d4d-5dcf-b4b4-57452f8fa23e', NULL, 'Cable Reverse Preacher Curl', 'Kabelzug-Reverse Preacher Curl', 'upper arms', 'biceps', 'cable', 'Adjust the cable machine so that the preacher curl pad is at chest height. Sit on the preacher curl bench and place your upper arms on the pad, with your palms facing down and your elbows fully extended. Grab the cable handles with an underhand grip, shoulder-width apart. Keeping your upper arms stationary, exhale and curl the handles towards your shoulders, contracting your biceps. Pause for a moment at the top of the movement, squeezing your biceps. Inhale and slowly lower the handles back to the starting position, fully extending your elbows. Repeat for the desired number of repetitions.', NULL, 'forearms', '["forearms"]', '["Adjust the cable machine so that the preacher curl pad is at chest height.","Sit on the preacher curl bench and place your upper arms on the pad, with your palms facing down and your elbows fully extended.","Grab the cable handles with an underhand grip, shoulder-width apart.","Keeping your upper arms stationary, exhale and curl the handles towards your shoulders, contracting your biceps.","Pause for a moment at the top of the movement, squeezing your biceps.","Inhale and slowly lower the handles back to the starting position, fully extending your elbows.","Repeat for the desired number of repetitions."]', '["Stelle den Kabelzug so ein, dass die Scott-Curl-Polsterung auf Brusthöhe ist.","Setze dich auf die Scott-Bank, lege die Oberarme auf das Polster, Handflächen nach unten, Ellbogen vollständig gestreckt.","Greife die Kabelgriffe im Untergriff, schulterbreit auseinander.","Halte die Oberarme ruhig, atme aus und ziehe die Griffe in Richtung Schultern, spanne dabei den Bizeps an.","Halte am oberen Punkt kurz inne und spanne den Bizeps an.","Atme ein und senke die Griffe langsam zurück in die Ausgangsposition ab, bis die Ellbogen vollständig gestreckt sind.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0209.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0209.gif', 1784612222128, 1784612222128, 0),
  ('75ca8677-6a1a-509e-98a2-e2313e36bdf3', NULL, 'Cable Reverse Wrist Curl', 'Kabelzug-Handgelenkcurl Obergriff', 'lower arms', 'forearms', 'cable', 'Attach a cable to a low pulley and sit on a bench facing the cable machine. Grasp the cable handle with an overhand grip, palms facing down. Rest your forearms on your thighs, with your wrists hanging off the edge. Keeping your forearms stationary, exhale and curl your wrists upward as far as possible. Pause for a moment at the top, then inhale and slowly lower your wrists back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'forearms', '["forearms","wrists"]', '["Attach a cable to a low pulley and sit on a bench facing the cable machine.","Grasp the cable handle with an overhand grip, palms facing down.","Rest your forearms on your thighs, with your wrists hanging off the edge.","Keeping your forearms stationary, exhale and curl your wrists upward as far as possible.","Pause for a moment at the top, then inhale and slowly lower your wrists back down to the starting position.","Repeat for the desired number of repetitions."]', '["Befestige ein Kabel an der unteren Umlenkrolle und setze dich mit dem Gesicht zum Kabelzug auf eine Bank.","Greife den Kabelgriff im Obergriff, Handflächen nach unten.","Lege die Unterarme auf die Oberschenkel, die Handgelenke hängen über die Kante.","Halte die Unterarme ruhig, atme aus und ziehe die Handgelenke so weit wie möglich nach oben.","Halte am oberen Punkt kurz inne, atme dann ein und senke die Handgelenke langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0210.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0210.gif', 1784612222128, 1784612222128, 0),
  ('88ec1115-7de3-5b75-89c0-2235eff2ee68', NULL, 'Cable Reverse-Grip Pushdown', 'Kabelzug-Pushdown Untergriff', 'upper arms', 'triceps', 'cable', 'Attach a straight bar to a high pulley cable machine. Stand facing the machine with your feet shoulder-width apart. Grasp the bar with an underhand grip, palms facing up, and your hands shoulder-width apart. Keep your elbows close to your sides and your upper arms stationary throughout the exercise. Using your triceps, push the bar down until your arms are fully extended and your triceps are contracted. Pause for a moment, then slowly return the bar to the starting position. Repeat for the desired number of repetitions.', NULL, 'forearms', '["forearms"]', '["Attach a straight bar to a high pulley cable machine.","Stand facing the machine with your feet shoulder-width apart.","Grasp the bar with an underhand grip, palms facing up, and your hands shoulder-width apart.","Keep your elbows close to your sides and your upper arms stationary throughout the exercise.","Using your triceps, push the bar down until your arms are fully extended and your triceps are contracted.","Pause for a moment, then slowly return the bar to the starting position.","Repeat for the desired number of repetitions."]', '["Befestige eine Stange an der oberen Umlenkrolle des Kabelzugs.","Stehe mit schulterbreiten Füssen vor dem Gerät.","Greife die Stange im Untergriff, Handflächen nach oben, Hände schulterbreit auseinander.","Halte die Ellbogen während der ganzen Übung nah am Körper und die Oberarme ruhig.","Drücke die Stange mit dem Trizeps nach unten, bis die Arme vollständig gestreckt und der Trizeps angespannt ist.","Halte kurz inne und führe die Stange dann langsam zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0207.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0207.gif', 1784612222128, 1784612222128, 0),
  ('0a5b6d7e-8044-59b5-9414-2b557642fa1c', NULL, 'Cable Reverse-Grip Straight Back Seated High Row', 'Kabelzug-Rudern sitzend hoch, gerader Rücken, Untergriff', 'back', 'upper back', 'cable', 'Sit on the seat facing the cable machine with your feet flat on the floor. Grasp the cable attachment with an underhand grip, palms facing up, and your hands shoulder-width apart. Keep your back straight and lean slightly forward from your hips. Pull the cable towards your torso by retracting your shoulder blades and squeezing your back muscles. Pause for a moment at the peak of the contraction, then slowly release the cable back to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","forearms"]', '["Sit on the seat facing the cable machine with your feet flat on the floor.","Grasp the cable attachment with an underhand grip, palms facing up, and your hands shoulder-width apart.","Keep your back straight and lean slightly forward from your hips.","Pull the cable towards your torso by retracting your shoulder blades and squeezing your back muscles.","Pause for a moment at the peak of the contraction, then slowly release the cable back to the starting position.","Repeat for the desired number of repetitions."]', '["Setze dich mit dem Gesicht zum Kabelzug auf den Sitz, Füsse flach auf dem Boden.","Greife den Griff im Untergriff, Handflächen nach oben, Hände schulterbreit auseinander.","Halte den Rücken gerade und lehne dich leicht aus der Hüfte nach vorne.","Ziehe das Kabel zum Oberkörper, indem du die Schulterblätter zurückziehst und die Rückenmuskeln anspannst.","Halte am Höhepunkt der Anspannung kurz inne und lass das Kabel dann langsam zurück in die Ausgangsposition gleiten.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0208.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0208.gif', 1784612222128, 1784612222128, 0),
  ('3276ea6a-49f2-5507-959f-63bcb1fd383c', NULL, 'Cable Rope Crossover Seated Row', 'Kabelzug-Rudern sitzend im Überkreuz mit Seil', 'back', 'upper back', 'cable', 'Sit on the rowing machine with your feet flat on the footrests and your knees slightly bent. Grasp the cable ropes with an overhand grip, palms facing each other. Lean back slightly, keeping your back straight and your core engaged. Pull the cable ropes towards your chest, squeezing your shoulder blades together. Pause for a moment at the peak of the movement, then slowly release the tension and return to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","forearms"]', '["Sit on the rowing machine with your feet flat on the footrests and your knees slightly bent.","Grasp the cable ropes with an overhand grip, palms facing each other.","Lean back slightly, keeping your back straight and your core engaged.","Pull the cable ropes towards your chest, squeezing your shoulder blades together.","Pause for a moment at the peak of the movement, then slowly release the tension and return to the starting position.","Repeat for the desired number of repetitions."]', '["Setze dich auf das Rudergerät, Füsse flach auf den Fussstützen, Knie leicht gebeugt.","Greife die Kabelseile im Obergriff, Handflächen zueinander.","Lehne dich leicht zurück, Rücken gerade, Körpermitte angespannt.","Ziehe die Kabelseile zur Brust und ziehe dabei die Schulterblätter zusammen.","Halte am Höhepunkt der Bewegung kurz inne, lass die Spannung dann langsam nach und kehre in die Ausgangsposition zurück.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1320.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1320.gif', 1784612222128, 1784612222128, 0),
  ('651fbf9c-8411-5e48-aa70-cd81d564e487', NULL, 'Cable Rope Elevated Seated Row', 'Kabelzug-Rudern sitzend erhöht mit Seil', 'back', 'upper back', 'cable', 'Sit on the elevated seat facing the cable machine. Grab the cable rope handles with an overhand grip, palms facing each other. Keep your back straight and lean slightly back, maintaining a slight bend in your knees. Pull the cable towards your body by retracting your shoulder blades and squeezing your back muscles. Pause for a moment at the fully contracted position. Slowly release the tension and extend your arms back to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","forearms"]', '["Sit on the elevated seat facing the cable machine.","Grab the cable rope handles with an overhand grip, palms facing each other.","Keep your back straight and lean slightly back, maintaining a slight bend in your knees.","Pull the cable towards your body by retracting your shoulder blades and squeezing your back muscles.","Pause for a moment at the fully contracted position.","Slowly release the tension and extend your arms back to the starting position.","Repeat for the desired number of repetitions."]', '["Setze dich mit dem Gesicht zum Kabelzug auf den erhöhten Sitz.","Greife die Seilgriffe im Obergriff, Handflächen zueinander.","Halte den Rücken gerade, lehne dich leicht zurück und behalte eine leichte Kniebeugung bei.","Ziehe das Kabel zum Körper, indem du die Schulterblätter zurückziehst und die Rückenmuskeln anspannst.","Halte am Punkt der vollen Anspannung kurz inne.","Lass die Spannung nach und strecke die Arme zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1321.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1321.gif', 1784612222128, 1784612222128, 0),
  ('27d5108e-f444-5655-a71c-296e50725af1', NULL, 'Cable Rope Extension Incline Bench Row', 'Kabelzug-Schrägbank-Rudern mit Seil (Streckung)', 'back', 'upper back', 'cable', 'Set up an incline bench at a 45-degree angle and attach a cable machine to the low pulley. Attach a rope handle to the cable machine and sit on the incline bench facing the machine. Grab the rope handle with an overhand grip and lean forward, keeping your back straight. Extend your arms fully, pulling the rope towards your upper chest while keeping your elbows close to your body. Squeeze your shoulder blades together at the end of the movement. Slowly release the tension and return to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","shoulders"]', '["Set up an incline bench at a 45-degree angle and attach a cable machine to the low pulley.","Attach a rope handle to the cable machine and sit on the incline bench facing the machine.","Grab the rope handle with an overhand grip and lean forward, keeping your back straight.","Extend your arms fully, pulling the rope towards your upper chest while keeping your elbows close to your body.","Squeeze your shoulder blades together at the end of the movement.","Slowly release the tension and return to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle eine Schrägbank im 45-Grad-Winkel auf und befestige den Kabelzug an der unteren Umlenkrolle.","Befestige einen Seilgriff am Kabelzug und setze dich mit dem Gesicht zum Gerät auf die Schrägbank.","Greife den Seilgriff im Obergriff und lehne dich nach vorne, der Rücken bleibt gerade.","Strecke die Arme vollständig und ziehe das Seil zur oberen Brust, die Ellbogen bleiben nah am Körper.","Ziehe die Schulterblätter am Ende der Bewegung zusammen.","Lass die Spannung langsam nach und kehre in die Ausgangsposition zurück.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1322.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1322.gif', 1784612222128, 1784612222128, 0),
  ('63fac83f-1dcf-5423-8353-51d8bea36647', NULL, 'Cable Rope Hammer Preacher Curl', 'Kabelzug-Hammer Preacher Curl mit Seil', 'upper arms', 'biceps', 'cable', 'Attach a rope attachment to a low pulley cable machine. Stand facing the machine with your feet shoulder-width apart. Grasp the rope with a neutral grip (palms facing each other). Position your upper arms against the preacher bench pad, keeping your elbows slightly bent. Keeping your upper arms stationary, exhale and curl the rope towards your shoulders by contracting your biceps. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly lower the rope back to the starting position. Repeat for the desired number of repetitions.', NULL, 'forearms', '["forearms"]', '["Attach a rope attachment to a low pulley cable machine.","Stand facing the machine with your feet shoulder-width apart.","Grasp the rope with a neutral grip (palms facing each other).","Position your upper arms against the preacher bench pad, keeping your elbows slightly bent.","Keeping your upper arms stationary, exhale and curl the rope towards your shoulders by contracting your biceps.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly lower the rope back to the starting position.","Repeat for the desired number of repetitions."]', '["Befestige einen Seilgriff an der unteren Umlenkrolle des Kabelzugs.","Stehe mit schulterbreiten Füssen vor dem Gerät.","Greife das Seil im neutralen Griff (Handflächen zueinander).","Lege die Oberarme an das Polster der Scott-Bank, die Ellbogen bleiben leicht gebeugt.","Halte die Oberarme ruhig, atme aus und ziehe das Seil in Richtung Schultern, indem du den Bizeps anspannst.","Halte die kontrahierte Position kurz und spanne dabei den Bizeps an.","Atme ein und senke das Seil langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1639.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1639.gif', 1784612222128, 1784612222128, 0),
  ('ff39c94e-d7df-526a-8d85-c3275479b931', NULL, 'Cable Rope High Pulley Overhead Tricep Extension', 'Kabelzug-Trizepsstrecken über Kopf am hohen Zug mit Seil', 'upper arms', 'triceps', 'cable', 'Attach a rope to a high pulley and adjust the weight accordingly. Stand facing away from the pulley machine with your feet shoulder-width apart. Grasp the rope with both hands, palms facing down, and bring your hands above your head. Keep your upper arms close to your head and perpendicular to the floor. Slowly lower the rope behind your head by bending your elbows. Pause for a moment, then extend your arms back to the starting position. Repeat for the desired number of repetitions.', NULL, 'shoulders', '["shoulders"]', '["Attach a rope to a high pulley and adjust the weight accordingly.","Stand facing away from the pulley machine with your feet shoulder-width apart.","Grasp the rope with both hands, palms facing down, and bring your hands above your head.","Keep your upper arms close to your head and perpendicular to the floor.","Slowly lower the rope behind your head by bending your elbows.","Pause for a moment, then extend your arms back to the starting position.","Repeat for the desired number of repetitions."]', '["Befestige ein Seil an der oberen Umlenkrolle und stelle das Gewicht entsprechend ein.","Stehe mit dem Rücken zum Gerät, Füsse schulterbreit auseinander.","Greife das Seil mit beiden Händen, Handflächen nach unten, und führe die Hände über den Kopf.","Halte die Oberarme nah am Kopf und senkrecht zum Boden.","Senke das Seil langsam hinter den Kopf ab, indem du die Ellbogen beugst.","Halte kurz inne und strecke die Arme dann zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1724.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1724.gif', 1784612222128, 1784612222128, 0),
  ('ee1adfdd-0b92-5d8d-a123-6d6bc38f0cd3', NULL, 'Cable Rope Incline Tricep Extension', 'Kabelzug-Trizepsstrecken auf der Schrägbank mit Seil', 'upper arms', 'triceps', 'cable', 'Attach a rope to a high pulley and adjust the incline bench to a comfortable angle. Stand facing away from the pulley with your feet shoulder-width apart. Grasp the rope with an overhand grip and extend your arms straight overhead. Keep your elbows close to your head and your upper arms stationary throughout the exercise. Lower the rope behind your head by bending your elbows until your forearms touch your biceps. Pause for a moment, then extend your arms back to the starting position. Repeat for the desired number of repetitions.', NULL, 'shoulders', '["shoulders"]', '["Attach a rope to a high pulley and adjust the incline bench to a comfortable angle.","Stand facing away from the pulley with your feet shoulder-width apart.","Grasp the rope with an overhand grip and extend your arms straight overhead.","Keep your elbows close to your head and your upper arms stationary throughout the exercise.","Lower the rope behind your head by bending your elbows until your forearms touch your biceps.","Pause for a moment, then extend your arms back to the starting position.","Repeat for the desired number of repetitions."]', '["Befestige ein Seil an der oberen Umlenkrolle und stelle die Schrägbank auf einen angenehmen Winkel ein.","Stehe mit dem Rücken zur Umlenkrolle, Füsse schulterbreit auseinander.","Greife das Seil im Obergriff und strecke die Arme gerade über den Kopf.","Halte die Ellbogen nah am Kopf und die Oberarme während der ganzen Übung ruhig.","Senke das Seil hinter den Kopf ab, indem du die Ellbogen beugst, bis die Unterarme den Bizeps berühren.","Halte kurz inne und strecke die Arme dann zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1725.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1725.gif', 1784612222128, 1784612222128, 0),
  ('d8a35f5a-898a-5376-9ba4-b0681e9031b2', NULL, 'Cable Rope Lying on Floor Tricep Extension', 'Kabelzug-Trizepsstrecken liegend am Boden mit Seil', 'upper arms', 'triceps', 'cable', 'Attach a rope to a cable machine and set it to the lowest position. Lie on the floor facing up, with your head towards the cable machine. Hold the rope with both hands, palms facing each other, and extend your arms straight up towards the ceiling. Keep your upper arms stationary and slowly lower the rope towards your forehead, bending your elbows. Pause for a moment, then extend your arms back up to the starting position. Repeat for the desired number of repetitions.', NULL, 'shoulders', '["shoulders"]', '["Attach a rope to a cable machine and set it to the lowest position.","Lie on the floor facing up, with your head towards the cable machine.","Hold the rope with both hands, palms facing each other, and extend your arms straight up towards the ceiling.","Keep your upper arms stationary and slowly lower the rope towards your forehead, bending your elbows.","Pause for a moment, then extend your arms back up to the starting position.","Repeat for the desired number of repetitions."]', '["Befestige ein Seil am Kabelzug und stelle es auf die tiefste Position ein.","Lege dich mit dem Rücken auf den Boden, den Kopf in Richtung Kabelzug.","Halte das Seil mit beiden Händen, Handflächen zueinander, und strecke die Arme gerade Richtung Decke.","Halte die Oberarme ruhig und senke das Seil langsam in Richtung Stirn ab, indem du die Ellbogen beugst.","Halte kurz inne und strecke die Arme dann wieder nach oben in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1726.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1726.gif', 1784612222128, 1784612222128, 0),
  ('02358d17-04e1-5395-a94a-94356807e38a', NULL, 'Cable Rope One Arm Hammer Preacher Curl', 'Kabelzug-Hammer Preacher Curl einarmig mit Seil', 'upper arms', 'biceps', 'cable', 'Attach a rope handle to a low pulley cable machine. Stand facing the machine with your feet shoulder-width apart. Grasp the rope handle with an underhand grip, palms facing up. Position your upper arm against the preacher bench pad, keeping your elbow slightly bent. Keep your back straight and your core engaged throughout the exercise. Slowly curl the rope handle towards your shoulder, keeping your upper arm stationary. Squeeze your biceps at the top of the movement, then slowly lower the rope handle back to the starting position. Repeat for the desired number of repetitions, then switch arms.', NULL, 'forearms', '["forearms"]', '["Attach a rope handle to a low pulley cable machine.","Stand facing the machine with your feet shoulder-width apart.","Grasp the rope handle with an underhand grip, palms facing up.","Position your upper arm against the preacher bench pad, keeping your elbow slightly bent.","Keep your back straight and your core engaged throughout the exercise.","Slowly curl the rope handle towards your shoulder, keeping your upper arm stationary.","Squeeze your biceps at the top of the movement, then slowly lower the rope handle back to the starting position.","Repeat for the desired number of repetitions, then switch arms."]', '["Befestige einen Seilgriff an der unteren Umlenkrolle des Kabelzugs.","Stehe mit schulterbreiten Füssen vor dem Gerät.","Greife den Seilgriff im Untergriff, Handflächen nach oben.","Lege den Oberarm an das Polster der Scott-Bank, der Ellbogen bleibt leicht gebeugt.","Halte den Rücken gerade und die Körpermitte während der ganzen Übung angespannt.","Ziehe den Seilgriff langsam Richtung Schulter, der Oberarm bleibt dabei ruhig.","Spanne den Bizeps am oberen Punkt an und senke den Seilgriff dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dann die Seite."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1640.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1640.gif', 1784612222128, 1784612222128, 0),
  ('1934844d-917b-5035-8165-53eeb7c5fcf1', NULL, 'Cable Rope Seated Row', 'Kabelzug-Rudern sitzend mit Seil', 'back', 'upper back', 'cable', 'Sit on the rowing machine with your feet flat on the footrests and knees slightly bent. Grasp the cable ropes with an overhand grip, palms facing each other. Keep your back straight and lean slightly forward, maintaining a slight bend in your elbows. Pull the cable ropes towards your body, squeezing your shoulder blades together. Pause for a moment at the peak of the movement, then slowly release the tension and return to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","forearms"]', '["Sit on the rowing machine with your feet flat on the footrests and knees slightly bent.","Grasp the cable ropes with an overhand grip, palms facing each other.","Keep your back straight and lean slightly forward, maintaining a slight bend in your elbows.","Pull the cable ropes towards your body, squeezing your shoulder blades together.","Pause for a moment at the peak of the movement, then slowly release the tension and return to the starting position.","Repeat for the desired number of repetitions."]', '["Setze dich auf das Rudergerät, Füsse flach auf den Fussstützen, Knie leicht gebeugt.","Greife die Kabelseile im Obergriff, Handflächen zueinander.","Halte den Rücken gerade und lehne dich leicht nach vorne, die Ellbogen bleiben leicht gebeugt.","Ziehe die Kabelseile zum Körper und ziehe dabei die Schulterblätter zusammen.","Halte am Höhepunkt der Bewegung kurz inne, lass die Spannung dann langsam nach und kehre in die Ausgangsposition zurück.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1323.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1323.gif', 1784612222128, 1784612222128, 0),
  ('89bedcb8-020b-5e7e-93c4-44d838b4ef1d', NULL, 'Cable Russian Twists (on Stability Ball)', 'Kabelzug-Russian Twist auf dem Gymnastikball', 'waist', 'abs', 'cable', 'Sit on a stability ball with your feet flat on the ground and your knees bent at a 90-degree angle. Hold the cable handle with both hands and extend your arms straight out in front of you. Lean back slightly while keeping your back straight and your core engaged. Twist your torso to the right, bringing the cable handle towards your right hip. Pause for a moment, then twist your torso to the left, bringing the cable handle towards your left hip. Continue alternating twists for the desired number of repetitions.', NULL, 'obliques', '["obliques","lower back"]', '["Sit on a stability ball with your feet flat on the ground and your knees bent at a 90-degree angle.","Hold the cable handle with both hands and extend your arms straight out in front of you.","Lean back slightly while keeping your back straight and your core engaged.","Twist your torso to the right, bringing the cable handle towards your right hip.","Pause for a moment, then twist your torso to the left, bringing the cable handle towards your left hip.","Continue alternating twists for the desired number of repetitions."]', '["Setze dich auf einen Gymnastikball, die Füsse flach am Boden, Knie im 90-Grad-Winkel gebeugt.","Halte den Kabelgriff mit beiden Händen und strecke die Arme gerade nach vorne aus.","Lehne dich leicht zurück, Rücken gerade, Körpermitte angespannt.","Drehe den Oberkörper nach rechts und führe den Kabelgriff Richtung rechte Hüfte.","Halte kurz inne und drehe den Oberkörper dann nach links, Richtung linke Hüfte.","Wechsle die Drehrichtung fortlaufend für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0211.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0211.gif', 1784612222128, 1784612222128, 0),
  ('38d07c5e-3352-5fa3-907c-8a30e960a78a', NULL, 'Cable Seated Chest Press', 'Kabelzug-Brustdrücken sitzend', 'chest', 'pectorals', 'cable', 'Adjust the seat height and cable handles to a comfortable position. Sit on the bench with your back straight and feet flat on the floor. Grasp the cable handles with an overhand grip at shoulder height. Push the handles forward and away from your body, extending your arms fully. Pause for a moment, then slowly bring the handles back to the starting position. Repeat for the desired number of repetitions.', NULL, 'shoulders', '["shoulders","triceps"]', '["Adjust the seat height and cable handles to a comfortable position.","Sit on the bench with your back straight and feet flat on the floor.","Grasp the cable handles with an overhand grip at shoulder height.","Push the handles forward and away from your body, extending your arms fully.","Pause for a moment, then slowly bring the handles back to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle Sitzhöhe und Kabelgriffe auf eine angenehme Position ein.","Setze dich mit geradem Rücken und flach am Boden stehenden Füssen auf die Bank.","Greife die Kabelgriffe im Obergriff auf Schulterhöhe.","Drücke die Griffe nach vorne und vom Körper weg, bis die Arme vollständig gestreckt sind.","Halte kurz inne und führe die Griffe dann langsam zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/2144.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/2144.gif', 1784612222128, 1784612222128, 0),
  ('28cc3da4-649f-5862-bf1b-612471d1dc11', NULL, 'Cable Seated Crunch', 'Kabelzug-Crunch sitzend', 'waist', 'abs', 'cable', 'Sit on a cable machine with your feet flat on the ground and your knees bent. Hold the cable handle with both hands and position it behind your head. Engage your abs and slowly curl your upper body forward, bringing your chest towards your knees. Pause for a moment at the top, then slowly return to the starting position. Repeat for the desired number of repetitions.', NULL, 'obliques', '["obliques"]', '["Sit on a cable machine with your feet flat on the ground and your knees bent.","Hold the cable handle with both hands and position it behind your head.","Engage your abs and slowly curl your upper body forward, bringing your chest towards your knees.","Pause for a moment at the top, then slowly return to the starting position.","Repeat for the desired number of repetitions."]', '["Setze dich an einen Kabelzug, Füsse flach am Boden, Knie gebeugt.","Halte den Kabelgriff mit beiden Händen und positioniere ihn hinter dem Kopf.","Spanne die Bauchmuskeln an und rolle den Oberkörper langsam nach vorne, die Brust kommt Richtung Knie.","Halte am oberen Punkt kurz inne und kehre dann langsam in die Ausgangsposition zurück.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0212.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0212.gif', 1784612222128, 1784612222128, 0),
  ('f60a20fe-7e4d-5b22-9931-2ccd073f1a00', NULL, 'Cable Seated Curl', 'Kabelzug-Curl sitzend', 'upper arms', 'biceps', 'cable', 'Sit on a cable machine with your feet flat on the ground and your back straight. Grasp the cable attachment with an underhand grip, palms facing up, and your arms fully extended. Keeping your upper arms stationary, exhale and curl the cable attachment towards your shoulders, contracting your biceps. Pause for a moment at the top of the movement, squeezing your biceps. Inhale and slowly lower the cable attachment back to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', NULL, 'forearms', '["forearms"]', '["Sit on a cable machine with your feet flat on the ground and your back straight.","Grasp the cable attachment with an underhand grip, palms facing up, and your arms fully extended.","Keeping your upper arms stationary, exhale and curl the cable attachment towards your shoulders, contracting your biceps.","Pause for a moment at the top of the movement, squeezing your biceps.","Inhale and slowly lower the cable attachment back to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."]', '["Setze dich an einen Kabelzug, Füsse flach am Boden, Rücken gerade.","Greife den Kabelgriff im Untergriff, Handflächen nach oben, Arme vollständig gestreckt.","Halte die Oberarme ruhig, atme aus und ziehe den Griff in Richtung Schultern, indem du den Bizeps anspannst.","Halte die kontrahierte Position kurz und spanne dabei den Bizeps an.","Atme ein und senke den Griff langsam zurück in die Ausgangsposition, bis die Arme vollständig gestreckt sind.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1641.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1641.gif', 1784612222128, 1784612222128, 0),
  ('bc452915-2793-55a3-a753-cafaa1a645cc', NULL, 'Cable Seated High Row (V-Bar)', 'Kabelzug-Rudern sitzend hoch (V-Griff)', 'back', 'lats', 'cable', 'Sit on the cable machine with your feet flat on the floor and your knees slightly bent. Grasp the v-bar attachment with an overhand grip, palms facing each other, and your hands shoulder-width apart. Keep your back straight and lean slightly forward from the hips. Pull the v-bar towards your torso by retracting your shoulder blades and squeezing your back muscles. Pause for a moment at the peak of the contraction, then slowly release the tension and return to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","rhomboids","rear deltoids"]', '["Sit on the cable machine with your feet flat on the floor and your knees slightly bent.","Grasp the v-bar attachment with an overhand grip, palms facing each other, and your hands shoulder-width apart.","Keep your back straight and lean slightly forward from the hips.","Pull the v-bar towards your torso by retracting your shoulder blades and squeezing your back muscles.","Pause for a moment at the peak of the contraction, then slowly release the tension and return to the starting position.","Repeat for the desired number of repetitions."]', '["Setze dich mit flach am Boden stehenden Füssen und leicht gebeugten Knien an den Kabelzug.","Greife den V-Griff im Obergriff, Handflächen zueinander, Hände schulterbreit auseinander.","Halte den Rücken gerade und lehne dich leicht aus der Hüfte nach vorne.","Ziehe den V-Griff zum Oberkörper, indem du die Schulterblätter zurückziehst und die Rückenmuskeln anspannst.","Halte am Höhepunkt der Anspannung kurz inne, lass die Spannung dann langsam nach und kehre in die Ausgangsposition zurück.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0213.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0213.gif', 1784612222128, 1784612222128, 0),
  ('1426fcc8-b59c-5c71-9bfd-de84e97fba28', NULL, 'Cable Seated One Arm Alternate Row', 'Kabelzug-Rudern sitzend einarmig wechselseitig', 'back', 'upper back', 'cable', 'Sit on a bench facing a cable machine with your feet flat on the ground and knees slightly bent. Grasp the handle with one hand and keep your arm fully extended in front of you. Pull the handle towards your body, retracting your shoulder blade and keeping your elbow close to your side. Pause for a moment at the top of the movement, squeezing your back muscles. Slowly release the handle back to the starting position. Repeat with the other arm. Alternate between arms for the desired number of repetitions.', NULL, 'biceps', '["biceps","forearms"]', '["Sit on a bench facing a cable machine with your feet flat on the ground and knees slightly bent.","Grasp the handle with one hand and keep your arm fully extended in front of you.","Pull the handle towards your body, retracting your shoulder blade and keeping your elbow close to your side.","Pause for a moment at the top of the movement, squeezing your back muscles.","Slowly release the handle back to the starting position.","Repeat with the other arm.","Alternate between arms for the desired number of repetitions."]', '["Setze dich mit dem Gesicht zum Kabelzug auf eine Bank, Füsse flach am Boden, Knie leicht gebeugt.","Greife den Griff mit einer Hand und halte den Arm vollständig gestreckt vor dir.","Ziehe den Griff zum Körper, ziehe dabei das Schulterblatt zurück und halte den Ellbogen nah am Körper.","Halte am oberen Punkt kurz inne und spanne die Rückenmuskeln an.","Lass den Griff langsam zurück in die Ausgangsposition gleiten.","Wiederhole mit dem anderen Arm.","Wechsle die Seite fortlaufend für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0214.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0214.gif', 1784612222128, 1784612222128, 0),
  ('b780c5ab-b2f9-5875-a21e-8479407573f8', NULL, 'Cable Seated One Arm Concentration Curl', 'Kabelzug-Konzentrationscurl sitzend einarmig', 'upper arms', 'biceps', 'cable', 'Sit on a bench with your feet flat on the floor and your back straight. Hold a cable handle with one hand and place your elbow on the inside of your thigh, just above the knee. Keep your upper arm stationary and curl the cable handle towards your shoulder while exhaling. Pause for a moment at the top of the movement, squeezing your biceps. Slowly lower the cable handle back to the starting position while inhaling. Repeat for the desired number of repetitions, then switch arms.', NULL, 'forearms', '["forearms"]', '["Sit on a bench with your feet flat on the floor and your back straight.","Hold a cable handle with one hand and place your elbow on the inside of your thigh, just above the knee.","Keep your upper arm stationary and curl the cable handle towards your shoulder while exhaling.","Pause for a moment at the top of the movement, squeezing your biceps.","Slowly lower the cable handle back to the starting position while inhaling.","Repeat for the desired number of repetitions, then switch arms."]', '["Setze dich auf eine Bank, Füsse flach am Boden, Rücken gerade.","Halte einen Kabelgriff mit einer Hand und stütze den Ellbogen an der Innenseite des Oberschenkels, direkt über dem Knie.","Halte den Oberarm ruhig und ziehe den Griff Richtung Schulter, während du ausatmest.","Halte am oberen Punkt kurz inne und spanne den Bizeps an.","Senke den Griff langsam zurück in die Ausgangsposition ab, während du einatmest.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dann die Seite."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1642.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1642.gif', 1784612222128, 1784612222128, 0),
  ('59e3b07a-3dcf-5eae-b0e1-ed5e4865634b', NULL, 'Cable Seated Overhead Curl', 'Kabelzug-Curl über Kopf sitzend', 'upper arms', 'biceps', 'cable', 'Sit on a bench facing the cable machine with your feet flat on the ground. Grasp the cable attachment with an underhand grip, palms facing up, and your hands shoulder-width apart. Keep your upper arms stationary and your elbows close to your sides. Exhale and curl the cable attachment towards your shoulders, contracting your biceps. Pause for a moment at the top of the movement, squeezing your biceps. Inhale and slowly lower the cable attachment back to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', NULL, 'forearms', '["forearms","shoulders"]', '["Sit on a bench facing the cable machine with your feet flat on the ground.","Grasp the cable attachment with an underhand grip, palms facing up, and your hands shoulder-width apart.","Keep your upper arms stationary and your elbows close to your sides.","Exhale and curl the cable attachment towards your shoulders, contracting your biceps.","Pause for a moment at the top of the movement, squeezing your biceps.","Inhale and slowly lower the cable attachment back to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."]', '["Setze dich mit dem Gesicht zum Kabelzug auf eine Bank, Füsse flach am Boden.","Greife den Kabelgriff im Untergriff, Handflächen nach oben, Hände schulterbreit auseinander.","Halte die Oberarme ruhig und die Ellbogen nah am Körper.","Atme aus und ziehe den Griff Richtung Schultern, indem du den Bizeps anspannst.","Halte am oberen Punkt kurz inne und spanne den Bizeps an.","Atme ein und senke den Griff langsam zurück in die Ausgangsposition ab, bis die Arme vollständig gestreckt sind.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1643.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1643.gif', 1784612222128, 1784612222128, 0),
  ('3f36a737-5332-584c-b2be-128c6a77995d', NULL, 'Cable Seated Rear Lateral Raise', 'Kabelzug-Seitheben hintere Schulter sitzend', 'shoulders', 'delts', 'cable', 'Sit on a bench facing the cable machine with your feet flat on the ground. Grasp the cable handles with an overhand grip and extend your arms straight in front of you. Keeping your arms straight, slowly raise them out to the sides until they are parallel to the floor. Pause for a moment at the top, then slowly lower your arms back to the starting position. Repeat for the desired number of repetitions.', NULL, 'traps', '["traps","rhomboids"]', '["Sit on a bench facing the cable machine with your feet flat on the ground.","Grasp the cable handles with an overhand grip and extend your arms straight in front of you.","Keeping your arms straight, slowly raise them out to the sides until they are parallel to the floor.","Pause for a moment at the top, then slowly lower your arms back to the starting position.","Repeat for the desired number of repetitions."]', '["Setze dich mit dem Gesicht zum Kabelzug auf eine Bank, Füsse flach am Boden.","Greife die Kabelgriffe im Obergriff und strecke die Arme gerade vor dir aus.","Halte die Arme gestreckt und hebe sie langsam seitlich an, bis sie parallel zum Boden sind.","Halte am oberen Punkt kurz inne und senke die Arme dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0215.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0215.gif', 1784612222128, 1784612222128, 0),
  ('813a3d92-7ebf-515b-88d0-a5fb31f43222', NULL, 'Cable Seated Row', 'Kabelzug-Rudern sitzend', 'back', 'upper back', 'cable', 'Sit on the cable row machine with your feet flat on the footrests and your knees slightly bent. Grasp the handles with an overhand grip, keeping your back straight and your shoulders relaxed. Pull the handles towards your body, squeezing your shoulder blades together. Pause for a moment at the peak of the movement, then slowly release the handles back to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","forearms"]', '["Sit on the cable row machine with your feet flat on the footrests and your knees slightly bent.","Grasp the handles with an overhand grip, keeping your back straight and your shoulders relaxed.","Pull the handles towards your body, squeezing your shoulder blades together.","Pause for a moment at the peak of the movement, then slowly release the handles back to the starting position.","Repeat for the desired number of repetitions."]', '["Setze dich an das Rudergerät, Füsse flach auf den Fussstützen, Knie leicht gebeugt.","Greife die Griffe im Obergriff, halte den Rücken gerade und die Schultern entspannt.","Ziehe die Griffe zum Körper und ziehe dabei die Schulterblätter zusammen.","Halte am Höhepunkt der Bewegung kurz inne und lass die Griffe dann langsam zurück in die Ausgangsposition gleiten.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0861.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0861.gif', 1784612222128, 1784612222128, 0),
  ('d3878d2f-1d05-5b9d-b3ea-74153da3ea4d', NULL, 'Cable Seated Shoulder Internal Rotation', 'Kabelzug-Innenrotation Schulter sitzend', 'shoulders', 'delts', 'cable', 'Sit on a bench or chair facing the cable machine with your feet flat on the ground. Hold the cable handle with your arm extended straight out in front of you, parallel to the ground. Keep your elbow slightly bent and your shoulder blades pulled back and down. Slowly rotate your arm inward, bringing the cable handle towards the center of your body. Pause for a moment at the end of the movement, then slowly return to the starting position. Repeat for the desired number of repetitions, then switch arms.', NULL, 'rotator cuff', '["rotator cuff","triceps"]', '["Sit on a bench or chair facing the cable machine with your feet flat on the ground.","Hold the cable handle with your arm extended straight out in front of you, parallel to the ground.","Keep your elbow slightly bent and your shoulder blades pulled back and down.","Slowly rotate your arm inward, bringing the cable handle towards the center of your body.","Pause for a moment at the end of the movement, then slowly return to the starting position.","Repeat for the desired number of repetitions, then switch arms."]', '["Setze dich mit dem Gesicht zum Kabelzug auf eine Bank oder einen Stuhl, Füsse flach am Boden.","Halte den Kabelgriff mit gestrecktem Arm vor dir, parallel zum Boden.","Halte den Ellbogen leicht gebeugt und die Schulterblätter nach hinten unten gezogen.","Drehe den Arm langsam nach innen und führe den Griff zur Körpermitte.","Halte am Ende der Bewegung kurz inne und kehre dann langsam in die Ausgangsposition zurück.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dann die Seite."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0216.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0216.gif', 1784612222128, 1784612222128, 0),
  ('01894930-f6d5-527c-8ba7-19bf8eb8c7ef', NULL, 'Cable Seated Twist', 'Kabelzug-Rumpfdrehung sitzend', 'waist', 'abs', 'cable', 'Sit on a cable machine with your feet flat on the ground and your knees slightly bent. Hold the cable handle with both hands and extend your arms straight in front of you. Keeping your core engaged, slowly rotate your torso to one side, pulling the cable across your body. Pause for a moment at the end of the range of motion, then slowly rotate back to the starting position. Repeat on the other side. Continue alternating sides for the desired number of repetitions.', NULL, 'obliques', '["obliques"]', '["Sit on a cable machine with your feet flat on the ground and your knees slightly bent.","Hold the cable handle with both hands and extend your arms straight in front of you.","Keeping your core engaged, slowly rotate your torso to one side, pulling the cable across your body.","Pause for a moment at the end of the range of motion, then slowly rotate back to the starting position.","Repeat on the other side.","Continue alternating sides for the desired number of repetitions."]', '["Setze dich an einen Kabelzug, Füsse flach am Boden, Knie leicht gebeugt.","Halte den Kabelgriff mit beiden Händen und strecke die Arme gerade vor dir aus.","Spanne die Körpermitte an und drehe den Oberkörper langsam zu einer Seite, wobei du das Kabel über den Körper ziehst.","Halte am Ende des Bewegungsradius kurz inne und drehe den Oberkörper dann langsam zurück in die Ausgangsposition.","Wiederhole auf der anderen Seite.","Wechsle die Seite fortlaufend für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/2399.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/2399.gif', 1784612222128, 1784612222128, 0),
  ('60449554-c4d8-5850-a366-3dba16683b07', NULL, 'Cable Seated Wide-Grip Row', 'Kabelzug-Rudern sitzend weiter Griff', 'back', 'upper back', 'cable', 'Sit on the cable row machine with your feet flat on the footrests and your knees slightly bent. Grasp the handle with a wide overhand grip, palms facing down. Keep your back straight and lean slightly forward from the hips. Pull the handle towards your lower chest, squeezing your shoulder blades together. Pause for a moment at the peak of the contraction. Slowly release the handle back to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","forearms"]', '["Sit on the cable row machine with your feet flat on the footrests and your knees slightly bent.","Grasp the handle with a wide overhand grip, palms facing down.","Keep your back straight and lean slightly forward from the hips.","Pull the handle towards your lower chest, squeezing your shoulder blades together.","Pause for a moment at the peak of the contraction.","Slowly release the handle back to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."]', '["Setze dich an das Rudergerät, Füsse flach auf den Fussstützen, Knie leicht gebeugt.","Greife den Griff im breiten Obergriff, Handflächen nach unten.","Halte den Rücken gerade und lehne dich leicht aus der Hüfte nach vorne.","Ziehe den Griff Richtung untere Brust und ziehe dabei die Schulterblätter zusammen.","Halte am Höhepunkt der Anspannung kurz inne.","Lass den Griff langsam zurück in die Ausgangsposition gleiten, bis die Arme vollständig gestreckt sind.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0218.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0218.gif', 1784612222128, 1784612222128, 0),
  ('ed157783-65a5-58ab-9eb8-9108896b6e7d', NULL, 'Cable Shoulder Press', 'Kabelzug-Schulterdrücken', 'shoulders', 'delts', 'cable', 'Adjust the cable machine so that the handles are at shoulder height. Stand facing away from the machine with your feet shoulder-width apart. Grasp the handles with an overhand grip and bring them up to shoulder level, with your elbows bent and pointing outwards. Press the handles upwards until your arms are fully extended overhead. Pause for a moment at the top, then slowly lower the handles back down to shoulder level. Repeat for the desired number of repetitions.', NULL, 'triceps', '["triceps","upper back"]', '["Adjust the cable machine so that the handles are at shoulder height.","Stand facing away from the machine with your feet shoulder-width apart.","Grasp the handles with an overhand grip and bring them up to shoulder level, with your elbows bent and pointing outwards.","Press the handles upwards until your arms are fully extended overhead.","Pause for a moment at the top, then slowly lower the handles back down to shoulder level.","Repeat for the desired number of repetitions."]', '["Stelle den Kabelzug so ein, dass die Griffe auf Schulterhöhe sind.","Stehe mit dem Rücken zum Gerät, Füsse schulterbreit auseinander.","Greife die Griffe im Obergriff und bringe sie auf Schulterhöhe, die Ellbogen zeigen nach aussen.","Drücke die Griffe nach oben, bis die Arme vollständig über dem Kopf gestreckt sind.","Halte am oberen Punkt kurz inne und senke die Griffe dann langsam zurück auf Schulterhöhe ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0219.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0219.gif', 1784612222128, 1784612222128, 0),
  ('e88010c4-edcd-5183-a36c-9bb1f5d99949', NULL, 'Cable Shrug', 'Kabelzug-Schulterheben', 'back', 'traps', 'cable', 'Stand facing the cable machine with your feet shoulder-width apart. Grasp the cable handles with an overhand grip and let your arms hang down in front of you. Keeping your arms straight, shrug your shoulders up towards your ears. Hold the contraction for a moment, then slowly lower your shoulders back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'shoulders', '["shoulders"]', '["Stand facing the cable machine with your feet shoulder-width apart.","Grasp the cable handles with an overhand grip and let your arms hang down in front of you.","Keeping your arms straight, shrug your shoulders up towards your ears.","Hold the contraction for a moment, then slowly lower your shoulders back down to the starting position.","Repeat for the desired number of repetitions."]', '["Stehe mit schulterbreiten Füssen vor dem Kabelzug.","Greife die Kabelgriffe im Obergriff und lass die Arme vor dir herabhängen.","Halte die Arme gestreckt und ziehe die Schultern Richtung Ohren hoch.","Halte die Anspannung kurz und senke die Schultern dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0220.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0220.gif', 1784612222128, 1784612222128, 0),
  ('5f9c3288-49a2-5a39-b1ad-7a479e114055', NULL, 'Cable Side Bend', 'Kabelzug-Seitbeuge', 'waist', 'abs', 'cable', 'Stand with your feet shoulder-width apart and grasp the cable handle with one hand. Keep your back straight and your core engaged. Slowly bend sideways at the waist, lowering the cable handle towards your knee. Pause for a moment, then return to the starting position. Repeat on the other side. Alternate sides for the desired number of repetitions.', NULL, 'obliques', '["obliques"]', '["Stand with your feet shoulder-width apart and grasp the cable handle with one hand.","Keep your back straight and your core engaged.","Slowly bend sideways at the waist, lowering the cable handle towards your knee.","Pause for a moment, then return to the starting position.","Repeat on the other side.","Alternate sides for the desired number of repetitions."]', '["Stehe mit schulterbreiten Füssen und greife den Kabelgriff mit einer Hand.","Halte den Rücken gerade und die Körpermitte angespannt.","Beuge dich langsam seitlich in der Hüfte und senke den Kabelgriff Richtung Knie ab.","Halte kurz inne und kehre dann in die Ausgangsposition zurück.","Wiederhole auf der anderen Seite.","Wechsle die Seite fortlaufend für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0222.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0222.gif', 1784612222128, 1784612222128, 0),
  ('24ef53cc-bf9b-5664-92d6-09e72f6fdd7c', NULL, 'Cable Side Bend Crunch (Bosu Ball)', 'Kabelzug-Seitbeuge-Crunch auf dem Bosu-Ball', 'waist', 'abs', 'cable', 'Stand with your feet shoulder-width apart, holding a cable handle in one hand. Place the other hand on your hip. Engage your core and slowly bend sideways towards the hand holding the cable, keeping your back straight. Pause for a moment at the bottom of the movement, then slowly return to the starting position. Repeat for the desired number of repetitions, then switch sides.', NULL, 'obliques', '["obliques"]', '["Stand with your feet shoulder-width apart, holding a cable handle in one hand.","Place the other hand on your hip.","Engage your core and slowly bend sideways towards the hand holding the cable, keeping your back straight.","Pause for a moment at the bottom of the movement, then slowly return to the starting position.","Repeat for the desired number of repetitions, then switch sides."]', '["Stehe mit schulterbreiten Füssen und halte den Kabelgriff mit einer Hand.","Lege die andere Hand auf die Hüfte.","Spanne die Körpermitte an und beuge dich langsam zur Seite mit dem Kabelgriff, der Rücken bleibt gerade.","Halte am unteren Punkt kurz inne und kehre dann langsam in die Ausgangsposition zurück.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dann die Seite."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0221.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0221.gif', 1784612222128, 1784612222128, 0),
  ('72d30d31-5fb7-52ae-a7e4-498546ed7bc1', NULL, 'Cable Side Crunch', 'Kabelzug-Seitlicher Crunch', 'waist', 'abs', 'cable', 'Attach a cable handle to a low pulley and stand sideways to the machine. Grasp the handle with the hand furthest from the machine and place your other hand on your hip. Keep your feet shoulder-width apart and your knees slightly bent. With your abs engaged, bend sideways at the waist, bringing your elbow down towards your hip. Pause for a moment at the bottom, then slowly return to the starting position. Repeat for the desired number of repetitions, then switch sides.', NULL, 'obliques', '["obliques"]', '["Attach a cable handle to a low pulley and stand sideways to the machine.","Grasp the handle with the hand furthest from the machine and place your other hand on your hip.","Keep your feet shoulder-width apart and your knees slightly bent.","With your abs engaged, bend sideways at the waist, bringing your elbow down towards your hip.","Pause for a moment at the bottom, then slowly return to the starting position.","Repeat for the desired number of repetitions, then switch sides."]', '["Befestige einen Kabelgriff an der unteren Umlenkrolle und stelle dich seitlich zum Gerät.","Greife den Griff mit der vom Gerät weiter entfernten Hand und lege die andere Hand auf die Hüfte.","Stelle die Füsse schulterbreit auseinander und beuge die Knie leicht.","Spanne die Bauchmuskeln an und beuge dich seitlich in der Hüfte, führe den Ellbogen Richtung Hüfte hinunter.","Halte am unteren Punkt kurz inne und kehre dann langsam in die Ausgangsposition zurück.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dann die Seite."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0223.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0223.gif', 1784612222128, 1784612222128, 0),
  ('e4397245-a11f-51f6-9c68-2fcf6d7abb5f', NULL, 'Cable Squat Row (with Rope Attachment)', 'Kabelzug-Kniebeuge-Rudern (Seilgriff)', 'back', 'lats', 'cable', 'Attach a rope to a cable machine at waist height. Stand facing the cable machine with your feet shoulder-width apart. Bend your knees and lower your body into a squat position, keeping your back straight and chest up. Grasp the rope with an overhand grip, with your hands shoulder-width apart. Engage your core and pull the rope towards your body, squeezing your shoulder blades together. Keep your elbows close to your body and continue pulling until your hands reach your chest. Pause for a moment at the top of the movement, then slowly release the rope and extend your arms back to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","rhomboids","rear deltoids"]', '["Attach a rope to a cable machine at waist height.","Stand facing the cable machine with your feet shoulder-width apart.","Bend your knees and lower your body into a squat position, keeping your back straight and chest up.","Grasp the rope with an overhand grip, with your hands shoulder-width apart.","Engage your core and pull the rope towards your body, squeezing your shoulder blades together.","Keep your elbows close to your body and continue pulling until your hands reach your chest.","Pause for a moment at the top of the movement, then slowly release the rope and extend your arms back to the starting position.","Repeat for the desired number of repetitions."]', '["Befestige ein Seil auf Hüfthöhe am Kabelzug.","Stehe mit schulterbreiten Füssen vor dem Kabelzug.","Beuge die Knie und senke den Körper in eine Kniebeuge ab, der Rücken bleibt gerade, die Brust raus.","Greife das Seil im Obergriff, Hände schulterbreit auseinander.","Spanne die Körpermitte an und ziehe das Seil zum Körper, indem du die Schulterblätter zusammenziehst.","Halte die Ellbogen nah am Körper und ziehe weiter, bis die Hände die Brust erreichen.","Halte am oberen Punkt kurz inne, lass das Seil dann langsam los und strecke die Arme zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1717.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1717.gif', 1784612222128, 1784612222128, 0),
  ('3acf3a23-a31b-517f-ac67-462d873485e7', NULL, 'Cable Squatting Curl', 'Kabelzug-Curl in der Kniebeuge', 'upper arms', 'biceps', 'cable', 'Attach a cable handle to the lowest setting on a cable machine. Stand facing the machine with your feet shoulder-width apart. Hold the cable handle with an underhand grip, palms facing up, and arms fully extended. Lower your body into a squat position, keeping your back straight and knees behind your toes. As you squat down, curl the cable handle towards your shoulders, keeping your elbows close to your sides. Pause for a moment at the top of the curl, squeezing your biceps. Slowly lower the cable handle back to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', NULL, 'forearms', '["forearms"]', '["Attach a cable handle to the lowest setting on a cable machine.","Stand facing the machine with your feet shoulder-width apart.","Hold the cable handle with an underhand grip, palms facing up, and arms fully extended.","Lower your body into a squat position, keeping your back straight and knees behind your toes.","As you squat down, curl the cable handle towards your shoulders, keeping your elbows close to your sides.","Pause for a moment at the top of the curl, squeezing your biceps.","Slowly lower the cable handle back to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."]', '["Befestige einen Kabelgriff auf der tiefsten Stufe am Kabelzug.","Stehe mit schulterbreiten Füssen vor dem Gerät.","Halte den Kabelgriff im Untergriff, Handflächen nach oben, Arme vollständig gestreckt.","Senke den Körper in eine Kniebeuge ab, der Rücken bleibt gerade, die Knie bleiben hinter den Zehenspitzen.","Ziehe den Kabelgriff beim Absenken in Richtung Schultern hoch, die Ellbogen bleiben nah am Körper.","Halte am oberen Punkt der Curl-Bewegung kurz inne und spanne den Bizeps an.","Senke den Kabelgriff langsam zurück in die Ausgangsposition ab, bis die Arme vollständig gestreckt sind.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1644.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1644.gif', 1784612222128, 1784612222128, 0),
  ('9cf5955e-d016-517c-b62f-59ea1be4d7ba', NULL, 'Cable Standing Back Wrist Curl', 'Kabelzug-Handgelenkcurl Obergriff stehend', 'lower arms', 'forearms', 'cable', 'Stand facing a cable machine with your feet shoulder-width apart. Hold the cable handle with an overhand grip, palms facing down. Keep your arms straight and your elbows close to your sides. Slowly curl your wrists upward, bringing the cable handle towards your body. Pause for a moment at the top, then slowly lower the cable handle back to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","brachialis"]', '["Stand facing a cable machine with your feet shoulder-width apart.","Hold the cable handle with an overhand grip, palms facing down.","Keep your arms straight and your elbows close to your sides.","Slowly curl your wrists upward, bringing the cable handle towards your body.","Pause for a moment at the top, then slowly lower the cable handle back to the starting position.","Repeat for the desired number of repetitions."]', '["Stehe mit schulterbreiten Füssen vor einem Kabelzug.","Halte den Kabelgriff im Obergriff, Handflächen nach unten.","Halte die Arme gestreckt und die Ellbogen nah am Körper.","Ziehe die Handgelenke langsam nach oben und führe den Kabelgriff Richtung Körper.","Halte am oberen Punkt kurz inne und senke den Kabelgriff dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0224.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0224.gif', 1784612222128, 1784612222128, 0),
  ('7df628db-19f3-50ac-a790-21ebf90b7171', NULL, 'Cable Standing Calf Raise', 'Kabelzug-Wadenheben stehend', 'lower legs', 'calves', 'cable', 'Stand facing a cable machine with your feet shoulder-width apart. Hold onto the cable machine handles or attach a cable ankle strap to your ankles. Raise your heels off the ground by extending your ankles as high as possible. Pause for a moment at the top, then slowly lower your heels back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'hamstrings', '["hamstrings","glutes"]', '["Stand facing a cable machine with your feet shoulder-width apart.","Hold onto the cable machine handles or attach a cable ankle strap to your ankles.","Raise your heels off the ground by extending your ankles as high as possible.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."]', '["Stehe mit schulterbreiten Füssen vor einem Kabelzug.","Halte dich an den Griffen des Kabelzugs fest oder befestige eine Kabel-Fussschlaufe an den Knöcheln.","Hebe die Fersen so weit wie möglich vom Boden ab, indem du die Sprunggelenke streckst.","Halte am oberen Punkt kurz inne und senke die Fersen dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1375.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1375.gif', 1784612222128, 1784612222128, 0),
  ('54c42eb8-7e91-5bf7-b685-54a4a7ec60fd', NULL, 'Cable Standing Cross-Over High Reverse Fly', 'Kabelzug-Reverse Fliegende stehend über Kreuz (hoch)', 'shoulders', 'delts', 'cable', 'Attach a D-handle to each side of a cable machine at shoulder height. Stand in the middle of the cable machine with your feet shoulder-width apart. Grasp the handles with an overhand grip and extend your arms out to the sides, palms facing forward. Keep a slight bend in your elbows and maintain a straight back throughout the exercise. Engage your shoulder muscles and squeeze your shoulder blades together as you pull the handles towards the front of your body. Pause for a moment at the peak of the movement, then slowly return to the starting position. Repeat for the desired number of repetitions.', NULL, 'trapezius', '["trapezius","rhomboids","rear deltoids"]', '["Attach a D-handle to each side of a cable machine at shoulder height.","Stand in the middle of the cable machine with your feet shoulder-width apart.","Grasp the handles with an overhand grip and extend your arms out to the sides, palms facing forward.","Keep a slight bend in your elbows and maintain a straight back throughout the exercise.","Engage your shoulder muscles and squeeze your shoulder blades together as you pull the handles towards the front of your body.","Pause for a moment at the peak of the movement, then slowly return to the starting position.","Repeat for the desired number of repetitions."]', '["Befestige an jeder Seite des Kabelzugs auf Schulterhöhe einen D-Griff.","Stehe mit schulterbreiten Füssen mittig zwischen den Kabelzügen.","Greife die Griffe im Obergriff und strecke die Arme seitlich aus, Handflächen nach vorne.","Halte die Ellbogen leicht gebeugt und den Rücken während der ganzen Übung gerade.","Spanne die Schultermuskeln an und ziehe die Schulterblätter zusammen, während du die Griffe vor den Körper ziehst.","Halte am Höhepunkt der Bewegung kurz inne und kehre dann langsam in die Ausgangsposition zurück.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0225.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0225.gif', 1784612222128, 1784612222128, 0),
  ('3bb10022-3069-5708-8bfb-4aceab1e72e8', NULL, 'Cable Standing Crunch', 'Kabelzug-Crunch stehend', 'waist', 'abs', 'cable', 'Attach a cable handle to a high pulley and stand facing away from the machine. Hold the handle with both hands and place it behind your head, keeping your elbows bent. Stand with your feet shoulder-width apart and your knees slightly bent. Keeping your abs engaged, exhale and crunch your torso down towards your knees, bringing your elbows towards your thighs. Pause for a moment at the bottom of the movement, then slowly return to the starting position. Repeat for the desired number of repetitions.', NULL, 'obliques', '["obliques"]', '["Attach a cable handle to a high pulley and stand facing away from the machine.","Hold the handle with both hands and place it behind your head, keeping your elbows bent.","Stand with your feet shoulder-width apart and your knees slightly bent.","Keeping your abs engaged, exhale and crunch your torso down towards your knees, bringing your elbows towards your thighs.","Pause for a moment at the bottom of the movement, then slowly return to the starting position.","Repeat for the desired number of repetitions."]', '["Befestige einen Kabelgriff an der oberen Umlenkrolle und stehe mit dem Rücken zum Gerät.","Halte den Griff mit beiden Händen hinter dem Kopf, die Ellbogen bleiben gebeugt.","Stehe mit schulterbreiten Füssen und leicht gebeugten Knien.","Spanne die Bauchmuskeln an, atme aus und beuge den Oberkörper Richtung Knie, führe dabei die Ellbogen Richtung Oberschenkel.","Halte am unteren Punkt der Bewegung kurz inne und kehre dann langsam in die Ausgangsposition zurück.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0226.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0226.gif', 1784612222128, 1784612222128, 0),
  ('1d9d3736-9ce4-55d0-a779-21d5d98ec0dc', NULL, 'Cable Standing Crunch (with Rope Attachment)', 'Kabelzug-Crunch stehend (Seilgriff)', 'waist', 'abs', 'cable', 'Attach a rope to a cable machine at chest height. Stand facing away from the machine with your feet shoulder-width apart. Hold the rope with both hands and bring it behind your head, keeping your elbows bent. Engage your abs and slowly crunch your torso forward, bringing your elbows towards your knees. Pause for a moment at the top of the crunch, then slowly return to the starting position. Repeat for the desired number of repetitions.', NULL, 'obliques', '["obliques"]', '["Attach a rope to a cable machine at chest height.","Stand facing away from the machine with your feet shoulder-width apart.","Hold the rope with both hands and bring it behind your head, keeping your elbows bent.","Engage your abs and slowly crunch your torso forward, bringing your elbows towards your knees.","Pause for a moment at the top of the crunch, then slowly return to the starting position.","Repeat for the desired number of repetitions."]', '["Befestige ein Seil auf Brusthöhe am Kabelzug.","Stehe mit dem Rücken zum Gerät, Füsse schulterbreit auseinander.","Halte das Seil mit beiden Händen hinter dem Kopf, die Ellbogen bleiben gebeugt.","Spanne die Bauchmuskeln an und beuge den Oberkörper langsam nach vorne, führe dabei die Ellbogen Richtung Knie.","Halte am oberen Punkt der Beugung kurz inne und kehre dann langsam in die Ausgangsposition zurück.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0874.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0874.gif', 1784612222128, 1784612222128, 0),
  ('cb84171e-d005-57f8-9fd3-064254c275e8', NULL, 'Cable Standing Fly', 'Kabelzug-Fliegende stehend', 'chest', 'pectorals', 'cable', 'Attach the handles to the cables at chest height. Stand with your feet shoulder-width apart, facing away from the cable machine. Grasp the handles with an overhand grip, palms facing forward. Step forward slightly to create tension in the cables. Keep your core engaged and your back straight throughout the exercise. With a slight bend in your elbows, slowly bring your arms forward and together in front of your chest. Squeeze your chest muscles at the peak of the movement. Slowly reverse the movement, returning your arms to the starting position. Repeat for the desired number of repetitions.', NULL, 'deltoids', '["deltoids","triceps"]', '["Attach the handles to the cables at chest height.","Stand with your feet shoulder-width apart, facing away from the cable machine.","Grasp the handles with an overhand grip, palms facing forward.","Step forward slightly to create tension in the cables.","Keep your core engaged and your back straight throughout the exercise.","With a slight bend in your elbows, slowly bring your arms forward and together in front of your chest.","Squeeze your chest muscles at the peak of the movement.","Slowly reverse the movement, returning your arms to the starting position.","Repeat for the desired number of repetitions."]', '["Befestige die Griffe auf Brusthöhe an den Kabeln.","Stehe mit schulterbreiten Füssen, mit dem Rücken zum Kabelzug.","Greife die Griffe im Obergriff, Handflächen nach vorne.","Trete leicht nach vorne, um Zug auf die Kabel zu bringen.","Halte die Körpermitte während der ganzen Übung angespannt und den Rücken gerade.","Halte die Ellbogen leicht gebeugt und führe die Arme langsam nach vorne und vor der Brust zusammen.","Spanne die Brustmuskeln am Höhepunkt der Bewegung an.","Kehre die Bewegung langsam um und führe die Arme zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0227.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0227.gif', 1784612222128, 1784612222128, 0),
  ('f8f537a1-d283-5aea-89af-42fbc6a1d970', NULL, 'Cable Standing Hip Extension', 'Kabelzug-Hüftstrecken stehend', 'upper legs', 'glutes', 'cable', 'Attach a cable to a low pulley and stand facing away from the machine. Place the cable around your ankle and stand with your feet shoulder-width apart. Keep your core engaged and your back straight throughout the exercise. Slowly extend your leg straight back, squeezing your glutes at the top of the movement. Pause for a moment, then return to the starting position. Repeat for the desired number of repetitions. Switch sides and repeat with the other leg.', NULL, 'hamstrings', '["hamstrings","quadriceps"]', '["Attach a cable to a low pulley and stand facing away from the machine.","Place the cable around your ankle and stand with your feet shoulder-width apart.","Keep your core engaged and your back straight throughout the exercise.","Slowly extend your leg straight back, squeezing your glutes at the top of the movement.","Pause for a moment, then return to the starting position.","Repeat for the desired number of repetitions.","Switch sides and repeat with the other leg."]', '["Befestige ein Kabel an der unteren Umlenkrolle und stehe mit dem Rücken zum Gerät.","Lege das Kabel um deinen Knöchel und stehe mit schulterbreiten Füssen.","Halte die Körpermitte während der ganzen Übung angespannt und den Rücken gerade.","Strecke das Bein langsam gerade nach hinten und spanne das Gesäss am oberen Punkt an.","Halte kurz inne und kehre dann in die Ausgangsposition zurück.","Wiederhole für die gewünschte Anzahl Wiederholungen.","Wechsle die Seite und wiederhole mit dem anderen Bein."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0228.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0228.gif', 1784612222128, 1784612222128, 0),
  ('dc0451dc-d31b-5203-95ea-672b3db8acf2', NULL, 'Cable Standing Inner Curl', 'Kabelzug-Curl stehend innen', 'upper arms', 'biceps', 'cable', 'Stand facing a cable machine with your feet shoulder-width apart. Grasp the cable handle with an underhand grip, palms facing up. Keep your elbows close to your sides and your upper arms stationary. Exhale and curl the cable handle towards your shoulders, contracting your biceps. Pause for a moment at the top of the movement, squeezing your biceps. Inhale and slowly lower the cable handle back to the starting position. Repeat for the desired number of repetitions.', NULL, 'forearms', '["forearms"]', '["Stand facing a cable machine with your feet shoulder-width apart.","Grasp the cable handle with an underhand grip, palms facing up.","Keep your elbows close to your sides and your upper arms stationary.","Exhale and curl the cable handle towards your shoulders, contracting your biceps.","Pause for a moment at the top of the movement, squeezing your biceps.","Inhale and slowly lower the cable handle back to the starting position.","Repeat for the desired number of repetitions."]', '["Stehe mit schulterbreiten Füssen vor einem Kabelzug.","Greife den Kabelgriff im Untergriff, Handflächen nach oben.","Halte die Ellbogen nah am Körper und die Oberarme ruhig.","Atme aus und ziehe den Kabelgriff Richtung Schultern, spanne dabei den Bizeps an.","Halte am oberen Punkt kurz inne und spanne den Bizeps an.","Atme ein und senke den Kabelgriff langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0229.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0229.gif', 1784612222128, 1784612222128, 0),
  ('1d816844-017b-5b5d-9d80-5385c0db83e1', NULL, 'Cable Standing Lift', 'Kabelzug-Heben stehend', 'waist', 'abs', 'cable', 'Stand facing the cable machine with your feet shoulder-width apart. Hold the cable handle with both hands and position it at waist height. Engage your core and maintain a straight back throughout the exercise. Keeping your arms straight, exhale and lift the cable handle up towards your opposite shoulder, rotating your torso. Pause for a moment at the top, then inhale and slowly lower the cable handle back to the starting position. Repeat for the desired number of repetitions, then switch sides.', NULL, 'obliques', '["obliques","lower back"]', '["Stand facing the cable machine with your feet shoulder-width apart.","Hold the cable handle with both hands and position it at waist height.","Engage your core and maintain a straight back throughout the exercise.","Keeping your arms straight, exhale and lift the cable handle up towards your opposite shoulder, rotating your torso.","Pause for a moment at the top, then inhale and slowly lower the cable handle back to the starting position.","Repeat for the desired number of repetitions, then switch sides."]', '["Stehe mit schulterbreiten Füssen vor dem Kabelzug.","Halte den Kabelgriff mit beiden Händen auf Hüfthöhe.","Spanne die Körpermitte an und halte den Rücken während der ganzen Übung gerade.","Halte die Arme gestreckt, atme aus und ziehe den Kabelgriff hoch Richtung gegenüberliegende Schulter, drehe dabei den Oberkörper.","Halte am oberen Punkt kurz inne, atme dann ein und senke den Kabelgriff langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dann die Seite."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0230.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0230.gif', 1784612222128, 1784612222128, 0),
  ('b88d0930-5460-5708-ba9b-a5f990c16fee', NULL, 'Cable Standing One Arm Triceps Extension', 'Kabelzug-Trizepsstrecken stehend einarmig', 'upper arms', 'triceps', 'cable', 'Stand with your feet shoulder-width apart, facing the cable machine. Hold the cable handle with your right hand, palm facing down, and position your arm so that it is fully extended and parallel to the ground. Keep your elbow stationary and close to your body. Slowly bend your elbow, lowering the cable handle towards the back of your head. Pause for a moment at the bottom of the movement, then extend your arm back to the starting position. Repeat for the desired number of repetitions, then switch sides and perform the exercise with your left arm.', NULL, 'shoulders', '["shoulders"]', '["Stand with your feet shoulder-width apart, facing the cable machine.","Hold the cable handle with your right hand, palm facing down, and position your arm so that it is fully extended and parallel to the ground.","Keep your elbow stationary and close to your body.","Slowly bend your elbow, lowering the cable handle towards the back of your head.","Pause for a moment at the bottom of the movement, then extend your arm back to the starting position.","Repeat for the desired number of repetitions, then switch sides and perform the exercise with your left arm."]', '["Stehe mit schulterbreiten Füssen vor dem Kabelzug.","Halte den Kabelgriff mit der rechten Hand, Handfläche nach unten, der Arm ist vollständig gestreckt und parallel zum Boden.","Halte den Ellbogen ruhig und nah am Körper.","Beuge den Ellbogen langsam und senke den Kabelgriff Richtung Hinterkopf ab.","Halte am unteren Punkt kurz inne und strecke den Arm dann zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dann die Seite, um die Übung mit dem linken Arm auszuführen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0231.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0231.gif', 1784612222128, 1784612222128, 0),
  ('6027d06d-5654-5cac-8133-703c55d79c5a', NULL, 'Cable Standing One Leg Calf Raise', 'Kabelzug-Wadenheben stehend einbeinig', 'lower legs', 'calves', 'cable', 'Stand facing a cable machine with your feet shoulder-width apart. Hold onto the cable machine for support. Lift one leg off the ground and balance on the other leg. Slowly raise your heel off the ground, lifting your body up onto your toes. Pause for a moment at the top, then slowly lower your heel back down to the starting position. Repeat for the desired number of repetitions, then switch legs.', NULL, 'ankles', '["ankles","feet"]', '["Stand facing a cable machine with your feet shoulder-width apart.","Hold onto the cable machine for support.","Lift one leg off the ground and balance on the other leg.","Slowly raise your heel off the ground, lifting your body up onto your toes.","Pause for a moment at the top, then slowly lower your heel back down to the starting position.","Repeat for the desired number of repetitions, then switch legs."]', '["Stehe mit schulterbreiten Füssen vor einem Kabelzug.","Halte dich am Kabelzug fest, um das Gleichgewicht zu halten.","Hebe ein Bein vom Boden ab und balanciere auf dem anderen Bein.","Hebe die Ferse langsam vom Boden ab, sodass sich dein Körper auf die Zehenspitzen hebt.","Halte am oberen Punkt kurz inne und senke die Ferse dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dann das Bein."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1376.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1376.gif', 1784612222128, 1784612222128, 0),
  ('49042ade-2da4-5197-9dac-f7226786dd2b', NULL, 'Cable Standing Pulldown (with Rope)', 'Kabelzug-Latzug stehend (mit Seil)', 'upper arms', 'biceps', 'cable', 'Attach a rope to the cable machine at the highest setting. Stand facing the machine with your feet shoulder-width apart. Grasp the rope with an overhand grip, palms facing down. Keep your back straight and core engaged throughout the exercise. Pull the rope down towards your thighs, squeezing your biceps. Pause for a moment at the bottom, then slowly release the rope back up. Repeat for the desired number of repetitions.', NULL, 'forearms', '["forearms","shoulders"]', '["Attach a rope to the cable machine at the highest setting.","Stand facing the machine with your feet shoulder-width apart.","Grasp the rope with an overhand grip, palms facing down.","Keep your back straight and core engaged throughout the exercise.","Pull the rope down towards your thighs, squeezing your biceps.","Pause for a moment at the bottom, then slowly release the rope back up.","Repeat for the desired number of repetitions."]', '["Befestige ein Seil auf höchster Stufe am Kabelzug.","Stehe mit schulterbreiten Füssen vor dem Gerät.","Greife das Seil im Obergriff, Handflächen nach unten.","Halte den Rücken gerade und die Körpermitte während der ganzen Übung angespannt.","Ziehe das Seil Richtung Oberschenkel nach unten und spanne dabei den Bizeps an.","Halte am unteren Punkt kurz inne und lass das Seil dann langsam wieder nach oben gleiten.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0232.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0232.gif', 1784612222128, 1784612222128, 0),
  ('2a65fc3d-1fe1-5c7f-bfe9-cf93d41e5570', NULL, 'Cable Standing Rear Delt Row (with Rope)', 'Kabelzug-Rudern hintere Schulter stehend (mit Seil)', 'shoulders', 'delts', 'cable', 'Stand facing a cable machine with your feet shoulder-width apart. Hold the cable attachment with both hands, palms facing each other, and step back to create tension in the cable. Keep your back straight and your core engaged. Pull the cable towards your body, squeezing your shoulder blades together. Pause for a moment at the peak of the movement, then slowly release the cable back to the starting position. Repeat for the desired number of repetitions.', NULL, 'trapezius', '["trapezius","rhomboids","biceps"]', '["Stand facing a cable machine with your feet shoulder-width apart.","Hold the cable attachment with both hands, palms facing each other, and step back to create tension in the cable.","Keep your back straight and your core engaged.","Pull the cable towards your body, squeezing your shoulder blades together.","Pause for a moment at the peak of the movement, then slowly release the cable back to the starting position.","Repeat for the desired number of repetitions."]', '["Stehe mit schulterbreiten Füssen vor einem Kabelzug.","Halte den Kabelgriff mit beiden Händen, Handflächen zueinander, und trete zurück, um Zug auf das Kabel zu bringen.","Halte den Rücken gerade und die Körpermitte angespannt.","Ziehe das Kabel zum Körper und ziehe dabei die Schulterblätter zusammen.","Halte am Höhepunkt der Bewegung kurz inne und lass das Kabel dann langsam zurück in die Ausgangsposition gleiten.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0233.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0233.gif', 1784612222128, 1784612222128, 0);

INSERT OR REPLACE INTO exercises (id, user_id, name, name_de, category, primary_muscle, equipment, instructions_en, instructions_de, muscle_group, secondary_muscles, instruction_steps_en, instruction_steps_de, thumbnail_url, gif_url, created_at, updated_at, deleted) VALUES
  ('cd7a372d-afbf-5c55-8687-9ac96277cdc2', NULL, 'Cable Standing Reverse Grip One Arm Overhead Tricep Extension', 'Kabelzug-Trizepsstrecken über Kopf stehend einarmig Untergriff', 'upper arms', 'triceps', 'cable', 'Stand facing away from the cable machine with your feet shoulder-width apart. Hold the cable handle with an underhand grip and extend your arm overhead, keeping your elbow close to your head. Keep your upper arm stationary and slowly lower the cable handle behind your head by bending your elbow. Pause for a moment at the bottom, then extend your arm back to the starting position. Repeat for the desired number of repetitions, then switch arms.', NULL, 'shoulders', '["shoulders"]', '["Stand facing away from the cable machine with your feet shoulder-width apart.","Hold the cable handle with an underhand grip and extend your arm overhead, keeping your elbow close to your head.","Keep your upper arm stationary and slowly lower the cable handle behind your head by bending your elbow.","Pause for a moment at the bottom, then extend your arm back to the starting position.","Repeat for the desired number of repetitions, then switch arms."]', '["Stehe mit dem Rücken zum Kabelzug, Füsse schulterbreit auseinander.","Halte den Kabelgriff im Untergriff und strecke den Arm über den Kopf, der Ellbogen bleibt nah am Kopf.","Halte den Oberarm ruhig und senke den Kabelgriff langsam hinter den Kopf ab, indem du den Ellbogen beugst.","Halte am unteren Punkt kurz inne und strecke den Arm dann zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dann die Seite."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1727.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1727.gif', 1784612222128, 1784612222128, 0),
  ('0c63f8e3-83d6-5983-af2b-9a8dcfeb6768', NULL, 'Cable Standing Row (V-Bar)', 'Kabelzug-Rudern stehend (V-Griff)', 'back', 'upper back', 'cable', 'Stand facing the cable machine with your feet shoulder-width apart. Grasp the v-bar attachment with an overhand grip, palms facing down. Keep your back straight and your core engaged. Pull the v-bar towards your body, squeezing your shoulder blades together. Pause for a moment at the peak of the movement, then slowly release the tension and return to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","shoulders"]', '["Stand facing the cable machine with your feet shoulder-width apart.","Grasp the v-bar attachment with an overhand grip, palms facing down.","Keep your back straight and your core engaged.","Pull the v-bar towards your body, squeezing your shoulder blades together.","Pause for a moment at the peak of the movement, then slowly release the tension and return to the starting position.","Repeat for the desired number of repetitions."]', '["Stehe mit schulterbreiten Füssen vor dem Kabelzug.","Greife den V-Griff im Obergriff, Handflächen nach unten.","Halte den Rücken gerade und die Körpermitte angespannt.","Ziehe den V-Griff zum Körper und ziehe dabei die Schulterblätter zusammen.","Halte am Höhepunkt der Bewegung kurz inne, lass die Spannung dann langsam nach und kehre in die Ausgangsposition zurück.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0234.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0234.gif', 1784612222128, 1784612222128, 0),
  ('8811b5ce-65f7-5819-a9b4-913bfcd3045e', NULL, 'Cable Standing Shoulder External Rotation', 'Kabelzug-Aussenrotation Schulter stehend', 'shoulders', 'delts', 'cable', 'Stand with your feet shoulder-width apart and your knees slightly bent. Hold the cable handle with your arm extended in front of you, parallel to the ground. Keep your elbow slightly bent and your shoulder blades pulled back. Slowly rotate your arm outward, away from your body, while keeping your elbow in the same position. Pause for a moment at the end of the movement, then slowly return to the starting position. Repeat for the desired number of repetitions.', NULL, 'rotator cuff', '["rotator cuff","trapezius"]', '["Stand with your feet shoulder-width apart and your knees slightly bent.","Hold the cable handle with your arm extended in front of you, parallel to the ground.","Keep your elbow slightly bent and your shoulder blades pulled back.","Slowly rotate your arm outward, away from your body, while keeping your elbow in the same position.","Pause for a moment at the end of the movement, then slowly return to the starting position.","Repeat for the desired number of repetitions."]', '["Stehe mit schulterbreiten Füssen und leicht gebeugten Knien.","Halte den Kabelgriff mit gestrecktem Arm vor dir, parallel zum Boden.","Halte den Ellbogen leicht gebeugt und die Schulterblätter nach hinten gezogen.","Drehe den Arm langsam nach aussen, vom Körper weg, während der Ellbogen an der gleichen Stelle bleibt.","Halte am Ende der Bewegung kurz inne und kehre dann langsam in die Ausgangsposition zurück.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0235.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0235.gif', 1784612222128, 1784612222128, 0),
  ('23b4564b-7a16-556d-ab70-0f1f8bdf31b9', NULL, 'Cable Standing Twist Row (V-Bar)', 'Kabelzug-Rudern mit Drehung stehend (V-Griff)', 'back', 'upper back', 'cable', 'Attach a v-bar attachment to a cable machine at chest height. Stand facing the cable machine with your feet shoulder-width apart. Grasp the v-bar with an overhand grip, palms facing down. Take a step back to create tension in the cable. Keep your back straight and core engaged throughout the exercise. Pull the v-bar towards your torso by retracting your shoulder blades and bending your elbows. As you pull, twist your torso to one side, squeezing your shoulder blades together. Pause for a moment at the top of the movement, feeling the contraction in your upper back. Slowly release the tension and return to the starting position, untwisting your torso. Repeat the movement for the desired number of repetitions, alternating the twisting direction with each rep.', NULL, 'biceps', '["biceps","shoulders"]', '["Attach a v-bar attachment to a cable machine at chest height.","Stand facing the cable machine with your feet shoulder-width apart.","Grasp the v-bar with an overhand grip, palms facing down.","Take a step back to create tension in the cable.","Keep your back straight and core engaged throughout the exercise.","Pull the v-bar towards your torso by retracting your shoulder blades and bending your elbows.","As you pull, twist your torso to one side, squeezing your shoulder blades together.","Pause for a moment at the top of the movement, feeling the contraction in your upper back.","Slowly release the tension and return to the starting position, untwisting your torso.","Repeat the movement for the desired number of repetitions, alternating the twisting direction with each rep."]', '["Befestige einen V-Griff auf Brusthöhe am Kabelzug.","Stehe mit schulterbreiten Füssen vor dem Kabelzug.","Greife den V-Griff im Obergriff, Handflächen nach unten.","Trete einen Schritt zurück, um Zug auf das Kabel zu bringen.","Halte den Rücken gerade und die Körpermitte während der ganzen Übung angespannt.","Ziehe den V-Griff zum Oberkörper, indem du die Schulterblätter zurückziehst und die Ellbogen beugst.","Drehe beim Ziehen den Oberkörper zu einer Seite und ziehe dabei die Schulterblätter zusammen.","Halte am oberen Punkt kurz inne und spüre die Anspannung im oberen Rücken.","Lass die Spannung langsam nach und kehre in die Ausgangsposition zurück, während du den Oberkörper zurückdrehst.","Wiederhole die Bewegung für die gewünschte Anzahl Wiederholungen und wechsle bei jeder Wiederholung die Drehrichtung."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0236.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0236.gif', 1784612222128, 1784612222128, 0),
  ('9ed1708b-21e2-58b1-834c-a8873fee20c3', NULL, 'Cable Standing Up Straight Crossovers', 'Kabelzug-Crossover stehend aufrecht', 'chest', 'pectorals', 'cable', 'Stand in the middle of a cable machine with your feet shoulder-width apart. Hold the handles of the cables with your palms facing down and your arms extended straight out to the sides. Keeping your arms straight, bring your hands together in front of your body, crossing them over each other. Pause for a moment, then slowly return to the starting position, keeping your arms extended. Repeat for the desired number of repetitions.', NULL, 'deltoids', '["deltoids","triceps"]', '["Stand in the middle of a cable machine with your feet shoulder-width apart.","Hold the handles of the cables with your palms facing down and your arms extended straight out to the sides.","Keeping your arms straight, bring your hands together in front of your body, crossing them over each other.","Pause for a moment, then slowly return to the starting position, keeping your arms extended.","Repeat for the desired number of repetitions."]', '["Stehe mittig zwischen den Kabelzügen, Füsse schulterbreit auseinander.","Halte die Griffe der Kabel mit nach unten zeigenden Handflächen, die Arme sind seitlich gestreckt.","Halte die Arme gestreckt und führe die Hände vor dem Körper zusammen, sodass sie sich kreuzen.","Halte kurz inne und kehre dann langsam in die Ausgangsposition zurück, die Arme bleiben gestreckt.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1269.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1269.gif', 1784612222128, 1784612222128, 0),
  ('5cf48b43-39f4-5e6a-bfe3-6b3adbdc2cb4', NULL, 'Cable Straight Arm Pulldown', 'Kabelzug-Latzug mit gestrecktem Arm', 'back', 'lats', 'cable', 'Attach a straight bar to the high pulley of a cable machine. Stand facing the machine with your feet shoulder-width apart. Grasp the bar with an overhand grip, keeping your arms straight and your palms facing down. Engage your lats and pull the bar down towards your thighs, keeping your arms straight throughout the movement. Pause for a moment at the bottom, then slowly return the bar to the starting position. Repeat for the desired number of repetitions.', NULL, 'shoulders', '["shoulders","biceps"]', '["Attach a straight bar to the high pulley of a cable machine.","Stand facing the machine with your feet shoulder-width apart.","Grasp the bar with an overhand grip, keeping your arms straight and your palms facing down.","Engage your lats and pull the bar down towards your thighs, keeping your arms straight throughout the movement.","Pause for a moment at the bottom, then slowly return the bar to the starting position.","Repeat for the desired number of repetitions."]', '["Befestige eine Stange an der oberen Umlenkrolle des Kabelzugs.","Stehe mit schulterbreiten Füssen vor dem Gerät.","Greife die Stange im Obergriff, die Arme bleiben gestreckt, Handflächen nach unten.","Spanne den Latissimus an und ziehe die Stange in Richtung Oberschenkel, die Arme bleiben während der Bewegung gestreckt.","Halte am unteren Punkt kurz inne und führe die Stange dann langsam zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0238.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0238.gif', 1784612222128, 1784612222128, 0),
  ('7d37b0a1-9543-5d69-b2cc-1a9aadac8e84', NULL, 'Cable Straight Arm Pulldown (with Rope)', 'Kabelzug-Latzug mit gestrecktem Arm (Seil)', 'back', 'lats', 'cable', 'Attach a rope to the cable machine at the highest setting. Stand facing the machine with your feet shoulder-width apart. Grasp the rope with both hands, palms facing down. Extend your arms fully in front of you, keeping your elbows slightly bent. Engage your lats and slowly pull the rope down towards your thighs, keeping your arms straight. Pause for a moment at the bottom, then slowly release the tension and return to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","forearms"]', '["Attach a rope to the cable machine at the highest setting.","Stand facing the machine with your feet shoulder-width apart.","Grasp the rope with both hands, palms facing down.","Extend your arms fully in front of you, keeping your elbows slightly bent.","Engage your lats and slowly pull the rope down towards your thighs, keeping your arms straight.","Pause for a moment at the bottom, then slowly release the tension and return to the starting position.","Repeat for the desired number of repetitions."]', '["Befestige ein Seil auf höchster Stufe am Kabelzug.","Stehe mit schulterbreiten Füssen vor dem Gerät.","Greife das Seil mit beiden Händen, Handflächen nach unten.","Strecke die Arme vollständig vor dir aus, die Ellbogen bleiben leicht gebeugt.","Spanne den Latissimus an und ziehe das Seil langsam Richtung Oberschenkel, die Arme bleiben gestreckt.","Halte am unteren Punkt kurz inne, lass die Spannung dann langsam nach und kehre in die Ausgangsposition zurück.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0237.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0237.gif', 1784612222128, 1784612222128, 0),
  ('30bff524-0fa4-599b-86c0-f47ead4895d4', NULL, 'Cable Straight Back Seated Row', 'Kabelzug-Rudern sitzend mit geradem Rücken', 'back', 'upper back', 'cable', 'Sit on the cable row machine with your feet flat on the footrests and your knees slightly bent. Grasp the cable handles with an overhand grip, palms facing down. Keep your back straight and lean slightly forward from the hips. Pull the cable handles towards your body, squeezing your shoulder blades together. Pause for a moment at the peak of the movement, then slowly release the handles back to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","forearms","shoulders"]', '["Sit on the cable row machine with your feet flat on the footrests and your knees slightly bent.","Grasp the cable handles with an overhand grip, palms facing down.","Keep your back straight and lean slightly forward from the hips.","Pull the cable handles towards your body, squeezing your shoulder blades together.","Pause for a moment at the peak of the movement, then slowly release the handles back to the starting position.","Repeat for the desired number of repetitions."]', '["Setze dich an das Rudergerät, Füsse flach auf den Fussstützen, Knie leicht gebeugt.","Greife die Kabelgriffe im Obergriff, Handflächen nach unten.","Halte den Rücken gerade und lehne dich leicht aus der Hüfte nach vorne.","Ziehe die Kabelgriffe zum Körper und ziehe dabei die Schulterblätter zusammen.","Halte am Höhepunkt der Bewegung kurz inne und lass die Griffe dann langsam zurück in die Ausgangsposition gleiten.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0239.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0239.gif', 1784612222128, 1784612222128, 0),
  ('0d1f8959-95d7-5f88-beef-6a7f96e4c983', NULL, 'Cable Supine Reverse Fly', 'Kabelzug-Reverse Fliegende liegend', 'shoulders', 'delts', 'cable', 'Attach a D-handle to a low pulley cable machine and lie face down on a flat bench. Grasp the D-handle with each hand, palms facing down, and extend your arms straight out in front of you. Keeping your arms straight, raise them out to the sides until they are parallel to the floor. Pause for a moment at the top, then slowly lower your arms back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'trapezius', '["trapezius","rhomboids"]', '["Attach a D-handle to a low pulley cable machine and lie face down on a flat bench.","Grasp the D-handle with each hand, palms facing down, and extend your arms straight out in front of you.","Keeping your arms straight, raise them out to the sides until they are parallel to the floor.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."]', '["Befestige einen D-Griff an der unteren Umlenkrolle und lege dich mit dem Gesicht nach unten auf eine flache Bank.","Greife den D-Griff mit jeder Hand, Handflächen nach unten, und strecke die Arme gerade vor dir aus.","Halte die Arme gestreckt und hebe sie seitlich an, bis sie parallel zum Boden sind.","Halte am oberen Punkt kurz inne und senke die Arme dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0240.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0240.gif', 1784612222128, 1784612222128, 0),
  ('b196294f-8dfb-59d0-84fe-9fc9b1cae943', NULL, 'Cable Thibaudeau Kayak Row', 'Kabelzug-Kayak-Rudern nach Thibaudeau', 'back', 'lats', 'cable', 'Attach a cable handle to a low pulley and sit facing the machine with your feet flat on the floor. Grasp the handle with your right hand and extend your arm fully, keeping a slight bend in your elbow. Lean forward from your hips, keeping your back straight and your abs engaged. Pull the handle towards your torso by retracting your shoulder blade and bending your elbow, keeping your arm close to your body. Squeeze your back muscles at the top of the movement, then slowly return to the starting position. Repeat for the desired number of repetitions, then switch sides and perform with your left arm.', NULL, 'biceps', '["biceps","rhomboids","rear deltoids"]', '["Attach a cable handle to a low pulley and sit facing the machine with your feet flat on the floor.","Grasp the handle with your right hand and extend your arm fully, keeping a slight bend in your elbow.","Lean forward from your hips, keeping your back straight and your abs engaged.","Pull the handle towards your torso by retracting your shoulder blade and bending your elbow, keeping your arm close to your body.","Squeeze your back muscles at the top of the movement, then slowly return to the starting position.","Repeat for the desired number of repetitions, then switch sides and perform with your left arm."]', '["Befestige einen Kabelgriff an der unteren Umlenkrolle und setze dich mit dem Gesicht zum Gerät, die Füsse flach auf dem Boden.","Greife den Griff mit der rechten Hand und strecke den Arm vollständig, der Ellbogen bleibt leicht gebeugt.","Beuge dich aus der Hüfte nach vorne, der Rücken bleibt gerade, die Bauchmuskeln angespannt.","Ziehe den Griff zum Oberkörper, indem du das Schulterblatt zurückziehst und den Ellbogen beugst, der Arm bleibt nah am Körper.","Spanne die Rückenmuskeln am oberen Punkt an und kehre dann langsam in die Ausgangsposition zurück.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dann die Seite, um mit dem linken Arm zu arbeiten."]', 'https://ascent-api.sweber.workers.dev/media/exercises/2464.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/2464.gif', 1784612222128, 1784612222128, 0),
  ('eb219aaa-276b-56ac-a8af-f5e962eb376a', NULL, 'Cable Triceps Pushdown (V-Bar)', 'Kabelzug-Trizeps-Pushdown (V-Griff)', 'upper arms', 'triceps', 'cable', 'Attach a v-bar attachment to the cable machine at the highest setting. Stand facing the cable machine with your feet shoulder-width apart. Grasp the v-bar with an overhand grip, palms facing down, and your hands shoulder-width apart. Keep your elbows close to your sides and your upper arms stationary throughout the exercise. Engage your triceps and exhale as you push the v-bar down until your arms are fully extended. Pause for a moment at the bottom of the movement, squeezing your triceps. Inhale as you slowly return the v-bar to the starting position, maintaining control. Repeat for the desired number of repetitions.', NULL, 'forearms', '["forearms"]', '["Attach a v-bar attachment to the cable machine at the highest setting.","Stand facing the cable machine with your feet shoulder-width apart.","Grasp the v-bar with an overhand grip, palms facing down, and your hands shoulder-width apart.","Keep your elbows close to your sides and your upper arms stationary throughout the exercise.","Engage your triceps and exhale as you push the v-bar down until your arms are fully extended.","Pause for a moment at the bottom of the movement, squeezing your triceps.","Inhale as you slowly return the v-bar to the starting position, maintaining control.","Repeat for the desired number of repetitions."]', '["Befestige einen V-Griff auf höchster Stufe am Kabelzug.","Stehe mit schulterbreiten Füssen vor dem Kabelzug.","Greife den V-Griff im Obergriff, Handflächen nach unten, Hände schulterbreit auseinander.","Halte die Ellbogen während der ganzen Übung nah am Körper und die Oberarme ruhig.","Spanne den Trizeps an und atme aus, während du den V-Griff nach unten drückst, bis die Arme vollständig gestreckt sind.","Halte am unteren Punkt der Bewegung kurz inne und spanne den Trizeps an.","Atme ein, während du den V-Griff langsam und kontrolliert zurück in die Ausgangsposition führst.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0241.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0241.gif', 1784612222128, 1784612222128, 0),
  ('0dc9e6bf-0103-5b17-9ff7-967962290a6c', NULL, 'Cable Triceps Pushdown (V-Bar) (with Arm Blaster)', 'Kabelzug-Trizeps-Pushdown (V-Griff, mit Arm Blaster)', 'upper arms', 'triceps', 'cable', 'Attach a v-bar attachment to the cable machine at the highest setting. Stand facing the cable machine with your feet shoulder-width apart. Grasp the v-bar with an overhand grip, palms facing down, and your hands shoulder-width apart. Keep your elbows close to your sides and your upper arms stationary throughout the exercise. Engage your triceps and exhale as you push the v-bar down until your arms are fully extended. Pause for a moment at the bottom of the movement, squeezing your triceps. Inhale as you slowly return the v-bar to the starting position, maintaining control. Repeat for the desired number of repetitions.', NULL, 'forearms', '["forearms"]', '["Attach a v-bar attachment to the cable machine at the highest setting.","Stand facing the cable machine with your feet shoulder-width apart.","Grasp the v-bar with an overhand grip, palms facing down, and your hands shoulder-width apart.","Keep your elbows close to your sides and your upper arms stationary throughout the exercise.","Engage your triceps and exhale as you push the v-bar down until your arms are fully extended.","Pause for a moment at the bottom of the movement, squeezing your triceps.","Inhale as you slowly return the v-bar to the starting position, maintaining control.","Repeat for the desired number of repetitions."]', '["Befestige einen V-Griff auf höchster Stufe am Kabelzug.","Stehe mit schulterbreiten Füssen vor dem Kabelzug.","Greife den V-Griff im Obergriff, Handflächen nach unten, Hände schulterbreit auseinander.","Halte die Ellbogen während der ganzen Übung nah am Körper und die Oberarme ruhig.","Spanne den Trizeps an und atme aus, während du den V-Griff nach unten drückst, bis die Arme vollständig gestreckt sind.","Halte am unteren Punkt der Bewegung kurz inne und spanne den Trizeps an.","Atme ein, während du den V-Griff langsam und kontrolliert zurück in die Ausgangsposition führst.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/2405.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/2405.gif', 1784612222128, 1784612222128, 0),
  ('ff417cdd-eaf7-593f-9270-9d1efcd51950', NULL, 'Cable Tuck Reverse Crunch', 'Kabelzug-Reverse Crunch angehockt', 'waist', 'abs', 'cable', 'Attach a cable to a low pulley and lie down on a mat facing up. Hold the cable with both hands and extend your arms straight up above your chest. Bend your knees and lift your legs up, bringing your knees towards your chest. At the same time, curl your pelvis up towards your chest, lifting your hips off the ground. Pause for a moment at the top, then slowly lower your legs and hips back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'hip flexors', '["hip flexors"]', '["Attach a cable to a low pulley and lie down on a mat facing up.","Hold the cable with both hands and extend your arms straight up above your chest.","Bend your knees and lift your legs up, bringing your knees towards your chest.","At the same time, curl your pelvis up towards your chest, lifting your hips off the ground.","Pause for a moment at the top, then slowly lower your legs and hips back down to the starting position.","Repeat for the desired number of repetitions."]', '["Befestige ein Kabel an der unteren Umlenkrolle und lege dich rücklings auf eine Matte.","Halte das Kabel mit beiden Händen und strecke die Arme gerade über der Brust nach oben.","Beuge die Knie und hebe die Beine an, sodass die Knie Richtung Brust kommen.","Rolle gleichzeitig das Becken Richtung Brust und hebe die Hüfte vom Boden ab.","Halte am oberen Punkt kurz inne und senke Beine und Hüfte dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0242.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0242.gif', 1784612222128, 1784612222128, 0),
  ('223c2739-3ae9-58ff-9f0f-24b09936a227', NULL, 'Cable Twist', 'Kabelzug-Rumpfdrehung', 'waist', 'abs', 'cable', 'Stand with your feet shoulder-width apart, facing the cable machine. Hold the cable handle with both hands in front of your chest, keeping your arms slightly bent. Engage your core and twist your torso to the right, pulling the cable across your body. Pause for a moment at the end of the movement, feeling the contraction in your abs and obliques. Slowly return to the starting position, resisting the cable''s pull. Repeat the movement to the left side. Continue alternating sides for the desired number of repetitions.', NULL, 'obliques', '["obliques"]', '["Stand with your feet shoulder-width apart, facing the cable machine.","Hold the cable handle with both hands in front of your chest, keeping your arms slightly bent.","Engage your core and twist your torso to the right, pulling the cable across your body.","Pause for a moment at the end of the movement, feeling the contraction in your abs and obliques.","Slowly return to the starting position, resisting the cable''s pull.","Repeat the movement to the left side.","Continue alternating sides for the desired number of repetitions."]', '["Stehe mit schulterbreiten Füssen vor dem Kabelzug.","Halte den Kabelgriff mit beiden Händen vor der Brust, die Arme bleiben leicht gebeugt.","Spanne die Körpermitte an und drehe den Oberkörper nach rechts, ziehe dabei das Kabel über den Körper.","Halte am Ende der Bewegung kurz inne und spüre die Anspannung in Bauch und schrägen Bauchmuskeln.","Kehre langsam in die Ausgangsposition zurück und widerstehe dabei dem Zug des Kabels.","Wiederhole die Bewegung zur linken Seite.","Wechsle die Seite fortlaufend für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0243.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0243.gif', 1784612222128, 1784612222128, 0),
  ('185bdcb3-0a8d-5e67-8134-fe30d5f19163', NULL, 'Cable Twist (Up-Down)', 'Kabelzug-Rumpfdrehung (auf-ab)', 'waist', 'abs', 'cable', 'Stand with your feet shoulder-width apart, facing the cable machine. Hold the cable handle with both hands in front of your chest, keeping your arms slightly bent. Engage your core and slowly rotate your torso to one side, keeping your hips and legs stable. Pause for a moment at the end of the rotation, then slowly return to the starting position. Repeat the rotation to the opposite side. Continue alternating sides for the desired number of repetitions.', NULL, 'obliques', '["obliques","lower back"]', '["Stand with your feet shoulder-width apart, facing the cable machine.","Hold the cable handle with both hands in front of your chest, keeping your arms slightly bent.","Engage your core and slowly rotate your torso to one side, keeping your hips and legs stable.","Pause for a moment at the end of the rotation, then slowly return to the starting position.","Repeat the rotation to the opposite side.","Continue alternating sides for the desired number of repetitions."]', '["Stehe mit schulterbreiten Füssen vor dem Kabelzug.","Halte den Kabelgriff mit beiden Händen vor der Brust, die Arme bleiben leicht gebeugt.","Spanne die Körpermitte an und drehe den Oberkörper langsam zu einer Seite, Hüfte und Beine bleiben stabil.","Halte am Ende der Drehung kurz inne und kehre dann langsam in die Ausgangsposition zurück.","Wiederhole die Drehung zur gegenüberliegenden Seite.","Wechsle die Seite fortlaufend für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0862.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0862.gif', 1784612222128, 1784612222128, 0),
  ('53949fc5-da11-5ffd-b62f-6e8b9f113e4e', NULL, 'Cable Twisting Pull', 'Kabelzug-Ziehen mit Drehung', 'back', 'lats', 'cable', 'Attach a cable handle to a low pulley and stand facing the machine. Grasp the handle with your left hand and step away from the machine, extending your arm fully. Position your feet shoulder-width apart, with your knees slightly bent. Keep your back straight and your core engaged throughout the exercise. Pull the handle towards your body, rotating your torso to the right as you do so. Squeeze your back muscles at the end of the movement. Slowly return to the starting position, keeping tension on the cable. Repeat for the desired number of repetitions, then switch sides and perform with your right hand.', NULL, 'shoulders', '["shoulders","biceps"]', '["Attach a cable handle to a low pulley and stand facing the machine.","Grasp the handle with your left hand and step away from the machine, extending your arm fully.","Position your feet shoulder-width apart, with your knees slightly bent.","Keep your back straight and your core engaged throughout the exercise.","Pull the handle towards your body, rotating your torso to the right as you do so.","Squeeze your back muscles at the end of the movement.","Slowly return to the starting position, keeping tension on the cable.","Repeat for the desired number of repetitions, then switch sides and perform with your right hand."]', '["Befestige einen Kabelgriff an der unteren Umlenkrolle und stehe vor dem Gerät.","Greife den Griff mit der linken Hand und trete vom Gerät weg, der Arm ist vollständig gestreckt.","Stelle die Füsse schulterbreit auseinander, die Knie leicht gebeugt.","Halte den Rücken gerade und die Körpermitte während der ganzen Übung angespannt.","Ziehe den Griff zum Körper und drehe dabei den Oberkörper nach rechts.","Spanne die Rückenmuskeln am Ende der Bewegung an.","Kehre langsam in die Ausgangsposition zurück und halte dabei die Spannung auf dem Kabel.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dann die Seite, um mit der rechten Hand zu arbeiten."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0244.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0244.gif', 1784612222128, 1784612222128, 0),
  ('b5687e15-7989-53aa-8f9d-779e4f6485eb', NULL, 'Cable Two Arm Curl on Incline Bench', 'Kabelzug-Curl beidarmig auf der Schrägbank', 'upper arms', 'biceps', 'cable', 'Sit on an incline bench with your back against the pad and your feet flat on the ground. Grasp the cable handles with an underhand grip, palms facing up, and your arms fully extended. Keeping your upper arms stationary, exhale and curl the handles towards your shoulders while contracting your biceps. Pause for a moment at the top of the movement, squeezing your biceps. Inhale and slowly lower the handles back to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', NULL, 'forearms', '["forearms"]', '["Sit on an incline bench with your back against the pad and your feet flat on the ground.","Grasp the cable handles with an underhand grip, palms facing up, and your arms fully extended.","Keeping your upper arms stationary, exhale and curl the handles towards your shoulders while contracting your biceps.","Pause for a moment at the top of the movement, squeezing your biceps.","Inhale and slowly lower the handles back to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."]', '["Setze dich auf eine Schrägbank, der Rücken liegt am Polster, die Füsse flach am Boden.","Greife die Kabelgriffe im Untergriff, Handflächen nach oben, Arme vollständig gestreckt.","Halte die Oberarme ruhig, atme aus und ziehe die Griffe Richtung Schultern, während du den Bizeps anspannst.","Halte am oberen Punkt kurz inne und spanne den Bizeps an.","Atme ein und senke die Griffe langsam zurück in die Ausgangsposition ab, bis die Arme vollständig gestreckt sind.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1645.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1645.gif', 1784612222128, 1784612222128, 0),
  ('00fd27e2-800a-5850-a188-298cdca8cd9e', NULL, 'Cable Two Arm Tricep Kickback', 'Kabelzug-Trizeps-Kickback beidarmig', 'upper arms', 'triceps', 'cable', 'Stand with your feet shoulder-width apart and knees slightly bent. Hold the cable handle in each hand with your palms facing inwards and your arms bent at a 90-degree angle. Keeping your upper arms stationary, extend your forearms backwards until your arms are fully extended. Pause for a moment, then slowly return to the starting position. Repeat for the desired number of repetitions.', NULL, 'shoulders', '["shoulders"]', '["Stand with your feet shoulder-width apart and knees slightly bent.","Hold the cable handle in each hand with your palms facing inwards and your arms bent at a 90-degree angle.","Keeping your upper arms stationary, extend your forearms backwards until your arms are fully extended.","Pause for a moment, then slowly return to the starting position.","Repeat for the desired number of repetitions."]', '["Stehe mit schulterbreiten Füssen und leicht gebeugten Knien.","Halte in jeder Hand einen Kabelgriff, Handflächen zueinander, die Arme im 90-Grad-Winkel gebeugt.","Halte die Oberarme ruhig und strecke die Unterarme nach hinten, bis die Arme vollständig gestreckt sind.","Halte kurz inne und kehre dann langsam in die Ausgangsposition zurück.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1728.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1728.gif', 1784612222128, 1784612222128, 0),
  ('7a9404b2-3650-5e02-8ebb-59ab10994bcb', NULL, 'Cable Underhand Pulldown', 'Kabelzug-Latzug Untergriff', 'back', 'lats', 'cable', 'Adjust the cable machine so that the pulldown bar is at a height above your head. Sit down on the seat and grab the pulldown bar with an underhand grip, hands slightly wider than shoulder-width apart. Keep your back straight and lean back slightly. Pull the bar down towards your chest, squeezing your shoulder blades together. Pause for a moment at the bottom of the movement, then slowly release the bar back up to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","forearms"]', '["Adjust the cable machine so that the pulldown bar is at a height above your head.","Sit down on the seat and grab the pulldown bar with an underhand grip, hands slightly wider than shoulder-width apart.","Keep your back straight and lean back slightly.","Pull the bar down towards your chest, squeezing your shoulder blades together.","Pause for a moment at the bottom of the movement, then slowly release the bar back up to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle den Kabelzug so ein, dass die Latzugstange über Kopfhöhe ist.","Setze dich auf den Sitz und greife die Latzugstange im Untergriff, Hände etwas breiter als schulterbreit.","Halte den Rücken gerade und lehne dich leicht zurück.","Ziehe die Stange Richtung Brust und ziehe dabei die Schulterblätter zusammen.","Halte am unteren Punkt kurz inne und lass die Stange dann langsam zurück nach oben gleiten.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0245.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0245.gif', 1784612222128, 1784612222128, 0),
  ('5632b2ca-2382-5fad-b6c4-cb7072faa30d', NULL, 'Cable Upper Chest Crossovers', 'Kabelzug-Crossover obere Brust', 'chest', 'pectorals', 'cable', 'Attach the handles to the cables at chest height. Stand in the center of the cable machine with one foot slightly in front of the other. Grasp the handles with your palms facing down and your arms extended out to the sides. Keep a slight bend in your elbows and engage your core. Pull the cables together in front of your chest, crossing them over each other. Squeeze your chest muscles at the peak of the movement. Slowly release the cables back to the starting position. Repeat for the desired number of repetitions.', NULL, 'deltoids', '["deltoids","triceps"]', '["Attach the handles to the cables at chest height.","Stand in the center of the cable machine with one foot slightly in front of the other.","Grasp the handles with your palms facing down and your arms extended out to the sides.","Keep a slight bend in your elbows and engage your core.","Pull the cables together in front of your chest, crossing them over each other.","Squeeze your chest muscles at the peak of the movement.","Slowly release the cables back to the starting position.","Repeat for the desired number of repetitions."]', '["Befestige die Griffe auf Brusthöhe an den Kabeln.","Stehe mittig zwischen den Kabelzügen, ein Fuss leicht vor dem anderen.","Greife die Griffe mit nach unten zeigenden Handflächen, die Arme seitlich gestreckt.","Halte die Ellbogen leicht gebeugt und spanne die Körpermitte an.","Ziehe die Kabel vor der Brust zusammen, sodass sie sich kreuzen.","Spanne die Brustmuskeln am Höhepunkt der Bewegung an.","Lass die Kabel langsam zurück in die Ausgangsposition gleiten.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1270.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1270.gif', 1784612222128, 1784612222128, 0),
  ('1fb092f6-fb08-5b63-b743-ebdc6d3f8504', NULL, 'Cable Upper Row', 'Kabelzug-Oberes Rudern', 'back', 'upper back', 'cable', 'Attach a straight bar to a cable machine at chest height. Stand facing the machine with your feet shoulder-width apart. Grasp the bar with an overhand grip, hands slightly wider than shoulder-width apart. Keep your back straight and your core engaged. Pull the bar towards your upper chest, squeezing your shoulder blades together. Pause for a moment at the top of the movement. Slowly release the bar back to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","shoulders"]', '["Attach a straight bar to a cable machine at chest height.","Stand facing the machine with your feet shoulder-width apart.","Grasp the bar with an overhand grip, hands slightly wider than shoulder-width apart.","Keep your back straight and your core engaged.","Pull the bar towards your upper chest, squeezing your shoulder blades together.","Pause for a moment at the top of the movement.","Slowly release the bar back to the starting position.","Repeat for the desired number of repetitions."]', '["Befestige eine Stange auf Brusthöhe am Kabelzug.","Stehe mit schulterbreiten Füssen vor dem Gerät.","Greife die Stange im Obergriff, Hände etwas breiter als schulterbreit.","Halte den Rücken gerade und die Körpermitte angespannt.","Ziehe die Stange Richtung obere Brust und ziehe dabei die Schulterblätter zusammen.","Halte am oberen Punkt der Bewegung kurz inne.","Lass die Stange langsam zurück in die Ausgangsposition gleiten.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1324.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1324.gif', 1784612222128, 1784612222128, 0),
  ('7cd8c312-d96f-542a-80ce-284eae596fec', NULL, 'Cable Upright Row', 'Kabelzug-Aufrechtes Rudern', 'shoulders', 'delts', 'cable', 'Stand with your feet shoulder-width apart, knees slightly bent, and hold the cable attachment with an overhand grip. Keep your back straight and your core engaged throughout the exercise. Pull the cable attachment straight up towards your chin, leading with your elbows. Pause for a moment at the top, squeezing your shoulder blades together. Slowly lower the cable attachment back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'traps', '["traps","biceps"]', '["Stand with your feet shoulder-width apart, knees slightly bent, and hold the cable attachment with an overhand grip.","Keep your back straight and your core engaged throughout the exercise.","Pull the cable attachment straight up towards your chin, leading with your elbows.","Pause for a moment at the top, squeezing your shoulder blades together.","Slowly lower the cable attachment back down to the starting position.","Repeat for the desired number of repetitions."]', '["Stehe mit schulterbreiten Füssen, leicht gebeugten Knien, und halte den Kabelgriff im Obergriff.","Halte den Rücken gerade und die Körpermitte während der ganzen Übung angespannt.","Ziehe den Kabelgriff gerade nach oben Richtung Kinn, die Ellbogen führen die Bewegung an.","Halte am oberen Punkt kurz inne und ziehe dabei die Schulterblätter zusammen.","Senke den Kabelgriff langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0246.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0246.gif', 1784612222128, 1784612222128, 0),
  ('1b933702-b871-5d24-ac2d-c8c84e625f62', NULL, 'Cable Wide Grip Rear Pulldown Behind Neck', 'Kabelzug-Nackenzug weiter Griff', 'back', 'lats', 'cable', 'Adjust the cable machine so that the pulldown bar is at a height above your head. Sit down on the seat and grab the pulldown bar with a wide overhand grip. Keep your back straight and your chest up as you lean back slightly. Pull the bar down towards your upper chest, squeezing your shoulder blades together. Pause for a moment at the bottom of the movement, then slowly release the bar back up to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","rhomboids","rear deltoids"]', '["Adjust the cable machine so that the pulldown bar is at a height above your head.","Sit down on the seat and grab the pulldown bar with a wide overhand grip.","Keep your back straight and your chest up as you lean back slightly.","Pull the bar down towards your upper chest, squeezing your shoulder blades together.","Pause for a moment at the bottom of the movement, then slowly release the bar back up to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle den Kabelzug so ein, dass die Latzugstange über Kopfhöhe ist.","Setze dich auf den Sitz und greife die Latzugstange im breiten Obergriff.","Halte den Rücken gerade und die Brust raus, während du dich leicht zurücklehnst.","Ziehe die Stange Richtung obere Brust und ziehe dabei die Schulterblätter zusammen.","Halte am unteren Punkt kurz inne und lass die Stange dann langsam zurück nach oben gleiten.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1325.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1325.gif', 1784612222128, 1784612222128, 0),
  ('45f316d5-b67e-5b8a-bfc7-a93f3bd7643b', NULL, 'Cable Wrist Curl', 'Kabelzug-Handgelenkcurl', 'lower arms', 'forearms', 'cable', 'Attach a straight bar to a low pulley cable machine. Stand facing the machine with your feet shoulder-width apart. Grasp the bar with an underhand grip, palms facing up, and your hands shoulder-width apart. Rest your forearms on a bench or pad, with your wrists hanging off the edge. Keeping your forearms stationary, exhale and curl your wrists upward as far as possible. Pause for a moment at the top, then inhale and slowly lower the bar back to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","brachialis"]', '["Attach a straight bar to a low pulley cable machine.","Stand facing the machine with your feet shoulder-width apart.","Grasp the bar with an underhand grip, palms facing up, and your hands shoulder-width apart.","Rest your forearms on a bench or pad, with your wrists hanging off the edge.","Keeping your forearms stationary, exhale and curl your wrists upward as far as possible.","Pause for a moment at the top, then inhale and slowly lower the bar back to the starting position.","Repeat for the desired number of repetitions."]', '["Befestige eine Stange an der unteren Umlenkrolle des Kabelzugs.","Stehe mit schulterbreiten Füssen vor dem Gerät.","Greife die Stange im Untergriff, Handflächen nach oben, Hände schulterbreit auseinander.","Lege die Unterarme auf eine Bank oder ein Polster, die Handgelenke hängen über die Kante.","Halte die Unterarme ruhig, atme aus und ziehe die Handgelenke so weit wie möglich nach oben.","Halte am oberen Punkt kurz inne, atme dann ein und senke die Stange langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0247.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0247.gif', 1784612222128, 1784612222128, 0),
  ('eeae4769-bf2f-54f4-8e09-cc6aa55fc891', NULL, 'Calf Push Stretch with Hands Against Wall', 'Wadendehnung mit Druck gegen die Wand', 'lower legs', 'calves', 'body weight', 'Stand facing a wall with your feet hip-width apart. Place your hands against the wall at shoulder height. Step back with one foot, keeping your heel on the ground and your leg straight. Bend your front knee slightly and lean forward, feeling a stretch in your calf. Hold the stretch for 20-30 seconds. Switch legs and repeat the stretch.', NULL, 'hamstrings', '["hamstrings"]', '["Stand facing a wall with your feet hip-width apart.","Place your hands against the wall at shoulder height.","Step back with one foot, keeping your heel on the ground and your leg straight.","Bend your front knee slightly and lean forward, feeling a stretch in your calf.","Hold the stretch for 20-30 seconds.","Switch legs and repeat the stretch."]', '["Stehe mit hüftbreiten Füssen vor einer Wand.","Lege die Hände auf Schulterhöhe an die Wand.","Trete mit einem Fuss zurück, die Ferse bleibt am Boden, das Bein bleibt gestreckt.","Beuge das vordere Knie leicht und lehne dich nach vorne, du spürst eine Dehnung in der Wade.","Halte die Dehnung 20-30 Sekunden.","Wechsle das Bein und wiederhole die Dehnung."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1407.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1407.gif', 1784612222128, 1784612222128, 0),
  ('0b7f3204-641d-53b6-a51b-ce9c975516e1', NULL, 'Calf Stretch with Hands Against Wall', 'Wadendehnung mit Händen an der Wand', 'lower legs', 'calves', 'body weight', 'Stand facing a wall with your feet hip-width apart. Place your hands against the wall at shoulder height. Step your right foot back, keeping your heel on the ground and your leg straight. Bend your left knee and lean forward, keeping your back leg straight and your heel on the ground. Hold the stretch for 20-30 seconds. Switch legs and repeat the stretch.', NULL, 'hamstrings', '["hamstrings"]', '["Stand facing a wall with your feet hip-width apart.","Place your hands against the wall at shoulder height.","Step your right foot back, keeping your heel on the ground and your leg straight.","Bend your left knee and lean forward, keeping your back leg straight and your heel on the ground.","Hold the stretch for 20-30 seconds.","Switch legs and repeat the stretch."]', '["Stehe mit hüftbreiten Füssen vor einer Wand.","Lege die Hände auf Schulterhöhe an die Wand.","Trete mit dem rechten Fuss zurück, die Ferse bleibt am Boden, das Bein bleibt gestreckt.","Beuge das linke Knie und lehne dich nach vorne, das hintere Bein bleibt gestreckt, die Ferse am Boden.","Halte die Dehnung 20-30 Sekunden.","Wechsle das Bein und wiederhole die Dehnung."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1377.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1377.gif', 1784612222128, 1784612222128, 0),
  ('1f5304a8-ee7f-5cc0-b029-42dc18334798', NULL, 'Calf Stretch with Rope', 'Wadendehnung mit Seil', 'lower legs', 'calves', 'rope', 'Stand facing a wall or sturdy object with your feet hip-width apart. Hold the ends of the rope in each hand and place the middle of the rope around the ball of your right foot. Step back with your left foot, keeping your heel on the ground and your leg straight. Lean forward, keeping your back straight, and gently pull on the rope to stretch your calf. Hold the stretch for 20-30 seconds, then release. Repeat on the other leg.', NULL, 'hamstrings', '["hamstrings"]', '["Stand facing a wall or sturdy object with your feet hip-width apart.","Hold the ends of the rope in each hand and place the middle of the rope around the ball of your right foot.","Step back with your left foot, keeping your heel on the ground and your leg straight.","Lean forward, keeping your back straight, and gently pull on the rope to stretch your calf.","Hold the stretch for 20-30 seconds, then release.","Repeat on the other leg."]', '["Stehe mit hüftbreiten Füssen vor einer Wand oder einem stabilen Gegenstand.","Halte die Enden des Bandes in jeder Hand und lege die Mitte des Bandes um den Ballen deines rechten Fusses.","Trete mit dem linken Fuss zurück, die Ferse bleibt am Boden, das Bein bleibt gestreckt.","Lehne dich nach vorne, der Rücken bleibt gerade, und ziehe sanft am Band, um die Wade zu dehnen.","Halte die Dehnung 20-30 Sekunden und löse sie dann.","Wiederhole am anderen Bein."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1378.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1378.gif', 1784612222128, 1784612222128, 0),
  ('7fb48b27-7237-59ee-a960-4b5ca58ba6b2', NULL, 'Cambered Bar Lying Row', 'Bogenhantel-Rudern liegend', 'back', 'upper back', 'barbell', 'Set up a barbell on the floor and lie face down on a bench with your chest just off the edge. Reach down and grab the barbell with an overhand grip, slightly wider than shoulder-width apart. With your legs straight and feet on the ground, lift the barbell off the floor by extending your arms. Pull the barbell towards your chest, squeezing your shoulder blades together. Lower the barbell back down to the starting position and repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","forearms"]', '["Set up a barbell on the floor and lie face down on a bench with your chest just off the edge.","Reach down and grab the barbell with an overhand grip, slightly wider than shoulder-width apart.","With your legs straight and feet on the ground, lift the barbell off the floor by extending your arms.","Pull the barbell towards your chest, squeezing your shoulder blades together.","Lower the barbell back down to the starting position and repeat for the desired number of repetitions."]', '["Lege eine Langhantel auf den Boden und lege dich mit der Brust knapp über der Bankkante bäuchlings auf eine Bank.","Greife nach unten und fasse die Langhantel im Obergriff, etwas breiter als schulterbreit.","Mit gestreckten Beinen und auf dem Boden stehenden Füssen hebst du die Langhantel vom Boden ab, indem du die Arme streckst.","Ziehe die Langhantel zur Brust und ziehe dabei die Schulterblätter zusammen.","Senke die Langhantel zurück in die Ausgangsposition ab und wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0248.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0248.gif', 1784612222128, 1784612222128, 0),
  ('6e3bb9e3-c1cc-586a-9c19-3c5ca0f44a4f', NULL, 'Captain''s Chair Straight Leg Raise', 'Beinheben gestreckt am Captain''s Chair', 'waist', 'abs', 'body weight', 'Sit on the captain''s chair with your back against the backrest and your forearms resting on the arm pads. Keep your upper body stable and your back straight. Engage your abs and lift your legs up in front of you, keeping them straight. Continue lifting until your legs are parallel to the ground or as high as you can comfortably go. Pause for a moment at the top, then slowly lower your legs back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'hip flexors', '["hip flexors"]', '["Sit on the captain''s chair with your back against the backrest and your forearms resting on the arm pads.","Keep your upper body stable and your back straight.","Engage your abs and lift your legs up in front of you, keeping them straight.","Continue lifting until your legs are parallel to the ground or as high as you can comfortably go.","Pause for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."]', '["Setze dich in den Dip-Stuhl mit Rückenlehne, die Unterarme auf den Armpolstern.","Halte den Oberkörper stabil und den Rücken gerade.","Spanne die Bauchmuskeln an und hebe die Beine gestreckt vor dir an.","Hebe weiter, bis die Beine parallel zum Boden sind oder so hoch wie du bequem kannst.","Halte am oberen Punkt kurz inne und senke die Beine dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/2963.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/2963.gif', 1784612222128, 1784612222128, 0),
  ('681c7e84-72ee-57f5-b776-37150007293f', NULL, 'Chair Leg Extended Stretch', 'Quadrizeps-Dehnung am Stuhl (gestrecktes Bein)', 'upper legs', 'quads', 'body weight', 'Sit on the edge of a chair with your back straight and feet flat on the ground. Extend one leg straight out in front of you, keeping your heel on the ground. Lean forward slightly, feeling a stretch in your quadriceps. Hold this position for 20-30 seconds. Switch legs and repeat the stretch.', NULL, 'hamstrings', '["hamstrings","calves"]', '["Sit on the edge of a chair with your back straight and feet flat on the ground.","Extend one leg straight out in front of you, keeping your heel on the ground.","Lean forward slightly, feeling a stretch in your quadriceps.","Hold this position for 20-30 seconds.","Switch legs and repeat the stretch."]', '["Setze dich an die Kante eines Stuhls, der Rücken gerade, die Füsse flach am Boden.","Strecke ein Bein gerade vor dir aus, die Ferse bleibt am Boden.","Lehne dich leicht nach vorne, du spürst eine Dehnung im Quadrizeps.","Halte diese Position 20-30 Sekunden.","Wechsle das Bein und wiederhole die Dehnung."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1548.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1548.gif', 1784612222128, 1784612222128, 0),
  ('5e0d4aca-0478-5f26-a3d3-f47cbbb257ca', NULL, 'Chest and Front of Shoulder Stretch', 'Dehnung für Brust und vordere Schulter', 'chest', 'pectorals', 'body weight', 'Stand tall with your feet shoulder-width apart. Extend your arms straight out in front of you at shoulder height. Cross your arms in front of your body, with your right arm on top of your left arm. Interlace your fingers and press your palms together. Gently squeeze your shoulder blades together and push your hands forward, feeling a stretch in your chest and front of your shoulders. Hold the stretch for 20-30 seconds, then release. Repeat for the desired number of repetitions.', NULL, 'deltoids', '["deltoids"]', '["Stand tall with your feet shoulder-width apart.","Extend your arms straight out in front of you at shoulder height.","Cross your arms in front of your body, with your right arm on top of your left arm.","Interlace your fingers and press your palms together.","Gently squeeze your shoulder blades together and push your hands forward, feeling a stretch in your chest and front of your shoulders.","Hold the stretch for 20-30 seconds, then release.","Repeat for the desired number of repetitions."]', '["Stehe aufrecht mit schulterbreiten Füssen.","Strecke die Arme auf Schulterhöhe gerade vor dir aus.","Kreuze die Arme vor dem Körper, der rechte Arm liegt über dem linken.","Verschränke die Finger und drücke die Handflächen zusammen.","Ziehe die Schulterblätter sanft zusammen und drücke die Hände nach vorne, du spürst eine Dehnung in Brust und vorderer Schulter.","Halte die Dehnung 20-30 Sekunden und löse sie dann.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1271.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1271.gif', 1784612222128, 1784612222128, 0),
  ('47c518f8-e02d-59cf-9af4-3283ebc5e618', NULL, 'Chest Dip', 'Brust-Dip', 'chest', 'pectorals', 'body weight', 'Position yourself on parallel bars with your arms fully extended and your body straight. Lower your body by bending your elbows until your shoulders are below your elbows. Push yourself back up to the starting position by straightening your arms. Repeat for the desired number of repetitions.', NULL, 'triceps', '["triceps","shoulders"]', '["Position yourself on parallel bars with your arms fully extended and your body straight.","Lower your body by bending your elbows until your shoulders are below your elbows.","Push yourself back up to the starting position by straightening your arms.","Repeat for the desired number of repetitions."]', '["Positioniere dich am Dip-Barren mit vollständig gestreckten Armen und geradem Körper.","Senke den Körper ab, indem du die Ellbogen beugst, bis die Schultern unter den Ellbogen sind.","Drücke dich zurück in die Ausgangsposition, indem du die Arme streckst.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0251.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0251.gif', 1784612222128, 1784612222128, 0),
  ('1f1f55df-7307-5452-a6fa-aedd76439c3c', NULL, 'Chest Dip (on Dip-Pull-up Cage)', 'Brust-Dip am Dip-Klimmzug-Gerät', 'chest', 'pectorals', 'body weight', 'Adjust the dip bars to a height that allows you to comfortably grip them. Stand between the bars and place your hands on each bar, slightly wider than shoulder-width apart. Jump up and straighten your arms, supporting your body weight on the bars. Bend your knees and cross your ankles behind you. Lower your body by bending your elbows, keeping your chest up and your shoulders down. Continue lowering until your shoulders are below your elbows or until you feel a stretch in your chest. Push through your palms and extend your elbows to raise your body back up to the starting position. Repeat for the desired number of repetitions.', NULL, 'triceps', '["triceps","shoulders"]', '["Adjust the dip bars to a height that allows you to comfortably grip them.","Stand between the bars and place your hands on each bar, slightly wider than shoulder-width apart.","Jump up and straighten your arms, supporting your body weight on the bars.","Bend your knees and cross your ankles behind you.","Lower your body by bending your elbows, keeping your chest up and your shoulders down.","Continue lowering until your shoulders are below your elbows or until you feel a stretch in your chest.","Push through your palms and extend your elbows to raise your body back up to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle die Dip-Barren auf eine Höhe ein, die du bequem greifen kannst.","Stelle dich zwischen die Barren und lege die Hände etwas breiter als schulterbreit auf jeden Barren.","Springe hoch und strecke die Arme, um dein Körpergewicht auf den Barren abzustützen.","Beuge die Knie und kreuze die Fussgelenke hinter dir.","Senke den Körper ab, indem du die Ellbogen beugst, die Brust bleibt raus, die Schultern unten.","Senke weiter ab, bis die Schultern unter den Ellbogen sind oder du eine Dehnung in der Brust spürst.","Drücke durch die Handflächen und strecke die Ellbogen, um den Körper zurück in die Ausgangsposition zu heben.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1430.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1430.gif', 1784612222128, 1784612222128, 0),
  ('4d294909-207d-5426-9593-3e806faef08d', NULL, 'Chest Dip on Straight Bar', 'Brust-Dip an der geraden Stange', 'chest', 'pectorals', 'body weight', 'Grab the parallel bars with your palms facing down and your arms fully extended. Bend your knees and cross your ankles. Lower your body by bending your arms until your shoulders are below your elbows. Push yourself back up to the starting position by straightening your arms. Repeat for the desired number of repetitions.', NULL, 'triceps', '["triceps","shoulders"]', '["Grab the parallel bars with your palms facing down and your arms fully extended.","Bend your knees and cross your ankles.","Lower your body by bending your arms until your shoulders are below your elbows.","Push yourself back up to the starting position by straightening your arms.","Repeat for the desired number of repetitions."]', '["Greife die Barren mit nach unten zeigenden Handflächen, die Arme vollständig gestreckt.","Beuge die Knie und kreuze die Fussgelenke.","Senke den Körper ab, indem du die Arme beugst, bis die Schultern unter den Ellbogen sind.","Drücke dich zurück in die Ausgangsposition, indem du die Arme streckst.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/2462.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/2462.gif', 1784612222128, 1784612222128, 0),
  ('32036c11-f3c7-52c9-aaa0-60e6f083718e', NULL, 'Chest Stretch with Exercise Ball', 'Brustdehnung mit Gymnastikball', 'chest', 'pectorals', 'stability ball', 'Sit on the stability ball with your feet flat on the ground and your back straight. Hold the exercise ball with both hands and extend your arms straight out in front of you. Slowly bring the exercise ball towards your chest, feeling a stretch in your chest muscles. Hold the stretch for a few seconds, then slowly return to the starting position. Repeat for the desired number of repetitions.', NULL, 'shoulders', '["shoulders","triceps"]', '["Sit on the stability ball with your feet flat on the ground and your back straight.","Hold the exercise ball with both hands and extend your arms straight out in front of you.","Slowly bring the exercise ball towards your chest, feeling a stretch in your chest muscles.","Hold the stretch for a few seconds, then slowly return to the starting position.","Repeat for the desired number of repetitions."]', '["Setze dich auf den Gymnastikball, Füsse flach am Boden, Rücken gerade.","Halte den Gymnastikball mit beiden Händen und strecke die Arme gerade vor dir aus.","Führe den Ball langsam Richtung Brust, du spürst eine Dehnung in der Brustmuskulatur.","Halte die Dehnung einige Sekunden und kehre dann langsam in die Ausgangsposition zurück.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1272.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1272.gif', 1784612222128, 1784612222128, 0),
  ('8ae39785-7deb-5ed6-b0ef-69878c210c00', NULL, 'Chest Tap Push-up (Male)', 'Liegestütz mit Brust-Antippen (männlich)', 'chest', 'pectorals', 'body weight', 'Start in a high plank position with your hands slightly wider than shoulder-width apart and your body in a straight line. Lower your body towards the ground by bending your elbows, keeping them close to your sides. As you lower yourself, tap your chest with your right hand. Push yourself back up to the starting position. Repeat the movement, this time tapping your chest with your left hand. Continue alternating sides for the desired number of repetitions.', NULL, 'triceps', '["triceps","shoulders"]', '["Start in a high plank position with your hands slightly wider than shoulder-width apart and your body in a straight line.","Lower your body towards the ground by bending your elbows, keeping them close to your sides.","As you lower yourself, tap your chest with your right hand.","Push yourself back up to the starting position.","Repeat the movement, this time tapping your chest with your left hand.","Continue alternating sides for the desired number of repetitions."]', '["Starte in einer hohen Plank-Position, die Hände etwas breiter als schulterbreit, der Körper bildet eine gerade Linie.","Senke den Körper Richtung Boden ab, indem du die Ellbogen beugst und nah am Körper hältst.","Tippe beim Absenken mit der rechten Hand deine Brust an.","Drücke dich zurück in die Ausgangsposition.","Wiederhole die Bewegung, diesmal mit der linken Hand.","Wechsle die Seite fortlaufend für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/3216.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/3216.gif', 1784612222128, 1784612222128, 0),
  ('a49f8713-ea89-580b-b068-5f250d5aced0', NULL, 'Chin-up', 'Klimmzug (Untergriff)', 'back', 'lats', 'body weight', 'Hang from a pull-up bar with your palms facing towards you and your hands shoulder-width apart. Engage your core and pull your body up towards the bar, leading with your chest. Continue pulling until your chin is above the bar. Pause for a moment at the top, then slowly lower your body back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","forearms"]', '["Hang from a pull-up bar with your palms facing towards you and your hands shoulder-width apart.","Engage your core and pull your body up towards the bar, leading with your chest.","Continue pulling until your chin is above the bar.","Pause for a moment at the top, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."]', '["Hänge dich mit zu dir zeigenden Handflächen und schulterbreiten Händen an eine Klimmzugstange.","Spanne die Körpermitte an und ziehe den Körper zur Stange hoch, die Brust führt die Bewegung an.","Ziehe weiter, bis dein Kinn über der Stange ist.","Halte am oberen Punkt kurz inne und senke den Körper dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1326.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1326.gif', 1784612222128, 1784612222128, 0),
  ('167536b7-f7cd-5b80-add7-b5feca054834', NULL, 'Chin-ups (Narrow Parallel Grip)', 'Klimmzug (Untergriff), enger Parallelgriff', 'back', 'upper back', 'body weight', 'Hang from a pull-up bar with a narrow parallel grip, palms facing towards you. Engage your back muscles and pull your body up towards the bar, keeping your elbows close to your body. Continue pulling until your chin is above the bar. Pause for a moment at the top, then slowly lower your body back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","forearms"]', '["Hang from a pull-up bar with a narrow parallel grip, palms facing towards you.","Engage your back muscles and pull your body up towards the bar, keeping your elbows close to your body.","Continue pulling until your chin is above the bar.","Pause for a moment at the top, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."]', '["Hänge dich mit engem, parallelem Griff an eine Klimmzugstange, die Handflächen zeigen zu dir.","Spanne die Rückenmuskeln an und ziehe den Körper zur Stange hoch, die Ellbogen bleiben nah am Körper.","Ziehe weiter, bis dein Kinn über der Stange ist.","Halte am oberen Punkt kurz inne und senke den Körper dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0253.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0253.gif', 1784612222128, 1784612222128, 0),
  ('22ba9060-9363-55c4-b495-1b5f75d7159e', NULL, 'Circles Knee Stretch', 'Kreisende Knie-Dehnung', 'lower legs', 'calves', 'body weight', 'Stand with your feet shoulder-width apart and your hands on your hips. Bend your knees slightly and lift your heels off the ground, balancing on the balls of your feet. Keeping your knees bent, rotate your knees in a circular motion, first clockwise and then counterclockwise. Perform the movement for the desired number of repetitions.', NULL, 'hamstrings', '["hamstrings","quadriceps"]', '["Stand with your feet shoulder-width apart and your hands on your hips.","Bend your knees slightly and lift your heels off the ground, balancing on the balls of your feet.","Keeping your knees bent, rotate your knees in a circular motion, first clockwise and then counterclockwise.","Perform the movement for the desired number of repetitions."]', '["Stehe mit schulterbreiten Füssen, die Hände auf den Hüften.","Beuge die Knie leicht und hebe die Fersen vom Boden ab, balanciere auf den Fussballen.","Halte die Knie gebeugt und kreise sie zunächst im Uhrzeigersinn, dann gegen den Uhrzeigersinn.","Führe die Bewegung für die gewünschte Anzahl Wiederholungen aus."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0257.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0257.gif', 1784612222128, 1784612222128, 0),
  ('d63f2d08-403e-5d7f-94e6-9f2f56393efb', NULL, 'Clap Push-up', 'Liegestütz mit Klatschen', 'chest', 'pectorals', 'body weight', 'Start in a high plank position with your hands slightly wider than shoulder-width apart. Lower your body towards the ground by bending your elbows, keeping your core engaged. Push through your palms explosively to propel your body off the ground. While in mid-air, clap your hands together before landing back in the starting position. Repeat for the desired number of repetitions.', NULL, 'triceps', '["triceps","shoulders"]', '["Start in a high plank position with your hands slightly wider than shoulder-width apart.","Lower your body towards the ground by bending your elbows, keeping your core engaged.","Push through your palms explosively to propel your body off the ground.","While in mid-air, clap your hands together before landing back in the starting position.","Repeat for the desired number of repetitions."]', '["Starte in einer hohen Plank-Position, die Hände etwas breiter als schulterbreit.","Senke den Körper Richtung Boden ab, indem du die Ellbogen beugst und die Körpermitte angespannt hältst.","Drücke explosiv durch die Handflächen, um den Körper vom Boden abzustossen.","Klatsche in der Luft in die Hände, bevor du zurück in die Ausgangsposition landest.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1273.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1273.gif', 1784612222128, 1784612222128, 0),
  ('6557d3b5-dcb2-5c32-b276-b89168fcb9f0', NULL, 'Clock Push-up', 'Liegestütz im Kreis', 'chest', 'pectorals', 'body weight', 'Start in a high plank position with your hands directly under your shoulders and your body in a straight line. Lower your body towards the ground by bending your elbows, keeping them close to your sides. As you lower, rotate your body to the left, extending your left arm straight out to the side. Push back up to the starting position, while rotating your body to the center. Repeat the push-up, this time rotating your body to the right and extending your right arm out to the side. Continue alternating sides with each repetition.', NULL, 'triceps', '["triceps","shoulders","core"]', '["Start in a high plank position with your hands directly under your shoulders and your body in a straight line.","Lower your body towards the ground by bending your elbows, keeping them close to your sides.","As you lower, rotate your body to the left, extending your left arm straight out to the side.","Push back up to the starting position, while rotating your body to the center.","Repeat the push-up, this time rotating your body to the right and extending your right arm out to the side.","Continue alternating sides with each repetition."]', '["Starte in einer hohen Plank-Position, die Hände direkt unter den Schultern, der Körper bildet eine gerade Linie.","Senke den Körper Richtung Boden ab, indem du die Ellbogen beugst und nah am Körper hältst.","Drehe den Körper beim Absenken nach links und strecke den linken Arm seitlich aus.","Drücke dich zurück in die Ausgangsposition und drehe den Körper dabei zur Mitte zurück.","Wiederhole den Liegestütz, diesmal mit einer Drehung nach rechts und gestrecktem rechten Arm zur Seite.","Wechsle die Seite bei jeder Wiederholung."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0258.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0258.gif', 1784612222128, 1784612222128, 0),
  ('358e5a8a-d78a-5fc2-98e4-fab73fd44aff', NULL, 'Close Grip Chin-up', 'Klimmzug (Untergriff) enger Griff', 'back', 'lats', 'body weight', 'Grab the pull-up bar with your palms facing towards you and your hands shoulder-width apart. Hang from the bar with your arms fully extended and your feet off the ground. Engage your back muscles and pull your body up towards the bar, keeping your elbows close to your body. Continue pulling until your chin is above the bar. Pause for a moment at the top, then slowly lower your body back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","forearms"]', '["Grab the pull-up bar with your palms facing towards you and your hands shoulder-width apart.","Hang from the bar with your arms fully extended and your feet off the ground.","Engage your back muscles and pull your body up towards the bar, keeping your elbows close to your body.","Continue pulling until your chin is above the bar.","Pause for a moment at the top, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."]', '["Greife die Klimmzugstange im Untergriff, die Handflächen zeigen zu dir, Hände schulterbreit auseinander.","Hänge dich an die Stange, die Arme vollständig gestreckt, die Füsse in der Luft.","Spanne die Rückenmuskeln an und ziehe den Körper zur Stange hoch, die Ellbogen bleiben nah am Körper.","Ziehe weiter, bis dein Kinn über der Stange ist.","Halte am oberen Punkt kurz inne und senke den Körper dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1327.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1327.gif', 1784612222128, 1784612222128, 0),
  ('f13835f7-a958-515c-8e86-4d16e188caae', NULL, 'Close-Grip Push-up', 'Liegestütz enger Griff', 'upper arms', 'triceps', 'body weight', 'Start in a high plank position with your hands placed close together, directly under your shoulders. Engage your core and lower your body towards the ground, keeping your elbows close to your sides. Push through your palms to extend your arms and return to the starting position. Repeat for the desired number of repetitions.', NULL, 'chest', '["chest","shoulders"]', '["Start in a high plank position with your hands placed close together, directly under your shoulders.","Engage your core and lower your body towards the ground, keeping your elbows close to your sides.","Push through your palms to extend your arms and return to the starting position.","Repeat for the desired number of repetitions."]', '["Starte in einer hohen Plank-Position, die Hände eng zusammen, direkt unter den Schultern.","Spanne die Körpermitte an und senke den Körper Richtung Boden ab, die Ellbogen bleiben nah am Körper.","Drücke durch die Handflächen, um die Arme zu strecken und in die Ausgangsposition zurückzukehren.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0259.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0259.gif', 1784612222128, 1784612222128, 0),
  ('5ef771f2-6841-5ddb-a21c-8bb07d47bda4', NULL, 'Close-Grip Push-up (on Knees)', 'Liegestütz enger Griff (auf den Knien)', 'upper arms', 'triceps', 'body weight', 'Start by getting on your hands and knees, with your hands shoulder-width apart and your knees hip-width apart. Lower your upper body towards the ground by bending your elbows, keeping them close to your sides. Pause for a moment when your chest is just above the ground. Push through your palms to straighten your arms and return to the starting position. Repeat for the desired number of repetitions.', NULL, 'chest', '["chest","shoulders"]', '["Start by getting on your hands and knees, with your hands shoulder-width apart and your knees hip-width apart.","Lower your upper body towards the ground by bending your elbows, keeping them close to your sides.","Pause for a moment when your chest is just above the ground.","Push through your palms to straighten your arms and return to the starting position.","Repeat for the desired number of repetitions."]', '["Gehe auf Hände und Knie, die Hände schulterbreit, die Knie hüftbreit auseinander.","Senke den Oberkörper Richtung Boden ab, indem du die Ellbogen beugst und nah am Körper hältst.","Halte kurz inne, wenn die Brust knapp über dem Boden ist.","Drücke durch die Handflächen, um die Arme zu strecken und in die Ausgangsposition zurückzukehren.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/2398.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/2398.gif', 1784612222128, 1784612222128, 0),
  ('161c7080-dc2f-5e58-a9d0-4303a7efdc45', NULL, 'Cocoons', 'Einrollen (Cocoon)', 'waist', 'abs', 'body weight', 'Lie flat on your back with your knees bent and feet flat on the ground. Place your hands behind your head with your elbows pointing outwards. Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle. Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'hip flexors', '["hip flexors","lower back"]', '["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands behind your head with your elbows pointing outwards.","Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."]', '["Lege dich flach auf den Rücken, die Knie gebeugt, die Füsse flach am Boden.","Lege die Hände hinter den Kopf, die Ellbogen zeigen nach aussen.","Spanne die Bauchmuskeln an und hebe den Oberkörper langsam vom Boden ab, bis der Rumpf im 45-Grad-Winkel steht.","Halte am oberen Punkt kurz inne und senke den Oberkörper dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0260.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0260.gif', 1784612222128, 1784612222128, 0),
  ('7dafcfc4-c542-5ae2-9be3-2577c6f7b392', NULL, 'Crab Twist Toe Touch', 'Seitliche Rumpfdrehung mit Zehenberührung (Crab-Position)', 'waist', 'abs', 'body weight', 'Start by sitting on the ground with your knees bent and feet flat on the floor. Place your hands behind you, fingers pointing towards your feet, and lift your hips off the ground. Extend one leg straight out in front of you while simultaneously reaching your opposite hand towards your toes. Return to the starting position and repeat on the other side. Continue alternating sides for the desired number of repetitions.', NULL, 'obliques', '["obliques","hip flexors"]', '["Start by sitting on the ground with your knees bent and feet flat on the floor.","Place your hands behind you, fingers pointing towards your feet, and lift your hips off the ground.","Extend one leg straight out in front of you while simultaneously reaching your opposite hand towards your toes.","Return to the starting position and repeat on the other side.","Continue alternating sides for the desired number of repetitions."]', '["Setze dich auf den Boden, die Knie gebeugt, die Füsse flach am Boden.","Lege die Hände hinter dir ab, die Finger zeigen Richtung Füsse, und hebe die Hüfte vom Boden ab.","Strecke ein Bein gerade nach vorne aus, während du gleichzeitig die gegenüberliegende Hand Richtung Zehen führst.","Kehre in die Ausgangsposition zurück und wiederhole auf der anderen Seite.","Wechsle die Seite fortlaufend für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1468.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1468.gif', 1784612222128, 1784612222128, 0),
  ('dfde4a9e-ee30-5685-8bec-bd4e40854224', NULL, 'Cross Body Crunch', 'Crunch über Kreuz', 'waist', 'abs', 'body weight', 'Lie flat on your back with your knees bent and feet flat on the ground. Place your hands behind your head with your elbows pointing outwards. Engaging your abs, lift your upper body off the ground and twist to bring your right elbow towards your left knee. Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Repeat on the other side, bringing your left elbow towards your right knee. Repeat for the desired number of repetitions.', NULL, 'obliques', '["obliques"]', '["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands behind your head with your elbows pointing outwards.","Engaging your abs, lift your upper body off the ground and twist to bring your right elbow towards your left knee.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat on the other side, bringing your left elbow towards your right knee.","Repeat for the desired number of repetitions."]', '["Lege dich flach auf den Rücken, die Knie gebeugt, die Füsse flach am Boden.","Lege die Hände hinter den Kopf, die Ellbogen zeigen nach aussen.","Spanne die Bauchmuskeln an, hebe den Oberkörper vom Boden ab und drehe dich, um den rechten Ellbogen Richtung linkes Knie zu führen.","Halte am oberen Punkt kurz inne und senke den Oberkörper dann langsam zurück in die Ausgangsposition ab.","Wiederhole auf der anderen Seite, den linken Ellbogen Richtung rechtes Knie.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0262.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0262.gif', 1784612222128, 1784612222128, 0),
  ('216fb539-cba3-57cc-bd7e-4f3fd89dd2bd', NULL, 'Crunch (Hands Overhead)', 'Crunch (Hände über dem Kopf)', 'waist', 'abs', 'body weight', 'Lie flat on your back with your knees bent and feet flat on the ground. Extend your arms straight above your head. Engaging your abs, lift your upper body off the ground, curling forward towards your knees. Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'hip flexors', '["hip flexors"]', '["Lie flat on your back with your knees bent and feet flat on the ground.","Extend your arms straight above your head.","Engaging your abs, lift your upper body off the ground, curling forward towards your knees.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."]', '["Lege dich flach auf den Rücken, die Knie gebeugt, die Füsse flach am Boden.","Strecke die Arme gerade über den Kopf.","Spanne die Bauchmuskeln an und hebe den Oberkörper vom Boden ab, rolle ihn Richtung Knie.","Halte am oberen Punkt kurz inne und senke den Oberkörper dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0267.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0267.gif', 1784612222128, 1784612222128, 0),
  ('f0ad2835-db00-548b-8050-32052e99704b', NULL, 'Crunch (on Stability Ball)', 'Crunch auf dem Gymnastikball', 'waist', 'abs', 'stability ball', 'Sit on the stability ball with your feet flat on the ground and your knees bent at a 90-degree angle. Lie back on the ball until your lower back is supported and your upper body is parallel to the floor. Place your hands behind your head or across your chest. Engage your abs and lift your upper body towards your knees, curling your torso forward. Pause for a moment at the top of the movement, then slowly lower your upper body back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'hip flexors', '["hip flexors"]', '["Sit on the stability ball with your feet flat on the ground and your knees bent at a 90-degree angle.","Lie back on the ball until your lower back is supported and your upper body is parallel to the floor.","Place your hands behind your head or across your chest.","Engage your abs and lift your upper body towards your knees, curling your torso forward.","Pause for a moment at the top of the movement, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."]', '["Setze dich auf den Gymnastikball, Füsse flach am Boden, Knie im 90-Grad-Winkel gebeugt.","Lehne dich auf dem Ball zurück, bis der untere Rücken gestützt und der Oberkörper parallel zum Boden ist.","Lege die Hände hinter den Kopf oder verschränke sie vor der Brust.","Spanne die Bauchmuskeln an und hebe den Oberkörper Richtung Knie, rolle den Rumpf nach vorne.","Halte am oberen Punkt kurz inne und senke den Oberkörper dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0271.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0271.gif', 1784612222128, 1784612222128, 0),
  ('7aec0a95-cf76-5032-bc7a-672f0a05b75f', NULL, 'Crunch (on Stability Ball, Arms Straight)', 'Crunch auf dem Gymnastikball (gestreckte Arme)', 'waist', 'abs', 'stability ball', 'Sit on the stability ball with your feet flat on the ground and your knees bent at a 90-degree angle. Lie back on the ball until your lower back is supported and your upper body is parallel to the floor. Place your hands behind your head or cross them over your chest. Engage your abs and lift your upper body off the ball, curling your shoulders towards your hips. Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'hip flexors', '["hip flexors"]', '["Sit on the stability ball with your feet flat on the ground and your knees bent at a 90-degree angle.","Lie back on the ball until your lower back is supported and your upper body is parallel to the floor.","Place your hands behind your head or cross them over your chest.","Engage your abs and lift your upper body off the ball, curling your shoulders towards your hips.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."]', '["Setze dich auf den Gymnastikball, Füsse flach am Boden, Knie im 90-Grad-Winkel gebeugt.","Lehne dich auf dem Ball zurück, bis der untere Rücken gestützt und der Oberkörper parallel zum Boden ist.","Lege die Hände hinter den Kopf oder verschränke sie vor der Brust.","Spanne die Bauchmuskeln an und hebe den Oberkörper vom Ball ab, rolle die Schultern Richtung Hüfte.","Halte am oberen Punkt kurz inne und senke den Oberkörper dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0272.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0272.gif', 1784612222128, 1784612222128, 0);

INSERT OR REPLACE INTO exercises (id, user_id, name, name_de, category, primary_muscle, equipment, instructions_en, instructions_de, muscle_group, secondary_muscles, instruction_steps_en, instruction_steps_de, thumbnail_url, gif_url, created_at, updated_at, deleted) VALUES
  ('57f70444-de83-5c22-8962-b0d1d3aba3aa', NULL, 'Crunch Floor', 'Crunch am Boden', 'waist', 'abs', 'body weight', 'Lie flat on your back with your knees bent and feet flat on the ground. Place your hands behind your head with your elbows pointing outwards. Engage your abs and lift your shoulders off the ground, curling forward towards your knees. Pause for a moment at the top, then slowly lower your shoulders back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'hip flexors', '["hip flexors"]', '["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands behind your head with your elbows pointing outwards.","Engage your abs and lift your shoulders off the ground, curling forward towards your knees.","Pause for a moment at the top, then slowly lower your shoulders back down to the starting position.","Repeat for the desired number of repetitions."]', '["Lege dich flach auf den Rücken, die Knie gebeugt, die Füsse flach am Boden.","Lege die Hände hinter den Kopf, die Ellbogen zeigen nach aussen.","Spanne die Bauchmuskeln an und hebe die Schultern vom Boden ab, rolle sie Richtung Knie.","Halte am oberen Punkt kurz inne und senke die Schultern dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0274.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0274.gif', 1784612222128, 1784612222128, 0),
  ('47e31f9a-35cc-587c-9c35-37ba7c9292d8', NULL, 'Curl-Up', 'Curl-Up (Bauch-Aufrollen)', 'waist', 'abs', 'body weight', 'Lie flat on your back with your knees bent and feet flat on the ground. Place your hands behind your head with your elbows pointing outwards. Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle. Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'hip flexors', '["hip flexors"]', '["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands behind your head with your elbows pointing outwards.","Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."]', '["Lege dich flach auf den Rücken, die Knie gebeugt, die Füsse flach am Boden.","Lege die Hände hinter den Kopf, die Ellbogen zeigen nach aussen.","Spanne die Bauchmuskeln an und hebe den Oberkörper langsam vom Boden ab, bis der Rumpf im 45-Grad-Winkel steht.","Halte am oberen Punkt kurz inne und senke den Oberkörper dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/3016.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/3016.gif', 1784612222128, 1784612222128, 0),
  ('2a62c00d-eab3-5367-b7c0-e365f92013d2', NULL, 'Curtsey Squat', 'Curtsy-Kniebeuge', 'upper legs', 'glutes', 'body weight', 'Stand with your feet shoulder-width apart. Take a step diagonally behind and across your body with your right foot, crossing it behind your left leg. Bend both knees as if you were curtsying, lowering your body towards the ground. Keep your torso upright and your weight on your front foot. Push through your front foot to return to the starting position. Repeat on the other side, stepping diagonally behind and across your body with your left foot.', NULL, 'quadriceps', '["quadriceps","hamstrings","calves"]', '["Stand with your feet shoulder-width apart.","Take a step diagonally behind and across your body with your right foot, crossing it behind your left leg.","Bend both knees as if you were curtsying, lowering your body towards the ground.","Keep your torso upright and your weight on your front foot.","Push through your front foot to return to the starting position.","Repeat on the other side, stepping diagonally behind and across your body with your left foot."]', '["Stehe mit schulterbreiten Füssen.","Trete mit dem rechten Fuss diagonal nach hinten und über den Körper, hinter das linke Bein.","Beuge beide Knie, als würdest du einen Knicks machen, und senke den Körper Richtung Boden ab.","Halte den Oberkörper aufrecht und das Gewicht auf dem vorderen Fuss.","Drücke dich durch den vorderen Fuss zurück in die Ausgangsposition.","Wiederhole auf der anderen Seite, trete mit dem linken Fuss diagonal nach hinten und über den Körper."]', 'https://ascent-api.sweber.workers.dev/media/exercises/3769.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/3769.gif', 1784612222128, 1784612222128, 0),
  ('d1eff3e0-8ed2-590a-8938-113517330624', NULL, 'Cycle Cross Trainer', 'Crosstrainer', 'cardio', 'cardiovascular system', 'leverage machine', 'Adjust the seat height and position yourself on the cycle cross trainer. Place your feet on the pedals and grip the handlebars. Start pedaling in a smooth and controlled motion. Maintain a steady pace and increase the resistance if desired. Continue pedaling for the desired duration of your cardio workout.', NULL, 'quadriceps', '["quadriceps","hamstrings","glutes"]', '["Adjust the seat height and position yourself on the cycle cross trainer.","Place your feet on the pedals and grip the handlebars.","Start pedaling in a smooth and controlled motion.","Maintain a steady pace and increase the resistance if desired.","Continue pedaling for the desired duration of your cardio workout."]', '["Stelle die Sitzhöhe ein und positioniere dich auf dem Crosstrainer.","Stelle die Füsse auf die Pedale und greife die Griffe.","Beginne mit einer flüssigen, kontrollierten Trittbewegung.","Halte ein gleichmässiges Tempo und erhöhe bei Bedarf den Widerstand.","Trete für die gewünschte Dauer deines Cardio-Trainings weiter."]', 'https://ascent-api.sweber.workers.dev/media/exercises/2331.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/2331.gif', 1784612222128, 1784612222128, 0),
  ('47b43d84-dd64-54e2-955e-d1e1a54f1f1e', NULL, 'Dead Bug', 'Dead Bug', 'waist', 'abs', 'body weight', 'Lie flat on your back with your arms extended towards the ceiling. Bend your knees and lift your legs off the ground, creating a 90-degree angle at your hips and knees. Engage your core and lower back to press your lower back into the ground. Slowly lower your right arm and left leg towards the ground, keeping them straight and hovering just above the floor. Pause for a moment, then return to the starting position. Repeat the movement with your left arm and right leg. Continue alternating sides for the desired number of repetitions.', NULL, 'hip flexors', '["hip flexors","lower back"]', '["Lie flat on your back with your arms extended towards the ceiling.","Bend your knees and lift your legs off the ground, creating a 90-degree angle at your hips and knees.","Engage your core and lower back to press your lower back into the ground.","Slowly lower your right arm and left leg towards the ground, keeping them straight and hovering just above the floor.","Pause for a moment, then return to the starting position.","Repeat the movement with your left arm and right leg.","Continue alternating sides for the desired number of repetitions."]', '["Lege dich flach auf den Rücken, die Arme Richtung Decke gestreckt.","Beuge die Knie und hebe die Beine an, sodass Hüfte und Knie im 90-Grad-Winkel stehen.","Spanne die Körpermitte an und drücke den unteren Rücken in den Boden.","Senke langsam den rechten Arm und das linke Bein Richtung Boden ab, beide bleiben gestreckt und schweben knapp über dem Boden.","Halte kurz inne und kehre dann in die Ausgangsposition zurück.","Wiederhole die Bewegung mit dem linken Arm und dem rechten Bein.","Wechsle die Seite fortlaufend für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0276.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0276.gif', 1784612222128, 1784612222128, 0),
  ('65639de6-2d70-5507-970e-8a4f4346bb24', NULL, 'Decline Crunch', 'Negativbank-Crunch', 'waist', 'abs', 'body weight', 'Lie on a decline bench with your feet secured and your knees bent at a 90-degree angle. Place your hands behind your head or across your chest. Engage your abs and lift your upper body towards your knees, curling your torso. Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'hip flexors', '["hip flexors"]', '["Lie on a decline bench with your feet secured and your knees bent at a 90-degree angle.","Place your hands behind your head or across your chest.","Engage your abs and lift your upper body towards your knees, curling your torso.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."]', '["Lege dich auf eine Negativbank, die Füsse gesichert, die Knie im 90-Grad-Winkel gebeugt.","Lege die Hände hinter den Kopf oder verschränke sie vor der Brust.","Spanne die Bauchmuskeln an und hebe den Oberkörper Richtung Knie, rolle dabei den Rumpf.","Halte am oberen Punkt kurz inne und senke den Oberkörper dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0277.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0277.gif', 1784612222128, 1784612222128, 0),
  ('b9ad60f7-b826-57de-acef-3bf4881be0a0', NULL, 'Decline Push-up', 'Negativ-Liegestütz', 'chest', 'pectorals', 'body weight', 'Place your hands on the ground slightly wider than shoulder-width apart, with your feet elevated on a stable surface. Keep your body in a straight line from head to toe, engaging your core muscles. Lower your chest towards the ground by bending your elbows, keeping them close to your body. Push through your palms to extend your arms and return to the starting position. Repeat for the desired number of repetitions.', NULL, 'triceps', '["triceps","shoulders"]', '["Place your hands on the ground slightly wider than shoulder-width apart, with your feet elevated on a stable surface.","Keep your body in a straight line from head to toe, engaging your core muscles.","Lower your chest towards the ground by bending your elbows, keeping them close to your body.","Push through your palms to extend your arms and return to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle die Hände etwas breiter als schulterbreit auf den Boden, die Füsse auf einer stabilen Erhöhung.","Halte den Körper in gerader Linie von Kopf bis Fuss, die Körpermitte angespannt.","Senke die Brust Richtung Boden, indem du die Ellbogen beugst und nah am Körper hältst.","Drücke durch die Handflächen, um die Arme zu strecken und in die Ausgangsposition zurückzukehren.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0279.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0279.gif', 1784612222128, 1784612222128, 0),
  ('bc757331-531c-5091-b138-13409fbdcdbd', NULL, 'Decline Sit-up', 'Negativbank-Sit-up', 'waist', 'abs', 'body weight', 'Lie on a decline bench with your feet secured and your knees bent. Place your hands behind your head or across your chest. Engage your abs and lift your upper body off the bench, curling forward towards your knees. Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'hip flexors', '["hip flexors","lower back"]', '["Lie on a decline bench with your feet secured and your knees bent.","Place your hands behind your head or across your chest.","Engage your abs and lift your upper body off the bench, curling forward towards your knees.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."]', '["Lege dich auf eine Negativbank, die Füsse gesichert, die Knie gebeugt.","Lege die Hände hinter den Kopf oder verschränke sie vor der Brust.","Spanne die Bauchmuskeln an und hebe den Oberkörper von der Bank ab, rolle ihn Richtung Knie.","Halte am oberen Punkt kurz inne und senke den Oberkörper dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0282.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0282.gif', 1784612222128, 1784612222128, 0),
  ('be330385-24d0-5894-809b-4689f29d0e3c', NULL, 'Deep Push-up', 'Tiefer Liegestütz', 'chest', 'pectorals', 'dumbbell', 'Start in a high plank position with your hands slightly wider than shoulder-width apart and your body in a straight line. Lower your chest towards the ground by bending your elbows, keeping them close to your body. Push through your palms to extend your arms and return to the starting position. Repeat for the desired number of repetitions.', NULL, 'triceps', '["triceps","shoulders"]', '["Start in a high plank position with your hands slightly wider than shoulder-width apart and your body in a straight line.","Lower your chest towards the ground by bending your elbows, keeping them close to your body.","Push through your palms to extend your arms and return to the starting position.","Repeat for the desired number of repetitions."]', '["Starte in einer hohen Plank-Position, die Hände etwas breiter als schulterbreit, der Körper bildet eine gerade Linie.","Senke die Brust Richtung Boden ab, indem du die Ellbogen beugst und nah am Körper hältst.","Drücke durch die Handflächen, um die Arme zu strecken und in die Ausgangsposition zurückzukehren.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1274.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1274.gif', 1784612222128, 1784612222128, 0),
  ('882fb1e1-c474-56b0-a464-1dc87c58cebf', NULL, 'Diamond Push-up', 'Diamant-Liegestütz', 'upper arms', 'triceps', 'body weight', 'Start in a high plank position with your hands close together, forming a diamond shape with your thumbs and index fingers. Keep your body in a straight line from head to toe, engaging your core and glutes. Lower your chest towards the diamond shape formed by your hands, keeping your elbows close to your body. Pause for a moment at the bottom, then push yourself back up to the starting position. Repeat for the desired number of repetitions.', NULL, 'chest', '["chest","shoulders"]', '["Start in a high plank position with your hands close together, forming a diamond shape with your thumbs and index fingers.","Keep your body in a straight line from head to toe, engaging your core and glutes.","Lower your chest towards the diamond shape formed by your hands, keeping your elbows close to your body.","Pause for a moment at the bottom, then push yourself back up to the starting position.","Repeat for the desired number of repetitions."]', '["Starte in einer hohen Plank-Position, die Hände eng zusammen, Daumen und Zeigefinger bilden eine Rautenform.","Halte den Körper in gerader Linie von Kopf bis Fuss, Körpermitte und Gesäss angespannt.","Senke die Brust Richtung Rautenform der Hände ab, die Ellbogen bleiben nah am Körper.","Halte am unteren Punkt kurz inne und drücke dich dann zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0283.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0283.gif', 1784612222128, 1784612222128, 0),
  ('b3cbc15d-a126-52d3-9c40-70f9c25f9c3c', NULL, 'Donkey Calf Raise', 'Donkey-Wadenheben', 'lower legs', 'calves', 'body weight', 'Stand with your toes on an elevated surface, such as a step or block. Place your hands on a stable support, such as a wall or railing, for balance. Raise your heels as high as possible, lifting your body weight onto the balls of your feet. Pause for a moment at the top, then slowly lower your heels back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'hamstrings', '["hamstrings","glutes"]', '["Stand with your toes on an elevated surface, such as a step or block.","Place your hands on a stable support, such as a wall or railing, for balance.","Raise your heels as high as possible, lifting your body weight onto the balls of your feet.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."]', '["Stehe mit den Zehenspitzen auf einer Erhöhung, zum Beispiel einer Stufe oder einem Block.","Lege die Hände zur Balance auf eine stabile Stütze, zum Beispiel eine Wand oder ein Geländer.","Hebe die Fersen so weit wie möglich an, sodass dein Körpergewicht auf den Fussballen ruht.","Halte am oberen Punkt kurz inne und senke die Fersen dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0284.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0284.gif', 1784612222128, 1784612222128, 0),
  ('9cb75328-e127-5628-af6c-727346a3e487', NULL, 'Drop Push-up', 'Drop-Liegestütz', 'chest', 'pectorals', 'body weight', 'Start in a high plank position with your hands slightly wider than shoulder-width apart. Lower your chest towards the ground, keeping your elbows close to your body. Once your chest is just above the ground, quickly drop your knees to the ground. Push yourself back up to the starting position by extending your arms. Repeat for the desired number of repetitions.', NULL, 'triceps', '["triceps","shoulders"]', '["Start in a high plank position with your hands slightly wider than shoulder-width apart.","Lower your chest towards the ground, keeping your elbows close to your body.","Once your chest is just above the ground, quickly drop your knees to the ground.","Push yourself back up to the starting position by extending your arms.","Repeat for the desired number of repetitions."]', '["Starte in einer hohen Plank-Position, die Hände etwas breiter als schulterbreit.","Senke die Brust Richtung Boden ab, die Ellbogen bleiben nah am Körper.","Sobald die Brust knapp über dem Boden ist, senke schnell die Knie auf den Boden.","Drücke dich zurück in die Ausgangsposition, indem du die Arme streckst.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1275.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1275.gif', 1784612222128, 1784612222128, 0),
  ('09e5a4ec-0e44-54f3-888e-f1ce70567caa', NULL, 'Dumbbell Alternate Biceps Curl', 'Kurzhantel-Bizepscurl wechselseitig', 'upper arms', 'biceps', 'dumbbell', 'Stand up straight with a dumbbell in each hand, palms facing forward and arms fully extended. Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly begin to lower the dumbbells back to the starting position. Repeat for the desired number of repetitions, alternating arms.', NULL, 'forearms', '["forearms"]', '["Stand up straight with a dumbbell in each hand, palms facing forward and arms fully extended.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions, alternating arms."]', '["Stehe aufrecht, in jeder Hand eine Kurzhantel, Handflächen nach vorne, Arme vollständig gestreckt.","Halte die Oberarme ruhig, atme aus und beuge die Arme, während du den Bizeps anspannst.","Hebe die Kurzhanteln weiter, bis der Bizeps vollständig angespannt ist und die Kurzhanteln auf Schulterhöhe sind.","Halte die kontrahierte Position kurz und spanne dabei den Bizeps an.","Atme ein und senke die Kurzhanteln langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dabei die Seite."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0285.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0285.gif', 1784612222128, 1784612222128, 0),
  ('988c7e60-48eb-5f75-9952-33ced6f11fff', NULL, 'Dumbbell Alternate Biceps Curl (with Arm Blaster)', 'Kurzhantel-Bizepscurl wechselseitig mit Arm Blaster', 'upper arms', 'biceps', 'dumbbell', 'Stand up straight with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing forward. Place the arm blaster on your upper arms, ensuring a secure fit. Keeping your upper arms stationary, exhale and curl one dumbbell up towards your shoulder while contracting your biceps. Continue to raise the dumbbell until your biceps are fully contracted and the dumbbell is at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly lower the dumbbell back to the starting position. Repeat the movement with the opposite arm. Continue alternating arms for the desired number of repetitions.', NULL, 'forearms', '["forearms"]', '["Stand up straight with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing forward.","Place the arm blaster on your upper arms, ensuring a secure fit.","Keeping your upper arms stationary, exhale and curl one dumbbell up towards your shoulder while contracting your biceps.","Continue to raise the dumbbell until your biceps are fully contracted and the dumbbell is at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly lower the dumbbell back to the starting position.","Repeat the movement with the opposite arm.","Continue alternating arms for the desired number of repetitions."]', '["Stehe aufrecht mit schulterbreiten Füssen, in jeder Hand eine Kurzhantel, Handflächen nach vorne.","Lege den Arm-Blaster an die Oberarme an und achte auf einen festen Sitz.","Halte die Oberarme ruhig, atme aus und beuge eine Kurzhantel Richtung Schulter, während du den Bizeps anspannst.","Hebe die Kurzhantel weiter, bis der Bizeps vollständig angespannt ist und die Kurzhantel auf Schulterhöhe ist.","Halte die kontrahierte Position kurz und spanne dabei den Bizeps an.","Atme ein und senke die Kurzhantel langsam zurück in die Ausgangsposition ab.","Wiederhole die Bewegung mit dem anderen Arm.","Wechsle den Arm fortlaufend für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/2403.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/2403.gif', 1784612222128, 1784612222128, 0),
  ('e9053856-be38-515a-97d8-12e2dde3b3e7', NULL, 'Dumbbell Alternate Hammer Preacher Curl', 'Kurzhantel-Hammer Preacher Curl wechselseitig', 'upper arms', 'biceps', 'dumbbell', 'Sit on a preacher bench with a dumbbell in each hand, palms facing your torso and arms fully extended. Keep your upper arms stationary and exhale as you curl the weights while contracting your biceps. Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly begin to lower the dumbbells back to the starting position. Repeat for the recommended amount of repetitions.', NULL, 'forearms', '["forearms"]', '["Sit on a preacher bench with a dumbbell in each hand, palms facing your torso and arms fully extended.","Keep your upper arms stationary and exhale as you curl the weights while contracting your biceps.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the recommended amount of repetitions."]', '["Setze dich auf eine Scott-Bank, in jeder Hand eine Kurzhantel, Handflächen zum Körper, Arme vollständig gestreckt.","Halte die Oberarme ruhig und atme aus, während du die Kurzhanteln hochziehst und den Bizeps anspannst.","Hebe die Kurzhanteln weiter, bis der Bizeps vollständig angespannt ist und die Kurzhanteln auf Schulterhöhe sind.","Halte die kontrahierte Position kurz und spanne dabei den Bizeps an.","Atme ein und senke die Kurzhanteln langsam zurück in die Ausgangsposition ab.","Wiederhole für die empfohlene Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1646.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1646.gif', 1784612222128, 1784612222128, 0),
  ('8750a51b-58ab-5fcb-8e92-050541df14df', NULL, 'Dumbbell Alternate Preacher Curl', 'Kurzhantel-Preacher Curl wechselseitig', 'upper arms', 'biceps', 'dumbbell', 'Sit on a preacher bench with a dumbbell in each hand, palms facing up. Rest your upper arms on the pad of the preacher bench, allowing your arms to fully extend. Keeping your upper arms stationary, exhale and curl the dumbbell in your right hand as you contract your biceps. Continue to curl the dumbbell until your biceps are fully contracted and the dumbbell is at shoulder level. Pause for a moment, then inhale and slowly lower the dumbbell back to the starting position. Repeat the movement with your left arm. Continue alternating arms for the desired number of repetitions.', NULL, 'forearms', '["forearms"]', '["Sit on a preacher bench with a dumbbell in each hand, palms facing up.","Rest your upper arms on the pad of the preacher bench, allowing your arms to fully extend.","Keeping your upper arms stationary, exhale and curl the dumbbell in your right hand as you contract your biceps.","Continue to curl the dumbbell until your biceps are fully contracted and the dumbbell is at shoulder level.","Pause for a moment, then inhale and slowly lower the dumbbell back to the starting position.","Repeat the movement with your left arm.","Continue alternating arms for the desired number of repetitions."]', '["Setze dich auf eine Scott-Bank, in jeder Hand eine Kurzhantel, Handflächen nach oben.","Lege die Oberarme auf das Polster der Scott-Bank, sodass die Arme vollständig gestreckt sind.","Halte die Oberarme ruhig, atme aus und ziehe die Kurzhantel in der rechten Hand hoch, während du den Bizeps anspannst.","Ziehe die Kurzhantel weiter hoch, bis der Bizeps vollständig angespannt ist und die Kurzhantel auf Schulterhöhe ist.","Halte kurz inne, atme dann ein und senke die Kurzhantel langsam zurück in die Ausgangsposition ab.","Wiederhole die Bewegung mit dem linken Arm.","Wechsle den Arm fortlaufend für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1647.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1647.gif', 1784612222128, 1784612222128, 0),
  ('36154e5e-74f2-5f65-84bb-ca3824d43985', NULL, 'Dumbbell Alternate Seated Hammer Curl', 'Kurzhantel-Hammercurl sitzend wechselseitig', 'upper arms', 'biceps', 'dumbbell', 'Sit on a bench with a dumbbell in each hand, palms facing your torso and arms extended down. Keep your back straight and your elbows close to your torso. Exhale and curl the dumbbell in your right hand towards your shoulder, keeping your upper arm stationary. Continue to raise the dumbbell until your biceps are fully contracted and the dumbbell is at shoulder level. Pause for a brief moment, then inhale and slowly lower the dumbbell back to the starting position. Repeat the movement with your left arm. Continue alternating arms for the desired number of repetitions.', NULL, 'forearms', '["forearms"]', '["Sit on a bench with a dumbbell in each hand, palms facing your torso and arms extended down.","Keep your back straight and your elbows close to your torso.","Exhale and curl the dumbbell in your right hand towards your shoulder, keeping your upper arm stationary.","Continue to raise the dumbbell until your biceps are fully contracted and the dumbbell is at shoulder level.","Pause for a brief moment, then inhale and slowly lower the dumbbell back to the starting position.","Repeat the movement with your left arm.","Continue alternating arms for the desired number of repetitions."]', '["Setze dich auf eine Bank, in jeder Hand eine Kurzhantel, Handflächen zum Körper, Arme nach unten gestreckt.","Halte den Rücken gerade und die Ellbogen nah am Körper.","Atme aus und ziehe die Kurzhantel in der rechten Hand Richtung Schulter, der Oberarm bleibt ruhig.","Hebe die Kurzhantel weiter, bis der Bizeps vollständig angespannt ist und die Kurzhantel auf Schulterhöhe ist.","Halte kurz inne, atme dann ein und senke die Kurzhantel langsam zurück in die Ausgangsposition ab.","Wiederhole die Bewegung mit dem linken Arm.","Wechsle den Arm fortlaufend für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1648.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1648.gif', 1784612222128, 1784612222128, 0),
  ('f3255606-9638-5347-bd7f-0dee5b3407b4', NULL, 'Dumbbell Alternate Side Press', 'Kurzhantel-Seitliches Drücken wechselseitig', 'shoulders', 'delts', 'dumbbell', 'Stand with your feet shoulder-width apart, holding a dumbbell in each hand at shoulder height. Press one dumbbell overhead while keeping the other dumbbell at shoulder height. Lower the pressed dumbbell back to shoulder height while pressing the other dumbbell overhead. Continue alternating sides for the desired number of repetitions.', NULL, 'triceps', '["triceps","core"]', '["Stand with your feet shoulder-width apart, holding a dumbbell in each hand at shoulder height.","Press one dumbbell overhead while keeping the other dumbbell at shoulder height.","Lower the pressed dumbbell back to shoulder height while pressing the other dumbbell overhead.","Continue alternating sides for the desired number of repetitions."]', '["Stehe mit schulterbreiten Füssen, in jeder Hand eine Kurzhantel auf Schulterhöhe.","Drücke eine Kurzhantel über Kopf, während die andere auf Schulterhöhe bleibt.","Senke die gedrückte Kurzhantel zurück auf Schulterhöhe, während du die andere über Kopf drückst.","Wechsle die Seite fortlaufend für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0286.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0286.gif', 1784612222128, 1784612222128, 0),
  ('75743433-66d4-5b45-a91f-2e2cca68d24b', NULL, 'Dumbbell Alternating Bicep Curl with Leg Raised on Exercise Ball', 'Kurzhantel-Bizepscurl wechselseitig mit angehobenem Bein auf dem Gymnastikball', 'upper arms', 'biceps', 'dumbbell', 'Stand with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing forward. Place an exercise ball behind you and position one foot on top of it, keeping your balance. With your arms fully extended and elbows close to your sides, curl one dumbbell towards your shoulder while keeping your upper arm stationary. Lower the dumbbell back down to the starting position and repeat with the other arm. Continue alternating arms for the desired number of repetitions.', NULL, 'forearms', '["forearms","shoulders"]', '["Stand with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing forward.","Place an exercise ball behind you and position one foot on top of it, keeping your balance.","With your arms fully extended and elbows close to your sides, curl one dumbbell towards your shoulder while keeping your upper arm stationary.","Lower the dumbbell back down to the starting position and repeat with the other arm.","Continue alternating arms for the desired number of repetitions."]', '["Stehe mit schulterbreiten Füssen, in jeder Hand eine Kurzhantel, Handflächen nach vorne.","Stelle einen Gymnastikball hinter dich und lege einen Fuss darauf ab, halte dabei das Gleichgewicht.","Mit vollständig gestreckten Armen und nah am Körper gehaltenen Ellbogen ziehst du eine Kurzhantel Richtung Schulter, der Oberarm bleibt ruhig.","Senke die Kurzhantel zurück in die Ausgangsposition ab und wiederhole mit dem anderen Arm.","Wechsle den Arm fortlaufend für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1649.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1649.gif', 1784612222128, 1784612222128, 0),
  ('ac07f071-cbce-55b3-91c7-5de916b9c1d4', NULL, 'Dumbbell Alternating Seated Bicep Curl on Exercise Ball', 'Kurzhantel-Bizepscurl sitzend wechselseitig auf dem Gymnastikball', 'upper arms', 'biceps', 'dumbbell', 'Sit on an exercise ball with your feet flat on the ground and your back straight. Hold a dumbbell in each hand with your palms facing forward and your arms fully extended. Keeping your upper arms stationary, exhale and curl one dumbbell while rotating your forearm until your palm is facing your shoulder. Inhale and slowly lower the dumbbell back to the starting position. Repeat the curl with the other arm. Continue alternating curls for the desired number of repetitions.', NULL, 'forearms', '["forearms"]', '["Sit on an exercise ball with your feet flat on the ground and your back straight.","Hold a dumbbell in each hand with your palms facing forward and your arms fully extended.","Keeping your upper arms stationary, exhale and curl one dumbbell while rotating your forearm until your palm is facing your shoulder.","Inhale and slowly lower the dumbbell back to the starting position.","Repeat the curl with the other arm.","Continue alternating curls for the desired number of repetitions."]', '["Setze dich auf einen Gymnastikball, Füsse flach am Boden, Rücken gerade.","Halte in jeder Hand eine Kurzhantel, Handflächen nach vorne, Arme vollständig gestreckt.","Halte die Oberarme ruhig, atme aus und beuge eine Kurzhantel, während du den Unterarm drehst, bis die Handfläche zur Schulter zeigt.","Atme ein und senke die Kurzhantel langsam zurück in die Ausgangsposition ab.","Wiederhole die Beugung mit dem anderen Arm.","Wechsle die Beugung fortlaufend für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1650.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1650.gif', 1784612222128, 1784612222128, 0),
  ('a806bda8-740f-5fe0-8c6c-833c689bbe82', NULL, 'Dumbbell Arnold Press', 'Kurzhantel-Arnold Press', 'shoulders', 'delts', 'dumbbell', 'Sit on a bench with back support and hold a dumbbell in each hand at shoulder level, palms facing your body and elbows bent. Press the dumbbells upward until your arms are fully extended and your palms are facing forward. Rotate your wrists as you lift, so that your palms are facing forward at the top of the movement. Pause for a moment at the top, then slowly lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', NULL, 'triceps', '["triceps","upper chest"]', '["Sit on a bench with back support and hold a dumbbell in each hand at shoulder level, palms facing your body and elbows bent.","Press the dumbbells upward until your arms are fully extended and your palms are facing forward.","Rotate your wrists as you lift, so that your palms are facing forward at the top of the movement.","Pause for a moment at the top, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."]', '["Setze dich auf eine Bank mit Rückenlehne, in jeder Hand eine Kurzhantel auf Schulterhöhe, Handflächen zum Körper, Ellbogen gebeugt.","Drücke die Kurzhanteln nach oben, bis die Arme vollständig gestreckt sind und die Handflächen nach vorne zeigen.","Drehe beim Hochdrücken die Handgelenke, sodass die Handflächen am oberen Punkt nach vorne zeigen.","Halte am oberen Punkt kurz inne und senke die Kurzhanteln dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/2137.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/2137.gif', 1784612222128, 1784612222128, 0),
  ('e1e9ee66-6458-5639-9bba-1aafca357053', NULL, 'Dumbbell Arnold Press V. 2', 'Kurzhantel-Arnold Press V. 2', 'shoulders', 'delts', 'dumbbell', 'Sit on a bench with back support and hold a dumbbell in each hand at shoulder level, palms facing your body and elbows bent. Press the dumbbells upward until your arms are fully extended and your palms are facing forward. Rotate your wrists as you lift, so that your palms end up facing forward at the top of the movement. Pause for a moment at the top, then slowly lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', NULL, 'triceps', '["triceps","upper chest"]', '["Sit on a bench with back support and hold a dumbbell in each hand at shoulder level, palms facing your body and elbows bent.","Press the dumbbells upward until your arms are fully extended and your palms are facing forward.","Rotate your wrists as you lift, so that your palms end up facing forward at the top of the movement.","Pause for a moment at the top, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."]', '["Setze dich auf eine Bank mit Rückenlehne, in jeder Hand eine Kurzhantel auf Schulterhöhe, Handflächen zum Körper, Ellbogen gebeugt.","Drücke die Kurzhanteln nach oben, bis die Arme vollständig gestreckt sind und die Handflächen nach vorne zeigen.","Drehe beim Hochdrücken die Handgelenke, sodass die Handflächen am oberen Punkt nach vorne zeigen.","Halte am oberen Punkt kurz inne und senke die Kurzhanteln dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0287.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0287.gif', 1784612222128, 1784612222128, 0),
  ('8a0d0a90-ca82-5530-8b40-f187993ce55f', NULL, 'Dumbbell Around Pullover', 'Kurzhantel-Rundum-Pullover', 'chest', 'pectorals', 'dumbbell', 'Lie flat on a bench with your head at one end and your feet firmly on the ground. Hold a dumbbell with both hands and extend your arms straight above your chest. Keeping your arms straight, slowly lower the dumbbell behind your head in an arc motion. Pause for a moment at the bottom, then raise the dumbbell back to the starting position. Repeat for the desired number of repetitions.', NULL, 'triceps', '["triceps","latissimus dorsi"]', '["Lie flat on a bench with your head at one end and your feet firmly on the ground.","Hold a dumbbell with both hands and extend your arms straight above your chest.","Keeping your arms straight, slowly lower the dumbbell behind your head in an arc motion.","Pause for a moment at the bottom, then raise the dumbbell back to the starting position.","Repeat for the desired number of repetitions."]', '["Lege dich flach auf eine Bank, der Kopf an einem Ende, die Füsse fest auf dem Boden.","Halte eine Kurzhantel mit beiden Händen und strecke die Arme gerade über der Brust nach oben.","Halte die Arme gestreckt und senke die Kurzhantel in einer Bogenbewegung langsam hinter den Kopf ab.","Halte am unteren Punkt kurz inne und hebe die Kurzhantel dann zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0288.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0288.gif', 1784612222128, 1784612222128, 0),
  ('54c45118-8996-5b52-a1aa-3ed7d9e8c11d', NULL, 'Dumbbell Bench Press', 'Kurzhantel-Bankdrücken', 'chest', 'pectorals', 'dumbbell', 'Lie flat on a bench with your feet flat on the ground and your back pressed against the bench. Hold a dumbbell in each hand, with your palms facing forward and your arms extended above your chest. Lower the dumbbells slowly to the sides of your chest, keeping your elbows at a 90-degree angle. Pause for a moment, then push the dumbbells back up to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', NULL, 'triceps', '["triceps","shoulders"]', '["Lie flat on a bench with your feet flat on the ground and your back pressed against the bench.","Hold a dumbbell in each hand, with your palms facing forward and your arms extended above your chest.","Lower the dumbbells slowly to the sides of your chest, keeping your elbows at a 90-degree angle.","Pause for a moment, then push the dumbbells back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."]', '["Lege dich flach auf eine Bank, Füsse flach am Boden, Rücken auf der Bank.","Halte in jeder Hand eine Kurzhantel, Handflächen nach vorne, Arme über der Brust gestreckt.","Senke die Kurzhanteln langsam an die Seiten der Brust ab, die Ellbogen bilden dabei einen 90-Grad-Winkel.","Halte kurz inne und drücke die Kurzhanteln dann zurück in die Ausgangsposition, die Arme vollständig gestreckt.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0289.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0289.gif', 1784612222128, 1784612222128, 0),
  ('01c682c8-f948-5556-b36c-9dc479f87ec9', NULL, 'Dumbbell Bench Seated Press', 'Kurzhantel-Drücken sitzend auf der Bank', 'shoulders', 'delts', 'dumbbell', 'Sit on a bench with a dumbbell in each hand, resting on your thighs. Lean back and position the dumbbells to the sides of your chest, palms facing forward. Press the dumbbells upward until your arms are fully extended. Pause for a moment at the top, then slowly lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', NULL, 'triceps', '["triceps","chest"]', '["Sit on a bench with a dumbbell in each hand, resting on your thighs.","Lean back and position the dumbbells to the sides of your chest, palms facing forward.","Press the dumbbells upward until your arms are fully extended.","Pause for a moment at the top, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."]', '["Setze dich auf eine Bank, in jeder Hand eine Kurzhantel, auf den Oberschenkeln abgestützt.","Lehne dich zurück und positioniere die Kurzhanteln seitlich der Brust, Handflächen nach vorne.","Drücke die Kurzhanteln nach oben, bis die Arme vollständig gestreckt sind.","Halte am oberen Punkt kurz inne und senke die Kurzhanteln dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0290.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0290.gif', 1784612222128, 1784612222128, 0),
  ('8d7b6ce4-24a2-5dd8-a0fd-6d055287f2d8', NULL, 'Dumbbell Bench Squat', 'Kurzhantel-Kniebeuge mit Bank', 'upper legs', 'glutes', 'dumbbell', 'Place a dumbbell on the ground in front of a bench. Stand facing away from the bench with your feet shoulder-width apart. Bend at the knees and hips to lower yourself down towards the bench, keeping your chest up and back straight. Once your glutes touch the bench, push through your heels to stand back up to the starting position. Repeat for the desired number of repetitions.', NULL, 'quadriceps', '["quadriceps","hamstrings","calves"]', '["Place a dumbbell on the ground in front of a bench.","Stand facing away from the bench with your feet shoulder-width apart.","Bend at the knees and hips to lower yourself down towards the bench, keeping your chest up and back straight.","Once your glutes touch the bench, push through your heels to stand back up to the starting position.","Repeat for the desired number of repetitions."]', '["Lege eine Kurzhantel vor eine Bank auf den Boden.","Stehe mit dem Rücken zur Bank, Füsse schulterbreit auseinander.","Beuge Knie und Hüfte, um dich Richtung Bank abzusenken, die Brust bleibt raus, der Rücken gerade.","Sobald das Gesäss die Bank berührt, drückst du dich durch die Fersen zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0291.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0291.gif', 1784612222128, 1784612222128, 0),
  ('7512a7fb-2e4f-57db-8e99-4206e4dfee9f', NULL, 'Dumbbell Bent Over Row', 'Kurzhantel-Rudern vorgebeugt', 'back', 'upper back', 'dumbbell', 'Stand with your feet shoulder-width apart, knees slightly bent, and hold a dumbbell in each hand with your palms facing your body. Bend forward at the hips, keeping your back straight and your core engaged. Let your arms hang straight down towards the floor, with your elbows slightly bent. Pull the dumbbells up towards your chest, squeezing your shoulder blades together. Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","forearms"]', '["Stand with your feet shoulder-width apart, knees slightly bent, and hold a dumbbell in each hand with your palms facing your body.","Bend forward at the hips, keeping your back straight and your core engaged.","Let your arms hang straight down towards the floor, with your elbows slightly bent.","Pull the dumbbells up towards your chest, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."]', '["Stehe mit schulterbreiten Füssen, Knie leicht gebeugt, in jeder Hand eine Kurzhantel, Handflächen zum Körper.","Beuge dich in der Hüfte nach vorne, der Rücken bleibt gerade, die Körpermitte angespannt.","Lass die Arme gerade Richtung Boden hängen, die Ellbogen leicht gebeugt.","Ziehe die Kurzhanteln Richtung Brust hoch und ziehe dabei die Schulterblätter zusammen.","Halte am oberen Punkt kurz inne und senke die Kurzhanteln dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0293.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0293.gif', 1784612222128, 1784612222128, 0),
  ('ca7333fc-5ff9-5a79-8f2f-c125410fb9f7', NULL, 'Dumbbell Bicep Curl Lunge with Bowling Motion', 'Kurzhantel-Bizepscurl im Ausfallschritt mit Bowling-Bewegung', 'upper arms', 'biceps', 'dumbbell', 'Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing forward. Take a step forward with your right foot, bending your right knee and lowering your body into a lunge position. As you lunge forward, curl the dumbbells up towards your shoulders, keeping your elbows close to your body. At the bottom of the lunge, rotate your torso to the right, as if you were bowling a ball. Reverse the motion, stepping back with your right foot and returning to the starting position while lowering the dumbbells back down. Repeat the lunge and curl motion, this time rotating your torso to the left. Continue alternating sides for the desired number of repetitions.', NULL, 'forearms', '["forearms","shoulders"]', '["Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing forward.","Take a step forward with your right foot, bending your right knee and lowering your body into a lunge position.","As you lunge forward, curl the dumbbells up towards your shoulders, keeping your elbows close to your body.","At the bottom of the lunge, rotate your torso to the right, as if you were bowling a ball.","Reverse the motion, stepping back with your right foot and returning to the starting position while lowering the dumbbells back down.","Repeat the lunge and curl motion, this time rotating your torso to the left.","Continue alternating sides for the desired number of repetitions."]', '["Stehe mit schulterbreiten Füssen, in jeder Hand eine Kurzhantel, Handflächen nach vorne.","Trete mit dem rechten Fuss nach vorne, beuge das rechte Knie und senke den Körper in eine Ausfallschritt-Position ab.","Ziehe beim Ausfallschritt die Kurzhanteln Richtung Schultern hoch, die Ellbogen bleiben nah am Körper.","Drehe am unteren Punkt des Ausfallschritts den Oberkörper nach rechts, wie beim Bowling.","Kehre die Bewegung um, trete mit dem rechten Fuss zurück in die Ausgangsposition und senke dabei die Kurzhanteln wieder ab.","Wiederhole den Ausfallschritt mit Curl, diesmal mit Drehung nach links.","Wechsle die Seite fortlaufend für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1651.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1651.gif', 1784612222128, 1784612222128, 0),
  ('c7caeb42-afc3-5f30-89b5-6b5d165f54d4', NULL, 'Dumbbell Bicep Curl on Exercise Ball with Leg Raised', 'Kurzhantel-Bizepscurl auf dem Gymnastikball mit angehobenem Bein', 'upper arms', 'biceps', 'dumbbell', 'Sit on an exercise ball with your feet flat on the ground and your back straight. Hold a dumbbell in each hand with your palms facing forward and your arms fully extended. Slowly curl the dumbbells towards your shoulders, keeping your elbows close to your sides. Pause for a moment at the top of the movement, then slowly lower the dumbbells back to the starting position. While performing the bicep curl, raise one leg off the ground and hold it in the air for the duration of the exercise. Repeat for the desired number of repetitions, then switch legs and repeat.', NULL, 'forearms', '["forearms","shoulders"]', '["Sit on an exercise ball with your feet flat on the ground and your back straight.","Hold a dumbbell in each hand with your palms facing forward and your arms fully extended.","Slowly curl the dumbbells towards your shoulders, keeping your elbows close to your sides.","Pause for a moment at the top of the movement, then slowly lower the dumbbells back to the starting position.","While performing the bicep curl, raise one leg off the ground and hold it in the air for the duration of the exercise.","Repeat for the desired number of repetitions, then switch legs and repeat."]', '["Setze dich auf einen Gymnastikball, Füsse flach am Boden, Rücken gerade.","Halte in jeder Hand eine Kurzhantel, Handflächen nach vorne, Arme vollständig gestreckt.","Ziehe die Kurzhanteln langsam Richtung Schultern hoch, die Ellbogen bleiben nah am Körper.","Halte am oberen Punkt kurz inne und senke die Kurzhanteln dann langsam zurück in die Ausgangsposition ab.","Hebe während des Curls ein Bein vom Boden ab und halte es für die Dauer der Übung in der Luft.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dann das Bein."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1652.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1652.gif', 1784612222128, 1784612222128, 0),
  ('d37b984d-4987-5798-bc02-309a23d871fb', NULL, 'Dumbbell Bicep Curl with Stork Stance', 'Kurzhantel-Bizepscurl im Storchenstand', 'upper arms', 'biceps', 'dumbbell', 'Stand with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing forward. Extend one leg behind you, balancing on the toes of that foot. Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly begin to lower the dumbbells back to the starting position. Repeat for the desired number of repetitions, then switch legs and repeat.', NULL, 'forearms', '["forearms"]', '["Stand with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing forward.","Extend one leg behind you, balancing on the toes of that foot.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions, then switch legs and repeat."]', '["Stehe mit schulterbreiten Füssen, in jeder Hand eine Kurzhantel, Handflächen nach vorne.","Strecke ein Bein nach hinten aus und balanciere auf den Zehenspitzen dieses Fusses.","Halte die Oberarme ruhig, atme aus und beuge die Arme, während du den Bizeps anspannst.","Hebe die Kurzhanteln weiter, bis der Bizeps vollständig angespannt ist und die Kurzhanteln auf Schulterhöhe sind.","Halte die kontrahierte Position kurz und spanne dabei den Bizeps an.","Atme ein und senke die Kurzhanteln langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dann das Bein."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1653.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1653.gif', 1784612222128, 1784612222128, 0),
  ('963bea93-8fd7-55d1-b5f5-1c867bfaf151', NULL, 'Dumbbell Biceps Curl', 'Kurzhantel-Bizepscurl', 'upper arms', 'biceps', 'dumbbell', 'Stand up straight with a dumbbell in each hand, palms facing forward and arms fully extended. Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly begin to lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', NULL, 'forearms', '["forearms"]', '["Stand up straight with a dumbbell in each hand, palms facing forward and arms fully extended.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."]', '["Stehe aufrecht, in jeder Hand eine Kurzhantel, Handflächen nach vorne, Arme vollständig gestreckt.","Halte die Oberarme ruhig, atme aus und beuge die Arme, während du den Bizeps anspannst.","Hebe die Kurzhanteln weiter, bis der Bizeps vollständig angespannt ist und die Kurzhanteln auf Schulterhöhe sind.","Halte die kontrahierte Position kurz und spanne dabei den Bizeps an.","Atme ein und senke die Kurzhanteln langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0294.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0294.gif', 1784612222128, 1784612222128, 0),
  ('71ec716d-f6f2-5088-b670-23fe1fed1aa2', NULL, 'Dumbbell Biceps Curl (with Arm Blaster)', 'Kurzhantel-Bizepscurl mit Arm Blaster', 'upper arms', 'biceps', 'dumbbell', 'Stand up straight with a dumbbell in each hand, palms facing forward. Keep your elbows close to your torso and your upper arms stationary. Exhale and curl the weights while contracting your biceps. Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly begin to lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', NULL, 'forearms', '["forearms"]', '["Stand up straight with a dumbbell in each hand, palms facing forward.","Keep your elbows close to your torso and your upper arms stationary.","Exhale and curl the weights while contracting your biceps.","Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."]', '["Stehe aufrecht, in jeder Hand eine Kurzhantel, Handflächen nach vorne.","Halte die Ellbogen nah am Körper und die Oberarme ruhig.","Atme aus und beuge die Arme, während du den Bizeps anspannst.","Hebe die Kurzhanteln weiter, bis der Bizeps vollständig angespannt ist und die Kurzhanteln auf Schulterhöhe sind.","Halte die kontrahierte Position kurz und spanne dabei den Bizeps an.","Atme ein und senke die Kurzhanteln langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/2401.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/2401.gif', 1784612222128, 1784612222128, 0),
  ('604858f5-8c1e-5e5d-93e2-3171383bbd19', NULL, 'Dumbbell Biceps Curl Reverse', 'Kurzhantel-Reverse Curl', 'upper arms', 'biceps', 'dumbbell', 'Stand up straight with a dumbbell in each hand, palms facing down and arms fully extended. Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly begin to lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', NULL, 'forearms', '["forearms"]', '["Stand up straight with a dumbbell in each hand, palms facing down and arms fully extended.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."]', '["Stehe aufrecht, in jeder Hand eine Kurzhantel, Handflächen nach unten, Arme vollständig gestreckt.","Halte die Oberarme ruhig, atme aus und beuge die Arme, während du den Bizeps anspannst.","Hebe die Kurzhanteln weiter, bis der Bizeps vollständig angespannt ist und die Kurzhanteln auf Schulterhöhe sind.","Halte die kontrahierte Position kurz und spanne dabei den Bizeps an.","Atme ein und senke die Kurzhanteln langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1654.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1654.gif', 1784612222128, 1784612222128, 0),
  ('f563959e-f004-5e2a-9a86-0b353423ba3f', NULL, 'Dumbbell Biceps Curl Squat', 'Kurzhantel-Bizepscurl in der Kniebeuge', 'upper arms', 'biceps', 'dumbbell', 'Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing forward. Keeping your back straight and your elbows close to your sides, exhale and curl the dumbbells up towards your shoulders. Pause for a moment at the top, squeezing your biceps. Inhale and slowly lower the dumbbells back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'forearms', '["forearms"]', '["Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing forward.","Keeping your back straight and your elbows close to your sides, exhale and curl the dumbbells up towards your shoulders.","Pause for a moment at the top, squeezing your biceps.","Inhale and slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."]', '["Stehe mit schulterbreiten Füssen, in jeder Hand eine Kurzhantel, Handflächen nach vorne.","Halte den Rücken gerade und die Ellbogen nah am Körper, atme aus und ziehe die Kurzhanteln Richtung Schultern hoch.","Halte am oberen Punkt kurz inne und spanne den Bizeps an.","Atme ein und senke die Kurzhanteln langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1655.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1655.gif', 1784612222128, 1784612222128, 0),
  ('aa66c3cb-6d9c-5cf4-baec-d824e3aa3eeb', NULL, 'Dumbbell Biceps Curl V-Sit on Bosu Ball', 'Kurzhantel-Bizepscurl im V-Sitz auf dem Bosu-Ball', 'upper arms', 'biceps', 'dumbbell', 'Sit on a bosu ball with your feet flat on the ground and your knees bent at a 90-degree angle. Hold a dumbbell in each hand with your palms facing forward and your arms fully extended down by your sides. Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly begin to lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', NULL, 'forearms', '["forearms","shoulders"]', '["Sit on a bosu ball with your feet flat on the ground and your knees bent at a 90-degree angle.","Hold a dumbbell in each hand with your palms facing forward and your arms fully extended down by your sides.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."]', '["Setze dich auf einen Bosu-Ball, Füsse flach am Boden, Knie im 90-Grad-Winkel gebeugt.","Halte in jeder Hand eine Kurzhantel, Handflächen nach vorne, Arme vollständig neben dem Körper nach unten gestreckt.","Halte die Oberarme ruhig, atme aus und beuge die Arme, während du den Bizeps anspannst.","Hebe die Kurzhanteln weiter, bis der Bizeps vollständig angespannt ist und die Kurzhanteln auf Schulterhöhe sind.","Halte die kontrahierte Position kurz und spanne dabei den Bizeps an.","Atme ein und senke die Kurzhanteln langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1656.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1656.gif', 1784612222128, 1784612222128, 0),
  ('3fb67eb3-68d8-5941-8358-e50b27e19437', NULL, 'Dumbbell Burpee', 'Kurzhantel-Burpee', 'cardio', 'cardiovascular system', 'dumbbell', 'Start in a standing position with your feet shoulder-width apart and a dumbbell in each hand. Lower your body into a squat position, placing the dumbbells on the ground in front of you. Kick your feet back into a push-up position, keeping your body in a straight line. Perform a push-up, bending your elbows and lowering your chest towards the ground. Jump your feet back towards your hands, landing in a squat position. Stand up explosively, lifting the dumbbells off the ground and bringing them to your shoulders. Press the dumbbells overhead, fully extending your arms. Lower the dumbbells back to your shoulders and repeat the entire sequence for the desired number of repetitions.', NULL, 'quadriceps', '["quadriceps","hamstrings","calves","shoulders","triceps","core"]', '["Start in a standing position with your feet shoulder-width apart and a dumbbell in each hand.","Lower your body into a squat position, placing the dumbbells on the ground in front of you.","Kick your feet back into a push-up position, keeping your body in a straight line.","Perform a push-up, bending your elbows and lowering your chest towards the ground.","Jump your feet back towards your hands, landing in a squat position.","Stand up explosively, lifting the dumbbells off the ground and bringing them to your shoulders.","Press the dumbbells overhead, fully extending your arms.","Lower the dumbbells back to your shoulders and repeat the entire sequence for the desired number of repetitions."]', '["Stehe aufrecht mit schulterbreiten Füssen, in jeder Hand eine Kurzhantel.","Senke den Körper in eine Kniebeuge ab und lege die Kurzhanteln vor dir auf den Boden.","Kicke die Füsse nach hinten in eine Liegestützposition, der Körper bildet eine gerade Linie.","Führe einen Liegestütz aus, beuge die Ellbogen und senke die Brust Richtung Boden.","Springe die Füsse zurück Richtung Hände und lande in einer Kniebeuge.","Stehe explosiv auf, hebe die Kurzhanteln vom Boden und bringe sie zu den Schultern.","Drücke die Kurzhanteln über Kopf, die Arme vollständig gestreckt.","Senke die Kurzhanteln zurück zu den Schultern und wiederhole die gesamte Abfolge für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1201.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1201.gif', 1784612222128, 1784612222128, 0),
  ('c462258f-a950-53f4-a5aa-911194383989', NULL, 'Dumbbell Clean', 'Kurzhantel-Umsetzen', 'upper legs', 'glutes', 'dumbbell', 'Stand with your feet shoulder-width apart, holding a dumbbell in each hand with an overhand grip. Bend your knees and lower your hips into a squat position, keeping your back straight and chest up. Explosively extend your hips and knees, driving through your heels to jump off the ground. As you jump, shrug your shoulders and pull the dumbbells up towards your shoulders, keeping them close to your body. Catch the dumbbells at shoulder height, with your elbows pointing forward and your palms facing up. Lower the dumbbells back down to the starting position by reversing the movement. Repeat for the desired number of repetitions.', NULL, 'hamstrings', '["hamstrings","quadriceps","calves"]', '["Stand with your feet shoulder-width apart, holding a dumbbell in each hand with an overhand grip.","Bend your knees and lower your hips into a squat position, keeping your back straight and chest up.","Explosively extend your hips and knees, driving through your heels to jump off the ground.","As you jump, shrug your shoulders and pull the dumbbells up towards your shoulders, keeping them close to your body.","Catch the dumbbells at shoulder height, with your elbows pointing forward and your palms facing up.","Lower the dumbbells back down to the starting position by reversing the movement.","Repeat for the desired number of repetitions."]', '["Stehe mit schulterbreiten Füssen, in jeder Hand eine Kurzhantel im Obergriff.","Beuge die Knie und senke die Hüfte in eine Kniebeuge ab, der Rücken bleibt gerade, die Brust raus.","Strecke Hüfte und Knie explosiv, drücke dich durch die Fersen vom Boden ab.","Ziehe beim Absprung die Schultern hoch und ziehe die Kurzhanteln Richtung Schultern, nah am Körper.","Fange die Kurzhanteln auf Schulterhöhe auf, die Ellbogen zeigen nach vorne, die Handflächen nach oben.","Senke die Kurzhanteln zurück in die Ausgangsposition ab, indem du die Bewegung umkehrst.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0295.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0295.gif', 1784612222128, 1784612222128, 0),
  ('7ff9e12f-fe73-5cee-ad54-52cd4dbcbdc6', NULL, 'Dumbbell Close Grip Press', 'Kurzhantel-Drücken enger Griff', 'upper arms', 'triceps', 'dumbbell', 'Sit on a flat bench with a dumbbell in each hand, resting on your thighs. Using your thighs to help raise the dumbbells, lift the dumbbells one at a time so that you can hold them in front of you at shoulder width. Once at shoulder width, rotate your wrists forward so that the palms of your hands are facing away from you. This will be your starting position. As you breathe in, slowly lower the dumbbells to your side until they are about level with your chest. As you exhale, use your triceps to lift the dumbbells back to the starting position. Make sure to use only your triceps and do not use your forearms or biceps to help lift the dumbbells. After a second pause at the contracted position, repeat the movement for the prescribed amount of repetitions.', NULL, 'chest', '["chest","shoulders"]', '["Sit on a flat bench with a dumbbell in each hand, resting on your thighs.","Using your thighs to help raise the dumbbells, lift the dumbbells one at a time so that you can hold them in front of you at shoulder width.","Once at shoulder width, rotate your wrists forward so that the palms of your hands are facing away from you. This will be your starting position.","As you breathe in, slowly lower the dumbbells to your side until they are about level with your chest.","As you exhale, use your triceps to lift the dumbbells back to the starting position. Make sure to use only your triceps and do not use your forearms or biceps to help lift the dumbbells.","After a second pause at the contracted position, repeat the movement for the prescribed amount of repetitions."]', '["Setze dich auf eine flache Bank, in jeder Hand eine Kurzhantel, auf den Oberschenkeln abgestützt.","Nutze die Oberschenkel, um die Kurzhanteln nacheinander anzuheben, sodass du sie vor dir auf Schulterbreite hältst.","Drehe auf Schulterbreite die Handgelenke nach vorne, sodass die Handflächen von dir weg zeigen. Das ist deine Ausgangsposition.","Atme ein und senke die Kurzhanteln langsam seitlich ab, bis sie etwa auf Brusthöhe sind.","Atme aus und nutze den Trizeps, um die Kurzhanteln zurück in die Ausgangsposition zu heben. Achte darauf, nur den Trizeps zu nutzen, nicht Unterarme oder Bizeps.","Halte am Punkt der vollen Anspannung eine Sekunde inne und wiederhole für die vorgeschriebene Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1731.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1731.gif', 1784612222128, 1784612222128, 0),
  ('47023ee4-138d-5566-a2ee-e8d6e967e35b', NULL, 'Dumbbell Close-Grip Press', 'Kurzhantel-Drücken enger Griff', 'upper arms', 'triceps', 'dumbbell', 'Sit on a flat bench with a dumbbell in each hand, resting on your thighs. Using your thighs to help raise the dumbbells, lift the dumbbells one at a time so that you can hold them in front of you at shoulder width. Once at shoulder width, rotate your wrists forward so that the palms of your hands are facing away from you. This will be your starting position. As you breathe in, slowly lower the dumbbells to your side until they are about level with your chest. As you exhale, use your triceps to lift the dumbbells back to the starting position. Repeat for the desired number of repetitions.', NULL, 'chest', '["chest","shoulders"]', '["Sit on a flat bench with a dumbbell in each hand, resting on your thighs.","Using your thighs to help raise the dumbbells, lift the dumbbells one at a time so that you can hold them in front of you at shoulder width.","Once at shoulder width, rotate your wrists forward so that the palms of your hands are facing away from you. This will be your starting position.","As you breathe in, slowly lower the dumbbells to your side until they are about level with your chest.","As you exhale, use your triceps to lift the dumbbells back to the starting position.","Repeat for the desired number of repetitions."]', '["Setze dich auf eine flache Bank, in jeder Hand eine Kurzhantel, auf den Oberschenkeln abgestützt.","Nutze die Oberschenkel, um die Kurzhanteln nacheinander anzuheben, sodass du sie vor dir auf Schulterbreite hältst.","Drehe auf Schulterbreite die Handgelenke nach vorne, sodass die Handflächen von dir weg zeigen. Das ist deine Ausgangsposition.","Atme ein und senke die Kurzhanteln langsam seitlich ab, bis sie etwa auf Brusthöhe sind.","Atme aus und nutze den Trizeps, um die Kurzhanteln zurück in die Ausgangsposition zu heben.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0296.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0296.gif', 1784612222128, 1784612222128, 0),
  ('e0ea7906-47b2-5aef-b74f-9bd0ab95048d', NULL, 'Dumbbell Concentration Curl', 'Kurzhantel-Konzentrationscurl', 'upper arms', 'biceps', 'dumbbell', 'Sit on a bench with your legs spread apart and a dumbbell in one hand, resting your elbow on the inside of your thigh. Fully extend your arm and hold the dumbbell with an underhand grip. Keeping your upper arm stationary, exhale and curl the weight up towards your shoulder while contracting your biceps. Continue to raise the dumbbell until your biceps are fully contracted and the dumbbell is at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly lower the dumbbell back to the starting position. Repeat for the desired number of repetitions, then switch arms.', NULL, 'forearms', '["forearms"]', '["Sit on a bench with your legs spread apart and a dumbbell in one hand, resting your elbow on the inside of your thigh.","Fully extend your arm and hold the dumbbell with an underhand grip.","Keeping your upper arm stationary, exhale and curl the weight up towards your shoulder while contracting your biceps.","Continue to raise the dumbbell until your biceps are fully contracted and the dumbbell is at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."]', '["Setze dich auf eine Bank, die Beine gespreizt, eine Kurzhantel in einer Hand, der Ellbogen auf der Innenseite des Oberschenkels abgestützt.","Strecke den Arm vollständig und halte die Kurzhantel im Untergriff.","Halte den Oberarm ruhig, atme aus und ziehe die Kurzhantel Richtung Schulter hoch, während du den Bizeps anspannst.","Hebe die Kurzhantel weiter, bis der Bizeps vollständig angespannt ist und die Kurzhantel auf Schulterhöhe ist.","Halte die kontrahierte Position kurz und spanne dabei den Bizeps an.","Atme ein und senke die Kurzhantel langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dann die Seite."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0297.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0297.gif', 1784612222128, 1784612222128, 0),
  ('c4327c71-8b4a-5d88-8224-0a457e2f41db', NULL, 'Dumbbell Contralateral Forward Lunge', 'Kurzhantel-Ausfallschritt vorwärts kontralateral', 'upper legs', 'glutes', 'dumbbell', 'Stand with your feet shoulder-width apart, holding a dumbbell in each hand. Take a step forward with your right foot, keeping your back straight and core engaged. Lower your body by bending both knees until your right thigh is parallel to the ground. Push through your right heel to return to the starting position. Repeat with your left leg. Alternate legs for the desired number of repetitions.', NULL, 'quadriceps', '["quadriceps","hamstrings","calves"]', '["Stand with your feet shoulder-width apart, holding a dumbbell in each hand.","Take a step forward with your right foot, keeping your back straight and core engaged.","Lower your body by bending both knees until your right thigh is parallel to the ground.","Push through your right heel to return to the starting position.","Repeat with your left leg.","Alternate legs for the desired number of repetitions."]', '["Stehe mit schulterbreiten Füssen, in jeder Hand eine Kurzhantel.","Trete mit dem rechten Fuss nach vorne, der Rücken bleibt gerade, die Körpermitte angespannt.","Senke den Körper ab, indem du beide Knie beugst, bis der rechte Oberschenkel parallel zum Boden ist.","Drücke dich durch die rechte Ferse zurück in die Ausgangsposition.","Wiederhole mit dem linken Bein.","Wechsle die Beine für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/3635.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/3635.gif', 1784612222128, 1784612222128, 0),
  ('c5412d53-fa95-58fd-a88b-83dd57ddeeb1', NULL, 'Dumbbell Cross Body Hammer Curl', 'Kurzhantel-Hammercurl über Kreuz', 'upper arms', 'biceps', 'dumbbell', 'Stand up straight with a dumbbell in each hand, palms facing your body. Keep your elbows close to your torso and your upper arms stationary. Exhale and curl the weights while contracting your biceps, bringing the dumbbells across your body towards your opposite shoulder. Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly begin to lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', NULL, 'forearms', '["forearms"]', '["Stand up straight with a dumbbell in each hand, palms facing your body.","Keep your elbows close to your torso and your upper arms stationary.","Exhale and curl the weights while contracting your biceps, bringing the dumbbells across your body towards your opposite shoulder.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."]', '["Stehe aufrecht, in jeder Hand eine Kurzhantel, Handflächen zum Körper.","Halte die Ellbogen nah am Körper und die Oberarme ruhig.","Atme aus und beuge die Arme, während du den Bizeps anspannst, führe die Kurzhanteln über den Körper Richtung gegenüberliegende Schulter.","Hebe die Kurzhanteln weiter, bis der Bizeps vollständig angespannt ist und die Kurzhanteln auf Schulterhöhe sind.","Halte die kontrahierte Position kurz und spanne dabei den Bizeps an.","Atme ein und senke die Kurzhanteln langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0298.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0298.gif', 1784612222128, 1784612222128, 0),
  ('62b6ac76-4316-57fe-a81a-8454dd21e02d', NULL, 'Dumbbell Cross Body Hammer Curl V. 2', 'Kurzhantel-Hammercurl über Kreuz V. 2', 'upper arms', 'biceps', 'dumbbell', 'Stand up straight with a dumbbell in each hand, palms facing your body. Keep your elbows close to your torso and your upper arms stationary. Exhale and curl the weights while contracting your biceps, bringing the dumbbells as close to your opposite shoulder as possible. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly begin to lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', NULL, 'forearms', '["forearms"]', '["Stand up straight with a dumbbell in each hand, palms facing your body.","Keep your elbows close to your torso and your upper arms stationary.","Exhale and curl the weights while contracting your biceps, bringing the dumbbells as close to your opposite shoulder as possible.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."]', '["Stehe aufrecht, in jeder Hand eine Kurzhantel, Handflächen zum Körper.","Halte die Ellbogen nah am Körper und die Oberarme ruhig.","Atme aus und beuge die Arme, während du den Bizeps anspannst, führe die Kurzhanteln so nah wie möglich an die gegenüberliegende Schulter.","Halte die kontrahierte Position kurz und spanne dabei den Bizeps an.","Atme ein und senke die Kurzhanteln langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1657.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1657.gif', 1784612222128, 1784612222128, 0),
  ('fadfb3d0-3879-531e-a58c-e1650d5e2dc9', NULL, 'Dumbbell Cuban Press', 'Kurzhantel-Cuban Press', 'shoulders', 'delts', 'dumbbell', 'Stand with your feet shoulder-width apart, holding a dumbbell in each hand at shoulder height with your palms facing down. Keeping your core engaged and your elbows slightly bent, press the dumbbells up and overhead until your arms are fully extended. Rotate your wrists so that your palms are facing forward. Slowly lower the dumbbells back to the starting position, rotating your wrists back to the starting position as you do so. Repeat for the desired number of repetitions.', NULL, 'triceps', '["triceps","upper back"]', '["Stand with your feet shoulder-width apart, holding a dumbbell in each hand at shoulder height with your palms facing down.","Keeping your core engaged and your elbows slightly bent, press the dumbbells up and overhead until your arms are fully extended.","Rotate your wrists so that your palms are facing forward.","Slowly lower the dumbbells back to the starting position, rotating your wrists back to the starting position as you do so.","Repeat for the desired number of repetitions."]', '["Stehe mit schulterbreiten Füssen, in jeder Hand eine Kurzhantel auf Schulterhöhe, Handflächen nach unten.","Spanne die Körpermitte an, halte die Ellbogen leicht gebeugt und drücke die Kurzhanteln nach oben über den Kopf, bis die Arme vollständig gestreckt sind.","Drehe die Handgelenke, sodass die Handflächen nach vorne zeigen.","Senke die Kurzhanteln langsam zurück in die Ausgangsposition ab und drehe dabei die Handgelenke zurück in die Ausgangsstellung.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0299.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0299.gif', 1784612222128, 1784612222128, 0),
  ('7ef0bbdb-6c8c-5276-8009-2b4a812c6adf', NULL, 'Dumbbell Cuban Press V. 2', 'Kurzhantel-Cuban Press V. 2', 'shoulders', 'delts', 'dumbbell', 'Stand with your feet shoulder-width apart, holding a dumbbell in each hand at shoulder height with your palms facing down. Keeping your core engaged and your back straight, press the dumbbells straight up overhead until your arms are fully extended. Rotate your wrists so that your palms are facing forward. Lower the dumbbells back down to shoulder height, rotating your wrists back to the starting position. Repeat for the desired number of repetitions.', NULL, 'triceps', '["triceps","upper back"]', '["Stand with your feet shoulder-width apart, holding a dumbbell in each hand at shoulder height with your palms facing down.","Keeping your core engaged and your back straight, press the dumbbells straight up overhead until your arms are fully extended.","Rotate your wrists so that your palms are facing forward.","Lower the dumbbells back down to shoulder height, rotating your wrists back to the starting position.","Repeat for the desired number of repetitions."]', '["Stehe mit schulterbreiten Füssen, in jeder Hand eine Kurzhantel auf Schulterhöhe, Handflächen nach unten.","Spanne die Körpermitte an, halte den Rücken gerade und drücke die Kurzhanteln gerade nach oben über den Kopf, bis die Arme vollständig gestreckt sind.","Drehe die Handgelenke, sodass die Handflächen nach vorne zeigen.","Senke die Kurzhanteln zurück auf Schulterhöhe ab und drehe dabei die Handgelenke zurück in die Ausgangsstellung.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/2136.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/2136.gif', 1784612222128, 1784612222128, 0),
  ('0531187b-4018-5860-9f3a-73291775bef5', NULL, 'Dumbbell Deadlift', 'Kurzhantel-Kreuzheben', 'upper legs', 'glutes', 'dumbbell', 'Stand with your feet shoulder-width apart, toes pointing forward. Hold a dumbbell in each hand, palms facing your body, arms extended downwards. Bend at your hips and knees, lowering the dumbbells towards the ground while keeping your back straight. Push through your heels and extend your hips and knees, lifting the dumbbells back up to the starting position. Repeat for the desired number of repetitions.', NULL, 'hamstrings', '["hamstrings","lower back"]', '["Stand with your feet shoulder-width apart, toes pointing forward.","Hold a dumbbell in each hand, palms facing your body, arms extended downwards.","Bend at your hips and knees, lowering the dumbbells towards the ground while keeping your back straight.","Push through your heels and extend your hips and knees, lifting the dumbbells back up to the starting position.","Repeat for the desired number of repetitions."]', '["Stehe mit schulterbreiten Füssen, Zehen zeigen nach vorne.","Halte in jeder Hand eine Kurzhantel, Handflächen zum Körper, Arme nach unten gestreckt.","Beuge Hüfte und Knie und senke die Kurzhanteln Richtung Boden ab, der Rücken bleibt gerade.","Drücke dich durch die Fersen ab und strecke Hüfte und Knie, um die Kurzhanteln zurück in die Ausgangsposition zu heben.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0300.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0300.gif', 1784612222128, 1784612222128, 0),
  ('2596c68a-b75d-582d-bba7-39559dac1f7e', NULL, 'Dumbbell Decline Bench Press', 'Kurzhantel-Bankdrücken auf der Negativbank', 'chest', 'pectorals', 'dumbbell', 'Lie down on a decline bench with your feet secured and your head lower than your hips. Hold a dumbbell in each hand and extend your arms straight up above your chest, palms facing forward. Lower the dumbbells slowly to the sides of your chest, keeping your elbows at a 90-degree angle. Push the dumbbells back up to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', NULL, 'triceps', '["triceps","shoulders"]', '["Lie down on a decline bench with your feet secured and your head lower than your hips.","Hold a dumbbell in each hand and extend your arms straight up above your chest, palms facing forward.","Lower the dumbbells slowly to the sides of your chest, keeping your elbows at a 90-degree angle.","Push the dumbbells back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."]', '["Lege dich auf eine Negativbank, die Füsse gesichert, der Kopf tiefer als die Hüfte.","Halte in jeder Hand eine Kurzhantel und strecke die Arme gerade über der Brust nach oben, Handflächen nach vorne.","Senke die Kurzhanteln langsam an die Seiten der Brust ab, die Ellbogen bilden dabei einen 90-Grad-Winkel.","Drücke die Kurzhanteln zurück in die Ausgangsposition, die Arme vollständig gestreckt.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0301.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0301.gif', 1784612222128, 1784612222128, 0),
  ('7143b2e7-0dc1-5235-9b9c-35b25a1893c8', NULL, 'Dumbbell Decline Fly', 'Kurzhantel-Fliegende auf der Negativbank', 'chest', 'pectorals', 'dumbbell', 'Lie on a decline bench with your feet secured and your head lower than your hips. Hold a dumbbell in each hand with your palms facing each other and your arms extended above your chest. Lower the dumbbells out to the sides in a wide arc until you feel a stretch in your chest. Pause for a moment, then squeeze your chest muscles to bring the dumbbells back to the starting position. Repeat for the desired number of repetitions.', NULL, 'shoulders', '["shoulders"]', '["Lie on a decline bench with your feet secured and your head lower than your hips.","Hold a dumbbell in each hand with your palms facing each other and your arms extended above your chest.","Lower the dumbbells out to the sides in a wide arc until you feel a stretch in your chest.","Pause for a moment, then squeeze your chest muscles to bring the dumbbells back to the starting position.","Repeat for the desired number of repetitions."]', '["Lege dich auf eine Negativbank, die Füsse gesichert, der Kopf tiefer als die Hüfte.","Halte in jeder Hand eine Kurzhantel, Handflächen zueinander, Arme über der Brust gestreckt.","Senke die Kurzhanteln in einer weiten Bogenbewegung seitlich ab, bis du eine Dehnung in der Brust spürst.","Halte kurz inne und spanne dann die Brustmuskeln an, um die Kurzhanteln zurück in die Ausgangsposition zu bringen.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0302.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0302.gif', 1784612222128, 1784612222128, 0),
  ('d951daea-c6a4-5e20-9c83-231b174bdb2e', NULL, 'Dumbbell Decline Hammer Press', 'Kurzhantel-Negativbank-Hammerdrücken', 'chest', 'pectorals', 'dumbbell', 'Lie on a decline bench with your feet secured and your head lower than your hips. Hold a dumbbell in each hand with your palms facing each other and your arms extended above your chest. Lower the dumbbells to the sides of your chest, keeping your elbows slightly bent. Press the dumbbells back up to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', NULL, 'triceps', '["triceps","shoulders"]', '["Lie on a decline bench with your feet secured and your head lower than your hips.","Hold a dumbbell in each hand with your palms facing each other and your arms extended above your chest.","Lower the dumbbells to the sides of your chest, keeping your elbows slightly bent.","Press the dumbbells back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."]', '["Lege dich auf eine Negativbank, die Füsse gesichert, der Kopf tiefer als die Hüfte.","Halte in jeder Hand eine Kurzhantel, Handflächen zueinander, Arme über der Brust gestreckt.","Senke die Kurzhanteln an die Seiten der Brust ab, die Ellbogen bleiben leicht gebeugt.","Drücke die Kurzhanteln zurück in die Ausgangsposition, die Arme vollständig gestreckt.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0303.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0303.gif', 1784612222128, 1784612222128, 0),
  ('dbc603a7-f7b0-5eeb-b12d-f606c9b5eb83', NULL, 'Dumbbell Decline One Arm Fly', 'Negativbank-Fliegende mit Kurzhanteln, einarmig', 'chest', 'pectorals', 'dumbbell', 'Lie down on a decline bench with a dumbbell in one hand, resting it on your thigh. Using your thigh to help raise the dumbbell, lift it up to shoulder width with your palm facing your torso. Rotate your wrist so that the palm of your hand is facing forward. As you breathe in, lower the dumbbell slowly to the side until you feel a stretch in your chest. Exhale and use your chest muscles to bring the dumbbell back up to the starting position. Repeat for the desired number of repetitions, then switch arms.', NULL, 'shoulders', '["shoulders"]', '["Lie down on a decline bench with a dumbbell in one hand, resting it on your thigh.","Using your thigh to help raise the dumbbell, lift it up to shoulder width with your palm facing your torso.","Rotate your wrist so that the palm of your hand is facing forward.","As you breathe in, lower the dumbbell slowly to the side until you feel a stretch in your chest.","Exhale and use your chest muscles to bring the dumbbell back up to the starting position.","Repeat for the desired number of repetitions, then switch arms."]', '["Lege dich auf eine Negativbank, eine Kurzhantel in einer Hand, auf dem Oberschenkel abgestützt.","Nutze den Oberschenkel, um die Kurzhantel auf Schulterbreite zu heben, Handfläche zum Oberkörper.","Drehe das Handgelenk, sodass die Handfläche nach vorne zeigt.","Senke die Kurzhantel beim Einatmen langsam zur Seite ab, bis du eine Dehnung in der Brust spürst.","Atme aus und nutze die Brustmuskeln, um die Kurzhantel zurück in die Ausgangsposition zu bringen.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dann die Seite."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1276.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1276.gif', 1784612222128, 1784612222128, 0);

INSERT OR REPLACE INTO exercises (id, user_id, name, name_de, category, primary_muscle, equipment, instructions_en, instructions_de, muscle_group, secondary_muscles, instruction_steps_en, instruction_steps_de, thumbnail_url, gif_url, created_at, updated_at, deleted) VALUES
  ('3590d8d7-2816-5031-a970-ba1777374654', NULL, 'Dumbbell Decline One Arm Hammer Press', 'Kurzhantel-Negativbank-Hammerdrücken, einarmig', 'upper arms', 'triceps', 'dumbbell', 'Lie on a decline bench with a dumbbell in one hand, resting on your chest. Extend your arm straight up, keeping your elbow slightly bent. Lower the dumbbell down towards your shoulder, keeping your elbow close to your body. Press the dumbbell back up to the starting position. Repeat for the desired number of repetitions, then switch arms.', NULL, 'chest', '["chest","shoulders"]', '["Lie on a decline bench with a dumbbell in one hand, resting on your chest.","Extend your arm straight up, keeping your elbow slightly bent.","Lower the dumbbell down towards your shoulder, keeping your elbow close to your body.","Press the dumbbell back up to the starting position.","Repeat for the desired number of repetitions, then switch arms."]', '["Lege dich auf eine Negativbank, eine Kurzhantel in einer Hand auf der Brust abgestützt.","Strecke den Arm gerade nach oben, der Ellbogen bleibt leicht gebeugt.","Senke die Kurzhantel Richtung Schulter ab, der Ellbogen bleibt nah am Körper.","Drücke die Kurzhantel zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dann die Seite."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1617.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1617.gif', 1784612222128, 1784612222128, 0),
  ('06d1fbe5-3873-51de-a1fd-94a676c57ade', NULL, 'Dumbbell Decline Shrug', 'Kurzhantel-Negativbank-Schulterheben', 'back', 'traps', 'dumbbell', 'Set up a decline bench at a 45-degree angle. Lie face down on the bench with your chest and stomach resting against it. Hold a dumbbell in each hand with your arms fully extended towards the floor. Keeping your arms straight, raise your shoulders towards your ears as high as possible. Hold the contraction for a moment, then slowly lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', NULL, 'shoulders', '["shoulders","rhomboids"]', '["Set up a decline bench at a 45-degree angle.","Lie face down on the bench with your chest and stomach resting against it.","Hold a dumbbell in each hand with your arms fully extended towards the floor.","Keeping your arms straight, raise your shoulders towards your ears as high as possible.","Hold the contraction for a moment, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle eine Negativbank im 45-Grad-Winkel auf.","Lege dich bäuchlings auf die Bank, Brust und Bauch liegen auf.","Halte in jeder Hand eine Kurzhantel, die Arme vollständig Richtung Boden gestreckt.","Halte die Arme gestreckt und ziehe die Schultern so hoch wie möglich Richtung Ohren.","Halte die Anspannung kurz und senke die Kurzhanteln dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0305.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0305.gif', 1784612222128, 1784612222128, 0),
  ('cec38992-da50-561c-860e-0e64fd78531b', NULL, 'Dumbbell Decline Shrug V. 2', 'Kurzhantel-Negativbank-Schulterheben (Variante 2)', 'back', 'traps', 'dumbbell', 'Set up a decline bench at a 45-degree angle. Lie face down on the bench with your chest and stomach resting on it. Hold a dumbbell in each hand with your palms facing each other and your arms fully extended. Keeping your arms straight, raise your shoulders as high as possible while squeezing your shoulder blades together. Hold the contraction for a brief pause, then lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', NULL, 'shoulders', '["shoulders","rhomboids"]', '["Set up a decline bench at a 45-degree angle.","Lie face down on the bench with your chest and stomach resting on it.","Hold a dumbbell in each hand with your palms facing each other and your arms fully extended.","Keeping your arms straight, raise your shoulders as high as possible while squeezing your shoulder blades together.","Hold the contraction for a brief pause, then lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle eine Negativbank im 45-Grad-Winkel auf.","Lege dich bäuchlings auf die Bank, Brust und Bauch liegen auf.","Halte in jeder Hand eine Kurzhantel, Handflächen zueinander, Arme vollständig gestreckt.","Halte die Arme gestreckt und ziehe die Schultern so hoch wie möglich, während du die Schulterblätter zusammenziehst.","Halte die Anspannung kurz und senke die Kurzhanteln dann zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0304.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0304.gif', 1784612222128, 1784612222128, 0),
  ('f6c96d0e-c999-5f3b-8a24-2575dc8ae2d7', NULL, 'Dumbbell Decline Triceps Extension', 'Kurzhantel-Negativbank-Trizeps-Extension', 'upper arms', 'triceps', 'dumbbell', 'Lie on a decline bench with your head lower than your feet and hold a dumbbell in each hand, palms facing each other. Extend your arms fully, keeping your elbows close to your head. Lower the dumbbells slowly behind your head, bending your elbows. Pause for a moment, then raise the dumbbells back to the starting position. Repeat for the desired number of repetitions.', NULL, 'shoulders', '["shoulders"]', '["Lie on a decline bench with your head lower than your feet and hold a dumbbell in each hand, palms facing each other.","Extend your arms fully, keeping your elbows close to your head.","Lower the dumbbells slowly behind your head, bending your elbows.","Pause for a moment, then raise the dumbbells back to the starting position.","Repeat for the desired number of repetitions."]', '["Lege dich auf eine Negativbank, der Kopf tiefer als die Füsse, in jeder Hand eine Kurzhantel, Handflächen zueinander.","Strecke die Arme vollständig, die Ellbogen bleiben nah am Kopf.","Senke die Kurzhanteln langsam hinter den Kopf ab, indem du die Ellbogen beugst.","Halte kurz inne und hebe die Kurzhanteln dann zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0306.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0306.gif', 1784612222128, 1784612222128, 0),
  ('58158b6b-aac5-5426-b47d-fa30e1d2deaf', NULL, 'Dumbbell Decline Twist Fly', 'Negativbank-Drehfliegende mit Kurzhanteln', 'chest', 'pectorals', 'dumbbell', 'Lie down on a decline bench with your head lower than your hips. Hold a dumbbell in each hand with your palms facing each other and your arms extended straight up over your chest. Lower the dumbbells out to the sides in a wide arc until you feel a stretch in your chest. As you lower the dumbbells, twist your wrists so that your palms face forward at the bottom of the movement. Reverse the motion and bring the dumbbells back up to the starting position, squeezing your chest muscles at the top. Repeat for the desired number of repetitions.', NULL, 'shoulders', '["shoulders","triceps"]', '["Lie down on a decline bench with your head lower than your hips.","Hold a dumbbell in each hand with your palms facing each other and your arms extended straight up over your chest.","Lower the dumbbells out to the sides in a wide arc until you feel a stretch in your chest.","As you lower the dumbbells, twist your wrists so that your palms face forward at the bottom of the movement.","Reverse the motion and bring the dumbbells back up to the starting position, squeezing your chest muscles at the top.","Repeat for the desired number of repetitions."]', '["Lege dich auf eine Negativbank, der Kopf tiefer als die Hüfte.","Halte in jeder Hand eine Kurzhantel, Handflächen zueinander, Arme gerade über der Brust gestreckt.","Senke die Kurzhanteln in einer weiten Bogenbewegung seitlich ab, bis du eine Dehnung in der Brust spürst.","Drehe beim Absenken die Handgelenke, sodass die Handflächen am unteren Punkt nach vorne zeigen.","Kehre die Bewegung um und führe die Kurzhanteln zurück in die Ausgangsposition, spanne dabei am oberen Punkt die Brustmuskeln an.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0307.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0307.gif', 1784612222128, 1784612222128, 0),
  ('9d0dd3a1-f2b6-5378-a298-370e98d02ae6', NULL, 'Dumbbell Finger Curls', 'Kurzhantel-Fingercurl', 'lower arms', 'forearms', 'dumbbell', 'Sit on a bench or chair with your feet flat on the ground and your back straight. Hold a dumbbell in one hand with an underhand grip, resting your forearm on your thigh, palm facing up. Allow the dumbbell to roll down to your fingertips, then curl it back up by flexing your fingers. Repeat for the desired number of repetitions, then switch to the other hand.', NULL, 'wrist flexors', '["wrist flexors","wrist extensors"]', '["Sit on a bench or chair with your feet flat on the ground and your back straight.","Hold a dumbbell in one hand with an underhand grip, resting your forearm on your thigh, palm facing up.","Allow the dumbbell to roll down to your fingertips, then curl it back up by flexing your fingers.","Repeat for the desired number of repetitions, then switch to the other hand."]', '["Setze dich auf eine Bank oder einen Stuhl, Füsse flach am Boden, Rücken gerade.","Halte eine Kurzhantel in einer Hand im Untergriff, der Unterarm liegt auf dem Oberschenkel, Handfläche nach oben.","Lass die Kurzhantel bis zu den Fingerspitzen abrollen und rolle sie dann zurück, indem du die Finger beugst.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dann die Hand."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1437.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1437.gif', 1784612222128, 1784612222128, 0),
  ('8762c51c-241c-5867-8cbc-9c7b649db290', NULL, 'Dumbbell Fly', 'Fliegende mit Kurzhanteln', 'chest', 'pectorals', 'dumbbell', 'Lie flat on a bench with a dumbbell in each hand, palms facing each other. Extend your arms straight up over your chest, with a slight bend in your elbows. Keeping a slight bend in your elbows, lower your arms out to the sides in a wide arc until you feel a stretch in your chest. Pause for a moment, then reverse the movement and bring the dumbbells back up to the starting position. Repeat for the desired number of repetitions.', NULL, 'shoulders', '["shoulders"]', '["Lie flat on a bench with a dumbbell in each hand, palms facing each other.","Extend your arms straight up over your chest, with a slight bend in your elbows.","Keeping a slight bend in your elbows, lower your arms out to the sides in a wide arc until you feel a stretch in your chest.","Pause for a moment, then reverse the movement and bring the dumbbells back up to the starting position.","Repeat for the desired number of repetitions."]', '["Lege dich flach auf eine Bank, in jeder Hand eine Kurzhantel, Handflächen zueinander.","Strecke die Arme gerade über der Brust nach oben, die Ellbogen leicht gebeugt.","Halte die leichte Ellbogenbeugung und senke die Arme in einer weiten Bogenbewegung seitlich ab, bis du eine Dehnung in der Brust spürst.","Halte kurz inne, kehre die Bewegung dann um und führe die Kurzhanteln zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0308.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0308.gif', 1784612222128, 1784612222128, 0),
  ('a7276d4f-763c-5ec7-b09a-b496e5699a6b', NULL, 'Dumbbell Fly on Exercise Ball', 'Fliegende mit Kurzhanteln auf dem Gymnastikball', 'chest', 'pectorals', 'dumbbell', 'Sit on an exercise ball and hold a dumbbell in each hand. Walk your feet forward and roll your body down until your head, neck, and upper back are supported by the ball. Extend your arms straight up above your chest, palms facing each other. Bend your elbows slightly and lower your arms out to the sides in a wide arc until you feel a stretch in your chest. Pause for a moment, then reverse the movement and squeeze your chest muscles as you bring the dumbbells back to the starting position. Repeat for the desired number of repetitions.', NULL, 'shoulders', '["shoulders","triceps"]', '["Sit on an exercise ball and hold a dumbbell in each hand.","Walk your feet forward and roll your body down until your head, neck, and upper back are supported by the ball.","Extend your arms straight up above your chest, palms facing each other.","Bend your elbows slightly and lower your arms out to the sides in a wide arc until you feel a stretch in your chest.","Pause for a moment, then reverse the movement and squeeze your chest muscles as you bring the dumbbells back to the starting position.","Repeat for the desired number of repetitions."]', '["Setze dich auf einen Gymnastikball und halte in jeder Hand eine Kurzhantel.","Gehe mit den Füssen nach vorne und rolle den Körper ab, bis Kopf, Nacken und oberer Rücken vom Ball gestützt werden.","Strecke die Arme gerade über die Brust, Handflächen zueinander.","Beuge die Ellbogen leicht und senke die Arme in einer weiten Bogenbewegung seitlich ab, bis du eine Dehnung in der Brust spürst.","Halte kurz inne, kehre die Bewegung um und spanne die Brustmuskeln an, während du die Kurzhanteln zurück in die Ausgangsposition führst.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1277.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1277.gif', 1784612222128, 1784612222128, 0),
  ('ebc55772-c6f5-570a-b5b5-caa8a2915e54', NULL, 'Dumbbell Forward Lunge Triceps Extension', 'Kurzhantel-Ausfallschritt mit Trizeps-Extension', 'upper arms', 'triceps', 'dumbbell', 'Stand with your feet shoulder-width apart, holding a dumbbell in each hand. Take a step forward with your right foot, lowering your body into a lunge position. Keep your back straight and your chest up. Extend your arms straight overhead, keeping your elbows close to your ears. Lower the dumbbells behind your head by bending your elbows. Pause for a moment, then straighten your arms to return to the starting position. Repeat the movement for the desired number of repetitions, then switch legs and repeat.', NULL, 'shoulders', '["shoulders","core"]', '["Stand with your feet shoulder-width apart, holding a dumbbell in each hand.","Take a step forward with your right foot, lowering your body into a lunge position.","Keep your back straight and your chest up.","Extend your arms straight overhead, keeping your elbows close to your ears.","Lower the dumbbells behind your head by bending your elbows.","Pause for a moment, then straighten your arms to return to the starting position.","Repeat the movement for the desired number of repetitions, then switch legs and repeat."]', '["Stehe mit schulterbreiten Füssen, in jeder Hand eine Kurzhantel.","Trete mit dem rechten Fuss nach vorne und senke den Körper in eine Ausfallschritt-Position ab.","Halte den Rücken gerade und die Brust raus.","Strecke die Arme gerade über den Kopf, die Ellbogen bleiben nah an den Ohren.","Senke die Kurzhanteln hinter den Kopf ab, indem du die Ellbogen beugst.","Halte kurz inne und strecke die Arme dann, um in die Ausgangsposition zurückzukehren.","Wiederhole die Bewegung für die gewünschte Anzahl Wiederholungen und wechsle dann das Bein."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1732.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1732.gif', 1784612222128, 1784612222128, 0),
  ('b3679d45-84cb-550a-a91f-6dc3eeb349a5', NULL, 'Dumbbell Front Raise', 'Kurzhantel-Frontheben', 'shoulders', 'delts', 'dumbbell', 'Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing your thighs. Keeping your arms straight, exhale and lift the dumbbells in front of you until they are at shoulder level. Pause for a moment at the top, then inhale and slowly lower the dumbbells back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","trapezius"]', '["Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing your thighs.","Keeping your arms straight, exhale and lift the dumbbells in front of you until they are at shoulder level.","Pause for a moment at the top, then inhale and slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."]', '["Stehe mit schulterbreiten Füssen, in jeder Hand eine Kurzhantel, Handflächen zu den Oberschenkeln.","Halte die Arme gestreckt, atme aus und hebe die Kurzhanteln vor dir an, bis sie auf Schulterhöhe sind.","Halte am oberen Punkt kurz inne, atme dann ein und senke die Kurzhanteln langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0310.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0310.gif', 1784612222128, 1784612222128, 0),
  ('bb31e8c3-e254-5487-a707-101672adec60', NULL, 'Dumbbell Front Raise V. 2', 'Kurzhantel-Frontheben (Variante 2)', 'shoulders', 'delts', 'dumbbell', 'Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing your thighs. Keep your back straight and engage your core. Slowly lift the dumbbells in front of you, with your arms straight, until they are at shoulder level. Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'trapezius', '["trapezius","biceps"]', '["Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing your thighs.","Keep your back straight and engage your core.","Slowly lift the dumbbells in front of you, with your arms straight, until they are at shoulder level.","Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."]', '["Stehe mit schulterbreiten Füssen, in jeder Hand eine Kurzhantel, Handflächen zu den Oberschenkeln.","Halte den Rücken gerade und spanne die Körpermitte an.","Hebe die Kurzhanteln langsam vor dir an, die Arme bleiben gestreckt, bis sie auf Schulterhöhe sind.","Halte am oberen Punkt kurz inne und senke die Kurzhanteln dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0309.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0309.gif', 1784612222128, 1784612222128, 0),
  ('d298364b-e854-5599-a8b7-ab4a34fb3f59', NULL, 'Dumbbell Full Can Lateral Raise', 'Kurzhantel-Full-Can-Seitheben', 'shoulders', 'delts', 'dumbbell', 'Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing your body. Keep your back straight and engage your core. Raise your arms out to the sides, keeping a slight bend in your elbows, until they are parallel to the ground. Pause for a moment at the top, then slowly lower your arms back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'traps', '["traps","rotator cuff"]', '["Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing your body.","Keep your back straight and engage your core.","Raise your arms out to the sides, keeping a slight bend in your elbows, until they are parallel to the ground.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."]', '["Stehe mit schulterbreiten Füssen, in jeder Hand eine Kurzhantel, Handflächen zum Körper.","Halte den Rücken gerade und spanne die Körpermitte an.","Hebe die Arme seitlich an, die Ellbogen bleiben leicht gebeugt, bis sie parallel zum Boden sind.","Halte am oberen Punkt kurz inne und senke die Arme dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0311.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0311.gif', 1784612222128, 1784612222128, 0),
  ('2053401e-fb94-5bd5-b5de-15c538792ea3', NULL, 'Dumbbell Goblet Squat', 'Kurzhantel-Goblet-Squat', 'upper legs', 'quads', 'dumbbell', 'Stand with your feet shoulder-width apart, holding a dumbbell vertically against your chest with both hands. Keeping your chest up and core engaged, lower your body down into a squat position by pushing your hips back and bending your knees. Continue lowering until your thighs are parallel to the ground, or as low as you can comfortably go. Pause for a moment at the bottom, then push through your heels to return to the starting position. Repeat for the desired number of repetitions.', NULL, 'glutes', '["glutes","hamstrings","calves"]', '["Stand with your feet shoulder-width apart, holding a dumbbell vertically against your chest with both hands.","Keeping your chest up and core engaged, lower your body down into a squat position by pushing your hips back and bending your knees.","Continue lowering until your thighs are parallel to the ground, or as low as you can comfortably go.","Pause for a moment at the bottom, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."]', '["Stehe mit schulterbreiten Füssen, halte eine Kurzhantel senkrecht mit beiden Händen vor der Brust.","Halte die Brust raus und die Körpermitte angespannt, senke den Körper in eine Kniebeuge ab, indem du die Hüfte nach hinten schiebst und die Knie beugst.","Senke weiter ab, bis die Oberschenkel parallel zum Boden sind, oder so tief wie du bequem kannst.","Halte am unteren Punkt kurz inne und drücke dich dann durch die Fersen zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1760.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1760.gif', 1784612222128, 1784612222128, 0),
  ('dd5ca231-f2ef-5cad-aeeb-91b5a424f52a', NULL, 'Dumbbell Hammer Curl', 'Kurzhantel-Hammercurl', 'upper arms', 'biceps', 'dumbbell', 'Stand up straight with a dumbbell in each hand, palms facing your torso. Keep your elbows close to your torso and rotate the palms of your hands until they are facing forward. This will be your starting position. Now, keeping the upper arms stationary, exhale and curl the weights while contracting your biceps. Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Then, inhale and slowly begin to lower the dumbbells back to the starting position. Repeat for the recommended amount of repetitions.', NULL, 'forearms', '["forearms"]', '["Stand up straight with a dumbbell in each hand, palms facing your torso.","Keep your elbows close to your torso and rotate the palms of your hands until they are facing forward.","This will be your starting position.","Now, keeping the upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Then, inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the recommended amount of repetitions."]', '["Stehe aufrecht, in jeder Hand eine Kurzhantel, Handflächen zum Körper.","Halte die Ellbogen nah am Körper und drehe die Handflächen, bis sie nach vorne zeigen.","Das ist deine Ausgangsposition.","Halte nun die Oberarme ruhig, atme aus und beuge die Arme, während du den Bizeps anspannst.","Hebe die Kurzhanteln weiter, bis der Bizeps vollständig angespannt ist und die Kurzhanteln auf Schulterhöhe sind.","Halte die kontrahierte Position kurz und spanne dabei den Bizeps an.","Atme dann ein und senke die Kurzhanteln langsam zurück in die Ausgangsposition ab.","Wiederhole für die empfohlene Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0313.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0313.gif', 1784612222128, 1784612222128, 0),
  ('8da29c49-1a3c-5c8c-b2cc-ddd64dc68187', NULL, 'Dumbbell Hammer Curl on Exercise Ball', 'Kurzhantel-Hammercurl auf dem Gymnastikball', 'upper arms', 'biceps', 'dumbbell', 'Sit on an exercise ball with your feet flat on the ground and your back straight. Hold a dumbbell in each hand with your palms facing your body and your arms fully extended. Keeping your upper arms stationary, exhale and curl the dumbbells while contracting your biceps. Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly begin to lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', NULL, 'forearms', '["forearms"]', '["Sit on an exercise ball with your feet flat on the ground and your back straight.","Hold a dumbbell in each hand with your palms facing your body and your arms fully extended.","Keeping your upper arms stationary, exhale and curl the dumbbells while contracting your biceps.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."]', '["Setze dich auf einen Gymnastikball, Füsse flach am Boden, Rücken gerade.","Halte in jeder Hand eine Kurzhantel, Handflächen zum Körper, Arme vollständig gestreckt.","Halte die Oberarme ruhig, atme aus und beuge die Kurzhanteln, während du den Bizeps anspannst.","Hebe die Kurzhanteln weiter, bis der Bizeps vollständig angespannt ist und die Kurzhanteln auf Schulterhöhe sind.","Halte die kontrahierte Position kurz und spanne dabei den Bizeps an.","Atme ein und senke die Kurzhanteln langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1659.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1659.gif', 1784612222128, 1784612222128, 0),
  ('79b5ed25-40f9-5f02-b649-dca74b74c6ff', NULL, 'Dumbbell Hammer Curl V. 2', 'Kurzhantel-Hammercurl (Variante 2)', 'upper arms', 'biceps', 'dumbbell', 'Stand up straight with a dumbbell in each hand, palms facing your torso. Keep your elbows close to your torso and rotate the palms of your hands until they are facing forward. This will be your starting position. Now, keeping the upper arms stationary, exhale and curl the weights while contracting your biceps. Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Then, inhale and slowly begin to lower the dumbbells back to the starting position. Repeat for the recommended amount of repetitions.', NULL, 'forearms', '["forearms"]', '["Stand up straight with a dumbbell in each hand, palms facing your torso.","Keep your elbows close to your torso and rotate the palms of your hands until they are facing forward.","This will be your starting position.","Now, keeping the upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Then, inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the recommended amount of repetitions."]', '["Stehe aufrecht, in jeder Hand eine Kurzhantel, Handflächen zum Körper.","Halte die Ellbogen nah am Körper und drehe die Handflächen, bis sie nach vorne zeigen.","Das ist deine Ausgangsposition.","Halte nun die Oberarme ruhig, atme aus und beuge die Arme, während du den Bizeps anspannst.","Hebe die Kurzhanteln weiter, bis der Bizeps vollständig angespannt ist und die Kurzhanteln auf Schulterhöhe sind.","Halte die kontrahierte Position kurz und spanne dabei den Bizeps an.","Atme dann ein und senke die Kurzhanteln langsam zurück in die Ausgangsposition ab.","Wiederhole für die empfohlene Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0312.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0312.gif', 1784612222128, 1784612222128, 0),
  ('fb2cb641-a4de-5cda-bbbc-c134d9271f6b', NULL, 'Dumbbell Hammer Curls (With Arm Blaster)', 'Kurzhantel-Hammercurls mit Armblaster', 'upper arms', 'biceps', 'dumbbell', 'Stand up straight with a dumbbell in each hand, palms facing your torso. Keep your elbows close to your torso and rotate the palms of your hands until they are facing forward. This will be your starting position. Now, while holding your upper arm stationary, exhale and curl the weights while contracting your biceps. Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Then, inhale and slowly begin to lower the dumbbells back to the starting position. Repeat for the recommended amount of repetitions.', NULL, 'forearms', '["forearms"]', '["Stand up straight with a dumbbell in each hand, palms facing your torso.","Keep your elbows close to your torso and rotate the palms of your hands until they are facing forward.","This will be your starting position.","Now, while holding your upper arm stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Then, inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the recommended amount of repetitions."]', '["Stehe aufrecht, in jeder Hand eine Kurzhantel, Handflächen zum Körper.","Halte die Ellbogen nah am Körper und drehe die Handflächen, bis sie nach vorne zeigen.","Das ist deine Ausgangsposition.","Halte nun den Oberarm ruhig, atme aus und beuge die Arme, während du den Bizeps anspannst.","Hebe die Kurzhanteln weiter, bis der Bizeps vollständig angespannt ist und die Kurzhanteln auf Schulterhöhe sind.","Halte die kontrahierte Position kurz und spanne dabei den Bizeps an.","Atme dann ein und senke die Kurzhanteln langsam zurück in die Ausgangsposition ab.","Wiederhole für die empfohlene Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/2402.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/2402.gif', 1784612222128, 1784612222128, 0),
  ('8a210213-08e2-568c-b5c7-5333bbe52fc6', NULL, 'Dumbbell High Curl', 'Kurzhantel-Curl mit erhobenen Armen', 'upper arms', 'biceps', 'dumbbell', 'Stand up straight with a dumbbell in each hand, palms facing forward. Keep your upper arms stationary and curl the dumbbells as high as possible while contracting your biceps. Pause for a moment at the top, then slowly lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', NULL, 'forearms', '["forearms"]', '["Stand up straight with a dumbbell in each hand, palms facing forward.","Keep your upper arms stationary and curl the dumbbells as high as possible while contracting your biceps.","Pause for a moment at the top, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."]', '["Stehe aufrecht, in jeder Hand eine Kurzhantel, Handflächen nach vorne.","Halte die Oberarme ruhig und ziehe die Kurzhanteln so hoch wie möglich, während du den Bizeps anspannst.","Halte am oberen Punkt kurz inne und senke die Kurzhanteln dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1664.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1664.gif', 1784612222128, 1784612222128, 0),
  ('7c94995f-a51a-5338-9999-69aa9f442adc', NULL, 'Dumbbell Incline Alternate Press', 'Kurzhantel-Schrägbank-Drücken, wechselseitig', 'chest', 'pectorals', 'dumbbell', 'Sit on an incline bench with a dumbbell in each hand, resting on your thighs. Lean back on the bench and use your thighs to help raise the dumbbells to shoulder height, palms facing forward. Once at shoulder height, rotate your wrists so that the palms of your hands are facing forward. Push the dumbbells up with your chest and shoulders, extending your arms fully. Lower the dumbbells back down to the starting position, keeping your elbows slightly bent. Repeat for the desired number of repetitions, alternating arms.', NULL, 'shoulders', '["shoulders","triceps"]', '["Sit on an incline bench with a dumbbell in each hand, resting on your thighs.","Lean back on the bench and use your thighs to help raise the dumbbells to shoulder height, palms facing forward.","Once at shoulder height, rotate your wrists so that the palms of your hands are facing forward.","Push the dumbbells up with your chest and shoulders, extending your arms fully.","Lower the dumbbells back down to the starting position, keeping your elbows slightly bent.","Repeat for the desired number of repetitions, alternating arms."]', '["Setze dich auf eine Schrägbank, in jeder Hand eine Kurzhantel, auf den Oberschenkeln abgestützt.","Lehne dich auf der Bank zurück und nutze die Oberschenkel, um die Kurzhanteln auf Schulterhöhe zu heben, Handflächen nach vorne.","Drehe auf Schulterhöhe die Handgelenke, sodass die Handflächen nach vorne zeigen.","Drücke die Kurzhanteln mit Brust und Schultern hoch, die Arme vollständig gestreckt.","Senke die Kurzhanteln zurück in die Ausgangsposition ab, die Ellbogen bleiben leicht gebeugt.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dabei die Seite."]', 'https://ascent-api.sweber.workers.dev/media/exercises/3545.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/3545.gif', 1784612222128, 1784612222128, 0),
  ('e9a59e64-6514-5b96-8fd0-edc6b084c702', NULL, 'Dumbbell Incline Bench Press', 'Kurzhantel-Schrägbank-Bankdrücken', 'chest', 'pectorals', 'dumbbell', 'Set up an incline bench at a 45-degree angle. Sit on the bench with your feet flat on the ground and your back pressed firmly against the bench. Hold a dumbbell in each hand, palms facing forward, and lift them to shoulder height. Slowly lower the dumbbells to the sides of your chest, keeping your elbows at a 90-degree angle. Push the dumbbells back up to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', NULL, 'shoulders', '["shoulders","triceps"]', '["Set up an incline bench at a 45-degree angle.","Sit on the bench with your feet flat on the ground and your back pressed firmly against the bench.","Hold a dumbbell in each hand, palms facing forward, and lift them to shoulder height.","Slowly lower the dumbbells to the sides of your chest, keeping your elbows at a 90-degree angle.","Push the dumbbells back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."]', '["Stelle eine Schrägbank im 45-Grad-Winkel auf.","Setze dich auf die Bank, Füsse flach am Boden, Rücken fest an der Bank.","Halte in jeder Hand eine Kurzhantel, Handflächen nach vorne, und hebe sie auf Schulterhöhe.","Senke die Kurzhanteln langsam an die Seiten der Brust ab, die Ellbogen bilden dabei einen 90-Grad-Winkel.","Drücke die Kurzhanteln zurück in die Ausgangsposition, die Arme vollständig gestreckt.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0314.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0314.gif', 1784612222128, 1784612222128, 0),
  ('800c4b74-0258-5f9d-b6a5-8ceebf59c3a3', NULL, 'Dumbbell Incline Biceps Curl', 'Kurzhantel-Schrägbank-Bizepscurl', 'upper arms', 'biceps', 'dumbbell', 'Sit on an incline bench with a dumbbell in each hand, palms facing forward, and arms fully extended. Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly begin to lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', NULL, 'forearms', '["forearms"]', '["Sit on an incline bench with a dumbbell in each hand, palms facing forward, and arms fully extended.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."]', '["Setze dich auf eine Schrägbank, in jeder Hand eine Kurzhantel, Handflächen nach vorne, Arme vollständig gestreckt.","Halte die Oberarme ruhig, atme aus und beuge die Arme, während du den Bizeps anspannst.","Hebe die Kurzhanteln weiter, bis der Bizeps vollständig angespannt ist und die Kurzhanteln auf Schulterhöhe sind.","Halte die kontrahierte Position kurz und spanne dabei den Bizeps an.","Atme ein und senke die Kurzhanteln langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0315.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0315.gif', 1784612222128, 1784612222128, 0),
  ('82a710dc-2fe9-56e4-9e6c-015628135e09', NULL, 'Dumbbell Incline Press', 'Kurzhantel-Schrägbank-Drücken', 'chest', 'pectorals', 'dumbbell', 'Set up an incline bench at a 45-degree angle. Sit on the bench with your back against the pad and feet flat on the ground. Hold a dumbbell in each hand with an overhand grip, palms facing forward. Start with your arms fully extended, perpendicular to the ground. Lower the dumbbells slowly to the sides of your chest, keeping your elbows at a 90-degree angle. Pause for a moment at the bottom, then push the dumbbells back up to the starting position. Repeat for the desired number of repetitions.', NULL, 'shoulders', '["shoulders","triceps"]', '["Set up an incline bench at a 45-degree angle.","Sit on the bench with your back against the pad and feet flat on the ground.","Hold a dumbbell in each hand with an overhand grip, palms facing forward.","Start with your arms fully extended, perpendicular to the ground.","Lower the dumbbells slowly to the sides of your chest, keeping your elbows at a 90-degree angle.","Pause for a moment at the bottom, then push the dumbbells back up to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle eine Schrägbank im 45-Grad-Winkel auf.","Setze dich auf die Bank, der Rücken am Polster, die Füsse flach am Boden.","Halte in jeder Hand eine Kurzhantel im Obergriff, Handflächen nach vorne.","Beginne mit vollständig gestreckten Armen, senkrecht zum Boden.","Senke die Kurzhanteln langsam an die Seiten der Brust ab, die Ellbogen bilden dabei einen 90-Grad-Winkel.","Halte am unteren Punkt kurz inne und drücke die Kurzhanteln dann zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0316.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0316.gif', 1784612222128, 1784612222128, 0),
  ('456b13e1-8ab7-54b2-9303-c6eecb9bd668', NULL, 'Dumbbell Incline Curl', 'Kurzhantel-Schrägbank-Curl', 'upper arms', 'biceps', 'dumbbell', 'Set an incline bench to a 45-degree angle and sit on it with a dumbbell in each hand, palms facing forward. Rest your upper arms on the incline bench and let your elbows hang down, fully extending your arms. Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly begin to lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', NULL, 'forearms', '["forearms"]', '["Set an incline bench to a 45-degree angle and sit on it with a dumbbell in each hand, palms facing forward.","Rest your upper arms on the incline bench and let your elbows hang down, fully extending your arms.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle eine Schrägbank auf einen 45-Grad-Winkel ein und setze dich mit einer Kurzhantel in jeder Hand darauf, Handflächen nach vorne.","Lege die Oberarme auf die Schrägbank und lass die Ellbogen hängen, die Arme vollständig gestreckt.","Halte die Oberarme ruhig, atme aus und beuge die Arme, während du den Bizeps anspannst.","Hebe die Kurzhanteln weiter, bis der Bizeps vollständig angespannt ist und die Kurzhanteln auf Schulterhöhe sind.","Halte die kontrahierte Position kurz und spanne dabei den Bizeps an.","Atme ein und senke die Kurzhanteln langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0318.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0318.gif', 1784612222128, 1784612222128, 0),
  ('34d87f00-37f7-5023-8f12-9cb0b3d26aa4', NULL, 'Dumbbell Incline Curl V. 2', 'Kurzhantel-Schrägbank-Curl (Variante 2)', 'upper arms', 'biceps', 'dumbbell', 'Sit on an incline bench with a dumbbell in each hand, palms facing forward and arms fully extended. Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly begin to lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', NULL, 'forearms', '["forearms"]', '["Sit on an incline bench with a dumbbell in each hand, palms facing forward and arms fully extended.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."]', '["Setze dich auf eine Schrägbank, in jeder Hand eine Kurzhantel, Handflächen nach vorne, Arme vollständig gestreckt.","Halte die Oberarme ruhig, atme aus und beuge die Arme, während du den Bizeps anspannst.","Hebe die Kurzhanteln weiter, bis der Bizeps vollständig angespannt ist und die Kurzhanteln auf Schulterhöhe sind.","Halte die kontrahierte Position kurz und spanne dabei den Bizeps an.","Atme ein und senke die Kurzhanteln langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0317.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0317.gif', 1784612222128, 1784612222128, 0),
  ('1c263eb5-6ff4-5359-8b38-af3ccfdcf162', NULL, 'Dumbbell Incline Fly', 'Schrägbank-Fliegende mit Kurzhanteln', 'chest', 'pectorals', 'dumbbell', 'Set an incline bench to a 45-degree angle. Sit on the bench with a dumbbell in each hand, palms facing each other. Lie back on the bench and press the dumbbells up to the starting position, directly above your chest. Lower the dumbbells out to the sides in a wide arc until you feel a stretch in your chest. Pause for a moment, then squeeze your chest muscles to bring the dumbbells back up to the starting position. Repeat for the desired number of repetitions.', NULL, 'shoulders', '["shoulders"]', '["Set an incline bench to a 45-degree angle.","Sit on the bench with a dumbbell in each hand, palms facing each other.","Lie back on the bench and press the dumbbells up to the starting position, directly above your chest.","Lower the dumbbells out to the sides in a wide arc until you feel a stretch in your chest.","Pause for a moment, then squeeze your chest muscles to bring the dumbbells back up to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle eine Schrägbank auf einen 45-Grad-Winkel ein.","Setze dich auf die Bank, in jeder Hand eine Kurzhantel, Handflächen zueinander.","Lehne dich auf der Bank zurück und drücke die Kurzhanteln in die Ausgangsposition, direkt über der Brust.","Senke die Kurzhanteln in einer weiten Bogenbewegung seitlich ab, bis du eine Dehnung in der Brust spürst.","Halte kurz inne und spanne dann die Brustmuskeln an, um die Kurzhanteln zurück in die Ausgangsposition zu bringen.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0319.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0319.gif', 1784612222128, 1784612222128, 0),
  ('9b40e2bb-53b9-53de-8be0-613ddf3258ad', NULL, 'Dumbbell Incline Fly on Exercise Ball', 'Schrägbank-Fliegende mit Kurzhanteln auf dem Gymnastikball', 'chest', 'pectorals', 'dumbbell', 'Set up an incline bench at a 45-degree angle. Sit on an exercise ball and roll forward until your upper back is resting on the incline bench. Hold a dumbbell in each hand with your palms facing each other and your arms extended above your chest. Lower the dumbbells out to the sides in a wide arc until you feel a stretch in your chest. Pause for a moment, then squeeze your chest muscles to bring the dumbbells back to the starting position. Repeat for the desired number of repetitions.', NULL, 'shoulders', '["shoulders"]', '["Set up an incline bench at a 45-degree angle.","Sit on an exercise ball and roll forward until your upper back is resting on the incline bench.","Hold a dumbbell in each hand with your palms facing each other and your arms extended above your chest.","Lower the dumbbells out to the sides in a wide arc until you feel a stretch in your chest.","Pause for a moment, then squeeze your chest muscles to bring the dumbbells back to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle eine Schrägbank im 45-Grad-Winkel auf.","Setze dich auf einen Gymnastikball und rolle nach vorne, bis dein oberer Rücken auf der Schrägbank aufliegt.","Halte in jeder Hand eine Kurzhantel, Handflächen zueinander, Arme über der Brust gestreckt.","Senke die Kurzhanteln in einer weiten Bogenbewegung seitlich ab, bis du eine Dehnung in der Brust spürst.","Halte kurz inne und spanne dann die Brustmuskeln an, um die Kurzhanteln zurück in die Ausgangsposition zu bringen.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1278.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1278.gif', 1784612222128, 1784612222128, 0),
  ('9f3e87e3-5864-5806-8b5b-dad5368df081', NULL, 'Dumbbell Incline Hammer Curl', 'Kurzhantel-Schrägbank-Hammercurl', 'upper arms', 'biceps', 'dumbbell', 'Sit on an incline bench with a dumbbell in each hand, palms facing your torso and arms fully extended. Keep your back against the bench and your feet flat on the floor. While keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly begin to lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', NULL, 'forearms', '["forearms"]', '["Sit on an incline bench with a dumbbell in each hand, palms facing your torso and arms fully extended.","Keep your back against the bench and your feet flat on the floor.","While keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."]', '["Setze dich auf eine Schrägbank, in jeder Hand eine Kurzhantel, Handflächen zum Körper, Arme vollständig gestreckt.","Halte den Rücken an der Bank und die Füsse flach am Boden.","Halte die Oberarme ruhig, atme aus und beuge die Arme, während du den Bizeps anspannst.","Hebe die Kurzhanteln weiter, bis der Bizeps vollständig angespannt ist und die Kurzhanteln auf Schulterhöhe sind.","Halte die kontrahierte Position kurz und spanne dabei den Bizeps an.","Atme ein und senke die Kurzhanteln langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0320.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0320.gif', 1784612222128, 1784612222128, 0),
  ('a6b191d4-dc74-5c27-8f25-b865fba0c66d', NULL, 'Dumbbell Incline Hammer Press', 'Kurzhantel-Schrägbank-Hammerdrücken', 'chest', 'pectorals', 'dumbbell', 'Set an incline bench to a 45-degree angle and sit on it with a dumbbell in each hand, resting on your thighs. Lie back on the bench and position the dumbbells at shoulder level with your palms facing each other. Press the dumbbells up and away from your body until your arms are fully extended. Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'shoulders', '["shoulders","triceps"]', '["Set an incline bench to a 45-degree angle and sit on it with a dumbbell in each hand, resting on your thighs.","Lie back on the bench and position the dumbbells at shoulder level with your palms facing each other.","Press the dumbbells up and away from your body until your arms are fully extended.","Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle eine Schrägbank auf einen 45-Grad-Winkel ein und setze dich mit einer Kurzhantel in jeder Hand darauf, auf den Oberschenkeln abgestützt.","Lehne dich auf der Bank zurück und positioniere die Kurzhanteln auf Schulterhöhe, Handflächen zueinander.","Drücke die Kurzhanteln nach oben und vom Körper weg, bis die Arme vollständig gestreckt sind.","Halte am oberen Punkt kurz inne und senke die Kurzhanteln dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0321.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0321.gif', 1784612222128, 1784612222128, 0),
  ('605f0412-a983-5807-86f1-a78eaeae453f', NULL, 'Dumbbell Incline Hammer Press on Exercise Ball', 'Kurzhantel-Schrägbank-Hammerdrücken auf dem Gymnastikball', 'upper arms', 'triceps', 'dumbbell', 'Sit on an exercise ball with a dumbbell in each hand, palms facing each other. Walk your feet forward and roll your body down the ball until your head, neck, and upper back are supported on the ball. Hold the dumbbells at shoulder level, elbows bent and pointing out to the sides. Press the dumbbells up and slightly inward, keeping your palms facing each other. Extend your arms fully, squeezing your triceps at the top of the movement. Slowly lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', NULL, 'chest', '["chest","shoulders"]', '["Sit on an exercise ball with a dumbbell in each hand, palms facing each other.","Walk your feet forward and roll your body down the ball until your head, neck, and upper back are supported on the ball.","Hold the dumbbells at shoulder level, elbows bent and pointing out to the sides.","Press the dumbbells up and slightly inward, keeping your palms facing each other.","Extend your arms fully, squeezing your triceps at the top of the movement.","Slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."]', '["Setze dich auf einen Gymnastikball, in jeder Hand eine Kurzhantel, Handflächen zueinander.","Gehe mit den Füssen nach vorne und rolle den Körper den Ball hinunter, bis Kopf, Nacken und oberer Rücken vom Ball gestützt werden.","Halte die Kurzhanteln auf Schulterhöhe, die Ellbogen gebeugt und seitlich zeigend.","Drücke die Kurzhanteln nach oben und leicht nach innen, die Handflächen bleiben zueinander gerichtet.","Strecke die Arme vollständig und spanne den Trizeps am oberen Punkt an.","Senke die Kurzhanteln langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1618.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1618.gif', 1784612222128, 1784612222128, 0),
  ('31fb2c62-f7dc-5598-b6e8-6ca2901f2970', NULL, 'Dumbbell Incline Inner Biceps Curl', 'Kurzhantel-Schrägbank-Bizepscurl, innen', 'upper arms', 'biceps', 'dumbbell', 'Sit on an incline bench with a dumbbell in each hand, palms facing each other. Rest your upper arms on the bench, allowing your elbows to hang down and your palms to face forward. Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly begin to lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', NULL, 'forearms', '["forearms"]', '["Sit on an incline bench with a dumbbell in each hand, palms facing each other.","Rest your upper arms on the bench, allowing your elbows to hang down and your palms to face forward.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."]', '["Setze dich auf eine Schrägbank, in jeder Hand eine Kurzhantel, Handflächen zueinander.","Lege die Oberarme auf die Bank, lass die Ellbogen hängen, die Handflächen zeigen nach vorne.","Halte die Oberarme ruhig, atme aus und beuge die Arme, während du den Bizeps anspannst.","Hebe die Kurzhanteln weiter, bis der Bizeps vollständig angespannt ist und die Kurzhanteln auf Schulterhöhe sind.","Halte die kontrahierte Position kurz und spanne dabei den Bizeps an.","Atme ein und senke die Kurzhanteln langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0322.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0322.gif', 1784612222128, 1784612222128, 0),
  ('93b777c3-0ffe-5fef-b423-bfa4faea6516', NULL, 'Dumbbell Incline One Arm Fly', 'Schrägbank-Fliegende mit Kurzhanteln, einarmig', 'chest', 'pectorals', 'dumbbell', 'Adjust the incline bench to a 30-45 degree angle. Sit on the bench with a dumbbell in one hand, resting it on your thigh. Lie back on the bench, keeping your feet flat on the ground. Hold the dumbbell with your arm extended straight up over your chest. Lower the dumbbell out to the side in a wide arc, keeping a slight bend in your elbow. Pause when your arm is parallel to the ground, then reverse the motion to bring the dumbbell back to the starting position. Repeat for the desired number of repetitions, then switch arms.', NULL, 'deltoids', '["deltoids","triceps"]', '["Adjust the incline bench to a 30-45 degree angle.","Sit on the bench with a dumbbell in one hand, resting it on your thigh.","Lie back on the bench, keeping your feet flat on the ground.","Hold the dumbbell with your arm extended straight up over your chest.","Lower the dumbbell out to the side in a wide arc, keeping a slight bend in your elbow.","Pause when your arm is parallel to the ground, then reverse the motion to bring the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."]', '["Stelle die Schrägbank auf einen Winkel von 30-45 Grad ein.","Setze dich auf die Bank, eine Kurzhantel in einer Hand, auf dem Oberschenkel abgestützt.","Lehne dich auf der Bank zurück, die Füsse bleiben flach am Boden.","Halte die Kurzhantel mit gestrecktem Arm gerade über der Brust.","Senke die Kurzhantel in einer weiten Bogenbewegung seitlich ab, der Ellbogen bleibt leicht gebeugt.","Halte inne, wenn der Arm parallel zum Boden ist, und kehre die Bewegung um, um die Kurzhantel zurück in die Ausgangsposition zu bringen.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dann die Seite."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1279.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1279.gif', 1784612222128, 1784612222128, 0),
  ('93d11e63-3ceb-59f6-8860-2862e0a7f116', NULL, 'Dumbbell Incline One Arm Fly on Exercise Ball', 'Schrägbank-Fliegende mit Kurzhanteln auf dem Gymnastikball, einarmig', 'chest', 'pectorals', 'dumbbell', 'Sit on an exercise ball with a dumbbell in one hand. Walk your feet forward and roll your body down until your head, neck, and upper back are supported on the ball. Hold the dumbbell with your arm extended straight up over your chest, palm facing inwards. Slowly lower the dumbbell out to the side, keeping a slight bend in your elbow. Pause for a moment when your arm is parallel to the ground. Engage your chest muscles to bring the dumbbell back up to the starting position. Repeat for the desired number of repetitions, then switch arms.', NULL, 'shoulders', '["shoulders"]', '["Sit on an exercise ball with a dumbbell in one hand.","Walk your feet forward and roll your body down until your head, neck, and upper back are supported on the ball.","Hold the dumbbell with your arm extended straight up over your chest, palm facing inwards.","Slowly lower the dumbbell out to the side, keeping a slight bend in your elbow.","Pause for a moment when your arm is parallel to the ground.","Engage your chest muscles to bring the dumbbell back up to the starting position.","Repeat for the desired number of repetitions, then switch arms."]', '["Setze dich auf einen Gymnastikball, eine Kurzhantel in einer Hand.","Gehe mit den Füssen nach vorne und rolle den Körper ab, bis Kopf, Nacken und oberer Rücken vom Ball gestützt werden.","Halte die Kurzhantel mit gestrecktem Arm gerade über der Brust, Handfläche nach innen.","Senke die Kurzhantel langsam seitlich ab, der Ellbogen bleibt leicht gebeugt.","Halte kurz inne, wenn der Arm parallel zum Boden ist.","Spanne die Brustmuskeln an, um die Kurzhantel zurück in die Ausgangsposition zu bringen.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dann die Seite."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1280.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1280.gif', 1784612222128, 1784612222128, 0),
  ('ced9dcb1-52fa-553a-a981-12cc139d8755', NULL, 'Dumbbell Incline One Arm Hammer Press', 'Kurzhantel-Schrägbank-Hammerdrücken, einarmig', 'upper arms', 'triceps', 'dumbbell', 'Sit on an incline bench with a dumbbell in one hand, resting on your thigh. Lean back on the bench and use your thigh to help raise the dumbbell to shoulder height. Rotate your wrist so that your palm is facing inward, towards your body. Press the dumbbell up and away from your body, extending your arm fully. Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position. Repeat for the desired number of repetitions, then switch arms.', NULL, 'shoulders', '["shoulders","chest"]', '["Sit on an incline bench with a dumbbell in one hand, resting on your thigh.","Lean back on the bench and use your thigh to help raise the dumbbell to shoulder height.","Rotate your wrist so that your palm is facing inward, towards your body.","Press the dumbbell up and away from your body, extending your arm fully.","Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position.","Repeat for the desired number of repetitions, then switch arms."]', '["Setze dich auf eine Schrägbank, eine Kurzhantel in einer Hand, auf dem Oberschenkel abgestützt.","Lehne dich auf der Bank zurück und nutze den Oberschenkel, um die Kurzhantel auf Schulterhöhe zu heben.","Drehe das Handgelenk, sodass die Handfläche zum Körper zeigt.","Drücke die Kurzhantel nach oben und vom Körper weg, der Arm vollständig gestreckt.","Halte am oberen Punkt kurz inne und senke die Kurzhantel dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dann die Seite."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1619.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1619.gif', 1784612222128, 1784612222128, 0),
  ('bb097072-eda5-5868-9a05-fc04e80ba733', NULL, 'Dumbbell Incline One Arm Hammer Press on Exercise Ball', 'Kurzhantel-Schrägbank-Hammerdrücken auf dem Gymnastikball, einarmig', 'upper arms', 'triceps', 'dumbbell', 'Sit on an exercise ball with a dumbbell in one hand. Walk your feet forward and roll your body down until your head, neck, and upper back are supported on the ball. Hold the dumbbell with your palm facing inward and your elbow bent at a 90-degree angle. Press the dumbbell up towards the ceiling, straightening your arm. Lower the dumbbell back down to the starting position. Repeat for the desired number of repetitions, then switch arms.', NULL, 'shoulders', '["shoulders","chest"]', '["Sit on an exercise ball with a dumbbell in one hand.","Walk your feet forward and roll your body down until your head, neck, and upper back are supported on the ball.","Hold the dumbbell with your palm facing inward and your elbow bent at a 90-degree angle.","Press the dumbbell up towards the ceiling, straightening your arm.","Lower the dumbbell back down to the starting position.","Repeat for the desired number of repetitions, then switch arms."]', '["Setze dich auf einen Gymnastikball, eine Kurzhantel in einer Hand.","Gehe mit den Füssen nach vorne und rolle den Körper ab, bis Kopf, Nacken und oberer Rücken vom Ball gestützt werden.","Halte die Kurzhantel, die Handfläche zeigt nach innen, der Ellbogen im 90-Grad-Winkel gebeugt.","Drücke die Kurzhantel Richtung Decke und strecke dabei den Arm.","Senke die Kurzhantel zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dann die Seite."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1620.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1620.gif', 1784612222128, 1784612222128, 0),
  ('193b8bf3-db50-5983-9e2f-6eada5c6939a', NULL, 'Dumbbell Incline One Arm Lateral Raise', 'Kurzhantel-Schrägbank-Seitheben, einarmig', 'shoulders', 'delts', 'dumbbell', 'Sit on an incline bench with a dumbbell in one hand, resting it on your thigh. Lean forward and position your upper arm against the inside of your thigh. Raise the dumbbell to the side, keeping your arm slightly bent and your palm facing down. Continue lifting until your arm is parallel to the floor. Pause for a moment at the top, then slowly lower the dumbbell back to the starting position. Repeat for the desired number of repetitions, then switch to the other arm.', NULL, 'trapezius', '["trapezius","triceps"]', '["Sit on an incline bench with a dumbbell in one hand, resting it on your thigh.","Lean forward and position your upper arm against the inside of your thigh.","Raise the dumbbell to the side, keeping your arm slightly bent and your palm facing down.","Continue lifting until your arm is parallel to the floor.","Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."]', '["Setze dich auf eine Schrägbank, eine Kurzhantel in einer Hand, auf dem Oberschenkel abgestützt.","Lehne dich nach vorne und stütze den Oberarm an der Innenseite des Oberschenkels ab.","Hebe die Kurzhantel seitlich an, der Arm bleibt leicht gebeugt, die Handfläche zeigt nach unten.","Hebe weiter, bis der Arm parallel zum Boden ist.","Halte am oberen Punkt kurz inne und senke die Kurzhantel dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dann zum anderen Arm."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0323.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0323.gif', 1784612222128, 1784612222128, 0),
  ('de0609b1-25b0-510e-bc8a-d2e8e58c4185', NULL, 'Dumbbell Incline One Arm Press', 'Kurzhantel-Schrägbank-Drücken, einarmig', 'chest', 'pectorals', 'dumbbell', 'Sit on an incline bench with a dumbbell in one hand, resting on your thigh. Lie back on the bench and position the dumbbell at shoulder level, palm facing forward. Press the dumbbell upward and slightly inward, extending your arm fully. Pause for a moment at the top, then slowly lower the dumbbell back to the starting position. Repeat for the desired number of repetitions, then switch to the other arm.', NULL, 'shoulders', '["shoulders","triceps"]', '["Sit on an incline bench with a dumbbell in one hand, resting on your thigh.","Lie back on the bench and position the dumbbell at shoulder level, palm facing forward.","Press the dumbbell upward and slightly inward, extending your arm fully.","Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."]', '["Setze dich auf eine Schrägbank, eine Kurzhantel in einer Hand, auf dem Oberschenkel abgestützt.","Lehne dich auf der Bank zurück und positioniere die Kurzhantel auf Schulterhöhe, Handfläche nach vorne.","Drücke die Kurzhantel nach oben und leicht nach innen, der Arm vollständig gestreckt.","Halte am oberen Punkt kurz inne und senke die Kurzhantel dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dann zum anderen Arm."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1281.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1281.gif', 1784612222128, 1784612222128, 0),
  ('58c284c8-57c2-5610-970b-6b39446f7dba', NULL, 'Dumbbell Incline One Arm Press on Exercise Ball', 'Kurzhantel-Schrägbank-Drücken auf dem Gymnastikball, einarmig', 'chest', 'pectorals', 'dumbbell', 'Sit on an exercise ball with a dumbbell in one hand, feet flat on the ground. Slowly walk your feet forward, rolling the ball until your head, neck, and upper back are supported on the ball. Hold the dumbbell at shoulder height with your palm facing forward. Press the dumbbell upward until your arm is fully extended. Pause for a moment at the top, then slowly lower the dumbbell back to the starting position. Repeat for the desired number of repetitions, then switch to the other arm.', NULL, 'shoulders', '["shoulders","triceps"]', '["Sit on an exercise ball with a dumbbell in one hand, feet flat on the ground.","Slowly walk your feet forward, rolling the ball until your head, neck, and upper back are supported on the ball.","Hold the dumbbell at shoulder height with your palm facing forward.","Press the dumbbell upward until your arm is fully extended.","Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."]', '["Setze dich auf einen Gymnastikball, eine Kurzhantel in einer Hand, Füsse flach am Boden.","Gehe langsam mit den Füssen nach vorne und rolle den Ball ab, bis Kopf, Nacken und oberer Rücken vom Ball gestützt werden.","Halte die Kurzhantel auf Schulterhöhe, die Handfläche zeigt nach vorne.","Drücke die Kurzhantel nach oben, bis der Arm vollständig gestreckt ist.","Halte am oberen Punkt kurz inne und senke die Kurzhantel dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dann zum anderen Arm."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1282.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1282.gif', 1784612222128, 1784612222128, 0),
  ('ec3c8e32-5a2e-531f-af98-5a3db03ce3b6', NULL, 'Dumbbell Incline Palm-In Press', 'Kurzhantel-Schrägbank-Drücken im Neutralgriff', 'chest', 'pectorals', 'dumbbell', 'Set up an incline bench at a 45-degree angle. Sit on the bench with a dumbbell in each hand, palms facing each other. Plant your feet firmly on the ground and keep your back straight against the bench. Start with the dumbbells at shoulder level, elbows bent and palms facing each other. Press the dumbbells up and away from your body, extending your arms fully. Pause for a moment at the top, then slowly lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', NULL, 'shoulders', '["shoulders","triceps"]', '["Set up an incline bench at a 45-degree angle.","Sit on the bench with a dumbbell in each hand, palms facing each other.","Plant your feet firmly on the ground and keep your back straight against the bench.","Start with the dumbbells at shoulder level, elbows bent and palms facing each other.","Press the dumbbells up and away from your body, extending your arms fully.","Pause for a moment at the top, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle eine Schrägbank im 45-Grad-Winkel auf.","Setze dich auf die Bank, in jeder Hand eine Kurzhantel, Handflächen zueinander.","Stelle die Füsse fest auf den Boden und halte den Rücken gerade an der Bank.","Beginne mit den Kurzhanteln auf Schulterhöhe, die Ellbogen gebeugt, die Handflächen zueinander.","Drücke die Kurzhanteln nach oben und vom Körper weg, bis die Arme vollständig gestreckt sind.","Halte am oberen Punkt kurz inne und senke die Kurzhanteln dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0324.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0324.gif', 1784612222128, 1784612222128, 0),
  ('ced58643-2076-5520-aa8d-9899faee4d6b', NULL, 'Dumbbell Incline Press on Exercise Ball', 'Kurzhantel-Schrägbank-Drücken auf dem Gymnastikball', 'chest', 'pectorals', 'dumbbell', 'Sit on an exercise ball with a dumbbell in each hand, palms facing forward. Slowly walk your feet forward, rolling your body down the ball until your head, neck, and upper back are supported on the ball. Hold the dumbbells at shoulder level, elbows bent and pointing out to the sides. Press the dumbbells upward, extending your arms fully. Pause for a moment at the top, then slowly lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', NULL, 'shoulders', '["shoulders","triceps"]', '["Sit on an exercise ball with a dumbbell in each hand, palms facing forward.","Slowly walk your feet forward, rolling your body down the ball until your head, neck, and upper back are supported on the ball.","Hold the dumbbells at shoulder level, elbows bent and pointing out to the sides.","Press the dumbbells upward, extending your arms fully.","Pause for a moment at the top, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."]', '["Setze dich auf einen Gymnastikball, in jeder Hand eine Kurzhantel, Handflächen nach vorne.","Gehe langsam mit den Füssen nach vorne und rolle den Körper den Ball hinunter, bis Kopf, Nacken und oberer Rücken vom Ball gestützt werden.","Halte die Kurzhanteln auf Schulterhöhe, die Ellbogen gebeugt und seitlich zeigend.","Drücke die Kurzhanteln nach oben, die Arme vollständig gestreckt.","Halte am oberen Punkt kurz inne und senke die Kurzhanteln dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1283.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1283.gif', 1784612222128, 1784612222128, 0),
  ('eb9212df-8793-513f-add5-77f0c0634220', NULL, 'Dumbbell Incline Raise', 'Kurzhantel-Schrägbank-Armheben', 'shoulders', 'delts', 'dumbbell', 'Sit on an incline bench with a dumbbell in each hand, resting on your thighs. Lean back on the bench and raise the dumbbells to shoulder height, palms facing forward. Keeping your back against the bench, exhale and raise the dumbbells above your head, fully extending your arms. Pause for a moment at the top, then inhale and slowly lower the dumbbells back to shoulder height. Repeat for the desired number of repetitions.', NULL, 'trapezius', '["trapezius","triceps"]', '["Sit on an incline bench with a dumbbell in each hand, resting on your thighs.","Lean back on the bench and raise the dumbbells to shoulder height, palms facing forward.","Keeping your back against the bench, exhale and raise the dumbbells above your head, fully extending your arms.","Pause for a moment at the top, then inhale and slowly lower the dumbbells back to shoulder height.","Repeat for the desired number of repetitions."]', '["Setze dich auf eine Schrägbank, in jeder Hand eine Kurzhantel, auf den Oberschenkeln abgestützt.","Lehne dich auf der Bank zurück und hebe die Kurzhanteln auf Schulterhöhe, Handflächen nach vorne.","Halte den Rücken an der Bank, atme aus und hebe die Kurzhanteln über den Kopf, bis die Arme vollständig gestreckt sind.","Halte am oberen Punkt kurz inne, atme dann ein und senke die Kurzhanteln langsam zurück auf Schulterhöhe ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0325.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0325.gif', 1784612222128, 1784612222128, 0),
  ('b6719379-aee0-5249-8990-d30d133a3e25', NULL, 'Dumbbell Incline Rear Lateral Raise', 'Kurzhantel-Schrägbank-Reverses Seitheben', 'shoulders', 'delts', 'dumbbell', 'Set up an incline bench at a 45-degree angle. Sit on the bench with your chest against the backrest and hold a dumbbell in each hand. Extend your arms straight down with your palms facing each other. Keeping a slight bend in your elbows, raise your arms out to the sides until they are parallel to the ground. Pause for a moment at the top, then slowly lower your arms back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'traps', '["traps","rhomboids"]', '["Set up an incline bench at a 45-degree angle.","Sit on the bench with your chest against the backrest and hold a dumbbell in each hand.","Extend your arms straight down with your palms facing each other.","Keeping a slight bend in your elbows, raise your arms out to the sides until they are parallel to the ground.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle eine Schrägbank im 45-Grad-Winkel auf.","Setze dich auf die Bank, die Brust an der Rückenlehne, und halte in jeder Hand eine Kurzhantel.","Strecke die Arme gerade nach unten, die Handflächen zueinander.","Halte die Ellbogen leicht gebeugt und hebe die Arme seitlich an, bis sie parallel zum Boden sind.","Halte am oberen Punkt kurz inne und senke die Arme dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0326.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0326.gif', 1784612222128, 1784612222128, 0),
  ('f2115ebc-29f4-5536-b213-325ddc800cbe', NULL, 'Dumbbell Incline Row', 'Kurzhantel-Schrägbank-Rudern', 'back', 'upper back', 'dumbbell', 'Set up an incline bench at a 45-degree angle. Grab a dumbbell in each hand and sit on the bench with your chest against the incline. Extend your arms fully, allowing the dumbbells to hang straight down from your shoulders. Pull the dumbbells up towards your chest, squeezing your shoulder blades together. Pause for a moment at the top, then slowly lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","shoulders"]', '["Set up an incline bench at a 45-degree angle.","Grab a dumbbell in each hand and sit on the bench with your chest against the incline.","Extend your arms fully, allowing the dumbbells to hang straight down from your shoulders.","Pull the dumbbells up towards your chest, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle eine Schrägbank im 45-Grad-Winkel auf.","Greife in jede Hand eine Kurzhantel und setze dich mit der Brust an der Schräge auf die Bank.","Strecke die Arme vollständig, sodass die Kurzhanteln gerade von den Schultern herabhängen.","Ziehe die Kurzhanteln Richtung Brust hoch und ziehe dabei die Schulterblätter zusammen.","Halte am oberen Punkt kurz inne und senke die Kurzhanteln dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0327.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0327.gif', 1784612222128, 1784612222128, 0),
  ('64be92a7-9319-5075-9ad4-5cf5d580631d', NULL, 'Dumbbell Incline Shoulder Raise', 'Kurzhantel-Schrägbank-Scapula-Push (Serratus anterior)', 'chest', 'serratus anterior', 'dumbbell', 'Set an incline bench to a 45-degree angle and sit on it with a dumbbell in each hand, palms facing down. Rest the dumbbells on your thighs and lean back onto the bench. Use your thighs to help raise the dumbbells to shoulder height, then rotate your wrists so that your palms are facing forward. Exhale and slowly raise the dumbbells above your head, keeping a slight bend in your elbows. Pause for a moment at the top, then inhale and slowly lower the dumbbells back to shoulder height. Repeat for the desired number of repetitions.', NULL, 'deltoids', '["deltoids","trapezius"]', '["Set an incline bench to a 45-degree angle and sit on it with a dumbbell in each hand, palms facing down.","Rest the dumbbells on your thighs and lean back onto the bench.","Use your thighs to help raise the dumbbells to shoulder height, then rotate your wrists so that your palms are facing forward.","Exhale and slowly raise the dumbbells above your head, keeping a slight bend in your elbows.","Pause for a moment at the top, then inhale and slowly lower the dumbbells back to shoulder height.","Repeat for the desired number of repetitions."]', '["Stelle eine Schrägbank auf einen 45-Grad-Winkel ein und setze dich mit einer Kurzhantel in jeder Hand darauf, Handflächen nach unten.","Lege die Kurzhanteln auf die Oberschenkel und lehne dich auf der Bank zurück.","Nutze die Oberschenkel, um die Kurzhanteln auf Schulterhöhe zu heben, drehe dann die Handgelenke, sodass die Handflächen nach vorne zeigen.","Atme aus und hebe die Kurzhanteln langsam über den Kopf, die Ellbogen bleiben leicht gebeugt.","Halte am oberen Punkt kurz inne, atme dann ein und senke die Kurzhanteln langsam zurück auf Schulterhöhe ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0328.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0328.gif', 1784612222128, 1784612222128, 0),
  ('7da16d50-72ee-57eb-ab1a-6136cce4e94d', NULL, 'Dumbbell Incline Shrug', 'Kurzhantel-Schrägbank-Schulterheben', 'back', 'traps', 'dumbbell', 'Set an incline bench to a 45-degree angle and sit on it with a dumbbell in each hand. Place your feet flat on the ground and let your arms hang straight down with your palms facing your body. Keeping your arms straight, shrug your shoulders up towards your ears as high as possible. Hold the contraction for a moment, then slowly lower your shoulders back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'shoulders', '["shoulders"]', '["Set an incline bench to a 45-degree angle and sit on it with a dumbbell in each hand.","Place your feet flat on the ground and let your arms hang straight down with your palms facing your body.","Keeping your arms straight, shrug your shoulders up towards your ears as high as possible.","Hold the contraction for a moment, then slowly lower your shoulders back down to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle eine Schrägbank auf einen 45-Grad-Winkel ein und setze dich mit einer Kurzhantel in jeder Hand darauf.","Stelle die Füsse flach auf den Boden und lass die Arme gerade herabhängen, die Handflächen zum Körper.","Halte die Arme gestreckt und ziehe die Schultern so hoch wie möglich Richtung Ohren.","Halte die Anspannung kurz und senke die Schultern dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0329.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0329.gif', 1784612222128, 1784612222128, 0),
  ('78f04130-ae31-5399-953c-b1ae13910dec', NULL, 'Dumbbell Incline T-Raise', 'Kurzhantel-Schrägbank-T-Raise', 'shoulders', 'delts', 'dumbbell', 'Set an incline bench to a 45-degree angle and sit on it with a dumbbell in each hand, palms facing inwards. Lean forward and let your arms hang straight down, perpendicular to the floor. Keeping your arms straight, raise them out to the sides until they are parallel to the floor, forming a ''T'' shape with your body. Pause for a moment at the top, then slowly lower your arms back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'traps', '["traps","rhomboids"]', '["Set an incline bench to a 45-degree angle and sit on it with a dumbbell in each hand, palms facing inwards.","Lean forward and let your arms hang straight down, perpendicular to the floor.","Keeping your arms straight, raise them out to the sides until they are parallel to the floor, forming a ''T'' shape with your body.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle eine Schrägbank auf einen 45-Grad-Winkel ein und setze dich mit einer Kurzhantel in jeder Hand darauf, Handflächen nach innen.","Lehne dich nach vorne und lass die Arme gerade herabhängen, senkrecht zum Boden.","Halte die Arme gestreckt und hebe sie seitlich an, bis sie parallel zum Boden sind und mit dem Körper ein T bilden.","Halte am oberen Punkt kurz inne und senke die Arme dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/3542.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/3542.gif', 1784612222128, 1784612222128, 0),
  ('7c7fe63e-5c7b-5545-9b97-3b34700760ec', NULL, 'Dumbbell Incline Triceps Extension', 'Kurzhantel-Schrägbank-Trizeps-Extension', 'upper arms', 'triceps', 'dumbbell', 'Sit on an incline bench with a dumbbell in each hand, palms facing inwards. Extend your arms fully overhead, keeping your elbows close to your head. Lower the dumbbells behind your head by bending your elbows, keeping your upper arms stationary. Pause for a moment, then raise the dumbbells back to the starting position by extending your arms. Repeat for the desired number of repetitions.', NULL, 'shoulders', '["shoulders"]', '["Sit on an incline bench with a dumbbell in each hand, palms facing inwards.","Extend your arms fully overhead, keeping your elbows close to your head.","Lower the dumbbells behind your head by bending your elbows, keeping your upper arms stationary.","Pause for a moment, then raise the dumbbells back to the starting position by extending your arms.","Repeat for the desired number of repetitions."]', '["Setze dich auf eine Schrägbank, in jeder Hand eine Kurzhantel, Handflächen zueinander.","Strecke die Arme vollständig über den Kopf, die Ellbogen bleiben nah am Kopf.","Senke die Kurzhanteln hinter den Kopf ab, indem du die Ellbogen beugst, die Oberarme bleiben ruhig.","Halte kurz inne und hebe die Kurzhanteln dann zurück in die Ausgangsposition, indem du die Arme streckst.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0330.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0330.gif', 1784612222128, 1784612222128, 0),
  ('571dda9c-eb25-5b8f-b7bb-ba216602a390', NULL, 'Dumbbell Incline Twisted Flyes', 'Schrägbank-Drehfliegende mit Kurzhanteln', 'chest', 'pectorals', 'dumbbell', 'Set an incline bench to a 45-degree angle and sit on it with a dumbbell in each hand, palms facing each other. Lie back on the bench and press the dumbbells up to the starting position, directly above your chest, with your arms extended. Lower the dumbbells out to the sides in a wide arc until you feel a stretch in your chest. As you lower the dumbbells, rotate your wrists so that your palms face forward at the bottom of the movement. Reverse the motion and bring the dumbbells back up to the starting position, squeezing your chest muscles together at the top. Repeat for the desired number of repetitions.', NULL, 'shoulders', '["shoulders","triceps"]', '["Set an incline bench to a 45-degree angle and sit on it with a dumbbell in each hand, palms facing each other.","Lie back on the bench and press the dumbbells up to the starting position, directly above your chest, with your arms extended.","Lower the dumbbells out to the sides in a wide arc until you feel a stretch in your chest.","As you lower the dumbbells, rotate your wrists so that your palms face forward at the bottom of the movement.","Reverse the motion and bring the dumbbells back up to the starting position, squeezing your chest muscles together at the top.","Repeat for the desired number of repetitions."]', '["Stelle eine Schrägbank auf einen 45-Grad-Winkel ein und setze dich mit einer Kurzhantel in jeder Hand darauf, Handflächen zueinander.","Lehne dich auf der Bank zurück und drücke die Kurzhanteln in die Ausgangsposition, direkt über der Brust, die Arme gestreckt.","Senke die Kurzhanteln in einer weiten Bogenbewegung seitlich ab, bis du eine Dehnung in der Brust spürst.","Drehe beim Absenken die Handgelenke, sodass die Handflächen am unteren Punkt nach vorne zeigen.","Kehre die Bewegung um und führe die Kurzhanteln zurück in die Ausgangsposition, spanne dabei am oberen Punkt die Brustmuskeln an.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0331.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0331.gif', 1784612222128, 1784612222128, 0),
  ('7f984cce-bd28-5560-a924-cc9156e4ceb9', NULL, 'Dumbbell Incline Two Arm Extension', 'Kurzhantel-Schrägbank-Trizeps-Extension, beidarmig', 'upper arms', 'triceps', 'dumbbell', 'Sit on an incline bench with a dumbbell in each hand, resting on your thighs. Slowly lie back on the bench, keeping the dumbbells close to your chest. Once you are fully lying down, extend your arms straight up towards the ceiling, keeping your elbows slightly bent. Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'shoulders', '["shoulders"]', '["Sit on an incline bench with a dumbbell in each hand, resting on your thighs.","Slowly lie back on the bench, keeping the dumbbells close to your chest.","Once you are fully lying down, extend your arms straight up towards the ceiling, keeping your elbows slightly bent.","Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."]', '["Setze dich auf eine Schrägbank, in jeder Hand eine Kurzhantel, auf den Oberschenkeln abgestützt.","Lege dich langsam auf der Bank zurück, die Kurzhanteln bleiben nah an der Brust.","Sobald du vollständig liegst, strecke die Arme gerade Richtung Decke, die Ellbogen bleiben leicht gebeugt.","Halte am oberen Punkt kurz inne und senke die Kurzhanteln dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1733.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1733.gif', 1784612222128, 1784612222128, 0),
  ('75984dbd-9095-5241-a73f-d30c3c1e192b', NULL, 'Dumbbell Incline Y-Raise', 'Kurzhantel-Schrägbank-Y-Raise', 'back', 'upper back', 'dumbbell', 'Set an incline bench to a 45-degree angle and sit on it with a dumbbell in each hand, palms facing inwards. Lean forward slightly and let your arms hang straight down, keeping a slight bend in your elbows. Raise your arms out to the sides and up in a Y shape until they are parallel to the ground. Pause for a moment at the top, then slowly lower your arms back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'shoulders', '["shoulders","rear deltoids"]', '["Set an incline bench to a 45-degree angle and sit on it with a dumbbell in each hand, palms facing inwards.","Lean forward slightly and let your arms hang straight down, keeping a slight bend in your elbows.","Raise your arms out to the sides and up in a Y shape until they are parallel to the ground.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."]', '["Stelle eine Schrägbank auf einen 45-Grad-Winkel ein und setze dich mit einer Kurzhantel in jeder Hand darauf, Handflächen nach innen.","Lehne dich leicht nach vorne und lass die Arme gerade herabhängen, die Ellbogen leicht gebeugt.","Hebe die Arme seitlich und nach oben in einer Y-Form an, bis sie parallel zum Boden sind.","Halte am oberen Punkt kurz inne und senke die Arme dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/3541.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/3541.gif', 1784612222128, 1784612222128, 0),
  ('0372e92a-b46d-5669-9a96-0cef2362b7de', NULL, 'Dumbbell Iron Cross', 'Kurzhantel-Iron-Cross', 'shoulders', 'delts', 'dumbbell', 'Stand with your feet shoulder-width apart, holding a dumbbell in each hand at your sides. Raise your arms out to the sides until they are parallel to the ground, forming a T shape with your body. Pause for a moment, then slowly lower your arms back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'triceps', '["triceps","chest"]', '["Stand with your feet shoulder-width apart, holding a dumbbell in each hand at your sides.","Raise your arms out to the sides until they are parallel to the ground, forming a T shape with your body.","Pause for a moment, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."]', '["Stehe mit schulterbreiten Füssen, in jeder Hand eine Kurzhantel an den Seiten.","Hebe die Arme seitlich an, bis sie parallel zum Boden sind und mit dem Körper ein T bilden.","Halte kurz inne und senke die Arme dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0332.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0332.gif', 1784612222128, 1784612222128, 0);

INSERT OR REPLACE INTO exercises (id, user_id, name, name_de, category, primary_muscle, equipment, instructions_en, instructions_de, muscle_group, secondary_muscles, instruction_steps_en, instruction_steps_de, thumbnail_url, gif_url, created_at, updated_at, deleted) VALUES
  ('b511a099-d3b4-50b4-a027-29feb3ca1a2c', NULL, 'Dumbbell Kickback', 'Kurzhantel-Trizeps-Kickback', 'upper arms', 'triceps', 'dumbbell', 'Stand with your feet shoulder-width apart and hold a dumbbell in each hand. Bend your knees slightly and hinge forward at the hips, keeping your back straight. Bring your upper arms close to your sides, with your elbows bent at a 90-degree angle. Extend your arms straight back, squeezing your triceps at the top of the movement. Pause for a moment, then slowly lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', NULL, 'shoulders', '["shoulders"]', '["Stand with your feet shoulder-width apart and hold a dumbbell in each hand.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Bring your upper arms close to your sides, with your elbows bent at a 90-degree angle.","Extend your arms straight back, squeezing your triceps at the top of the movement.","Pause for a moment, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."]', '["Stehe mit schulterbreiten Füssen und halte in jeder Hand eine Kurzhantel.","Beuge die Knie leicht und beuge dich in der Hüfte nach vorne, der Rücken bleibt gerade.","Bringe die Oberarme nah an den Körper, die Ellbogen im 90-Grad-Winkel gebeugt.","Strecke die Arme gerade nach hinten und spanne den Trizeps am oberen Punkt der Bewegung an.","Halte kurz inne und senke die Kurzhanteln dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0333.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0333.gif', 1784612222128, 1784612222128, 0),
  ('fa2a2460-6ce5-55e7-9256-80c9b4bbe116', NULL, 'Dumbbell Kickbacks on Exercise Ball', 'Kurzhantel-Trizeps-Kickback auf dem Gymnastikball', 'upper arms', 'triceps', 'dumbbell', 'Sit on an exercise ball with your feet flat on the ground and your back straight. Hold a dumbbell in each hand with your palms facing inwards and your arms bent at a 90-degree angle. Extend your arms straight back, squeezing your triceps at the top of the movement. Pause for a moment, then slowly lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', NULL, 'shoulders', '["shoulders","back"]', '["Sit on an exercise ball with your feet flat on the ground and your back straight.","Hold a dumbbell in each hand with your palms facing inwards and your arms bent at a 90-degree angle.","Extend your arms straight back, squeezing your triceps at the top of the movement.","Pause for a moment, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."]', '["Setze dich auf einen Gymnastikball, Füsse flach am Boden, Rücken gerade.","Halte in jeder Hand eine Kurzhantel, Handflächen nach innen, Arme im 90-Grad-Winkel gebeugt.","Strecke die Arme gerade nach hinten und spanne den Trizeps am oberen Punkt der Bewegung an.","Halte kurz inne und senke die Kurzhanteln dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1734.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1734.gif', 1784612222128, 1784612222128, 0),
  ('3aabd735-a3bd-5a17-9f90-520822fd8f20', NULL, 'Dumbbell Kneeling Bicep Curl Exercise Ball', 'Kurzhantel-Bizepscurl im Knien auf dem Gymnastikball', 'upper arms', 'biceps', 'dumbbell', 'Kneel on the floor with an exercise ball in front of you. Place your elbows on top of the exercise ball, holding a dumbbell in each hand with your palms facing up. Keeping your upper arms stationary, exhale and curl the dumbbells while contracting your biceps. Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly begin to lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', NULL, 'forearms', '["forearms"]', '["Kneel on the floor with an exercise ball in front of you.","Place your elbows on top of the exercise ball, holding a dumbbell in each hand with your palms facing up.","Keeping your upper arms stationary, exhale and curl the dumbbells while contracting your biceps.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."]', '["Kniee dich mit einem Gymnastikball vor dir auf den Boden.","Lege die Ellbogen auf den Gymnastikball und halte in jeder Hand eine Kurzhantel, Handflächen nach oben.","Halte die Oberarme ruhig, atme aus und beuge die Kurzhanteln, während du den Bizeps anspannst.","Hebe die Kurzhanteln weiter, bis der Bizeps vollständig angespannt ist und die Kurzhanteln auf Schulterhöhe sind.","Halte die kontrahierte Position kurz und spanne dabei den Bizeps an.","Atme ein und senke die Kurzhanteln langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1660.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1660.gif', 1784612222128, 1784612222128, 0),
  ('89f8c5bd-b4f5-5240-bbde-02da06af53ba', NULL, 'Dumbbell Lateral Raise', 'Kurzhantel-Seitheben', 'shoulders', 'delts', 'dumbbell', 'Stand with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing your body. Keep your back straight and engage your core. Raise your arms out to the sides until they are parallel to the floor, keeping a slight bend in your elbows. Pause for a moment at the top, then slowly lower your arms back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'traps', '["traps"]', '["Stand with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing your body.","Keep your back straight and engage your core.","Raise your arms out to the sides until they are parallel to the floor, keeping a slight bend in your elbows.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."]', '["Stehe mit schulterbreiten Füssen, in jeder Hand eine Kurzhantel, Handflächen zum Körper.","Halte den Rücken gerade und spanne die Körpermitte an.","Hebe die Arme seitlich an, bis sie parallel zum Boden sind, die Ellbogen bleiben leicht gebeugt.","Halte am oberen Punkt kurz inne und senke die Arme dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0334.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0334.gif', 1784612222128, 1784612222128, 0),
  ('28f9f73e-8293-50c1-9e0f-d6ab24411d07', NULL, 'Dumbbell Lateral to Front Raise', 'Kurzhantel-Seitheben zu Frontheben', 'shoulders', 'delts', 'dumbbell', 'Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing your body. Keep your back straight and engage your core. Raise your arms out to the sides until they are parallel to the ground, keeping a slight bend in your elbows. Pause for a moment at the top, then slowly lower your arms back down to the starting position. Next, raise your arms in front of you until they are parallel to the ground, again keeping a slight bend in your elbows. Pause for a moment at the top, then slowly lower your arms back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'trapezius', '["trapezius","biceps"]', '["Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing your body.","Keep your back straight and engage your core.","Raise your arms out to the sides until they are parallel to the ground, keeping a slight bend in your elbows.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Next, raise your arms in front of you until they are parallel to the ground, again keeping a slight bend in your elbows.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."]', '["Stehe mit schulterbreiten Füssen, in jeder Hand eine Kurzhantel, Handflächen zum Körper.","Halte den Rücken gerade und spanne die Körpermitte an.","Hebe die Arme seitlich an, bis sie parallel zum Boden sind, die Ellbogen bleiben leicht gebeugt.","Halte am oberen Punkt kurz inne und senke die Arme dann langsam zurück in die Ausgangsposition ab.","Hebe die Arme als Nächstes vor dir an, bis sie parallel zum Boden sind, die Ellbogen wieder leicht gebeugt.","Halte am oberen Punkt kurz inne und senke die Arme dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0335.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0335.gif', 1784612222128, 1784612222128, 0),
  ('99aa46ff-2557-5d09-803e-d817914061ba', NULL, 'Dumbbell Lunge', 'Kurzhantel-Ausfallschritt', 'upper legs', 'glutes', 'dumbbell', 'Stand with your feet shoulder-width apart, holding a dumbbell in each hand. Take a step forward with your right foot, lowering your body into a lunge position. Keep your back straight and your chest up as you lower your body. Push through your right heel to return to the starting position. Repeat with your left leg. Alternate legs for the desired number of repetitions.', NULL, 'quadriceps', '["quadriceps","hamstrings","calves"]', '["Stand with your feet shoulder-width apart, holding a dumbbell in each hand.","Take a step forward with your right foot, lowering your body into a lunge position.","Keep your back straight and your chest up as you lower your body.","Push through your right heel to return to the starting position.","Repeat with your left leg.","Alternate legs for the desired number of repetitions."]', '["Stehe mit schulterbreiten Füssen, in jeder Hand eine Kurzhantel.","Trete mit dem rechten Fuss nach vorne und senke den Körper in eine Ausfallschritt-Position ab.","Halte den Rücken gerade und die Brust raus, während du den Körper absenkst.","Drücke dich durch die rechte Ferse zurück in die Ausgangsposition.","Wiederhole mit dem linken Bein.","Wechsle die Beine für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0336.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0336.gif', 1784612222128, 1784612222128, 0),
  ('868ee6ca-2947-59a1-80cf-0e37b8406661', NULL, 'Dumbbell Lunge with Bicep Curl', 'Kurzhantel-Ausfallschritt mit Bizepscurl', 'upper arms', 'biceps', 'dumbbell', 'Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing forward. Take a step forward with your right foot, lowering your body into a lunge position. Your right knee should be bent at a 90-degree angle and your left knee should be hovering just above the ground. As you lunge forward, simultaneously curl the dumbbells towards your shoulders, keeping your elbows close to your body. Pause for a moment at the bottom of the lunge, then push through your right heel to return to the starting position, lowering the dumbbells back down to your sides. Repeat the lunge and bicep curl on the opposite side, stepping forward with your left foot. Continue alternating sides for the desired number of repetitions.', NULL, 'quadriceps', '["quadriceps","hamstrings"]', '["Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing forward.","Take a step forward with your right foot, lowering your body into a lunge position. Your right knee should be bent at a 90-degree angle and your left knee should be hovering just above the ground.","As you lunge forward, simultaneously curl the dumbbells towards your shoulders, keeping your elbows close to your body.","Pause for a moment at the bottom of the lunge, then push through your right heel to return to the starting position, lowering the dumbbells back down to your sides.","Repeat the lunge and bicep curl on the opposite side, stepping forward with your left foot.","Continue alternating sides for the desired number of repetitions."]', '["Stehe mit schulterbreiten Füssen, in jeder Hand eine Kurzhantel, Handflächen nach vorne.","Trete mit dem rechten Fuss nach vorne und senke den Körper in eine Ausfallschritt-Position ab. Das rechte Knie ist im 90-Grad-Winkel gebeugt, das linke Knie schwebt knapp über dem Boden.","Ziehe beim Ausfallschritt gleichzeitig die Kurzhanteln Richtung Schultern hoch, die Ellbogen bleiben nah am Körper.","Halte am unteren Punkt des Ausfallschritts kurz inne, drücke dich dann durch die rechte Ferse zurück in die Ausgangsposition und senke dabei die Kurzhanteln wieder ab.","Wiederhole den Ausfallschritt mit Bizeps-Curl auf der gegenüberliegenden Seite, trete mit dem linken Fuss nach vorne.","Wechsle die Seite fortlaufend für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1658.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1658.gif', 1784612222128, 1784612222128, 0),
  ('6c188628-dcd4-58b6-b83b-ca21bb6f8793', NULL, 'Dumbbell Lying Extension (Across Face)', 'Kurzhantel-Trizeps-Extension im Liegen (über das Gesicht)', 'upper arms', 'triceps', 'dumbbell', 'Lie flat on a bench with your feet flat on the ground and your head at the end of the bench. Hold a dumbbell with both hands and extend your arms straight up above your chest, palms facing each other. Keeping your upper arms stationary, slowly lower the dumbbell in an arc behind your head until your forearms are parallel to the ground. Pause for a moment, then contract your triceps to bring the dumbbell back to the starting position. Repeat for the desired number of repetitions.', NULL, 'shoulders', '["shoulders"]', '["Lie flat on a bench with your feet flat on the ground and your head at the end of the bench.","Hold a dumbbell with both hands and extend your arms straight up above your chest, palms facing each other.","Keeping your upper arms stationary, slowly lower the dumbbell in an arc behind your head until your forearms are parallel to the ground.","Pause for a moment, then contract your triceps to bring the dumbbell back to the starting position.","Repeat for the desired number of repetitions."]', '["Lege dich flach auf eine Bank, die Füsse flach am Boden, der Kopf am Ende der Bank.","Halte eine Kurzhantel mit beiden Händen und strecke die Arme gerade über der Brust, Handflächen zueinander.","Halte die Oberarme ruhig und senke die Kurzhantel langsam in einer Bogenbewegung hinter den Kopf ab, bis die Unterarme parallel zum Boden sind.","Halte kurz inne und spanne dann den Trizeps an, um die Kurzhantel zurück in die Ausgangsposition zu bringen.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0337.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0337.gif', 1784612222128, 1784612222128, 0),
  ('de017a9e-97e2-582d-b8a5-e9ddd14739fc', NULL, 'Dumbbell Lying Alternate Extension', 'Kurzhantel-Trizeps-Extension im Liegen, wechselseitig', 'upper arms', 'triceps', 'dumbbell', 'Lie flat on a bench with a dumbbell in each hand, palms facing each other. Extend your arms straight up over your chest, keeping a slight bend in your elbows. Lower one dumbbell down towards your head, bending at the elbow, while keeping the other arm extended. Pause for a moment at the bottom, then raise the dumbbell back up to the starting position. Repeat with the other arm, alternating sides for the desired number of repetitions.', NULL, 'shoulders', '["shoulders"]', '["Lie flat on a bench with a dumbbell in each hand, palms facing each other.","Extend your arms straight up over your chest, keeping a slight bend in your elbows.","Lower one dumbbell down towards your head, bending at the elbow, while keeping the other arm extended.","Pause for a moment at the bottom, then raise the dumbbell back up to the starting position.","Repeat with the other arm, alternating sides for the desired number of repetitions."]', '["Lege dich flach auf eine Bank, in jeder Hand eine Kurzhantel, Handflächen zueinander.","Strecke die Arme gerade über der Brust, die Ellbogen bleiben leicht gebeugt.","Senke eine Kurzhantel Richtung Kopf ab, indem du den Ellbogen beugst, während der andere Arm gestreckt bleibt.","Halte am unteren Punkt kurz inne und hebe die Kurzhantel dann zurück in die Ausgangsposition.","Wiederhole mit dem anderen Arm, wechsle die Seite fortlaufend für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1729.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1729.gif', 1784612222128, 1784612222128, 0),
  ('18f72671-2c6a-58cf-8406-6e4463128dee', NULL, 'Dumbbell Lying Elbow Press', 'Kurzhantel-Ellbogendrücken im Liegen', 'upper arms', 'triceps', 'dumbbell', 'Lie flat on a bench with a dumbbell in each hand, palms facing each other and arms extended straight up over your chest. Lower the dumbbells towards your shoulders by bending your elbows, keeping your upper arms stationary. Pause for a moment at the bottom, then press the dumbbells back up to the starting position by extending your elbows. Repeat for the desired number of repetitions.', NULL, 'chest', '["chest","shoulders"]', '["Lie flat on a bench with a dumbbell in each hand, palms facing each other and arms extended straight up over your chest.","Lower the dumbbells towards your shoulders by bending your elbows, keeping your upper arms stationary.","Pause for a moment at the bottom, then press the dumbbells back up to the starting position by extending your elbows.","Repeat for the desired number of repetitions."]', '["Lege dich flach auf eine Bank, in jeder Hand eine Kurzhantel, Handflächen zueinander, Arme gerade über der Brust gestreckt.","Senke die Kurzhanteln Richtung Schultern ab, indem du die Ellbogen beugst, die Oberarme bleiben ruhig.","Halte am unteren Punkt kurz inne und drücke die Kurzhanteln dann zurück in die Ausgangsposition, indem du die Ellbogen streckst.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0338.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0338.gif', 1784612222128, 1784612222128, 0),
  ('f53e5ed7-5608-5dca-b8ae-c84c969677dc', NULL, 'Dumbbell Lying External Shoulder Rotation', 'Kurzhantel-Aussenrotation der Schulter im Liegen', 'shoulders', 'delts', 'dumbbell', 'Lie on your side on a flat bench with your upper arm against your side and your elbow bent 90 degrees. Hold a dumbbell in your hand with your palm facing down. Keeping your upper arm against your side, slowly rotate your forearm upward as far as possible. Pause for a moment at the top, then slowly lower your forearm back down to the starting position. Repeat for the desired number of repetitions, then switch sides.', NULL, 'rotator cuff', '["rotator cuff","triceps"]', '["Lie on your side on a flat bench with your upper arm against your side and your elbow bent 90 degrees.","Hold a dumbbell in your hand with your palm facing down.","Keeping your upper arm against your side, slowly rotate your forearm upward as far as possible.","Pause for a moment at the top, then slowly lower your forearm back down to the starting position.","Repeat for the desired number of repetitions, then switch sides."]', '["Lege dich seitlich auf eine flache Bank, der Oberarm liegt am Körper, der Ellbogen im 90-Grad-Winkel gebeugt.","Halte eine Kurzhantel in der Hand, die Handfläche zeigt nach unten.","Halte den Oberarm am Körper und drehe den Unterarm langsam so weit wie möglich nach oben.","Halte am oberen Punkt kurz inne und senke den Unterarm dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dann die Seite."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0863.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0863.gif', 1784612222128, 1784612222128, 0),
  ('1bc45ee7-e58a-57f1-aedd-91551372caf0', NULL, 'Dumbbell Lying Femoral', 'Kurzhantel-Beincurl im Liegen', 'upper legs', 'hamstrings', 'dumbbell', 'Lie flat on your back with your legs extended and a dumbbell resting on your lower abdomen. Bend your knees and bring the dumbbell towards your glutes, keeping your feet flat on the ground. Pause for a moment at the top, then slowly lower the dumbbell back to the starting position. Repeat for the desired number of repetitions.', NULL, 'glutes', '["glutes"]', '["Lie flat on your back with your legs extended and a dumbbell resting on your lower abdomen.","Bend your knees and bring the dumbbell towards your glutes, keeping your feet flat on the ground.","Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions."]', '["Lege dich flach auf den Rücken, die Beine gestreckt, eine Kurzhantel auf dem unteren Bauch abgelegt.","Beuge die Knie und führe die Kurzhantel Richtung Gesäss, die Füsse bleiben flach am Boden.","Halte am oberen Punkt kurz inne und senke die Kurzhantel dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0339.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0339.gif', 1784612222128, 1784612222128, 0),
  ('883f5bda-dba6-5e63-ba60-e7a4a8bb4905', NULL, 'Dumbbell Lying Hammer Press', 'Kurzhantel-Hammerdrücken im Liegen', 'chest', 'pectorals', 'dumbbell', 'Lie flat on a bench with a dumbbell in each hand, palms facing each other and arms extended straight up. Lower the dumbbells to the sides of your chest, keeping your elbows at a 90-degree angle. Press the dumbbells back up to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', NULL, 'triceps', '["triceps","shoulders"]', '["Lie flat on a bench with a dumbbell in each hand, palms facing each other and arms extended straight up.","Lower the dumbbells to the sides of your chest, keeping your elbows at a 90-degree angle.","Press the dumbbells back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."]', '["Lege dich flach auf eine Bank, in jeder Hand eine Kurzhantel, Handflächen zueinander, Arme gerade gestreckt.","Senke die Kurzhanteln an die Seiten der Brust ab, die Ellbogen bilden dabei einen 90-Grad-Winkel.","Drücke die Kurzhanteln zurück in die Ausgangsposition, die Arme vollständig gestreckt.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0340.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0340.gif', 1784612222128, 1784612222128, 0),
  ('928360bd-c4c2-5e0e-a28b-2365447993b2', NULL, 'Dumbbell Lying on Floor Rear Delt Raise', 'Kurzhantel-Reverses Seitheben auf dem Boden', 'shoulders', 'delts', 'dumbbell', 'Lie face down on the floor with a dumbbell in each hand, palms facing each other. Extend your arms straight out in front of you, keeping a slight bend in your elbows. Engaging your shoulder muscles, lift your arms up and out to the sides, squeezing your shoulder blades together. Pause for a moment at the top, then slowly lower your arms back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'trapezius', '["trapezius","rhomboids"]', '["Lie face down on the floor with a dumbbell in each hand, palms facing each other.","Extend your arms straight out in front of you, keeping a slight bend in your elbows.","Engaging your shoulder muscles, lift your arms up and out to the sides, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."]', '["Lege dich bäuchlings auf den Boden, in jeder Hand eine Kurzhantel, Handflächen zueinander.","Strecke die Arme gerade vor dir aus, die Ellbogen bleiben leicht gebeugt.","Spanne die Schultermuskeln an und hebe die Arme seitlich an, ziehe dabei die Schulterblätter zusammen.","Halte am oberen Punkt kurz inne und senke die Arme dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/2470.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/2470.gif', 1784612222128, 1784612222128, 0),
  ('c6d26c9f-4c7b-5e71-b3ba-96b083a46a68', NULL, 'Dumbbell Lying One Arm Deltoid Rear', 'Kurzhantel-Reverses Seitheben im Liegen, einarmig', 'shoulders', 'delts', 'dumbbell', 'Lie face down on a flat bench with a dumbbell in one hand, palm facing inwards. Extend your arm straight down towards the floor, keeping it close to your body. Raise your arm up and back, squeezing your shoulder blade towards your spine. Pause for a moment at the top, then slowly lower your arm back down to the starting position. Repeat for the desired number of repetitions, then switch arms.', NULL, 'trapezius', '["trapezius","rhomboids"]', '["Lie face down on a flat bench with a dumbbell in one hand, palm facing inwards.","Extend your arm straight down towards the floor, keeping it close to your body.","Raise your arm up and back, squeezing your shoulder blade towards your spine.","Pause for a moment at the top, then slowly lower your arm back down to the starting position.","Repeat for the desired number of repetitions, then switch arms."]', '["Lege dich bäuchlings auf eine flache Bank, eine Kurzhantel in einer Hand, Handfläche nach innen.","Strecke den Arm gerade Richtung Boden, nah am Körper.","Hebe den Arm nach oben und hinten, ziehe dabei das Schulterblatt Richtung Wirbelsäule.","Halte am oberen Punkt kurz inne und senke den Arm dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dann die Seite."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0341.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0341.gif', 1784612222128, 1784612222128, 0),
  ('088ce36d-1bac-5d0e-9640-4c669f949ba2', NULL, 'Dumbbell Lying One Arm Press', 'Kurzhantel-Drücken im Liegen, einarmig', 'chest', 'pectorals', 'dumbbell', 'Lie flat on a bench with a dumbbell in one hand and your feet flat on the ground. Hold the dumbbell at shoulder level with your palm facing forward. Press the dumbbell upward until your arm is fully extended. Pause for a moment at the top, then slowly lower the dumbbell back to the starting position. Repeat for the desired number of repetitions, then switch to the other arm.', NULL, 'triceps', '["triceps","shoulders"]', '["Lie flat on a bench with a dumbbell in one hand and your feet flat on the ground.","Hold the dumbbell at shoulder level with your palm facing forward.","Press the dumbbell upward until your arm is fully extended.","Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."]', '["Lege dich flach auf eine Bank, eine Kurzhantel in einer Hand, die Füsse flach am Boden.","Halte die Kurzhantel auf Schulterhöhe, die Handfläche zeigt nach vorne.","Drücke die Kurzhantel nach oben, bis der Arm vollständig gestreckt ist.","Halte am oberen Punkt kurz inne und senke die Kurzhantel dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dann zum anderen Arm."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0343.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0343.gif', 1784612222128, 1784612222128, 0),
  ('833b1828-ee59-5129-9046-97c2c6aa3477', NULL, 'Dumbbell Lying One Arm Press V. 2', 'Kurzhantel-Drücken im Liegen, einarmig (Variante 2)', 'chest', 'pectorals', 'dumbbell', 'Lie flat on a bench with your back supported and feet flat on the ground. Hold a dumbbell in one hand with your palm facing towards your feet. Extend your arm straight up towards the ceiling, keeping your elbow slightly bent. Slowly lower the dumbbell down towards your chest, keeping your elbow close to your body. Pause for a moment at the bottom, then push the dumbbell back up to the starting position. Repeat for the desired number of repetitions, then switch to the other arm.', NULL, 'triceps', '["triceps","shoulders"]', '["Lie flat on a bench with your back supported and feet flat on the ground.","Hold a dumbbell in one hand with your palm facing towards your feet.","Extend your arm straight up towards the ceiling, keeping your elbow slightly bent.","Slowly lower the dumbbell down towards your chest, keeping your elbow close to your body.","Pause for a moment at the bottom, then push the dumbbell back up to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."]', '["Lege dich flach auf eine Bank, der Rücken gestützt, die Füsse flach am Boden.","Halte eine Kurzhantel in einer Hand, die Handfläche zeigt zu den Füssen.","Strecke den Arm gerade Richtung Decke, der Ellbogen bleibt leicht gebeugt.","Senke die Kurzhantel langsam Richtung Brust ab, der Ellbogen bleibt nah am Körper.","Halte am unteren Punkt kurz inne und drücke die Kurzhantel dann zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dann zum anderen Arm."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0342.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0342.gif', 1784612222128, 1784612222128, 0),
  ('a4725db9-5d85-5221-ad97-9dceb3ceb66b', NULL, 'Dumbbell Lying One Arm Pronated Triceps Extension', 'Kurzhantel-Trizeps-Extension im Liegen (proniert), einarmig', 'upper arms', 'triceps', 'dumbbell', 'Lie flat on a bench with your back and head supported, and your feet flat on the ground. Hold a dumbbell in one hand with your palm facing down, and extend your arm straight up above your shoulder. Keeping your upper arm stationary, slowly lower the dumbbell behind your head by bending your elbow. Pause for a moment at the bottom, then extend your arm back up to the starting position. Repeat for the desired number of repetitions, then switch arms.', NULL, 'shoulders', '["shoulders"]', '["Lie flat on a bench with your back and head supported, and your feet flat on the ground.","Hold a dumbbell in one hand with your palm facing down, and extend your arm straight up above your shoulder.","Keeping your upper arm stationary, slowly lower the dumbbell behind your head by bending your elbow.","Pause for a moment at the bottom, then extend your arm back up to the starting position.","Repeat for the desired number of repetitions, then switch arms."]', '["Lege dich flach auf eine Bank, Rücken und Kopf gestützt, die Füsse flach am Boden.","Halte eine Kurzhantel in einer Hand, die Handfläche zeigt nach unten, und strecke den Arm gerade über die Schulter.","Halte den Oberarm ruhig und senke die Kurzhantel langsam hinter den Kopf ab, indem du den Ellbogen beugst.","Halte am unteren Punkt kurz inne und strecke den Arm dann zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dann die Seite."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0344.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0344.gif', 1784612222128, 1784612222128, 0),
  ('0300266e-4cd0-5956-a1b0-3316725ddd58', NULL, 'Dumbbell Lying One Arm Rear Lateral Raise', 'Kurzhantel-Reverses Seitheben im Liegen, einarmig', 'shoulders', 'delts', 'dumbbell', 'Lie face down on a flat bench with a dumbbell in one hand, hanging towards the floor. Keep your arm straight and lift the dumbbell out to the side, away from your body. Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position. Repeat for the desired number of repetitions, then switch to the other arm.', NULL, 'traps', '["traps","rhomboids"]', '["Lie face down on a flat bench with a dumbbell in one hand, hanging towards the floor.","Keep your arm straight and lift the dumbbell out to the side, away from your body.","Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."]', '["Lege dich bäuchlings auf eine flache Bank, eine Kurzhantel in einer Hand, Richtung Boden hängend.","Halte den Arm gestreckt und hebe die Kurzhantel seitlich vom Körper weg an.","Halte am oberen Punkt kurz inne und senke die Kurzhantel dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dann zum anderen Arm."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0345.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0345.gif', 1784612222128, 1784612222128, 0),
  ('283756ba-5d45-5d47-87e8-3897ac0577bb', NULL, 'Dumbbell Lying One Arm Supinated Triceps Extension', 'Kurzhantel-Trizeps-Extension im Liegen (supiniert), einarmig', 'upper arms', 'triceps', 'dumbbell', 'Lie flat on a bench with your back and head supported, and your feet flat on the ground. Hold a dumbbell in one hand with an underhand grip, and extend your arm straight up above your shoulder. Keeping your upper arm stationary, slowly lower the dumbbell behind your head by bending your elbow. Pause for a moment at the bottom, then extend your arm back up to the starting position. Repeat for the desired number of repetitions, then switch arms.', NULL, 'forearms', '["forearms"]', '["Lie flat on a bench with your back and head supported, and your feet flat on the ground.","Hold a dumbbell in one hand with an underhand grip, and extend your arm straight up above your shoulder.","Keeping your upper arm stationary, slowly lower the dumbbell behind your head by bending your elbow.","Pause for a moment at the bottom, then extend your arm back up to the starting position.","Repeat for the desired number of repetitions, then switch arms."]', '["Lege dich flach auf eine Bank, Rücken und Kopf gestützt, die Füsse flach am Boden.","Halte eine Kurzhantel in einer Hand im Untergriff und strecke den Arm gerade über die Schulter.","Halte den Oberarm ruhig und senke die Kurzhantel langsam hinter den Kopf ab, indem du den Ellbogen beugst.","Halte am unteren Punkt kurz inne und strecke den Arm dann zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dann die Seite."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0346.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0346.gif', 1784612222128, 1784612222128, 0),
  ('94110e84-c793-5995-a160-5f26144c98ec', NULL, 'Dumbbell Lying Pronation', 'Kurzhantel-Pronation im Liegen', 'lower arms', 'forearms', 'dumbbell', 'Lie flat on a bench with your chest facing down and your arms extended straight down, holding a dumbbell in each hand. Rotate your palms so they are facing up. Keeping your upper arms stationary, exhale and curl the dumbbells as you rotate your palms to face down. Inhale and slowly lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","shoulders"]', '["Lie flat on a bench with your chest facing down and your arms extended straight down, holding a dumbbell in each hand.","Rotate your palms so they are facing up.","Keeping your upper arms stationary, exhale and curl the dumbbells as you rotate your palms to face down.","Inhale and slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."]', '["Lege dich mit der Brust nach unten auf eine Bank, die Arme gerade nach unten gestreckt, in jeder Hand eine Kurzhantel.","Drehe die Handflächen, sodass sie nach oben zeigen.","Halte die Oberarme ruhig, atme aus und ziehe die Kurzhanteln hoch, während du die Handflächen nach unten drehst.","Atme ein und senke die Kurzhanteln langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0347.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0347.gif', 1784612222128, 1784612222128, 0),
  ('139fa3a2-ac84-53d6-b516-abb4667ad63a', NULL, 'Dumbbell Lying Pronation on Floor', 'Kurzhantel-Pronation auf dem Boden', 'lower arms', 'forearms', 'dumbbell', 'Lie flat on the floor with your face down and your arms extended straight out in front of you, holding a dumbbell in each hand. Rotate your palms so they are facing down towards the floor. Keeping your arms straight, lift the dumbbells off the floor by contracting your forearms. Continue lifting until your forearms are fully contracted and the dumbbells are at shoulder level. Hold for a moment, then slowly lower the dumbbells back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","triceps"]', '["Lie flat on the floor with your face down and your arms extended straight out in front of you, holding a dumbbell in each hand.","Rotate your palms so they are facing down towards the floor.","Keeping your arms straight, lift the dumbbells off the floor by contracting your forearms.","Continue lifting until your forearms are fully contracted and the dumbbells are at shoulder level.","Hold for a moment, then slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."]', '["Lege dich mit dem Gesicht nach unten flach auf den Boden, die Arme gerade vor dir ausgestreckt, in jeder Hand eine Kurzhantel.","Drehe die Handflächen, sodass sie Richtung Boden zeigen.","Halte die Arme gestreckt und hebe die Kurzhanteln vom Boden ab, indem du die Unterarme anspannst.","Hebe weiter, bis die Unterarme vollständig angespannt sind und die Kurzhanteln auf Schulterhöhe sind.","Halte einen Moment und senke die Kurzhanteln dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/2705.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/2705.gif', 1784612222128, 1784612222128, 0),
  ('e98866a9-008d-5e6c-aeb1-7f4ff1659e70', NULL, 'Dumbbell Lying Pullover on Exercise Ball', 'Kurzhantel-Überzüge im Liegen auf dem Gymnastikball', 'chest', 'pectorals', 'dumbbell', 'Sit on an exercise ball and roll forward until your upper back is resting on the ball. Hold a dumbbell with both hands and extend your arms straight up over your chest. Slowly lower the dumbbell behind your head while keeping your arms straight. Pause for a moment, then raise the dumbbell back to the starting position. Repeat for the desired number of repetitions.', NULL, 'triceps', '["triceps","shoulders","back"]', '["Sit on an exercise ball and roll forward until your upper back is resting on the ball.","Hold a dumbbell with both hands and extend your arms straight up over your chest.","Slowly lower the dumbbell behind your head while keeping your arms straight.","Pause for a moment, then raise the dumbbell back to the starting position.","Repeat for the desired number of repetitions."]', '["Setze dich auf einen Gymnastikball und rolle nach vorne, bis dein oberer Rücken auf dem Ball aufliegt.","Halte eine Kurzhantel mit beiden Händen und strecke die Arme gerade über die Brust.","Senke die Kurzhantel langsam hinter den Kopf ab, die Arme bleiben gestreckt.","Halte kurz inne und hebe die Kurzhantel dann zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1284.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1284.gif', 1784612222128, 1784612222128, 0),
  ('e0c93e88-ee32-5e3a-82a2-eafefb1f81df', NULL, 'Dumbbell Lying Rear Delt Row', 'Kurzhantel-Rudern für die hintere Schulter im Liegen', 'back', 'upper back', 'dumbbell', 'Lie face down on a flat bench with a dumbbell in each hand, palms facing inwards. Extend your arms straight down towards the floor, keeping a slight bend in your elbows. Engaging your back muscles, lift the dumbbells up towards your chest, squeezing your shoulder blades together. Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'shoulders', '["shoulders","biceps"]', '["Lie face down on a flat bench with a dumbbell in each hand, palms facing inwards.","Extend your arms straight down towards the floor, keeping a slight bend in your elbows.","Engaging your back muscles, lift the dumbbells up towards your chest, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."]', '["Lege dich bäuchlings auf eine flache Bank, in jeder Hand eine Kurzhantel, Handflächen zueinander.","Strecke die Arme gerade Richtung Boden, die Ellbogen leicht gebeugt.","Spanne die Rückenmuskeln an und hebe die Kurzhanteln Richtung Brust, ziehe dabei die Schulterblätter zusammen.","Halte am oberen Punkt kurz inne und senke die Kurzhanteln dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1328.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1328.gif', 1784612222128, 1784612222128, 0),
  ('7a61dc77-554a-5c10-984d-42f744cd5412', NULL, 'Dumbbell Lying Rear Lateral Raise', 'Kurzhantel-Reverses Seitheben im Liegen', 'shoulders', 'delts', 'dumbbell', 'Lie face down on a flat bench with a dumbbell in each hand, palms facing each other. Extend your arms straight down towards the floor, keeping a slight bend in your elbows. Engaging your shoulder muscles, lift your arms out to the sides until they are parallel to the floor. Pause for a moment at the top, then slowly lower your arms back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'traps', '["traps","rhomboids"]', '["Lie face down on a flat bench with a dumbbell in each hand, palms facing each other.","Extend your arms straight down towards the floor, keeping a slight bend in your elbows.","Engaging your shoulder muscles, lift your arms out to the sides until they are parallel to the floor.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."]', '["Lege dich bäuchlings auf eine flache Bank, in jeder Hand eine Kurzhantel, Handflächen zueinander.","Strecke die Arme gerade Richtung Boden, die Ellbogen leicht gebeugt.","Spanne die Schultermuskeln an und hebe die Arme seitlich an, bis sie parallel zum Boden sind.","Halte am oberen Punkt kurz inne und senke die Arme dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0348.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0348.gif', 1784612222128, 1784612222128, 0),
  ('cdfdb68e-83e7-5717-ba43-11e5171e9cf2', NULL, 'Dumbbell Lying Single Extension', 'Kurzhantel-Trizeps-Extension im Liegen, einarmig', 'upper arms', 'triceps', 'dumbbell', 'Lie flat on a bench with a dumbbell in one hand and your arm fully extended above your chest. Lower the dumbbell in a controlled manner towards your forehead, keeping your upper arm stationary. Pause briefly at the bottom of the movement, then extend your arm back to the starting position. Repeat for the desired number of repetitions, then switch arms.', NULL, 'shoulders', '["shoulders"]', '["Lie flat on a bench with a dumbbell in one hand and your arm fully extended above your chest.","Lower the dumbbell in a controlled manner towards your forehead, keeping your upper arm stationary.","Pause briefly at the bottom of the movement, then extend your arm back to the starting position.","Repeat for the desired number of repetitions, then switch arms."]', '["Lege dich flach auf eine Bank, eine Kurzhantel in einer Hand, der Arm vollständig über der Brust gestreckt.","Senke die Kurzhantel kontrolliert Richtung Stirn ab, der Oberarm bleibt ruhig.","Halte am unteren Punkt kurz inne und strecke den Arm dann zurück in die Ausgangsposition.","Wiederhole für die gewünschte Anzahl Wiederholungen und wechsle dann die Seite."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1735.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1735.gif', 1784612222128, 1784612222128, 0),
  ('ffb4d335-4113-5326-915b-76dadc163ea1', NULL, 'Dumbbell Lying Supination', 'Kurzhantel-Supination im Liegen', 'lower arms', 'forearms', 'dumbbell', 'Lie flat on a bench with your feet flat on the ground. Hold a dumbbell in each hand with your palms facing up and your arms fully extended. Keeping your upper arms stationary, curl the dumbbells towards your shoulders by contracting your forearms. Pause for a moment at the top, then slowly lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","shoulders"]', '["Lie flat on a bench with your feet flat on the ground.","Hold a dumbbell in each hand with your palms facing up and your arms fully extended.","Keeping your upper arms stationary, curl the dumbbells towards your shoulders by contracting your forearms.","Pause for a moment at the top, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."]', '["Lege dich flach auf eine Bank, die Füsse flach am Boden.","Halte in jeder Hand eine Kurzhantel, Handflächen nach oben, Arme vollständig gestreckt.","Halte die Oberarme ruhig und ziehe die Kurzhanteln Richtung Schultern hoch, indem du die Unterarme anspannst.","Halte am oberen Punkt kurz inne und senke die Kurzhanteln dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/0349.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/0349.gif', 1784612222128, 1784612222128, 0),
  ('f70f24e9-1306-54f1-8d8b-80269becf144', NULL, 'Dumbbell Lying Supination on Floor', 'Kurzhantel-Supination auf dem Boden', 'lower arms', 'forearms', 'dumbbell', 'Lie flat on your back on the floor with your legs extended and your arms by your sides, holding a dumbbell in each hand. Rotate your palms to face up, keeping your elbows close to your sides. Slowly curl the dumbbells towards your shoulders, squeezing your forearms. Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position. Repeat for the desired number of repetitions.', NULL, 'biceps', '["biceps","shoulders"]', '["Lie flat on your back on the floor with your legs extended and your arms by your sides, holding a dumbbell in each hand.","Rotate your palms to face up, keeping your elbows close to your sides.","Slowly curl the dumbbells towards your shoulders, squeezing your forearms.","Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."]', '["Lege dich flach auf den Rücken auf den Boden, die Beine gestreckt, die Arme neben dem Körper, in jeder Hand eine Kurzhantel.","Drehe die Handflächen nach oben, die Ellbogen bleiben nah am Körper.","Ziehe die Kurzhanteln langsam Richtung Schultern hoch und spanne dabei die Unterarme an.","Halte am oberen Punkt kurz inne und senke die Kurzhanteln dann langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/2706.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/2706.gif', 1784612222128, 1784612222128, 0),
  ('157d1f29-5612-5bb2-80fc-23c3dad405ff', NULL, 'Dumbbell Lying Supine Biceps Curl', 'Kurzhantel-Bizepscurl im Liegen (Rückenlage)', 'upper arms', 'biceps', 'dumbbell', 'Lie flat on a bench with your back and head supported, and your feet flat on the ground. Hold a dumbbell in each hand with your palms facing up and your arms fully extended. Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly begin to lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', NULL, 'forearms', '["forearms"]', '["Lie flat on a bench with your back and head supported, and your feet flat on the ground.","Hold a dumbbell in each hand with your palms facing up and your arms fully extended.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."]', '["Lege dich flach auf eine Bank, Rücken und Kopf gestützt, die Füsse flach am Boden.","Halte in jeder Hand eine Kurzhantel, Handflächen nach oben, Arme vollständig gestreckt.","Halte die Oberarme ruhig, atme aus und beuge die Arme, während du den Bizeps anspannst.","Hebe die Kurzhanteln weiter, bis der Bizeps vollständig angespannt ist und die Kurzhanteln auf Schulterhöhe sind.","Halte die kontrahierte Position kurz und spanne dabei den Bizeps an.","Atme ein und senke die Kurzhanteln langsam zurück in die Ausgangsposition ab.","Wiederhole für die gewünschte Anzahl Wiederholungen."]', 'https://ascent-api.sweber.workers.dev/media/exercises/1661.jpg', 'https://ascent-api.sweber.workers.dev/media/exercises/1661.gif', 1784612222128, 1784612222128, 0),
